INSERT INTO `clothing_info` VALUES (19969263, '谢尔登裤（男女通用）', 'シェルドンパンツ（ユニセックス）', 0, 31750121, 'THE NORTH FACE', '', '', 'THE NORTH FACE Korea Collection 以都市与精致氛围为灵感的系列。此款休闲长裤采用具有自然光泽与自然皱感的尼龙面料，并进行防泼水处理。设计包含膝部省道，左右插袋，右后臀拉链口袋与左后臀魔术贴口袋；腰部为织带式调节设计，裾口配有抽绳以便调节贴合度。可与同材质夹克（NPW02603WL）成套搭配。适合生活方式与户外场景。', '都会的かつ洗練されたムードのアイテムで、韓国独自のクリエイションを追求したTHE NORTH FACE Korea Collection。ナチュラルな光沢と自然なシワ感のある生地を採用したカジュアルなパンツ。 特徴 ・膝ダーツ仕様 ・同素材のジャケット（NPW02603WL）とセットアップ可能 素材 ・ナチュラルな光沢と自然なシワ感のあるナイロン生地・はっ水加工 機能・デザイン・容量 ・左右ポケット・右ヒップフラップ切り替え部にファスナーポケット、左ヒップフラップ切り替え部に面ファスナー付きポケット・ウエストはウェビングベルト仕様 ・裾のドローコードでフィット感の調節が可能 おすすめシーン ライフスタイル、アウトドアご注文について・Goldwin Online Store 限定販売・店舗受取り注文についてはご利用いただけません {\"素材/テクノロジー\": [{\"Water Resistant\": \"はっ水機能\"}], \"適したアクティビティ\": [\"ライフスタイル\"]}', '19250.0 JPY', 1174.25, 0, 0, 0, '', 0, 0, '', '2026-03-16 07:06:21', '2026-03-17 13:14:58', 'thenorthface_NB02609WL', '', '69b853459d1ab1886832c1de', '生活/休闲，徒步/登山', '', '通用', '青年（18-44岁）', '锦纶100%', 'https://www.goldwin.co.jp/ap/item/i/m/NB02609WL', '下装', '冲锋裤', '登山裤', '', 'hiking pants', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/the_north_face/20260317/GDW01_A0GDW0001RGI_02_BE29.jpg', 0, 0, 1, 0.99951, 0, -2, 0, 0, 0, 3, NULL, '防水，膝部省道设计提升活动灵活性，腰部织带腰带可调节，裾口抽绳可调节贴合度，多口袋收纳（左右插袋、右后臀拉链口袋、左后臀魔术贴口袋），可与同材质夹克成套搭配', '膝部省道设计提升活动灵活性,腰部织带腰带可调节,裾口抽绳可调节贴合度,多口袋收纳（左右插袋、右后臀拉链口袋、左后臀魔术贴口袋）,可与同材质夹克成套搭配', '防泼水功能', '面料具有自然光泽与自然皱感,韩国系列，都市与精致风格表达,尼龙面料轻质耐穿,设计与收纳细节适合日常与户外使用', '纯色', '该款为长裤，采用轻质尼龙面料并具备防泼水功能、膝部省道、可调节裾口抽绳与多口袋等户外实用细节，且推荐场景含“户外”。这些特征与“hiking pants（徒步裤）”的定义高度吻合。hiking pants：专为户外徒步等活动设计的功能性长裤，通常使用耐用、快干或防泼水材料，并通过便于活动与收纳的结构细节提升实用性与舒适度。', 1, 0, 0, 0, 'hiking pants', NULL, '', 0, NULL, 0, NULL, NULL, 'color_BE29', 'スモークグレー', 0);
