INSERT INTO `clothing_info` VALUES (19969260, '阿罗哈防撕裂短裤（男女通用）', 'アロハリップショーツ（ユニセックス）', 0, 31750121, 'THE NORTH FACE', '', '', '采用具有天然质感的防撕裂面料，兼具通气与防紫外线功能。面料在保持经典外观的同时具有干爽的触感与良好的肌理离肤性，使用具弹性且透气的聚酯材质。印花款以约塞米蒂的统计资料为灵感的图形设计，也有易于搭配的纯色款。腰部为抽绳设计，左右侧口袋，右后配拉链口袋。适用场景：生活方式、夏季户外。提供UPF30-50+，紫外线遮蔽率90%以上。', '【再入荷通知・在庫取り寄せあり】通気性とUVカット機能を備えた、天然調のリップストップ素材を採用したショーツ 特徴 ・クラシカルな表情を持ちつつ、肌離れのよいドライな質感の生地・UVガード（UPF30-50+、紫外線カット率90%以上）機能付き 生地・素材 ・通気性、UVカット機能に加え、ストレッチ性も備えるポリエステル素材 機能・デザイン ・ヨセミテの統計資料をグラフィックに落とし込んだプリントデザインと、コーディネートしやすい無地のカラーバリエーション・ウエストはスピンドル仕様・左右サイドにポケット、右ヒップにファスナーポケット おすすめシーン ライフスタイル、夏のアウトドア {\"素材/テクノロジー\": [{\"Stretch\": \"ストレッチ素材を使用。\"}, {\"UV GUARD\": \"屋外でのスポーツや長時間の外出に対応。UPF30-50＋、UVカット率90%以上を確保。\"}, {\"BREEZERANGE\": \"通気とUVカットの機能を備えた素材。衣服内の空気の循環を助け蒸れを軽減し、UVカット機能により太陽光からの有害な紫外線を遮断し肌を保護する。涼しく快適な着用感を実現。\"}], \"適したアクティビティ\": [\"ライフスタイル\"]}', '9900.0 JPY', 603.90, 0, 0, 0, '', 0, 0, '', '2026-03-16 07:06:23', '2026-03-17 13:14:56', 'thenorthface_NB42635', '', '69b853459d1ab1886832c1db', '生活/休闲', '', '通用', '青年（18-44岁）', '涤纶100%', 'https://www.goldwin.co.jp/ap/item/i/m/NB42635', '下装', '短裤', '短裤', '', 'shorts', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/the_north_face/20260317/GDW01_A0GDW0001NEB_02_BC14.jpg', 0, 0, 1, 0.99758, 0, -2, 0, 0, 0, 3, NULL, '透气，防紫外线，高弹力，促进衣内空气循环，降低闷热感', '促进衣内空气循环,降低闷热感', 'BREEZERANGE（通风与防紫外线面料）,UV GUARD（防紫外线）,Stretch（弹力面料）', '采用具天然质感的防撕裂机织面料,干爽不粘肤的穿着触感,腰部抽绳设计,两侧插袋与右后拉链口袋,提供印花与纯色两种配色,UPF30-50+，紫外线遮蔽率90%以上', '文字，字母，数字，科技', '该产品为及大腿的短裤版型，属于下装的短裤类别；文案明确为“ショーツ（短裤）”，适用于生活方式与夏季户外。综合图文判断其功能与版型皆为常规休闲/户外短裤，因此选择 sub_category 为“shorts”。定义：shorts——长度至膝上或膝附近的短裤，用于日常休闲或户外活动。', 1, 0, 0, 0, 'shorts', NULL, '', 0, NULL, 0, NULL, NULL, 'color_BC14', 'ハーフドームドローイングフォッシルアイボリー', 0);
