INSERT INTO `clothing_info` VALUES (19969257, 'Shelldon长裙（女款）', 'シェルドンスカート（レディース）', 0, 31750121, 'THE NORTH FACE', '', '', 'THE NORTH FACE Korea Collection（韩国系列），以都市感与精致氛围为特点，追求韩国独有的创意。这是一款采用具有自然光泽与自然褶皱感的面料打造的休闲、轻量长裙。特点：前部左右大号工装口袋，翻盖上方亦可使用的2WAY口袋；下摆抽绳可调节轮廓；可与同材质夹克（NPW02603WL）成套搭配。材质：具有自然光泽与自然褶皱感的尼龙面料；防泼水处理。功能/设计：左右插袋、左右前部带按扣的工装口袋；右侧后臀部假翻盖口袋；腰部为松紧结构，配有腰带袢。推荐场景：生活方式、户外。', '都会的かつ洗練されたムードのアイテムで、韓国独自のクリエイションを追求したTHE NORTH FACE Korea Collection。ナチュラルな光沢と自然なシワ感のある生地を採用したカジュアルな軽量ロングスカート。 特徴 ・フロントの左右大きめなカーゴポケットは、フラップ上からも使用できる2WAYポケット・裾のドローコードによりシルエットの調節が可能・同素材のジャケット（NPW02603WL）とセットアップ可能 素材 ・ナチュラルな光沢と自然なシワ感のあるナイロン生地・はっ水加工 機能・デザイン・容量 ・左右ポケット・左右フロントスナップ付きカーゴポケット ・右ヒップにフェイクフラップポケット ・ウエストはゴム仕様、ベルトループ付き おすすめシーン ライフスタイル、アウトドアご注文について・Goldwin Online Store 限定販売・店舗受取り注文についてはご利用いただけません {\"素材/テクノロジー\": [{\"Water Resistant\": \"はっ水機能\"}], \"適したアクティビティ\": [\"ライフスタイル\"]}', '17050.0 JPY', 1040.05, 0, 0, 0, '', 0, 0, '', '2026-03-16 07:06:33', '2026-03-17 13:14:53', 'thenorthface_NBW02611WL', '', '69b853459d1ab1886832c1da', '生活/休闲', '', '女', '青年（18-44岁）', '锦纶100%', 'https://www.goldwin.co.jp/ap/item/i/m/NBW02611WL', '裙装', '半身裙', '长裙', '', 'maxi skirt', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/the_north_face/20260317/GDW01_A0GDW0001RGK_02_BE27.jpg', 0, 0, 1, 0.99488, 0, -2, 0, 0, 0, 3, NULL, '防水，下摆抽绳可调节轮廓，2WAY工装口袋，腰部松紧设计，大容量口袋，可与同材质夹克套穿', '下摆抽绳可调节轮廓,2WAY工装口袋,腰部松紧设计,大容量口袋,可与同材质夹克套穿', '防泼水处理', '韩国系列，强调都市与精致风格,尼龙机织面料，具有自然光泽与自然褶皱感,前部左右大号工装口袋，配按扣翻盖,右后假翻盖口袋设计,腰部为橡筋结构并配有腰带袢,轻量化穿着体验', '纯色', '产品名称为“长裙”，描述中明确为“轻量ロングスカート（长裙）”，图中裙长明显为长款并配有下摆抽绳与工装口袋，符合“maxi skirt”的定义。选择的子类：maxi skirt。该子类定义：及踝或接近及踝长度的长款裙装，常用于休闲或都市风格造型。', 1, 0, 0, 0, 'maxi skirt', NULL, '', 0, NULL, 0, NULL, NULL, 'color_BE27', 'クールグレー', 0);
