INSERT INTO `clothing_info` VALUES (19969259, 'Shelldon长裙（女款）', 'シェルドンスカート（レディース）', 0, 31750121, 'THE NORTH FACE', '', '', 'THE NORTH FACE Korea Collection（韩国系列），以都市感与精致氛围为特点，追求韩国独有的创意。这是一款采用具有自然光泽与自然褶皱感的面料打造的休闲、轻量长裙。特点：前部左右大号工装口袋，翻盖上方亦可使用的2WAY口袋；下摆抽绳可调节轮廓；可与同材质夹克（NPW02603WL）成套搭配。材质：具有自然光泽与自然褶皱感的尼龙面料；防泼水处理。功能/设计：左右插袋、左右前部带按扣的工装口袋；右侧后臀部假翻盖口袋；腰部为松紧结构，配有腰带袢。推荐场景：生活方式、户外。', '都会的かつ洗練されたムードのアイテムで、韓国独自のクリエイションを追求したTHE NORTH FACE Korea Collection。ナチュラルな光沢と自然なシワ感のある生地を採用したカジュアルな軽量ロングスカート。 特徴 ・フロントの左右大きめなカーゴポケットは、フラップ上からも使用できる2WAYポケット・裾のドローコードによりシルエットの調節が可能・同素材のジャケット（NPW02603WL）とセットアップ可能 素材 ・ナチュラルな光沢と自然なシワ感のあるナイロン生地・はっ水加工 機能・デザイン・容量 ・左右ポケット・左右フロントスナップ付きカーゴポケット ・右ヒップにフェイクフラップポケット ・ウエストはゴム仕様、ベルトループ付き おすすめシーン ライフスタイル、アウトドアご注文について・Goldwin Online Store 限定販売・店舗受取り注文についてはご利用いただけません {\"素材/テクノロジー\": [{\"Water Resistant\": \"はっ水機能\"}], \"適したアクティビティ\": [\"ライフスタイル\"]}', '17050.0 JPY', 1040.05, 0, 0, 0, '', 0, 0, '', '2026-03-16 07:06:33', '2026-03-17 13:14:54', 'thenorthface_NBW02611WL', '', '69b853459d1ab1886832c1da', '生活/休闲', '', '女', '青年（18-44岁）', '锦纶100%', 'https://www.goldwin.co.jp/ap/item/i/m/NBW02611WL', '裙装', '半身裙', '长裙', '', 'maxi skirt', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/the_north_face/20260317/GDW01_A0GDW0001RGK_02_V901.jpg', 0, 0, 1, 0.99811, 0, -2, 0, 0, 0, 3, NULL, '防水，下摆抽绳可调节轮廓，2WAY工装口袋，腰部松紧设计，大容量口袋，可与同材质夹克套穿', '下摆抽绳可调节轮廓,2WAY工装口袋,腰部松紧设计,大容量口袋,可与同材质夹克套穿', '防泼水处理', '韩国系列，强调都市与精致风格,尼龙机织面料，具有自然光泽与自然褶皱感,前部左右大号工装口袋，配按扣翻盖,右后假翻盖口袋设计,腰部为橡筋结构并配有腰带袢,轻量化穿着体验', '纯色', '产品名称为“长裙”，描述中明确为“轻量ロングスカート（长裙）”，图中裙长明显为长款并配有下摆抽绳与工装口袋，符合“maxi skirt”的定义。选择的子类：maxi skirt。该子类定义：及踝或接近及踝长度的长款裙装，常用于休闲或都市风格造型。', 1, 2, 0, 0, 'maxi skirt', NULL, '', 0, NULL, 0, NULL, NULL, 'color_V901', 'ブラック', 0);
INSERT INTO `clothing_info` VALUES (19973900, 'Cecilie Bahnsen 联名 Base Camp Duffel S', 'セシリーバンセン ベースキャンプダッフル S', 0, 31750121, 'THE NORTH FACE', '', '', '与丹麦高定品牌 Cecilie Bahnsen 的特别联名，融合其女性化与极简、精致的装饰风格。以 THE NORTH FACE 长销探险款为灵感的行李包。采用具有良好泼水性与耐磨性的 1000D TPE 覆膜再生聚酯面料，并辅以 840D 再生尼龙。设计亮点：Cecilie Bahnsen 3D 刺绣花卉贴饰；简洁主仓，D 形拉链大开口便于收纳；翻盖内侧拉链口袋可收纳小物；侧面抓手便于搬运；附收纳袋。推荐场景：日常、旅行。', 'フェミニンな世界観とミニマルで緻密な装飾が特徴的なデンマークのハイファッションブランド・Cecilie Bahnsenとの特別コラボレーションアイテム。数多くのエクスペディションを支えてきたTHE NORTH FACEのロングセラーモデルをモチーフにしたダッフルバッグ。 特徴 ・Cecilie Bahnsenの3D刺繍フラワーアップリケをあしらったフェミニンでエレガントなデザイン・たっぷり入る容量48L 素材 ・はっ水性と耐摩耗性に優れた1000デニールのTPEコーティングポリエステル素材 機能・デザイン・容量 ・シンプルなメインコンパートメント・大きく開閉して収納しやすいD型ファスナーオープン・小物の収納に便利なフラップ裏ファスナーポケット・持ち運びに便利なサイドのグラブハンドル・収納袋付き おすすめシーン ・日常シーン・旅行ご注文について・Goldwin Online Store 一部店舗 限定販売・1製品につき、お一人様1点までのご購入とさせていただきます・店舗受取り注文についてはご利用いただけません・お客様都合による返品、交換はお受けできません・万一お届けした製品に不具合があった場合、代品のご用意があればご交換にて対応させていただきます。代品がご用意できない場合は、ご返金対応となります {\"素材/テクノロジー\": [], \"適したアクティビティ\": [\"ライフスタイル\"]}', '63800.0 JPY', 3891.80, 0, 0, 0, '', 0, 0, '', '2026-03-19 02:04:20', '2026-03-24 12:27:34', 'thenorthface_NM82608CB', '', '69c1eb7d9c7a2598148913ca', '生活/休闲，差旅/商务', '', '通用', '青年（18-44岁）', '再生涤纶100%', 'https://www.goldwin.co.jp/ap/item/i/m/NM82608CB', '其他服饰/物品', '其他', '旅行包', '', 'duffle bag', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/the_north_face/20260319/GDW01_A0GDW0001PFU_02_G548.jpg', 0, 0, 9, 0.97363, 0, 1, 0, 0, 0, 3, NULL, '防水，耐磨损', '耐磨损', 'TPE覆膜技术,3D刺绣贴饰工艺,高旦数面料（1000D/840D）', '与Cecilie Bahnsen联名，女性化与优雅风格,3D花卉刺绣贴饰装点外观,主仓结构简洁，D形拉链大开口便于装取,翻盖内侧拉链口袋可收纳小物,侧面抓手便于搬运,附收纳袋便于整洁收纳,采用1000D TPE覆膜面料与840D再生尼龙，兼具泼水与耐磨', '花卉图案', '该产品为旅行用大容量行李包，具有简洁主仓、D形大开口、侧面抓手与附收纳袋等典型运动旅行包结构特征，且文本明确为“ダッフルバッグ”。因此归类为“duffle bag”。duffle bag（圆筒/运动旅行包）的定义：以大主仓为核心、适合旅行与运动装备携带的包款，通常配有抓手或肩带，便于装载与搬运。', 0, 0, 0, 0, 'duffle bag', NULL, '', 0, NULL, 0, NULL, NULL, 'color_G548', 'フォレストナイトグリーン', 0);
INSERT INTO `clothing_info` VALUES (19973894, 'Tread 夹克（男款）', 'トレッドジャケット（メンズ）', 0, 31750121, 'THE NORTH FACE', '', '', '采用具备洗涤耐久性的 WUROS（2.5层）防水透湿材料的壳式夹克，适合户外入门到日常使用。特点：接缝压胶以减少从缝线处渗水的防水构造；内层为干爽手感，贴肤清爽。材质：40D 再生尼龙防撕裂 WUROS（2.5层）。功能与设计：前门襟使用止水拉链；带翻盖的斜插口袋；未使用时可收纳的内置帽兜；帽兜支持单手调节；下摆配有抽绳以减少风灌入。推荐场景：登山、徒步、远足。素材/技术：WUROS 防水透湿（耐久、抗水解）；防水与泼水、防风；止水拉链；附带收纳袋，便于压缩收纳与携带。', '【在庫取り寄せあり】アウトドアエントリーから活用しやすい、洗濯耐久性を備えた防水透湿素材「WUROS（2.5層）」を採用したシェルジャケット 特徴 ・縫い目からの水の浸入を抑えたシームシーリング加工を施した防水仕様・内側はドライタッチで、肌に触れてもサラッとした着用感 素材 ・40Dリサイクルナイロンリップストップ WUROS（2.5層）を使用 機能・デザイン・容量 ・フロントは止水ファスナーを採用・フラップ付きスランティングポケット・フード未使用時に収納可能なビルトインフード仕様・片手で操作可能なワンハンドアジャスター対応フーデッド・裾からの風の侵入を軽減するドローコードを装備 おすすめシーン ・登山・トレッキング・ハイキングご注文について・Goldwin Online Store 一部店舗 限定販売 {\"素材/テクノロジー\": [{\"Waterproof\": \"防水機能\"}, {\"Water Resistant\": \"はっ水機能\"}, {\"Windproof\": \"防風機能\"}, {\"Water Repellent Zippers\": \"止水ファスナー\"}, {\"Stuff Sack\": \"収納用のスタッフサックが付属。コンパクトに収納して持ち運び可能。\"}, {\"WUROS\": \"従来のポリウレタン皮膜より加水分解が起こりにくい、耐久性を向上させた防水透湿素材。\"}], \"適したアクティビティ\": []}', '38500.0 JPY', 2348.50, 0, 0, 0, '', 0, 0, '', '2026-03-19 02:04:36', '2026-03-24 12:27:28', 'thenorthface_NP12615', '', '69c1eb7d9c7a2598148913ba', '攀岩，徒步/登山', '', '男', '青年（18-44岁）', '锦纶100%', 'https://www.goldwin.co.jp/ap/item/i/m/NP12615', '上装', '冲锋衣', '徒步夹克', '', 'hiking jacket', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/the_north_face/20260319/GDW01_A0GDW0001P1M_02_AJ71.jpg', 0, 0, 1, 0.99994, 0, -2, 0, 0, 0, 3, NULL, '防水，防风，透气，接缝压胶密封（Seam Sealing），止水拉链，可收纳式内置帽兜，单手调节帽兜，下摆抽绳防风，附带收纳袋（Stuff Sack），内层干爽触感', '接缝压胶密封（Seam Sealing）,止水拉链,可收纳式内置帽兜,单手调节帽兜,下摆抽绳防风,附带收纳袋（Stuff Sack）,内层干爽触感', 'WUROS 防水透湿（2.5层）,接缝压胶密封,止水拉链,随附收纳袋（Stuff Sack）', '40D再生尼龙防撕裂面料（Taslan）,2.5层结构，兼具防水与透湿,前门襟采用止水拉链提升防护,斜插翻盖口袋设计,内置帽兜可折叠收纳,帽兜支持单手快速调节,下摆抽绳减少风灌入,内层干爽触感，贴肤不黏腻,适合登山、徒步、远足等户外场景', '品牌标识，纯色', '该产品为具备防水透湿与防风性能的户外壳类上衣，描述中明确推荐“登山・トレッキング・ハイキング”，并配有可收纳帽兜、止水拉链、接缝压胶等技术特征，符合“hiking jacket”的定义。选择的子类别：hiking jacket。该子类别的适当定义：专为徒步、登山与远足等户外活动设计的功能性夹克，注重防水、防风与透湿等防护性能，并具备便携与调节性设计。', 1, 0, 0, 0, 'hiking jacket', NULL, '', 0, NULL, 0, NULL, NULL, 'color_AJ71', 'クレイグレー', 0);
INSERT INTO `clothing_info` VALUES (19973895, 'Tread 夹克（男款）', 'トレッドジャケット（メンズ）', 0, 31750121, 'THE NORTH FACE', '', '', '采用具备洗涤耐久性的 WUROS（2.5层）防水透湿材料的壳式夹克，适合户外入门到日常使用。特点：接缝压胶以减少从缝线处渗水的防水构造；内层为干爽手感，贴肤清爽。材质：40D 再生尼龙防撕裂 WUROS（2.5层）。功能与设计：前门襟使用止水拉链；带翻盖的斜插口袋；未使用时可收纳的内置帽兜；帽兜支持单手调节；下摆配有抽绳以减少风灌入。推荐场景：登山、徒步、远足。素材/技术：WUROS 防水透湿（耐久、抗水解）；防水与泼水、防风；止水拉链；附带收纳袋，便于压缩收纳与携带。', '【在庫取り寄せあり】アウトドアエントリーから活用しやすい、洗濯耐久性を備えた防水透湿素材「WUROS（2.5層）」を採用したシェルジャケット 特徴 ・縫い目からの水の浸入を抑えたシームシーリング加工を施した防水仕様・内側はドライタッチで、肌に触れてもサラッとした着用感 素材 ・40Dリサイクルナイロンリップストップ WUROS（2.5層）を使用 機能・デザイン・容量 ・フロントは止水ファスナーを採用・フラップ付きスランティングポケット・フード未使用時に収納可能なビルトインフード仕様・片手で操作可能なワンハンドアジャスター対応フーデッド・裾からの風の侵入を軽減するドローコードを装備 おすすめシーン ・登山・トレッキング・ハイキングご注文について・Goldwin Online Store 一部店舗 限定販売 {\"素材/テクノロジー\": [{\"Waterproof\": \"防水機能\"}, {\"Water Resistant\": \"はっ水機能\"}, {\"Windproof\": \"防風機能\"}, {\"Water Repellent Zippers\": \"止水ファスナー\"}, {\"Stuff Sack\": \"収納用のスタッフサックが付属。コンパクトに収納して持ち運び可能。\"}, {\"WUROS\": \"従来のポリウレタン皮膜より加水分解が起こりにくい、耐久性を向上させた防水透湿素材。\"}], \"適したアクティビティ\": []}', '38500.0 JPY', 2348.50, 0, 0, 0, '', 0, 0, '', '2026-03-19 02:04:36', '2026-03-24 12:27:28', 'thenorthface_NP12615', '', '69c1eb7d9c7a2598148913ba', '攀岩，徒步/登山', '', '男', '青年（18-44岁）', '锦纶100%', 'https://www.goldwin.co.jp/ap/item/i/m/NP12615', '上装', '冲锋衣', '徒步夹克', '', 'hiking jacket', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/the_north_face/20260319/GDW01_A0GDW0001P1M_02_BC75.jpg', 0, 0, 1, 0.99995, 0, -2, 0, 0, 0, 3, NULL, '防水，防风，透气，接缝压胶密封（Seam Sealing），止水拉链，可收纳式内置帽兜，单手调节帽兜，下摆抽绳防风，附带收纳袋（Stuff Sack），内层干爽触感', '接缝压胶密封（Seam Sealing）,止水拉链,可收纳式内置帽兜,单手调节帽兜,下摆抽绳防风,附带收纳袋（Stuff Sack）,内层干爽触感', 'WUROS 防水透湿（2.5层）,接缝压胶密封,止水拉链,随附收纳袋（Stuff Sack）', '40D再生尼龙防撕裂面料（Taslan）,2.5层结构，兼具防水与透湿,前门襟采用止水拉链提升防护,斜插翻盖口袋设计,内置帽兜可折叠收纳,帽兜支持单手快速调节,下摆抽绳减少风灌入,内层干爽触感，贴肤不黏腻,适合登山、徒步、远足等户外场景', '品牌标识，纯色', '该产品为具备防水透湿与防风性能的户外壳类上衣，描述中明确推荐“登山・トレッキング・ハイキング”，并配有可收纳帽兜、止水拉链、接缝压胶等技术特征，符合“hiking jacket”的定义。选择的子类别：hiking jacket。该子类别的适当定义：专为徒步、登山与远足等户外活动设计的功能性夹克，注重防水、防风与透湿等防护性能，并具备便携与调节性设计。', 1, 1, 0, 0, 'hiking jacket', NULL, '', 0, NULL, 0, NULL, NULL, 'color_BC75', 'マリーナブルー×TNFブルー', 0);
