INSERT INTO `clothing_info` VALUES (19973888, 'Cecilie Bahnsen 长款防风夹克（女款）', 'セシリーバンセン ロングウィンドジャケット（レディース）', 0, 31750121, 'THE NORTH FACE', '', '', '与丹麦高定品牌 Cecilie Bahnsen 的特别联名款，将机能性与优雅的花卉元素融合的防风夹克。通体花卉压纹图案；配有定制花形 D 环与同色系花形抽绳锁扣的可调节腰部抽绳。设计细节包括：带花形抽绳拉头的 VISLON 制双向前拉链；带花形拉头的 VISLON 制胸前阿尔卑斯风格拉链口袋与袖臂拉链口袋；前后可调的弹性三片式连帽结构；下摆与袖口可通过花形抽绳锁扣调节。左胸口袋处为 TNF × Cecilie Bahnsen 联名花卉标识，背部中间约克位置印有 Cecilie Bahnsen 品牌标识。推荐场景：生活方式、户外。', 'フェミニンな世界観とミニマルで緻密な装飾が特徴的なデンマークのハイファッションブランド・Cecilie Bahnsenとの特別コラボレーションアイテム。パフォーマンス性と優雅なフローラルモチーフを融合したウィンドジャケット。 特徴 ・全体にエンボス加工を施したフラワープリント・カスタムフラワーDリング付き、同色系フローラルコードロックを備えた調整可能なウエストドローコード 機能・デザイン・容量 ・フラワーコードプル付き、VISLON製2WAYフロントファスナー・フラワーコードプル付き、VISLON製アルパインスタイルのファスナー付き胸ポケット・フラワーコードプル付き、VISLON製ファスナー付きアームポケット・前後で調整可能な、伸縮性のある3パネル構造フード・裾と袖口はフラワーコードロックで調整可能・左胸ポケットにTNF × Cecilie Bahnsenのフローラル・コーブランディング・背面中央のヨーク部分にCecilie Bahnsenのブランディング おすすめシーン ライフスタイル、アウトドアご注文について・Goldwin Online Store 一部店舗 限定販売・1製品につき、お一人様1点までのご購入とさせていただきます・店舗受取り注文についてはご利用いただけません・お客様都合による返品、交換はお受けできません・万一お届けした製品に不具合があった場合、代品のご用意があればご交換にて対応させていただきます。代品がご用意できない場合は、ご返金対応となります {\"素材/テクノロジー\": [], \"適したアクティビティ\": []}', '88000.0 JPY', 5368.00, 0, 0, 0, '', 0, 0, '', '2026-03-19 02:04:59', '2026-03-24 12:27:22', 'thenorthface_NPW02600CB', '', '69c1eb7c9c7a259814891394', '生活/休闲', '', '女', '青年（18-44岁）', '锦纶94%,涤纶6%', 'https://www.goldwin.co.jp/ap/item/i/m/NPW02600CB', '上装', '冲锋衣', '防风衣', '', 'windbreaker', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/the_north_face/20260319/GDW01_A0GDW0001RM8_02_BE33.jpg', 0, 0, 1, 0.99991, 0, -2, 0, 0, 0, 3, NULL, '防风，可调节腰部抽绳，连帽设计（前后可调的三片结构），双向前拉链，胸部与袖臂拉链口袋收纳，下摆与袖口可调节', '可调节腰部抽绳,连帽设计（前后可调的三片结构）,双向前拉链,胸部与袖臂拉链口袋收纳,下摆与袖口可调节', 'VISLON 双向拉链,压纹工艺,树脂涂层加工', '与 Cecilie Bahnsen 联名，融合高定花卉美学与机能设计,全身花卉压纹图案，细腻且优雅,定制花形 D 环与同色系花形抽绳锁扣细节,左胸口袋处联名花卉标识，后背约克区域品牌标识,长款版型，腰部可收束塑形', '花卉图案', '产品名称明确为“ロングウィンドジャケット（长款风/防风夹克）”，并具备防风外套典型结构：连帽、双向拉链、可调节抽绳、多拉链口袋等。长款但仍以防风功能为核心，且材质为机织涂层面料，符合轻薄防风外套的特征。故选择 sub_category：windbreaker。定义：windbreaker 指以轻薄机织面料制成、以防风为主要功能的外套，常配备连帽、拉链与抽绳等细节，适用于日常与户外轻度活动。', 0, 0, 0, 0, 'windbreaker', NULL, '', 0, NULL, 0, NULL, NULL, 'color_BE33', 'フォレストナイトグリーン', 0);
INSERT INTO `clothing_info` VALUES (19982304, 'Cecilie Bahnsen 可转换裤（女款）', 'セシリーバンセン コンバーチブルパンツ（レディース）', 0, 31750121, 'THE NORTH FACE', '', '', '与丹麦高端时装品牌 Cecilie Bahnsen 的特别合作款。配备多功能实用口袋的可转换设计长裤。整体采用 Cecilie Bahnsen 花卉图案压花处理，可通过隐形拉链转换为短裤，内侧为全面接缝贴条结构。设计与容量：略高腰；手袋配花形抽绳与 AquaGuard 拉链；货物贴袋采用花形按扣，并配同色系装饰性花卉 D 形环；裤脚可通过花形抽绳锁扣调节；左下口袋带 TNF × Cecilie Bahnsen 花卉联名标识；右后口袋带 Cecilie Bahnsen 品牌标识。推荐场景：日常生活、户外。', 'フェミニンな世界観とミニマルで緻密な装飾が特徴的なデンマークのハイファッションブランド・Cecilie Bahnsenとの特別コラボレーションアイテム。マルチファンクションなユーティリティポケットを備えた、コンバーチブル仕様のパンツ。 特徴 ・全体にエンボス加工を施したCecilie Bahnsenフラワープリント・コンシールファスナーにより、股下9インチ（約23cm）のショーツへと切り替え可能・内側は全面シームテープ仕様 機能・デザイン・容量 ・ややハイウエスト・フラワーコードプル付き、AquaGuard製ファスナー付きハンドポケット・フラワースナップ留めと、装飾的な同色系フローラルDリングを備えたカーゴパッチポケット・裾はフラワーコードロックで調整可能・左下ポケットにTNF × Cecilie Bahnsenのフローラル・コーブランディング・右後ろポケットにCecilie Bahnsenのブランディング おすすめシーン ライフスタイル、アウトドアお取扱い注意ゴム仕様のウエスト部分が通常よりタイトに設計されています。着用の際にはご注意ください。ご注文について・Goldwin Online Store 一部店舗 限定販売・1製品につき、お一人様1点までのご購入とさせていただきます・店舗受取り注文についてはご利用いただけません・お客様都合による返品、交換はお受けできません・万一お届けした製品に不具合があった場合、代品のご用意があればご交換にて対応させていただきます。代品がご用意できない場合は、ご返金対応となります {\"素材/テクノロジー\": [], \"適したアクティビティ\": []}', '95700.0 JPY', 5837.70, 0, 0, 0, '', 0, 0, '', '2026-03-19 02:05:18', '2026-03-24 15:32:41', 'thenorthface_NBW02603CB', '', '69c1eb7c9c7a259814891390', '生活/休闲，徒步/登山', '', '女', '青年（18-44岁）', '锦纶94%,涤纶3%', 'https://www.goldwin.co.jp/ap/item/i/m/NBW02603CB', '下装', '工装裤', '工装裤', '', 'cargo pants', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/the_north_face/20260319/GDW01_A0GDW0001RM7_02_BE33.jpg', 0, 0, 1, 0.99576, 0, -2, 0, 0, 0, 3, NULL, '防水，可转换为短裤，多功能口袋，可调节裤脚，高腰设计', '可转换为短裤,多功能口袋,可调节裤脚,高腰设计', 'AquaGuard防水拉链,全面接缝贴条,涂层树脂加工,压花工艺', '联名合作款,全覆盖花卉压花图案,隐形拉链转换结构,装饰性同色系花卉D形环,花形抽绳与花形按扣,货物贴袋与手袋设计', '花卉图案', '该产品为长裤并具备多处“货物贴袋/实用口袋”，且描述为可通过隐形拉链转换为短裤，明显属于工装风格的功能性裤装。综合文字与图片判断，最贴切的类别为“cargo pants”。定义：cargo pants（工装裤）——配有多个大容量功能性口袋的长裤，常用于户外与生活场景，注重实用与装载能力。', 0, 0, 0, 0, 'cargo pants', NULL, '', 0, NULL, 0, NULL, NULL, 'color_BE33', 'フォレストナイトグリーン', 0);
INSERT INTO `clothing_info` VALUES (19981124, 'Tread裤（女士）', 'トレッドパンツ（レディース）', 0, 31750121, 'THE NORTH FACE', '', '', '采用具备洗涤耐久性的防水透湿材料WUROS（2.5层）的外壳裤，适合户外入门到进阶使用。防水设计，接缝密封以减少水从针脚渗入。内侧触感干爽，贴肤也保持清爽穿着感。面料：40D/80D Taslan尼龙WUROS（2.5层）。设计与功能：裤脚至膝下的开合拉链，可在不脱鞋的情况下穿脱；腰部抽绳便于调节尺寸；裤脚抽绳便于调节，提升步伐灵活性。推荐场景：登山、徒步、远足。材质/技术：防水、泼水、防风；WUROS为耐久性提升、较不易发生水解的防水透湿材料。随附收纳袋，便于压缩携带。', '【在庫取り寄せあり】アウトドアエントリーから活用しやすい、洗濯耐久性を備えた防水透湿素材「WUROS（2.5層）」を採用したシェルパンツ 特徴 ・縫い目からの水の浸入を抑えたシームシーリング加工を施した防水仕様・内側はドライタッチで、肌に触れてもサラッとした着用感 素材 ・40Dリサイクルナイロンリップストップ WUROS（2.5層）を使用 機能・デザイン・容量 ・裾から膝下まで開閉するファスナーでシューズを履いたまま着脱が可能・ウエストはサイズ調整しやすいスピンドル仕様・足さばきがしやすい裾ドローコード仕様 おすすめシーン ・登山・トレッキング・ハイキングご注文について・Goldwin Online Store 一部店舗 限定販売 {\"素材/テクノロジー\": [{\"Waterproof\": \"防水機能\"}, {\"Water Resistant\": \"はっ水機能\"}, {\"Windproof\": \"防風機能\"}, {\"Stuff Sack\": \"収納用のスタッフサックが付属。コンパクトに収納して持ち運び可能。\"}, {\"WUROS\": \"従来のポリウレタン皮膜より加水分解が起こりにくい、耐久性を向上させた防水透湿素材。\"}], \"適したアクティビティ\": []}', '27500.0 JPY', 1677.50, 0, 0, 0, '', 0, 0, '', '2026-03-19 02:05:19', '2026-03-24 15:15:34', 'thenorthface_NPW12616', '', '69c1eb7c9c7a25981489138c', '徒步/登山，攀岩', '', '女', '青年（18-44岁）', '锦纶100%', 'https://www.goldwin.co.jp/ap/item/i/m/NPW12616', '下装', '冲锋裤', '防水冲锋裤', '', 'waterproof pants', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/the_north_face/20260319/GDW01_A0GDW0001P1S_02_V901.jpg', 0, 0, 1, 0.99519, 0, -2, 0, 0, 0, 3, NULL, '防水，防风，透气，泼水，接缝密封（防止针孔渗水），裤脚至膝下拉链便于穿脱，腰部抽绳便于调节，裤脚抽绳提升步伐灵活性，附带收纳袋，便于压缩携带，耐久性提升（抗水解）', '泼水,接缝密封（防止针孔渗水）,裤脚至膝下拉链便于穿脱,腰部抽绳便于调节,裤脚抽绳提升步伐灵活性,附带收纳袋，便于压缩携带,耐久性提升（抗水解）', 'WUROS防水透湿材料（2.5层）,接缝压胶/封胶（Seam Sealing）,收纳袋（Stuff Sack）', '40D/80D Taslan尼龙面料,2.5层结构,内侧干爽触感，贴肤舒适,防撕裂织物结构,适合登山、徒步、远足等户外场景', '品牌标识，纯色', '该产品为户外外层壳裤，采用WUROS 2.5层防水透湿材料并进行接缝压胶，具备防水、防风特性，且支持穿着登山鞋快速穿脱，明显属于“waterproof pants（防水裤）”。定义：防水裤——以防水透湿面料为主体并通过接缝密封等工艺实现防雨防风的外层裤装，用于徒步、登山等户外活动。', 0, 0, 0, 0, 'waterproof pants', NULL, '', 0, NULL, 0, NULL, NULL, 'color_V901', 'ブラック', 0);
INSERT INTO `clothing_info` VALUES (19986557, '壳层手套（男女通用）', 'シェルグローブ（ユニセックス）', 0, 31750121, 'THE NORTH FACE', '', '', '兼顾操作灵活性与防水性能的轻量化壳层手套。特点：三指分趾设计提升操控性；内侧采用3D打印结构，提升皮肤离面性；接缝贴胶，实现防水。面料与材质：采用THE NORTH FACE自研防水透湿材料HYVENT 2.5层结构。功能与设计：支持智能手机等触控屏操作。推荐场景：登山。', '【在庫取り寄せあり】操作性と防水性を両立した軽量なシェルグローブ 特徴 ・操作性がいいスリーフィンガータイプ・肌面は肌離れがいい3Dプリント仕様・縫い目をシーリングした防水仕様 生地・素材 ・THE NORTH FACE独自の防水透湿素材「HYVENT」2.5層を採用 機能・デザイン ・スマートフォンなどのタッチスクリーン対応 おすすめシーン ・登山SIZE TABLE {\"素材/テクノロジー\": [{\"HYVENT\": \"ポリウレタンコーティングやラミネートによる防水透湿性を有した素材。\"}, {\"Waterproof\": \"防水機能\"}, {\"SMART PHONE\": \"スマートフォンが操作可能。\"}], \"適したアクティビティ\": [\"ライフスタイル\"]}', '9900.0 JPY', 603.90, 0, 0, 0, '', 0, 0, '', '2026-03-23 09:54:51', '2026-03-25 15:45:53', 'thenorthface_NN12600', '', '69c32628b1d84b40f2ef2d0f', '徒步/登山', '', '通用', '青年（18-44岁）', '锦纶100%', 'https://www.goldwin.co.jp/ap/item/i/m/NN12600', '配饰', '手套', NULL, '', 'waterproof gloves', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/the_north_face/20260325/GDW01_A0GDW0001NI8_02_D880.jpg', 0, 0, 9, 0.44553, 0, 1, 0, 0, 0, 3, NULL, '防水，透气，触控屏兼容，三指分趾设计提升操作性，接缝封胶提高防水性', '触控屏兼容,三指分趾设计提升操作性,接缝封胶提高防水性', 'HYVENT防水透湿技术,聚氨酯层压膜,3D打印内层结构,触屏技术', '轻量化设计,2.5层防水透湿结构,内侧3D打印提升肌肤离面性,三指分趾造型提升操控性,接缝封胶工艺', '纯色，点，品牌标识', '该产品为户外壳层手套，强调“防水透湿（HYVENT 2.5层）”与“接缝封胶”以及“登山”使用场景，并具备“三指分趾设计”和“触屏兼容”等功能，核心属性是防水手套，最契合“waterproof gloves”。定义：waterproof gloves——采用防水材料或层压膜与密封工艺，旨在在潮湿环境下保持手部干燥的手套，常用于户外活动。', 1, 0, 0, 0, 'waterproof gloves', NULL, '', 0, NULL, 0, NULL, NULL, 'color_D880', 'クレスグリーン', 0);
INSERT INTO `clothing_info` VALUES (19986558, '壳层手套（男女通用）', 'シェルグローブ（ユニセックス）', 0, 31750121, 'THE NORTH FACE', '', '', '兼顾操作灵活性与防水性能的轻量化壳层手套。特点：三指分趾设计提升操控性；内侧采用3D打印结构，提升皮肤离面性；接缝贴胶，实现防水。面料与材质：采用THE NORTH FACE自研防水透湿材料HYVENT 2.5层结构。功能与设计：支持智能手机等触控屏操作。推荐场景：登山。', '【在庫取り寄せあり】操作性と防水性を両立した軽量なシェルグローブ 特徴 ・操作性がいいスリーフィンガータイプ・肌面は肌離れがいい3Dプリント仕様・縫い目をシーリングした防水仕様 生地・素材 ・THE NORTH FACE独自の防水透湿素材「HYVENT」2.5層を採用 機能・デザイン ・スマートフォンなどのタッチスクリーン対応 おすすめシーン ・登山SIZE TABLE {\"素材/テクノロジー\": [{\"HYVENT\": \"ポリウレタンコーティングやラミネートによる防水透湿性を有した素材。\"}, {\"Waterproof\": \"防水機能\"}, {\"SMART PHONE\": \"スマートフォンが操作可能。\"}], \"適したアクティビティ\": [\"ライフスタイル\"]}', '9900.0 JPY', 603.90, 0, 0, 0, '', 0, 0, '', '2026-03-23 09:54:51', '2026-03-25 15:45:54', 'thenorthface_NN12600', '', '69c32628b1d84b40f2ef2d0f', '徒步/登山', '', '通用', '青年（18-44岁）', '锦纶100%', 'https://www.goldwin.co.jp/ap/item/i/m/NN12600', '配饰', '手套', NULL, '', 'waterproof gloves', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/the_north_face/20260325/GDW01_A0GDW0001NI8_02_V901.jpg', 0, 0, 9, 0.44954, 0, 1, 0, 0, 0, 3, NULL, '防水，透气，触控屏兼容，三指分趾设计提升操作性，接缝封胶提高防水性', '触控屏兼容,三指分趾设计提升操作性,接缝封胶提高防水性', 'HYVENT防水透湿技术,聚氨酯层压膜,3D打印内层结构,触屏技术', '轻量化设计,2.5层防水透湿结构,内侧3D打印提升肌肤离面性,三指分趾造型提升操控性,接缝封胶工艺', '纯色，点，品牌标识', '该产品为户外壳层手套，强调“防水透湿（HYVENT 2.5层）”与“接缝封胶”以及“登山”使用场景，并具备“三指分趾设计”和“触屏兼容”等功能，核心属性是防水手套，最契合“waterproof gloves”。定义：waterproof gloves——采用防水材料或层压膜与密封工艺，旨在在潮湿环境下保持手部干燥的手套，常用于户外活动。', 1, 1, 0, 0, 'waterproof gloves', NULL, '', 0, NULL, 0, NULL, NULL, 'color_V901', 'ブラック', 0);
INSERT INTO `clothing_info` VALUES (19991841, '阿奇卡特', 'アチキャット', 0, 31750121, 'THE NORTH FACE', '', '', '利用Ultra面料的特性打造的2WAY相机包，可肩背亦可作为雨盖安装，适用于极地远征等严苛环境中的拍摄。材质特点：采用轻量且耐用的Ultra面料；相机仓使用具缓冲性的面料。功能与设计：背面口袋可收纳相机以外的小型工具；可作为雨盖安装；可与Etah 40（NM62560）联结。推荐场景：徒步与拍摄、伴随拍摄的极地或远征、雪山拍摄。适用活动：徒步/远足。', '【在庫取り寄せあり】Ultraファブリックの特性を生かし、極地の遠征においての撮影でも使用可能なショルダーと雨蓋の２WAY仕様のカメラバッグ特徴Ultraファブリックの特性を生かし、極地の遠征においての撮影でも使用可能なショルダーと雨蓋の２WAY仕様のカメラバッグ生地・素材・軽量性と耐久性が特徴のUltraファブリックを使用・気室内にカメラをクッション性のある生地を使用機能・デザイン・容量・カメラ以外の小さな道具を収納できる背面ポケット・雨蓋としても取付可能な仕様・Etah 40(NM62560)と連結可能おすすめシーン・トレッキング＆撮影・撮影の伴う極地や遠征・雪山での撮影ご注文について・Goldwin Online Store 一部店舗 限定販売・店舗受取り注文についてはご利用いただけません {\"素材/テクノロジー\": [], \"適したアクティビティ\": [\"トレッキング/ ハイキング\"]}', '16500.0 JPY', 1006.50, 0, 0, 0, '', 0, 0, '', '2026-03-25 10:14:14', '2026-03-27 06:48:23', 'thenorthface_NM62563', '', '69c430ceb9ef4746cd2dbfd0', '徒步/登山', '', '通用', '青年（18-44岁）', NULL, 'https://www.goldwin.co.jp/ap/item/i/m/NM62563', '其他服饰/物品', '其他', '配件', '', 'accessories', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/the_north_face/20260326/GDW01_A0GDW0001QYB_02_BD77.jpg', 0, 0, 9, 0.53138, 0, 1, 0, 0, 0, 3, NULL, '轻量，耐用，缓冲保护，两用肩带与雨盖，背面口袋收纳，可与Etah 40连接', '轻量,耐用,缓冲保护,两用肩带与雨盖,背面口袋收纳,可与Etah 40连接', 'Ultra 面料', '相机隔层采用具缓冲性的面料以保护设备,背面口袋可收纳相机以外的小工具,包体可作为雨盖安装形成2WAY使用,可与Etah 40（NM62560）联结使用', '钻石', '选择“accessories”。定义：Accessories 指非服装的配件类产品，如包袋等。该产品为肩带与雨盖两用的相机包，属于包类配件，并非服装、家纺或其他家居纺织品，因此归入配件类（accessories）。', 0, 0, 0, 0, 'accessories', NULL, '', 0, NULL, 0, NULL, NULL, 'color_BD77', 'シールグレー', 0);
INSERT INTO `clothing_info` VALUES (19991838, 'Base Camp 实用托特包（通用款）', 'ベースキャンプユーティリティートート（ユニセックス）', 0, 31750121, 'THE NORTH FACE', '', '', '采用耐用材质，实用性出色的托特包。特点：手提与肩背两用；结构易于自立，便于取放。面料：具备泼水性与耐磨性的1000旦TPE涂层聚酯材质。功能与设计：大容量；丰富的口袋；内侧配有带钥匙夹的网袋；左右两侧提手；雏菊链。推荐场景：日常使用。', '【在庫取り寄せあり】耐久性のある素材を採用し実用性に優れたトートバッグ特徴・手持ちも肩掛けもできる2WAY仕様・荷物の出し入れが容易な自立しやすい設計生地・素材・はっ水性と耐摩耗性に優れた1000デニールのTPEコーティングポリエステル素材機能・デザイン・容量・豊富なポケット・内側にキークリップ付きメッシュポケット・左右にキャリーハンドル・デイジーチェーンおすすめシーン・日常シーンご注文について・Goldwin Online Store 一部店舗 限定販売・店舗受取り注文についてはご利用いただけません {\"素材/テクノロジー\": [], \"適したアクティビティ\": [\"ライフスタイル\"]}', '13200.0 JPY', 805.20, 0, 0, 0, '', 0, 0, '', '2026-03-25 10:14:17', '2026-03-27 06:48:20', 'thenorthface_NM72635R', '', '69c430ceb9ef4746cd2dbfce', '生活/休闲', '', '通用', '青年（18-44岁）', '再生涤纶100%', 'https://www.goldwin.co.jp/ap/item/i/m/NM72635R', '其他服饰/物品', '其他', '配件', '', 'accessories', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/the_north_face/20260326/GDW01_A0GDW0001PNZ_02_BD75.jpg', 0, 0, 9, 0.99522, 0, 1, 1, 0, 0, 3, NULL, '防水，耐磨损，结构可自立，便于取放，双提手2WAY携带（手提/肩背），多口袋收纳，内侧网袋带钥匙夹，左右侧提手，雏菊链挂点', '耐磨损,结构可自立，便于取放,双提手2WAY携带（手提/肩背）,多口袋收纳,内侧网袋带钥匙夹,左右侧提手,雏菊链挂点', 'TPE涂层,高旦数（1000D）面料,再生聚酯纤维,再生尼龙', '采用耐久材料与加厚织物提升实用性,大容量设计,外部与内部均设有多个收纳隔层,品牌Logo局部印刷装饰,适合日常通勤与城市使用', '纯色，品牌标识', '该产品为托特包（非服装、非家纺），主要用于携带物品，具备2WAY手提/肩背设计与多口袋收纳，明确属于配件类而非衣物类别。选择“accessories（配件）”更准确地描述其产品类型；“accessories”定义：非服装的随身与功能性附属品（如包袋、帽子、手套等）。', 1, 0, 0, 0, 'accessories', NULL, '', 0, NULL, 0, NULL, NULL, 'color_BD75', 'ホワイトアッシュ×カルカッタ×ペールカーキ', 0);
