INSERT INTO `clothing_info` VALUES (19991840, 'Base Camp 实用托特包（通用款）', 'ベースキャンプユーティリティートート（ユニセックス）', 0, 31750121, 'THE NORTH FACE', '', '', '采用耐用材质，实用性出色的托特包。特点：手提与肩背两用；结构易于自立，便于取放。面料：具备泼水性与耐磨性的1000旦TPE涂层聚酯材质。功能与设计：大容量；丰富的口袋；内侧配有带钥匙夹的网袋；左右两侧提手；雏菊链。推荐场景：日常使用。', '【在庫取り寄せあり】耐久性のある素材を採用し実用性に優れたトートバッグ特徴・手持ちも肩掛けもできる2WAY仕様・荷物の出し入れが容易な自立しやすい設計生地・素材・はっ水性と耐摩耗性に優れた1000デニールのTPEコーティングポリエステル素材機能・デザイン・容量・豊富なポケット・内側にキークリップ付きメッシュポケット・左右にキャリーハンドル・デイジーチェーンおすすめシーン・日常シーンご注文について・Goldwin Online Store 一部店舗 限定販売・店舗受取り注文についてはご利用いただけません {\"素材/テクノロジー\": [], \"適したアクティビティ\": [\"ライフスタイル\"]}', '13200.0 JPY', 805.20, 0, 0, 0, '', 0, 0, '', '2026-03-25 10:14:17', '2026-03-27 06:48:22', 'thenorthface_NM72635R', '', '69c430ceb9ef4746cd2dbfce', '生活/休闲', '', '通用', '青年（18-44岁）', '再生涤纶100%', 'https://www.goldwin.co.jp/ap/item/i/m/NM72635R', '其他服饰/物品', '其他', '配件', '', 'accessories', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/the_north_face/20260326/GDW01_A0GDW0001PNZ_02_X152.jpg', 0, 0, 9, 0.99031, 0, 1, 0, 0, 0, 3, NULL, '防水，耐磨损，结构可自立，便于取放，双提手2WAY携带（手提/肩背），多口袋收纳，内侧网袋带钥匙夹，左右侧提手，雏菊链挂点', '耐磨损,结构可自立，便于取放,双提手2WAY携带（手提/肩背）,多口袋收纳,内侧网袋带钥匙夹,左右侧提手,雏菊链挂点', 'TPE涂层,高旦数（1000D）面料,再生聚酯纤维,再生尼龙', '采用耐久材料与加厚织物提升实用性,大容量设计,外部与内部均设有多个收纳隔层,品牌Logo局部印刷装饰,适合日常通勤与城市使用', '纯色，品牌标识', '该产品为托特包（非服装、非家纺），主要用于携带物品，具备2WAY手提/肩背设计与多口袋收纳，明确属于配件类而非衣物类别。选择“accessories（配件）”更准确地描述其产品类型；“accessories”定义：非服装的随身与功能性附属品（如包袋、帽子、手套等）。', 1, 2, 0, 0, 'accessories', NULL, '', 0, NULL, 0, NULL, NULL, 'color_X152', 'ブラック×アスファルトグレー', 0);
INSERT INTO `clothing_info` VALUES (19991837, 'Bonnie SR 2WAY迷你托特包', 'ボニーSR 2WAYトートミニ', 0, 31750121, 'THE NORTH FACE', '', '', '来自THE NORTH FACE Korea Collection，兼具都市与精致气质的2WAY迷你托特包。采用具有光泽感的防撕裂格纹尼龙面料，可肩背或手提。主仓内设拉链口袋，背面配拉链口袋；前部配D形环可悬挂小物；金属材质的品牌标识。适合日常使用。', '都会的かつ洗練されたムードのアイテムで、韓国独自のクリエイションを追求したTHE NORTH FACE Korea Collection。上品な光沢感が際立つ2WAY仕様のミニトート。 特徴 ・ショルダーとハンドバッグの2WAY仕様 素材 ・光沢感のあるリップストップナイロン素材 機能・デザイン・容量 ・容量4L・メイン気室内にファスナーポケット・背面にファスナー付きポケット・フロントに小物を取り付け可能なDカン・メタル素材のロゴ おすすめシーン ・日常シーンご注文について・Goldwin Online Store 限定販売・店舗受取り注文についてはご利用いただけません {\"素材/テクノロジー\": [], \"適したアクティビティ\": [\"ライフスタイル\"]}', '8250.0 JPY', 503.25, 0, 0, 0, '', 0, 0, '', '2026-03-25 10:14:18', '2026-03-27 06:48:20', 'thenorthface_NM82618WL', '', '69c430ceb9ef4746cd2dbfcb', '生活/休闲', '', '通用', '青年（18-44岁）', '锦纶100%', 'https://www.goldwin.co.jp/ap/item/i/m/NM82618WL', '其他服饰/物品', '其他', '配件', '', 'accessories', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/the_north_face/20260326/GDW01_A0GDW0001RCN_02_V944.jpg', 0, 0, 1, 0.88517, 0, -2, 0, 0, 0, 3, NULL, '肩背与手提2WAY使用，多口袋收纳设计，前部D形环可挂载小物，主仓内置拉链口袋，背面拉链口袋', '肩背与手提2WAY使用,多口袋收纳设计,前部D形环可挂载小物,主仓内置拉链口袋,背面拉链口袋', '', '采用具有光泽感的防撕裂尼龙（ripstop nylon）面料,金属材质品牌标识,韩国系列设计，都市精致风格', '纯色', '该产品为“肩背/手提两用的迷你托特包”，属于包类配饰而非服装、家纺等。在提供的子类别列表中没有“托特包/手袋”的专门分类，最匹配的是“accessories”。“accessories”的定义：用于搭配或实用的非服装类物品，如包袋、腰带、帽饰等。', 0, 0, 0, 0, 'accessories', NULL, '', 0, NULL, 0, NULL, NULL, 'color_V944', 'ホワイト', 0);
INSERT INTO `clothing_info` VALUES (19991836, 'Eta 40', 'エタ 40', 0, 31750121, 'THE NORTH FACE', '', '', '利用 Ultra 面料的特性打造，兼具耐久性与收纳性，适用于极地远征拍摄的专业相机包。特点：适配山野/野外环境的高端相机背包；在严苛环境下可同时携带器材与安全装备；兼顾轻量与耐久；便于相机收纳与取出的仓体布局。面料与材料：主材采用轻量且耐久的 Ultra 面料；气室内衬采用高可视性材料。功能、设计与容量：上部设有卷口封闭的快速取物仓；主相机仓可从背面开启并快速访问；采用固定式分隔结构，减少器材偏移；仓内配有用于相机与周边设备的多种口袋；相机仓翻盖配有 PC 夹层；前仓可容纳雪崩装备；包底设有副仓，便于收纳衣物等多类物品；副仓翻盖内标配雨罩；侧袋可放置水瓶或三脚架；可与 Achicat（NM62563）作为雨盖进行联结。推荐场景：徒步与摄影；伴随拍摄的极地与远征；雪山拍摄。', '【在庫取り寄せあり】Ultraファブリックの特性を生かし、極地遠征での撮影にも対応する耐久性と収納性を備えたカメラバッグ特徴・バックカントリー対応のプレミアムカメラパック・過酷な環境下でも機材と安全装備を持ち運ぶことが可能・軽量性と耐久性を両立・カメラの収納と取り出しがしやすいコンパートメント設計生地・素材・軽量性と耐久性に優れたUltraファブリックをメイン素材に使用・視認性の高い裏地を気室内に使用機能・デザイン・容量・すぐ取り出したいものを収納するのに便利な、バック上部に設けられたロールトップクロージャー仕様のコンパートメント・背面オープンでアクセス可能なメインのカメラ気室・機材の偏りが発生しにくい固定式ディバイダーを採用・気室内にはカメラや周辺機器を細かく収納できるポケットを配置・カメラ気室のフラップにPCスリーブ・アバランチギアも入るフロントコンパートメント・パック底面にウエア類など多様なアイテムの収納に便利なサブ気室を配備・サブ気室のフラップにレインカバーを標準装備・ボトルや三脚を収納できるサイドポケット・Achicat（NM62563）を雨蓋として連結可能おすすめシーン・トレッキング＆撮影・撮影の伴う極地や遠征・雪山での撮影ご注文について・Goldwin Online Store 一部店舗 限定販売・店舗受取り注文についてはご利用いただけません {\"素材/テクノロジー\": [], \"適したアクティビティ\": [\"トレッキング/ ハイキング\"]}', '60500.0 JPY', 3690.50, 0, 0, 0, '', 0, 0, '', '2026-03-25 10:14:19', '2026-03-27 06:48:19', 'thenorthface_NM62560', '', '69c430ceb9ef4746cd2dbfc0', '徒步/登山', '', '女', '青年（18-44岁）', NULL, 'https://www.goldwin.co.jp/ap/item/i/m/NM62560', '其他服饰/物品', '其他', '配件', '', 'accessories', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/the_north_face/20260326/GDW01_A0GDW0001QY9_02_BD77.jpg', 0, 0, 9, 0.98765, 0, 1, 0, 0, 0, 3, NULL, '防水，抗撕裂，背面开口主相机仓便捷取用，上部卷口封闭的快速取物仓，固定式分隔结构减少器材偏移，相机与周边设备的精细分隔口袋，相机仓翻盖内置PC夹层，前仓可收纳雪崩装备，底部副仓便于收纳衣物等物品，侧袋可收纳水瓶或三脚架，标配独立雨罩，可与 Achicat（NM62563）作为雨盖联结', '背面开口主相机仓便捷取用,上部卷口封闭的快速取物仓,固定式分隔结构减少器材偏移,相机与周边设备的精细分隔口袋,相机仓翻盖内置PC夹层,前仓可收纳雪崩装备,底部副仓便于收纳衣物等物品,侧袋可收纳水瓶或三脚架,标配独立雨罩,可与 Achicat（NM62563）作为雨盖联结', 'Ultra 面料技术,Achicat（NM62563）联结设计', '主材使用轻量且高耐久的 Ultra 面料,气室内采用高可视性内衬，便于快速识别物品,兼顾轻量与耐久的整体设计,适用于极地远征与雪山环境中的摄影携行,具备大容量与多分区的专业相机背包结构', '纯色', '该产品为用于携带摄影器材的相机背包，属于包类随身配件，非服装或家纺。枚举列表中没有“背包/相机包”选项，因此选择最贴近的“accessories”。定义：accessories（配件）指非服装的随身用品与功能性附属品，如包袋、帽袜手套等。', 0, 0, 0, 0, 'accessories', NULL, '', 0, NULL, 0, NULL, NULL, 'color_BD77', 'シールグレー', 0);
INSERT INTO `clothing_info` VALUES (19991832, 'Eta 30', 'エタ 30', 0, 31750121, 'THE NORTH FACE', '', '', '利用Ultra面料的特性，具备适应极地远征拍摄的耐久性与收纳能力的相机背包。特点：适用于山野滑雪等背乡环境的高端相机包；在恶劣条件下可同时携带影像器材与安全装备；兼顾轻量与耐久；相机仓分隔与开口设计便于收纳与快速取用。面料：主材采用轻量且耐用的Ultra面料；气室内采用高可视度内衬。功能与设计：顶部设快取仓；主相机仓可从背面开启；采用固定式分隔板，降低器材偏移；气室内设置多口袋以细分收纳相机及配件；相机仓翻盖带PC电脑隔层；前置仓可收纳雪崩装备；底部配副仓以容纳衣物等多种物品；副仓翻盖标配雨罩；侧袋可装水瓶或三脚架；可与Achicat（NM62563）连接作为雨盖。推荐场景：徒步与拍摄；极地或远征拍摄；雪山拍摄。', '【在庫取り寄せあり】Ultraファブリックの特性を生かし、極地遠征での撮影にも対応する耐久性と収納性を備えたカメラバッグ特徴・バックカントリー対応のプレミアムカメラパック・過酷な環境下でも機材と安全装備を持ち運ぶことが可能・軽量性と耐久性を両立・カメラの収納と取り出しがしやすいコンパートメント設計生地・素材・軽量性と耐久性に優れたUltraファブリックをメイン素材に使用・視認性の高い裏地を気室内に使用機能・デザイン・容量・すぐ取り出したいものを収納するのに便利な、バック上部に設けられたコンパートメント・背面オープンでアクセス可能なメインのカメラ気室・機材の偏りが発生しにくい固定式ディバイダーを採用・気室内にはカメラや周辺機器を細かく収納できるポケットを配置・カメラ気室のフラップにPCスリーブ・アバランチギアも入るフロントコンパートメント・パック底面にウエア類など多様なアイテムの収納に便利なサブ気室を配備・サブ気室のフラップにレインカバーを標準装備・ボトルや三脚を収納できるサイドポケット・Achicat（NM62563）を雨蓋として連結可能おすすめシーン・トレッキング＆撮影・撮影の伴う極地や遠征・雪山での撮影ご注文について・Goldwin Online Store 一部店舗 限定販売・店舗受取り注文についてはご利用いただけません {\"素材/テクノロジー\": [], \"適したアクティビティ\": [\"トレッキング/ ハイキング\"]}', '49500.0 JPY', 3019.50, 0, 0, 0, '', 0, 0, '', '2026-03-25 10:14:21', '2026-03-27 06:48:14', 'thenorthface_NM62561', '', '69c430ceb9ef4746cd2dbfb9', '徒步/登山，冰雪运动', '', '通用', '青年（18-44岁）', NULL, 'https://www.goldwin.co.jp/ap/item/i/m/NM62561', '其他服饰/物品', '其他', '配件', '', 'accessories', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/the_north_face/20260326/GDW01_A0GDW0001QYA_02_BD77.jpg', 0, 0, 9, 0.99715, 0, 1, 0, 0, 0, 3, NULL, '背面开口主相机仓，快速取放相机，固定式分隔板，减少器材偏移，相机与周边设备的多口袋细分收纳，相机仓翻盖设有PC电脑隔层，前置仓可收纳雪崩安全装备，底部副仓可装衣物等多种物品，副仓翻盖自带雨罩，侧袋可装水瓶或三脚架，上部快取仓便于随手物品，与Achicat（NM62563）可联结作为雨盖', '背面开口主相机仓，快速取放相机,固定式分隔板，减少器材偏移,相机与周边设备的多口袋细分收纳,相机仓翻盖设有PC电脑隔层,前置仓可收纳雪崩安全装备,底部副仓可装衣物等多种物品,副仓翻盖自带雨罩,侧袋可装水瓶或三脚架,上部快取仓便于随手物品,与Achicat（NM62563）可联结作为雨盖', 'Ultra面料', '内衬采用高可视度颜色，便于查看内容物,兼顾轻量与耐久的总体设计,为极地与高山越野拍摄环境而设的结构布局', '品牌标识，纯色', '该产品为用于户外拍摄的相机背包，属于包类配件而非服装或家纺。在提供的子类别列表中未包含“backpack/包”的专门选项，最贴近的是“accessories”。选择“accessories”的原因：它泛指服饰配件与随身用品（如包、帽、手套等），用于辅助穿搭或承载物品，定义为“用于搭配或携带的配件类产品”。', 0, 0, 0, 0, 'accessories', NULL, '', 0, NULL, 0, NULL, NULL, 'color_BD77', 'シールグレー', 0);
INSERT INTO `clothing_info` VALUES (19991833, '幼童长袖 TNF Be Free 图案T恤（儿童）', 'トドラーロングスリーブTNFビーフリーグラフィックティー（キッズ）', 0, 31750121, 'THE NORTH FACE', '', '', '采用具备通气性与快速干燥特性的聚酯鹿子（珠地）针织面料，轻盈舒适，并经过防虫处理使虫不易靠近。配备UV PROTECT功能（UPF50+），有效阻隔有害紫外线，提供皮肤防护。BREEZERANGE材料通过促进衣内空气循环来减轻闷热，带来清爽舒适的穿着体验。背部配有大幅方形Logo图案，左胸为Logo印花，适合户外与生活方式场景。', '【在庫取り寄せあり】通気性とUVカット機能を備えた素材に虫よけ加工を施した、高機能長袖Tシャツのトドラーモデル 特徴 ・軽量で速乾性を備えた鹿の子編みの生地・UVプロテクト（UPF50+、紫外線カット率95%以上）機能付き 生地・素材 ・通気性があり乾きやすいポリエステル素材・虫が近寄りにくい加工 機能・デザイン ・背面に大きくスクエアロゴのグラフィックを配置・左胸にロゴプリント おすすめシーン ・アウトドア・ライフスタイル {\"素材/テクノロジー\": [{\"With Relief\": \"ナノテクノロジー技術により肌への優しさと耐久性を両立した虫よけ機能をもつテキスタイル。子どもから大人まで幅広く使用できる。\"}, {\"UV PROTECT\": \"強い日差しに対応。UPF50+、UVカット率95％以上を確保。\"}, {\"BREEZERANGE\": \"通気とUVカットの機能を備えた素材。衣服内の空気の循環を助け蒸れを軽減し、UVカット機能により太陽光からの有害な紫外線を遮断し肌を保護する。涼しく快適な着用感を実現。\"}], \"適したアクティビティ\": [\"ライフスタイル\"]}', '5610.0 JPY', 342.21, 0, 0, 0, '', 0, 0, '', '2026-03-25 10:14:21', '2026-03-27 06:48:15', 'thenorthface_NTT12636', '', '69c430ceb9ef4746cd2dbfc1', '生活/休闲', '', '通用', '婴幼儿（0-3岁）', '涤纶44%', 'https://www.goldwin.co.jp/ap/item/i/m/NTT12636', '上装', 'T恤', 'T恤', '', 't-shirt', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/the_north_face/20260326/GDW01_A0GDW0001NO5_02_AF12.jpg', 0, 0, 1, 0.72191, 0, -2, 0, 0, 0, 3, NULL, '透气，速干，防紫外线，防蚊虫，轻量，促进衣内空气循环，减少闷热感', '轻量,促进衣内空气循环,减少闷热感', 'With Relief 纳米防虫技术,UV PROTECT 防紫外线技术,BREEZERANGE 通气与防紫外线材料', '幼童长袖款式，适合日常与户外穿着,背部大面积方形Logo图案，左胸Logo印花,采用再生聚酯材质，环保,鹿子（珠地）针织结构，手感清爽、透气良好', '品牌标识', '该产品为幼童款长袖上衣，描述明确为“長袖Tシャツ”，且以针织面料制作并带有图案印花，最符合“t-shirt”类别。选择的子类别：t-shirt。定义：t-shirt 指以针织面料制成的休闲上衣（可为短袖或长袖），通常为圆领或其他简洁领型，常配有印花或图案，适合日常穿着。', 1, 0, 0, 0, 't-shirt', NULL, '', 0, NULL, 0, NULL, NULL, 'color_AF12', 'ホワイトデューン', 0);
INSERT INTO `clothing_info` VALUES (19991834, '幼童长袖 TNF Be Free 图案T恤（儿童）', 'トドラーロングスリーブTNFビーフリーグラフィックティー（キッズ）', 0, 31750121, 'THE NORTH FACE', '', '', '采用具备通气性与快速干燥特性的聚酯鹿子（珠地）针织面料，轻盈舒适，并经过防虫处理使虫不易靠近。配备UV PROTECT功能（UPF50+），有效阻隔有害紫外线，提供皮肤防护。BREEZERANGE材料通过促进衣内空气循环来减轻闷热，带来清爽舒适的穿着体验。背部配有大幅方形Logo图案，左胸为Logo印花，适合户外与生活方式场景。', '【在庫取り寄せあり】通気性とUVカット機能を備えた素材に虫よけ加工を施した、高機能長袖Tシャツのトドラーモデル 特徴 ・軽量で速乾性を備えた鹿の子編みの生地・UVプロテクト（UPF50+、紫外線カット率95%以上）機能付き 生地・素材 ・通気性があり乾きやすいポリエステル素材・虫が近寄りにくい加工 機能・デザイン ・背面に大きくスクエアロゴのグラフィックを配置・左胸にロゴプリント おすすめシーン ・アウトドア・ライフスタイル {\"素材/テクノロジー\": [{\"With Relief\": \"ナノテクノロジー技術により肌への優しさと耐久性を両立した虫よけ機能をもつテキスタイル。子どもから大人まで幅広く使用できる。\"}, {\"UV PROTECT\": \"強い日差しに対応。UPF50+、UVカット率95％以上を確保。\"}, {\"BREEZERANGE\": \"通気とUVカットの機能を備えた素材。衣服内の空気の循環を助け蒸れを軽減し、UVカット機能により太陽光からの有害な紫外線を遮断し肌を保護する。涼しく快適な着用感を実現。\"}], \"適したアクティビティ\": [\"ライフスタイル\"]}', '5610.0 JPY', 342.21, 0, 0, 0, '', 0, 0, '', '2026-03-25 10:14:21', '2026-03-27 06:48:16', 'thenorthface_NTT12636', '', '69c430ceb9ef4746cd2dbfc1', '生活/休闲', '', '通用', '婴幼儿（0-3岁）', '涤纶44%', 'https://www.goldwin.co.jp/ap/item/i/m/NTT12636', '上装', 'T恤', 'T恤', '', 't-shirt', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/the_north_face/20260326/GDW01_A0GDW0001NO5_02_BB90.jpg', 0, 0, 1, 0.73262, 0, -2, 0, 0, 0, 3, NULL, '透气，速干，防紫外线，防蚊虫，轻量，促进衣内空气循环，减少闷热感', '轻量,促进衣内空气循环,减少闷热感', 'With Relief 纳米防虫技术,UV PROTECT 防紫外线技术,BREEZERANGE 通气与防紫外线材料', '幼童长袖款式，适合日常与户外穿着,背部大面积方形Logo图案，左胸Logo印花,采用再生聚酯材质，环保,鹿子（珠地）针织结构，手感清爽、透气良好', '品牌标识', '该产品为幼童款长袖上衣，描述明确为“長袖Tシャツ”，且以针织面料制作并带有图案印花，最符合“t-shirt”类别。选择的子类别：t-shirt。定义：t-shirt 指以针织面料制成的休闲上衣（可为短袖或长袖），通常为圆领或其他简洁领型，常配有印花或图案，适合日常穿着。', 1, 1, 0, 0, 't-shirt', NULL, '', 0, NULL, 0, NULL, NULL, 'color_BB90', 'オパールフロスト', 0);
