INSERT INTO `clothing_info` VALUES (19991829, '幼童TNF Be Free裤（儿童）', 'トドラーTNFビーフリーパンツ（キッズ）', 0, 31750121, 'THE NORTH FACE', '', '', '采用兼具通气性与UV防护的面料，并进行防虫处理的3WAY高功能幼童长裤。面料轻盈顺滑，表面设有通气孔，提升透气性并帮助保持体感凉爽。配备UV GUARD（UPF30-50+，紫外线遮蔽率90%以上）功能。通过With Relief纳米技术实现兼顾亲肤与耐久性的防虫能力，为户外使用提供保护。左右设大容量侧袋，便于营地收纳。裤脚与口袋下配有暗扣，可将裤脚上翻后固定，亦可通过扣合收紧裤口，灵活调整裤长与轮廓。适合露营与户外玩耍等多种场景。并采用BREEZERANGE科技，促进衣内空气循环，减少闷热，带来清凉舒适的穿着体验。', '【在庫取り寄せあり】通気性とUVカット機能を備えた素材に虫よけ加工を施した、3WAY仕様の高機能パンツのトドラーモデル。軽くなめらかな生地は、表面の通気孔により熱がこもりにくく、高い通気性が特徴。衣服内を適温に保ちます。UVガード（UPF30-50＋、紫外線カット率90％以上）機能付き。肌へのやさしさと耐久性を両立した虫よけ加工により、アウトドアシーンで虫から子供の肌を守ります。太めのシルエットで、キャンプ時に必要な道具を収納できる大容量のサイドポケットを左右に配置。川遊びなどで裾をまくり上げることができるよう、裾とポケット下にドットボタンを配しており、裾とポケット下のボタンを留めることで、まくり上げた裾がずり落ちないよう固定することができます。また、裾同士のドットボタンを留めることで裾を絞ることが可能。丈やシルエットを変更することができます。キャンプや外遊びなど、幅広いシーンで活躍する1着です。 {\"素材/テクノロジー\": [{\"With Relief\": \"ナノテクノロジー技術により肌への優しさと耐久性を両立した虫よけ機能をもつテキスタイル。子どもから大人まで幅広く使用できる。\"}, {\"UV GUARD\": \"屋外でのスポーツや長時間の外出に対応。UPF30-50＋、UVカット率90%以上を確保。\"}, {\"BREEZERANGE\": \"通気とUVカットの機能を備えた素材。衣服内の空気の循環を助け蒸れを軽減し、UVカット機能により太陽光からの有害な紫外線を遮断し肌を保護する。涼しく快適な着用感を実現。\"}], \"適したアクティビティ\": [\"ライフスタイル\"]}', '10450.0 JPY', 637.45, 0, 0, 0, '', 0, 0, '', '2026-03-25 10:14:22', '2026-03-27 06:48:12', 'thenorthface_NBT32552', '', '69c430ceb9ef4746cd2dbfb8', '露营，生活/休闲', '', '通用', '婴幼儿（0-3岁）', '涤纶41%', 'https://www.goldwin.co.jp/ap/item/i/m/NBT32552', '下装', '冲锋裤', '登山裤', '', 'hiking pants', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/the_north_face/20260326/GDW01_A0GDW0001HSW_02_BC52.jpg', 0, 0, 1, 0.99128, 0, -2, 0, 0, 0, 3, NULL, '透气，防紫外线，防蚊虫，温度调节，3WAY版型调节，大容量侧袋，裤脚可上翻并固定，裤脚可收紧', '3WAY版型调节,大容量侧袋,裤脚可上翻并固定,裤脚可收紧', 'With Relief,UV GUARD,BREEZERANGE', '面料表面设有通气孔，增强空气循环与凉爽感,宽松版型，便于活动,左右大容量侧袋，适合露营与外出收纳,下摆及口袋下配有暗扣，支持翻折固定与收紧下摆,适用于露营、外出玩耍等多场景', '品牌标识，纯色', '该款为幼童户外功能长裤，具备通气、UV防护与防虫等户外特性，并强调露营与外出玩耍场景，版型宽松且带大容量侧袋与可调节下摆，符合“hiking pants”的特征。选择的子类：hiking pants。定义：适用于徒步/露营等户外活动的功能性长裤，通常采用耐用、透气、防晒等技术面料，并配备多口袋及可调节细节，以提升户外穿着的实用性与舒适性。', 1, 0, 0, 0, 'hiking pants', NULL, '', 0, NULL, 0, NULL, NULL, 'color_BC52', 'ディープシーコーラル', 0);
INSERT INTO `clothing_info` VALUES (19991830, '幼童TNF Be Free裤（儿童）', 'トドラーTNFビーフリーパンツ（キッズ）', 0, 31750121, 'THE NORTH FACE', '', '', '采用兼具通气性与UV防护的面料，并进行防虫处理的3WAY高功能幼童长裤。面料轻盈顺滑，表面设有通气孔，提升透气性并帮助保持体感凉爽。配备UV GUARD（UPF30-50+，紫外线遮蔽率90%以上）功能。通过With Relief纳米技术实现兼顾亲肤与耐久性的防虫能力，为户外使用提供保护。左右设大容量侧袋，便于营地收纳。裤脚与口袋下配有暗扣，可将裤脚上翻后固定，亦可通过扣合收紧裤口，灵活调整裤长与轮廓。适合露营与户外玩耍等多种场景。并采用BREEZERANGE科技，促进衣内空气循环，减少闷热，带来清凉舒适的穿着体验。', '【在庫取り寄せあり】通気性とUVカット機能を備えた素材に虫よけ加工を施した、3WAY仕様の高機能パンツのトドラーモデル。軽くなめらかな生地は、表面の通気孔により熱がこもりにくく、高い通気性が特徴。衣服内を適温に保ちます。UVガード（UPF30-50＋、紫外線カット率90％以上）機能付き。肌へのやさしさと耐久性を両立した虫よけ加工により、アウトドアシーンで虫から子供の肌を守ります。太めのシルエットで、キャンプ時に必要な道具を収納できる大容量のサイドポケットを左右に配置。川遊びなどで裾をまくり上げることができるよう、裾とポケット下にドットボタンを配しており、裾とポケット下のボタンを留めることで、まくり上げた裾がずり落ちないよう固定することができます。また、裾同士のドットボタンを留めることで裾を絞ることが可能。丈やシルエットを変更することができます。キャンプや外遊びなど、幅広いシーンで活躍する1着です。 {\"素材/テクノロジー\": [{\"With Relief\": \"ナノテクノロジー技術により肌への優しさと耐久性を両立した虫よけ機能をもつテキスタイル。子どもから大人まで幅広く使用できる。\"}, {\"UV GUARD\": \"屋外でのスポーツや長時間の外出に対応。UPF30-50＋、UVカット率90%以上を確保。\"}, {\"BREEZERANGE\": \"通気とUVカットの機能を備えた素材。衣服内の空気の循環を助け蒸れを軽減し、UVカット機能により太陽光からの有害な紫外線を遮断し肌を保護する。涼しく快適な着用感を実現。\"}], \"適したアクティビティ\": [\"ライフスタイル\"]}', '10450.0 JPY', 637.45, 0, 0, 0, '', 0, 0, '', '2026-03-25 10:14:22', '2026-03-27 06:48:13', 'thenorthface_NBT32552', '', '69c430ceb9ef4746cd2dbfb8', '露营，生活/休闲', '', '通用', '婴幼儿（0-3岁）', '涤纶41%', 'https://www.goldwin.co.jp/ap/item/i/m/NBT32552', '下装', '冲锋裤', '登山裤', '', 'hiking pants', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/the_north_face/20260326/GDW01_A0GDW0001HSW_02_BC54.jpg', 0, 0, 1, 0.92121, 0, -2, 0, 0, 0, 3, NULL, '透气，防紫外线，防蚊虫，温度调节，3WAY版型调节，大容量侧袋，裤脚可上翻并固定，裤脚可收紧', '3WAY版型调节,大容量侧袋,裤脚可上翻并固定,裤脚可收紧', 'With Relief,UV GUARD,BREEZERANGE', '面料表面设有通气孔，增强空气循环与凉爽感,宽松版型，便于活动,左右大容量侧袋，适合露营与外出收纳,下摆及口袋下配有暗扣，支持翻折固定与收紧下摆,适用于露营、外出玩耍等多场景', '品牌标识，纯色', '该款为幼童户外功能长裤，具备通气、UV防护与防虫等户外特性，并强调露营与外出玩耍场景，版型宽松且带大容量侧袋与可调节下摆，符合“hiking pants”的特征。选择的子类：hiking pants。定义：适用于徒步/露营等户外活动的功能性长裤，通常采用耐用、透气、防晒等技术面料，并配备多口袋及可调节细节，以提升户外穿着的实用性与舒适性。', 1, 1, 0, 0, 'hiking pants', NULL, '', 0, NULL, 0, NULL, NULL, 'color_BC54', 'クレスグリーン', 0);
