INSERT INTO `clothing_info` VALUES (19991825, 'TNF标志卡车帽（男女同款）', 'TNFロゴトラッカーキャップ（ユニセックス）', 0, 31750121, 'THE NORTH FACE', '', '', '这是一款作为街头休闲经典款而广受欢迎的棒球帽。特点：前幅TNF标志刺绣是设计亮点。推荐场景：日常生活、户外。', '【再入荷通知・在庫取り寄せあり】ストリートカジュアルの定番キャップとして人気の高いベースボールキャップ。特徴・フロントに配置したTNFロゴ刺繍がデザインのアクセント。おすすめシーンライフスタイル、アウトドアご注文について・Goldwin Online Store 一部店舗 限定販売 {\"素材/テクノロジー\": [], \"適したアクティビティ\": []}', '6050.0 JPY', 369.05, 0, 0, 0, '', 0, 0, '', '2026-03-25 10:14:23', '2026-03-27 06:48:09', 'thenorthface_NN02634R', '', '69c430ceb9ef4746cd2dbfb5', '生活/休闲', '', '通用', '青年（18-44岁）', '棉100%', 'https://www.goldwin.co.jp/ap/item/i/m/NN02634R', '配饰', '帽子', NULL, '', 'baseball cap', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/the_north_face/20260326/GDW01_A0GDW0001PQ9_02_BC41.jpg', 0, 0, 9, 0.93463, 0, 1, 0, 0, 0, 3, NULL, '', '', '', '前幅TNF标志刺绣作为视觉亮点,经典棒球帽版型，街头休闲风格,男女同款设计', '品牌标识', '产品为“TNFロゴトラッカーキャップ（ユニセックス）”，描述中明确为街头休闲定番的“ベースボールキャップ”，并有弯曲帽檐与前幅Logo刺绣，符合棒球帽的典型结构与风格。综合文本与图片判断，选择“baseball cap”。定义：baseball cap（棒球帽）指具有弯曲帽檐、结构化帽冠，常见前幅装饰（如刺绣Logo）的休闲帽款，适用于日常与户外穿戴。', 1, 0, 0, 0, 'baseball cap', NULL, '', 0, NULL, 0, NULL, NULL, 'color_BC41', 'フォリッジグリーン', 0);
