INSERT INTO `clothing_info` VALUES (19991820, '水陆两用七分裤（儿童）', 'ウォーターサイドクロップドパンツ（キッズ）', 0, 31750121, 'THE NORTH FACE', '', '', '适用于徒步、露营及水上运动的水陆两用儿童七分裤。膝下长度便于户外活动，腰部采用滑动式抽绳，方便孩子自行调节。配备UV防护（UPF50+，紫外线阻隔率95%以上）。面料为双层织尼龙，贴肤面为疏水性聚丙烯，具备弹性。左脚口有品牌标志刺绣。推荐使用场景：户外、日常生活。科技/功能：防泼水、UV PROTECT（UPF50+）。', '【在庫取り寄せあり】ハイキングやキャンプ、ウォータースポーツまで幅広く対応する水陸両用、クロップド丈の水陸両用パンツ 特徴 ・アウトドアシーンで活用しやすい膝下丈・ウエストは子どもが自分で調節しやすいスライド式のスピンドル仕様・UVプロテクト（UPF50+、紫外線カット率95%以上）機能付き 生地・素材 ・二重織りのナイロン、肌面に疎水性のポリプロピレンを使用したストレッチ性のある生地 機能・デザイン ・左裾にロゴ刺繍 おすすめシーン ・アウトドア・ライフスタイル {\"素材/テクノロジー\": [{\"Water Resistant\": \"はっ水機能\"}, {\"UV PROTECT\": \"強い日差しに対応。UPF50+、UVカット率95％以上を確保。\"}], \"適したアクティビティ\": [\"ライフスタイル\"]}', '7150.0 JPY', 436.15, 0, 0, 0, '', 0, 0, '', '2026-03-25 10:14:25', '2026-03-27 06:48:04', 'thenorthface_NBJ42630', '', '69c430ceb9ef4746cd2dbfab', '露营，徒步/登山，水上运动，生活/休闲', '', '通用', '儿童（4-12岁）', '锦纶86%,丙纶9%,氨纶5%', 'https://www.goldwin.co.jp/ap/item/i/m/NBJ42630', '下装', '休闲裤', '七分裤', '', 'capris', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/the_north_face/20260326/GDW01_A0GDW0001NEX_02_BC51.jpg', 0, 0, 1, 0.98558, 0, -2, 0, 0, 0, 3, NULL, '防紫外线，防水，高弹力，水陆两用，滑动式抽绳腰部便于儿童自我调节，膝下裁剪长度便于活动', '水陆两用,滑动式抽绳腰部便于儿童自我调节,膝下裁剪长度便于活动', 'UV PROTECT（UPF50+）,防泼水处理', '双层织尼龙结构，贴肤面采用疏水性聚丙烯,面料具有弹性，提升活动舒适度,左脚口有品牌标志刺绣', '纯色，品牌标识', '产品名称与描述明确为“クロップド丈（膝下丈）”的儿童户外裤，属于介于短裤与长裤之间的裁剪长度；与“capris”定义（膝下至小腿中段的九/七分长度裤型）一致，且非泳裤或标准短裤。因此选择子类：capris。定义：capris——长度至膝下至小腿中段的裁剪裤型，常用于休闲与运动场景。', 1, 0, 0, 0, 'capris', NULL, '', 0, NULL, 0, NULL, NULL, 'color_BC51', 'ダスクブルー', 0);
