INSERT INTO `clothing_info` VALUES (19991824, '幼童印花轻便夹克（儿童）', 'トドラーノベルティコンパクトジャケット（キッズ）', 0, 31750121, 'THE NORTH FACE', '', '', '这是一款适合户外与日常穿着、可应对恶劣天气的壳式夹克，是 THE NORTH FACE 经典防风外套的幼童版本。特色：以 1970 年代风格的明信片插画进行全身印花。帽子可通过按扣拆卸，拆下后可将按扣收纳于领内。面料：采用经防泼水处理的尼龙材质。功能与设计：两侧拉链口袋，袖口魔术贴调节贴合度，品牌标志刺绣。推荐场景：生活方式、户外。材质/技术：NORTH TECH CLOTH——化纤却具有棉感，轻盈且易收纳；Water Resistant——防泼水。适用活动：生活方式。', '【在庫取り寄せあり】アウトドアから日常まで悪天候に対応できるシェルジャケット。THE NORTH FACE定番のウインドブレーカーのトドラーモデル 特徴 ・1970年代風ポストカードのイラストを全体にあしらったノベルティカラー・フードはスナップボタンで取り外し可能、外したときはボタンを襟の内側にしまうことができる 生地・素材 ・はっ水加工を施したナイロン素材 機能・デザイン ・両サイドにファスナーポケット・袖口は面ファスナーでフィット感の調節が可能・ロゴ刺繍 おすすめシーン ・ライフスタイル・アウトドア {\"素材/テクノロジー\": [{\"NORTH TECH CLOTH\": \"化学繊維でありながらもコットンのような風合いが特徴。軽量、コンパクト性に優れている。\"}, {\"Water Resistant\": \"はっ水機能\"}], \"適したアクティビティ\": [\"ライフスタイル\"]}', '10450.0 JPY', 637.45, 0, 0, 0, '', 0, 0, '', '2026-03-25 10:14:25', '2026-03-27 06:48:08', 'thenorthface_NPT22511', '', '69c430ceb9ef4746cd2dbfaf', '生活/休闲', '', '通用', '婴幼儿（0-3岁）', '锦纶100%', 'https://www.goldwin.co.jp/ap/item/i/m/NPT22511', '上装', '冲锋衣', '防风衣', '', 'windbreaker', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/the_north_face/20260326/GDW01_A0GDW0001LNT_02_BC47.jpg', 0, 0, 1, 0.99997, 0, -2, 0, 0, 0, 3, NULL, '防风，防泼水，可拆卸帽，袖口可调节，轻量，易收纳，拉链口袋，品牌刺绣标识', '防泼水,可拆卸帽,袖口可调节,轻量,易收纳,拉链口袋,品牌刺绣标识', 'NORTH TECH CLOTH 面料,防泼水（Water Resistant）', '1970年代风格明信片插画全身印花,幼童版型,按扣可拆卸帽，按扣可收纳于领内,袖口魔术贴调节贴合度,两侧拉链口袋,化纤面料具棉感，轻盈且便于收纳', '物体，文字', '该产品为儿童壳式外套，采用尼龙机织面料并具备防风、防泼水功能，配有可拆卸帽与拉链口袋，定位为轻薄外层抵御风雨的功能性夹克，符合“windbreaker”的特征。选择的子类：windbreaker。定义：windbreaker——以轻薄机织面料为主，注重防风与基础防泼水的外套，适用于户外与日常的轻度气候防护。', 0, 0, 0, 0, 'windbreaker', NULL, '', 0, NULL, 0, NULL, NULL, 'color_BC47', 'ポストカードオパールフロスト', 0);
INSERT INTO `clothing_info` VALUES (19996825, '马克笔涂鸦马克杯', 'マーカーマグ', 0, 200335, 'GEORGE’S', '', '', '这是一款可以将孩子的插画直接保留在杯身上的马克笔涂鸦马克杯。使用方法非常简单，只需用套装内的马克笔在杯子上画画，再用水冲洗即可，让孩子轻松创作只属于自己的专属马克杯。非常适合作为母亲节、父亲节等重要日子的礼物。', 'ーーー<br>子どものイラストをそのままマグカップに残すことのできるマーカー付きマグカップです。<br>作り方はとても簡単！<br>セットのマーカーでマグカップにお絵かきをして、水で洗い流すだけ。<br>簡単に世界に一つだけのマグカップを作ることができます。<br>母の日や父の日など、大切な日のギフトにもおすすめです。<br>ーーー', '1500.0 JPY', 91.50, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:08:56', '2026-04-02 04:20:21', 'adastria_366286', '', '69cd72d8a7ab618f2967ccbc', '生活/休闲', '', '通用', '儿童（4-12岁）', '陶器100%', 'https://www.dot-st.com/georges/disp/item/366286/?COLOR_CD=00', '其他服饰/物品', '其他', '配件', '', 'accessories', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/george’s/20260401/item_366286_main_00_1738568581_b.jpg', 0, 0, 9, 0.89803, 0, 1, 0, 0, 0, 3, NULL, '可反复绘画，可清洗再创作，适合作为礼物', '可反复绘画,可清洗再创作,适合作为礼物', '', '陶瓷材质,附带6色马克笔,适合孩子在杯子上自由创作,可制作独一无二的图案杯', '纯色，纯色', '该产品是一款带马克笔的陶瓷马克杯，属于家居生活类的小物件和礼品配件，不是服装、床品、窗帘等纺织品，因此在提供的分类中最接近的是“accessories（配饰/杂项用品）”。accessories 在此可理解为包含杯子等非服装的小物品。', 0, 0, 0, 0, 'accessories', NULL, '', 0, NULL, 0, NULL, NULL, '00', 'ホワイト(01)', 0);
INSERT INTO `clothing_info` VALUES (19996820, '水培花器 80mm', 'アクアカルチャーベース 80mm', 0, 200335, 'GEORGE’S', '', '', '这是一款可以欣赏植物在水中生长全过程的花器“AQUA CULTURE VASE”。由上下两部分构成，上部托盘支撑香草等叶片的生长，并能稳固承托风信子等球根类或牛油果等种子。对于多肉、仙人掌等较为脆弱的植物，更换水时无需直接触碰植物，同时便于观赏在水中伸展的根系。', '<b>のびのびと育つ葉、水のなかで広がる根、植物のすべてを愉しむ</b><br>ーーー<br>植物が水の中で育っていく美しい過程を愉しめる花器 AQUA CULTURE VASE。<br>ーーー<br>さまざまな植物の成長や手入れのしやすさを考慮し、2つのパーツで構成しています。<br>上部の受け皿はハーブなどの葉の成長をサポートし、ヒヤシンスなどの球根類やアボカドなどの種が安定して収まる形状です。<br>多肉植物やサボテンなど繊細な植物には直接触れることなく、水の交換ができます。<br><br><br>', '1800.0 JPY', 109.80, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:08:58', '2026-04-02 04:20:17', 'adastria_742663', '', '69cd72d8a7ab618f2967ccac', '生活/休闲', '', '通用', '青年（18-44岁）', 'ソーダガラス100%', 'https://www.dot-st.com/georges/disp/item/742663/?COLOR_CD=01', '其他服饰/物品', '其他', '配件', '', 'accessories', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/george’s/20260401/item_742663_main_01_1774596135_b.jpg', 0, 0, 9, 0.94832, 0, 1, 0, 0, 0, 3, NULL, '装饰摆件，室内绿植水培容器', '装饰摆件,室内绿植水培容器', '', '由两部分结构组成，上部托盘支撑叶片、球根或种子，下部为蓄水容器,适合水培香草、球根花卉、多肉等多种植物,便于观察植物在水中生长的根系变化,更换水分时可避免直接接触脆弱植物', '纯色，纯色', '商品为“アクアカルチャーベース（水培花器）”，图片与描述均为玻璃花瓶/花器类家居杂物，并非服装、床品或窗帘等纺织品。给定类目中最接近的是“accessories”，可涵盖此类家居用小物。sub_category: accessories，对应定义为非服装主体的配饰或家居小物。', 1, 0, 0, 0, 'accessories', NULL, '', 0, NULL, 0, NULL, NULL, '01', 'クリア(01)', 0);
INSERT INTO `clothing_info` VALUES (19996821, '水培花器 80mm', 'アクアカルチャーベース 80mm', 0, 200335, 'GEORGE’S', '', '', '这是一款可以欣赏植物在水中生长全过程的花器“AQUA CULTURE VASE”。由上下两部分构成，上部托盘支撑香草等叶片的生长，并能稳固承托风信子等球根类或牛油果等种子。对于多肉、仙人掌等较为脆弱的植物，更换水时无需直接触碰植物，同时便于观赏在水中伸展的根系。', '<b>のびのびと育つ葉、水のなかで広がる根、植物のすべてを愉しむ</b><br>ーーー<br>植物が水の中で育っていく美しい過程を愉しめる花器 AQUA CULTURE VASE。<br>ーーー<br>さまざまな植物の成長や手入れのしやすさを考慮し、2つのパーツで構成しています。<br>上部の受け皿はハーブなどの葉の成長をサポートし、ヒヤシンスなどの球根類やアボカドなどの種が安定して収まる形状です。<br>多肉植物やサボテンなど繊細な植物には直接触れることなく、水の交換ができます。<br><br><br>', '1800.0 JPY', 109.80, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:08:58', '2026-04-02 04:20:17', 'adastria_742663', '', '69cd72d8a7ab618f2967ccac', '生活/休闲', '', '通用', '青年（18-44岁）', 'ソーダガラス100%', 'https://www.dot-st.com/georges/disp/item/742663/?COLOR_CD=01', '其他服饰/物品', '其他', '配件', '', 'accessories', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/george’s/20260401/item_742663_main_80_1774596138_b.jpg', 0, 0, 9, 0.99478, 0, 1, 0, 0, 0, 3, NULL, '装饰摆件，室内绿植水培容器', '装饰摆件,室内绿植水培容器', '', '由两部分结构组成，上部托盘支撑叶片、球根或种子，下部为蓄水容器,适合水培香草、球根花卉、多肉等多种植物,便于观察植物在水中生长的根系变化,更换水分时可避免直接接触脆弱植物', '纯色，纯色', '商品为“アクアカルチャーベース（水培花器）”，图片与描述均为玻璃花瓶/花器类家居杂物，并非服装、床品或窗帘等纺织品。给定类目中最接近的是“accessories”，可涵盖此类家居用小物。sub_category: accessories，对应定义为非服装主体的配饰或家居小物。', 1, 1, 0, 0, 'accessories', NULL, '', 0, NULL, 0, NULL, NULL, '80', 'ブルー(80)', 0);
INSERT INTO `clothing_info` VALUES (19996822, '5号 带托盘 Botany植物花盆', '5号 受皿付 ボタニーポット', 0, 200335, 'GEORGE’S', '', '', '具有复古感的陶瓷植木盆。以“BOTANY”立体标志为亮点，配色带有一点怀旧气息。可通过不同尺寸的搭配，或更换颜色来组合花盆与托盘，享受与植物一起进行搭配布置的乐趣。底部带排水孔，并配有托盘。', 'ーーー<br>ビンテージ感のあるセラミックの植木鉢です。<br><br>BOTANYのロゴがポイントの陶器ポット。<br>どことなくビンテージっぽいカラーリングが特徴です。<br>ーーー<br>サイズ違いで揃えたり、カラー違いでポットとソーサーの組み合わせをたのしんだり、<br>植物とのコーディネートを楽しめるアイテムです。<br>※底穴あり / 受皿付き<br><br>▼4号サイズはこちら<br>⇒アプリからご覧の方は<a href=\'adastriaapp://item?itemCode=364123\'>こちら</a><br>⇒ブラウザからご覧の方は<a href=\'https://www.dot-st.com/georges/disp/item/364123/\'>こちら</a>', '1800.0 JPY', 109.80, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:08:58', '2026-04-02 04:20:18', 'adastria_363892', '', '69cd72d8a7ab618f2967ccb1', '生活/休闲', '', '通用', '青年（18-44岁）', 'セラミック100%', 'https://www.dot-st.com/georges/disp/item/363892/?COLOR_CD=70', '其他服饰/物品', '其他', '配件', '', 'accessories', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/george’s/20260401/item_363892_main_70_1738832468_b.jpg', 0, 0, 9, 0.98099, 0, 1, 0, 0, 0, 3, NULL, '家居装饰，栽种植物使用', '家居装饰,栽种植物使用', '', '带排水底孔和配套托盘，方便养护植物,表面有BOTANY立体标志，提升装饰感,做旧感配色，营造复古氛围,可与不同尺寸、颜色组合搭配', '纯色，纯色', '该商品为“セラミックの植木鉢”“陶器ポット”，属于家居园艺类小物，而非服装或家纺主体。现有分类里没有专门的花盆、绿植用品类目，最接近的是可涵盖各类搭配小物、生活配件的“accessories”。因此将其归为“accessories（配饰/杂配类）”，定义为：非主体服装或家纺、用于搭配或装饰空间与造型的附属类商品。', 1, 0, 0, 0, 'accessories', NULL, '', 0, NULL, 0, NULL, NULL, '70', 'グリーン(70)', 0);
INSERT INTO `clothing_info` VALUES (19996823, '5号 带托盘 Botany植物花盆', '5号 受皿付 ボタニーポット', 0, 200335, 'GEORGE’S', '', '', '具有复古感的陶瓷植木盆。以“BOTANY”立体标志为亮点，配色带有一点怀旧气息。可通过不同尺寸的搭配，或更换颜色来组合花盆与托盘，享受与植物一起进行搭配布置的乐趣。底部带排水孔，并配有托盘。', 'ーーー<br>ビンテージ感のあるセラミックの植木鉢です。<br><br>BOTANYのロゴがポイントの陶器ポット。<br>どことなくビンテージっぽいカラーリングが特徴です。<br>ーーー<br>サイズ違いで揃えたり、カラー違いでポットとソーサーの組み合わせをたのしんだり、<br>植物とのコーディネートを楽しめるアイテムです。<br>※底穴あり / 受皿付き<br><br>▼4号サイズはこちら<br>⇒アプリからご覧の方は<a href=\'adastriaapp://item?itemCode=364123\'>こちら</a><br>⇒ブラウザからご覧の方は<a href=\'https://www.dot-st.com/georges/disp/item/364123/\'>こちら</a>', '1800.0 JPY', 109.80, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:08:58', '2026-04-02 04:20:19', 'adastria_363892', '', '69cd72d8a7ab618f2967ccb1', '生活/休闲', '', '通用', '青年（18-44岁）', 'セラミック100%', 'https://www.dot-st.com/georges/disp/item/363892/?COLOR_CD=70', '其他服饰/物品', '其他', '配件', '', 'accessories', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/george’s/20260401/item_363892_main_50_1738832347_b.jpg', 0, 0, 9, 0.94243, 0, 1, 0, 0, 0, 3, NULL, '家居装饰，栽种植物使用', '家居装饰,栽种植物使用', '', '带排水底孔和配套托盘，方便养护植物,表面有BOTANY立体标志，提升装饰感,做旧感配色，营造复古氛围,可与不同尺寸、颜色组合搭配', '纯色，纯色', '该商品为“セラミックの植木鉢”“陶器ポット”，属于家居园艺类小物，而非服装或家纺主体。现有分类里没有专门的花盆、绿植用品类目，最接近的是可涵盖各类搭配小物、生活配件的“accessories”。因此将其归为“accessories（配饰/杂配类）”，定义为：非主体服装或家纺、用于搭配或装饰空间与造型的附属类商品。', 1, 1, 0, 0, 'accessories', NULL, '', 0, NULL, 0, NULL, NULL, '50', 'ベージュ(50)', 0);
INSERT INTO `clothing_info` VALUES (19996824, '生砂糖 400g / 鴻商店', '生砂糖 400g / 鴻商店', 0, 200332, 'TODAY’S SPECIAL', '', '', '生砂糖是从鹿儿岛县萨南诸岛收获的优质甘蔗中仅提取糖分制成的未精制纯砂糖。颗粒较粗且湿润，呈棕色颗粒，外观给人营养丰富的印象。由于未精制，表面仍保留类似黑糖风味的蜜分，甜味上品，并具有独特的旨味和醇厚感，同时富含维生素和矿物质等营养成分。生砂糖非常容易溶解，适合用于饮品，也适合用于需要增加醇厚感的炖煮料理等。原产国：日本（大阪）。', '<!--ーーー--><br>鹿児島県薩南諸島で収穫された良質のサトウキビから糖分だけを採り出した未精製の純粋な砂糖が生砂糖です。<br>粗めでしっとりとした茶色い粒子が、見た目にも栄養たっぷりといった感じです。<br><br>未精製なので、表面にまだ黒砂糖風味の蜜分が残っていますが、上品な甘さで、独特のうま味とコクを持ち合わせています。<br>ビタミンやミネラル、旨味を豊富に含んでいるのも特徴です。<br>「生砂糖」は非常に溶けやすいので飲み物はもちろんのこと、コクを出したい煮物などのお料理にも活躍します。<br><br><br>原産国 : 日本(大阪)<!--ーーー--><br>内容量 : 400g<br><br><b>\"鴻商店\"アイテム一覧はこちら</b><br><a href=\"https://www.dot-st.com/todaysspecial/disp/itemlist/?dispNo=002005283\" target=\"_blank\"><font size=\"2\" color=\"blue\">ブラウザでみる</a></font></b> | <a href=\"adastriaapp://items?dispNo=0000100084_002005283&orderBy=00\" target=\"_blank\"><font size=\"2\" color=\"blue\">アプリでみる</a></font></b><br><b>\"砂糖\"アイテム一覧はこちら</b><br><a href=\"https://www.dot-st.com/todaysspecial/disp/itemlist/?dispNo=002005432\" target=\"_blank\"><font size=\"2\" color=\"blue\">ブラウザでみる</a></font></b> | <a href=\"adastriaapp://items?dispNo=0000100084_002005432&orderBy=00\" target=\"_blank\"><font size=\"2\" color=\"blue\">アプリでみる</a></font></b><br><br>', '450.0 JPY', 27.45, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:08:58', '2026-04-02 04:20:20', 'adastria_455637', '', '69cd72d8a7ab618f2967ccb0', '生活/休闲', '', '通用', '青年（18-44岁）', NULL, 'https://www.dot-st.com/todaysspecial/disp/item/455637/?COLOR_CD=00', '其他服饰/物品', '其他', '配件', '', 'accessories', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/today’s_special/20260401/item_455637_main_00_1774252019_b.jpg', 0, 0, 9, 0.96670, 0, 1, 1, 0, 0, 3, NULL, '营养丰富，易溶解，提升菜肴风味和醇厚感', '营养丰富,易溶解,提升菜肴风味和醇厚感', '', '采用鹿儿岛县萨南诸岛产甘蔗制成,未精制保留黑糖风味蜜分,具有上品的甘味和独特旨味与醇厚感,含有丰富维生素和矿物质,适用于饮品和需要增加醇厚感的料理', '纯色，纯色', '商品是“生砂糖”食品，不属于服装或家用纺织品，没有对应的服装/家纺细分类目。为完成结构化输出，只能选择与服饰无直接冲突且最为中性的“accessories”作为占位。此处的“accessories（配饰）”被视为非服装主体的附属类别，用作无法归类为服装纺织品时的技术性分类。', 0, 0, 0, 0, 'accessories', NULL, '', 0, NULL, 0, NULL, NULL, '00', '生砂糖 400g(00)', 0);
INSERT INTO `clothing_info` VALUES (19996799, '簇绒多功能水果杯垫', 'タフトマルチコースター', 0, 200164, 'studio CLIP', '', '', '采用柔软蓬松材质制作的簇绒杯垫，以水果为主题图案设计。不同水果图案对应的尺寸略有差异，整体略偏大，可用于放置茶壶、花瓶等多种物品，既具功能性又具装饰性。产地为中国。由于材质特性，表面绒毛稍有掉毛现象，颜色和尺寸存在一定个体差异属正常现象。', '<b><font color=\"000000\">ふわふわ素材のコースター</font></b><br><br>フルーツモチーフを落とし込んだタフトコースター。<br>サイズはモチーフによって異なりますが、少し大き目に設定しました。<br>ポットや花瓶などの下に敷いたりと色んな使い方ができます。<br><br>■洗濯：不可<br>■原産国：中国<br><br>※洗濯はお避け下さい。<br>※直射日光等により退色する恐れがありますので、お取り扱いにはご注意ください。<br>※色味やサイズに個体差があります。製品の特性としてご理解ください。<br>※素材の性質上、多少毛が抜けやすくなっております。<br><br>ーーー<br>コースター　タフト　フルーツ　マルチ<br>ーーー', '800.0 JPY', 48.80, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:11:34', '2026-04-02 04:19:59', 'adastria_631868', '', '69cd72d7a7ab618f2967cc6a', '生活/休闲', '', '通用', '青年（18-44岁）', '涤纶80%', 'https://www.dot-st.com/studioclip/disp/item/631868/?COLOR_CD=03', '其他服饰/物品', '其他', '配件', '', 'accessories', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/studio_clip/20260401/item_631868_main_03_1770346494_b.jpg', 0, 0, 8, 0.90145, 0, -1, 0, 0, 0, 3, NULL, '桌面装饰，隔热防护，吸附放置物品防滑', '桌面装饰,隔热防护,吸附放置物品防滑', '', '采用水果图案设计，具有装饰性,绒毛感强的蓬松触感,尺寸偏大，可放茶壶或花瓶等物品,不可水洗，需注意日晒褪色和掉毛,可能存在颜色和尺寸个体差异', '花卉图案，其他', '产品是“タフトマルチコースター”，属于桌面用的小型垫片，用于杯子、茶壶、花瓶等下方的摆放和装饰，并非服装或床品等可穿戴或大面积家纺，最接近的类别是在服饰大类中归入“accessories（配件/小物）”。accessories 在这里可泛指非衣服本体的附属小物，与产品性质最吻合。', 1, 0, 0, 0, 'accessories', NULL, '', 0, NULL, 0, NULL, NULL, '03', 'サクランボ03', 0);
INSERT INTO `clothing_info` VALUES (19996800, '簇绒多功能水果杯垫', 'タフトマルチコースター', 0, 200164, 'studio CLIP', '', '', '采用柔软蓬松材质制作的簇绒杯垫，以水果为主题图案设计。不同水果图案对应的尺寸略有差异，整体略偏大，可用于放置茶壶、花瓶等多种物品，既具功能性又具装饰性。产地为中国。由于材质特性，表面绒毛稍有掉毛现象，颜色和尺寸存在一定个体差异属正常现象。', '<b><font color=\"000000\">ふわふわ素材のコースター</font></b><br><br>フルーツモチーフを落とし込んだタフトコースター。<br>サイズはモチーフによって異なりますが、少し大き目に設定しました。<br>ポットや花瓶などの下に敷いたりと色んな使い方ができます。<br><br>■洗濯：不可<br>■原産国：中国<br><br>※洗濯はお避け下さい。<br>※直射日光等により退色する恐れがありますので、お取り扱いにはご注意ください。<br>※色味やサイズに個体差があります。製品の特性としてご理解ください。<br>※素材の性質上、多少毛が抜けやすくなっております。<br><br>ーーー<br>コースター　タフト　フルーツ　マルチ<br>ーーー', '800.0 JPY', 48.80, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:11:34', '2026-04-02 04:20:00', 'adastria_631868', '', '69cd72d7a7ab618f2967cc6a', '生活/休闲', '', '通用', '青年（18-44岁）', '涤纶80%', 'https://www.dot-st.com/studioclip/disp/item/631868/?COLOR_CD=03', '其他服饰/物品', '其他', '配件', '', 'accessories', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/studio_clip/20260401/item_631868_main_02_1770346491_b.jpg', 0, 0, 8, 0.97400, 0, -1, 0, 0, 0, 3, NULL, '桌面装饰，隔热防护，吸附放置物品防滑', '桌面装饰,隔热防护,吸附放置物品防滑', '', '采用水果图案设计，具有装饰性,绒毛感强的蓬松触感,尺寸偏大，可放茶壶或花瓶等物品,不可水洗，需注意日晒褪色和掉毛,可能存在颜色和尺寸个体差异', '花卉图案，其他', '产品是“タフトマルチコースター”，属于桌面用的小型垫片，用于杯子、茶壶、花瓶等下方的摆放和装饰，并非服装或床品等可穿戴或大面积家纺，最接近的类别是在服饰大类中归入“accessories（配件/小物）”。accessories 在这里可泛指非衣服本体的附属小物，与产品性质最吻合。', 1, 1, 0, 0, 'accessories', NULL, '', 0, NULL, 0, NULL, NULL, '02', 'リンゴ02', 0);
INSERT INTO `clothing_info` VALUES (19996798, '【daily CLIP】印度风网眼收纳小包 S', '【daily CLIP】インディアメッシュポーチ Ｓ', 0, 200164, 'studio CLIP', '', '', '充满印度风情的网眼收纳小包。\n采用色彩鲜艳的网眼材质，醒目抢眼。使用有挺度的聚酯纱线，织造略微疏松，呈现印度风格的质感。日常使用之外，也非常适合海边、泳池及夏季旅行等场景使用。', '<b>インドの魅力が詰まったメッシュポーチ</b><br><br>カラフルな色合いが目を惹くメッシュ素材のポーチ。<br>ハリのあるポリエステル糸を使用しており、ややざっくりと織ったインドらしいアイテムです。<br>普段使いはもちろん、海やプール、夏の旅行などにも重宝します◎<br><br>■原産国：インド<br><br>ーーー<br>ポーチ　メッシュ　小物収納　インド<br>ーーー<br><br>', '1500.0 JPY', 91.50, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:11:35', '2026-04-02 04:19:58', 'adastria_412962', '', '69cd72d7a7ab618f2967cc68', '生活/休闲', '', '通用', '青年（18-44岁）', '涤纶100%', 'https://www.dot-st.com/studioclip/disp/item/412962/?COLOR_CD=60', '其他服饰/物品', '其他', '配件', '', 'accessories', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/studio_clip/20260401/item_412962_main_60_1742783803_b.jpg', 0, 0, 9, 0.99526, 0, 1, 0, 0, 0, 3, NULL, '收纳功能', '收纳功能', '', '采用色彩鲜艳的条纹设计，视觉效果醒目,主体为聚酯纤维网布，织造较为疏松，有一定挺括感,口部使用聚氨酯材质，增加装饰性与结构稳定性,适合日常出行及海边、泳池、夏季旅行时携带小物件', '条纹', '从商品描述与图片来看，这是用于收纳小物件的「メッシュポーチ」（网状小包/收纳包），属于配饰类包袋小物，而非服装、床品或窗帘等纺织品。给出的子类列表中没有专门的“pouch/包”选项，最接近且合理的归类是 accessories（配饰类小物）。accessories 在这里可以涵盖钱包、小包、收纳袋等非服装随身小物，因此选择 sub_category: accessories。', 0, 0, 0, 0, 'accessories', NULL, '', 0, NULL, 0, NULL, NULL, '60', 'イエロー60', 0);
INSERT INTO `clothing_info` VALUES (19996796, '方形羊毛毡杯垫/桌面垫', 'スクエアフェルトマット', 0, 200164, 'studio CLIP', '', '', '采用具有温暖质感的羊毛毡材质制作，并配有悬挂用的皮质环。表面点缀配色线条，增添视觉亮点。稍大一些的方形尺寸，可用作杯垫，也能承托椭圆形的烤盘等餐具。亦适合作为花器等摆件下方的装饰垫使用。尼泊尔手工制作，每件成品会有些许差异，属于产品的自然特性。', '<b><font color=\"606060\">ぬくもり感あるフェルト素材のループ付きマット</font></b><br><br>アクセントに配色のラインをあしらいました。<br>いつもより少し大きめなスクエア型で、コースター代わりや<br>オーバルの形状のグラタン皿なども乗せられるデザインです。<br>花器などの下に敷くアクセントマットとしてもおすすめです。<br><br>■ネパール製<br><br>※本製品は手作業のため、一点ずつ仕上がりに個体差があります。製品の特性としてご理解ください。<br><br>ーーー<br>アクセントマット　フェルト<br>ーーー', '800.0 JPY', 48.80, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:11:36', '2026-04-02 04:19:56', 'adastria_150024', '', '69cd72d7a7ab618f2967cc5e', '生活/休闲', '', '通用', '青年（18-44岁）', '羊毛100%', 'https://www.dot-st.com/studioclip/disp/item/150024/?COLOR_CD=60', '其他服饰/物品', '其他', '配件', '', 'accessories', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/studio_clip/20260401/item_150024_main_60_1730353660_b.jpg', 0, 0, 9, 0.75956, 0, -1, 0, 0, 0, 3, NULL, '桌面保护，隔热垫用作餐具垫，装饰点缀', '桌面保护,隔热垫用作餐具垫,装饰点缀', '', '采用羊毛毡材质，具有手工制作质感,方形设计，尺寸略大，可兼作杯垫或小烤盘垫,带挂环设计，便于悬挂收纳,表面有配色线条，增强装饰性,尼泊尔手工制作，每件有轻微差异', '纯色', '该产品是羊毛毡材质的方形桌面垫，用于杯子、小烤盘或花器等餐具下的摆放与装饰，属于餐厨/家居小物件配件，而非服装、床品、窗帘、毛巾、地毯、靠垫或桌布等主件。综合来看最接近列表中的“accessories（配件）”，可理解为家居餐桌类辅助小配件。', 0, 0, 0, 0, 'accessories', NULL, '', 0, NULL, 0, NULL, NULL, '60', 'イエロー60', 0);
INSERT INTO `clothing_info` VALUES (19996797, '复古奶感帕菲杯', 'レトロミルキーパフェカップ', 0, 200164, 'studio CLIP', '', '', '外观清爽的复古喫茶风格帕菲杯。以仿佛复古咖啡厅中出现的造型设计，呈现奶感十足的夏日气息黄配色。只需在日常冰淇淋上加些水果等简单装饰，就能在家轻松营造喫茶店般的氛围。与同系列的复古冰淇淋勺搭配使用更加推荐。采用苏打玻璃制成，非耐热材质，为玻璃制品，使用和收纳时需谨慎轻放。', '<b><font color=\"000000\">見た目も爽やかなパフェカップ</font></b><br><br>レトロ喫茶で出てきそうなパフェカップ。<br>ミルキーな夏らしさがたまらないイエローをご用意しました。<br>いつものアイスにフルーツを乗せるなどひと手間加えることで、手軽にご自宅で喫茶気分が味わえます。<br>一緒に展開しているレトロなアイススプーンと一緒に使うのもおススメです。<br><br>■容量：80ml<br>■電子レンジ、食洗器：不可<br>■原産国：中国<br><br>※耐熱ガラスではございません。<br>※ガラス製のためお取り扱いには十分にご注意ください。<br><br>ーーー<br>夏　パフェ　グラス　食器　テーブルコーディネート　<br>ーーー<br>', '700.0 JPY', 42.70, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:11:36', '2026-04-02 04:19:57', 'adastria_496950', '', '69cd72d7a7ab618f2967cc67', '生活/休闲', '', '通用', '青年（18-44岁）', 'ソーダガラス100%', 'https://www.dot-st.com/studioclip/disp/item/496950/?COLOR_CD=60', '其他服饰/物品', '其他', '配件', '', 'accessories', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/studio_clip/20260401/item_496950_main_60_1751511360_b.jpg', 0, 0, 9, 0.74889, 0, -1, 0, 0, 0, 3, NULL, '家用餐饮使用，桌面装饰氛围营造', '家用餐饮使用,桌面装饰氛围营造', '', '复古喫茶风格外观设计,适合盛放冰淇淋、圣代、甜品等,适合夏季清爽主题搭配,需避免微波炉和洗碗机使用,非耐热玻璃，使用需注意温差与碰撞', '纯色，纯色', '产品为用于盛放冰淇淋和圣代的玻璃“パフェカップ”（甜品杯），属于餐厨小物而非服装或家纺类织物。在给定的服装/配件类枚举中，没有专门的餐具或杯具类别，最接近的是非服装类的通用“accessories（配件）”。因此将其归为 accessories（配件类小物），定义为：搭配和辅助使用的非服装主体小物品。', 0, 0, 0, 0, 'accessories', NULL, '', 0, NULL, 0, NULL, NULL, '60', 'イエロー60', 0);
INSERT INTO `clothing_info` VALUES (19996795, '宽松牛仔夹克', 'ルーズデニムジャケット', 0, 200164, 'studio CLIP', '', '', '袖口异材质拼接是亮点，廓形宽松的牛仔夹克。\n\n【材质】\n选用约10盎司、厚度适中的牛仔面料，既不太重又有一定挺括度。棉质面料触感干爽舒适。\n\n【设计】\n宽松大码轮廓，营造成熟可爱的牛仔夹克造型。下摆及拼接处采用裁剪毛边的流苏设计，增添低调的设计感。袖口拼接灯芯绒面料，翻折露出灯芯绒可以形成造型亮点。宽松剪裁便于内搭多层单品，可长时间跨季节穿着。\n\n【搭配】\n由于是宽松轮廓，内搭建议选择合身上衣或利落下装，打造干练有型的穿搭，也适合搭配连衣裙造型。', '<b><font color=\"000000\">袖口の異素材がポイント<br>ゆったりとしたサイズ感のデニムジャケット</font></b><br>ーーー<br><br>【素材】<br>10オンスくらいの重すぎない程よい厚みのデニムを塩湯。<br>コットンのさらりとした生地感が特徴です。<br><br>【デザイン】<br>BIGサイズが大人可愛いデニムジャケット。<br>裾や切り替え部分は裁ち切りのフリンジデザインになっており、さりげないデザインポイントが◎<br>袖口には異素材のコーデュロイを施しているので、袖口を折り返してコーデュロイを見せたスタイリングもおすすめです。<br>ゆったりとしたサイズ感は中にしっかり着込めるので、長い期間ご着用いただけます。<br><br><br>アウター　デニム　ジャケット　オーバーサイズ　ルーズ<br>　<br>ーーー<br><br>【スタイリング】<br>ルーズシルエットなので、インはジャストなトップスやすっきりめなボトムスと合わせたスタイリッシュな着こなしがおすすめ。<br>ワンピーススタイルにも◎<br>', '7537.0 JPY', 459.76, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:11:53', '2026-04-02 04:19:55', 'adastria_492948', '', '69cd72d7a7ab618f2967cc4d', '生活/休闲', '', '通用', '青年（18-44岁）', '棉100%', 'https://www.dot-st.com/studioclip/disp/item/492948/?COLOR_CD=80', '上装', '牛仔外套', '牛仔夹克', '', 'denim jacket', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/studio_clip/20260401/item_492948_main_80_1758791654_b.jpg', 0, 0, 6, 0.93531, 0, 1, 1, 0, 0, 3, NULL, '保暖性适中，适合长季节穿着', '保暖性适中，适合长季节穿着', '', '10盎司左右适中克重牛仔面料,棉质面料干爽触感,宽松廓形，方便内搭叠穿,下摆和拼接处毛边流苏设计,袖口拼接灯芯绒面料，可翻折露出对比材质,适合搭配连衣裙或修身上衣与利落下装', '纯色', '从商品名“ルーズデニムジャケット”和图片来看，为牛仔面料制作的宽松廓形短外套，属于典型牛仔夹克版型，因此选择 sub_category 中的 “denim jacket（牛仔夹克）”。其定义为：以牛仔布为主要面料、作为外穿上衣的短款夹克类外套。', 0, 0, 0, 0, 'denim jacket', NULL, '', 0, NULL, 0, NULL, NULL, '80', 'ブルー80', 0);
INSERT INTO `clothing_info` VALUES (19996794, '【eL】亮片迷你包', '【eL】Spangle Mini Bag', 0, 31749826, 'JEANASIS', '', '', '闪耀材质营造季节氛围的亮片包。选用高密度满铺亮片的面料，打造圆润可爱的轮廓，同时具备与外观不符的实用收纳容量。随着动作闪闪发光，为整体造型增添亮点。附带两种长度肩带，可根据穿搭自由变换。长肩带可调节长度并可拆卸，短肩带手腕穿戴时呈现如同发圈般的装饰感。既适合日常休闲造型中用作点睛单品，也能胜任派对和正式场合。', 'ーーー<br>煌めく素材がシーズンムードを盛り上げてくれるスパンコールバック<br>ーーー<br><br>-DETAIL-<br>ぎっしりと高密度でスパンコールが施された素材を使用し、コロンとしたフォルムと、見た目に反した収納力が魅力のミニバッグを作りました。<br>動くたびに煌めき、コーディネートのアクセントになってくれます。<br>2種のストラップを付けているため、スタイリングに合わせてアレンジを楽しんでいただけます。<br>ロングストラップは、長さ調整と取り外しが可能。<br>ショートストラップは手首を通すとシュシュを付けたようなデザインが魅力です。<br><br>-STYLING-<br>普段使いでカジュアルなスタイリングの外しに使うのがおすすめです。<br>パーティやフォーマルシーンにも活躍します。', '8000.0 JPY', 488.00, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:12:20', '2026-04-02 04:19:55', 'adastria_249859', '', '69cd72d7a7ab618f2967cc4c', '生活/休闲', '', '通用', '青年（18-44岁）', 'pet(ポリエチレンテレフタレート)ポリエステル100%', 'https://www.dot-st.com/jeanasis/disp/item/249859/?COLOR_CD=12', '其他服饰/物品', '其他', '配件', '', 'accessories', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/jeanasis/20260401/item_249859_main_12_1733914232_b.jpg', 0, 0, 8, 0.68328, 0, 1, 0, 0, 0, 3, NULL, '装饰搭配，收纳物品', '装饰搭配,收纳物品', '', '小巧桶型迷你包造型,高密度满铺亮片设计，具有强烈闪耀效果,配有长短两种肩带，可拆卸与调节长度,短肩带造型类似抓褶发圈，具有装饰性,适合日常造型点缀，也可用于派对和正式场合,表里层均为聚酯纤维材质，手感挺括耐用', '其他', '该商品为手拎/斜挎用的迷你包，从品类上属于包袋配饰，而非服装或家纺产品。在提供的枚举中最接近且合理的类别是“accessories”，其定义可理解为：用于穿搭点缀和实用收纳的非服装类配饰，包括包袋、小物等。本品为亮片迷你包，主要功能是装饰造型和收纳随身物，因此归入“accessories”最为合适。', 0, 0, 0, 0, 'accessories', NULL, '', 0, NULL, 0, NULL, NULL, '12', 'シルバー(12)', 0);
INSERT INTO `clothing_info` VALUES (19996792, '【100%亚麻】亚麻双褶直筒长裤［含小个子・加大尺码］', '【リネン100%】リネンツータックストレートパンツ[プチ・プラスサイズあり]', 0, 200164, 'studio CLIP', '', '', '每年广受好评的100%亚麻系列再次登场，这是一条易于融入各种造型的直筒裤。选用触感柔软、贴合肌肤的亚麻面料，采用素色感的哈克米细格纹组织，使整体更显干练。版型为不过分贴合身体线条的适中宽松直筒轮廓，既能遮掩腿部线条，又保持利落感。腰部前片为平整设计，在保留穿着余量的同时，让腹部区域看起来更加平坦。直筒轮廓易于与各种单品搭配，可从休闲风到优雅通勤风多场合穿着。可与同材质的单排扣亚麻夹克搭配，打造成套穿着风格。', '<b><font color=\"000000\">毎年好評のリネン100%シリーズが今年も登場！<br>スタイリングに取り入れやすいストレートパンツ</font></b><br>ーーー<br><br>【素材】<br>肌馴染みの良い柔らかな風合いが特徴のリネンを使用。<br>無地見えのハケメチェックで綺麗めに仕上げています。<br><br>【デザイン】<br>体の線を拾わない程よい太さのストレートシルエットのリネンパンツ。<br>ベルトフロント部分はフラット仕様で、ゆとりがありながらもお腹周りをすっきりと見せてくれます。<br>アイテム問わず合わせやすいストレートシルエットは、カジュアルから綺麗めまで幅広く着こなせる一着です。<br><br><br>ボトム　パンツ　リネン　セットアップ<br><br>ーーー<br><br>【スタイリング】<br>ブラウス合わせで綺麗めに、カットソー合わせでカジュアルに。<br>同素材の『品番：594166　シングルリネンジャケット』と合わせたセットアップでの着こなしもおすすめです。<br><br><br>■同素材のジャケットはこちら <br><a href=\'https://www.dot-st.com/studioclip/disp/item/594166/\'><b><font color=\"ff1493\">ブラウザ版＞＞＞</font></b></a> <br><a href=\'adastriaapp://item?itemCode=594166\'><b><font color=\"ff1493\">アプリ版＞＞＞</font></b></a> <br>', '6355.0 JPY', 387.65, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:12:21', '2026-04-02 04:19:53', 'adastria_594169', '', '69cd72d7a7ab618f2967cc48', '生活/休闲', '', '女', '青年（18-44岁）', '亚麻100%', 'https://www.dot-st.com/studioclip/disp/item/594169/?COLOR_CD=02', '下装', '西裤', '裤装', '', 'trousers', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/studio_clip/20260401/item_594169_main_02_1773133256_b.jpg', 0, 0, 2, 0.92231, 0, 1, 1, 0, 0, 3, NULL, '透气，凉感穿着感受', '凉感穿着感受', '', '采用100%亚麻材质，质地柔软、亲肤透气,直筒版型与双褶设计，遮掩腿部线条，修饰身形,腰部前片平整设计，视觉上收腹显瘦,可搭配同面料单排扣亚麻西装形成套装造型,哈克米细格纹组织，让面料呈现素色感但更有质感', '其他', '从品名“ストレートパンツ”、品类“パンツ”以及图片呈现的下装版型来看，这是女性直筒长裤，非家纺或其他配饰类产品。英文分类中与之最匹配的是“trousers”，即日常穿着的长裤。trousers 的定义：指覆盖下半身、两条裤筒分开的长裤服装，用于日常或正式场合穿着，本款亚麻直筒裤完全符合该定义。', 1, 0, 0, 0, 'trousers', NULL, '', 0, NULL, 0, NULL, NULL, '02', 'ハケメベージュ02', 0);
INSERT INTO `clothing_info` VALUES (19996793, '【100%亚麻】亚麻双褶直筒长裤［含小个子・加大尺码］', '【リネン100%】リネンツータックストレートパンツ[プチ・プラスサイズあり]', 0, 200164, 'studio CLIP', '', '', '每年广受好评的100%亚麻系列再次登场，这是一条易于融入各种造型的直筒裤。选用触感柔软、贴合肌肤的亚麻面料，采用素色感的哈克米细格纹组织，使整体更显干练。版型为不过分贴合身体线条的适中宽松直筒轮廓，既能遮掩腿部线条，又保持利落感。腰部前片为平整设计，在保留穿着余量的同时，让腹部区域看起来更加平坦。直筒轮廓易于与各种单品搭配，可从休闲风到优雅通勤风多场合穿着。可与同材质的单排扣亚麻夹克搭配，打造成套穿着风格。', '<b><font color=\"000000\">毎年好評のリネン100%シリーズが今年も登場！<br>スタイリングに取り入れやすいストレートパンツ</font></b><br>ーーー<br><br>【素材】<br>肌馴染みの良い柔らかな風合いが特徴のリネンを使用。<br>無地見えのハケメチェックで綺麗めに仕上げています。<br><br>【デザイン】<br>体の線を拾わない程よい太さのストレートシルエットのリネンパンツ。<br>ベルトフロント部分はフラット仕様で、ゆとりがありながらもお腹周りをすっきりと見せてくれます。<br>アイテム問わず合わせやすいストレートシルエットは、カジュアルから綺麗めまで幅広く着こなせる一着です。<br><br><br>ボトム　パンツ　リネン　セットアップ<br><br>ーーー<br><br>【スタイリング】<br>ブラウス合わせで綺麗めに、カットソー合わせでカジュアルに。<br>同素材の『品番：594166　シングルリネンジャケット』と合わせたセットアップでの着こなしもおすすめです。<br><br><br>■同素材のジャケットはこちら <br><a href=\'https://www.dot-st.com/studioclip/disp/item/594166/\'><b><font color=\"ff1493\">ブラウザ版＞＞＞</font></b></a> <br><a href=\'adastriaapp://item?itemCode=594166\'><b><font color=\"ff1493\">アプリ版＞＞＞</font></b></a> <br>', '6355.0 JPY', 387.65, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:12:21', '2026-04-02 04:19:54', 'adastria_594169', '', '69cd72d7a7ab618f2967cc48', '生活/休闲', '', '女', '青年（18-44岁）', '亚麻100%', 'https://www.dot-st.com/studioclip/disp/item/594169/?COLOR_CD=02', '下装', '西裤', '裤装', '', 'trousers', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/studio_clip/20260401/item_594169_main_01_1773133316_b.jpg', 0, 0, 2, 0.84377, 0, 1, 1, 0, 0, 3, NULL, '透气，凉感穿着感受', '凉感穿着感受', '', '采用100%亚麻材质，质地柔软、亲肤透气,直筒版型与双褶设计，遮掩腿部线条，修饰身形,腰部前片平整设计，视觉上收腹显瘦,可搭配同面料单排扣亚麻西装形成套装造型,哈克米细格纹组织，让面料呈现素色感但更有质感', '其他', '从品名“ストレートパンツ”、品类“パンツ”以及图片呈现的下装版型来看，这是女性直筒长裤，非家纺或其他配饰类产品。英文分类中与之最匹配的是“trousers”，即日常穿着的长裤。trousers 的定义：指覆盖下半身、两条裤筒分开的长裤服装，用于日常或正式场合穿着，本款亚麻直筒裤完全符合该定义。', 1, 1, 0, 0, 'trousers', NULL, '', 0, NULL, 0, NULL, NULL, '01', 'ハケメブラック01', 0);
INSERT INTO `clothing_info` VALUES (19996790, '【产前・产后适用】孕妇／拼接蕾丝套头上衣', '【産前・産後対応】マタニティ／パッチワークレースプルオーバー', 0, 31749816, 'LEPSIM', '', '', '蕾丝与网眼材质拼接而成的设计感套头上衣，适合即将到来的夏季穿着，版型宽松、清爽不贴身。侧边开衩设计减轻臃肿感，营造利落修长的视觉效果。低调的异材质拼接细节成为造型亮点。无论搭配窄款半身裙还是喇叭裤等下装，都能轻松搭配出多样造型，适合孕期及产后日常出行与通勤穿着。', 'ーーー<br>レースとメッシュ素材がパッチワークになっているデザインプルオーバー<br>ーーー<br><br>【デザイン】<br>これからの夏にぴったりな、肌離れする1枚です。<br>スリット入りなので着膨れしにくく、すっきり見えが叶います◎<br>さりげない異素材デザインがポイントになっています！<br><br>【デザイン】<br>・ナロースカートでもフレアパンツでも合わせやすく、様々なスタイリングをお楽しみいただけます！', '4537.0 JPY', 276.76, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:12:25', '2026-04-02 04:19:51', 'adastria_661833', '', '69cd72d7a7ab618f2967cc41', '生活/休闲', '', '女', '青年（18-44岁）', '棉100%', 'https://www.dot-st.com/lepsim/disp/item/661833/?COLOR_CD=19', '上装', '卫衣', '套头衫', '', 'pullover', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/lepsim/20260401/item_661833_main_19_1774923777_b.jpg', 0, 0, 2, 0.74323, 0, 1, 0, 0, 0, 3, NULL, '透气，宽松版型便于孕期和产后身形变化，遮肚显瘦修饰身形，夏季穿着舒适的肌离剪裁', '宽松版型便于孕期和产后身形变化,遮肚显瘦修饰身形,夏季穿着舒适的肌离剪裁', '', '拼接蕾丝与网眼面料形成拼布效果,侧开衩设计减少臃肿感,七分偏长袖与宽松廓形利于层搭,适合搭配窄裙或喇叭裤等多种下装', '其他', '从商品名“プルオーバー”和图片版型看，此款为套头上衣，整体为宽松圆领短袖上装，不是开襟衬衫或外套，也非连衣裙或家居服，最符合列表中的“pullover（套头上衣/卫衣类上装）”类别。', 1, 0, 0, 0, 'pullover', NULL, '', 0, NULL, 0, NULL, NULL, '19', 'チャコール19', 0);
INSERT INTO `clothing_info` VALUES (19996791, '【产前・产后适用】孕妇／拼接蕾丝套头上衣', '【産前・産後対応】マタニティ／パッチワークレースプルオーバー', 0, 31749816, 'LEPSIM', '', '', '蕾丝与网眼材质拼接而成的设计感套头上衣，适合即将到来的夏季穿着，版型宽松、清爽不贴身。侧边开衩设计减轻臃肿感，营造利落修长的视觉效果。低调的异材质拼接细节成为造型亮点。无论搭配窄款半身裙还是喇叭裤等下装，都能轻松搭配出多样造型，适合孕期及产后日常出行与通勤穿着。', 'ーーー<br>レースとメッシュ素材がパッチワークになっているデザインプルオーバー<br>ーーー<br><br>【デザイン】<br>これからの夏にぴったりな、肌離れする1枚です。<br>スリット入りなので着膨れしにくく、すっきり見えが叶います◎<br>さりげない異素材デザインがポイントになっています！<br><br>【デザイン】<br>・ナロースカートでもフレアパンツでも合わせやすく、様々なスタイリングをお楽しみいただけます！', '4537.0 JPY', 276.76, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:12:25', '2026-04-02 04:19:52', 'adastria_661833', '', '69cd72d7a7ab618f2967cc41', '生活/休闲', '', '女', '青年（18-44岁）', '棉100%', 'https://www.dot-st.com/lepsim/disp/item/661833/?COLOR_CD=19', '上装', '卫衣', '套头衫', '', 'pullover', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/lepsim/20260401/item_661833_main_08_1774923789_b.jpg', 0, 0, 7, 0.76348, 0, 1, 0, 0, 0, 3, NULL, '透气，宽松版型便于孕期和产后身形变化，遮肚显瘦修饰身形，夏季穿着舒适的肌离剪裁', '宽松版型便于孕期和产后身形变化,遮肚显瘦修饰身形,夏季穿着舒适的肌离剪裁', '', '拼接蕾丝与网眼面料形成拼布效果,侧开衩设计减少臃肿感,七分偏长袖与宽松廓形利于层搭,适合搭配窄裙或喇叭裤等多种下装', '其他', '从商品名“プルオーバー”和图片版型看，此款为套头上衣，整体为宽松圆领短袖上装，不是开襟衬衫或外套，也非连衣裙或家居服，最符合列表中的“pullover（套头上衣/卫衣类上装）”类别。', 1, 1, 0, 0, 'pullover', NULL, '', 0, NULL, 0, NULL, NULL, '08', 'ナチュラル08', 0);
INSERT INTO `clothing_info` VALUES (19996787, '【预售/官网・部分地区先行】轻松穿着的凉感长裤【含小个子・大码】', '【先行予約/WEB・一部地域先行】軽らくトラウザーパンツ[プチ・プラスサイズあり]', 0, 200164, 'studio CLIP', '', '', '在炎热季节也令人开心的接触冷感功能长裤，打造轻松有型的穿搭。\n\n【材质】\n采用具有清爽表面感的棉尼龙broken布料，带来利落印象。面料具备适度挺括感与轻盈特性，并附加接触冷感功能，适合炎热季节穿着。\n\n【设计】\n轮廓具有辨识度的长裤，前片加入褶皱设计，可从休闲到略正式风格广泛搭配。推出亲和度高的粉色和绿色等色彩，为造型增添新鲜感。洗后不易产生明显皱折，适合日常频繁穿着。\n\n【搭配】\n可与T恤或夏季针织单品组合呈现休闲风，也能搭配衬衫或女衬衫打造更干练的造型。裤型略有蓬松感，建议与较为合身的上衣搭配以取得整体平衡。', '<b><font color=\"ff1493\">暑い時期に嬉しい接触冷感の機能付き！<br>こなれた着こなしが楽しめるトラウザーパンツ</font></b><br>ーーー<br><br>【素材】<br>クリアな表面感ですっきりとした印象の綿ナイロンブロークン生地を使用。<br>程よいハリ感と軽さが特徴で、暑い時期に嬉しい接触冷感の機能付きです。<br><br>【デザイン】<br>特徴的なシルエットのトラウザーパンツ。<br>フロントにタックが入っており、カジュアルから綺麗めまで幅広い着こなしをお楽しみいただけます。<br>馴染みの良いピンクやグリーンで鮮度UP◎<br>洗濯後シワになりづらいのでデイリーに穿けるのも嬉しいポイントです。<br><br><br>ボトム　パンツ　ワイド　イージーパンツ<br><br>ーーー<br><br>【スタイリング】<br>Tシャツやサマーニット合わせでカジュアルに、シャツやブラウス合わせで綺麗めに。<br>程よくボリュームがあるのでトップスはコンパクトなものを合わせるとバランスよく着こなせます。', '4900.0 JPY', 298.90, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:12:34', '2026-04-02 04:19:49', 'adastria_637595', '', '69cd72d7a7ab618f2967cc3c', '生活/休闲', '', '女', '青年（18-44岁）', '棉67%,锦纶30%,氨纶3%', 'https://www.dot-st.com/studioclip/disp/item/637595/?COLOR_CD=20', '下装', '西裤', '裤装', '', 'trousers', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/studio_clip/20260401/item_637595_main_20_1773215923_b.webp', 0, 0, 2, 0.87533, 0, 1, 1, 0, 0, 3, NULL, '接触冷感，防皱，轻量，易打理', '轻量,易打理', '接触冷感功能', '棉尼龙混纺面料，表面清爽有清晰感,面料具有适度挺括感与轻盈特性，适合炎热季节穿着,前片打褶设计，版型宽松有量感,颜色为易于搭配的粉色、绿色等，提高造型新鲜感,洗后不易起皱，适合日常高频穿着', '纯色，纯色', '商品为“トラウザーパンツ”，下装长裤，裤脚到脚踝，非运动裤或家居裤，版型偏正装与休闲之间，最符合分类中的“trousers（长裤/西裤类）”定义。trousers：指日常或通勤可穿的长裤、斜纹裤或西裤类，而非牛仔、运动或短裤。', 1, 0, 0, 0, 'trousers', NULL, '', 0, NULL, 0, NULL, NULL, '20', 'ピンク20', 0);
INSERT INTO `clothing_info` VALUES (19996788, '【预售/官网・部分地区先行】轻松穿着的凉感长裤【含小个子・大码】', '【先行予約/WEB・一部地域先行】軽らくトラウザーパンツ[プチ・プラスサイズあり]', 0, 200164, 'studio CLIP', '', '', '在炎热季节也令人开心的接触冷感功能长裤，打造轻松有型的穿搭。\n\n【材质】\n采用具有清爽表面感的棉尼龙broken布料，带来利落印象。面料具备适度挺括感与轻盈特性，并附加接触冷感功能，适合炎热季节穿着。\n\n【设计】\n轮廓具有辨识度的长裤，前片加入褶皱设计，可从休闲到略正式风格广泛搭配。推出亲和度高的粉色和绿色等色彩，为造型增添新鲜感。洗后不易产生明显皱折，适合日常频繁穿着。\n\n【搭配】\n可与T恤或夏季针织单品组合呈现休闲风，也能搭配衬衫或女衬衫打造更干练的造型。裤型略有蓬松感，建议与较为合身的上衣搭配以取得整体平衡。', '<b><font color=\"ff1493\">暑い時期に嬉しい接触冷感の機能付き！<br>こなれた着こなしが楽しめるトラウザーパンツ</font></b><br>ーーー<br><br>【素材】<br>クリアな表面感ですっきりとした印象の綿ナイロンブロークン生地を使用。<br>程よいハリ感と軽さが特徴で、暑い時期に嬉しい接触冷感の機能付きです。<br><br>【デザイン】<br>特徴的なシルエットのトラウザーパンツ。<br>フロントにタックが入っており、カジュアルから綺麗めまで幅広い着こなしをお楽しみいただけます。<br>馴染みの良いピンクやグリーンで鮮度UP◎<br>洗濯後シワになりづらいのでデイリーに穿けるのも嬉しいポイントです。<br><br><br>ボトム　パンツ　ワイド　イージーパンツ<br><br>ーーー<br><br>【スタイリング】<br>Tシャツやサマーニット合わせでカジュアルに、シャツやブラウス合わせで綺麗めに。<br>程よくボリュームがあるのでトップスはコンパクトなものを合わせるとバランスよく着こなせます。', '4900.0 JPY', 298.90, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:12:34', '2026-04-02 04:19:50', 'adastria_637595', '', '69cd72d7a7ab618f2967cc3c', '生活/休闲', '', '女', '青年（18-44岁）', '棉67%,锦纶30%,氨纶3%', 'https://www.dot-st.com/studioclip/disp/item/637595/?COLOR_CD=20', '下装', '西裤', '裤装', '', 'trousers', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/studio_clip/20260401/item_637595_main_70_1772788371_b.jpg', 0, 0, 2, 0.89673, 0, 1, 1, 0, 0, 3, NULL, '接触冷感，防皱，轻量，易打理', '轻量,易打理', '接触冷感功能', '棉尼龙混纺面料，表面清爽有清晰感,面料具有适度挺括感与轻盈特性，适合炎热季节穿着,前片打褶设计，版型宽松有量感,颜色为易于搭配的粉色、绿色等，提高造型新鲜感,洗后不易起皱，适合日常高频穿着', '纯色，纯色', '商品为“トラウザーパンツ”，下装长裤，裤脚到脚踝，非运动裤或家居裤，版型偏正装与休闲之间，最符合分类中的“trousers（长裤/西裤类）”定义。trousers：指日常或通勤可穿的长裤、斜纹裤或西裤类，而非牛仔、运动或短裤。', 1, 1, 0, 0, 'trousers', NULL, '', 0, NULL, 0, NULL, NULL, '70', 'グリーン70', 0);
INSERT INTO `clothing_info` VALUES (19996789, '【预售/官网・部分地区先行】轻松穿着的凉感长裤【含小个子・大码】', '【先行予約/WEB・一部地域先行】軽らくトラウザーパンツ[プチ・プラスサイズあり]', 0, 200164, 'studio CLIP', '', '', '在炎热季节也令人开心的接触冷感功能长裤，打造轻松有型的穿搭。\n\n【材质】\n采用具有清爽表面感的棉尼龙broken布料，带来利落印象。面料具备适度挺括感与轻盈特性，并附加接触冷感功能，适合炎热季节穿着。\n\n【设计】\n轮廓具有辨识度的长裤，前片加入褶皱设计，可从休闲到略正式风格广泛搭配。推出亲和度高的粉色和绿色等色彩，为造型增添新鲜感。洗后不易产生明显皱折，适合日常频繁穿着。\n\n【搭配】\n可与T恤或夏季针织单品组合呈现休闲风，也能搭配衬衫或女衬衫打造更干练的造型。裤型略有蓬松感，建议与较为合身的上衣搭配以取得整体平衡。', '<b><font color=\"ff1493\">暑い時期に嬉しい接触冷感の機能付き！<br>こなれた着こなしが楽しめるトラウザーパンツ</font></b><br>ーーー<br><br>【素材】<br>クリアな表面感ですっきりとした印象の綿ナイロンブロークン生地を使用。<br>程よいハリ感と軽さが特徴で、暑い時期に嬉しい接触冷感の機能付きです。<br><br>【デザイン】<br>特徴的なシルエットのトラウザーパンツ。<br>フロントにタックが入っており、カジュアルから綺麗めまで幅広い着こなしをお楽しみいただけます。<br>馴染みの良いピンクやグリーンで鮮度UP◎<br>洗濯後シワになりづらいのでデイリーに穿けるのも嬉しいポイントです。<br><br><br>ボトム　パンツ　ワイド　イージーパンツ<br><br>ーーー<br><br>【スタイリング】<br>Tシャツやサマーニット合わせでカジュアルに、シャツやブラウス合わせで綺麗めに。<br>程よくボリュームがあるのでトップスはコンパクトなものを合わせるとバランスよく着こなせます。', '4900.0 JPY', 298.90, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:12:34', '2026-04-02 04:19:50', 'adastria_637595', '', '69cd72d7a7ab618f2967cc3c', '生活/休闲', '', '女', '青年（18-44岁）', '棉67%,锦纶30%,氨纶3%', 'https://www.dot-st.com/studioclip/disp/item/637595/?COLOR_CD=20', '下装', '西裤', '裤装', '', 'trousers', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/studio_clip/20260401/item_637595_main_88_1773824814_b.jpg', 0, 0, 4, 0.94029, 0, 1, 0, 0, 0, 3, NULL, '接触冷感，防皱，轻量，易打理', '轻量,易打理', '接触冷感功能', '棉尼龙混纺面料，表面清爽有清晰感,面料具有适度挺括感与轻盈特性，适合炎热季节穿着,前片打褶设计，版型宽松有量感,颜色为易于搭配的粉色、绿色等，提高造型新鲜感,洗后不易起皱，适合日常高频穿着', '纯色，纯色', '商品为“トラウザーパンツ”，下装长裤，裤脚到脚踝，非运动裤或家居裤，版型偏正装与休闲之间，最符合分类中的“trousers（长裤/西裤类）”定义。trousers：指日常或通勤可穿的长裤、斜纹裤或西裤类，而非牛仔、运动或短裤。', 1, 2, 0, 0, 'trousers', NULL, '', 0, NULL, 0, NULL, NULL, '88', 'ネイビー88', 0);
INSERT INTO `clothing_info` VALUES (19996784, '【daily CLIP】钩编串珠手链', '【daily CLIP】リリアンビーズブレスレット', 0, 200164, 'studio CLIP', '', '', '具有个性色彩的串珠手镯，为腕间增添亮点。一颗一颗细致编织而成，充满手工温度，贴合手腕，纤细造型却拥有丰富多变的图案，可为整体搭配增添点睛效果。既可单独佩戴，也适合与自有手表或其他手链叠戴使用。产地：印度。', '<b><font color=\"000000\">個性のある色合いが手元にアクセントをプラス</font></b><br><br>一つ一つ丁寧に編み込まれた温かみのあるビーズバングル。<br>手首にスッと馴染みスリムなフォルムながら、個性豊かなパターンがコーディネートのアクセントに。<br>単品使いはもちろん、お手持ちの時計やブレスレットとの重ね付けも楽しめるアイテムです。<br><br>■原産国：インド<br><br>ーーー<br>ブレスレット　バングル<br>ーーー<br><br>', '2264.0 JPY', 138.10, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:12:48', '2026-04-02 04:19:46', 'adastria_631309', '', '69cd72d7a7ab618f2967cc38', '生活/休闲', '', '通用', '青年（18-44岁）', NULL, 'https://www.dot-st.com/studioclip/disp/item/631309/?COLOR_CD=01', '其他服饰/物品', '其他', '配件', '', 'accessories', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/studio_clip/20260401/item_631309_main_01_1773647119_b.jpg', 0, 0, 9, 0.99661, 0, 1, 0, 0, 0, 3, NULL, '', '', '', '手工编织感强，颗粒状玻璃珠串联形成立体质感,色彩搭配有对比度，可作为造型点缀单品,可与手表或其他手链进行叠戴搭配,产地为印度，具有一定手工饰品风格特色', '花卉图案', '该产品为“リリアンビーズブレスレット”，说明是手链/手镯类配饰，并非服装或家纺用品，不属于衣物、床品、窗帘等类别。综合品类“アクセサリー”和图片中可见的珠串圆环造型，可归入配饰大类中最合适的子类“accessories（配饰）”。Definition：accessories 指佩戴在身上的装饰性小物，如项链、手链、戒指等，用于搭配服装提升造型感。', 1, 0, 0, 0, 'accessories', NULL, '', 0, NULL, 0, NULL, NULL, '01', 'GD×BL01', 0);
