INSERT INTO `clothing_info` VALUES (19996782, '【预售/Limited Line】蕾丝领法式套头上衣', '【先行予約/Limited Line】レースカラーフレンチプルオーバー', 0, 200164, 'studio CLIP', '', '', '穿上精致蕾丝点缀的大人感T恤式女衬衫。\n\n【材质】\n以亲肤、适合日常穿着的棉质天竺针织面料为基础，拼接同色蕾丝面料。\n\n【设计】\n可前后两面穿着，领口有两种变化。领口中央穿有同面料系带，收紧时呈华丽的荷叶边效果，放松时则形成带有留白感的高领造型，可根据喜好调整氛围。袖口同样大量运用蕾丝装饰，宽松的廓形与宽袖设计能修饰手臂线条。\n\n【搭配】\n适合与简约的宽腿裤或背带裤叠穿作为内搭。前后调换穿法，把系带置于背面时，背影更加出彩，呈现干净利落的造型。', '<font color=\"#000000\"><b>繊細なレースを纏った大人のTブラウス</b></font><br><br>ーーー<br>【素材】<br>肌馴染みが良くデイリーに使いやすいコットン天竺をベースに、<br>同色のレースを組み合わせました。<br><br>【デザイン】<br>前後着用可能な2WAY仕様になっており、襟の変化を2通り楽しめます。<br>襟の中心部には共布のヒモが通っており、ぎゅっと絞ることで華やかなフリル調に、緩めることで抜け感のあるハイネックにと、お好みでニュアンスを変えられるのがポイント。<br>袖口にも贅沢にレースを施し、ゆったりとしたワイドスリーブが腕のラインをカバーしてくれます。<br><br>ーーー<br>【スタイリング】<br>シンプルなワイドパンツやサロペットのインナーとして合わせるのがおすすめです。<br>前後を入れ替えてリボンの位置を後ろにすれば、バックスタイルが映えるクリーンな着こなしに。<br>', '5537.0 JPY', 337.76, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:12:58', '2026-04-02 04:19:44', 'adastria_664305', '', '69cd72d7a7ab618f2967cc32', '生活/休闲', '', '女', '青年（18-44岁）', '棉100%', 'https://www.dot-st.com/studioclip/disp/item/664305/?COLOR_CD=88', '上装', '衬衫', '女式衬衫', '', 'blouse', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/studio_clip/20260401/item_664305_main_88_1774593944_b.jpg', 0, 0, 4, 0.81295, 0, 1, 1, 0, 0, 3, NULL, '透气，舒适亲肤', '舒适亲肤', '', '前后皆可穿的2WAY领口设计，可通过抽绳调节成荷叶边或高领效果,领口与袖口拼接同色蕾丝，提升成熟女性气质与装饰感,宽松廓形与宽袖设计，有一定遮肉与修饰手臂线条作用,以棉质天竺针织面料为底，适合日常穿着', '纯色，纯色', '从商品名“レースカラーフレンチプルオーバー”和描述来看，是一款以棉天竺针织为底、配有蕾丝领口和袖口、可前后两穿的上衣。整体风格偏淑女、搭配正装或时装为主，属于“上装类的时尚衬衫/女式上衣”，最符合列表中的“blouse（女式衬衫/时装上衣）”定义，因此选择 sub_category: blouse。', 1, 0, 0, 0, 'blouse', NULL, '', 0, NULL, 0, NULL, NULL, '88', 'ネイビー88', 0);
INSERT INTO `clothing_info` VALUES (19996783, '【预售/Limited Line】蕾丝领法式套头上衣', '【先行予約/Limited Line】レースカラーフレンチプルオーバー', 0, 200164, 'studio CLIP', '', '', '穿上精致蕾丝点缀的大人感T恤式女衬衫。\n\n【材质】\n以亲肤、适合日常穿着的棉质天竺针织面料为基础，拼接同色蕾丝面料。\n\n【设计】\n可前后两面穿着，领口有两种变化。领口中央穿有同面料系带，收紧时呈华丽的荷叶边效果，放松时则形成带有留白感的高领造型，可根据喜好调整氛围。袖口同样大量运用蕾丝装饰，宽松的廓形与宽袖设计能修饰手臂线条。\n\n【搭配】\n适合与简约的宽腿裤或背带裤叠穿作为内搭。前后调换穿法，把系带置于背面时，背影更加出彩，呈现干净利落的造型。', '<font color=\"#000000\"><b>繊細なレースを纏った大人のTブラウス</b></font><br><br>ーーー<br>【素材】<br>肌馴染みが良くデイリーに使いやすいコットン天竺をベースに、<br>同色のレースを組み合わせました。<br><br>【デザイン】<br>前後着用可能な2WAY仕様になっており、襟の変化を2通り楽しめます。<br>襟の中心部には共布のヒモが通っており、ぎゅっと絞ることで華やかなフリル調に、緩めることで抜け感のあるハイネックにと、お好みでニュアンスを変えられるのがポイント。<br>袖口にも贅沢にレースを施し、ゆったりとしたワイドスリーブが腕のラインをカバーしてくれます。<br><br>ーーー<br>【スタイリング】<br>シンプルなワイドパンツやサロペットのインナーとして合わせるのがおすすめです。<br>前後を入れ替えてリボンの位置を後ろにすれば、バックスタイルが映えるクリーンな着こなしに。<br>', '5537.0 JPY', 337.76, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:12:58', '2026-04-02 04:19:45', 'adastria_664305', '', '69cd72d7a7ab618f2967cc32', '生活/休闲', '', '女', '青年（18-44岁）', '棉100%', 'https://www.dot-st.com/studioclip/disp/item/664305/?COLOR_CD=88', '上装', '衬衫', '女式衬衫', '', 'blouse', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/studio_clip/20260401/item_664305_main_52_1774593951_b.webp', 0, 0, 2, 0.99566, 0, 1, 1, 0, 0, 3, NULL, '透气，舒适亲肤', '舒适亲肤', '', '前后皆可穿的2WAY领口设计，可通过抽绳调节成荷叶边或高领效果,领口与袖口拼接同色蕾丝，提升成熟女性气质与装饰感,宽松廓形与宽袖设计，有一定遮肉与修饰手臂线条作用,以棉质天竺针织面料为底，适合日常穿着', '纯色，纯色', '从商品名“レースカラーフレンチプルオーバー”和描述来看，是一款以棉天竺针织为底、配有蕾丝领口和袖口、可前后两穿的上衣。整体风格偏淑女、搭配正装或时装为主，属于“上装类的时尚衬衫/女式上衣”，最符合列表中的“blouse（女式衬衫/时装上衣）”定义，因此选择 sub_category: blouse。', 1, 1, 0, 0, 'blouse', NULL, '', 0, NULL, 0, NULL, NULL, '52', 'アイボリー53', 0);
INSERT INTO `clothing_info` VALUES (19996777, '【预售/限定系列】拼接设计中长连衣裙', '【先行予約/Limited Line】アソート切り替えワンピース', 0, 200164, 'studio CLIP', '', '', '采用三种不同材质组合而成，层次感丰富的拼接式层叠连衣裙。主面料为触感柔软的100%纯棉，亲肤舒适。身身与袖子选用不同图案及质感的面料，以拼布方式进行不对称排布，营造独特的混搭效果。裙身在层叠拼接处更换图案与材质，即使单穿也能呈现完整造型。简洁圆领搭配具有分量感的层叠轮廓，塑造放松又富有女性气质的造型。搭配运动鞋可营造休闲氛围，也可配合凉鞋增添清爽感，并能与外搭夹克或马甲叠穿，轻松完成多样造型。', '<font color=\"#000000\"><b>3種類の素材を組み合わせた<br>表情豊かなティアードワンピース</b></font><br>ーーー<br>【素材】<br>肌さわりの良い綿100％素材を使用しています。<br><br>【デザイン】<br>身頃や袖に、それぞれ異なる柄や素材の生地をパッチワークのように配置した、アソートワンピース。<br>ティアードデザインの切り替え部分で柄が変化するため、1枚でもコーディネートが完成！<br>首元はすっきりとしたクルーネックで、ボリュームのあるティアードシルエットが、リラックス感のある女性らしいフォルムに。<br><br>ーーー<br>【スタイリング】<br>足元にスニーカーを合わせてカジュアルダウンさせたり、サンダルで清涼感をプラスしたりと、合わせる小物次第で幅広い雰囲気に。<br>上からジャケットやベストを重ねたレイヤードスタイルもバランス良くまとまります。', '9900.0 JPY', 603.90, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:12:59', '2026-04-02 04:19:40', 'adastria_664411', '', '69cd72d7a7ab618f2967cc24', '生活/休闲', '', '女', '青年（18-44岁）', '棉100%', 'https://www.dot-st.com/studioclip/disp/item/664411/?COLOR_CD=11', '裙装', '连衣裙', '中长裙', '', 'midi dress', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/studio_clip/20260401/item_664411_main_11_1774601458_b.jpg', 0, 0, 7, 0.86587, 0, 1, 1, 0, 0, 3, NULL, '透气，舒适亲肤', '舒适亲肤', '', '三种不同面料拼接形成拼布效果,下摆采用花型刺绣蕾丝面料,宽松廓形营造休闲放松风格,圆领设计便于日常搭配,全棉材质提升穿着舒适度', '花卉图案', '该商品为单件一体式的连衣裙，长度中长，小腿附近位置，日文也标注为“ワンピース・ドレス”，版型是宽松的梯形/层叠裙摆设计。结合图片和描述“ティアードワンピース”（层叠连衣裙），最符合服装大类中的连衣裙类别。长度为中长款，因此在给定列表中选择“midi dress”（中长连衣裙）最合适。midi dress 指长度大约至小腿位置的连衣裙，兼具日常与优雅风格。', 1, 0, 0, 0, 'midi dress', NULL, '', 0, NULL, 0, NULL, NULL, '11', 'オフホワイト11', 0);
