INSERT INTO `clothing_info` VALUES (19996779, '【预售/限定系列】拼接设计中长连衣裙', '【先行予約/Limited Line】アソート切り替えワンピース', 0, 200164, 'studio CLIP', '', '', '采用三种不同材质组合而成，层次感丰富的拼接式层叠连衣裙。主面料为触感柔软的100%纯棉，亲肤舒适。身身与袖子选用不同图案及质感的面料，以拼布方式进行不对称排布，营造独特的混搭效果。裙身在层叠拼接处更换图案与材质，即使单穿也能呈现完整造型。简洁圆领搭配具有分量感的层叠轮廓，塑造放松又富有女性气质的造型。搭配运动鞋可营造休闲氛围，也可配合凉鞋增添清爽感，并能与外搭夹克或马甲叠穿，轻松完成多样造型。', '<font color=\"#000000\"><b>3種類の素材を組み合わせた<br>表情豊かなティアードワンピース</b></font><br>ーーー<br>【素材】<br>肌さわりの良い綿100％素材を使用しています。<br><br>【デザイン】<br>身頃や袖に、それぞれ異なる柄や素材の生地をパッチワークのように配置した、アソートワンピース。<br>ティアードデザインの切り替え部分で柄が変化するため、1枚でもコーディネートが完成！<br>首元はすっきりとしたクルーネックで、ボリュームのあるティアードシルエットが、リラックス感のある女性らしいフォルムに。<br><br>ーーー<br>【スタイリング】<br>足元にスニーカーを合わせてカジュアルダウンさせたり、サンダルで清涼感をプラスしたりと、合わせる小物次第で幅広い雰囲気に。<br>上からジャケットやベストを重ねたレイヤードスタイルもバランス良くまとまります。', '9900.0 JPY', 603.90, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:12:59', '2026-04-02 04:19:42', 'adastria_664411', '', '69cd72d7a7ab618f2967cc24', '生活/休闲', '', '女', '青年（18-44岁）', '棉100%', 'https://www.dot-st.com/studioclip/disp/item/664411/?COLOR_CD=11', '裙装', '连衣裙', '中长裙', '', 'midi dress', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/studio_clip/20260401/item_664411_main_88_1774601550_b.jpg', 0, 0, 6, 0.82477, 0, 1, 1, 0, 0, 3, NULL, '透气，舒适亲肤', '舒适亲肤', '', '三种不同面料拼接形成拼布效果,下摆采用花型刺绣蕾丝面料,宽松廓形营造休闲放松风格,圆领设计便于日常搭配,全棉材质提升穿着舒适度', '花卉图案', '该商品为单件一体式的连衣裙，长度中长，小腿附近位置，日文也标注为“ワンピース・ドレス”，版型是宽松的梯形/层叠裙摆设计。结合图片和描述“ティアードワンピース”（层叠连衣裙），最符合服装大类中的连衣裙类别。长度为中长款，因此在给定列表中选择“midi dress”（中长连衣裙）最合适。midi dress 指长度大约至小腿位置的连衣裙，兼具日常与优雅风格。', 1, 2, 0, 0, 'midi dress', NULL, '', 0, NULL, 0, NULL, NULL, '88', 'ネイビー88', 0);
INSERT INTO `clothing_info` VALUES (19996780, '【预售 / 限定系列】褶皱蝴蝶结马甲背心', '【先行予約/Limited Line】タックリボンジレ', 0, 200164, 'studio CLIP', '', '', '用于修饰体型的前后双面可穿马甲背心。采用干爽手感、有挺度的棉混纤维面料，触感清爽顺滑。前片排布三只细致蝴蝶结，腰部位置加入精巧的褶皱与抽褶设计作为视觉亮点。可前后反穿：蝴蝶结在前时可作为外搭开襟马甲，换到简单的一面在前，则呈现类似套头上衣的效果。侧边设置大口袋，并配有可收紧口部的抽绳设计，为轮廓变化增添趣味。只需叠穿在简单的T恤或衬衫外即可完成时髦的层次造型，也可以收紧侧袋打造类似气球般蓬松的轮廓，并与连衣裙或字母T恤自由组合，展现多样穿搭。', '<font color=\"#000000\"><b>体型カバーにも！<br>前後2WAYで着こなしの幅が広がるジレ</b></font><br><br>ーーー<br>【素材】<br>ドライタッチでハリのある綿混の素材を使用。<br>さらりとした肌触りが特徴です。<br><br>【デザイン】<br>フロントに並んだ3つの華奢なリボンと、ウエスト部分の繊細なタックギャザーがデザインのポイントです。<br>前後着用可能な2WAY仕様になっており、リボンを前にして羽織りとして着るスタイルと、シンプルな面を前にしてプルオーバー風に着るスタイルで印象をガラリと変えられます。サイドの大きめなポケットは、口を絞れるドロストデザインになっており、変化をつけられる遊び心が詰まっています。<br><br>ーーー<br>【スタイリング】<br>シンプルなTシャツやブラウスに重ねるだけで、旬なレイヤードスタイルが完成します。<br>サイドのポケットをぎゅっと絞れば、バルーンのようなふんわりとしたシルエットに。<br>前後2WAYを活かして、ワンピースの上から重ねたり、ロゴTシャツをリボンの間から覗かせたりと、合わせるインナー次第で自由自在な着こなしを楽しめる万能な一枚です。', '7900.0 JPY', 481.90, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:12:59', '2026-04-02 04:19:43', 'adastria_664306', '', '69cd72d7a7ab618f2967cc2e', '生活/休闲', '', '女', '青年（18-44岁）', '棉31%,锦纶8%', 'https://www.dot-st.com/studioclip/disp/item/664306/?COLOR_CD=88', '上装', '背心', '马甲背心', '', 'vest', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/studio_clip/20260401/item_664306_main_88_1774601016_b.jpg', 0, 0, 2, 0.95511, 0, 1, 1, 0, 0, 3, NULL, '透气，体型修饰', '体型修饰', '', '前后2WAY穿法，可作为系带开衫式外搭或作套头风格上衣使用,腰部细致褶皱与抽绳大口袋增加层次感与廓形变化,干爽手感的棉混纤维面料，适合叠搭造型,侧边口袋抽绳可收紧形成气球感轮廓', '纯色，纯色', '根据商品名“タックリボンジレ”和图片可见，这是无袖、开衩侧边、用于外搭叠穿的单品，前身有系带设计，整体版型属于时装马甲/背心类，而非有袖上衣或外套，因此从列表中选择“vest（背心/马甲）”。vest：指无袖、常用于叠穿的上身服装，可作为造型外搭或内搭单品。', 1, 0, 0, 0, 'vest', NULL, '', 0, NULL, 0, NULL, NULL, '88', 'ネイビー88', 0);
