INSERT INTO `clothing_info` VALUES (19996774, '【预售/限定款】拼接设计百搭衬衫上衣', '【先行予約/Limited Line】アソート切り替えブラウス', 0, 200164, 'studio CLIP', '', '', '采用触感柔软的100%纯棉面料制成，由身片与袖子处三种不同面料拼接而成，富有层次感。前身和下摆位置加入丰富褶皱设计，营造自然蓬松的轮廓。宽松的廓形与宽版七分袖带来休闲的穿着体验，同时略短的衣长让整体轮廓显得利落干练。一件即可成为造型亮点，兼具趣味性与装饰感。适合搭配宽腿裤、锥形裤、简约牛仔裤或卡其裤，轻松打造自然大人感风格。', '<font color=\"#000000\"><b>3種類の素材を組み合わせた<br>遊び心溢れる切り替えブラウス</b></font><br><br>ーーー<br>【素材】<br>肌さわりの良い綿100％素材を使用しています。<br><br>【デザイン】<br>身頃や袖に3種類の生地を組み合わせたギャザーデザインがポイントです。<br>ゆったりとしたワイドスリーブと、広がりすぎない短めの着丈が、リラックス感がありつつもスッキリとしたシルエットに。<br>1枚で着映えする、遊び心溢れるデザインです。<br><br>ーーー<br>【スタイリング】<br>短めの着丈に設定されているため、ワイドパンツやテーパードパンツなど、カジュアルなパンツとのコーディネートがおすすめ。<br>ブラウスのデザインが華やかなので、シンプルなデニムやチノパンと合わせるだけで、オシャレ見えする大人のナチュラルスタイルが完成します。', '8537.0 JPY', 520.76, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:13:00', '2026-04-02 04:19:38', 'adastria_664302', '', '69cd72d7a7ab618f2967cc25', '生活/休闲', '', '女', '青年（18-44岁）', '棉100%', 'https://www.dot-st.com/studioclip/disp/item/664302/?COLOR_CD=11', '上装', '衬衫', '女式衬衫', '', 'blouse', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/studio_clip/20260401/item_664302_main_11_1774592923_b.jpg', 0, 0, 2, 0.99510, 0, 1, 1, 0, 0, 3, NULL, '透气，舒适亲肤', '舒适亲肤', '', '宽松版型与五分宽袖设计，营造休闲感和遮肉效果,采用三种不同质感面料拼接，增加层次感和设计感,短款衣长方便与高腰或宽腿裤搭配，优化身材比例,前身布料有丰富褶皱和抽褶设计，增强视觉丰富度,下摆花型刺绣蕾丝区域带来女性化与浪漫风格', '花卉图案', '从商品名称“ブラウス（blouse）”以及款式来看，这是上身穿着的女式轻薄上衣，非针织T恤而是梭织布加蕾丝拼接，版型偏宽松、带有褶皱与拼接设计，典型为女装衬衫类上衣，因此在给定列表中选择“blouse（女式衬衫/雪纺上衣类）”最为合适。blouse 通常指以梭织面料为主、具有设计细节的女性上衣。', 1, 0, 0, 0, 'blouse', NULL, '', 0, NULL, 0, NULL, NULL, '11', 'オフホワイト11', 0);
