INSERT INTO `clothing_info` VALUES (19996769, '【预售 / Limited Line】蕾丝拼接衬衫上衣', '【先行予約/Limited Line】レース切り替えブラウス', 0, 200164, 'studio CLIP', '', '', '以多种棉质面料进行拼接，营造具有存在感的大人感衬衫上衣。\n\n【材质】\n将棉质刺绣面料、提花面料与蕾丝面料进行奢华组合。100%棉带来自然质感，穿着舒适惬意。\n\n【设计】\n将刺绣、提花、蕾丝等不同面料以拼接方式组合，打造具有存在感的设计亮点。领口及下摆为抽绳设计，可随心收紧，调节出类似气球轮廓的蓬松感。腋下开口较宽，即使叠穿袖子较蓬的内搭也不显臃肿，便于层次搭配。\n\n【搭配】\n通过多种面料的拼接设计，只需单穿即可完成造型。可与蕾丝下装搭配呈现女性化风格，也可与牛仔单品组合打造休闲造型。', '<font color=\"#000000\"><b>様々なコットン生地をパッチワーク風に紡いだ、<br>存在感溢れる大人のブラウス</b></font><br>ーーー<br>【素材】<br>コットン素材の刺繍生地、ジャガード生地、レース生地を贅沢に組み合わせています。<br>綿100%のナチュラルな質感で、心地よい着用感です。<br><br>【デザイン】<br>刺繍・ジャガード・レースの異なる生地をパッチワーク風に切り替えた、存在感のあるデザインがポイント。<br>首回りや裾は、ドロスト仕様で絞れる設計になっており、バルーンシルエットのようなふんわりとしたボリューム感を自在に調整できます。<br>アームホールは広めに設定されており、袖にボリュームのあるインナーの上からでももたつかずに着用できる、レイヤードしやすいデザインです。<br><br>ーーー<br>【スタイリング】<br>様々な生地がパッチワーク風に組み合わさっているため、一枚でさらりと着こなすだけで様になります。<br>レースのボトムと合わせてフェミニンに合わせたり、デニムと合わせたカジュアルなスタイルもオススメです。', '6900.0 JPY', 420.90, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:13:07', '2026-04-02 04:19:34', 'adastria_664409', '', '69cd72d7a7ab618f2967cc17', '生活/休闲', '', '女', '青年（18-44岁）', '棉100%', 'https://www.dot-st.com/studioclip/disp/item/664409/?COLOR_CD=52', '上装', '衬衫', '女式衬衫', '', 'blouse', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/studio_clip/20260401/item_664409_main_52_1774593509_b.jpg', 0, 0, 2, 0.88799, 0, 1, 1, 0, 0, 3, NULL, '透气，舒适，轻盈', '舒适,轻盈', '', '多种棉质面料拼接设计，包含刺绣、提花和蕾丝,领口和下摆配有抽绳，可调节廓形与蓬松度,腋下开口较大，方便与有体积感袖子的内搭叠穿,整体为棉质天然手感，强调穿着舒适', '花卉图案', '该产品名称为“レース切り替えブラウス”，并描述为大人のブラウス，属于上装类的衬衫/女式上衣，非针织卫衣也非T恤，更不是外套类，因此在给定列表中最匹配的类别是“blouse（女式衬衫上衣）”。blouse 一般指以布帛为主、版型偏宽松、带有设计细节的上衣，本款采用多种棉质刺绣、提花、蕾丝布料拼接，具备明显的女式衬衫/上衣特征，故选择 sub_category: blouse。', 1, 0, 0, 0, 'blouse', NULL, '', 0, NULL, 0, NULL, NULL, '52', 'アイボリー52', 0);
INSERT INTO `clothing_info` VALUES (19996770, '【预售 / Limited Line】蕾丝拼接衬衫上衣', '【先行予約/Limited Line】レース切り替えブラウス', 0, 200164, 'studio CLIP', '', '', '以多种棉质面料进行拼接，营造具有存在感的大人感衬衫上衣。\n\n【材质】\n将棉质刺绣面料、提花面料与蕾丝面料进行奢华组合。100%棉带来自然质感，穿着舒适惬意。\n\n【设计】\n将刺绣、提花、蕾丝等不同面料以拼接方式组合，打造具有存在感的设计亮点。领口及下摆为抽绳设计，可随心收紧，调节出类似气球轮廓的蓬松感。腋下开口较宽，即使叠穿袖子较蓬的内搭也不显臃肿，便于层次搭配。\n\n【搭配】\n通过多种面料的拼接设计，只需单穿即可完成造型。可与蕾丝下装搭配呈现女性化风格，也可与牛仔单品组合打造休闲造型。', '<font color=\"#000000\"><b>様々なコットン生地をパッチワーク風に紡いだ、<br>存在感溢れる大人のブラウス</b></font><br>ーーー<br>【素材】<br>コットン素材の刺繍生地、ジャガード生地、レース生地を贅沢に組み合わせています。<br>綿100%のナチュラルな質感で、心地よい着用感です。<br><br>【デザイン】<br>刺繍・ジャガード・レースの異なる生地をパッチワーク風に切り替えた、存在感のあるデザインがポイント。<br>首回りや裾は、ドロスト仕様で絞れる設計になっており、バルーンシルエットのようなふんわりとしたボリューム感を自在に調整できます。<br>アームホールは広めに設定されており、袖にボリュームのあるインナーの上からでももたつかずに着用できる、レイヤードしやすいデザインです。<br><br>ーーー<br>【スタイリング】<br>様々な生地がパッチワーク風に組み合わさっているため、一枚でさらりと着こなすだけで様になります。<br>レースのボトムと合わせてフェミニンに合わせたり、デニムと合わせたカジュアルなスタイルもオススメです。', '6900.0 JPY', 420.90, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:13:07', '2026-04-02 04:19:34', 'adastria_664409', '', '69cd72d7a7ab618f2967cc17', '生活/休闲', '', '女', '青年（18-44岁）', '棉100%', 'https://www.dot-st.com/studioclip/disp/item/664409/?COLOR_CD=52', '上装', '衬衫', '女式衬衫', '', 'blouse', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/studio_clip/20260401/item_664409_main_88_1774593513_b.webp', 0, 0, 6, 0.82311, 0, 1, 1, 0, 0, 3, NULL, '透气，舒适，轻盈', '舒适,轻盈', '', '多种棉质面料拼接设计，包含刺绣、提花和蕾丝,领口和下摆配有抽绳，可调节廓形与蓬松度,腋下开口较大，方便与有体积感袖子的内搭叠穿,整体为棉质天然手感，强调穿着舒适', '花卉图案', '该产品名称为“レース切り替えブラウス”，并描述为大人のブラウス，属于上装类的衬衫/女式上衣，非针织卫衣也非T恤，更不是外套类，因此在给定列表中最匹配的类别是“blouse（女式衬衫上衣）”。blouse 一般指以布帛为主、版型偏宽松、带有设计细节的上衣，本款采用多种棉质刺绣、提花、蕾丝布料拼接，具备明显的女式衬衫/上衣特征，故选择 sub_category: blouse。', 1, 1, 0, 0, 'blouse', NULL, '', 0, NULL, 0, NULL, NULL, '88', 'ネイビー88', 0);
INSERT INTO `clothing_info` VALUES (19996771, '前片蕾丝拼接背心', 'フロントレースドッキングタンクトップ', 0, 200164, 'studio CLIP', '', '', '这是一款兼具简约与优雅风格的背心，上身既可日常休闲也能搭配偏精致的造型。\n\n【材质】\n主体采用柔软亲肤的天竺针织面料，穿着舒适。前身叠加网眼蕾丝面料，增加层次与精致感。\n\n【设计】\n前片蕾丝拼接设计令这款背心带有类似衬衫般的精致感，因此既适合偏利落的通勤风，也能演绎健康自然的休闲风。通过不同单品组合，可打造成熟休闲或清爽健康的多种造型。\n\n【搭配】\n可与牛仔裤、开衫或衬衫外搭组合形成轻松大人的休闲搭配，也适合作为背带裤等款式的内搭，营造清爽健康的穿搭效果。', '<b><font color=\"000000\">綺麗めスタイルにも合わせやすい一枚<br>様々な着こなしが楽しめるタンクトップ</font></b><br>ーーー<br><br>【素材】<br>本体は柔らかく着心地の良い天竺素材を使用、<br>前身頃は上にメッシュレースを重ねています。<br><br>【デザイン】<br>レースのドッキングデザインが新鮮なタンクトップ。<br>タンクトップですがブラウス見えするので、綺麗めスタイルにも合わせやすい一着です。<br>合わせるアイテムを変えて大人なカジュアルスタイルも、ヘルシースタイルもお楽しみいただけます。<br><br><br>トップス　インナー　タンク　タンクトップ　レース<br><br>ーーー<br><br>【スタイリング】<br>ボトムはデニムパンツ、シャツやカーデを羽織った大人カジュアルな着こなしがおすすめ。<br>サロペットのインに合わせたヘルシーな着こなしも素敵です◎', '2900.0 JPY', 176.90, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:13:07', '2026-04-02 04:19:35', 'adastria_645826', '', '69cd72d7a7ab618f2967cc19', '生活/休闲', '', '女', '青年（18-44岁）', '棉100%', 'https://www.dot-st.com/studioclip/disp/item/645826/?COLOR_CD=12', '上装', '背心', '背心', '', 'tank top', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/studio_clip/20260401/item_645826_main_12_1774239087_b.jpg', 0, 0, 1, 0.99559, 0, -2, 0, 0, 0, 3, NULL, '透气，舒适穿着', '舒适穿着', '', '前身叠加精致网眼蕾丝，视觉上有类似衬衫/女式上衣的效果,本体为柔软天竺针织面料，贴身舒适,无袖设计，适合夏季或内搭使用,可搭配开衫、衬衫或背带裤，风格多变', '纯色，纯色', '商品名称为「タンクトップ」，为无袖圆领上衣，作为打底或单穿上衣使用，明显属于贴身上装类别中的“tank top（背心 / 吊带背心）”。虽然前片有蕾丝装饰，整体版型仍是基础背心款，因此选择子类目“tank top（无袖贴身上衣，常作打底或夏季单穿）”。', 1, 0, 0, 0, 'tank top', NULL, '', 0, NULL, 0, NULL, NULL, '12', 'ライトグレー12', 0);
INSERT INTO `clothing_info` VALUES (19996772, '前片蕾丝拼接背心', 'フロントレースドッキングタンクトップ', 0, 200164, 'studio CLIP', '', '', '这是一款兼具简约与优雅风格的背心，上身既可日常休闲也能搭配偏精致的造型。\n\n【材质】\n主体采用柔软亲肤的天竺针织面料，穿着舒适。前身叠加网眼蕾丝面料，增加层次与精致感。\n\n【设计】\n前片蕾丝拼接设计令这款背心带有类似衬衫般的精致感，因此既适合偏利落的通勤风，也能演绎健康自然的休闲风。通过不同单品组合，可打造成熟休闲或清爽健康的多种造型。\n\n【搭配】\n可与牛仔裤、开衫或衬衫外搭组合形成轻松大人的休闲搭配，也适合作为背带裤等款式的内搭，营造清爽健康的穿搭效果。', '<b><font color=\"000000\">綺麗めスタイルにも合わせやすい一枚<br>様々な着こなしが楽しめるタンクトップ</font></b><br>ーーー<br><br>【素材】<br>本体は柔らかく着心地の良い天竺素材を使用、<br>前身頃は上にメッシュレースを重ねています。<br><br>【デザイン】<br>レースのドッキングデザインが新鮮なタンクトップ。<br>タンクトップですがブラウス見えするので、綺麗めスタイルにも合わせやすい一着です。<br>合わせるアイテムを変えて大人なカジュアルスタイルも、ヘルシースタイルもお楽しみいただけます。<br><br><br>トップス　インナー　タンク　タンクトップ　レース<br><br>ーーー<br><br>【スタイリング】<br>ボトムはデニムパンツ、シャツやカーデを羽織った大人カジュアルな着こなしがおすすめ。<br>サロペットのインに合わせたヘルシーな着こなしも素敵です◎', '2900.0 JPY', 176.90, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:13:07', '2026-04-02 04:19:36', 'adastria_645826', '', '69cd72d7a7ab618f2967cc19', '生活/休闲', '', '女', '青年（18-44岁）', '棉100%', 'https://www.dot-st.com/studioclip/disp/item/645826/?COLOR_CD=12', '上装', '背心', '背心', '', 'tank top', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/studio_clip/20260401/item_645826_main_16_1774239089_b.jpg', 0, 0, 1, 0.99806, 0, -2, 0, 0, 0, 3, NULL, '透气，舒适穿着', '舒适穿着', '', '前身叠加精致网眼蕾丝，视觉上有类似衬衫/女式上衣的效果,本体为柔软天竺针织面料，贴身舒适,无袖设计，适合夏季或内搭使用,可搭配开衫、衬衫或背带裤，风格多变', '纯色，纯色', '商品名称为「タンクトップ」，为无袖圆领上衣，作为打底或单穿上衣使用，明显属于贴身上装类别中的“tank top（背心 / 吊带背心）”。虽然前片有蕾丝装饰，整体版型仍是基础背心款，因此选择子类目“tank top（无袖贴身上衣，常作打底或夏季单穿）”。', 1, 1, 0, 0, 'tank top', NULL, '', 0, NULL, 0, NULL, NULL, '16', 'スモーク16', 0);
INSERT INTO `clothing_info` VALUES (19996773, '前片蕾丝拼接背心', 'フロントレースドッキングタンクトップ', 0, 200164, 'studio CLIP', '', '', '这是一款兼具简约与优雅风格的背心，上身既可日常休闲也能搭配偏精致的造型。\n\n【材质】\n主体采用柔软亲肤的天竺针织面料，穿着舒适。前身叠加网眼蕾丝面料，增加层次与精致感。\n\n【设计】\n前片蕾丝拼接设计令这款背心带有类似衬衫般的精致感，因此既适合偏利落的通勤风，也能演绎健康自然的休闲风。通过不同单品组合，可打造成熟休闲或清爽健康的多种造型。\n\n【搭配】\n可与牛仔裤、开衫或衬衫外搭组合形成轻松大人的休闲搭配，也适合作为背带裤等款式的内搭，营造清爽健康的穿搭效果。', '<b><font color=\"000000\">綺麗めスタイルにも合わせやすい一枚<br>様々な着こなしが楽しめるタンクトップ</font></b><br>ーーー<br><br>【素材】<br>本体は柔らかく着心地の良い天竺素材を使用、<br>前身頃は上にメッシュレースを重ねています。<br><br>【デザイン】<br>レースのドッキングデザインが新鮮なタンクトップ。<br>タンクトップですがブラウス見えするので、綺麗めスタイルにも合わせやすい一着です。<br>合わせるアイテムを変えて大人なカジュアルスタイルも、ヘルシースタイルもお楽しみいただけます。<br><br><br>トップス　インナー　タンク　タンクトップ　レース<br><br>ーーー<br><br>【スタイリング】<br>ボトムはデニムパンツ、シャツやカーデを羽織った大人カジュアルな着こなしがおすすめ。<br>サロペットのインに合わせたヘルシーな着こなしも素敵です◎', '2900.0 JPY', 176.90, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:13:07', '2026-04-02 04:19:37', 'adastria_645826', '', '69cd72d7a7ab618f2967cc19', '生活/休闲', '', '女', '青年（18-44岁）', '棉100%', 'https://www.dot-st.com/studioclip/disp/item/645826/?COLOR_CD=12', '上装', '背心', '背心', '', 'tank top', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/studio_clip/20260401/item_645826_main_52_1774239092_b.jpg', 0, 0, 1, 0.99927, 0, -2, 0, 0, 0, 3, NULL, '透气，舒适穿着', '舒适穿着', '', '前身叠加精致网眼蕾丝，视觉上有类似衬衫/女式上衣的效果,本体为柔软天竺针织面料，贴身舒适,无袖设计，适合夏季或内搭使用,可搭配开衫、衬衫或背带裤，风格多变', '纯色，纯色', '商品名称为「タンクトップ」，为无袖圆领上衣，作为打底或单穿上衣使用，明显属于贴身上装类别中的“tank top（背心 / 吊带背心）”。虽然前片有蕾丝装饰，整体版型仍是基础背心款，因此选择子类目“tank top（无袖贴身上衣，常作打底或夏季单穿）”。', 1, 2, 0, 0, 'tank top', NULL, '', 0, NULL, 0, NULL, NULL, '52', 'アイボリー52', 0);
INSERT INTO `clothing_info` VALUES (19996768, 'FESTINO 沙龙护理负离子发梳', 'フェスティノ サロンケアイオンブラシ', 0, 200164, 'studio CLIP', '', '', '为自己犒劳或作为礼物都很适合。\n\n这是一款为头发注入负离子、为头皮带来舒适刺激的新型美发护理工具，以“沙龙级”的舒适体验多方位护理头发与头皮。\n\n通过安装软质或硬质气垫梳头部，长按电源键启动振动与负离子功能，并通过LED灯提示工作状态。先从发梢开始梳理，配合振动帮助放松头皮，更易去除头发和头皮上的污垢；再从发根到发梢缓慢梳理，使负离子均匀作用于整个头发，打造顺滑有光泽的秀发。\n\n适用于日常的头发护理、头皮护理与面部周围的沙龙级护理体验。', '<b><font color=\"000000\">自分へのご褒美やギフトにも</font></b><br><br>髪にイオン、頭皮に刺激の新ヘアケア習慣アイテム。<br>“サロン級”の心地良さで髪と頭皮をケアする多機能ブラシです。<br><br>■原産国：中国<br>■仕様：単4形アルカリ乾電池×2本（別売）<br><br>【使用方法】<br>１）本体に、ソフトクッションブラシまたはハードクッションブラシを取り付けます。<br>２）電源スイッチを長押しして電源を入れると本体が振動し、LEDが点灯してイオンが発生します。<br>３）毛先からブラッシングして髪のからまりをほぐします。ヘッドの振動で頭皮をほぐして、髪と頭皮の汚れを落としやすくします。<br>４）マイナスイオンが髪全体に行き渡るように、根元から毛先までゆっくりブラッシングすることでキレイなツヤ髪に！<br><br>【使用上の注意】<br>※ブラシに整髪剤などをつけて使用しないでください。劣化の原因になります。<br>※濡れた髪に使用しないでください。故障の恐れがあります。<br><br><br>ーーー<br>ヘアケア　頭皮ケア　フェイシャルサロンケア<br>ーーー', '4000.0 JPY', 244.00, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:14:12', '2026-04-02 04:19:33', 'adastria_326481', '', '69cd72d7a7ab618f2967cc10', '生活/休闲', '', '通用', '青年（18-44岁）', NULL, 'https://www.dot-st.com/studioclip/disp/item/326481/?COLOR_CD=10', '其他服饰/物品', '其他', '配件', '', 'accessories', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/studio_clip/20260401/item_326481_main_10_1743500552_b.jpg', 0, 0, 9, 0.75292, 0, 1, 0, 0, 0, 3, NULL, '头皮按摩，头皮护理，改善发丝顺滑度，增加头发光泽，辅助清除头皮污垢和皮脂，多功能美容护理', '头皮按摩,头皮护理,改善发丝顺滑度,增加头发光泽,辅助清除头皮污垢和皮脂,多功能美容护理', '负离子功能,震动按摩技术', '适合作为犒劳自己或赠礼使用,提供软、硬两种可替换气垫梳头部,通过LED指示离子工作状态,使用干电池供电，便于携带使用,适用于头发和头皮的日常沙龙级护理', '纯色，纯色', '该产品为电动离子梳，用于头发与头皮护理，不属于服装或家纺类，而是随身美容工具。现有分类中最接近的是“accessories（配饰）”，可涵盖此类非服装、非家居但与个人使用相关的小型用品。accessories 在这里理解为与个人造型、美容相关的附属用品，最为贴切。', 0, 0, 0, 0, 'accessories', NULL, '', 0, NULL, 0, NULL, NULL, '10', 'ホワイト(10)', 0);
INSERT INTO `clothing_info` VALUES (19996765, '假裹身条纹长款半身裙 / 线上限量预售', 'ラップフウストライプスカート/WEB先行予約', 0, 200336, 'A part by', '', '', '——\n・设计感强的假裹身I字型长款半身裙\n——\n\n【设计与特点】\n・采用包裹式设计，呈直筒I字轮廓\n・口袋为不对称设计，设置在左侧及右后臀部\n・左侧内里开衩，既避免肌肤过度裸露，又方便行走\n・后中拉链开合，穿脱方便\n・配有里布，提升舒适度与遮蔽性\n\n【面料特点】\n・再生纤维和黏胶带来良好垂坠感，麻纤维营造自然质感，配以细针条纹，呈现成熟干练气质\n・触感清爽顺滑，夏季穿着亦轻盈凉爽\n\n【搭配建议】\n・只需搭配简约T恤或背心，即可利用裙装的设计感营造时髦造型', 'ーーー<br>・デザイン性の高いラップ風のIラインチェックマキシスカート<br>ーーー<br><br>【デザインと特徴】							<br>・ポケットは変形で、左脇と右ヒップの２か所があります			<br>・左脇内側にスリットを入れているので、素肌が見えすぎないですが、足さばきもよく、		<br>後ろファスナー空きなのでさっとはけて着やすさもあります◎				<br>・裏地つきです。<br><br>【素材特徴】									<br>・レーヨンの落ち感とリネンのナチュラル感に、ピンストライプの大人っぽさが絶妙な<br>バランスよい生地								<br>・さらっとした質感で夏も涼しく<br><br>【スタイリング】<br>・トップスはシンプルなTシャツやタンクトップでも、デザイン性があるスカートなのでとってもおしゃれに◎<br><br>【洗濯可否】<br>手洗いでのお手入れが可能です。<br>', '12000.0 JPY', 732.00, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:15:15', '2026-04-02 04:19:30', 'adastria_672044', '', '69cd72d7a7ab618f2967cc09', '生活/休闲', '', '女', '青年（18-44岁）', '粘胶16%,涤纶5%,亚麻4%', 'https://www.dot-st.com/apartbylowrys/disp/item/672044/?COLOR_CD=58', '裙装', '半身裙', '长裙', '', 'maxi skirt', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/a_part_by/20260401/item_672044_main_58_1774597314_b.jpg', 0, 0, 1, 0.53136, 0, -2, 0, 0, 0, 3, NULL, '透气，凉感穿着，修饰身形', '凉感穿着,修饰身形', '', '包裹感I字型廓形，显瘦拉长腿部线条,左侧内开衩兼顾活动性与端庄度,不对称包裹式门襟增加设计感,带变形口袋，兼具实用与装饰,有全裙里布，提升舒适度与防透性,适合夏季搭配简约上装打造成熟感造型', '条纹', '商品为“ラップ風Iラインチェックマキシスカート”，从图片看为及踝长度、包裹式设计的直筒长裙，属于覆盖小腿到脚踝的长款半身裙，对应的英文子类应为“maxi skirt（长款半身裙）”，这一定义指长度在小腿下部至脚踝的裙装，与本品长度和款式最为匹配。', 1, 0, 0, 0, 'maxi skirt', NULL, '', 0, NULL, 0, NULL, NULL, '58', 'ブラウンチェック(58)', 0);
INSERT INTO `clothing_info` VALUES (19996766, '假裹身条纹长款半身裙 / 线上限量预售', 'ラップフウストライプスカート/WEB先行予約', 0, 200336, 'A part by', '', '', '——\n・设计感强的假裹身I字型长款半身裙\n——\n\n【设计与特点】\n・采用包裹式设计，呈直筒I字轮廓\n・口袋为不对称设计，设置在左侧及右后臀部\n・左侧内里开衩，既避免肌肤过度裸露，又方便行走\n・后中拉链开合，穿脱方便\n・配有里布，提升舒适度与遮蔽性\n\n【面料特点】\n・再生纤维和黏胶带来良好垂坠感，麻纤维营造自然质感，配以细针条纹，呈现成熟干练气质\n・触感清爽顺滑，夏季穿着亦轻盈凉爽\n\n【搭配建议】\n・只需搭配简约T恤或背心，即可利用裙装的设计感营造时髦造型', 'ーーー<br>・デザイン性の高いラップ風のIラインチェックマキシスカート<br>ーーー<br><br>【デザインと特徴】							<br>・ポケットは変形で、左脇と右ヒップの２か所があります			<br>・左脇内側にスリットを入れているので、素肌が見えすぎないですが、足さばきもよく、		<br>後ろファスナー空きなのでさっとはけて着やすさもあります◎				<br>・裏地つきです。<br><br>【素材特徴】									<br>・レーヨンの落ち感とリネンのナチュラル感に、ピンストライプの大人っぽさが絶妙な<br>バランスよい生地								<br>・さらっとした質感で夏も涼しく<br><br>【スタイリング】<br>・トップスはシンプルなTシャツやタンクトップでも、デザイン性があるスカートなのでとってもおしゃれに◎<br><br>【洗濯可否】<br>手洗いでのお手入れが可能です。<br>', '12000.0 JPY', 732.00, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:15:15', '2026-04-02 04:19:31', 'adastria_672044', '', '69cd72d7a7ab618f2967cc09', '生活/休闲', '', '女', '青年（18-44岁）', '粘胶16%,涤纶5%,亚麻4%', 'https://www.dot-st.com/apartbylowrys/disp/item/672044/?COLOR_CD=58', '裙装', '半身裙', '长裙', '', 'maxi skirt', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/a_part_by/20260401/item_672044_main_88_1774597307_b.jpg', 0, 0, 1, 0.78493, 0, -2, 0, 0, 0, 3, NULL, '透气，凉感穿着，修饰身形', '凉感穿着,修饰身形', '', '包裹感I字型廓形，显瘦拉长腿部线条,左侧内开衩兼顾活动性与端庄度,不对称包裹式门襟增加设计感,带变形口袋，兼具实用与装饰,有全裙里布，提升舒适度与防透性,适合夏季搭配简约上装打造成熟感造型', '条纹', '商品为“ラップ風Iラインチェックマキシスカート”，从图片看为及踝长度、包裹式设计的直筒长裙，属于覆盖小腿到脚踝的长款半身裙，对应的英文子类应为“maxi skirt（长款半身裙）”，这一定义指长度在小腿下部至脚踝的裙装，与本品长度和款式最为匹配。', 1, 1, 0, 0, 'maxi skirt', NULL, '', 0, NULL, 0, NULL, NULL, '88', 'ネイビーチェック(88)', 0);
INSERT INTO `clothing_info` VALUES (19996763, '缝线牛仔猎帽', 'ステッチデニムハンチング', 0, 31749826, 'JEANASIS', '', '', '为搭配增添随性感的牛仔猎帽。\n简约轮廓的猎帽设计，采用基础色系，日常穿搭易于搭配。后部配有腰带和按扣，可调节头围尺寸。', 'ーーー<br>スタイリングにこなれ感をプラスするデニムハンチング<br>ーーー<br><br>シンプルなシルエットのハンチング帽です。<br><br>ベーシックなカラー展開で、スタイリングしやすいところが◎<br><br>後ろのベルト・スナップボタンで頭回りの調節が可能です。', '4000.0 JPY', 244.00, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:15:43', '2026-04-02 04:19:28', 'adastria_663105', '', '69cd72d7a7ab618f2967cc02', '生活/休闲', '', '通用', '青年（18-44岁）', '棉100%', 'https://www.dot-st.com/jeanasis/disp/item/663105/?COLOR_CD=88', '其他服饰/物品', '其他', NULL, '', 'hat', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/jeanasis/20260401/item_663105_main_88_1774595925_b.jpg', 0, 0, 9, 0.94506, 0, 1, 0, 0, 0, 3, NULL, '可调节头围，易于搭配造型', '可调节头围,易于搭配造型', '', '使用牛仔面料并配有对比色车线装饰,后部配有腰带与按扣可调节尺寸,造型简洁，适合日常穿搭', '纯色，纯色', '根据商品名称“デニムハンチング”和图片可知，这是用于佩戴在头部的配饰类单品，属于帽子范畴而非服装或家纺。给定枚举中与之最接近的类别是“hat（帽子）”，其定义为：佩戴在头部用于遮挡、装饰或造型的各类帽饰，本品的哈报帽造型、尺寸调节设计等都符合这一定义。', 1, 0, 0, 0, 'hat', NULL, '', 0, NULL, 0, NULL, NULL, '88', 'ネイビー(88)', 0);
INSERT INTO `clothing_info` VALUES (19996764, '缝线牛仔猎帽', 'ステッチデニムハンチング', 0, 31749826, 'JEANASIS', '', '', '为搭配增添随性感的牛仔猎帽。\n简约轮廓的猎帽设计，采用基础色系，日常穿搭易于搭配。后部配有腰带和按扣，可调节头围尺寸。', 'ーーー<br>スタイリングにこなれ感をプラスするデニムハンチング<br>ーーー<br><br>シンプルなシルエットのハンチング帽です。<br><br>ベーシックなカラー展開で、スタイリングしやすいところが◎<br><br>後ろのベルト・スナップボタンで頭回りの調節が可能です。', '4000.0 JPY', 244.00, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:15:43', '2026-04-02 04:19:29', 'adastria_663105', '', '69cd72d7a7ab618f2967cc02', '生活/休闲', '', '通用', '青年（18-44岁）', '棉100%', 'https://www.dot-st.com/jeanasis/disp/item/663105/?COLOR_CD=88', '其他服饰/物品', '其他', NULL, '', 'hat', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/jeanasis/20260401/item_663105_main_09_1774595927_b.jpg', 0, 0, 9, 0.94889, 0, 1, 0, 0, 0, 3, NULL, '可调节头围，易于搭配造型', '可调节头围,易于搭配造型', '', '使用牛仔面料并配有对比色车线装饰,后部配有腰带与按扣可调节尺寸,造型简洁，适合日常穿搭', '纯色，纯色', '根据商品名称“デニムハンチング”和图片可知，这是用于佩戴在头部的配饰类单品，属于帽子范畴而非服装或家纺。给定枚举中与之最接近的类别是“hat（帽子）”，其定义为：佩戴在头部用于遮挡、装饰或造型的各类帽饰，本品的哈报帽造型、尺寸调节设计等都符合这一定义。', 1, 1, 0, 0, 'hat', NULL, '', 0, NULL, 0, NULL, NULL, '09', 'ブラック(09)', 0);
INSERT INTO `clothing_info` VALUES (19996761, '内搭层次感假两件T恤', 'Inner layerカットソー', 0, 31749825, 'HARE', '', '', '一件即可完成造型的精心设计单品，将舒适感与前卫感兼具的假两件T恤。将半袖T恤与条纹袖巧妙拼接，呈现充满玩味的假叠穿设计。领口沿用人气宽松领版型，保持放松的穿着感同时不显邋遢，营造恰到好处的随性气质。无需复杂层叠，仅此一件就能为造型增添层次与节奏感。\n\n面料采用对肌肤友好的高棉含量柔软天竺针织，兼具天然材质特有的顺滑触感与良好透气性，长时间穿着也不易产生负担。布料具备适度伸缩性与一定耐穿度，既适合单穿，也可作为内搭不显臃肿，四季皆可灵活运用，是兼具设计感与实用性的日常单品。', 'ーーー<br><br>1枚で完成する緻密な計算。心地よさとエッジを両立したフェイクレイヤードTシャツ。<br><br>ーーー<br><br><b>DESIGN</b><br>半袖Tシャツにボーダー柄の袖をドッキングした、HAREらしい遊び心溢れるフェイクレイヤードデザイン。<br>首元は定評のあるユルネックTと同寸に設定されており、リラックスした着心地をキープしながらも、だらしなく見えない絶妙な抜け感を演出します。<br>複雑な重ね着をせずとも、これ1枚でスタイリングに奥行きとリズムが生まれる、まさにスタイリング完結型の一着。<br><br><b>MATERIAL</b><br>肌への優しさを追求した、綿混率95％以上の柔らかな天竺素材を採用。<br>天然素材ならではの滑らかな肌触りと通気性を備えており、長時間の着用でもストレスを感じさせない着心地を実現しました。<br>デザイン性の高さに負けない着心地の良」を両立させることで、デイリーユースに最適な仕上がりに。<br>適度な伸縮性とタフさを兼ね備えた生地は、1枚着としてはもちろん、インナー使いでもゴワつかず、シーズンを問わずマルチに活躍する機能美アイテムです。', '6300.0 JPY', 384.30, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:15:54', '2026-04-02 04:19:27', 'adastria_662486', '', '69cd72d7a7ab618f2967cbf3', '生活/休闲', '', '通用', '青年（18-44岁）', '棉92%,氨纶8%', 'https://www.dot-st.com/hare/disp/item/662486/?COLOR_CD=09', '上装', 'T恤', 'T恤', '', 't-shirt', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/hare/20260401/item_662486_main_09_1773298495_b.jpg', 0, 0, 2, 0.99175, 0, 1, 1, 0, 0, 3, NULL, '透气，高弹力，舒适亲肤', '舒适亲肤', '', '假两件叠穿设计，短袖与条纹袖组合形成层次感,采用高棉含量天竺针织，面料柔软有一定厚度和挺括度,适合作为单穿或内搭，多季节穿着', '条纹', '从图片和文案看，这是一件短袖圆领针织上衣，强调“Tシャツ”“カットソー”，无拉链或开襟，不属于卫衣或衬衫，且为日常内外皆可穿的基础上装，最符合“Tシャツ”的范畴。因此选择子类为“t-shirt（圆领针织短袖上衣）”。', 1, 0, 0, 0, 't-shirt', NULL, '', 0, NULL, 0, NULL, NULL, '09', 'ブラック09', 0);
INSERT INTO `clothing_info` VALUES (19996762, '内搭层次感假两件T恤', 'Inner layerカットソー', 0, 31749825, 'HARE', '', '', '一件即可完成造型的精心设计单品，将舒适感与前卫感兼具的假两件T恤。将半袖T恤与条纹袖巧妙拼接，呈现充满玩味的假叠穿设计。领口沿用人气宽松领版型，保持放松的穿着感同时不显邋遢，营造恰到好处的随性气质。无需复杂层叠，仅此一件就能为造型增添层次与节奏感。\n\n面料采用对肌肤友好的高棉含量柔软天竺针织，兼具天然材质特有的顺滑触感与良好透气性，长时间穿着也不易产生负担。布料具备适度伸缩性与一定耐穿度，既适合单穿，也可作为内搭不显臃肿，四季皆可灵活运用，是兼具设计感与实用性的日常单品。', 'ーーー<br><br>1枚で完成する緻密な計算。心地よさとエッジを両立したフェイクレイヤードTシャツ。<br><br>ーーー<br><br><b>DESIGN</b><br>半袖Tシャツにボーダー柄の袖をドッキングした、HAREらしい遊び心溢れるフェイクレイヤードデザイン。<br>首元は定評のあるユルネックTと同寸に設定されており、リラックスした着心地をキープしながらも、だらしなく見えない絶妙な抜け感を演出します。<br>複雑な重ね着をせずとも、これ1枚でスタイリングに奥行きとリズムが生まれる、まさにスタイリング完結型の一着。<br><br><b>MATERIAL</b><br>肌への優しさを追求した、綿混率95％以上の柔らかな天竺素材を採用。<br>天然素材ならではの滑らかな肌触りと通気性を備えており、長時間の着用でもストレスを感じさせない着心地を実現しました。<br>デザイン性の高さに負けない着心地の良」を両立させることで、デイリーユースに最適な仕上がりに。<br>適度な伸縮性とタフさを兼ね備えた生地は、1枚着としてはもちろん、インナー使いでもゴワつかず、シーズンを問わずマルチに活躍する機能美アイテムです。', '6300.0 JPY', 384.30, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:15:54', '2026-04-02 04:19:28', 'adastria_662486', '', '69cd72d7a7ab618f2967cbf3', '生活/休闲', '', '通用', '青年（18-44岁）', '棉92%,氨纶8%', 'https://www.dot-st.com/hare/disp/item/662486/?COLOR_CD=09', '上装', 'T恤', 'T恤', '', 't-shirt', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/hare/20260401/item_662486_main_19_1773298498_b.webp', 0, 0, 2, 0.99490, 0, 1, 1, 0, 0, 3, NULL, '透气，高弹力，舒适亲肤', '舒适亲肤', '', '假两件叠穿设计，短袖与条纹袖组合形成层次感,采用高棉含量天竺针织，面料柔软有一定厚度和挺括度,适合作为单穿或内搭，多季节穿着', '条纹', '从图片和文案看，这是一件短袖圆领针织上衣，强调“Tシャツ”“カットソー”，无拉链或开襟，不属于卫衣或衬衫，且为日常内外皆可穿的基础上装，最符合“Tシャツ”的范畴。因此选择子类为“t-shirt（圆领针织短袖上衣）”。', 1, 1, 0, 0, 't-shirt', NULL, '', 0, NULL, 0, NULL, NULL, '19', 'グレー19', 0);
INSERT INTO `clothing_info` VALUES (19996755, '刺绣针织POLO衫', 'シシュウニットポロ', 0, 31749825, 'HARE', '', '', '这款针织POLO衫将经典的优雅气质与当下潮流感结合，领口与袖口处的花卉刺绣格外吸睛，在基础款式上增添艺术感与精致度。以流行的针织POLO为基础，通过细腻的刺绣点缀，让脸部周围更加明亮有神。整体轮廓略带宽松感，下摆适度收口，不扎进下装也能呈现良好比例。纽扣选用与衣身融为一体的颜色，使刺绣图案更加突出，整体视觉干净简约。\n面料采用混有粘胶纤维的高弹力纱线织成高针密针织布，织目细腻平整，手感顺滑，带有适度光泽，能提升整体穿搭的摩登气质。面料具有良好的弹性，不限制身体活动，穿着轻松舒适。', 'ーーー<br><br>クラシックな上品さとトレンド感を融合させた、刺繍が目を惹くデザインニットポロ。<br><br>ーーー<br><br><span style=\"font-weight: bold; font-size: 130%\">DESIGN</span><br>襟元に施されたフラワー刺繍が特徴。トレンドのニットポロをベースに、繊細な刺繍を取り入れることで、顔周りを華やかに彩るアート性の高い一着に。<br>全体的にゆとりを持たせつつ、程よく裾を絞ったトレンド感のあるシルエットを採用。タックインしなくてもバランス良く決まります。<br>ボディに馴染むボタンを使用することで、刺繍の美しさを際立たせるミニマルな表情にまとめています。<br><br><span style=\"font-weight: bold; font-size: 130%\">MATERIAL</span><br>レーヨン混のストレッチ糸を使用した、目面の綺麗なハイゲージニット生地を採用。滑らかな肌触りと適度な光沢感が、モードスタイルを格上げします。<br>ストレッチ性に優れた糸を使用しているため、身体の動きを妨げず、ストレスフリーな着用感を実現しています。', '11800.0 JPY', 719.80, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:15:55', '2026-04-02 04:19:22', 'adastria_639309', '', '69cd72d7a7ab618f2967cbe4', '生活/休闲', '', '女', '青年（18-44岁）', '粘胶70%,涤纶30%', 'https://www.dot-st.com/hare/disp/item/639309/?COLOR_CD=09', '上装', 'Polo衫', 'Polo衫', '', 'polo shirt', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/hare/20260401/item_639309_main_09_1769426009_b.jpg', 0, 0, 1, 0.99992, 0, -2, 0, 0, 0, 3, NULL, '高弹力，舒适，亲肤，有光泽感', '舒适,亲肤,有光泽感', '弹力纱线应用,高针密织造', '领口和袖口花卉刺绣装饰，增强设计感与视觉焦点,宽松版型并在下摆适度收口，营造流行廓形,采用顺色纽扣以突出刺绣图案的主体地位,高针数针织结构，表面纹理细腻整洁,整体风格兼具经典POLO元素与女性化花卉装饰', '花卉图案', '从版型和结构上看，该款为带翻领和门襟纽扣的上衣，属于典型POLO结构，并且是针织材质的长袖款式，官方名称中也写明“ニットポロ（针织POLO）”。因此在给定列表中最合适的类别是“polo shirt（POLO衫）”，即带领口和开襟纽扣的针织/针织衫式上衣。', 1, 0, 0, 0, 'polo shirt', NULL, '', 0, NULL, 0, NULL, NULL, '09', 'ブラック09', 0);
INSERT INTO `clothing_info` VALUES (19996756, '刺绣针织POLO衫', 'シシュウニットポロ', 0, 31749825, 'HARE', '', '', '这款针织POLO衫将经典的优雅气质与当下潮流感结合，领口与袖口处的花卉刺绣格外吸睛，在基础款式上增添艺术感与精致度。以流行的针织POLO为基础，通过细腻的刺绣点缀，让脸部周围更加明亮有神。整体轮廓略带宽松感，下摆适度收口，不扎进下装也能呈现良好比例。纽扣选用与衣身融为一体的颜色，使刺绣图案更加突出，整体视觉干净简约。\n面料采用混有粘胶纤维的高弹力纱线织成高针密针织布，织目细腻平整，手感顺滑，带有适度光泽，能提升整体穿搭的摩登气质。面料具有良好的弹性，不限制身体活动，穿着轻松舒适。', 'ーーー<br><br>クラシックな上品さとトレンド感を融合させた、刺繍が目を惹くデザインニットポロ。<br><br>ーーー<br><br><span style=\"font-weight: bold; font-size: 130%\">DESIGN</span><br>襟元に施されたフラワー刺繍が特徴。トレンドのニットポロをベースに、繊細な刺繍を取り入れることで、顔周りを華やかに彩るアート性の高い一着に。<br>全体的にゆとりを持たせつつ、程よく裾を絞ったトレンド感のあるシルエットを採用。タックインしなくてもバランス良く決まります。<br>ボディに馴染むボタンを使用することで、刺繍の美しさを際立たせるミニマルな表情にまとめています。<br><br><span style=\"font-weight: bold; font-size: 130%\">MATERIAL</span><br>レーヨン混のストレッチ糸を使用した、目面の綺麗なハイゲージニット生地を採用。滑らかな肌触りと適度な光沢感が、モードスタイルを格上げします。<br>ストレッチ性に優れた糸を使用しているため、身体の動きを妨げず、ストレスフリーな着用感を実現しています。', '11800.0 JPY', 719.80, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:15:55', '2026-04-02 04:19:22', 'adastria_639309', '', '69cd72d7a7ab618f2967cbe4', '生活/休闲', '', '女', '青年（18-44岁）', '粘胶70%,涤纶30%', 'https://www.dot-st.com/hare/disp/item/639309/?COLOR_CD=09', '上装', 'Polo衫', 'Polo衫', '', 'polo shirt', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/hare/20260401/item_639309_main_86_1769426002_b.jpg', 0, 0, 1, 0.99989, 0, -2, 0, 0, 0, 3, NULL, '高弹力，舒适，亲肤，有光泽感', '舒适,亲肤,有光泽感', '弹力纱线应用,高针密织造', '领口和袖口花卉刺绣装饰，增强设计感与视觉焦点,宽松版型并在下摆适度收口，营造流行廓形,采用顺色纽扣以突出刺绣图案的主体地位,高针数针织结构，表面纹理细腻整洁,整体风格兼具经典POLO元素与女性化花卉装饰', '花卉图案', '从版型和结构上看，该款为带翻领和门襟纽扣的上衣，属于典型POLO结构，并且是针织材质的长袖款式，官方名称中也写明“ニットポロ（针织POLO）”。因此在给定列表中最合适的类别是“polo shirt（POLO衫）”，即带领口和开襟纽扣的针织/针织衫式上衣。', 1, 1, 0, 0, 'polo shirt', NULL, '', 0, NULL, 0, NULL, NULL, '86', 'ブルー86', 0);
INSERT INTO `clothing_info` VALUES (19996757, '【网络先行预约 女款】2WAY透明口袋托特包', '【WEB先行予約 LADIES】2WAYクリアポケットトートバッグ', 0, 31749825, 'HARE', '', '', '适合应援活动和日常使用的大容量托特包。正面口袋可在提花图案与透明面之间切换，实现2WAY外观效果。包身容量充足，可放入A4大小文件或应援扇。侧边口袋尺寸可轻松容纳水瓶或应援灯，内侧还配有口袋，方便分类收纳。配有可挂饰品的D形环，便于增添个性装饰。整体设计带有品牌特色，风格优雅，适合搭配连衣裙、裙装等穿搭，也因为尺寸偏大且有多个口袋，非常适合学校通勤或工作通勤使用。', 'ーーー<br><br>推し活にも日常でも使える大容量トートバッグ<br><br>ーーー<br><br><span style=\"font-weight: bold; font-size: 130%\">point</span><br>□ポケットがジャガード柄とクリアの2WAY仕様えボタンを外すとクリア面に<br>□A4サイズやうちわも入る大容量<br>□サイドポケットはペットボトルやペンライトがすっぽり入るサイズ感<br>□内ポケット付きで収納力抜群<br>□チャームをつけれるDカン付き<br><br><span style=\"font-weight: bold; font-size: 130%\">styling</span><br>HAREらしいデザインで上品なアイテムな為、ワンピースやスカートなどに合わせたスタイリングがおすすめ◎<br>パソコンも収納できる大きめなサイズ感で、ポケットも沢山ある為、学校やお仕事にも万能なサイズ感です。', '6363.0 JPY', 388.14, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:15:55', '2026-04-02 04:19:23', 'adastria_668116', '', '69cd72d7a7ab618f2967cbe2', '生活/休闲', '', '女', '青年（18-44岁）', '涤纶100%', 'https://www.dot-st.com/hare/disp/item/668116/?COLOR_CD=09', '其他服饰/物品', '其他', '配件', '', 'accessories', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/hare/20260401/item_668116_main_09_1774954420_b.jpg', 0, 0, 8, 0.92761, 0, 1, 1, 0, 0, 3, NULL, '大容量收纳，多口袋设计，可收纳电脑，可收纳A4文件和应援物品，日常通勤与上学两用', '大容量收纳,多口袋设计,可收纳电脑,可收纳A4文件和应援物品,日常通勤与上学两用', '', '正面配有可翻转使用的透明口袋与提花口袋设计，形成2WAY外观效果,侧边口袋尺寸适合放置水瓶或应援灯等直筒物品,内里设计收纳口袋提升整理性,附带可挂饰品的D形环，方便进行个性化装饰,整体造型简洁利落，适合搭配连衣裙和裙装等偏优雅穿搭', '其他', '该商品是用于携带物品的托特包，并非穿在身上的服装，也不是家纺类产品。从图片和描述看，是一款大容量2WAY手提包/托特包，带透明口袋和多收纳设计，因此在给定选项中最合适归到“accessories（配饰类，含包袋等）”。accessories 的定义：用于搭配穿搭或提高便利性的附属品，如包袋、帽子、围巾等，本品完全符合这一特点。', 0, 0, 0, 0, 'accessories', NULL, '', 0, NULL, 0, NULL, NULL, '09', 'ブラック09', 0);
INSERT INTO `clothing_info` VALUES (19996758, '【官网先行预约 可成套搭配】DABO宽松蕾丝阔腿裤', '【WEB先行予約 SET UP対応】DABOルーズレースパンツ', 0, 31749825, 'HARE', '', '', '———\n\n以精致蕾丝勾勒出的摩登而感性的阔腿廓形设计长裤。\n\n【设计】\n裤筒向下逐渐加大分量，形成DABO式宽松轮廓，行走间面料自然流动，存在感十足。腰部加入褶裥，增加臀腰余量的同时，褶裥延伸出的正中垂坠线条强化纵向比例，起到修饰身形的效果。裤脚配有抽绳，可根据造型需要调节轮廓。将本身带有女性气息的蕾丝，以深色调与宽裤脚形式呈现，营造出HARE风格的前卫摩登平衡感。\n\n【面料】\n采用在整体表面铺满精致花卉图案的奢华花式蕾丝。通过控制蕾丝特有的甜美感，兼具柔润厚实的质感与优雅光泽。立体花纹的凹凸结构使光线产生复杂反射，即便是深色也不会显得单调，呈现富有层次的明暗效果。面料具有适中的重量，带来优美摆动与垂坠度，使阔腿裤形成独特的顺滑落感轮廓。可与同面料上装搭配，完成成套造型。', 'ーーー<br><br>繊細なレースが描く、モードで官能的なワイドシルエットのデザインパンツ<br><br>ーーー<br><br><b>DESIGN</b><br>裾にかけて分量感を贅沢に持たせDABOルーズシルエット。歩くたびに生地が流れ、圧倒的な存在感を放ちます。<br>ウエストはタック入りで腰回りにゆとりを持たせつつ、タックから繋がるセンターのドレープが、縦のラインを強調し、スタイルアップを叶えます。<br>裾はドローコード付きでシルエットを変えて着用可能です。<br>フェミニンな要素を持つレースを、あえてダークトーンとワイドな裾幅で仕上げることで、ハレらしいエッジの効いたモードなバランスへ昇華しました。<br><br><b>MATERIAL</b><br>繊細な花柄を全面にあしらった贅沢なコードレースを採用。レース特有の甘さを抑え、しっとりとした重厚感と上品な光沢を両立させました。<br>立体的な柄の凹凸が光を複雑に反射し、濃色でも単調にならず深みのある陰影を演出します。適度な重みのある素材が美しい揺れとドレープを生み出し、ワイドパンツ特有の絶妙な落ち感のあるシルエットになります。<br><br><b>SET ITEM</b><br><a href=\'https://www.dot-st.com/hare/disp/item/667752/\'>【セットアップ対応ジャケット：ブラウザの方はコチラ】</a><br><a href=\'adastriaapp://item?itemCode=667752\'>【セットアップ対応ジャケット：アプリの方はコチラ】</a>', '12000.0 JPY', 732.00, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:15:55', '2026-04-02 04:19:24', 'adastria_667754', '', '69cd72d7a7ab618f2967cbeb', '生活/休闲', '', '通用', '青年（18-44岁）', '锦纶64%,棉19%,粘胶17%', 'https://www.dot-st.com/hare/disp/item/667754/?COLOR_CD=09', '下装', '休闲裤', '阔腿裤', '', 'palazzo pants', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/hare/20260401/item_667754_main_09_1774601579_b.jpg', 0, 0, 2, 0.92363, 0, 1, 1, 0, 0, 3, NULL, '修饰腿型，显高显瘦，可调节裤脚造型', '修饰腿型,显高显瘦,可调节裤脚造型', '', '宽松直筒剪裁，裤脚配有抽绳可变换轮廓,高腰打褶设计，带来纵向垂坠线条,整体使用大面积花型码织蕾丝面料，色调偏暗黑,面料具有一定重量感，行走时产生明显摆动与垂坠感,适合作为同面料上装的套装搭配使用', '花卉图案', '从商品名“ルーズレースパンツ”和图片来看，是高腰、极宽裤腿、整体垂坠感很强的时装长裤，且描述中强调“ワイドシルエット”“適度な重みのある素材が美しい揺れとドレープを生み出し”，符合女装中典型的阔腿拖地式“palazzo pants（阔腿裤）”定义，因此选择子分类“palazzo pants（阔腿裤）”。该子分类指裤腿从上到下宽直、轮廓飘逸、多用于时装与都市穿搭的宽腿长裤。', 1, 0, 0, 0, 'palazzo pants', NULL, '', 0, NULL, 0, NULL, NULL, '09', 'ブラック09', 0);
INSERT INTO `clothing_info` VALUES (19996759, '【官网先行预约 可成套搭配】DABO宽松蕾丝阔腿裤', '【WEB先行予約 SET UP対応】DABOルーズレースパンツ', 0, 31749825, 'HARE', '', '', '———\n\n以精致蕾丝勾勒出的摩登而感性的阔腿廓形设计长裤。\n\n【设计】\n裤筒向下逐渐加大分量，形成DABO式宽松轮廓，行走间面料自然流动，存在感十足。腰部加入褶裥，增加臀腰余量的同时，褶裥延伸出的正中垂坠线条强化纵向比例，起到修饰身形的效果。裤脚配有抽绳，可根据造型需要调节轮廓。将本身带有女性气息的蕾丝，以深色调与宽裤脚形式呈现，营造出HARE风格的前卫摩登平衡感。\n\n【面料】\n采用在整体表面铺满精致花卉图案的奢华花式蕾丝。通过控制蕾丝特有的甜美感，兼具柔润厚实的质感与优雅光泽。立体花纹的凹凸结构使光线产生复杂反射，即便是深色也不会显得单调，呈现富有层次的明暗效果。面料具有适中的重量，带来优美摆动与垂坠度，使阔腿裤形成独特的顺滑落感轮廓。可与同面料上装搭配，完成成套造型。', 'ーーー<br><br>繊細なレースが描く、モードで官能的なワイドシルエットのデザインパンツ<br><br>ーーー<br><br><b>DESIGN</b><br>裾にかけて分量感を贅沢に持たせDABOルーズシルエット。歩くたびに生地が流れ、圧倒的な存在感を放ちます。<br>ウエストはタック入りで腰回りにゆとりを持たせつつ、タックから繋がるセンターのドレープが、縦のラインを強調し、スタイルアップを叶えます。<br>裾はドローコード付きでシルエットを変えて着用可能です。<br>フェミニンな要素を持つレースを、あえてダークトーンとワイドな裾幅で仕上げることで、ハレらしいエッジの効いたモードなバランスへ昇華しました。<br><br><b>MATERIAL</b><br>繊細な花柄を全面にあしらった贅沢なコードレースを採用。レース特有の甘さを抑え、しっとりとした重厚感と上品な光沢を両立させました。<br>立体的な柄の凹凸が光を複雑に反射し、濃色でも単調にならず深みのある陰影を演出します。適度な重みのある素材が美しい揺れとドレープを生み出し、ワイドパンツ特有の絶妙な落ち感のあるシルエットになります。<br><br><b>SET ITEM</b><br><a href=\'https://www.dot-st.com/hare/disp/item/667752/\'>【セットアップ対応ジャケット：ブラウザの方はコチラ】</a><br><a href=\'adastriaapp://item?itemCode=667752\'>【セットアップ対応ジャケット：アプリの方はコチラ】</a>', '12000.0 JPY', 732.00, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:15:55', '2026-04-02 04:19:25', 'adastria_667754', '', '69cd72d7a7ab618f2967cbeb', '生活/休闲', '', '通用', '青年（18-44岁）', '锦纶64%,棉19%,粘胶17%', 'https://www.dot-st.com/hare/disp/item/667754/?COLOR_CD=09', '下装', '休闲裤', '阔腿裤', '', 'palazzo pants', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/hare/20260401/item_667754_main_05_1774601574_b.jpg', 0, 0, 6, 0.49936, 0, 1, 0, 0, 0, 3, NULL, '修饰腿型，显高显瘦，可调节裤脚造型', '修饰腿型,显高显瘦,可调节裤脚造型', '', '宽松直筒剪裁，裤脚配有抽绳可变换轮廓,高腰打褶设计，带来纵向垂坠线条,整体使用大面积花型码织蕾丝面料，色调偏暗黑,面料具有一定重量感，行走时产生明显摆动与垂坠感,适合作为同面料上装的套装搭配使用', '花卉图案', '从商品名“ルーズレースパンツ”和图片来看，是高腰、极宽裤腿、整体垂坠感很强的时装长裤，且描述中强调“ワイドシルエット”“適度な重みのある素材が美しい揺れとドレープを生み出し”，符合女装中典型的阔腿拖地式“palazzo pants（阔腿裤）”定义，因此选择子分类“palazzo pants（阔腿裤）”。该子分类指裤腿从上到下宽直、轮廓飘逸、多用于时装与都市穿搭的宽腿长裤。', 1, 1, 0, 0, 'palazzo pants', NULL, '', 0, NULL, 0, NULL, NULL, '05', 'ホワイト05', 0);
