, 0, 0, 'palazzo pants', NULL, '', 0, NULL, 0, NULL, NULL, '86', 'ネイビー86', 0);
INSERT INTO `clothing_info` VALUES (19996753, '纽扣高领针织上衣', 'ボタンハイネックカット', 0, 31749825, 'HARE', '', '', '这款高领上衣在颈部加入纽扣细节，为叠穿造型增添层次感，是本季值得入手的基础单品。\n\n【设计】\n极简高领剪裁，是打造潮流叠穿造型的关键单品。领口配有纽扣，作为衬衫或夹克的内搭时，领口处露出的纽扣成为低调的视觉亮点。领型贴合颈部线条，通过开合纽扣可以改变领口造型，拓展多种穿搭方式。\n\n【面料】\n采用棉与人造纤维混纺面料，既具有人造纤维的顺滑垂感，又保有棉质的亲肤舒适。加入少量弹性纤维，提升整体伸缩性，穿着贴身却不紧绷，带来轻松无压的穿着体验。', 'ーーー<br><br>首元のボタンディテールがレイヤードに奥行きを生む、今季マストバイのハイネックトップス。<br><br>ーーー<br><br><b>DESIGN</b><br>トレンドのレイヤードスタイルを構築する上で欠かせない、ミニマルなハイネックカットソー。 <br>ネック部分にボタンを配することで、シャツやジャケットのインナーとして着用した際に、首元から覗くボタンがさりげないアクセントとして機能します。<br>首に沿うような美しいシルエットでありながら、ボタンの開閉でニュアンスを変えられるため、スタイリングの幅を広げる一着です。<br><br><b>MATERIAL</b><br>レーヨンの滑らかさとコットンの肌馴染みの良さを両立した、着心地抜群の綿・レーヨン混紡素材を使用。<br>ポリウレタン%配合することで優れた伸縮性を実現し、体に優しくフィットしながらも窮屈感のない、ストレスフリーな着用感を叶えました。', '6300.0 JPY', 384.30, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:15:56', '2026-04-02 04:19:20', 'adastria_663080', '', '69cd72d7a7ab618f2967cbde', '生活/休闲', '', '通用', '青年（18-44岁）', '粘胶48%,棉44%,氨纶8%', 'https://www.dot-st.com/hare/disp/item/663080/?COLOR_CD=89', '上装', '毛衫', '高领毛衣', '', 'turtleneck', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/hare/20260401/item_663080_main_89_1769760748_b.jpg', 0, 0, 2, 0.98271, 0, 1, 1, 0, 0, 3, NULL, '高弹力，舒适亲肤，柔软垂坠感', '舒适亲肤,柔软垂坠感', '弹力纤维混纺', '颈部配有装饰性纽扣设计，增强层次感与造型感,适合作为衬衫或夹克内搭的极简风高领上衣,版型贴合颈部但通过开合纽扣可调整造型与露肤度,面料兼具人造纤维的顺滑与棉质的自然手感', '纯色，纯色', '商品为长袖高领（ハイネック）针织上衣，主要作为内搭或单穿上装使用，属于贴身上衣类别，不是外套或衬衫；结合图像为简洁无门襟、无开衩的套头式高领，因此在所给列表中最符合“turtleneck（高领上衣）”这一子类定义：即领口高度包覆颈部、以高领造型为主要特征的上装款式。', 1, 0, 0, 0, 'turtleneck', NULL, '', 0, NULL, 0, NULL, NULL, '89', 'ネイビー89', 0);
INSERT INTO `clothing_info` VALUES (19996754, '纽扣高领针织上衣', 'ボタンハイネックカット', 0, 31749825, 'HARE', '', '', '这款高领上衣在颈部加入纽扣细节，为叠穿造型增添层次感，是本季值得入手的基础单品。\n\n【设计】\n极简高领剪裁，是打造潮流叠穿造型的关键单品。领口配有纽扣，作为衬衫或夹克的内搭时，领口处露出的纽扣成为低调的视觉亮点。领型贴合颈部线条，通过开合纽扣可以改变领口造型，拓展多种穿搭方式。\n\n【面料】\n采用棉与人造纤维混纺面料，既具有人造纤维的顺滑垂感，又保有棉质的亲肤舒适。加入少量弹性纤维，提升整体伸缩性，穿着贴身却不紧绷，带来轻松无压的穿着体验。', 'ーーー<br><br>首元のボタンディテールがレイヤードに奥行きを生む、今季マストバイのハイネックトップス。<br><br>ーーー<br><br><b>DESIGN</b><br>トレンドのレイヤードスタイルを構築する上で欠かせない、ミニマルなハイネックカットソー。 <br>ネック部分にボタンを配することで、シャツやジャケットのインナーとして着用した際に、首元から覗くボタンがさりげないアクセントとして機能します。<br>首に沿うような美しいシルエットでありながら、ボタンの開閉でニュアンスを変えられるため、スタイリングの幅を広げる一着です。<br><br><b>MATERIAL</b><br>レーヨンの滑らかさとコットンの肌馴染みの良さを両立した、着心地抜群の綿・レーヨン混紡素材を使用。<br>ポリウレタン%配合することで優れた伸縮性を実現し、体に優しくフィットしながらも窮屈感のない、ストレスフリーな着用感を叶えました。', '6300.0 JPY', 384.30, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:15:56', '2026-04-02 04:19:21', 'adastria_663080', '', '69cd72d7a7ab618f2967cbde', '生活/休闲', '', '通用', '青年（18-44岁）', '粘胶48%,棉44%,氨纶8%', 'https://www.dot-st.com/hare/disp/item/663080/?COLOR_CD=89', '上装', '毛衫', '高领毛衣', '', 'turtleneck', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/hare/20260401/item_663080_main_80_1769760731_b.jpg', 0, 0, 2, 0.96625, 0, 1, 1, 0, 0, 3, NULL, '高弹力，舒适亲肤，柔软垂坠感', '舒适亲肤,柔软垂坠感', '弹力纤维混纺', '颈部配有装饰性纽扣设计，增强层次感与造型感,适合作为衬衫或夹克内搭的极简风高领上衣,版型贴合颈部但通过开合纽扣可调整造型与露肤度,面料兼具人造纤维的顺滑与棉质的自然手感', '纯色，纯色', '商品为长袖高领（ハイネック）针织上衣，主要作为内搭或单穿上装使用，属于贴身上衣类别，不是外套或衬衫；结合图像为简洁无门襟、无开衩的套头式高领，因此在所给列表中最符合“turtleneck（高领上衣）”这一子类定义：即领口高度包覆颈部、以高领造型为主要特征的上装款式。', 1, 1, 0, 0, 'turtleneck', NULL, '', 0, NULL, 0, NULL, NULL, '80', 'ブルー80', 0);
INSERT INTO `clothing_info` VALUES (19996746, '【网络预售】Liminal 直筒牛仔裤', '【WEB先行予約】リミナルストレートデニムパンツ', 0, 31749825, 'HARE', '', '', '追求既非宽裤也非紧身裤，而是位于两者“边界”上的微宽直筒牛仔裤。顺应由夸张宽松轮廓向更利落I型线条过渡的潮流感。外观看似简洁的直筒版型，在膝部加入轻微立体感处理，为容易显得平面的牛仔裤增加自然的层次与纵深，让裤型在搭配简单上装时也能突出存在感。\n\n为保持立体剪影的美感，选用了具有适度硬挺与支撑力的面料，不易变形，能够长时间维持利落的I字线条。采用耐用且贴肤舒适的100%棉牛仔布，穿着次数增加后会逐渐贴合身体，形成只属于个人的复古做旧表情，带来牛仔布特有的愉悦岁月变化。', 'ーーー<br><br>ワイドでもスリムでもない、境界線にある絶妙な太さを追求したストレートデニム<br><br>ーーー<br><br><b>DESIGN</b><br>※ Liminal（リミナル）＝ 境界・移行段階<br>オーバーサイズからコンパクトなIラインへとトレンドが移行する今の気分にフィットするデニムパンツ。ワイドでもスリムでもない、その「境界線」にある絶妙な太さを追求しました。<br>一見シンプルなストレートでありながら膝部分にわずかな立体感を持たせることで、平面的に見えがちなデニムに自然な奥行きをプラス。<br>これにより、シンプルなトップスとのスタイリングでも、パンツのフォルムが際立ちます。<br><br><b>MATERIAL</b><br>立体的なシルエットを美しく保つため、適度なハリとコシのある生地を選定。型崩れしにくく、きれいなIラインを長く維持します。<br>丈夫で肌馴染みの良いコットン100%のデニム生地なので穿き込むほどに体に馴染み、自分だけのヴィンテージな表情へと育っていく、デニム本来の経年変化を愉しめます。', '12000.0 JPY', 732.00, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:15:57', '2026-04-02 04:19:14', 'adastria_676302', '', '69cd72d6a7ab618f2967cbcc', '生活/休闲', '', '通用', '青年（18-44岁）', '棉100%', 'https://www.dot-st.com/hare/disp/item/676302/?COLOR_CD=09', '下装', '牛仔裤', '牛仔裤', '', 'jeans', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/hare/20260401/item_676302_main_09_1774604936_b.jpg', 0, 0, 2, 0.81197, 0, 1, 1, 0, 0, 3, NULL, '耐用，不易变形，塑形修饰腿型', '耐用,不易变形,塑形修饰腿型', '', '直筒版型，介于宽裤与修身裤之间的中宽廓形,膝部加入轻微立体造型，增强轮廓感和层次感,选用具有适度挺括感和回弹力的牛仔面料，保持笔直I型线条,穿着时间越长越能产生个人化的做旧与复古感,整条裤子整体洗水做旧效果明显，视觉上更有立体感', '其他', '从商品名称“ストレートデニムパンツ”和图片可以看出，这是用牛仔面料制作的长裤，具有典型牛仔裤结构和水洗效果，属于下装裤类中的“jeans（牛仔裤）”。“jeans”定义为以牛仔布为主要面料、通常有水洗或做旧效果、用于日常穿着的长裤，与本品完全匹配。', 1, 0, 0, 0, 'jeans', NULL, '', 0, NULL, 0, NULL, NULL, '09', 'ブラック09', 0);
INSERT INTO `clothing_info` VALUES (19996747, '【网络预售】Liminal 直筒牛仔裤', '【WEB先行予約】リミナルストレートデニムパンツ', 0, 31749825, 'HARE', '', '', '追求既非宽裤也非紧身裤，而是位于两者“边界”上的微宽直筒牛仔裤。顺应由夸张宽松轮廓向更利落I型线条过渡的潮流感。外观看似简洁的直筒版型，在膝部加入轻微立体感处理，为容易显得平面的牛仔裤增加自然的层次与纵深，让裤型在搭配简单上装时也能突出存在感。\n\n为保持立体剪影的美感，选用了具有适度硬挺与支撑力的面料，不易变形，能够长时间维持利落的I字线条。采用耐用且贴肤舒适的100%棉牛仔布，穿着次数增加后会逐渐贴合身体，形成只属于个人的复古做旧表情，带来牛仔布特有的愉悦岁月变化。', 'ーーー<br><br>ワイドでもスリムでもない、境界線にある絶妙な太さを追求したストレートデニム<br><br>ーーー<br><br><b>DESIGN</b><br>※ Liminal（リミナル）＝ 境界・移行段階<br>オーバーサイズからコンパクトなIラインへとトレンドが移行する今の気分にフィットするデニムパンツ。ワイドでもスリムでもない、その「境界線」にある絶妙な太さを追求しました。<br>一見シンプルなストレートでありながら膝部分にわずかな立体感を持たせることで、平面的に見えがちなデニムに自然な奥行きをプラス。<br>これにより、シンプルなトップスとのスタイリングでも、パンツのフォルムが際立ちます。<br><br><b>MATERIAL</b><br>立体的なシルエットを美しく保つため、適度なハリとコシのある生地を選定。型崩れしにくく、きれいなIラインを長く維持します。<br>丈夫で肌馴染みの良いコットン100%のデニム生地なので穿き込むほどに体に馴染み、自分だけのヴィンテージな表情へと育っていく、デニム本来の経年変化を愉しめます。', '12000.0 JPY', 732.00, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:15:57', '2026-04-02 04:19:15', 'adastria_676302', '', '69cd72d6a7ab618f2967cbcc', '生活/休闲', '', '通用', '青年（18-44岁）', '棉100%', 'https://www.dot-st.com/hare/disp/item/676302/?COLOR_CD=09', '下装', '牛仔裤', '牛仔裤', '', 'jeans', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/hare/20260401/item_676302_main_11_1774604945_b.jpg', 0, 0, 2, 0.98060, 0, 1, 1, 0, 0, 3, NULL, '耐用，不易变形，塑形修饰腿型', '耐用,不易变形,塑形修饰腿型', '', '直筒版型，介于宽裤与修身裤之间的中宽廓形,膝部加入轻微立体造型，增强轮廓感和层次感,选用具有适度挺括感和回弹力的牛仔面料，保持笔直I型线条,穿着时间越长越能产生个人化的做旧与复古感,整条裤子整体洗水做旧效果明显，视觉上更有立体感', '其他', '从商品名称“ストレートデニムパンツ”和图片可以看出，这是用牛仔面料制作的长裤，具有典型牛仔裤结构和水洗效果，属于下装裤类中的“jeans（牛仔裤）”。“jeans”定义为以牛仔布为主要面料、通常有水洗或做旧效果、用于日常穿着的长裤，与本品完全匹配。', 1, 1, 0, 0, 'jeans', NULL, '', 0, NULL, 0, NULL, NULL, '11', 'グレー11', 0);
