INSERT INTO `clothing_info` VALUES (19996750, '【网络限定预售 接触冷感/可成套搭配 女款】多WAY可拆背带口袋工装裤', '【WEB先行予約 接触冷感/SET UP対応 LADIES】マルチWAYサスツキポケットカーゴパンツ', 0, 31749825, 'HARE', '', '', '可拆卸背带与外置口袋设计，兼具造型感与实用性的多功能工装裤。裤脚配有抽绳，可收紧营造廓形变化。后腰为松紧设计，穿着舒适无束缚。采用接触冷感材质，夏季也能保持清爽舒适。膝上位置配有拉链，微开可形成开衩效果，完全打开则可拆下裤腿，作为短裤穿着。一款可根据造型与体型特征自由调整穿法的多WAY单品，也可与同面料衬衫搭配成套造型。', 'ーーー<br><br>サスペンダーとポケットが取り外し可能！<br>デザイン性の高いマルチに使えるカーゴパンツ<br><br>ーーー<br><br><span style=\"font-weight: bold; font-size: 130%\">point</span><br>□サスペンダーと特徴的な外付けポケットがついたストリート要素のあるカーゴパンツ<br>□裾はドローコードがついており、絞ってシルエットの変化を楽しめる<br>□ウエストの後ろがゴム仕様でストレスフリーな履き心地<br>□接触冷感素材を使用しており、夏でも快適に着用可能◎<br>□膝上のジップを少し開けるとスリットに、完全に開けると下が取れる仕様の為、ハーフパンツとしても着用可能<br><br><span style=\"font-weight: bold; font-size: 130%\">styling</span><br>骨格ナチュラル：サスペンダーを下に降ろして、重心を下げたラフな着こなしに。オーバーサイズのロンTや、ざっくりとしたメッシュニットにあえてズルッとルーズに履くのが今っぽくてオススメ。<br>骨格ウェーブ：コンパクトなクロップド丈のトップスや、透け感のあるシアー素材のブラウスを合わせると女性らしい雰囲気になります。裾をギュッと絞ってバルーンシルエットにすると更に華奢な印象になります。<br>骨格ストレート：サスペンダーは外すか垂らして縦線を強調。腰周りがスッキリ見えます。Vネックのタイトなニットやハリのある白シャツを合わせて、裾は絞らずストレートで履くのがベスト◎<br><br><span style=\"font-weight: bold; font-size: 130%\">set item</span><br>同じ生地を使用したシャツとセットアップが可能。<br><br>★ブラウザの方はこちらから<br><a href=\'https://www.dot-st.com/hare/disp/item/647217/\'>【セットアップ対応アイテムはコチラ】</a><br><br>★アプリの方はこちらから<br><a href=\'adastriaapp://item?itemCode=647217\'>【セットアップ対応アイテムはコチラ】</a>', '16300.0 JPY', 994.30, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:15:57', '2026-04-02 04:19:17', 'adastria_655855', '', '69cd72d6a7ab618f2967cbd3', '生活/休闲', '', '女', '青年（18-44岁）', '涤纶51%,锦纶19%,粘胶11%,羊毛10%,氨纶9%', 'https://www.dot-st.com/hare/disp/item/655855/?COLOR_CD=98', '下装', '工装裤', '工装裤', '', 'cargo pants', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/hare/20260401/item_655855_main_98_1774948805_b.jpg', 0, 0, 2, 0.59325, 0, 1, 1, 0, 0, 3, NULL, '接触冷感，可拆卸设计，宽松舒适版型，弹性腰头设计，廓形可调节', '可拆卸设计,宽松舒适版型,弹性腰头设计,廓形可调节', '接触冷感面料', '带可拆卸背带与外置口袋，造型感强,膝上拉链设计，可在长裤与短裤之间自由切换,裤脚配有抽绳，可调整为直筒或气球廓形,腰部后片松紧设计，提升舒适度,可与同面料上衣搭配成套穿着', '花卉图案', '从商品名称和描述来看，该款为「カーゴパンツ」，具有多口袋设计和工装风格，且图片中可见大腿及侧边的外置口袋和宽松直筒裤型，符合 cargo pants（工装裤）的定义：多功能口袋、街头/机能风长裤。同时具备可拆卸裤腿变为短裤的设计，但核心形态仍是工装长裤，因此选择 sub_category 为 cargo pants（工装裤）。', 1, 0, 0, 0, 'cargo pants', NULL, '', 0, NULL, 0, NULL, NULL, '98', 'パープル98', 0);
