INSERT INTO `clothing_info` VALUES (19996752, '【官网先行预订 女款】提花拼接透明小物收纳包', '【WEB先行予約 LADIES】ジャガードキリカエクリアポーチ', 0, 31749825, 'HARE', '', '', '可挂在包包等物品上的透明收纳包，既适合应援、推し活场景，也适合日常使用。一侧为透明材质，一侧为提花面料，通过调整肩带或挂链的连接方式，可实现两种不同正反展示效果。可放入玩偶、化妆品等喜爱的物品随身携带，底部有一定宽度，内部设有两个小分隔口袋，提升收纳与整理功能。配有可拆卸链条，营造利落又带点华丽感的造型。既可作为包内的化妆收纳包，也可在演唱会或推し活时挂在包包或裤子腰带环上使用。', 'ーーー<br><br>バッグなどに身に着けられる<br>推し活にも日常にも使えるクリアポーチ<br><br>ーーー<br><br><span style=\"font-weight: bold; font-size: 130%\">point</span><br>□片面をクリア、片面をジャガード生地で作成している為、ストラップの付け方で2WAY仕様可能<br>□ぬいぐるみやコスメなど、好きなものを入れて持ち運びが可能<br>□マチがしっかりあり、内側には小分けポケットが2つ付いている為、機能性〇<br>□取り外し可能なチェーン付きで、ハレらしいモードな印象に<br><br><span style=\"font-weight: bold; font-size: 130%\">styling</span><br>カバンの中の化粧ポーチとしても、ライブや推し活時にバッグやパンツのベルトループに着けて持ち運ぶのもおすすめです。', '3000.0 JPY', 183.00, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:15:57', '2026-04-02 04:19:19', 'adastria_676391', '', '69cd72d7a7ab618f2967cbdc', '生活/休闲', '', '通用', '青年（18-44岁）', NULL, 'https://www.dot-st.com/hare/disp/item/676391/?COLOR_CD=09', '其他服饰/物品', '其他', '配件', '', 'accessories', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/hare/20260401/item_676391_main_09_1774954174_b.jpg', 0, 0, 8, 0.98539, 0, 1, 0, 0, 0, 3, NULL, '收纳整理，便于携带，两用佩戴方式', '收纳整理,便于携带,两用佩戴方式', '', '一面为透明PVC材质，另一面为提花面料拼接,附带可拆卸链条，可挂在包包或裤子腰带环上,内部带有两个小分隔口袋，方便分类收纳,具有一定厚度的底部结构，容量更实用,兼顾日常化妆品与“应援/推し活”周边收纳需求', '其他', '该商品是一个可挂在包上的小型收纳“クリアポーチ”，属于包袋类配件而非服装。结合日文分类“財布・小物”和图片中挂在托特包上的使用方式，可判断最适合归入配饰类，因此选择子类目“accessories（配饰）”。该子类主要涵盖非服装的随身小物，如钱包、卡包、钥匙包、小袋/小包等。', 0, 0, 0, 0, 'accessories', NULL, '', 0, NULL, 0, NULL, NULL, '09', 'ブラック09', 0);
INSERT INTO `clothing_info` VALUES (19996740, '【网络先行预订 接触冷感/可成套搭配 女款】系带迷你半身裙', '【WEB先行予約 接触冷感/SETUP対応 LADIES】レースアップミニスカート', 0, 31749825, 'HARE', '', '', '采用接触冷感材质打造，腰部系带细节为亮点的迷你半身裙。兼具优雅与女性化气质，附带安全感更强的配套内搭短裤，单穿也不易走光。后腰为松紧设计，穿着无束缚感，更加舒适。运用接触冷感面料，即使在夏季也能保持清凉舒适。同色系的系带设计，低调中增添设计感。可与同面料衬衫搭配，完成成套造型。', 'ーーー<br><br>接触冷感素材(icy feel)を使用した<br>レースアップがポイントのミニスカート<br><br>ーーー<br><br><span style=\"font-weight: bold; font-size: 130%\">point</span><br>□上品さとフェミニンさを兼ね備えたミニスカート<br>□ペチパンツがセットになっていて一枚で着用しやすい<br>□ウエストの後ろがゴム仕様でストレスフリーな履き心地<br>□接触冷感素材を使用しており、夏でも快適に着用可能◎<br>□同色レースアップでさりげないデザインポイントをプラス<br><br><span style=\"font-weight: bold; font-size: 130%\">styling</span><br>骨格ナチュラル：大き目のシャツを羽織って、大人スタイルに。ソックスにローファーやローヒールのサンダル合わせが〇<br>骨格ウェーブ：リブトップスやシアートップスなど細身シルエットのもので合わせてスタイルアップ。ヒール合わせで脚長効果もプラス。<br>骨格ストレート：Vネックトップスやスキッパートップスで抜け感をプラス。華奢なアクセサリーを身に着け、女性らしさのあるスタイルに。<br><br><br><span style=\"font-weight: bold; font-size: 130%\">set item</span><br>同素材を使用したシャツとのセットアップが可能。<br><br>★ブラウザの方はこちらから<br><a href=\'https://www.dot-st.com/hare/disp/item/647217/\'>【セットアップ対応アイテムはコチラ】</a><br><br>★アプリの方はこちらから<br><a href=\'adastriaapp://item?itemCode=647217\'>【セットアップ対応アイテムはコチラ】</a><br><br>', '9000.0 JPY', 549.00, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:16:07', '2026-04-02 04:19:09', 'adastria_647530', '', '69cd72d6a7ab618f2967cbc7', '生活/休闲', '', '女', '青年（18-44岁）', '涤纶51%,锦纶19%,粘胶11%,羊毛10%,氨纶9%', 'https://www.dot-st.com/hare/disp/item/647530/?COLOR_CD=98', '裙装', '半身裙', '半身裙', '', 'skirt', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/hare/20260401/item_647530_main_98_1774949749_b.jpg', 0, 0, 6, 0.91161, 0, 1, 0, 0, 0, 3, NULL, '接触冷感，舒适弹性，凉感穿着体验', '舒适弹性,凉感穿着体验', '', '高腰系带设计提升腰线比例,后腰松紧设计提升舒适度,附带安全感更强的内搭短裤,适合夏季穿着的凉感面料,可与同面料衬衫搭配成套穿着', '纯色，纯色', '从商品名称“レースアップミニスカート”、品类“スカート”和图片来看，这是一条长度在大腿的女式迷你半身裙，侧面有系带装饰，属于典型下装裙类，而非连衣裙或短裤。结合列表中最接近的品类，“skirt”即“半身裙/短裙”最为贴切，其定义为单件下身裙装，不带上身结构，符合本产品特征。', 1, 0, 0, 0, 'skirt', NULL, '', 0, NULL, 0, NULL, NULL, '98', 'パープル98', 0);
