INSERT INTO `clothing_info` VALUES (19996742, '【官网优先预约 可成套搭配 女款】不对称拼接提花褶裥长裙', '【WEB先行予約 SET UP対応 LADIES】アシメフレアジャガードプリーツスカート', 0, 31749825, 'HARE', '', '', '提花拼接设计华丽抢眼，是造型中主角级的褶裥长裙。通过在褶裥中加入喇叭廓形元素，营造出优雅又富有动感的轮廓，同时裙身具有良好的垂坠感，不贴身不显身形。略宽的褶裥间距让整体不过分甜美，呈现偏摩登的印象，后腰为松紧设计，提升穿着舒适度。提花面料与素色面料的切换为搭配带来亮点。可与相同提花图案的衬衫或同面料窄裙搭配，打造成套风格多样造型。适合搭配宽松卫衣、透感衬衫或合身上衣等不同骨架类型的穿着需求。', 'ーーー<br><br>ジャガードの切り替えデザインが華やかな主役級プリーツスカート<br><br>ーーー<br><br><span style=\"font-weight: bold; font-size: 130%\">point</span><br>□プリーツにフレア要素をプラスし、エレガントで動きのあるシルエット<br>□身体のラインを拾わない落ち感のあるシルエット<br>□少し太めのプリーツ幅で甘くなりすぎず、モードな印象<br>□後ろがゴム仕様で履き心地◎<br>□ジャガード生地との切替でコーディネートのポイントに<br><br><span style=\"font-weight: bold; font-size: 130%\">styling</span><br>骨格ナチュラル：オーバーサイズのスウェットを合わせたカジュアルスタイルが抜け感を出せてオススメです。<br>骨格ウェーブ：シアーブラウスなどの透け感のある素材で軽さを出しつつ、袖にボリュームがあるものを選んで上半身に華やかさをプラス。首元にチョーカーを添えるとさらにバランス◎<br>骨格ストレート：コンパクトなトップスをインしてウエスト周りをスッキリさせるスタイルがオススメです。細ストラップ付のサンダルやパンプスを合わせるとシャープな印象になります。<br><br><br><span style=\"font-weight: bold; font-size: 130%\">set item</span><br>同じジャガード柄のシャツとセットアップで着用可能。同柄のナロースカートもご用意しております。<br><br>★ブラウザの方はこちらから<br><a href=\'https://www.dot-st.com/hare/disp/item/661455/\'>【セットアップ対応アイテムはコチラ】</a><br><a href=\'https://www.dot-st.com/hare/disp/item/453376/\'>【ナロースカートはコチラ】</a><br><br>★アプリの方はこちらから<br><a href=\'adastriaapp://item?itemCode=661455\'>【セットアップ対応アイテムはコチラ】</a><br><a href=\'adastriaapp://item?itemCode=453376\'>【ナロースカートはコチラ】</a>', '13600.0 JPY', 829.60, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:16:07', '2026-04-02 04:19:11', 'adastria_661457', '', '69cd72d6a7ab618f2967cbc4', '生活/休闲', '', '女', '青年（18-44岁）', '涤纶93%,氨纶7%', 'https://www.dot-st.com/hare/disp/item/661457/?COLOR_CD=08', '裙装', '半身裙', '长裙', '', 'maxi skirt', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/hare/20260401/item_661457_main_08_1774950909_b.jpg', 0, 0, 6, 0.80122, 0, 1, 0, 0, 0, 3, NULL, '修饰身材，舒适穿着，显瘦', '修饰身材,舒适穿着,显瘦', '', '不对称剪裁与拼接设计,宽幅褶裥营造优雅摆动感,后腰松紧设计提升舒适度与适配性,采用提花面料与素色面料拼接增强造型感,可与同面料衬衫或窄裙组合成套装造型', '其他', '该商品为女装下装，描述中多次提到“プリーツスカート”，图片显示为覆盖脚踝的长款不对称拼接裙，长度明显是长裙而非中裙或短裙，因此在给定列表中最符合“maxi skirt（长款半身裙）”这一子类。', 1, 0, 0, 0, 'maxi skirt', NULL, '', 0, NULL, 0, NULL, NULL, '08', 'ホワイト08', 0);
