INSERT INTO `clothing_info` VALUES (19996732, '【网络预售 女士】系带罗纹背心', '【WEB先行予約 LADIES】ストリングリブタンクトップ', 0, 31749825, 'HARE', '', '', '肩带与颈部系带设计是亮点的HARE经典背心款式。独特的颈部系带设计在搭配衬衫或套头上衣作内搭时也能成为视觉重点。采用具有弹性的罗纹面料，兼顾伸缩性与不过分贴身的版型，带来无压力的舒适穿着感。面料手感干爽，不易松垂变形，经多次清洗也更耐用。肩带宽度经过考量，可有效遮挡内衣肩带，减少内搭顾虑，肩带处的开衩细节增添适度装饰感。适合作为薄纱上衣或夹克的内搭，也可以单穿，营造健康露肤造型。', 'ーーー<br><br>肩紐デザインがポイントのHARE定番タンクトップ<br><br>ーーー<br><br><span style=\"font-weight: bold; font-size: 130%\">point</span><br>□他にはない首紐のデザインがポイント<br>□シャツやプルオーバーのインナーで使用しても紐デザインが映える一枚に作成<br>□伸縮性＋ボディラインを拾いすぎないリブ素材を使用し、ストレスフリーな着心地<br>□よれにくいドライタッチな素材を使用し、洗濯しても長持ちしやすい<br>□肩紐は下着の紐が見えづらい幅に設定し、インナーを気にせず着用しやすい<br>□肩紐のスリットが程よいアクセントに<br><br><br><span style=\"font-weight: bold; font-size: 130%\">styling</span><br>シアーのトップスやジャケットなどのインナーに◎<br>一枚でもデザインが凝っている為、ヘルシーに着用して頂けます。<br>', '3000.0 JPY', 183.00, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:16:34', '2026-04-02 04:19:02', 'adastria_636796', '', '69cd72d6a7ab618f2967cbb9', '生活/休闲', '', '女', '青年（18-44岁）', '涤纶65%,棉35%', 'https://www.dot-st.com/hare/disp/item/636796/?COLOR_CD=85', '上装', '背心', '背心', '', 'tank top', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/hare/20260401/item_636796_main_85_1773831909_b.jpg', 0, 0, 8, 0.89782, 0, 1, 1, 0, 0, 3, NULL, '高弹力，抗皱，耐洗耐穿，舒适贴身', '抗皱,耐洗耐穿,舒适贴身', '', '肩部有独特的颈部系带装饰设计,采用罗纹针织结构，具有良好弹性且不过分紧贴身形,面料为干爽手感，设计上不易松垂变形,肩带宽度可遮挡内衣肩带，增强作为打底穿着的便利性,肩带处开衩细节增加造型感,适合作为透视上衣或夹克的内搭单品，也可单穿', '条纹', '根据商品名称“ストリングリブタンクトップ”以及图片可见为无袖、肩带设计、贴身穿着的上衣，属于典型的背心类单品。与候选列表中“tank top（背心/吊带背心）”最为匹配，因此选择 sub_category 为 “tank top（背心类上衣，用作单穿或打底的无袖上衣）”。', 1, 0, 0, 0, 'tank top', NULL, '', 0, NULL, 0, NULL, NULL, '85', 'ブルー85', 0);
