INSERT INTO `clothing_info` VALUES (19996728, '＜预售＞多色条纹T恤', '＜先行予約＞マルチボーダーＴシャツ', 0, 31749821, 'RAGEBLUE', '', '', '采用不同条纹宽度的多色横条纹图案设计，一件即可成为造型焦点。身宽为当下流行的宽松版型，衣长适中，方便与多种裤装搭配。配色讲究，既适合作为内搭，也能单穿成为造型主角。选用有挺度且耐磨的100%棉材质，使用略粗棉纱织成天竺针织面料，提升耐久性，不易发生型变，可长久穿着。', '<b><font color=\"blue\">クラシックなマルチボーダーを、ストリートな雰囲気に</font></b><br>ーーー<br><b>■ポイント</b><br>ピッチの太さが異なるマルチボーダー柄をあしらった、一枚で様になるTシャツ。<br>身幅は現代的なオーバーサイズで仕立て、着丈は程よい長さにすることで、様々なパンツと合わせやすくなっています。<br>配色にも拘り、インナー使いしやすさを残しつつ、一枚着としてしっかりと主役に。<br><br><b>■素材</b><br>ハリがあり、丈夫なコットン100%素材を使用。<br>やや太めの糸で天竺編み生地に仕立てることで、耐久性が高いことに加え、<br>型崩れがしにくく長く着ていただけるTシャツです。<br><br>======<br><b>■参考サイズ</b><br>M：～175cm<br>L：175cm～<br>======<br>ーーー', '4537.0 JPY', 276.76, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:17:12', '2026-04-02 04:18:59', 'adastria_666495', '', '69cd72d6a7ab618f2967cba9', '生活/休闲', '', '通用', '青年（18-44岁）', '棉100%', 'https://www.dot-st.com/rageblue/disp/item/666495/?COLOR_CD=04', '上装', 'T恤', 'T恤', '', 't-shirt', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/rageblue/20260401/item_666495_main_04_1774863825_b.jpg', 0, 0, 2, 0.87458, 0, 1, 1, 0, 0, 3, NULL, '耐用，不易变形', '耐用,不易变形', '', '宽松廓形、身幅偏大、衣长适中，方便搭配各种裤装,采用较粗棉纱织成天竺针织面料，增加面料挺括度与耐久性,配色为经典多色横向条纹，兼顾内搭与单穿视觉效果', '条纹', '商品名称为“Tシャツ”，描述中提到是一枚即可穿出造型的T恤，款式为短袖圆领针织上衣，模特上身图也显示为典型休闲T恤版型。根据这些信息可判断属于 sub_category 中的“t-shirt（T恤）”，即日常穿着的针织上衣。', 1, 0, 0, 0, 't-shirt', NULL, '', 0, NULL, 0, NULL, NULL, '04', 'ホワイト04', 0);
