INSERT INTO `clothing_info` VALUES (19996725, '迷你格纹/宽松版衬衫', 'ミニチェック柄/オーバーサイズシャツ', 0, 31749821, 'RAGEBLUE', '', '', '低调迷你格纹充满魅力，是一件万能百搭衬衫，宽松的廓形让搭配性极强。简洁设计易于融入各种造型，肩宽与身宽都做得较大，呈现潮流的宽松轮廓。采用夏季也能舒适穿着的面料，垂坠感自然，整体风格干练利落。男女皆可穿着，可实现多种风格搭配。\n\n面料使用具有适度挺括感的聚酯纤维与人造纤维混纺材质，透气性佳，即使在闷热夏季也能保持舒适，仅需随意披上就能完成有型造型。\n\n推荐与牛仔裤或卡其裤搭配，营造休闲风格，也可以与西裤组合打造利落的穿搭，再配合帽饰或配件打造属于自己的造型。', '<b><font color=\"blue\">さりげないチェック柄が魅力的な万能シャツ。<br>着回し力抜群のオーバーサイズデザイン。</font></b><br>ーーー<br><b>■ポイント</b><br>さりげなく目を引くチェック柄が特徴のシャツは、着回し抜群の一着です。<br>シンプルでどんなコーディネートにも合わせやすく、肩幅や身幅を広くとったトレンドのオーバーサイズシルエットです。<br>夏でも快適に着られる素材で仕上げ、揺れ感のあるスタイリッシュな仕上がりに。<br>ユニセックスで使えるため、幅広いスタイリングが可能です。<br><br><b>■素材</b><br>程よいハリ感があるポリエステルとレーヨンの混紡素材を使用。<br>風通しが良く、暑い夏でも快適に着用できるのが魅力です。<br>サラッと羽織るだけでかっこよく決まる万能な一着となっています。<br><br>======<br><b>■参考サイズ</b><br>M：～175cm<br>L：175cm～<br>======<br><br>ーーー<br><b>■スタイリング</b><br>このチェックシャツは、デニムやチノパンと合わせてカジュアルに着こなすのがおすすめです。<br>スラックスと組み合わせて、上品なスタイリングにも対応可能。<br>帽子やアクセサリーでアクセントを加え、自分だけのコーディネートを楽しんでください。<br><br>【RAGEBLUE MENS】最新アイテムはここからCHECK<br><a href=\"https://www.dot-st.com/rageblue/disp/itemlist/?mode=&sort=00&groupNm=1&p=1&refineFlg=true&dispNo=002100001&dispNoRadio=001002&search_range_price_min=&search_range_price_max=&search_refine_range_min=&search_refine_range_max=\"><font color=\"blue\">＞＞ブラウザをご利用のお客様はこちら＜＜</font></a><br><a href=\"adastriaapp://items?dispNo=0000100007_002100001&orderBy=00&genre=001002\"><font color=\"blue\">＞＞アプリをご利用のお客様はこちら＜＜</font></a><br>', '5446.0 JPY', 332.21, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:17:15', '2026-04-02 04:18:56', 'adastria_578279', '', '69cd72d6a7ab618f2967cba1', '生活/休闲', '', '通用', '青年（18-44岁）', '涤纶71%,粘胶26%,氨纶3%', 'https://www.dot-st.com/rageblue/disp/item/578279/?COLOR_CD=56', '上装', '衬衫', '纽扣衬衫', '', 'button-up shirt', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/rageblue/20260401/item_578279_main_56_1751501916_b.jpg', 0, 0, 2, 0.93852, 0, 1, 1, 0, 0, 3, NULL, '透气，凉爽舒适，宽松版型便于叠穿', '凉爽舒适,宽松版型便于叠穿', '', '男女皆宜的中性风格设计,微弹混纺织物提高舒适度,夏季也适穿的轻薄面料,小格纹提升造型感,宽肩宽身的 oversize 轮廓', '格纹', '产品名称为“オーバーサイズシャツ”，描述中多次提到“シャツ”，且图片为前襟全开扣、翻领、短袖的日常衬衫款式，明显属于有门襟纽扣结构的衬衫类型，因此从列表中选择最相符的“button-up shirt（前开襟衬衫）”。button-up shirt 指前襟全排扣、可敞开穿着的衬衫单品。', 1, 0, 0, 0, 'button-up shirt', NULL, '', 0, NULL, 0, NULL, NULL, '56', 'ブラウン系56', 0);
INSERT INTO `clothing_info` VALUES (19996726, '迷你格纹/宽松版衬衫', 'ミニチェック柄/オーバーサイズシャツ', 0, 31749821, 'RAGEBLUE', '', '', '低调迷你格纹充满魅力，是一件万能百搭衬衫，宽松的廓形让搭配性极强。简洁设计易于融入各种造型，肩宽与身宽都做得较大，呈现潮流的宽松轮廓。采用夏季也能舒适穿着的面料，垂坠感自然，整体风格干练利落。男女皆可穿着，可实现多种风格搭配。\n\n面料使用具有适度挺括感的聚酯纤维与人造纤维混纺材质，透气性佳，即使在闷热夏季也能保持舒适，仅需随意披上就能完成有型造型。\n\n推荐与牛仔裤或卡其裤搭配，营造休闲风格，也可以与西裤组合打造利落的穿搭，再配合帽饰或配件打造属于自己的造型。', '<b><font color=\"blue\">さりげないチェック柄が魅力的な万能シャツ。<br>着回し力抜群のオーバーサイズデザイン。</font></b><br>ーーー<br><b>■ポイント</b><br>さりげなく目を引くチェック柄が特徴のシャツは、着回し抜群の一着です。<br>シンプルでどんなコーディネートにも合わせやすく、肩幅や身幅を広くとったトレンドのオーバーサイズシルエットです。<br>夏でも快適に着られる素材で仕上げ、揺れ感のあるスタイリッシュな仕上がりに。<br>ユニセックスで使えるため、幅広いスタイリングが可能です。<br><br><b>■素材</b><br>程よいハリ感があるポリエステルとレーヨンの混紡素材を使用。<br>風通しが良く、暑い夏でも快適に着用できるのが魅力です。<br>サラッと羽織るだけでかっこよく決まる万能な一着となっています。<br><br>======<br><b>■参考サイズ</b><br>M：～175cm<br>L：175cm～<br>======<br><br>ーーー<br><b>■スタイリング</b><br>このチェックシャツは、デニムやチノパンと合わせてカジュアルに着こなすのがおすすめです。<br>スラックスと組み合わせて、上品なスタイリングにも対応可能。<br>帽子やアクセサリーでアクセントを加え、自分だけのコーディネートを楽しんでください。<br><br>【RAGEBLUE MENS】最新アイテムはここからCHECK<br><a href=\"https://www.dot-st.com/rageblue/disp/itemlist/?mode=&sort=00&groupNm=1&p=1&refineFlg=true&dispNo=002100001&dispNoRadio=001002&search_range_price_min=&search_range_price_max=&search_refine_range_min=&search_refine_range_max=\"><font color=\"blue\">＞＞ブラウザをご利用のお客様はこちら＜＜</font></a><br><a href=\"adastriaapp://items?dispNo=0000100007_002100001&orderBy=00&genre=001002\"><font color=\"blue\">＞＞アプリをご利用のお客様はこちら＜＜</font></a><br>', '5446.0 JPY', 332.21, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:17:15', '2026-04-02 04:18:57', 'adastria_578279', '', '69cd72d6a7ab618f2967cba1', '生活/休闲', '', '通用', '青年（18-44岁）', '涤纶71%,粘胶26%,氨纶3%', 'https://www.dot-st.com/rageblue/disp/item/578279/?COLOR_CD=56', '上装', '衬衫', '纽扣衬衫', '', 'button-up shirt', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/rageblue/20260401/item_578279_main_09_1751501914_b.jpg', 0, 0, 8, 0.79716, 0, 1, 1, 0, 0, 3, NULL, '透气，凉爽舒适，宽松版型便于叠穿', '凉爽舒适,宽松版型便于叠穿', '', '男女皆宜的中性风格设计,微弹混纺织物提高舒适度,夏季也适穿的轻薄面料,小格纹提升造型感,宽肩宽身的 oversize 轮廓', '格纹', '产品名称为“オーバーサイズシャツ”，描述中多次提到“シャツ”，且图片为前襟全开扣、翻领、短袖的日常衬衫款式，明显属于有门襟纽扣结构的衬衫类型，因此从列表中选择最相符的“button-up shirt（前开襟衬衫）”。button-up shirt 指前襟全排扣、可敞开穿着的衬衫单品。', 1, 1, 0, 0, 'button-up shirt', NULL, '', 0, NULL, 0, NULL, NULL, '09', 'ブラック系09', 0);
