INSERT INTO `clothing_info` VALUES (19996723, '【预售】波点层叠长裙', '【先行予約】ドットティアードスカート', 0, 31749824, 'mysty woman', '', '', '窄版廓形设计的层叠长裙，营造成熟大气的女性印象。采用流行波点图案，为穿搭增添亮点，微透感面料带来优雅轻盈的视觉效果。裙身偏窄的轮廓使整体更显干练利落，三段式层叠设计增加摆动感与华丽度。后部开衩设计，在保持设计感的同时提升行走便利性。可搭配简约T恤或针织开衫打造大人感休闲风，夏季与背心或针织马甲组合即可呈现轻松的时髦造型，再配合配饰点缀，突出女性化穿搭风格。', 'ーーー<br>ナローシルエットで大人見えのティアードスカート<br><br>■point<br>・トレンドのドット柄でコーディネートのポイントに<br>・微シアーな生地で上品な印象を演出<br>・ナロー寄りのシルエットで大人っぽく着こなせるのも魅力<br>・3段ティアードデザインにより動きのある華やかさをプラス<br>・バックにベンツあき付きで動きやすさとデザイン性を両立<br><br>ーーー<br><br>■styling<br>シンプルなTシャツやニットカーディガンなどとの合わせで大人カジュアルな装いに。<br>夏にはタンクトップやニットベストをさらっと合わせるだけで抜け感のあるトレンドスタイルに。<br>小物やアクセをプラスして女性らしく着こなすのがおすすめです。', '9000.0 JPY', 549.00, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:17:16', '2026-04-02 04:18:55', 'adastria_678872', '', '69cd72d6a7ab618f2967cba3', '生活/休闲', '', '女', '青年（18-44岁）', '粘胶69%,锦纶31%', 'https://www.dot-st.com/mystywoman/disp/item/678872/?COLOR_CD=05', '裙装', '半身裙', '长裙', '', 'maxi skirt', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/mysty_woman/20260401/item_678872_main_05_1774589657_b.jpg', 0, 0, 2, 0.81813, 0, 1, 0, 0, 0, 3, NULL, '显瘦修饰身形，提升女性化气质，方便活动', '显瘦修饰身形,提升女性化气质,方便活动', '', '三层分段式层叠设计，增加摆动感和华丽度,后开衩设计兼顾造型感与行走便利,微透纱感面料营造轻盈优雅效果,窄版廓形突出成熟大人风格,经典圆点元素增加搭配亮点', '点', '从图片与商品名“ドットティアードスカート”可见，这是女性下装，长度覆盖至脚踝附近，属于长款裙子，并非连衣裙；整体为高腰、全长、带三层阶梯式荷叶拼接的下身单品。与提供类目对比，“maxi skirt”指及踝或更长的长裙，下装单品，最为吻合本款商品的版型与长度，因此选择“maxi skirt（及踝长裙）”。', 1, 0, 0, 0, 'maxi skirt', NULL, '', 0, NULL, 0, NULL, NULL, '05', 'オフドット(05)', 0);
INSERT INTO `clothing_info` VALUES (19996724, '【预售】波点层叠长裙', '【先行予約】ドットティアードスカート', 0, 31749824, 'mysty woman', '', '', '窄版廓形设计的层叠长裙，营造成熟大气的女性印象。采用流行波点图案，为穿搭增添亮点，微透感面料带来优雅轻盈的视觉效果。裙身偏窄的轮廓使整体更显干练利落，三段式层叠设计增加摆动感与华丽度。后部开衩设计，在保持设计感的同时提升行走便利性。可搭配简约T恤或针织开衫打造大人感休闲风，夏季与背心或针织马甲组合即可呈现轻松的时髦造型，再配合配饰点缀，突出女性化穿搭风格。', 'ーーー<br>ナローシルエットで大人見えのティアードスカート<br><br>■point<br>・トレンドのドット柄でコーディネートのポイントに<br>・微シアーな生地で上品な印象を演出<br>・ナロー寄りのシルエットで大人っぽく着こなせるのも魅力<br>・3段ティアードデザインにより動きのある華やかさをプラス<br>・バックにベンツあき付きで動きやすさとデザイン性を両立<br><br>ーーー<br><br>■styling<br>シンプルなTシャツやニットカーディガンなどとの合わせで大人カジュアルな装いに。<br>夏にはタンクトップやニットベストをさらっと合わせるだけで抜け感のあるトレンドスタイルに。<br>小物やアクセをプラスして女性らしく着こなすのがおすすめです。', '9000.0 JPY', 549.00, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:17:16', '2026-04-02 04:18:55', 'adastria_678872', '', '69cd72d6a7ab618f2967cba3', '生活/休闲', '', '女', '青年（18-44岁）', '粘胶69%,锦纶31%', 'https://www.dot-st.com/mystywoman/disp/item/678872/?COLOR_CD=05', '裙装', '半身裙', '长裙', '', 'maxi skirt', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/mysty_woman/20260401/item_678872_main_88_1774589681_b.jpg', 0, 0, 2, 0.43898, 0, 1, 0, 0, 0, 3, NULL, '显瘦修饰身形，提升女性化气质，方便活动', '显瘦修饰身形,提升女性化气质,方便活动', '', '三层分段式层叠设计，增加摆动感和华丽度,后开衩设计兼顾造型感与行走便利,微透纱感面料营造轻盈优雅效果,窄版廓形突出成熟大人风格,经典圆点元素增加搭配亮点', '点', '从图片与商品名“ドットティアードスカート”可见，这是女性下装，长度覆盖至脚踝附近，属于长款裙子，并非连衣裙；整体为高腰、全长、带三层阶梯式荷叶拼接的下身单品。与提供类目对比，“maxi skirt”指及踝或更长的长裙，下装单品，最为吻合本款商品的版型与长度，因此选择“maxi skirt（及踝长裙）”。', 1, 1, 0, 0, 'maxi skirt', NULL, '', 0, NULL, 0, NULL, NULL, '88', 'ネイビードット(88)', 0);
INSERT INTO `clothing_info` VALUES (19996720, '【预售】7G V领网眼针织开衫', '【先行予約】7GVネックメッシュニットカーディガン', 0, 31749824, 'mysty woman', '', '', '简约而优雅的V领网眼针织开衫。采用干爽触感的纱线，带来舒适的穿着体验。配有富有高级感的金色纽扣，呈现精致印象。网眼间距适中，整体比例更协调。100%丙烯酸纤维材质，日常打理方便。V领设计令脸部周围更显利落清爽。质地轻盈，便于携带，非常适合季节更替时穿着。只需搭配T恤与牛仔裤外搭，即可营造随性又有型的休闲造型；叠穿在连衣裙外，也能打造富有层次感的季节过渡穿搭。', 'ーーー<br>シンプルで上品なVネックメッシュニットカーディガン<br><br>■point<br>・ドライタッチの糸を使用し、快適な着心地を実現<br>・高級感のある金ボタン仕様で上品な印象<br>・大きすぎないメッシュピッチでバランスの良いデザイン<br>・アクリル100%素材でお手入れが簡単<br>・Vネックデザインで顔周りをすっきり見せてくれます<br>・軽量で持ち運びやすく、季節の変わり目に最適<br>・高級感あふれる金ボタンデザイン<br>ーーー<br><br>■styling<br>Tシャツとデニムパンツのシンプルなコーディネートに羽織るだけで、こなれ感のあるカジュアルスタイルに仕上がります。<br>ワンピースの上に重ね着して、季節の変わり目のレイヤードスタイルを楽しむのもおすすめです。', '8000.0 JPY', 488.00, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:17:21', '2026-04-02 04:18:52', 'adastria_679305', '', '69cd72d6a7ab618f2967cb9e', '生活/休闲', '', '女', '青年（18-44岁）', '腈纶100%', 'https://www.dot-st.com/mystywoman/disp/item/679305/?COLOR_CD=05', '上装', '毛衫', '开衫', '', 'cardigan', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/mysty_woman/20260401/item_679305_main_05_1774587737_b.jpg', 0, 0, 2, 0.95725, 0, 1, 1, 0, 0, 3, NULL, '透气，高弹力，轻量，易打理，干爽触感', '轻量,易打理,干爽触感', '', '金属纽扣装饰提升整体的精致感和高级感,网眼结构适合季节交替时的叠穿搭配,V领设计在视觉上修饰脸型与颈部线条', '其他', '从商品名“メッシュニットカーディガン”和图片可以看出，这是前开襟、带排扣、可作为外搭穿着的针织上衣，典型属于“cardigan（开衫）”。并非套头式针织衫（sweater/pullover），也不是外套类大衣，因此选择子类“cardigan（针织开衫）”最合适。cardigan 指前面有开襟和纽扣的针织上衣，多用于叠穿与搭配。', 1, 0, 0, 0, 'cardigan', NULL, '', 0, NULL, 0, NULL, NULL, '05', 'オフ(05)', 0);
