INSERT INTO `clothing_info` VALUES (19996722, '【预售】7G V领网眼针织开衫', '【先行予約】7GVネックメッシュニットカーディガン', 0, 31749824, 'mysty woman', '', '', '简约而优雅的V领网眼针织开衫。采用干爽触感的纱线，带来舒适的穿着体验。配有富有高级感的金色纽扣，呈现精致印象。网眼间距适中，整体比例更协调。100%丙烯酸纤维材质，日常打理方便。V领设计令脸部周围更显利落清爽。质地轻盈，便于携带，非常适合季节更替时穿着。只需搭配T恤与牛仔裤外搭，即可营造随性又有型的休闲造型；叠穿在连衣裙外，也能打造富有层次感的季节过渡穿搭。', 'ーーー<br>シンプルで上品なVネックメッシュニットカーディガン<br><br>■point<br>・ドライタッチの糸を使用し、快適な着心地を実現<br>・高級感のある金ボタン仕様で上品な印象<br>・大きすぎないメッシュピッチでバランスの良いデザイン<br>・アクリル100%素材でお手入れが簡単<br>・Vネックデザインで顔周りをすっきり見せてくれます<br>・軽量で持ち運びやすく、季節の変わり目に最適<br>・高級感あふれる金ボタンデザイン<br>ーーー<br><br>■styling<br>Tシャツとデニムパンツのシンプルなコーディネートに羽織るだけで、こなれ感のあるカジュアルスタイルに仕上がります。<br>ワンピースの上に重ね着して、季節の変わり目のレイヤードスタイルを楽しむのもおすすめです。', '8000.0 JPY', 488.00, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:17:21', '2026-04-02 04:18:54', 'adastria_679305', '', '69cd72d6a7ab618f2967cb9e', '生活/休闲', '', '女', '青年（18-44岁）', '腈纶100%', 'https://www.dot-st.com/mystywoman/disp/item/679305/?COLOR_CD=05', '上装', '毛衫', '开衫', '', 'cardigan', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/mysty_woman/20260401/item_679305_main_52_1774587215_b.jpg', 0, 0, 6, 0.52097, 0, 1, 1, 0, 0, 3, NULL, '透气，高弹力，轻量，易打理，干爽触感', '轻量,易打理,干爽触感', '', '金属纽扣装饰提升整体的精致感和高级感,网眼结构适合季节交替时的叠穿搭配,V领设计在视觉上修饰脸型与颈部线条', '其他', '从商品名“メッシュニットカーディガン”和图片可以看出，这是前开襟、带排扣、可作为外搭穿着的针织上衣，典型属于“cardigan（开衫）”。并非套头式针织衫（sweater/pullover），也不是外套类大衣，因此选择子类“cardigan（针织开衫）”最合适。cardigan 指前面有开襟和纽扣的针织上衣，多用于叠穿与搭配。', 1, 2, 0, 0, 'cardigan', NULL, '', 0, NULL, 0, NULL, NULL, '52', 'ベージュ(52)', 0);
INSERT INTO `clothing_info` VALUES (19996717, '【预售】撞色卷边衬衫式开衫', '【先行予約】配色メローシャツカーディガン', 0, 31749824, 'mysty woman', '', '', '———\n以撞色卷边为亮点的设计感剪裁开衫上衣。\n\n■ 特点\n・采用99%聚酯纤维、1%聚氨酯的针织面料。\n・高弹力，活动自如，穿着舒适。\n・具有细腻皱感的面料带来优雅高级的印象。\n・撞色卷边作为视觉重点，为搭配增添亮点。\n・无领配合翻驳感门襟设计，同时呈现利落与随性。\n・袖口与下摆仿荷叶边的卷边设计，营造女性化气质。\n\n■ 搭配建议\n可在美式背心或吊带外叠穿，营造夏日放松风格。\n与牛仔裤或休闲裤搭配，打造随性日常造型。\n也可披在连衣裙外，丰富层次感。\n在凸显温柔女性风格的同时，兼具弹力与活动便捷，是一件实用的开衫单品。', 'ーーー<br>配色メローがアクセントのデザインカットシャツ<br><br>■point<br>・ポリエステル99%、ポリウレタン1%のカット素材<br>・高いストレッチ性で動きやすく、快適な着用感<br>・シボ感のある生地が上品な印象を与えてくれます<br>・配色メローがアクセントとなり、コーディネートのポイントに<br>・ノーカラー＆ラペル見えのデザインで、きちんと感とこなれ感を両立<br>・袖口と裾のフリル風メローがフェミニンな雰囲気を演出<br>ーーー<br><br>■styling<br>アメスリタンクやキャミソールをインナーに合わせて、夏のリラックススタイルに。<br>デニムパンツやイージーパンツと合わせてカジュアルに着こなすのがおすすめです。<br>ワンピースの上に羽織ることで、レイヤードスタイルに。<br>フェミニンな印象を引き立てつつ、ストレッチ性で動きやすさも◎<br>１枚あると便利なカーディガンです。', '9000.0 JPY', 549.00, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:17:27', '2026-04-02 04:18:49', 'adastria_678691', '', '69cd72d6a7ab618f2967cb90', '生活/休闲', '', '女', '青年（18-44岁）', '涤纶99%,氨纶1%', 'https://www.dot-st.com/mystywoman/disp/item/678691/?COLOR_CD=09', '上装', '毛衫', '开衫', '', 'cardigan', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/mysty_woman/20260401/item_678691_main_09_1774591393_b.jpg', 0, 0, 2, 0.92629, 0, 1, 1, 0, 0, 3, NULL, '高弹力，舒适穿着感', '舒适穿着感', '', '无领设计，配合翻驳门襟，兼具正式感与休闲感,袖口与下摆采用荷叶边风格的卷边装饰，增强女性化气质,面料具有轻微皱褶感，呈现自然肌理与高级感,撞色卷边细节突出，增加造型亮点', '纯色，纯色', '从名称“配色メローシャツカーディガン”以及图片来看，这是一件可开襟、有前门襟纽扣、用于外搭的轻薄上装，整体版型与功能更接近“cardigan（开襟针织/开衫类外搭上衣）”而非普通衬衫或T恤。虽然文案中使用“シャツ”字样，但其主要卖点为开衫式叠穿、可在吊带或连衣裙外面搭配，符合“cardigan”的使用方式和风格定义，因此选择 sub_category 为“cardigan（开襟外搭上衣）”。', 1, 0, 0, 0, 'cardigan', NULL, '', 0, NULL, 0, NULL, NULL, '09', 'ブラック(09)', 0);
INSERT INTO `clothing_info` VALUES (19996718, '【预售】撞色卷边衬衫式开衫', '【先行予約】配色メローシャツカーディガン', 0, 31749824, 'mysty woman', '', '', '———\n以撞色卷边为亮点的设计感剪裁开衫上衣。\n\n■ 特点\n・采用99%聚酯纤维、1%聚氨酯的针织面料。\n・高弹力，活动自如，穿着舒适。\n・具有细腻皱感的面料带来优雅高级的印象。\n・撞色卷边作为视觉重点，为搭配增添亮点。\n・无领配合翻驳感门襟设计，同时呈现利落与随性。\n・袖口与下摆仿荷叶边的卷边设计，营造女性化气质。\n\n■ 搭配建议\n可在美式背心或吊带外叠穿，营造夏日放松风格。\n与牛仔裤或休闲裤搭配，打造随性日常造型。\n也可披在连衣裙外，丰富层次感。\n在凸显温柔女性风格的同时，兼具弹力与活动便捷，是一件实用的开衫单品。', 'ーーー<br>配色メローがアクセントのデザインカットシャツ<br><br>■point<br>・ポリエステル99%、ポリウレタン1%のカット素材<br>・高いストレッチ性で動きやすく、快適な着用感<br>・シボ感のある生地が上品な印象を与えてくれます<br>・配色メローがアクセントとなり、コーディネートのポイントに<br>・ノーカラー＆ラペル見えのデザインで、きちんと感とこなれ感を両立<br>・袖口と裾のフリル風メローがフェミニンな雰囲気を演出<br>ーーー<br><br>■styling<br>アメスリタンクやキャミソールをインナーに合わせて、夏のリラックススタイルに。<br>デニムパンツやイージーパンツと合わせてカジュアルに着こなすのがおすすめです。<br>ワンピースの上に羽織ることで、レイヤードスタイルに。<br>フェミニンな印象を引き立てつつ、ストレッチ性で動きやすさも◎<br>１枚あると便利なカーディガンです。', '9000.0 JPY', 549.00, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:17:27', '2026-04-02 04:18:50', 'adastria_678691', '', '69cd72d6a7ab618f2967cb90', '生活/休闲', '', '女', '青年（18-44岁）', '涤纶99%,氨纶1%', 'https://www.dot-st.com/mystywoman/disp/item/678691/?COLOR_CD=09', '上装', '毛衫', '开衫', '', 'cardigan', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/mysty_woman/20260401/item_678691_main_08_1774591341_b.jpg', 0, 0, 2, 0.92913, 0, 1, 1, 0, 0, 3, NULL, '高弹力，舒适穿着感', '舒适穿着感', '', '无领设计，配合翻驳门襟，兼具正式感与休闲感,袖口与下摆采用荷叶边风格的卷边装饰，增强女性化气质,面料具有轻微皱褶感，呈现自然肌理与高级感,撞色卷边细节突出，增加造型亮点', '纯色，纯色', '从名称“配色メローシャツカーディガン”以及图片来看，这是一件可开襟、有前门襟纽扣、用于外搭的轻薄上装，整体版型与功能更接近“cardigan（开襟针织/开衫类外搭上衣）”而非普通衬衫或T恤。虽然文案中使用“シャツ”字样，但其主要卖点为开衫式叠穿、可在吊带或连衣裙外面搭配，符合“cardigan”的使用方式和风格定义，因此选择 sub_category 为“cardigan（开襟外搭上衣）”。', 1, 1, 0, 0, 'cardigan', NULL, '', 0, NULL, 0, NULL, NULL, '08', 'アイボリー(08)', 0);
INSERT INTO `clothing_info` VALUES (19996719, '【预售】撞色卷边衬衫式开衫', '【先行予約】配色メローシャツカーディガン', 0, 31749824, 'mysty woman', '', '', '———\n以撞色卷边为亮点的设计感剪裁开衫上衣。\n\n■ 特点\n・采用99%聚酯纤维、1%聚氨酯的针织面料。\n・高弹力，活动自如，穿着舒适。\n・具有细腻皱感的面料带来优雅高级的印象。\n・撞色卷边作为视觉重点，为搭配增添亮点。\n・无领配合翻驳感门襟设计，同时呈现利落与随性。\n・袖口与下摆仿荷叶边的卷边设计，营造女性化气质。\n\n■ 搭配建议\n可在美式背心或吊带外叠穿，营造夏日放松风格。\n与牛仔裤或休闲裤搭配，打造随性日常造型。\n也可披在连衣裙外，丰富层次感。\n在凸显温柔女性风格的同时，兼具弹力与活动便捷，是一件实用的开衫单品。', 'ーーー<br>配色メローがアクセントのデザインカットシャツ<br><br>■point<br>・ポリエステル99%、ポリウレタン1%のカット素材<br>・高いストレッチ性で動きやすく、快適な着用感<br>・シボ感のある生地が上品な印象を与えてくれます<br>・配色メローがアクセントとなり、コーディネートのポイントに<br>・ノーカラー＆ラペル見えのデザインで、きちんと感とこなれ感を両立<br>・袖口と裾のフリル風メローがフェミニンな雰囲気を演出<br>ーーー<br><br>■styling<br>アメスリタンクやキャミソールをインナーに合わせて、夏のリラックススタイルに。<br>デニムパンツやイージーパンツと合わせてカジュアルに着こなすのがおすすめです。<br>ワンピースの上に羽織ることで、レイヤードスタイルに。<br>フェミニンな印象を引き立てつつ、ストレッチ性で動きやすさも◎<br>１枚あると便利なカーディガンです。', '9000.0 JPY', 549.00, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:17:27', '2026-04-02 04:18:51', 'adastria_678691', '', '69cd72d6a7ab618f2967cb90', '生活/休闲', '', '女', '青年（18-44岁）', '涤纶99%,氨纶1%', 'https://www.dot-st.com/mystywoman/disp/item/678691/?COLOR_CD=09', '上装', '毛衫', '开衫', '', 'cardigan', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/mysty_woman/20260401/item_678691_main_58_1774591360_b.webp', 0, 0, 2, 0.96630, 0, 1, 1, 0, 0, 3, NULL, '高弹力，舒适穿着感', '舒适穿着感', '', '无领设计，配合翻驳门襟，兼具正式感与休闲感,袖口与下摆采用荷叶边风格的卷边装饰，增强女性化气质,面料具有轻微皱褶感，呈现自然肌理与高级感,撞色卷边细节突出，增加造型亮点', '纯色，纯色', '从名称“配色メローシャツカーディガン”以及图片来看，这是一件可开襟、有前门襟纽扣、用于外搭的轻薄上装，整体版型与功能更接近“cardigan（开襟针织/开衫类外搭上衣）”而非普通衬衫或T恤。虽然文案中使用“シャツ”字样，但其主要卖点为开衫式叠穿、可在吊带或连衣裙外面搭配，符合“cardigan”的使用方式和风格定义，因此选择 sub_category 为“cardigan（开襟外搭上衣）”。', 1, 2, 0, 0, 'cardigan', NULL, '', 0, NULL, 0, NULL, NULL, '58', 'ブラウン(58)', 0);
INSERT INTO `clothing_info` VALUES (19996714, '＜预售＞颜料加工亨利领短款T恤', '＜先行予約＞ピグメント加工/ヘンリーネックTシャツ', 0, 31749821, 'RAGEBLUE', '', '', '流行的亨利领设计延伸至短款长度，领口通过开合纽扣即可改变造型氛围。领口使用贝壳质感纽扣，带来适度光泽与精致感。身幅为现代感的宽松廓形，衣长偏短，从轮廓上营造时髦感并达到显高效果。下摆采用外露包缝工艺，保留类似古着的做旧氛围。面料选用耐久性优异的100%棉材质，采用inlay针织结构带来一定的挺括与支撑，不易变形。通过使用不溶于水的特殊颜料进行颜料加工，呈现出深邃而独特的褪色质感。', '<b><font color=\"blue\">トレンドのヘンリーネックをショート丈に</font></b><br>ーーー<br><br><b>■ポイント</b><br>首元にアクセントを生むヘンリーネックは、ボタンの開け閉めだけでニュアンスの変化を楽しめます。<br>襟元には、貝蝶ボタンを採用することで、程よい光沢感があり、高見えします。<br>身幅は現代的リラックスシルエット、着丈は短めに設定することで、<br>アウトラインからトレンド感を生み出し、スタイルアップ効果も叶います。<br>裾にはオーバーロックをあしらうことで、古着のような雰囲気は残しつつ縫い留めしています。<br><br><b>■素材</b><br>耐久性の高いコットン100%素材を使用。<br>インレイ生地に仕立てることで、ハリとコシが生まれ、型崩れがしにくいです。<br>また水に溶けない特殊な顔料でピグメント加工を施すことで、深みのある独特なフェード感を演出します。<br><br>======<br><b>■参考サイズ</b><br>M：～175cm<br>L：175cm～<br>======<br><br>ーーー', '4537.0 JPY', 276.76, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:17:33', '2026-04-02 04:18:47', 'adastria_675654', '', '69cd72d6a7ab618f2967cb91', '生活/休闲', '', '男', '青年（18-44岁）', '棉100%', 'https://www.dot-st.com/rageblue/disp/item/675654/?COLOR_CD=18', '上装', 'T恤', '亨利衫', '', 'henley shirt', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/rageblue/20260401/item_675654_main_18_1774865682_b.jpg', 0, 0, 2, 0.92479, 0, 1, 1, 0, 0, 3, NULL, '耐用，挺括有型，不易变形', '耐用,挺括有型,不易变形', '颜料染色/ピグメント加工', '短款宽松版型，强调身材比例和时尚感,前襟采用亨利领设计，可通过开合纽扣调整领口造型,使用贝壳风格纽扣，增加适度光泽与精致感,下摆采用外露包缝线设计，营造仿古着感,采用100%棉针织inlay面料，具有一定厚实度与支撑性,通过特殊不溶于水的颜料进行处理，呈现独特褪色与旧化效果', '纯色', '根据商品名“ヘンリーネックTシャツ”和图片可见：为短袖、套头、前中有开襟条并配数颗纽扣的T恤型上衣，这正是典型的“亨利领T恤”设计，故选择子类“henley shirt（亨利领T恤）”。该子类指以圆领配前襟开扣门襟为特征的休闲针织上衣。', 1, 0, 0, 0, 'henley shirt', NULL, '', 0, NULL, 0, NULL, NULL, '18', 'グレー18', 0);
INSERT INTO `clothing_info` VALUES (19996715, '＜预售＞颜料加工亨利领短款T恤', '＜先行予約＞ピグメント加工/ヘンリーネックTシャツ', 0, 31749821, 'RAGEBLUE', '', '', '流行的亨利领设计延伸至短款长度，领口通过开合纽扣即可改变造型氛围。领口使用贝壳质感纽扣，带来适度光泽与精致感。身幅为现代感的宽松廓形，衣长偏短，从轮廓上营造时髦感并达到显高效果。下摆采用外露包缝工艺，保留类似古着的做旧氛围。面料选用耐久性优异的100%棉材质，采用inlay针织结构带来一定的挺括与支撑，不易变形。通过使用不溶于水的特殊颜料进行颜料加工，呈现出深邃而独特的褪色质感。', '<b><font color=\"blue\">トレンドのヘンリーネックをショート丈に</font></b><br>ーーー<br><br><b>■ポイント</b><br>首元にアクセントを生むヘンリーネックは、ボタンの開け閉めだけでニュアンスの変化を楽しめます。<br>襟元には、貝蝶ボタンを採用することで、程よい光沢感があり、高見えします。<br>身幅は現代的リラックスシルエット、着丈は短めに設定することで、<br>アウトラインからトレンド感を生み出し、スタイルアップ効果も叶います。<br>裾にはオーバーロックをあしらうことで、古着のような雰囲気は残しつつ縫い留めしています。<br><br><b>■素材</b><br>耐久性の高いコットン100%素材を使用。<br>インレイ生地に仕立てることで、ハリとコシが生まれ、型崩れがしにくいです。<br>また水に溶けない特殊な顔料でピグメント加工を施すことで、深みのある独特なフェード感を演出します。<br><br>======<br><b>■参考サイズ</b><br>M：～175cm<br>L：175cm～<br>======<br><br>ーーー', '4537.0 JPY', 276.76, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:17:33', '2026-04-02 04:18:48', 'adastria_675654', '', '69cd72d6a7ab618f2967cb91', '生活/休闲', '', '男', '青年（18-44岁）', '棉100%', 'https://www.dot-st.com/rageblue/disp/item/675654/?COLOR_CD=18', '上装', 'T恤', '亨利衫', '', 'henley shirt', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/rageblue/20260401/item_675654_main_05_1774859753_b.jpg', 0, 0, 2, 0.99066, 0, 1, 1, 0, 0, 3, NULL, '耐用，挺括有型，不易变形', '耐用,挺括有型,不易变形', '颜料染色/ピグメント加工', '短款宽松版型，强调身材比例和时尚感,前襟采用亨利领设计，可通过开合纽扣调整领口造型,使用贝壳风格纽扣，增加适度光泽与精致感,下摆采用外露包缝线设计，营造仿古着感,采用100%棉针织inlay面料，具有一定厚实度与支撑性,通过特殊不溶于水的颜料进行处理，呈现独特褪色与旧化效果', '纯色', '根据商品名“ヘンリーネックTシャツ”和图片可见：为短袖、套头、前中有开襟条并配数颗纽扣的T恤型上衣，这正是典型的“亨利领T恤”设计，故选择子类“henley shirt（亨利领T恤）”。该子类指以圆领配前襟开扣门襟为特征的休闲针织上衣。', 1, 1, 0, 0, 'henley shirt', NULL, '', 0, NULL, 0, NULL, NULL, '05', 'ホワイト05', 0);
INSERT INTO `clothing_info` VALUES (19996716, '＜预售＞颜料加工亨利领短款T恤', '＜先行予約＞ピグメント加工/ヘンリーネックTシャツ', 0, 31749821, 'RAGEBLUE', '', '', '流行的亨利领设计延伸至短款长度，领口通过开合纽扣即可改变造型氛围。领口使用贝壳质感纽扣，带来适度光泽与精致感。身幅为现代感的宽松廓形，衣长偏短，从轮廓上营造时髦感并达到显高效果。下摆采用外露包缝工艺，保留类似古着的做旧氛围。面料选用耐久性优异的100%棉材质，采用inlay针织结构带来一定的挺括与支撑，不易变形。通过使用不溶于水的特殊颜料进行颜料加工，呈现出深邃而独特的褪色质感。', '<b><font color=\"blue\">トレンドのヘンリーネックをショート丈に</font></b><br>ーーー<br><br><b>■ポイント</b><br>首元にアクセントを生むヘンリーネックは、ボタンの開け閉めだけでニュアンスの変化を楽しめます。<br>襟元には、貝蝶ボタンを採用することで、程よい光沢感があり、高見えします。<br>身幅は現代的リラックスシルエット、着丈は短めに設定することで、<br>アウトラインからトレンド感を生み出し、スタイルアップ効果も叶います。<br>裾にはオーバーロックをあしらうことで、古着のような雰囲気は残しつつ縫い留めしています。<br><br><b>■素材</b><br>耐久性の高いコットン100%素材を使用。<br>インレイ生地に仕立てることで、ハリとコシが生まれ、型崩れがしにくいです。<br>また水に溶けない特殊な顔料でピグメント加工を施すことで、深みのある独特なフェード感を演出します。<br><br>======<br><b>■参考サイズ</b><br>M：～175cm<br>L：175cm～<br>======<br><br>ーーー', '4537.0 JPY', 276.76, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:17:33', '2026-04-02 04:18:49', 'adastria_675654', '', '69cd72d6a7ab618f2967cb91', '生活/休闲', '', '男', '青年（18-44岁）', '棉100%', 'https://www.dot-st.com/rageblue/disp/item/675654/?COLOR_CD=18', '上装', 'T恤', '亨利衫', '', 'henley shirt', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/rageblue/20260401/item_675654_main_09_1774859775_b.jpg', 0, 0, 2, 0.98205, 0, 1, 1, 0, 0, 3, NULL, '耐用，挺括有型，不易变形', '耐用,挺括有型,不易变形', '颜料染色/ピグメント加工', '短款宽松版型，强调身材比例和时尚感,前襟采用亨利领设计，可通过开合纽扣调整领口造型,使用贝壳风格纽扣，增加适度光泽与精致感,下摆采用外露包缝线设计，营造仿古着感,采用100%棉针织inlay面料，具有一定厚实度与支撑性,通过特殊不溶于水的颜料进行处理，呈现独特褪色与旧化效果', '纯色', '根据商品名“ヘンリーネックTシャツ”和图片可见：为短袖、套头、前中有开襟条并配数颗纽扣的T恤型上衣，这正是典型的“亨利领T恤”设计，故选择子类“henley shirt（亨利领T恤）”。该子类指以圆领配前襟开扣门襟为特征的休闲针织上衣。', 1, 2, 0, 0, 'henley shirt', NULL, '', 0, NULL, 0, NULL, NULL, '09', 'ブラック09', 0);
INSERT INTO `clothing_info` VALUES (19996712, '【NBA】别注/字母贴布标志休闲衬衫', '【NBA】別注/アップリケロゴシャツ', 0, 31749821, 'RAGEBLUE', '', '', '前幅字母贴布标志醒目，是一款设计感突出的宽松版衬衫，可单穿也可作内搭，实用性高。清爽配色适合春季造型，男女皆可穿着。肩宽和身宽加大，呈现流行的宽松廓形，通过开合门襟纽扣可以变化造型风格。采用质地挺括且触感舒适的100%棉牛津纺面料，兼顾耐穿与舒适。与NBA合作，具有联名特色。', '<b><font color=\"blue\">フロントのロゴが映えるオーバーサイズシャツ！<br>一枚着やインナーとして汎用性の高い一着。</font></b><br>ーーー<br><b>■ポイント</b><br>・フロントのロゴがアクセントになるデザインシャツが登場<br>・爽やかな色味で、春のスタイリングに最適<br>・ユニセックスでおすすめのかわいらしいシャツ〇<br><br><b>■デザイン・シルエット</b><br>・フロントのアップリケロゴが映える、デザイン性の高い一着。<br>・肩幅や身幅を広くとった、トレンドのオーバーサイズ/ルーズシルエット。<br>・ボタンを開閉することでガラッと印象が変わるため、様々なスタイリングをお楽しみいただけます！<br><br><b>■素材</b><br>ガシッとした質感と肌触りの良さを兼ね備えた、コットン100％のオックスフォード生地を使用。<br>春らしい爽やかな色味もポイントです。<br><br>======<br><b>■参考サイズ</b><br>FREE：160cm～<br>======<br><br>ーーー<br><b>■スタイリング</b><br>羽織るだけでかっこよく決まるブロードシャツは様々なコーディネートにおすすめ！<br>今年らしくスラックスやワイドパンツなどのきれいめボトムスと合わせたトレンドスタイルから、<br>デニムパンツと合わせた定番スタイルまで幅広く対応可能〇<br><br><font color=\"red\">【NBA】ナショナル・バスケットボール・アソシエーション（英語:National Basketball Association）</font><br><br>1946年に創設された北米大陸を拠点とするプロバスケットボールリーグ。<br>アメリカ合衆国の29チームおよびカナダの1チームの計30チームからなる。<br>', '9082.0 JPY', 554.00, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:17:34', '2026-04-02 04:18:45', 'adastria_323842', '', '69cd72d6a7ab618f2967cb8d', '生活/休闲', '', '通用', '青年（18-44岁）', '棉100%', 'https://www.dot-st.com/rageblue/disp/item/323842/?COLOR_CD=85', '上装', '衬衫', '休闲衬衫', '', 'casual shirt', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/rageblue/20260401/item_323842_main_85_1738890712_b.jpg', 0, 0, 1, 0.99994, 0, -2, 0, 0, 0, 3, NULL, '透气，舒适，宽松版型便于叠穿', '舒适,宽松版型便于叠穿', '', '与NBA合作的联名款，前幅立体字母装饰增强潮流感,采用全棉牛津纺面料，质地挺括且手感舒适,宽松落肩廓形，适合多种叠穿与造型方式,适合春季穿着的清爽配色', '字母', '该商品为长袖、有翻领和前门襟纽扣的上衣，属于典型衬衫结构，且用于日常穿搭，不是正式商务衬衫，因此在给定列表中选择“casual shirt（休闲衬衫）”最为贴切。', 1, 0, 0, 0, 'casual shirt', NULL, '', 0, NULL, 0, NULL, NULL, '85', 'ブルー85', 0);
INSERT INTO `clothing_info` VALUES (19996713, '【NBA】别注/字母贴布标志休闲衬衫', '【NBA】別注/アップリケロゴシャツ', 0, 31749821, 'RAGEBLUE', '', '', '前幅字母贴布标志醒目，是一款设计感突出的宽松版衬衫，可单穿也可作内搭，实用性高。清爽配色适合春季造型，男女皆可穿着。肩宽和身宽加大，呈现流行的宽松廓形，通过开合门襟纽扣可以变化造型风格。采用质地挺括且触感舒适的100%棉牛津纺面料，兼顾耐穿与舒适。与NBA合作，具有联名特色。', '<b><font color=\"blue\">フロントのロゴが映えるオーバーサイズシャツ！<br>一枚着やインナーとして汎用性の高い一着。</font></b><br>ーーー<br><b>■ポイント</b><br>・フロントのロゴがアクセントになるデザインシャツが登場<br>・爽やかな色味で、春のスタイリングに最適<br>・ユニセックスでおすすめのかわいらしいシャツ〇<br><br><b>■デザイン・シルエット</b><br>・フロントのアップリケロゴが映える、デザイン性の高い一着。<br>・肩幅や身幅を広くとった、トレンドのオーバーサイズ/ルーズシルエット。<br>・ボタンを開閉することでガラッと印象が変わるため、様々なスタイリングをお楽しみいただけます！<br><br><b>■素材</b><br>ガシッとした質感と肌触りの良さを兼ね備えた、コットン100％のオックスフォード生地を使用。<br>春らしい爽やかな色味もポイントです。<br><br>======<br><b>■参考サイズ</b><br>FREE：160cm～<br>======<br><br>ーーー<br><b>■スタイリング</b><br>羽織るだけでかっこよく決まるブロードシャツは様々なコーディネートにおすすめ！<br>今年らしくスラックスやワイドパンツなどのきれいめボトムスと合わせたトレンドスタイルから、<br>デニムパンツと合わせた定番スタイルまで幅広く対応可能〇<br><br><font color=\"red\">【NBA】ナショナル・バスケットボール・アソシエーション（英語:National Basketball Association）</font><br><br>1946年に創設された北米大陸を拠点とするプロバスケットボールリーグ。<br>アメリカ合衆国の29チームおよびカナダの1チームの計30チームからなる。<br>', '9082.0 JPY', 554.00, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:17:34', '2026-04-02 04:18:46', 'adastria_323842', '', '69cd72d6a7ab618f2967cb8d', '生活/休闲', '', '通用', '青年（18-44岁）', '棉100%', 'https://www.dot-st.com/rageblue/disp/item/323842/?COLOR_CD=85', '上装', '衬衫', '休闲衬衫', '', 'casual shirt', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/rageblue/20260401/item_323842_main_82_1738890709_b.jpg', 0, 0, 1, 0.99995, 0, -2, 0, 0, 0, 3, NULL, '透气，舒适，宽松版型便于叠穿', '舒适,宽松版型便于叠穿', '', '与NBA合作的联名款，前幅立体字母装饰增强潮流感,采用全棉牛津纺面料，质地挺括且手感舒适,宽松落肩廓形，适合多种叠穿与造型方式,适合春季穿着的清爽配色', '字母', '该商品为长袖、有翻领和前门襟纽扣的上衣，属于典型衬衫结构，且用于日常穿搭，不是正式商务衬衫，因此在给定列表中选择“casual shirt（休闲衬衫）”最为贴切。', 1, 1, 0, 0, 'casual shirt', NULL, '', 0, NULL, 0, NULL, NULL, '82', 'ブルー82', 0);
INSERT INTO `clothing_info` VALUES (19996711, 'Summer Motion Tech 西装外套 / Salon de GW / 647374', 'サマーモーションテックジャケット/Salon de GW/647374', 0, 31749815, 'GLOBAL WORK', '', '', '采用混纺真丝的高支针织面料，触感清爽顺滑，兼具柔韧质感与针织特有的高弹力，并通过丝纤维带来上品光泽与高级感。版型延续2025秋冬季的设计与廓形，在保持利落外观的同时，进一步提升活动自如度，实现无束缚的舒适西装穿着体验。推荐与同面料长裤成套搭配，打造适合商务与正式场合的大人感造型。品牌「Salon de GW」专注于兼具普遍性与时代感的精致正装，由拥有丰富经验与精湛工艺的国际品牌〈リングヂャケット〉协力打造，提供高品质、高性价比且具有高级氛围的衣橱选择。', '<font color=#0000ff><b>Salon de GW 2026</b></font><br>ーーー<br>・素材/機能<br>シルク混のハイカウントジャージ素材です。<br>さらりとしていてしなやかなタッチ感と、ジャージ特有の高いストレッチ性が特徴です。<br>シルク混のため、上品な光沢感が高級感を演出します。<br><br>・デザイン<br>2025秋冬シーズンからデザイン、シルエットの変更ありません。<br>より一層の動きやすさと、ストレスフリーなスーチングスタイルを実現しています。<br><br>ーーー<br>・お勧めスタイリング<br>同素材のパンツとの組み合わせがおすすめです。<br><br>・ABOUT：Salon de GW(サロン ド グローバルワーク)<br>それは普遍性と時代性を追求した価値あるドレスクロージング<br><br>GLOBAL WORKがおくる「Salon de GW(サロン ド グローバルワーク)」。<br>それはビジネスユースやフォーマルシーン、しかるべき装いを求められる大人へ向けた、<br>普遍的でありながら静かに時代性も薫る洗練のドレスクロージング。<br>その理想をカタチにして、さらなる高みへと押し上げるべくパートナーに迎えたのは、<br>日本をはじめ北米・欧州・アジア諸国でも展開するインターナショナルクロージングブランド〈リングヂャケット〉。<br>長年の豊かな経験と卓越した職人技を誇り、国内外で優れた評価を獲得している彼らのノウハウを惜しみなく注ぎ込むことで、<br>ハイクオリティかつハイコストパフォーマンス、そしてハイクラスな価値あるワードロープを叶えています。<br><br><a href=\"https://www.dot-st.com/globalwork/concept/?dispNo=013001727019\"><b><font size=\"2\" color=\"blue\"><u>取り扱い店舗一覧はこちら</u></a></font></b><br><br><a href=\"https://www.dot-st.com/globalwork/disp/itemlist/?dispNo=002002510\"><b><font size=\"2\" color=\"blue\"><u> Salon de GW 26SS アイテム一覧はこちら</u></a></font></b><br><a href=\"adastriaapp://items?dispNo=0000100002_002002510\"><b><font size=\"2\" color=\"blue\"><u> Salon de GW 26SSアイテム一覧アプリの方はこちら</u></a></font></b>', '13628.0 JPY', 831.31, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:18:47', '2026-04-02 04:18:44', 'adastria_647374', '', '69cd72d6a7ab618f2967cb82', '差旅/商务', '', '男', '青年（18-44岁）', '粘胶49%,锦纶33%,氨纶13%,桑蚕丝5%', 'https://www.dot-st.com/globalwork/disp/item/647374/?COLOR_CD=88', '上装', '西装外套', '西装外套', '', 'blazer', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/global_work/20260401/item_647374_main_88_1773893544_b.jpg', 0, 0, 2, 0.68726, 0, 1, 1, 0, 0, 3, NULL, '高弹力，透气，舒适，易活动，高级感光泽，柔软触感', '舒适,易活动,高级感光泽,柔软触感', '高密针织材质,功能性弹力面料', '采用丝混高密针织面料，兼具顺滑手感与挺括度,面料具有较高弹性，适合长时间商务穿着,带有上品光泽感，适用于商务与正式场合,版型延续前一季设计，强调活动自如与无束缚穿着体验,推荐与同面料裤装成套搭配，打造西装风格造型', '纯色', '从图片和描述看，这是一款有翻驳领、单排两粒扣、胸袋和贴袋设计的西装式上衣，用于商务和正装场合，明显属于“blazer（西装外套）”范畴，而不是休闲夹克或功能外套。根据提供的子类列表，“blazer”定义为用于正装/商务穿着的西装上衣，与商品“サマーモーションテックジャケット”及其商务、フォーマル用途完全吻合。', 0, 0, 0, 0, 'blazer', NULL, '', 0, NULL, 0, NULL, NULL, '88', 'ネイビー88', 0);
INSERT INTO `clothing_info` VALUES (19996710, '超弹力拼接连衣裙 /133627', 'スゴラクストレッチドッキングワンピース/133627', 0, 31749815, 'GLOBAL WORK', '', '', '「既非常轻松，又非常优雅」的SUGORAKU弹力系列。面料具有良好伸缩性，活动自如，采用具有高级质感的剪裁针织乔其面料，兼具舒适与利落外观。通过使用降低耐电压的特殊附属材料，减轻恼人的静电。整件为一件即可完成造型的拼接感连衣裙，上身仿衬衫与下身裙装套装风格。上身略短的长度设计，营造纤细感并有拉长比例效果。后身开衩加上弹力面料，保证行动方便。腰部为松紧设计，长时间穿着也能保持舒适。本季在袖口加入仿珍珠纽扣，提升华丽度，并重新调整版型，使轮廓更为利落好看。搭配胸花或胸针能营造更华丽的氛围，适合各类仪式场合。上身部分的尺寸可在外搭夹克时保持舒适。适合在新生活开启的春季穿着，兼顾显气质效果与功能性的典礼与办公连衣裙。', '<font color=#ff69b4><b>すごく楽ちん。すごくきれい。<br>スゴラクストレッチシリーズ</b></font><br>ーーー<br>・素材/機能<br>伸縮性があり、動きやすさが抜群<br>キレイ見えするカットジョーゼット<br><br>静電気軽減　耐電圧を下げる特殊な付属を使用し、不快な静電気を軽減します<br><br>・デザイン/アップデート<br>1枚でスタイルが完成する、ブラウスとスカートのセットアップ風ワンピース。<br>ブラウス部分は短めの着丈で、華奢見え・スタイルUP効果があります。<br>バックスリット入りとストレッチで動きやすさも担保。<br>更にウエストがゴム仕様なので、長時間の着用でも快適に過ごせます。<br>今シーズンは袖にパール調ボタンを付けて、華やかさをアップデート。<br>シルエットもより綺麗に見えるように調整しています。<br>ーーー<br>・お勧めスタイリング<br>コサージュやブローチをつけるとより華やかな雰囲気に。<br>セレモニーシーンにもおススメです。<br>ブラウス部分は上からジャケットを羽織れるサイジングになっています。<br><br>新しい生活が始まる春に向けて、着映えも機能性も叶う<br>GLOBAL WORKのセレモニーウェアとオフィスウェア<br><a href=\"adastriaapp://items?dispNo=0000100002_002100025001&orderBy=00\"><b><font size=\"2\" color=\"black\">アイテム一覧はこちら</a></font></b><br><br>PC・ブラウザの方はこちら↓<br><a href=\"https://www.dot-st.com/globalwork/disp/itemlist/?dispNo=002100025001\"><b><font size=\"3\" color=\"black\">セレモニー・オフィスウェア</a></font></b>', '7264.0 JPY', 443.10, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:19:28', '2026-04-02 04:18:44', 'adastria_133627', '', '69cd72d6a7ab618f2967cb79', '生活/休闲，差旅/商务', '', '女', '青年（18-44岁）', '涤纶97%,氨纶3%', 'https://www.dot-st.com/globalwork/disp/item/133627/?COLOR_CD=09', '裙装', '连衣裙', '中长裙', '', 'midi dress', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/global_work/20260401/item_133627_main_09_1731034562_b.jpg', 0, 0, 2, 0.87041, 0, 1, 1, 0, 0, 3, NULL, '防静电，高弹力，舒适穿着，修饰身形，易活动', '舒适穿着,修饰身形,易活动', '降低静电电压的特殊附属材料', '一件即可完成上衣与裙子套装感造型,腰部松紧设计提升长期穿着舒适度,后开衩与弹力面料提升活动性,袖口装饰珍珠感纽扣增加华丽感,适合典礼、入学/毕业等仪式与通勤办公场合,剪影经过优化以提升挺括与显瘦效果', '纯色，纯色', '从商品名称“ドッキングワンピース”和图片可以看出，这是上身仿衬衫/上衣、下身裙装连为一体的连衣裙款式，裙长过膝至小腿中部，属于中长长度，因此在给定列表中最符合“midi dress（中长连衣裙）”这一类别。midi dress 指裙长介于膝盖与脚踝之间的一体式连衣裙，本品完全符合该定义。', 0, 0, 0, 0, 'midi dress', NULL, '', 0, NULL, 0, NULL, NULL, '09', 'ブラック09', 0);
INSERT INTO `clothing_info` VALUES (19996708, 'meets India／蕾丝长裙／601013', 'meets India/レーススカート/601013', 0, 31749815, 'GLOBAL WORK', '', '', '为成熟女性设计的印度棉长裙，整体在甜美基础上做了收敛处理，呈现更大人的平衡感。采用具有印度面料特有纤细感与柔软触感的棉质薄纱（cotton voile），质地轻盈柔和。通过蕾丝拼接与精致的细褶细节增加层次感与视觉亮点，同时保持不过分蓬起的顺畅轮廓。腰部为全松紧设计，并配有抽绳，可根据身形调节贴合度，穿着舒适。提供不同裙长选择，可根据体型与风格挑选合适长度。全色系均配有里布和口袋，兼具美观与实用性。浅色如米白略带透感，可通过调整内搭颜色或与裤装叠穿来平衡。适合搭配简约衬衫、字母或照片印花T恤，营造女性化造型，也可作为西装外套等单品的柔和平衡搭配。', '<font color=#ff69b4><b>甘さを抑えた大人のためのインド綿スカート</b></font><br>ーーー<br>・素材/機能<br>家庭洗濯可能<br><br>インド素材ならではの繊細さとソフトな風合いが特徴のコットンボイル素材です。<br>家庭洗濯可能ですが、干す際に大きなシワを縦方向に整えて干すと洗いざらしでも着やすい仕上がりになるのでおすすめです。<br>インド生産および製品洗い加工のため、1点1点風合いや許容範囲内の若干のサイズブレがございます。<br><br>・デザイン<br>レース切り替えデザインの甘さを抑え、大人なバランスに仕上げました。<br>広がり過ぎないシルエットも魅力です。<br>華奢なレースとピンタックを繊細に組み合わせてアクセントにしています。<br>体型やイメージで丈を選べるショート、レギュラー展開。<br>ウエストは総ゴムで着心地が良く、ドロストでサイズ調節できます。<br>全色裏地、ポケット付きで実用性にも優れています。<br>ーーー<br>・おすすめスタイリング<br>シンプルなシャツ類やロゴ、フォトTシャツを合わせたフェミニンな印象のスタイルに。<br>ジャケット類の外しアイテムとしても活用いただけます。<br>繊細な素材ということもあり、オフホワイトは若干の透け感がありますが、下着の色の調整やパンツに重ねるなどのスタイリングでカバーできます。', '6355.0 JPY', 387.65, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:19:32', '2026-04-02 04:18:42', 'adastria_601013', '', '69cd72d6a7ab618f2967cb6a', '生活/休闲', '', '女', '青年（18-44岁）', '棉100%', 'https://www.dot-st.com/globalwork/disp/item/601013/?COLOR_CD=09', '裙装', '半身裙', '长裙', '', 'maxi skirt', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/global_work/20260401/item_601013_main_09_1774939026_b.jpg', 0, 0, 2, 0.94370, 0, 1, 0, 0, 0, 3, NULL, '透气，家用可机洗，腰部松紧调节舒适穿着，带口袋便于收纳小物，遮挡腿部线条修饰身形', '家用可机洗,腰部松紧调节舒适穿着,带口袋便于收纳小物,遮挡腿部线条修饰身形', '', '采用印度棉cotton voile材质，质地轻薄柔软,整体为蕾丝拼接与细致压褶设计，风格偏成熟甜美,版型不过分蓬松，保持顺直垂坠感,提供不同裙长可选择，适配不同身高与风格,部分浅色有轻微透视感，可通过搭配内搭或裤装解决', '其他', '从图片和描述看，这是长及脚踝的女性下装裙子，版型修长、长度明显为长裙而非中裙或短裙，且重点是日常穿着的时尚单品，因此在给定类别中最贴近“maxi skirt（长款半身裙）”。', 1, 0, 0, 0, 'maxi skirt', NULL, '', 0, NULL, 0, NULL, NULL, '09', 'ブラック09', 0);
INSERT INTO `clothing_info` VALUES (19996709, 'meets India／蕾丝长裙／601013', 'meets India/レーススカート/601013', 0, 31749815, 'GLOBAL WORK', '', '', '为成熟女性设计的印度棉长裙，整体在甜美基础上做了收敛处理，呈现更大人的平衡感。采用具有印度面料特有纤细感与柔软触感的棉质薄纱（cotton voile），质地轻盈柔和。通过蕾丝拼接与精致的细褶细节增加层次感与视觉亮点，同时保持不过分蓬起的顺畅轮廓。腰部为全松紧设计，并配有抽绳，可根据身形调节贴合度，穿着舒适。提供不同裙长选择，可根据体型与风格挑选合适长度。全色系均配有里布和口袋，兼具美观与实用性。浅色如米白略带透感，可通过调整内搭颜色或与裤装叠穿来平衡。适合搭配简约衬衫、字母或照片印花T恤，营造女性化造型，也可作为西装外套等单品的柔和平衡搭配。', '<font color=#ff69b4><b>甘さを抑えた大人のためのインド綿スカート</b></font><br>ーーー<br>・素材/機能<br>家庭洗濯可能<br><br>インド素材ならではの繊細さとソフトな風合いが特徴のコットンボイル素材です。<br>家庭洗濯可能ですが、干す際に大きなシワを縦方向に整えて干すと洗いざらしでも着やすい仕上がりになるのでおすすめです。<br>インド生産および製品洗い加工のため、1点1点風合いや許容範囲内の若干のサイズブレがございます。<br><br>・デザイン<br>レース切り替えデザインの甘さを抑え、大人なバランスに仕上げました。<br>広がり過ぎないシルエットも魅力です。<br>華奢なレースとピンタックを繊細に組み合わせてアクセントにしています。<br>体型やイメージで丈を選べるショート、レギュラー展開。<br>ウエストは総ゴムで着心地が良く、ドロストでサイズ調節できます。<br>全色裏地、ポケット付きで実用性にも優れています。<br>ーーー<br>・おすすめスタイリング<br>シンプルなシャツ類やロゴ、フォトTシャツを合わせたフェミニンな印象のスタイルに。<br>ジャケット類の外しアイテムとしても活用いただけます。<br>繊細な素材ということもあり、オフホワイトは若干の透け感がありますが、下着の色の調整やパンツに重ねるなどのスタイリングでカバーできます。', '6355.0 JPY', 387.65, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:19:32', '2026-04-02 04:18:43', 'adastria_601013', '', '69cd72d6a7ab618f2967cb6a', '生活/休闲', '', '女', '青年（18-44岁）', '棉100%', 'https://www.dot-st.com/globalwork/disp/item/601013/?COLOR_CD=09', '裙装', '半身裙', '长裙', '', 'maxi skirt', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/global_work/20260401/item_601013_main_05_1772538768_b.jpg', 0, 0, 2, 0.94959, 0, 1, 0, 0, 0, 3, NULL, '透气，家用可机洗，腰部松紧调节舒适穿着，带口袋便于收纳小物，遮挡腿部线条修饰身形', '家用可机洗,腰部松紧调节舒适穿着,带口袋便于收纳小物,遮挡腿部线条修饰身形', '', '采用印度棉cotton voile材质，质地轻薄柔软,整体为蕾丝拼接与细致压褶设计，风格偏成熟甜美,版型不过分蓬松，保持顺直垂坠感,提供不同裙长可选择，适配不同身高与风格,部分浅色有轻微透视感，可通过搭配内搭或裤装解决', '其他', '从图片和描述看，这是长及脚踝的女性下装裙子，版型修长、长度明显为长裙而非中裙或短裙，且重点是日常穿着的时尚单品，因此在给定类别中最贴近“maxi skirt（长款半身裙）”。', 1, 1, 0, 0, 'maxi skirt', NULL, '', 0, NULL, 0, NULL, NULL, '05', 'オフ05', 0);
INSERT INTO `clothing_info` VALUES (19996706, '花朵编织耳夹/646393', 'フラワー編みイヤリング/646393', 0, 31749815, 'GLOBAL WORK', '', '', '一颗一颗细致编织而成、具有立体感的珠饰耳夹。以珠子特有的柔和光泽与温暖质感，为耳畔增添自然的华丽气息。花朵造型不过分甜美，与大人感休闲或自然风穿搭非常相配，也适合作为酷感造型中的点睛之笔。适合日常外出及派对等场合佩戴。', '<font color=#ff69b4><b>甘すぎない大人のビーズ編み</b></font><br>ーーー<br>ひと粒ずつ丁寧に編みあげた、立体感のあるビーズイヤリング。<br>ビーズならではのやさしい光沢とぬくもりが、耳元に自然な華やかさをプラスしてくれます。<br>フラワーモチーフでも甘くなりすぎず、大人カジュアルやナチュラルコーデと好相性。<br>クールなスタイリングの外しとしても。<br><br>プチプラ　花　お出かけ　パーティー<br>ーーー', '1600.0 JPY', 97.60, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:20:13', '2026-04-02 04:18:40', 'adastria_646393', '', '69cd72d6a7ab618f2967cb64', '生活/休闲', '', '通用', '青年（18-44岁）', NULL, 'https://www.dot-st.com/globalwork/disp/item/646393/?COLOR_CD=58', '其他服饰/物品', '其他', '配件', '', 'accessories', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/global_work/20260401/item_646393_main_58_1770777536_b.jpg', 0, 0, 9, 0.98896, 0, -1, 0, 0, 0, 3, NULL, '装饰搭配，提升造型精致度', '装饰搭配,提升造型精致度', '', '采用手工感较强的珠子编织工艺，呈现立体花朵造型,金属与聚酯材质结合，既有光泽感又有温润质感,风格偏大人感，不会过于甜美，适合日常与聚会场合', '花卉图案', '该产品为耳环类首饰，属于搭配用小物，并非服装或家纺。根据图片与描述“ビーズイヤリング”“フラワーモチーフ”，可判断是饰品配件，因此选择子类目“accessories（配饰）”，定义为：用于装饰身体或服装的非服装类小物，如耳环、项链、帽饰等。', 1, 0, 0, 0, 'accessories', NULL, '', 0, NULL, 0, NULL, NULL, '58', 'ブラウン58', 0);
INSERT INTO `clothing_info` VALUES (19996707, '花朵编织耳夹/646393', 'フラワー編みイヤリング/646393', 0, 31749815, 'GLOBAL WORK', '', '', '一颗一颗细致编织而成、具有立体感的珠饰耳夹。以珠子特有的柔和光泽与温暖质感，为耳畔增添自然的华丽气息。花朵造型不过分甜美，与大人感休闲或自然风穿搭非常相配，也适合作为酷感造型中的点睛之笔。适合日常外出及派对等场合佩戴。', '<font color=#ff69b4><b>甘すぎない大人のビーズ編み</b></font><br>ーーー<br>ひと粒ずつ丁寧に編みあげた、立体感のあるビーズイヤリング。<br>ビーズならではのやさしい光沢とぬくもりが、耳元に自然な華やかさをプラスしてくれます。<br>フラワーモチーフでも甘くなりすぎず、大人カジュアルやナチュラルコーデと好相性。<br>クールなスタイリングの外しとしても。<br><br>プチプラ　花　お出かけ　パーティー<br>ーーー', '1600.0 JPY', 97.60, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:20:13', '2026-04-02 04:18:41', 'adastria_646393', '', '69cd72d6a7ab618f2967cb64', '生活/休闲', '', '通用', '青年（18-44岁）', NULL, 'https://www.dot-st.com/globalwork/disp/item/646393/?COLOR_CD=58', '其他服饰/物品', '其他', '配件', '', 'accessories', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/global_work/20260401/item_646393_main_08_1770777535_b.jpg', 0, 0, 9, 0.59640, 0, -1, 0, 0, 0, 3, NULL, '装饰搭配，提升造型精致度', '装饰搭配,提升造型精致度', '', '采用手工感较强的珠子编织工艺，呈现立体花朵造型,金属与聚酯材质结合，既有光泽感又有温润质感,风格偏大人感，不会过于甜美，适合日常与聚会场合', '花卉图案', '该产品为耳环类首饰，属于搭配用小物，并非服装或家纺。根据图片与描述“ビーズイヤリング”“フラワーモチーフ”，可判断是饰品配件，因此选择子类目“accessories（配饰）”，定义为：用于装饰身体或服装的非服装类小物，如耳环、项链、帽饰等。', 1, 1, 0, 0, 'accessories', NULL, '', 0, NULL, 0, NULL, NULL, '08', 'アイボリー08', 0);
INSERT INTO `clothing_info` VALUES (19996703, 'CONVERSE/STAR FIRE AG/网页版限定/678638', 'CONVERSE/STAR FIRE AG/WEB限定/678638', 0, 31749815, 'GLOBAL WORK', '', '', '以1977年登场的跑鞋“STAR FIRE”为原型，将经典外观与舒适脚感结合的薄底款。鞋面经过水洗处理，呈现尼龙自然褶皱、麂皮色差以及鞋舌标老化感，再现复古风貌。配色汲取品牌档案灵感，具有复古街头氛围。采用双层结构E.V.A.中底，在薄底设计下依旧实现舒适的穿着体验。适合通勤、通学、街头休闲及户外场景穿着。', '<font color=#ff69b4><b>1977年の名作を快適な履き心地で復刻</b></font><br>ーーー<br>1977年に登場したランニングシューズ「STAR FIRE」をベースに、クラシックなルックスと快適な履き心地を兼ね備えた薄底モデル。<br>アッパーに洗い加工を施し、ナイロンのシワやスエードの色ムラ、タンラベルのエイジング感などヴィンテージの風合いを再現。<br>アーカイブからインスピレーションを得たカラーリングもポイント。<br>薄底ながらも、2層構造のE.V.A.ミッドソールを採用することで、快適な履き心地を実現。<br><br>コンバース　CONVERSE　スターファイヤー　通勤　通学　ストリート　アウトドア　差し色　カラー<br>ーーー', '12500.0 JPY', 762.50, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:20:35', '2026-04-02 04:18:38', 'adastria_678638', '', '69cd72d6a7ab618f2967cb63', '生活/休闲', '', '通用', '青年（18-44岁）', NULL, 'https://www.dot-st.com/globalwork/disp/item/678638/?COLOR_CD=35', '其他服饰/物品', '其他', NULL, '', 'shoes', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/global_work/20260401/item_678638_main_35_1774833657_b.jpg', 0, 0, 9, 0.85209, 0, 1, 0, 0, 0, 3, NULL, '透气，舒适穿着，缓震支撑，抓地力好', '舒适穿着,缓震支撑,抓地力好', 'E.V.A.中底双层结构', '复刻1977年经典跑鞋STAR FIRE款式,薄底设计但脚感舒适,鞋面经过水洗工艺呈现复古做旧效果,尼龙面料有自然皱感与麂皮色差营造老化感,鞋舌标有仿旧老化效果,配色来自品牌档案，具有复古街头风格', '纯色', '产品类别标注为“シューズ”，图片为一双系带运动鞋，且描述为CONVERSE复刻跑鞋，显然是穿在脚上的鞋类单品，因此在给定列表中选择最接近的“shoes”。“shoes”定义为各种鞋履产品，本品为经典跑鞋/休闲运动鞋，完全符合该子类。', 1, 0, 0, 0, 'shoes', NULL, '', 0, NULL, 0, NULL, NULL, '35', 'レッド35', 0);
