INSERT INTO `clothing_info` VALUES (19996697, '米卢斯现代印花短袖T恤', 'ミュルーズモダンTシャツ/半袖/678612', 0, 31749815, 'GLOBAL WORK', '', '', '这是一款与米卢斯染织美术馆合作的印花T恤，面料为表面光滑、手感适中的100%棉，既有一定厚度又具备良好通用性。选取该美术馆收藏的约600万件染织资料中严选出的6种图案进行印花，呈现出富有知识与艺术气息的设计。版型为适度宽松的放松廓形，单穿即可营造当下流行的造型感，女性也能舒适穿着。可与休闲宽腿下装或利落西裤搭配，提升整体造型的完成度和知性印象。', '<font color=#0000ff><b>ミュルーズコラボTシャツ</b></font><br>ーーー<br>・素材/機能/アップデート<br>程よい肉感で汎用性のある、表面が滑らかなコットン100％の素材です。<br><br>・デザイン/アップデートポイント<br>1857年、フランスのアルザス地方に創設されたミュルーズ染織美術館は、世界でも類を見ない染織生地などの貴重な資料を収蔵しています。<br>それらは多くの一流ブランドのデザインソースともなっています。<br>世界各地から収集された約600万点もの染織資料より、厳選した6柄をプリントした知的な印象のTシャツです。<br><br>程よいリラックスシルエットで、一枚で着ても今っぽさのあるサイズ感に仕上げました。<br>女性のお客様にも、程よいリラックス感で着用いただけるためおすすめです。<br><br>ーーー<br>・おすすめスタイリング<br>カジュアルなワイドボトムスはもちろん、クリーンな印象のスラックス合わせでも、知的な印象の本製品と相性が良く、スタイリングの完成度が上がります。', '4537.0 JPY', 276.76, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:21:47', '2026-04-02 04:18:33', 'adastria_678612', '', '69cd72d6a7ab618f2967cb5c', '生活/休闲', '', '通用', '青年（18-44岁）', '棉100%', 'https://www.dot-st.com/globalwork/disp/item/678612/?COLOR_CD=10', '上装', 'T恤', 'T恤', '', 't-shirt', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/global_work/20260401/item_678612_main_10_1774956228_b.jpg', 0, 0, 1, 0.99868, 0, -2, 0, 0, 0, 3, NULL, '舒适，亲肤，日常休闲穿着', '舒适,亲肤,日常休闲穿着', '', '与米卢斯染织美术馆联名印花图案,棉100%材质，表面光滑，有一定厚实度,中等宽松版型，呈现适度放松感,适合男女通穿的中性T恤设计,可搭配休闲阔腿裤或干练西裤穿搭', '其他', '商品名称中含有“Tシャツ/半袖”，并从图片上看为典型短袖圆领上衣，属于基础针织上衣类型；结合版型与用途，最符合列表中的“t-shirt（T恤）”类目。t-shirt 定义为以针织面料为主、短袖或长袖、贴身或宽松穿着的上衣，本品完全符合这一特征。', 1, 0, 0, 0, 't-shirt', NULL, '', 0, NULL, 0, NULL, NULL, '10', 'ブラック10', 0);
INSERT INTO `clothing_info` VALUES (19996698, '米卢斯现代印花短袖T恤', 'ミュルーズモダンTシャツ/半袖/678612', 0, 31749815, 'GLOBAL WORK', '', '', '这是一款与米卢斯染织美术馆合作的印花T恤，面料为表面光滑、手感适中的100%棉，既有一定厚度又具备良好通用性。选取该美术馆收藏的约600万件染织资料中严选出的6种图案进行印花，呈现出富有知识与艺术气息的设计。版型为适度宽松的放松廓形，单穿即可营造当下流行的造型感，女性也能舒适穿着。可与休闲宽腿下装或利落西裤搭配，提升整体造型的完成度和知性印象。', '<font color=#0000ff><b>ミュルーズコラボTシャツ</b></font><br>ーーー<br>・素材/機能/アップデート<br>程よい肉感で汎用性のある、表面が滑らかなコットン100％の素材です。<br><br>・デザイン/アップデートポイント<br>1857年、フランスのアルザス地方に創設されたミュルーズ染織美術館は、世界でも類を見ない染織生地などの貴重な資料を収蔵しています。<br>それらは多くの一流ブランドのデザインソースともなっています。<br>世界各地から収集された約600万点もの染織資料より、厳選した6柄をプリントした知的な印象のTシャツです。<br><br>程よいリラックスシルエットで、一枚で着ても今っぽさのあるサイズ感に仕上げました。<br>女性のお客様にも、程よいリラックス感で着用いただけるためおすすめです。<br><br>ーーー<br>・おすすめスタイリング<br>カジュアルなワイドボトムスはもちろん、クリーンな印象のスラックス合わせでも、知的な印象の本製品と相性が良く、スタイリングの完成度が上がります。', '4537.0 JPY', 276.76, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:21:47', '2026-04-02 04:18:33', 'adastria_678612', '', '69cd72d6a7ab618f2967cb5c', '生活/休闲', '', '通用', '青年（18-44岁）', '棉100%', 'https://www.dot-st.com/globalwork/disp/item/678612/?COLOR_CD=10', '上装', 'T恤', 'T恤', '', 't-shirt', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/global_work/20260401/item_678612_main_09_1774956232_b.jpg', 0, 0, 1, 0.99691, 0, -2, 0, 0, 0, 3, NULL, '舒适，亲肤，日常休闲穿着', '舒适,亲肤,日常休闲穿着', '', '与米卢斯染织美术馆联名印花图案,棉100%材质，表面光滑，有一定厚实度,中等宽松版型，呈现适度放松感,适合男女通穿的中性T恤设计,可搭配休闲阔腿裤或干练西裤穿搭', '其他', '商品名称中含有“Tシャツ/半袖”，并从图片上看为典型短袖圆领上衣，属于基础针织上衣类型；结合版型与用途，最符合列表中的“t-shirt（T恤）”类目。t-shirt 定义为以针织面料为主、短袖或长袖、贴身或宽松穿着的上衣，本品完全符合这一特征。', 1, 1, 0, 0, 't-shirt', NULL, '', 0, NULL, 0, NULL, NULL, '09', 'ブラック09', 0);
