INSERT INTO `clothing_info` VALUES (19996702, '高山直子合作款／可拆卸领口罗纹针织套头衫／EiiS／289622', '高山直子さんコラボ/襟2WAYリブニットプルオーバー/EiiS/289622', 0, 31749815, 'GLOBAL WORK', '', '', '功能上，领子可拆卸，可作为圆领针织衫单独穿着。采用不易勾勒身体曲线的挺括罗纹针织材质，领口与袖口以蕾丝装饰为亮点。通过更换领子可营造不同印象，增加搭配灵活性。紧凑利落的版型有显瘦效果，并且与廓形感较强的下装相配平衡感良好。适合与褶皱宽松工装风长裤或锥形裤搭配，打造干练风格，也可以与伞裙、鱼尾裙等搭出更为优雅、女性化的造型，整体更显华丽。品牌EiiS旨在为小个子女性提供“即使个子小也能自由挑选想穿的衣服”的选择，希望通过贴合身型的剪裁与设计带来幸福感和自信。', '・機能<br>襟取り外し可能<br><br>・デザイン<br>身体のラインを拾いにくい、しっかり目素材のリブニット。<br>襟元と袖のレースデザインがポイント。<br>襟は取り外し可能で、クルーネックニットとしても着られます。<br>異なる印象が楽しめ、着回しもしやすいです。<br>コンパクトなシルエットで細見えし、ボリュームのあるボトムスとも好相性。<br>ーーー<br>・お勧めスタイリング<br><a href=\"https://www.dot-st.com/globalwork/disp/item/289617/\"><b><font size=\"2\" color=\"black\">タックワイドチノパンツ/EiiS</a></font></b>や、テーパードパンツと合わせたキレイ目スタイルや、フレアスカートを合わせたレディライクなスタイルがおススメ。<br>華やかに仕上がります。<br><br><br>[EiiS(エス)]<br>Even if it\'s small(小さくても...)の頭文字から。<br>「\"小さいから\"あきらめていた方に向けた、\"小さくても\"着たい服を自由に選べるブランド。」という想いを込めています。<br>また、EとSで「エス」と呼ぶことで、<br>Euphoria(幸福感)Small,Excellent(優れた)Small,Enthrall(魅了する)Smallなどとして、<br>ただS SIZEだけじゃないという意味も持たせます。<br><br>《高山直子》<br>155cm<br>大阪府出身。<br>アイラッシュ&アイブロウサロン「un CALiN(アンカラン)」代表。<br>女性の美のトータルプロデューサーとして雑誌やTVなど、さまざまなメディアで活躍中。<br>また、3歳になる娘と二匹の愛犬に囲まれたライフスタイルでも注目を集める。<br>料理好き、器好きの一面もあり、SNSのタグ「#なおコロ食堂」にもファンが多い。<br><br><a href=\"adastriaapp://items?dispNo=0000100002_002001564&orderBy=00\"><b><font size=\"2\" color=\"black\">EiiSアイテム一覧</a></font></b>はこちら<br><br>PC・ブラウザの方はこちら↓<br><a href=\"https://www.dot-st.com/globalwork/disp/itemlist/?mode=&sort=01&groupNm=0&p=1&refineFlg=true&dispNo=002001564&dispNoRadio=&search_color_cd=&search_size_cd=&search_class_attribute=&search_function_tag=&search_range_price_min=&search_range_price_max=&search_refine_range_min=&search_refine_range_max=&search_price=&goodsType=&search_campaign=&store_delv_yn=&gift_wrap_yn=&stock=&20230912EiiSALL\"><b><font size=\"2\" color=\"black\">EiiSアイテム一覧</a></font></b>', '5446.0 JPY', 332.21, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:21:47', '2026-04-02 04:18:37', 'adastria_289622', '', '69cd72d6a7ab618f2967cb57', '生活/休闲', '', '女', '青年（18-44岁）', '涤纶100%', 'https://www.dot-st.com/globalwork/disp/item/289622/?COLOR_CD=56', '上装', '卫衣', '套头衫', '', 'pullover', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/global_work/20260401/item_289622_main_56_1740015165_b.jpg', 0, 0, 8, 0.86779, 0, 1, 1, 0, 0, 3, NULL, '领子可拆卸设计，遮掩身形线条，显瘦版型', '领子可拆卸设计,遮掩身形线条,显瘦版型', '', '采用较挺的罗纹针织结构，不易紧贴身体曲线,配有可拆卸装饰领，造型变化性强,领口与袖口拼接精致花型蕾丝，提升华丽感,紧凑合身轮廓，适合与高腰或廓形下装搭配,主打小个子女性尺寸与版型设计', '花卉图案', '从商品名“リブニットプルオーバー”以及图片来看，这是套头款的针织上衣，没有开襟和拉链，属于典型针织套头衫，因此选择“pullover（套头衫/针织套头上衣）”。pullover 的定义是从头套穿、无前开襟结构的上衣类针织或毛衣，此款正好符合。', 0, 0, 0, 0, 'pullover', NULL, '', 0, NULL, 0, NULL, NULL, '56', 'ブラウン56', 0);
INSERT INTO `clothing_info` VALUES (19996691, '凉感纯棉印花T恤/636802', '冷感コットンプリントＴシャツ/636802', 0, 31749815, 'GLOBAL WORK', '', '', '采用具有接触冷感功能的100%纯棉面料，穿着舒适扎实。设计为配色丰富的学院风字母印花T恤，略微宽松的版型与身体有一定距离，即使在闷热季节也能保持舒适。非常适合作为春夏日常穿搭单品，也是值得入手多色的款式。无论搭配哪种下装都很百搭，若在下装颜色上呼应印花颜色，可营造更时髦的整体感。适用于运动会、户外、公园、露营及日常出行等场景。', '<font color=#ff69b4><b>ひんやり接触冷感で夏も快適な綿100％ロゴＴ</b></font><br>ーーー<br>・機能/素材<br>接触冷感<br><br>着心地が良く、しっかりした綿100%素材<br><br>・デザイン<br>カラバリ豊富な、カレッジロゴプリントTシャツ。<br>肌離れする丁度良いサイズ感で、じめっとした季節も快適に過ごせます。<br>春夏のデイリーウェアにぴったり。<br>リーズナブルな価格で、色違いで欲しくなるアイテムです。<br><br>・おすすめスタイリング<br>ボトムスを問わず、どんなアイテムとも合わせやすいです。<br>プリントカラーに合わせた色をボトムスに持ってくると、お洒落な雰囲気にきまります。<br><br>ロゴT　カラー　アソート　半袖T　運動会　体育祭　公園　アウトドア　キャンプ　お出かけ<br>ーーー', '1800.0 JPY', 109.80, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:21:49', '2026-04-02 04:18:27', 'adastria_636802', '', '69cd72d6a7ab618f2967cb56', '生活/休闲，露营', '', '通用', '青年（18-44岁）', '棉100%', 'https://www.dot-st.com/globalwork/disp/item/636802/?COLOR_CD=05', '上装', 'T恤', 'T恤', '', 't-shirt', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/global_work/20260401/item_636802_main_05_1773391704_b.jpg', 0, 0, 2, 0.97877, 0, 1, 1, 0, 0, 3, NULL, '接触冷感，透气，舒适，易于搭配，适合日常穿着', '舒适,易于搭配,适合日常穿着', '接触冷感整理', '棉100%材质，手感扎实且舒适,学院风英文字母Logo印花，颜色选择丰富,版型略微宽松，避免贴身闷热，适合春夏季穿着,价格亲民，适合多色入手', '字母', '从商品名称“冷感コットンプリントＴシャツ”和图片可以看出，这是短袖、圆领、单穿为主的上衣，属于基础款针织T恤，对应的子类是“t-shirt（T恤）”。', 1, 0, 0, 0, 't-shirt', NULL, '', 0, NULL, 0, NULL, NULL, '05', 'オフ05', 0);
