INSERT INTO `clothing_info` VALUES (19996690, '佩斯利印花短裤', 'ペイズリープリントショーツ', 0, 200333, 'niko and ...', '', '', '2025 夏季吸睛印花单品。\n\n【设计特点】\n・采用具有沙沙手感的面料，夏季也能保持与肌肤的适度离体感，穿着清爽舒适。\n・前片加入褶饰，呈现适度放松感的轮廓。\n・沉稳配色的佩斯利印花，为造型增添亮点。\n・腰部配有松紧和内抽绳，贴合腰部且便于调节。\n・可与同面料衬衫搭配成套穿着。\n\n【搭配建议】\n可与成熟感的薄透衬衫搭配，打造度假氛围的休闲造型。脚上可以选择凉鞋营造随性感，也可以搭配乐福鞋等营造更利落的感觉。\n\n【穿着感受（员工评语）】\n版型宽松，长度约至膝盖上方。面料轻盈、触感干爽，充满度假感的图案非常适合夏季造型，为简单的夏日穿搭增添个性。', '<font color=\"#336600\"><b>2025 Summer<br>目をひく柄ものアイテム</b></font><br><br><b>【POINT】</b>　 <br>◆シャリ感のある素材で夏でも肌離れが良く快適なはき心地。<br>◆タックを入れ、程よくリラックス感のあるシルエットになっています。<br>◆落ち着いたペイズリー柄のプリントでスタイリングのアクセントに◎<br>◆ウエストゴムと内紐が付いているので腰回りにしっかりフィット。<br>◆同生地を使用したシャツとセットアップも可能です。<br>▽こちらもチェック！▽　　<br>品名：ペイズリープリントシャツ<br>品番：494874<br><a href=\"adastriaapp://item?itemCode=494874\" target=\"_blank\"><font color=\"\"aqua\" size=2><b>＞＞アプリ版でこのアイテムをチェック</b></font></a><br><a href=\"https://www.dot-st.com/disp/itemlist/?q=494874&userinput=\" target=\"_blank\"><font color=\"\"black\" size=2><b>＞＞ブラウザ版でこのアイテムをチェック</b></font></a><br><br><b>【STYLING】</b><br>大人びたシアーシャツと合わせてリゾート気分なカジュアルコーデ。<br>足元はサンダルでラフに合わせるも良し、ローファーなどでカチッと締めるのも良し◎<br>▽合わせるならコレ！▽　　<br>品名：シアースキッパーシャツ<br>品番：492882<br><a href=\"adastriaapp://item?itemCode=492882\" target=\"_blank\"><font color=\"\"aqua\" size=2><b>＞＞アプリ版でこのアイテムをチェック</b></font></a><br><a href=\"https://www.dot-st.com/disp/itemlist/?q=492882&userinput=\" target=\"_blank\"><font color=\"\"black\" size=2><b>＞＞ブラウザ版でこのアイテムをチェック</b></font></a><br><br><b>【STAFF REVIEW】</b><br>身長：169ｃｍ / 体型：細身/ 着用サイズ：Mサイズ<br>サイズ感：ゆとりのあるシルエット。膝見えする丈感。<br>着心地：軽やかでドライな肌触り。<br>リゾート感のある柄が夏にぴったり◎<br>シンプルになりがちな夏コーデは柄もので個性を出していきましょう！<br><br>niko and ... mens 最新アイテムはここからCHECK<br><a href=\"adastriaapp://items?dispNo=0000100016_001002\" target=\"_blank\"><font color=\"\"aqua\" size=2><b>＞＞アプリ版はこちら</b></font></a><br><a href=\"https://www.dot-st.com/nikoand/disp/itemlist/?dispNo=001002\" target=\"_blank\"><font color=\"\"aqua\" size=2><b>＞＞ブラウザ版はこちら</b></font></a><br><br><br>ーーー<br>パンツ　ショーツ　ショートパンツ　柄　ペイズリー　プリント<br>ーーー', '5455.0 JPY', 332.75, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:22:35', '2026-04-02 04:18:26', 'adastria_494747', '', '69cd72d6a7ab618f2967cb47', '生活/休闲，差旅/商务', '', '男', '青年（18-44岁）', '涤纶100%', 'https://www.dot-st.com/nikoand/disp/item/494747/?COLOR_CD=88', '下装', '短裤', '短裤', '', 'shorts', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/niko_and/20260401/item_494747_main_88_1748510239_b.webp', 0, 0, 2, 0.88532, 0, 1, 0, 0, 0, 3, NULL, '透气，轻盈，舒适，凉爽触感', '轻盈,舒适,凉爽触感', '', '采用具有沙沙手感的夏季面料，穿着时与皮肤有一定离体感,整体为宽松休闲版型，膝上长度短裤设计,腰部配有松紧和内抽绳，便于调节贴合度,采用低调配色的佩斯利图案，适合作为穿搭造型亮点,可与同面料衬衫组成成套穿搭，营造度假风格', '佩斯利', '从商品名“ペイズリープリントショーツ”和描述中的“パンツ　ショーツ　ショートパンツ”可明确判断这是及膝长度的休闲短裤，因此在子类中选择“shorts（短裤）”最为贴切。该子类指代日常或休闲场景穿着的短裤，与商品版型和用途完全一致。', 0, 0, 0, 0, 'shorts', NULL, '', 0, NULL, 0, NULL, NULL, '88', 'ネイビー88', 0);
INSERT INTO `clothing_info` VALUES (19996689, '防晒连体三件套', 'ラッシュオールインワン3点セット', 0, 200333, 'niko and ...', '', '', '这款单品是一套在各种户外与水边场景都能时髦穿着的多功能连体装。面料具有耐氯特性，并具备遮蔽率95%以上的UV防护功能，质地轻盈且触感柔软。\n\n组合包括一件可水陆两用的连体裤，以及内搭楊柳材质的吊带上衣和三角短裤。连体裤可像防晒上衣一样，轻松罩穿在泳衣外，版型宽松不易勾勒身体线条，穿着放松舒适并具有一定体型修饰效果。配套泳装为带胸杯的吊带款式，肩带长度可调节，提升穿着便利性与稳定性。\n\n可与草编包、凉鞋搭配，打造度假风造型；叠加外搭则可作为日常连体服穿着，也是旅行时的一公里便服选择。亦可与同系列楊柳防晒开衫组合使用。', '<font color=\"492898\"><b>アクティブシーンでもオシャレに着られる万能オールインワン</b></font><br>		<br>■素材特性<br>耐塩素、遮蔽率95％以上のUVカット機能付きで、軽量で柔らかな肌触りも特徴です。<br>		<br>■デザイン<br>日常やアウトドア、プールやビーチでも着用できる水陸両用のオールインワンと、インナーに楊柳素材のキャミ＆ショーツがセットになったアイテム！<br>オールインワンはラッシュガードのような感覚で、水着の上からさらりと着られるサイズ感です。<br>セットの水着は、肩紐の長さ調節が可能なカップ付きのキャミソールなのも嬉しいポイント◎<br>体のラインを拾いにくいゆったりめのシルエットで、リラクシーな着心地と体系カバーを叶えてくれます。<br><br>■おすすめスタイリング	<br>カゴバックやサンダルと合わせれば、リゾート風の着こなしに！<br>羽織りをプラスすれば、タウンユースのオールインワンとしても活躍！旅先のワンマイルウェアにぴったりなアイテムです。<br>同シリーズの楊柳ラッシュカーディガンと組み合わせるのもおすすめ◎<br><br>ーーー		<br>水陸両用　ラッシュガード　オールインワン　セットアイテム　UV対策　UVカット　リゾート<br>ーーー', '8182.0 JPY', 499.10, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:22:36', '2026-04-02 04:18:26', 'adastria_498990', '', '69cd72d6a7ab618f2967cb46', '游泳，水上运动，生活/休闲，差旅/商务', '', '女', '青年（18-44岁）', '涤纶100%', 'https://www.dot-st.com/nikoand/disp/item/498990/?COLOR_CD=19', '孕妇衣', '孕妇衣', '孕妇背带裤', '', 'jumpsuit', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/niko_and/20260401/item_498990_main_19_1750384839_b.jpg', 0, 0, 1, 0.99280, 0, -2, 0, 0, 0, 3, NULL, '防晒，防紫外线，高弹力，遮蔽率高，轻量，柔软手感，体型修饰，水陆两用', '遮蔽率高,轻量,柔软手感,体型修饰,水陆两用', '耐氯处理,UVカット功能面料', '三件套组合设计（连体裤+吊带上衣+三角泳裤）,适合作为防晒外搭穿在泳衣外面,肩带长度可调节并带胸杯设计,廓形宽松，减少贴身感,可搭配同系列楊柳材质开衫使用', '纯色，纯色', '根据描述这是“水陸両用のオールインワン”且外层为连体式剪裁，从肩到裤连成一体，日常也可当连体服穿着，因此在给定列表中最适合归类为“jumpsuit（连体裤/连体衣）”。jumpsuit 的定义是上下装一体式的连体服装，本款防晒连体款正符合这一点。', 0, 0, 0, 0, 'jumpsuit', NULL, '', 0, NULL, 0, NULL, NULL, '19', 'ブラック(19)', 0);
INSERT INTO `clothing_info` VALUES (19996683, '【STRANGER THINGS】联名 多款式宽松短袖衬衫', '【STRANGER THINGS】コラボ アソートオーバーショートスリーブシャツ', 0, 200333, 'niko and ...', '', '', 'Netflix剧集《怪奇物语》与 niko and ... 联名推出的限定合作款短袖衬衫。\n\n■ 材料特点\n采用100%纯棉面料，质地结实耐穿，透气性和吸湿性优异，适合多个季节反复穿着。\n\n■ 设计\n从剧中形象汲取灵感，使用条纹图案打造宽松版型的短袖大廓形衬衫。不同配色搭配各异的刺绣与印花细节，呈现出活泼有趣的视觉效果。背部的“Stranger Things”刺绣是联名限定的低调亮点。\n\n■ 穿搭建议\n可以单穿作为造型主角，也适合与潮流感的轻薄透视或网眼长袖T恤叠穿，作为点亮基础下装的造型单品。', '<font color=\"#E92A2D\"><b>Netflixシリーズ「ストレンジャー・シングス 未知の世界」× niko and ...<br>ここでしか出会えない限定コラボレーションアイテムが登場！</b></font><br><br>■素材特性<br>コットン100%なので、しっかりとした丈夫な素材感が特徴です◎<br>通気性・吸水性に優れていて、シーズン通して沢山着用を楽しんでいただけます。<br><br>■デザイン<br>劇中のイメージからインスパイアされたストライプ柄を使用したBIGシャツ。<br>カラーによって異なる、刺繍やプリント等を施したポップでユニークなアイテムが完成しました！<br>バックに配されたStranger Thingsの刺繍は、コラボならではのさりげないポイントに◎<br><br>■おすすめスタイリング<br>メインでさらっと１枚の着こなしはもちろん、トレンドのシアーやメッシュのロンTとのレイヤードスタイリングも◎<br>ベーシックなボトムをリフレッシュしたいときのアクセントアイテムにおすすめの1着です！<br><br>【STRANGER THINGS(ストレンジャー・シングス 未知の世界)】その他コラボアイテムはこちら！<br><a href=\"adastriaapp://items?dispNo=0000100016_002100729&orderBy=00\" target=\"_blank\"><font color=\"#558ed5\"><b>＞＞and ST アプリの方はこちら</b></font></a><br><a href=\"https://www.dot-st.com/nikoand/disp/itemlist/?dispNo=002100729\" target=\"_blank\"><font color=\"#558ed5\"><b>＞＞ブラウザの方はこちら</b></font></a><br><br>【Netflixシリーズ「ストレンジャー・シングス 未知の世界」 】<br>1980年代の小さな町ホーキンスを舞台に、突然姿を消した少年ウィルの失踪事件と突如現れた謎の少女イレブンを巡り、想像を超える不可解な事件に巻き込まれながらも、少年たちが友人や家族たちを守るために事件解決に立ち向かうミステリー・アドベンチャー。<br>80年代の名作映画へのリスペクトが込められたドラマチックな展開と緊張感あふれるスリラー描写、そして心躍る子供たちの友情と冒険が組み合わさった本作は、2016年のシーズン１配信開始以来、全世界で大ヒット！世界中に社会現象とも言えるムーブメントを巻き起こしている。 現在シーズン1～4を独占配信中。<br><a href=\"https://www.netflix.com/jp/title/80057281\" target=\"_blank\"><font color=\"#558ed5\"><b>＞＞作品ページはこちら</b></font></a><br><br>ーーー<br>Stranger Things　ストレンジャー・シングス　未知の世界　コラボ　Netflix　シャツ<br>ーーー', '7273.0 JPY', 443.65, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:22:39', '2026-04-02 04:18:20', 'adastria_290573', '', '69cd72d6a7ab618f2967cb33', '生活/休闲', '', '通用', '青年（18-44岁）', '棉100%', 'https://www.dot-st.com/nikoand/disp/item/290573/?COLOR_CD=60', '上装', '衬衫', '休闲衬衫', '', 'casual shirt', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/niko_and/20260401/item_290573_main_60_1747129036_b.jpg', 0, 0, 8, 0.88212, 0, 1, 1, 0, 0, 3, NULL, '透气，吸湿排汗，耐用', '耐用', '', '与《怪奇物语》IP联名合作，背部有主题刺绣装饰,宽松版型的短袖大廓形衬衫，适合叠穿造型,条纹图案搭配局部刺绣与印花，视觉效果醒目,100%纯棉平纹机织面料，穿着舒适且有一定挺括感', '条纹，字母', '产品名称为“オーバーショートスリーブシャツ”，描述中多次出现“シャツ（衬衫）”“BIGシャツ”，且为短袖、可单穿或叠穿的日常上衣，并非正式场合正装衬衣，因此在给定列表中最接近的是“casual shirt（休闲衬衫）”。该类别指日常穿着、版型宽松、带图案或装饰的非正装衬衫，本商品完全符合。', 0, 0, 0, 0, 'casual shirt', NULL, '', 0, NULL, 0, NULL, NULL, '60', 'イエロー(60)', 0);
INSERT INTO `clothing_info` VALUES (19996684, '《防紫外线/抗菌防臭/防泼水处理》可收纳UV防护渔夫帽', '《紫外線防止/抗菌防臭/撥水加工》ポケッタブルUVケアハット', 0, 200333, 'niko and ...', '', '', '采用结实的裂纹纹理感尼龙面料制成的防晒帽，轻盈到几乎忘记佩戴，且不易起皱、透气性好，是日晒防护的理想单品。可折叠收纳于附带的小袋中，便于随身携带。可拆卸的下颌拉绳有助于在骑自行车或风大时调节贴合度并保持稳定。适合短途外出、露营、音乐节、体育观赛等各类户外活动。面料具备阻隔透过的紫外线功能，帮助保护肌肤；汗带部位经过抗菌防臭处理，抑制细菌滋生和异味产生；表面经过防泼水加工，更加耐用实用。', '<font color=\"#EE7948\"><b>紫外線防止・抗菌防臭・撥水加工<br>夏定番のUVケアハットがリニューアル</b></font><br><br>丈夫なリップストップ風ナイロン生地を使用したハット。<br>被っていることを忘れるほどの軽やかさで、シワになりにくく、蒸れにくい、日差し対策におすすめのアイテムです。<br>付属のポーチに折り畳んで収納できるポケッタブル仕様のため、持ち運びにも便利！<br>取り外し可能なドローコードは、自転車に乗るときや風が強い日もフィット感を調節できて安心です。<br>ちょっとしたお出かけから、キャンプ、フェス、スポーツ観戦などのアクティブなお出かけまで、幅広いシーンで活躍してくれます。<br><br>■UV CARE（紫外線防止）<br>この製品は生地を透過する紫外線を遮蔽する機能があり紫外線(UV)からお肌を保護します。<br><br>■DEODORANT（抗菌防臭）<br>汗帯に細菌の増殖を抑え、臭いの発生を抑制する加工をしています。<br><br>■WATER REPELLENT（撥水加工）<br>水をはじきやすい加工を施してあります。使用を繰り返すことで水をはじく効果が低下することがあります。<br>縫製部分から水が浸入することがあり、完全防水ではありません。<br><br>ーーー<br>帽子　ハット　バケハ　紫外線防止　UVケア　抗菌防臭　デオドラント　撥水加工　ポケッタブル　アウトドア　レジャー<br>ーーー', '3628.0 JPY', 221.31, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:22:39', '2026-04-02 04:18:21', 'adastria_661601', '', '69cd72d6a7ab618f2967cb39', '露营，徒步/登山，跑步，生活/休闲，网球，训练', '', '通用', '青年（18-44岁）', '锦纶100%', 'https://www.dot-st.com/nikoand/disp/item/661601/?COLOR_CD=01', '配饰', '帽子', NULL, '', 'sun hat', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/niko_and/20260401/item_661601_main_01_1774849530_b.jpg', 0, 0, 9, 0.97169, 0, 1, 1, 0, 0, 3, NULL, '防水，防晒，抗菌，防臭，轻量，防泼水，可折叠收纳，透气，耐用，便携，可调节佩戴稳固性', '防臭,轻量,防泼水,可折叠收纳,透气,耐用,便携,可调节佩戴稳固性', '紫外线防护加工,抗菌防臭整理,防泼水整理', '采用耐用的防裂纹感尼龙面料，适合户外环境,帽体轻盈且不易起皱，提升佩戴舒适度与携带便利性,汗带区域做抗菌防臭加工，针对汗液环境优化,配有可拆卸调节拉绳，增强风大或骑行时的稳定性,自带收纳袋，可折叠压缩为便携尺寸,适合从日常外出到露营、音乐节、观赛等多种户外场景', '其他', '该产品为户外功能型宽檐帽，主打紫外线防止、UVケア，并用于露营、户外、运动观赛等防晒场景，结构上是软质圆顶加大帽檐，符合“sun hat（日晒防护帽）”的定义。sun hat 主要指以遮阳、防晒为目的的宽檐帽类产品，本品与之高度吻合，因此归类为 sun hat。', 1, 0, 0, 0, 'sun hat', NULL, '', 0, NULL, 0, NULL, NULL, '01', 'MIX(01)', 0);
