INSERT INTO `clothing_info` VALUES (19996686, '《防紫外线/抗菌防臭/防泼水处理》可收纳UV防护渔夫帽', '《紫外線防止/抗菌防臭/撥水加工》ポケッタブルUVケアハット', 0, 200333, 'niko and ...', '', '', '采用结实的裂纹纹理感尼龙面料制成的防晒帽，轻盈到几乎忘记佩戴，且不易起皱、透气性好，是日晒防护的理想单品。可折叠收纳于附带的小袋中，便于随身携带。可拆卸的下颌拉绳有助于在骑自行车或风大时调节贴合度并保持稳定。适合短途外出、露营、音乐节、体育观赛等各类户外活动。面料具备阻隔透过的紫外线功能，帮助保护肌肤；汗带部位经过抗菌防臭处理，抑制细菌滋生和异味产生；表面经过防泼水加工，更加耐用实用。', '<font color=\"#EE7948\"><b>紫外線防止・抗菌防臭・撥水加工<br>夏定番のUVケアハットがリニューアル</b></font><br><br>丈夫なリップストップ風ナイロン生地を使用したハット。<br>被っていることを忘れるほどの軽やかさで、シワになりにくく、蒸れにくい、日差し対策におすすめのアイテムです。<br>付属のポーチに折り畳んで収納できるポケッタブル仕様のため、持ち運びにも便利！<br>取り外し可能なドローコードは、自転車に乗るときや風が強い日もフィット感を調節できて安心です。<br>ちょっとしたお出かけから、キャンプ、フェス、スポーツ観戦などのアクティブなお出かけまで、幅広いシーンで活躍してくれます。<br><br>■UV CARE（紫外線防止）<br>この製品は生地を透過する紫外線を遮蔽する機能があり紫外線(UV)からお肌を保護します。<br><br>■DEODORANT（抗菌防臭）<br>汗帯に細菌の増殖を抑え、臭いの発生を抑制する加工をしています。<br><br>■WATER REPELLENT（撥水加工）<br>水をはじきやすい加工を施してあります。使用を繰り返すことで水をはじく効果が低下することがあります。<br>縫製部分から水が浸入することがあり、完全防水ではありません。<br><br>ーーー<br>帽子　ハット　バケハ　紫外線防止　UVケア　抗菌防臭　デオドラント　撥水加工　ポケッタブル　アウトドア　レジャー<br>ーーー', '3628.0 JPY', 221.31, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:22:39', '2026-04-02 04:18:23', 'adastria_661601', '', '69cd72d6a7ab618f2967cb39', '露营，徒步/登山，跑步，生活/休闲，网球，训练', '', '通用', '青年（18-44岁）', '锦纶100%', 'https://www.dot-st.com/nikoand/disp/item/661601/?COLOR_CD=01', '配饰', '帽子', NULL, '', 'sun hat', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/niko_and/20260401/item_661601_main_19_1774849534_b.jpg', 0, 0, 9, 0.98127, 0, 1, 0, 0, 0, 3, NULL, '防水，防晒，抗菌，防臭，轻量，防泼水，可折叠收纳，透气，耐用，便携，可调节佩戴稳固性', '防臭,轻量,防泼水,可折叠收纳,透气,耐用,便携,可调节佩戴稳固性', '紫外线防护加工,抗菌防臭整理,防泼水整理', '采用耐用的防裂纹感尼龙面料，适合户外环境,帽体轻盈且不易起皱，提升佩戴舒适度与携带便利性,汗带区域做抗菌防臭加工，针对汗液环境优化,配有可拆卸调节拉绳，增强风大或骑行时的稳定性,自带收纳袋，可折叠压缩为便携尺寸,适合从日常外出到露营、音乐节、观赛等多种户外场景', '其他', '该产品为户外功能型宽檐帽，主打紫外线防止、UVケア，并用于露营、户外、运动观赛等防晒场景，结构上是软质圆顶加大帽檐，符合“sun hat（日晒防护帽）”的定义。sun hat 主要指以遮阳、防晒为目的的宽檐帽类产品，本品与之高度吻合，因此归类为 sun hat。', 1, 2, 0, 0, 'sun hat', NULL, '', 0, NULL, 0, NULL, NULL, '19', 'ブラック(19)', 0);
INSERT INTO `clothing_info` VALUES (19996687, '易打理清凉感抽绳长款衬衫上衣', 'ケアイージーコタットチュニックシャツ', 0, 200333, 'niko and ...', '', '', '这款长款衬衫采用兼具天然棉般舒适触感与聚酯纤维功能性的理想面料，手感干爽利落，不易产生褶皱，为免烫易打理材质。宽松廓形可以柔和地遮盖身体线条，通过袖口穿过的系带收紧后，袖部立刻形成富有动感的垂坠褶皱造型，蝴蝶结系带增添一丝俏皮感，成为恰到好处的造型亮点。与浅色牛仔裤搭配即可呈现清爽风格，是简单搭配时的理想单品。', '<font color=\"#1eb307\"><b>さらりとした清涼感が魅力！<br>季節を纏うオトナシャツ</b></font><br><br>■素材特性<br>天然のコットンのような着心地とポリエステルの機能性の良いところだけを合わせた理想の生地感。<br>さらっとした手触りでしわ感も抑え、アイロンいらずのイージーケア素材です◎<br><br>■デザイン<br>ワイドなシルエットでふんわりとボディラインをカバーしてくれるチュニックシャツ。<br>袖回りに通ったリボン紐を絞ることによって、動きのあるドレープデザインに早変わり！<br>リボンデザインでひとさじのチャーミングさをプラスし、ちょうどいいアクセントに◎<br><br>■おすすめスタイリング<br>淡いカラーのデニムパンツと合わせた爽やかスタイルが鉄板コーデ！<br>シンプルに決めたいときのワンツーアイテムにぴったり♪<br><br>ーーー<br>シャツ　チュニック　ドレープ　リボン　ギャザー　イージーケア<br>ーーー', '5000.0 JPY', 305.00, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:22:39', '2026-04-02 04:18:24', 'adastria_234884', '', '69cd72d6a7ab618f2967cb3d', '生活/休闲', '', '女', '青年（18-44岁）', '涤纶100%', 'https://www.dot-st.com/nikoand/disp/item/234884/?COLOR_CD=11', '上装', '卫衣', '罩衫', '', 'tunic', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/niko_and/20260401/item_234884_main_11_1748911595_b.webp', 0, 0, 2, 0.92046, 0, 1, 1, 0, 0, 3, NULL, '防皱，免烫易打理', '免烫易打理', '', '宽松廓形遮盖身形线条,袖部抽绳系带可营造垂坠褶皱效果,触感清爽、适合换季穿着,设计简约百搭，易于与牛仔裤搭配', '纯色，纯色', '从图片和描述看，这是一款长度盖过臀部、版型宽松的上衣，前门襟为全开扣的衬衫结构，但着重强调“チュニックシャツ（tunic shirt）”、宽松廓形和遮挡身形的特性，更接近可单穿的中长上衣而非标准短款衬衫，因此在提供的类别中选择最贴切的“tunic（束腰长上衣/中长上衣）”。tunic：指长度多覆盖臀部或大腿上部、版型相对宽松、可搭配裤装的中长上衣。', 0, 0, 0, 0, 'tunic', NULL, '', 0, NULL, 0, NULL, NULL, '11', 'オフ11', 0);
INSERT INTO `clothing_info` VALUES (19996688, 'FINE亚麻斜纹裤', 'FINEリネンツイルパンツ', 0, 200333, 'niko and ...', '', '', '采用通气性极佳的亚麻材质，即使在气温较高的日子也能保持轻松无负担的穿着感受和自然的肌理触感。穿得越久，面料风合越丰富，更有质感。\n\n可拆卸式背带设计，既可以作为简约长裤穿着，也可以加上背带增强造型感。裤脚配有系带，可根据喜好收紧，改变轮廓。收口时能在脚踝处形成自然蓬松的份量感，呈现休闲、宽松的印象。即便是背带设计，也能保持成熟不幼稚的时髦气质。\n\n推荐与清爽的衬衫或女式上衣搭配，营造适合暖季的干净利落造型。', '<font color=\"green\"><b>品のある生地感と快適さで<br>毎年人気のFINEリネン</b></font><br><br>■素材特性<br>通気性に優れているリネン素材を使用しており、気温の高い日でもストレスフリーな着心地とナチュラルな肌触りが叶います。<br>着用するほど風合いが増すので、どんどん愛着も湧いてくる1点です<br><br>■デザイン<br>サスペンダーは取り外し可能、裾も紐で絞れるのでシルエットを変えて着用が楽しめます◎<br>裾を絞るとさりげなくボリュームができるので、カジュアルでゆったりとした印象に！<br>サスペンダー付きでも子供っぽくならないオトナなデザインが魅力です◎<br><br>■おすすめスタイリング<br>涼しげなシャツやブラウスと合わせると、爽やかに仕上がるのでこれからのシーズンにもおすすめのコーディネートです♪<br><br>ーーー<br>パンツ　リネン　ナチュラル　サスペンダー<br>ーーー', '8637.0 JPY', 526.86, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:22:39', '2026-04-02 04:18:25', 'adastria_142547', '', '69cd72d6a7ab618f2967cb43', '生活/休闲', '', '女', '青年（18-44岁）', '亚麻100%', 'https://www.dot-st.com/nikoand/disp/item/142547/?COLOR_CD=19', '下装', '休闲裤', '女士裤装', '', 'pantsuit', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/niko_and/20260401/item_142547_main_19_1741311141_b.jpg', 0, 0, 2, 0.95240, 0, 1, 1, 0, 0, 3, NULL, '透气，凉爽舒适，可调节裤脚轮廓，可拆卸背带设计', '凉爽舒适,可调节裤脚轮廓,可拆卸背带设计', '', '采用100%亚麻材质，随穿着逐渐产生更柔和的天然风合,裤脚可通过抽绳收紧，形成休闲蓬松轮廓,配有可拆卸吊带，增强搭配变化与造型感,适合搭配清爽衬衫或女式上衣，营造夏季自然感造型', '纯色', '从图片和描述看，这是带可拆卸背带的长裤，下装为宽松直筒裤型、裤脚可抽绳收口，属于裤装类而非整体连体裤。提供的枚举中没有单独“pants”选项，最接近“パンツ（裤子）”的下装类别是“pantsuit”，故选择 sub_category 为 “pantsuit（裤装）”；该类可定义为：以长裤为主体的下装单品或裤装套系。', 0, 0, 0, 0, 'pantsuit', NULL, '', 0, NULL, 0, NULL, NULL, '19', 'ブラック19', 0);
INSERT INTO `clothing_info` VALUES (19996676, '[MODE NORM CORE] 2WAY天竺荷叶边套头上衣', '[MODE NORM CORE] 2WAY天竺フリルプルオーバー', 0, 200333, 'niko and ...', '', '', '背后造型同样精致的设计，丰富的荷叶边细节十分吸睛，可选择不同前后着装方式的2WAY上衣。\n\n■ 材质特性\n采用触感清爽的纯棉天竺针织面料，使用了有助于减轻汗渍显现的功能性加工素材。\n\n■ 设计\n前后皆可作为正面穿着的层次感上衣，只需套上就能打造华丽有存在感的造型。宽松的轮廓能在视觉上适度遮掩身形，领口为干净利落的圆领设计。\n\n■ 推荐搭配\n只需与简约牛仔单品搭配就能与众不同，是一件会想融入日常穿搭的实穿单品。', '<font color=\"mediumaquamarine\"><b>後ろ姿も抜かりない！たっぷりフリルが目を惹く<br>着丈も選べる　前後2WAYトップス</b></font><br><br>■素材特性<br>さらりとしたコットン天竺生地を使用。<br>これからの季節に嬉しい、汗ジミ軽減加工素材。<br>(使用・洗濯を繰り返すことで効果が薄れていきます。)<br><br>■デザイン<br>前後どちらを前にしても着ることができるレイヤードトップス。<br>着るだけで華やかなコーデになる着映えアイテムです。<br>ゆったりとしたシルエットでさりげなく体型カバーも<br>襟もとはすっきりとしたクルーネックなのも◎<br><br>■おすすめスタイリング<br>シンプルにデニムと合わせるだけでも周りと差がつきます。<br>毎日のコーデに取り入れたくなる1枚です。<br><br><font color=\"mediumaquamarine\"><b>【MODE NORM CORE】2025夏アイテム一覧をCHECK！</b></font><br><a href=\"adastriaapp://items?dispNo=0000100016_002001582&orderBy=00\"><b>>>アプリ版</b></font></a><br><a href=\"https://www.dot-st.com/nikoand/disp/itemlist/?dispNo=002001582\" target=\"_blank\"><b>>>ブラウザ版</b></font></a><br><br>ーーー<br>MODENORMCORE　モードノーム　フリル　カットソー　半袖　Tシャツ<br>ーーー', '4091.0 JPY', 249.55, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:22:41', '2026-04-02 04:18:15', 'adastria_323564', '', '69cd72d5a7ab618f2967cb1a', '生活/休闲', '', '女', '青年（18-44岁）', '棉100%', 'https://www.dot-st.com/nikoand/disp/item/323564/?COLOR_CD=10', '上装', '卫衣', '套头衫', '', 'pullover', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/niko_and/20260401/item_323564_main_10_1747123104_b.jpg', 0, 0, 2, 0.80619, 0, 1, 1, 0, 0, 3, NULL, '吸湿排汗，遮盖身材线条，双面可穿/前后2WAY设计，提升穿搭造型感', '遮盖身材线条,双面可穿/前后2WAY设计,提升穿搭造型感', '汗渍减轻加工', '采用清爽的全棉天竺针织面料,前后皆可作为正面穿着的设计增加搭配灵活性,宽松轮廓带来舒适穿着感并有修饰身形效果,领口为干净利落的圆领设计,大量荷叶边设计使整体更华丽吸睛', '纯色', '商品名称为「2WAY天竺フリルプルオーバー」，且描述为レイヤードトップス、カットソー、Tシャツ，结合图片可见为套头式针织上衣，无开襟与门襟，版型宽松，属于典型的套头上衣范畴。因此在给定列表中选择「pullover」。Pullover 指的是从头套穿、无前开襟的上衣或针织衫，与本款前后2WAY、套头穿着的短袖上衣最为匹配。', 0, 0, 0, 0, 'pullover', NULL, '', 0, NULL, 0, NULL, NULL, '10', 'ホワイト(10)', 0);
INSERT INTO `clothing_info` VALUES (19996677, '2WAY荷叶边法式T恤', '2WAYフリルフレンチTシャツ', 0, 200333, 'niko and ...', '', '', '这款T恤采用不过薄也不过厚的100%纯棉面料，手感适中，兼顾舒适与实穿性。胸前点缀女性化的荷叶边褶饰，配合略显紧凑的剪裁，让整体造型既休闲又带有精致感。低调优雅的法式袖设计，在修饰肩部线条的同时增添轻松感。前后均可穿着的2WAY设计，使单品的搭配可能性更高，无论是日常休闲还是小出行都十分适合。', '<font color=\"#1100ff\"><b>甘すぎないがちょうどいい<br>2wayで着こなすオトナのフレンチTシャツ</b></font><br>		<br>■素材特性<br>薄すぎず暑すぎない、ちょうど良い肉感の綿100％素材です。<br>		<br>■デザイン<br>胸元にあしらわれたフェミニンなフリルと、コンパクトなシルエットが程よくカジュアルに着こなせるフレンチTシャツ。<br>控えめで上品なフレンチスリーブは、肩回りを華奢見せしつつも、さりげなく抜け感をプラス◎<br>前後2wayで着用可能なデザインは、一枚でスタイリングのバリエーションが広がる万能トップスです。<br><br>■おすすめスタイリング	<br>シンプルフェイスな日にはカラーパンツでポイントをプラス！足元もスニーカーやスポーツサンダル合わせでカジュアルに！<br>フリルを主役にヒールやフレアスカートでまとめたお出かけスタイルもおすすめです◎<br>		<br>ーーー		<br>2WAY　フリルトップス　フレンチスリーブ<br>ーーー', '3637.0 JPY', 221.86, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:22:41', '2026-04-02 04:18:15', 'adastria_571926', '', '69cd72d6a7ab618f2967cb24', '生活/休闲', '', '女', '青年（18-44岁）', '棉100%', 'https://www.dot-st.com/nikoand/disp/item/571926/?COLOR_CD=12', '上装', 'T恤', 'T恤', '', 't-shirt', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/niko_and/20260401/item_571926_main_12_1750036730_b.jpg', 0, 0, 2, 0.83093, 0, 1, 1, 0, 0, 3, NULL, '透气，舒适，亲肤', '舒适,亲肤', '', '前后2WAY穿法设计,胸前装饰有多层荷叶边褶饰,法式袖型，优化肩部线条,版型适中，适合日常休闲与通勤搭配,纯棉面料，厚薄适中，适合换季时节穿着', '纯色', '从商品名称“2WAYフリルフレンチTシャツ”和图片来看，是短袖/法式袖、圆领、针织棉质上衣，整体版型和使用场景都符合日常T恤的特征。虽然有装饰荷叶边和前后2WAY设计，但本质仍是基础针织上衣，因此在给定列表中选择“t-shirt”最合适。t-shirt 指以针织面料为主、套头式、休闲属性强的上身短袖或中袖上衣。', 1, 0, 0, 0, 't-shirt', NULL, '', 0, NULL, 0, NULL, NULL, '12', 'ライトグレー(12)', 0);
