INSERT INTO `clothing_info` VALUES (19996679, '2WAY荷叶边法式T恤', '2WAYフリルフレンチTシャツ', 0, 200333, 'niko and ...', '', '', '这款T恤采用不过薄也不过厚的100%纯棉面料，手感适中，兼顾舒适与实穿性。胸前点缀女性化的荷叶边褶饰，配合略显紧凑的剪裁，让整体造型既休闲又带有精致感。低调优雅的法式袖设计，在修饰肩部线条的同时增添轻松感。前后均可穿着的2WAY设计，使单品的搭配可能性更高，无论是日常休闲还是小出行都十分适合。', '<font color=\"#1100ff\"><b>甘すぎないがちょうどいい<br>2wayで着こなすオトナのフレンチTシャツ</b></font><br>		<br>■素材特性<br>薄すぎず暑すぎない、ちょうど良い肉感の綿100％素材です。<br>		<br>■デザイン<br>胸元にあしらわれたフェミニンなフリルと、コンパクトなシルエットが程よくカジュアルに着こなせるフレンチTシャツ。<br>控えめで上品なフレンチスリーブは、肩回りを華奢見せしつつも、さりげなく抜け感をプラス◎<br>前後2wayで着用可能なデザインは、一枚でスタイリングのバリエーションが広がる万能トップスです。<br><br>■おすすめスタイリング	<br>シンプルフェイスな日にはカラーパンツでポイントをプラス！足元もスニーカーやスポーツサンダル合わせでカジュアルに！<br>フリルを主役にヒールやフレアスカートでまとめたお出かけスタイルもおすすめです◎<br>		<br>ーーー		<br>2WAY　フリルトップス　フレンチスリーブ<br>ーーー', '3637.0 JPY', 221.86, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:22:41', '2026-04-02 04:18:17', 'adastria_571926', '', '69cd72d6a7ab618f2967cb24', '生活/休闲', '', '女', '青年（18-44岁）', '棉100%', 'https://www.dot-st.com/nikoand/disp/item/571926/?COLOR_CD=12', '上装', 'T恤', 'T恤', '', 't-shirt', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/niko_and/20260401/item_571926_main_88_1752575424_b.jpg', 0, 0, 2, 0.97772, 0, 1, 1, 0, 0, 3, NULL, '透气，舒适，亲肤', '舒适,亲肤', '', '前后2WAY穿法设计,胸前装饰有多层荷叶边褶饰,法式袖型，优化肩部线条,版型适中，适合日常休闲与通勤搭配,纯棉面料，厚薄适中，适合换季时节穿着', '纯色', '从商品名称“2WAYフリルフレンチTシャツ”和图片来看，是短袖/法式袖、圆领、针织棉质上衣，整体版型和使用场景都符合日常T恤的特征。虽然有装饰荷叶边和前后2WAY设计，但本质仍是基础针织上衣，因此在给定列表中选择“t-shirt”最合适。t-shirt 指以针织面料为主、套头式、休闲属性强的上身短袖或中袖上衣。', 1, 2, 0, 0, 't-shirt', NULL, '', 0, NULL, 0, NULL, NULL, '88', 'ネイビーBD(88)', 0);
INSERT INTO `clothing_info` VALUES (19996680, '3D立体花卉荷叶短袖衬衫上衣', '3Dフラワーフリルフレンチブラウス', 0, 200333, 'niko and ...', '', '', '点缀立体花卉刺绣的女性化衬衫上衣。\n\n■ 材质特性\n采用清爽凉感的100%纯棉面料，吸湿性与速干性佳，在易出汗的季节也能保持舒适。\n\n■ 设计\n富有立体感的花朵刺绣与低调的背部荷叶边增添华丽感，一件就能完成造型。略长衣长可遮盖腰部，胸前切换设计上移视线，具有修饰身形的效果。通气性良好，既可作为上衣单穿，也可解开纽扣当作轻薄外搭，穿着清爽。\n\n■ 推荐搭配\n适合与夏季感的功能性长裤或阔腿裤搭配，营造宽松休闲造型，也易于与直筒裤等偏利落单品组合，穿搭实用度高。', '<font color=\"#ed39b7\"><b>フラワー刺繍をちりばめたフェミニンブラウス</b></font><br>		<br>■素材特性<br>さらっと涼しいコットン100％素材。<br>吸湿性と速乾性が高く汗ばむ季節でも快適です。<br>		<br>■デザイン<br>立体感のあるフラワー刺繍とさり気ないバックのフリルが華やかさを演出し、1枚でサマになるブラウス！<br>腰回りがカバーできる長めの丈感と、胸元からの切り替えデザインで目線を上げてスタイルアップ効果も◎<br>通気性が良いのでトップスとしてはもちろん、ボタンを開けて羽織にしても涼しく着用いただけます。<br>		<br>■おすすめスタイリング	<br>夏っぽいDRYパンツや、ワイドパンツと合わせたゆったりカジュアルコーデが◎<br>ストレートパンツなどのキレイめアイテムとも合わせやすい着回し力抜群な1枚です。<br>		<br>ーーー		<br>フラワー　フリル　ブラウス　刺繍<br>ーーー', '5455.0 JPY', 332.75, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:22:41', '2026-04-02 04:18:18', 'adastria_571776', '', '69cd72d6a7ab618f2967cb29', '生活/休闲', '', '女', '青年（18-44岁）', '棉100%', 'https://www.dot-st.com/nikoand/disp/item/571776/?COLOR_CD=60', '上装', '衬衫', '女式衬衫', '', 'blouse', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/niko_and/20260401/item_571776_main_60_1749091112_b.jpg', 0, 0, 2, 0.98857, 0, 1, 1, 0, 0, 3, NULL, '透气，吸湿排汗，凉爽触感，显瘦修饰身形', '凉爽触感,显瘦修饰身形', '', '采用100%棉面料，穿着轻盈凉爽,上身布满立体花朵刺绣，装饰效果强,背部加入细致荷叶边设计，增强女性化风格,前开全排扣设计，可作上衣也可当开衫外搭,衣长偏长，可遮挡腰臀部，修饰身材比例', '花卉图案', '从商品名“3Dフラワーフリルフレンチブラウス”和描述中的“ブラウス”可确认是女式上装衬衫类单品，带前排扣、短袖、上身较宽松，属于典型的“blouse（女式衬衫/上衣）”。在给定子类列表中，“blouse”正好对应这类带装饰刺绣、适合日常通勤与休闲穿着的女性上衣。\n\nblouse：指具有一定结构和设计细节（如纽扣、褶皱、装饰刺绣等）的女性上衣，多用于日常或稍正式场合穿着。', 0, 0, 0, 0, 'blouse', NULL, '', 0, NULL, 0, NULL, NULL, '60', 'イエロー(60)', 0);
INSERT INTO `clothing_info` VALUES (19996681, '清凉触感圆摆T恤', 'ひんやり機能付きラウンドTシャツ', 0, 200333, 'niko and ...', '', '', '简约设计，搭配自由度高。\n\n■素材特性\n采用清爽顺滑手感的接触冷感面料，皮肤接触瞬间带来清凉触感，穿着清爽凉快。\n\n■设计\n百搭基础设计的法式袖T恤是亮点。圆弧下摆能够修饰、遮盖腰部和臀部区域，带来利落印象。既可单穿，也适合作为与束胸上衣或马甲叠穿的内搭上衣。\n\n■推荐搭配\n与具有图案或蕾丝等存在感下装的搭配效果极佳，通过对比变化打造更有层次感的成熟休闲风格。\n\n——\n法式袖 T恤 简约 圆弧下摆 接触冷感 清凉功能\n——', '<font color=\"#10deaa\"><b>シンプルデザインはアレンジ自在</b></font><br><br>■素材特性<br>さらっとした肌触りの良い接触冷感生地を使用。<br>肌に触れた瞬間にひんやりとした感覚を得られ、爽やかに涼しく着用できます。<br><br>■デザイン<br>着回し力高めなベーシックなデザインが魅力のフレンチTシャツ。<br>腰やヒップ回りをカバーするラウンドヘムがスッキリとした印象に！<br>メインでももちろん、ビスチェやベストに合わせるレイヤードトップスとしても優秀な1点です◎<br><br>■おすすめスタイリング<br>柄やレース生地などの存在感のあるボトムが相性抜群◎<br>メリハリ感をつけてワンランク上の大人カジュアルスタイルが完成します！<br><br>ーーー<br>フレンチスリーブ　Tシャツ　シンプル　ラウンドヘム　接触冷感　ひんやり機能<br>ーーー', '3182.0 JPY', 194.10, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:22:41', '2026-04-02 04:18:19', 'adastria_578210', '', '69cd72d6a7ab618f2967cb2c', '生活/休闲', '', '女', '青年（18-44岁）', '棉82%,锦纶18%', 'https://www.dot-st.com/nikoand/disp/item/578210/?COLOR_CD=11', '上装', 'T恤', 'T恤', '', 't-shirt', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/niko_and/20260401/item_578210_main_11_1752487138_b.jpg', 0, 0, 2, 0.98881, 0, 1, 1, 0, 0, 3, NULL, '接触冷感，凉感功能，亲肤舒适', '凉感功能,亲肤舒适', '接触冷感纱线或整理工艺', '法式袖设计，修饰肩部线条,圆弧下摆可遮挡腰部和臀部线条,版型简约，易于与马甲、束胸上衣等单品叠穿,建议与具有图案或蕾丝质感的下装搭配，提升造型层次感', '纯色，纯色', '根据商品名“ラウンドTシャツ”和描述中的“フレンチTシャツ”，可以确定这是短袖上衣，属于基础圆领T恤版型，且无开襟或拉链，不是衬衫、针织衫或外套，因此选择子类别“t-shirt（T恤）”。该类别定义为：以针织面料为主、套头式、上身穿着的短袖或中袖休闲上衣。', 1, 0, 0, 0, 't-shirt', NULL, '', 0, NULL, 0, NULL, NULL, '11', 'オフ(11)', 0);
