INSERT INTO `clothing_info` VALUES (19996670, '【预售】可成套搭配【LFM(U)】尼龙抽绳下摆短袖上衣', '【先行予約】SETUP可能【LFM(U)】ナイロンドローコードＳＳ／Ｐ', 0, 31749818, 'LOWRYS FARM', '', '', '下摆配有抽绳设计，可根据喜好收紧，改变轮廓造型。尼龙材质带来休闲感，适合日常穿搭，也推荐用于户外等场景。可与同系列下装搭配成套造型。', 'ーーー<br>■デザイン<br>裾にドローコードが付いているので、絞って形を変えて着ることもできます。<br>ナイロン素材なので、カジュアルな印象になります。<br>デイリー使いはもちろん、野外などでもおすすめ。<br>ＳＥＴＵＰでの着用も可能です。<br><br>ＳＥＴＵＰできるボトムはこちら<br><a href=\'https://www.dot-st.com/lowrysfarm/disp/item/670621/\'>【LFM(U)】ナイロンイージーショーツ／Ｐ</a><br>ーーー', '5000.0 JPY', 305.00, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:22:42', '2026-04-02 04:18:10', 'adastria_670623', '', '69cd72d5a7ab618f2967cb18', '生活/休闲，露营', '', '通用', '青年（18-44岁）', '锦纶100%', 'https://www.dot-st.com/lowrysfarm/disp/item/670623/?COLOR_CD=18', '上装', 'T恤', 'T恤', '', 't-shirt', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/lowrys_farm/20260401/item_670623_main_18_1774947420_b.jpg', 0, 0, 1, 0.99908, 0, -2, 0, 0, 0, 3, NULL, '透气，轻量，宽松版型便于活动，下摆可通过抽绳调节造型', '轻量,宽松版型便于活动,下摆可通过抽绳调节造型', '', '采用尼龙材质，呈现休闲户外风格,下摆配有抽绳设计，可改变衣身轮廓,可与同系列尼龙短裤成套搭配,适合日常穿着及户外场景', '纯色', '从图片和描述看，这是短袖套头上衣，版型类似宽松T恤，圆领、半袖、无开襟纽扣，也非衬衫结构；材质为尼龙，带下摆抽绳，仍属于休闲短袖上衣范畴。在提供的子类中，与“T-shirt（T恤）”最接近，适合作为宽松休闲机能风T恤来归类。', 1, 0, 0, 0, 't-shirt', NULL, '', 0, NULL, 0, NULL, NULL, '18', 'チャコールグレー18', 0);
INSERT INTO `clothing_info` VALUES (19996671, '【预售】可成套搭配【LFM(U)】尼龙抽绳下摆短袖上衣', '【先行予約】SETUP可能【LFM(U)】ナイロンドローコードＳＳ／Ｐ', 0, 31749818, 'LOWRYS FARM', '', '', '下摆配有抽绳设计，可根据喜好收紧，改变轮廓造型。尼龙材质带来休闲感，适合日常穿搭，也推荐用于户外等场景。可与同系列下装搭配成套造型。', 'ーーー<br>■デザイン<br>裾にドローコードが付いているので、絞って形を変えて着ることもできます。<br>ナイロン素材なので、カジュアルな印象になります。<br>デイリー使いはもちろん、野外などでもおすすめ。<br>ＳＥＴＵＰでの着用も可能です。<br><br>ＳＥＴＵＰできるボトムはこちら<br><a href=\'https://www.dot-st.com/lowrysfarm/disp/item/670621/\'>【LFM(U)】ナイロンイージーショーツ／Ｐ</a><br>ーーー', '5000.0 JPY', 305.00, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:22:42', '2026-04-02 04:18:10', 'adastria_670623', '', '69cd72d5a7ab618f2967cb18', '生活/休闲，露营', '', '通用', '青年（18-44岁）', '锦纶100%', 'https://www.dot-st.com/lowrysfarm/disp/item/670623/?COLOR_CD=18', '上装', 'T恤', 'T恤', '', 't-shirt', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/lowrys_farm/20260401/item_670623_main_09_1774947423_b.jpg', 0, 0, 1, 0.99613, 0, -2, 0, 0, 0, 3, NULL, '透气，轻量，宽松版型便于活动，下摆可通过抽绳调节造型', '轻量,宽松版型便于活动,下摆可通过抽绳调节造型', '', '采用尼龙材质，呈现休闲户外风格,下摆配有抽绳设计，可改变衣身轮廓,可与同系列尼龙短裤成套搭配,适合日常穿着及户外场景', '纯色', '从图片和描述看，这是短袖套头上衣，版型类似宽松T恤，圆领、半袖、无开襟纽扣，也非衬衫结构；材质为尼龙，带下摆抽绳，仍属于休闲短袖上衣范畴。在提供的子类中，与“T-shirt（T恤）”最接近，适合作为宽松休闲机能风T恤来归类。', 1, 1, 0, 0, 't-shirt', NULL, '', 0, NULL, 0, NULL, NULL, '09', 'ブラック09', 0);
INSERT INTO `clothing_info` VALUES (19996672, '【LFM(U)】BAICYCLON 流苏单肩包 L', '【LFM(U)】BAICYCLON／ FRINGE　ショルダー／Ｌ', 0, 31749818, 'LOWRYS FARM', '', '', '■设计\n・人气织带流苏系列中的全新款单肩包\n・采用高品质尼龙斜纹面料，呈现精致高级的外观\n・包内设有多个口袋，方便分类收纳各类物品\n・表层面料为经表面防泼水处理的尼龙斜纹\n・里料（210D 尼龙）背面采用 AIR TIGHTNESS 气密加工，在背面覆以硅树脂涂层以提升气密性，并阻挡水分从面料内部渗入\n\nBAICYCLON by bagjack 是源自柏林的手工包袋品牌 bagjack 的副线。\n在延续 bagjack 功能性与品牌 DNA 的基础上，通过限定面料与配色，实现成本控制，提供兼具耐久性、防水性、机能性与扩展性的实用包袋。\n通过统一的模块化设计，可与 bagjack 的所有配件和装置互相兼容使用。', 'ーーー<br>■デザイン<br>・人気のテープフリンジシリーズから新型ショルダーバッグ<br>・上質なナイロンツイルを使用した上品な仕上がり<br>・本体の中には多数のポケットがあり、様々な物を収納できます。<br>・表生地は表面に撥水加工されたNYLON TWILL<br>・裏生地(210D NYLON)の裏面には AIR TIGHTNESS 加工<br>気密性能を上げる為にシリコン樹脂を裏面にコーティング<br>生地から水の侵入もガードします。<br><br>ーーー<br>BAICYCLON by bagjackは、ベルリン発のハンドメイドバッグブランドbagjackのセカンドライン。<br>bagjackを「カスタムメイド」とするなら、BAICYCLONは「レディメイド（既製品）」という位置付けになります。<br>bagjackの機能性と DNA は保持しながらも、素材やカラーのバリエーションを制限することにより、コストカットを実現。<br>耐久性、防水性、機能性、拡張性をを追求したbagjackのデザイン哲学を受け継ぐ、手頃な価格のバッグを提供しています。<br>共通のモジュラー設計により、bagjackのすべてのアクセサリーやガジェットとの互換性を備えています。', '12000.0 JPY', 732.00, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:22:42', '2026-04-02 04:18:11', 'adastria_585539', '', '69cd72d5a7ab618f2967cb15', '生活/休闲', '', '通用', '青年（18-44岁）', '锦纶100%', 'https://www.dot-st.com/lowrysfarm/disp/item/585539/?COLOR_CD=09', '其他服饰/物品', '其他', '配件', '', 'accessories', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/lowrys_farm/20260401/item_585539_main_09_1752218470_b.jpg', 0, 0, 9, 0.98861, 0, 1, 0, 0, 0, 3, NULL, '防水，防污/防油，高耐久性，可扩展性设计，多口袋收纳功能，模块化设计兼容配件，提升气密性能', '高耐久性,可扩展性设计,多口袋收纳功能,模块化设计兼容配件,提升气密性能', '面料表层撥水加工,里料背面AIR TIGHTNESS气密涂层,硅树脂涂层', '使用高品质尼龙斜纹面料，整体质感较为高级,包体前幅有带状流苏装饰，造型感强,肩带为编织结构，增强视觉效果与舒适度,内部设置多个收纳口袋，便于分类整理物品,品牌延续bagjack的功能与DNA但通过统一物料与配色控制成本', '纯色', '该产品为单肩包，属于配饰类中的“accessories（配件/配饰）”而非服装或家纺。商品名称为“ショルダーバッグ”，图片中也清晰可见为一款带编织肩带与流苏装饰的包袋，并非穿着类服装、床品、窗帘、地毯或桌布。因此选择子类为 accessories。其最合适的定义是：用于搭配与收纳的小件物品，如包袋、腰带等服装配饰。', 0, 0, 0, 0, 'accessories', NULL, '', 0, NULL, 0, NULL, NULL, '09', 'ブラック09', 0);
INSERT INTO `clothing_info` VALUES (19996673, '莫尔条纹开领短袖衬衫', 'モールストライプシャツ', 0, 200333, 'niko and ...', '', '', '采用由4种不同番手纱线捻合而成的特殊面料的开领半袖衬衫。渐变条纹中混入莫尔纱条纹，呈现独特氛围。质地轻盈通透，手感清爽，适合炎热季节穿着。标准衣长，易于与各种下装搭配。可与夏季穿着舒适的易穿裤或短裤组合，打造松弛感休闲造型，既可单穿也可搭配T恤或背心作为外搭。面料触感干爽轻盈，穿着凉爽，沉稳色调上身即有成熟感表现，既能搭配深色下装，也能与米色或蓝色牛仔等浅色单品协调搭配。', '<font color=\"green\"><b>2025 Summer<br>1枚でコーデが決まるトレンドアイテム</b></font><br><br><b>【POINT】</b>　 <br>◆4種類の異なった番手の糸を撚った特殊な生地を使用したオープンカラー半袖シャツ。<br>◆グラデーションストライプにモール糸のストライプが混じっていて、独特の雰囲気が特徴です。<br>◆エアリーで清涼感のある風合いでこれからの季節に活躍間違いなし◎<br>◆スタンダードな着丈で幅広いボトムスと合わせていただけます。<br><br><b>【STYLING】</b><br>夏でも快適な履き心地のイージーパンツやハーフパンツと合わせて抜け感のあるカジュアルスタイル！<br>一枚着はもちろん、Tシャツやタンクトップなどの羽織としても◎<br>▽合わせるならコレ！▽　　<br>品名：ワイド5ポケットデニムショートパンツ<br>品番：323346<br><a href=\"adastriaapp://item?itemCode=323346\" target=\"_blank\"><font color=\"\"aqua\" size=2><b>＞＞アプリ版でこのアイテムをチェック</b></font></a><br><a href=\"https://www.dot-st.com/disp/itemlist/?q=323346&userinput=\" target=\"_blank\"><font color=\"\"black\" size=2><b>＞＞ブラウザ版でこのアイテムをチェック</b></font></a>　<br>品名：USAコットンショートスリーブTシャツ<br>品番：316573<br><a href=\"adastriaapp://item?itemCode=316573\" target=\"_blank\"><font color=\"\"aqua\" size=2><b>＞＞アプリ版でこのアイテムをチェック</b></font></a><br><a href=\"https://www.dot-st.com/disp/itemlist/?q=316573&userinput=\" target=\"_blank\"><font color=\"\"black\" size=2><b>＞＞ブラウザ版でこのアイテムをチェック</b></font></a><br><br><b>【STAFF REVIEW】</b><br>身長：170ｃｍ / 体型：細身/ 着用サイズ：Mサイズ<br>サイズ感：肘が隠れる程度の丈感。ゆったりサイズ。<br>着心地：さらっとした肌触り。軽やかで涼しい！<br>落ち着いた色味で着るだけで大人見え。<br>ボトムスも暗いトーンで合わせるのはもちろん、ベージュやブルーデニムなど明るいものを持ってきてもバランス良くまとまります！<br><br>niko and ... mens 最新アイテムはここからCHECK<br><a href=\"adastriaapp://items?dispNo=0000100016_001002\" target=\"_blank\"><font color=\"\"aqua\" size=2><b>＞＞アプリ版はこちら</b></font></a><br><a href=\"https://www.dot-st.com/nikoand/disp/itemlist/?dispNo=001002\" target=\"_blank\"><font color=\"\"aqua\" size=2><b>＞＞ブラウザ版はこちら</b></font></a><br><br><br>ーーー<br>シャツ　ストライプ　柄<br>ーーー', '6000.0 JPY', 366.00, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:22:42', '2026-04-02 04:18:12', 'adastria_498896', '', '69cd72d5a7ab618f2967cb17', '生活/休闲', '', '男', '青年（18-44岁）', '涤纶43%,粘胶17%,锦纶15%', 'https://www.dot-st.com/nikoand/disp/item/498896/?COLOR_CD=70', '上装', '衬衫', '休闲衬衫', '', 'casual shirt', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/niko_and/20260401/item_498896_main_70_1747823209_b.jpg', 0, 0, 1, 0.99974, 0, -2, 0, 0, 0, 3, NULL, '透气，清凉感，轻盈垂坠感', '清凉感,轻盈垂坠感', '', '使用4种不同番手纱线捻合的特殊面料,加入莫尔纱条纹形成立体肌理效果,渐变色条纹配色营造成熟感,版型宽松、肘下五分袖、标准衣长,可单穿也可作为外搭叠穿', '条纹', '商品为“オープンカラー半袖シャツ”，从图片看为男装开领短袖衬衫，上装、前排扣、翻领、休闲宽松版型，明显属于日常休闲风格衬衫，因此在提供的列表中选择最贴切的“casual shirt（休闲衬衫）”。', 1, 0, 0, 0, 'casual shirt', NULL, '', 0, NULL, 0, NULL, NULL, '70', 'グリーン70', 0);
INSERT INTO `clothing_info` VALUES (19996674, '莫尔条纹开领短袖衬衫', 'モールストライプシャツ', 0, 200333, 'niko and ...', '', '', '采用由4种不同番手纱线捻合而成的特殊面料的开领半袖衬衫。渐变条纹中混入莫尔纱条纹，呈现独特氛围。质地轻盈通透，手感清爽，适合炎热季节穿着。标准衣长，易于与各种下装搭配。可与夏季穿着舒适的易穿裤或短裤组合，打造松弛感休闲造型，既可单穿也可搭配T恤或背心作为外搭。面料触感干爽轻盈，穿着凉爽，沉稳色调上身即有成熟感表现，既能搭配深色下装，也能与米色或蓝色牛仔等浅色单品协调搭配。', '<font color=\"green\"><b>2025 Summer<br>1枚でコーデが決まるトレンドアイテム</b></font><br><br><b>【POINT】</b>　 <br>◆4種類の異なった番手の糸を撚った特殊な生地を使用したオープンカラー半袖シャツ。<br>◆グラデーションストライプにモール糸のストライプが混じっていて、独特の雰囲気が特徴です。<br>◆エアリーで清涼感のある風合いでこれからの季節に活躍間違いなし◎<br>◆スタンダードな着丈で幅広いボトムスと合わせていただけます。<br><br><b>【STYLING】</b><br>夏でも快適な履き心地のイージーパンツやハーフパンツと合わせて抜け感のあるカジュアルスタイル！<br>一枚着はもちろん、Tシャツやタンクトップなどの羽織としても◎<br>▽合わせるならコレ！▽　　<br>品名：ワイド5ポケットデニムショートパンツ<br>品番：323346<br><a href=\"adastriaapp://item?itemCode=323346\" target=\"_blank\"><font color=\"\"aqua\" size=2><b>＞＞アプリ版でこのアイテムをチェック</b></font></a><br><a href=\"https://www.dot-st.com/disp/itemlist/?q=323346&userinput=\" target=\"_blank\"><font color=\"\"black\" size=2><b>＞＞ブラウザ版でこのアイテムをチェック</b></font></a>　<br>品名：USAコットンショートスリーブTシャツ<br>品番：316573<br><a href=\"adastriaapp://item?itemCode=316573\" target=\"_blank\"><font color=\"\"aqua\" size=2><b>＞＞アプリ版でこのアイテムをチェック</b></font></a><br><a href=\"https://www.dot-st.com/disp/itemlist/?q=316573&userinput=\" target=\"_blank\"><font color=\"\"black\" size=2><b>＞＞ブラウザ版でこのアイテムをチェック</b></font></a><br><br><b>【STAFF REVIEW】</b><br>身長：170ｃｍ / 体型：細身/ 着用サイズ：Mサイズ<br>サイズ感：肘が隠れる程度の丈感。ゆったりサイズ。<br>着心地：さらっとした肌触り。軽やかで涼しい！<br>落ち着いた色味で着るだけで大人見え。<br>ボトムスも暗いトーンで合わせるのはもちろん、ベージュやブルーデニムなど明るいものを持ってきてもバランス良くまとまります！<br><br>niko and ... mens 最新アイテムはここからCHECK<br><a href=\"adastriaapp://items?dispNo=0000100016_001002\" target=\"_blank\"><font color=\"\"aqua\" size=2><b>＞＞アプリ版はこちら</b></font></a><br><a href=\"https://www.dot-st.com/nikoand/disp/itemlist/?dispNo=001002\" target=\"_blank\"><font color=\"\"aqua\" size=2><b>＞＞ブラウザ版はこちら</b></font></a><br><br><br>ーーー<br>シャツ　ストライプ　柄<br>ーーー', '6000.0 JPY', 366.00, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:22:42', '2026-04-02 04:18:13', 'adastria_498896', '', '69cd72d5a7ab618f2967cb17', '生活/休闲', '', '男', '青年（18-44岁）', '涤纶43%,粘胶17%,锦纶15%', 'https://www.dot-st.com/nikoand/disp/item/498896/?COLOR_CD=70', '上装', '衬衫', '休闲衬衫', '', 'casual shirt', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/niko_and/20260401/item_498896_main_19_1748832806_b.jpg', 0, 0, 8, 0.78675, 0, 1, 1, 0, 0, 3, NULL, '透气，清凉感，轻盈垂坠感', '清凉感,轻盈垂坠感', '', '使用4种不同番手纱线捻合的特殊面料,加入莫尔纱条纹形成立体肌理效果,渐变色条纹配色营造成熟感,版型宽松、肘下五分袖、标准衣长,可单穿也可作为外搭叠穿', '条纹', '商品为“オープンカラー半袖シャツ”，从图片看为男装开领短袖衬衫，上装、前排扣、翻领、休闲宽松版型，明显属于日常休闲风格衬衫，因此在提供的列表中选择最贴切的“casual shirt（休闲衬衫）”。', 1, 1, 0, 0, 'casual shirt', NULL, '', 0, NULL, 0, NULL, NULL, '19', 'ブラック19', 0);
