INSERT INTO `clothing_info` VALUES (19996669, '【男士】UO标志刺绣帽', '【MEN】ＵＯロゴシシュウＨＡＴ', 0, 31749818, 'LOWRYS FARM', '', '', '前部点缀刺绣logo的简约帽款设计。整体风格简单百搭，适合多种穿搭场景。', 'ーーー<br>■デザイン<br>フロントにロゴが刺繍されたデザインのハット。<br>シンプルなデザインなので、服装問わず使用いただけます。<br>ーーー', '4000.0 JPY', 244.00, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:22:43', '2026-04-02 04:18:09', 'adastria_115419', '', '69cd72d5a7ab618f2967cb11', '生活/休闲', '', '男', '青年（18-44岁）', '棉100%', 'https://www.dot-st.com/lowrysfarm/disp/item/115419/?COLOR_CD=88', '其他服饰/物品', '其他', NULL, '', 'hat', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/lowrys_farm/20260401/item_115419_main_88_1740120720_b.jpg', 0, 0, 9, 0.98225, 0, 1, 1, 0, 0, 3, NULL, '遮阳，装饰搭配', '遮阳,装饰搭配', '', '正面有品牌感字母刺绣标识,款式为经典渔夫帽造型,整体风格简约，易于日常搭配,为男士设计，但日常也可中性佩戴', '字母', '该产品为戴在头部的配饰，日文类别为“帽子”，图片中为有下垂帽檐的一体成型圆顶帽，属于典型渔夫帽/桶帽类型，归属在配饰大类下的“hat（帽子）”最合适。hat 指各种款式的帽子，本品正是这种头部配饰。', 0, 0, 0, 0, 'hat', NULL, '', 0, NULL, 0, NULL, NULL, '88', 'ネイビー88', 0);
INSERT INTO `clothing_info` VALUES (19996662, '【wiggle wiggle】联名 图案T恤', '【wiggle wiggle(ウィグルウィグル)】コラボ モチーフTシャツ', 0, 200333, 'niko and ...', '', '', '这款单品采用适合多季节穿着的100%纯棉面料，质地扎实有型。\n\n胸前点缀wiggle wiggle人气图案，造型醒目可爱。略带宽松感的版型，穿着舒适，同时有一定遮肉修饰身形的效果。背部缝有便签风装饰标签，增添别致而富有趣味的设计感。\n\n可与牛仔裤或短裤搭配打造休闲风造型，也适合配长裙营造混搭风格。\n\nwiggle wiggle是诞生于韩国的生活方式品牌，以“Maximal HAPPINESS”为主题，推出色彩鲜明、充满玩味的时尚杂货、手机配件和家居小物，以大胆配色和独特设计为日常增添乐趣与活力，深受Z世代至30代人群喜爱。', '<font color=\"#f734c3\"><b>wiggle wiggle meets niko and ...<br>カラフルでポップなライフスタイルブランドとの初コラボ！</b></font><br><br>■素材特性<br>ロングシーズンで使えるしっかりめのコットン100％生地を使用しています。<br><br>■デザイン<br>wiggle wiggleで人気のモチーフを胸元に施したキャッチ―で可愛らしいTシャツ。<br>程良くゆとりのあるシルエットは体系カバーも叶う着心地の良いサイズ感◎<br>バックには付箋風の飾りネームを縫い付け、個性的で遊び心の効いたデザインに注目です！<br><br>■おすすめスタイリング<br>シンプルにデニムパンツや春夏らしくハーフパンツと合わせたカジュアルコーデが◎<br>ロングスカートで合わせたMIXスタイルもおすすめです！<br><br><font color=\"#f734c3\"><b>【wiggle wiggle(ウィグルウィグル)】コラボアイテム一覧はこちら</b></font><br><a href=\"adastriaapp://items?dispNo=0000100016_002001602&orderBy=00\" target=\"_blank\"><b>>>アプリ版</b></a><br><a href=\"https://www.dot-st.com/nikoand/disp/itemlist/?dispNo=002001602\" target=\"_blank\"><b>>>ブラウザ版</b></a><br><br>【wiggle wiggle(ウィグルウィグル)】<br>韓国で誕生したライフスタイルブランドです。<br> \"Maximal HAPPINESS\"をテーマに、ファッション雑貨やスマホアクセサリー、インテリア小物など、カラフルで遊び心あふれるアイテムを展開。<br>日常に楽しさや鮮やかさを添える独自のスタイルで、Z世代から30代を中心に、幅広い層から支持されています。<br>他にはない大胆なカラーリングと、感性に響くユニークなデザインで、いつもの日常にわくわくする気分をプラス。 <br>心がはずむような“かわいい”を通して、wiggle wiggleのハッピーな世界をCheck！！<br><br>ーーー<br>wiggle wiggle　コラボ　Tシャツ　半袖Tシャツ　ロゴTシャツ<br>ーー', '5000.0 JPY', 305.00, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:22:44', '2026-04-02 04:18:03', 'adastria_451721', '', '69cd72d5a7ab618f2967cafe', '生活/休闲', '', '通用', '青年（18-44岁）', '棉100%', 'https://www.dot-st.com/nikoand/disp/item/451721/?COLOR_CD=11', '上装', 'T恤', 'T恤', '', 't-shirt', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/niko_and/20260401/item_451721_main_11_1746094042_b.jpg', 0, 0, 2, 0.98883, 0, 1, 1, 0, 0, 3, NULL, '透气，舒适，宽松版型显瘦遮肉', '舒适,宽松版型显瘦遮肉', '', '与wiggle wiggle品牌联名，设计感强,胸前位置有品牌特色插画式小图案,背部有便签风格装饰织标，增加趣味性,版型适度宽松，适合多种身形,适合春夏等多个季节穿着,整体风格色彩简约、图案俏皮可爱', '人物图案（人形，人体）', '商品名称为「モチーフTシャツ」，说明是印有图案的T恤；描述中多次提到「Tシャツ」「半袖Tシャツ」「ロゴTシャツ」，并从图片上看为短袖圆领针织上衣，因此最合适的子类为 t-shirt（短袖针织圆领上衣）。t-shirt 指的是日常穿着的针织短袖上衣，多为棉质、圆领或简洁领型，本商品完全符合这一定义。', 0, 0, 0, 0, 't-shirt', NULL, '', 0, NULL, 0, NULL, NULL, '11', 'オフ(11)', 0);
INSERT INTO `clothing_info` VALUES (19996663, '多种穿法T恤吊带组合套装', 'マルチWAYTシャツセット', 0, 200333, 'niko and ...', '', '', '这是一款既可叠穿也可单独穿着的多种穿法T恤套装。面料选用触感干爽柔软的全棉材质，具有优良的透气性和吸湿性，穿着清凉舒适。整体由一件简约基础T恤与一件前系带吊带组成，吊带通过褶皱和系带细节营造出具有华丽感的设计亮点。两件单品既可成套搭配，也能分别与衣橱中的其他单品自由组合，拓展造型变化，提升穿搭乐趣。适合与休闲感的格纹或条纹下装搭配，或与富有蓬松感的裙装组合，营造多样造型。', '<font color=\"#ff3075\"><b>重ねても単体でも着られるマルチWAYが嬉しいTシャツセット</b></font><br>		<br>■素材特性<br>さらっと柔らかい生地感のコットン素材。<br>通気性・吸湿性に優れている為、涼しく着ていただけます。<br>	<br>■デザイン<br>シンプルなベーシックTシャツとフロントリボンのキャミソールがセットになったマルチWAYTシャツ。<br>キャミソールはギャザーや結び目が目を引く、華やかさのあるデザインに仕上げました。<br>それぞれをお持ちのアイテムと組み合わせても楽しめる、着こなしの幅が広がる優秀トップスです！<br>		<br>■おすすめスタイリング	<br>リラックス感のあるチェックやストライプ柄のボトムスと合わせてカジュアルに！<br>程よくコンパクトなシルエットは、ボリュームのあるスカートともマッチする着回し抜群なアイテムです◎<br>		<br>ーーー		<br>セットアイテム　Tシャツ　キャミソール　マルチWAY<br>ーーー', '5000.0 JPY', 305.00, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:22:44', '2026-04-02 04:18:04', 'adastria_571614', '', '69cd72d5a7ab618f2967cb06', '生活/休闲', '', '女', '青年（18-44岁）', '棉100%', 'https://www.dot-st.com/nikoand/disp/item/571614/?COLOR_CD=19', '上装', 'T恤', 'T恤', '', 't-shirt', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/niko_and/20260401/item_571614_main_19_1751589131_b.jpg', 0, 0, 2, 0.92688, 0, 1, 1, 0, 0, 3, NULL, '透气，吸湿排汗', '', '', 'T恤与前系带吊带组合成多穿法套装,面料为柔软亲肤的全棉材质，适合夏季穿着,吊带前片有褶皱和系带设计，增加层次感与装饰性,T恤版型偏基础简约，轮廓适度修身,可与自有单品自由叠搭，提升搭配多样性', '纯色', '此款为“マルチWAYTシャツセット”，核心单品是基础圆领短袖T恤，搭配一件前系带设计的吊带上衣叠穿。从版型与用途看属于日常针织T恤范畴，而非衬衫或外套，因此选择子类目为“t-shirt”。“t-shirt”的定义是：以针织面料为主、T字型结构、用于日常休闲穿着的上衣，本商品完全符合这一特征。', 1, 0, 0, 0, 't-shirt', NULL, '', 0, NULL, 0, NULL, NULL, '19', 'ブラック(19)', 0);
