INSERT INTO `clothing_info` VALUES (19996665, '【预售】【LFM(U)】MLB×PEANUTS 联名短袖T恤', '【先行予約】【LFM(U)】ＭＬＢ＊ＰＥＡＮＵＴＳＰＴＳＳ', 0, 31749818, 'LOWRYS FARM', '', '', '世界最高水平棒球联赛MLB与跨世代受喜爱的漫画《PEANUTS》打造的特别联名系列。将不同MLB球队的队名、队标与PEANUTS角色相结合，呈现独特联名图案。衣身采用颜料染工艺，营造多次穿着后的褪色质感与复古风格，在休闲中体现层次感。无论搭配牛仔、工装裤还是西裤混搭都十分适合。', 'ーーー<br>■デザイン<br>世界最高峰のベースボールリーグ メジャーリーグベースボール（MLB） と、世代を超えて愛されるコミック PEANUTS によるスペシャルコレクション。<br>それぞれ異なるMLBチームをプリントし、チームカラーやロゴとPEANUTSのキャラクターを掛け合わせた特別なグラフィックに仕上げました<br>ボディにはピグメント加工を施し、着込んだようなフェード感とヴィンテージライクな風合いを演出。カジュアルな中に奥行きを感じさせる一枚に。<br>デニムやカーゴパンツはもちろん、スラックスと合わせたミックススタイルにも映えるアイテムです。							<br>ーーー', '5446.0 JPY', 332.21, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:22:44', '2026-04-02 04:18:05', 'adastria_664942', '', '69cd72d5a7ab618f2967cb08', '生活/休闲', '', '通用', '青年（18-44岁）', '棉100%', 'https://www.dot-st.com/lowrysfarm/disp/item/664942/?COLOR_CD=09', '上装', 'T恤', 'T恤', '', 't-shirt', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/lowrys_farm/20260401/item_664942_main_09_1773734268_b.jpg', 0, 0, 1, 0.99972, 0, -2, 0, 0, 0, 3, NULL, '舒适休闲，宽松版型', '舒适休闲,宽松版型', '', '与MLB和PEANUTS联名的特别系列,前幅大面积角色与球队标志印花图案,运用颜料染工艺呈现褪色感与复古风格,宽松轮廓适合搭配牛仔裤、工装裤及西裤', '文字，卡通人物（拟人化物体）', '从产品名称中的「ＰＴＳＳ」以及整体版型来看，这是短袖圆领套头上衣，属于典型的休闲款短袖T恤，因此选择子类目“t-shirt（短袖T恤）”。该子类目定义为日常穿着的针织圆领/其他领型短袖上衣，本商品完全符合。', 1, 0, 0, 0, 't-shirt', NULL, '', 0, NULL, 0, NULL, NULL, '09', 'ブラック09', 0);
