INSERT INTO `clothing_info` VALUES (19996658, '【预售】可成套搭配【LFM(U)】尼龙休闲短裤／P', '【先行予約】SETUP可能【LFM(U)】ナイロンイージーショーツ／Ｐ', 0, 31749818, 'LOWRYS FARM', '', '', '采用尼龙面料制作的休闲半裤，适合日常穿着，也适合露营等户外场景。裤长不过短，穿着舒适便捷。可与同系列上装搭配成套穿着。', 'ーーー<br>■デザイン<br>ナイロン素材のハーフパンツ。<br>デイリー使いはもちろん、キャンプなど野外な場面などにも◎<br>短すぎない丈感なので、履きやすいデザインです。<br>SETUPも可能なので、一緒に着るのもおすすめ。<br>ーーー<br>SETUPのトップスはこちら<br><a href=\'https://www.dot-st.com/lowrysfarm/disp/item/670623/\'>【LFM(U)】ナイロンドローコードＳＳ／Ｐ</a>', '5446.0 JPY', 332.21, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:22:46', '2026-04-02 04:17:59', 'adastria_670621', '', '69cd72d5a7ab618f2967cb02', '露营，生活/休闲', '', '通用', '青年（18-44岁）', '锦纶100%', 'https://www.dot-st.com/lowrysfarm/disp/item/670621/?COLOR_CD=09', '下装', '短裤', '短裤', '', 'shorts', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/lowrys_farm/20260401/item_670621_main_09_1774946059_b.jpg', 0, 0, 1, 0.99120, 0, -2, 0, 0, 0, 3, NULL, '透气，轻量，舒适穿着', '轻量,舒适穿着', '', '采用尼龙面料，适合日常与户外场景的休闲短裤,中等裤长设计，避免过短，提升穿着舒适与实用性,可与同系列上装搭配成套穿着（SETUP）', '纯色，纯色', '从品名“ナイロンイージーショーツ”以及图片可以看出，这是长度在膝上/膝部的休闲短裤，并非长裤或家居裤，故应归类为“shorts（短裤）”。shorts 指以短裤型为主、长度通常在膝盖以上或附近，用于日常或运动穿着的下装单品，本款尼龙休闲短裤完全符合该定义。', 1, 0, 0, 0, 'shorts', NULL, '', 0, NULL, 0, NULL, NULL, '09', 'ブラック09', 0);
