INSERT INTO `clothing_info` VALUES (19996661, '【STRANGER THINGS】联名 SCOOP 拼色边T恤', '【STRANGER THINGS】コラボ SCOOPリンガーTシャツ', 0, 200333, 'niko and ...', '', '', '本款为Netflix剧集《怪奇物语》与niko and ...的限定联名单品。采用100%纯棉面料，手感柔软，穿着时有被温柔包裹的舒适感，且具有良好的耐用性、透气性和吸湿性，能有效吸收汗液等水分。设计灵感来自剧中史蒂夫和罗ビン打工的冰淇淋店“Scoops Ahoy”，以店内角色图案打造复古感拼色边T恤。正面采用具有立体感的印花工艺，呈现类似3D的视觉效果，整体营造浓厚80年代氛围，是一件穿上即可感受《怪奇物语》世界观的单品。推荐搭配裤装和棒球帽打造中性休闲风，也可与具有手作感的下装组合，展现更具当下感的造型。', '<font color=\"#E92A2D\"><b>Netflixシリーズ「ストレンジャー・シングス 未知の世界」× niko and ...<br>ここでしか出会えない限定コラボレーションアイテムが登場！</b></font><br><br>■素材特性<br>優しくふんわりと包み込んでくれるような肌触りの綿100％生地。<br>丈夫で通気性・吸湿性が高いので、汗などの水分をしっかりと吸収してくれます◎<br><br>■デザイン<br>劇中でスティーブとロビンがアルバイトをしていた<br>アイスクリームパーラー「Scoops Ahoy」のキャラクターをデザインしたレトロなリンガーTシャツ。<br>グラフィックのプリント手法にもこだわり、3Dのような見え感になるように仕上げました！<br>着るだけでストレンジャーシングスの世界を楽しめる80\'s感漂う1枚。<br><br>■おすすめスタイリング<br>パンツ×キャップを合わせたボーイッシュスタイルは相性抜群◎<br>ボトムはクラフト感のあるアイテムに変えれば、今っぽいこなれ感も楽しめます！<br><br>【STRANGER THINGS(ストレンジャー・シングス 未知の世界)】その他コラボアイテムはこちら！<br><a href=\"adastriaapp://items?dispNo=0000100016_002100729&orderBy=00\" target=\"_blank\"><font color=\"#558ed5\"><b>＞＞and ST アプリの方はこちら</b></font></a><br><a href=\"https://www.dot-st.com/nikoand/disp/itemlist/?dispNo=002100729\" target=\"_blank\"><font color=\"#558ed5\"><b>＞＞ブラウザの方はこちら</b></font></a><br><br>【Netflixシリーズ「ストレンジャー・シングス 未知の世界」 】<br>1980年代の小さな町ホーキンスを舞台に、突然姿を消した少年ウィルの失踪事件と突如現れた謎の少女イレブンを巡り、想像を超える不可解な事件に巻き込まれながらも、少年たちが友人や家族たちを守るために事件解決に立ち向かうミステリー・アドベンチャー。<br>80年代の名作映画へのリスペクトが込められたドラマチックな展開と緊張感あふれるスリラー描写、そして心躍る子供たちの友情と冒険が組み合わさった本作は、2016年のシーズン１配信開始以来、全世界で大ヒット！世界中に社会現象とも言えるムーブメントを巻き起こしている。 現在シーズン1～4を独占配信中。<br><a href=\"https://www.netflix.com/jp/title/80057281\" target=\"_blank\"><font color=\"#558ed5\"><b>＞＞作品ページはこちら</b></font></a><br><br>ーーー<br>Stranger Things　ストレンジャー・シングス　未知の世界　コラボ　Netflix<br>ーーー', '4546.0 JPY', 277.31, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:22:46', '2026-04-02 04:18:02', 'adastria_459176', '', '69cd72d5a7ab618f2967cb04', '生活/休闲', '', '通用', '青年（18-44岁）', '棉100%', 'https://www.dot-st.com/nikoand/disp/item/459176/?COLOR_CD=82', '上装', 'T恤', 'T恤', '', 't-shirt', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/niko_and/20260401/item_459176_main_82_1747123539_b.webp', 0, 0, 2, 0.61294, 0, 1, 1, 0, 0, 3, NULL, '透气，吸湿排汗，舒适亲肤', '舒适亲肤', '', '与Netflix剧集《怪奇物语》联名合作，具有IP属性与收藏价值,采用100%纯棉针织面料，强调柔软、耐用与良好吸湿性,前身带复古感角色图案与英文LOGO，具有强烈80年代复古风格,3D感印花效果增强图案立体视觉冲击,对比色领口的经典リンガーT恤设计，具有休闲街头风格', '品牌标识，人物图案（人形，人体），物体', '该商品为日常穿着的短袖上衣，描述中多次提到「リンガーTシャツ」，版型和图片也都为经典圆领短袖针织衫，无前开襟或衬衫结构，因此归类为针织休闲上衣中的“t-shirt（T恤）”。t-shirt：指以针织面料制成、套头穿着、通常为短袖或长袖的圆领或V领上衣，是最基础的休闲上装款式。', 0, 0, 0, 0, 't-shirt', NULL, '', 0, NULL, 0, NULL, NULL, '82', 'ライトブルー(82)', 0);
INSERT INTO `clothing_info` VALUES (19996655, '2WAY花朵工艺吊带背心', '2WAYフラワークラフトキャミソール', 0, 200333, 'niko and ...', '', '', '这款单品采用织入蕾丝的手工感面料，触感柔软、穿着轻盈舒适。以方形拼接花片为基础，搭配花朵图案，营造出略带复古气息的设计感。只需叠穿在上衣外，就能为整体造型增添亮点，容易融入多种风格。肩带长度可微调，打结形成的蝴蝶结也是低调的设计细节。前后均可穿着的2WAY设计，可根据当日造型自由切换。无论搭配简约上衣还是带有图案的上衣叠穿，都能呈现出时髦的混搭效果。', '<font color=\"#c97908\"><b>おしゃれ心を刺激する旬な1枚！</b></font><br><br>■素材特性<br>レースを織り込んだクラフト感のある素材。<br>やわらかな肌触りと軽やかな着心地が特徴です。<br><br>■デザイン<br>四角いモチーフ編みにフラワーを組み合わせたデザインが、どこかレトロな雰囲気のあるアイテム！<br>レイヤードするだけでコーディネートにアクセントを与えどんなスタイルにも馴染んでくれます。<br>肩紐は長さの微調整も可能◎結んだ部分のリボンがさりげないポイントに！<br>前後2WAYで着用できるのでその日のコーデに合わせて切り替えてみて下さい！<br>		<br>■おすすめスタイリング	<br>シンプルなトップスはもちろん柄の入ったトップスとのレイヤードも相性◎<br>ゆるっとボーイッシュなスタイルと合わせた甘辛ミックスが今っぽくておすすめです！<br><br>ーーー		<br>２WAY　キャミソール　ビスチェ　レース　リボン　クラフト感　花<br>ーーー', '4546.0 JPY', 277.31, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:22:47', '2026-04-02 04:17:57', 'adastria_571612', '', '69cd72d5a7ab618f2967caf1', '生活/休闲', '', '女', '青年（18-44岁）', '锦纶95%,涤纶5%', 'https://www.dot-st.com/nikoand/disp/item/571612/?COLOR_CD=19', '上装', '背心', '吊带背心', '', 'camisole', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/niko_and/20260401/item_571612_main_19_1751588086_b.jpg', 0, 0, 2, 0.92734, 0, 1, 1, 0, 0, 3, NULL, '可前后两穿，适合叠穿造型', '可前后两穿,适合叠穿造型', '', '方形钩针花片拼接设计，具有复古感和手工感,肩带可调节长度并可系成蝴蝶结装饰,前后2WAY穿法，增加搭配灵活性,轻盈柔软，适合春夏季节叠穿', '其他', '从商品名“2WAYフラワークラフトキャミソール”和图片来看，这是无袖细肩带、作为内搭或叠穿上衣使用的短款小吊带/小背心式单品，属于贴身上装类别，对应列表中“camisole（吊带背心）”最为准确。该品非常规T恤或针织衫，也不是外套或连衣裙，因此选择 sub_category: camisole。定义：camisole 为带细肩带、通常无袖、可单穿或叠穿的轻薄上衣。', 1, 0, 0, 0, 'camisole', NULL, '', 0, NULL, 0, NULL, NULL, '19', 'ブラック(19)', 0);
