INSERT INTO `clothing_info` VALUES (19996657, '2WAY花朵工艺吊带背心', '2WAYフラワークラフトキャミソール', 0, 200333, 'niko and ...', '', '', '这款单品采用织入蕾丝的手工感面料，触感柔软、穿着轻盈舒适。以方形拼接花片为基础，搭配花朵图案，营造出略带复古气息的设计感。只需叠穿在上衣外，就能为整体造型增添亮点，容易融入多种风格。肩带长度可微调，打结形成的蝴蝶结也是低调的设计细节。前后均可穿着的2WAY设计，可根据当日造型自由切换。无论搭配简约上衣还是带有图案的上衣叠穿，都能呈现出时髦的混搭效果。', '<font color=\"#c97908\"><b>おしゃれ心を刺激する旬な1枚！</b></font><br><br>■素材特性<br>レースを織り込んだクラフト感のある素材。<br>やわらかな肌触りと軽やかな着心地が特徴です。<br><br>■デザイン<br>四角いモチーフ編みにフラワーを組み合わせたデザインが、どこかレトロな雰囲気のあるアイテム！<br>レイヤードするだけでコーディネートにアクセントを与えどんなスタイルにも馴染んでくれます。<br>肩紐は長さの微調整も可能◎結んだ部分のリボンがさりげないポイントに！<br>前後2WAYで着用できるのでその日のコーデに合わせて切り替えてみて下さい！<br>		<br>■おすすめスタイリング	<br>シンプルなトップスはもちろん柄の入ったトップスとのレイヤードも相性◎<br>ゆるっとボーイッシュなスタイルと合わせた甘辛ミックスが今っぽくておすすめです！<br><br>ーーー		<br>２WAY　キャミソール　ビスチェ　レース　リボン　クラフト感　花<br>ーーー', '4546.0 JPY', 277.31, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:22:47', '2026-04-02 04:17:58', 'adastria_571612', '', '69cd72d5a7ab618f2967caf1', '生活/休闲', '', '女', '青年（18-44岁）', '锦纶95%,涤纶5%', 'https://www.dot-st.com/nikoand/disp/item/571612/?COLOR_CD=19', '上装', '背心', '吊带背心', '', 'camisole', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/niko_and/20260401/item_571612_main_52_1751449577_b.jpg', 0, 0, 8, 0.96951, 0, 1, 1, 0, 0, 3, NULL, '可前后两穿，适合叠穿造型', '可前后两穿,适合叠穿造型', '', '方形钩针花片拼接设计，具有复古感和手工感,肩带可调节长度并可系成蝴蝶结装饰,前后2WAY穿法，增加搭配灵活性,轻盈柔软，适合春夏季节叠穿', '其他', '从商品名“2WAYフラワークラフトキャミソール”和图片来看，这是无袖细肩带、作为内搭或叠穿上衣使用的短款小吊带/小背心式单品，属于贴身上装类别，对应列表中“camisole（吊带背心）”最为准确。该品非常规T恤或针织衫，也不是外套或连衣裙，因此选择 sub_category: camisole。定义：camisole 为带细肩带、通常无袖、可单穿或叠穿的轻薄上衣。', 1, 2, 0, 0, 'camisole', NULL, '', 0, NULL, 0, NULL, NULL, '52', 'アイボリー(52)', 0);
INSERT INTO `clothing_info` VALUES (19996653, 'COMFORT亚麻褶皱衬衫', 'COMFORTリネンタックシャツ', 0, 200333, 'niko and ...', '', '', '简约耐看的设计，呈现成熟大人的衬衫风格。\n\n【材质特点】\n追求舒适、惬意触感的温柔面料。再生纤维（纤维素）带来清爽顺滑的肤触，亚麻则提供良好的通气性。\n\n【设计】\n适度宽松的版型营造轻松随性的氛围。前后长度有差异的圆弧下摆设计，在修饰腰臀部位的同时带来利落印象。适合作为换季时节的防晒外搭单品，自然感四色提升季节氛围。\n\n【推荐搭配】\n一件即可成型的衬衫，也很适合作为外搭使用。只需在T恤外随性披上，即可打造洗练的穿搭。', '<font color=\"#0709a8\"><b>シンプルで飽きのこないデザインが魅力のオトナシャツ</b></font><br><br>■素材特性<br>快適・心地良いを求めた優しい素材感。<br>再生繊維(セルロース)のさらっとなめらかな肌さわりとリネンの通気性の良さが魅力です◎<br><br>■デザイン<br>程よいゆとり感のあるサイジングがこなれた雰囲気に。<br>前後で差をつけたラウンドカットデザインは、腰回りをカバーしつつすっきりした印象に仕上げました◎<br>紫外線対策など、これからの季節の羽織りアイテムでもおすすめです！<br>シーズンムードを高めてくれる4色のナチュラルカラーでご用意です♪<br><br>■おすすめスタイリング<br>1枚でも決まるシャツをあえて、羽織りに切り替えて♪<br>Tシャツなどの上から羽織るだけで洗練された着こなしに早変わり！<br><br>ーーー<br>シャツ　羽織り　ラウンドカット　<br>ーーー', '5455.0 JPY', 332.75, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:22:50', '2026-04-02 04:17:55', 'adastria_234878', '', '69cd72d5a7ab618f2967caef', '生活/休闲', '', '女', '青年（18-44岁）', '亚麻25%', 'https://www.dot-st.com/nikoand/disp/item/234878/?COLOR_CD=18', '上装', '衬衫', '纽扣衬衫', '', 'button-up shirt', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/niko_and/20260401/item_234878_main_18_1738208079_b.jpg', 0, 0, 2, 0.93635, 0, 1, 1, 0, 0, 3, NULL, '透气，防紫外线，舒适亲肤，凉爽触感，遮阳，修饰身形', '舒适亲肤,凉爽触感,遮阳,修饰身形', '', '宽松版型，前后不对称下摆圆弧剪裁,采用再生纤维与亚麻混纺，兼顾柔滑手感与良好通风性,设计为可单穿亦可作为外搭使用,自然系配色提升季节氛围', '纯色，纯色', '从版型和细节看，这件商品为长袖开襟、有门襟排扣和翻领的上衣，属于典型的“衬衫”结构，对应列表中的“button-up shirt（开襟衬衫）”。商品名为“シャツ”，并强调可作羽织穿搭，进一步说明是前开扣的衬衫款式。因此选择子类目：button-up shirt，定义为：以前门全开排扣和翻领为特征、可单穿或外搭的衬衫上衣。', 1, 0, 0, 0, 'button-up shirt', NULL, '', 0, NULL, 0, NULL, NULL, '18', 'チャコール18', 0);
