INSERT INTO `clothing_info` VALUES (19996650, '[MODE NORM CORE] 亚麻天竺蝙蝠袖套头上衣', '[MODE NORM CORE] リネン天竺ドルマンプルオーバー', 0, 200333, 'niko and ...', '', '', '亚麻100%带来干爽舒适穿感，如同T恤般轻松好穿，却自带造型感，是为成熟女性打造的设计感上衣。\n\n■ 面料特点\n采用细番手亚麻纱精致编织而成的100%亚麻天竺针织面料。即使出汗也不易黏身，触感清爽舒适，尤其适合湿度较高或盛夏高温季节穿着。\n\n■ 设计\n在简约外观中融入设计巧思的异素材拼接上衣。袖口加入丰富褶皱，形成宽松廓形，有效遮盖上臂线条，营造柔和女性印象。一件就能避免造型平淡，轻松提升整体穿搭质感。\n\n■ 穿搭建议\n无论是搭配裙装还是阔腿裤，都能在休闲与优雅风格之间自由切换。可根据不同体型选择合适尺码，获得理想的宽松或合身效果。既可单穿，也适合与围裙式连衣裙或背带裤叠搭。', '<font color=\"mediumaquamarine\"><b>リネン100%はさらりと快適<br>Tシャツ感覚で着ただけでサマになる<br>大人のためのデザイントップス</b></font><br><br>■素材特性<br>細番手のリネン糸で繊細に仕立てたリネン100%天竺。<br>汗をかいても張り付かず、さらりとした快適な着心地。<br>湿気の多い時期や、気温が高い夏におすすめの素材です。<br><br>■デザイン<br>シンプルな見た目ながらもデザインの利いた<br>異素材切り替えのトップス。<br>袖口にたっぷりとギャザーを施したスリーブなので、<br>二の腕をカバーし、ゆったりとしたシルエットが女性らしい印象に。<br>一枚で着ても平凡にならずスタイリングを格上げします。<br><br>■おすすめスタイリング<br>スカート・ワイドパンツとも好相性で、カジュアルにも上品スタイルにも着回し自在。<br>更に、選べるサイズ展開で自分にぴったりのフィット感を選べます。<br>一枚ではもちろん、ジャンパースカートやサロペットの中にも合わせても◎<br><br><font color=\"mediumaquamarine\"><b>【MODE NORM CORE】2025夏アイテム一覧をCHECK！</b></font><br><a href=\"adastriaapp://items?dispNo=0000100016_002001582&orderBy=00\"><b>>>アプリ版</b></font></a><br><a href=\"https://www.dot-st.com/nikoand/disp/itemlist/?dispNo=002001582\" target=\"_blank\"><b>>>ブラウザ版</b></font></a><br><br>ーーー<br>MODENORMCORE　モードノーム　麻　リネン　シアー　夏トップス　カットソー<br>ーーー', '5000.0 JPY', 305.00, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:22:51', '2026-04-02 04:17:53', 'adastria_451812', '', '69cd72d5a7ab618f2967caea', '生活/休闲', '', '女', '青年（18-44岁）', '亚麻100%', 'https://www.dot-st.com/nikoand/disp/item/451812/?COLOR_CD=11', '上装', '卫衣', '套头衫', '', 'pullover', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/niko_and/20260401/item_451812_main_11_1747108957_b.jpg', 0, 0, 4, 0.86185, 0, 1, 1, 0, 0, 3, NULL, '透气，清凉舒适，遮掩手臂线条，宽松版型提升舒适度', '清凉舒适,遮掩手臂线条,宽松版型提升舒适度', '', '采用细番手100%亚麻天竺针织面料，质地轻薄透气,适合高温及潮湿季节穿着的夏季上衣,袖口大量褶皱设计，呈现女性化廓形并修饰手臂线条,异素材拼接设计提升造型感,可搭配裙装、阔腿裤或叠穿在连衣裙、背带裤内外，多场合适用', '纯色', '商品名称为“リネン天竺ドルマンプルオーバー”，属套头式上衣且非卫衣/针织衫，而是轻薄天竺针织T恤感上装，最接近“pullover（套头上衣）”分类。该子类指从头套穿、无前开襟的上衣单品，符合本款设计特点。', 1, 0, 0, 0, 'pullover', NULL, '', 0, NULL, 0, NULL, NULL, '11', 'オフホワイト(11)', 0);
INSERT INTO `clothing_info` VALUES (19996651, '[MODE NORM CORE] 亚麻天竺蝙蝠袖套头上衣', '[MODE NORM CORE] リネン天竺ドルマンプルオーバー', 0, 200333, 'niko and ...', '', '', '亚麻100%带来干爽舒适穿感，如同T恤般轻松好穿，却自带造型感，是为成熟女性打造的设计感上衣。\n\n■ 面料特点\n采用细番手亚麻纱精致编织而成的100%亚麻天竺针织面料。即使出汗也不易黏身，触感清爽舒适，尤其适合湿度较高或盛夏高温季节穿着。\n\n■ 设计\n在简约外观中融入设计巧思的异素材拼接上衣。袖口加入丰富褶皱，形成宽松廓形，有效遮盖上臂线条，营造柔和女性印象。一件就能避免造型平淡，轻松提升整体穿搭质感。\n\n■ 穿搭建议\n无论是搭配裙装还是阔腿裤，都能在休闲与优雅风格之间自由切换。可根据不同体型选择合适尺码，获得理想的宽松或合身效果。既可单穿，也适合与围裙式连衣裙或背带裤叠搭。', '<font color=\"mediumaquamarine\"><b>リネン100%はさらりと快適<br>Tシャツ感覚で着ただけでサマになる<br>大人のためのデザイントップス</b></font><br><br>■素材特性<br>細番手のリネン糸で繊細に仕立てたリネン100%天竺。<br>汗をかいても張り付かず、さらりとした快適な着心地。<br>湿気の多い時期や、気温が高い夏におすすめの素材です。<br><br>■デザイン<br>シンプルな見た目ながらもデザインの利いた<br>異素材切り替えのトップス。<br>袖口にたっぷりとギャザーを施したスリーブなので、<br>二の腕をカバーし、ゆったりとしたシルエットが女性らしい印象に。<br>一枚で着ても平凡にならずスタイリングを格上げします。<br><br>■おすすめスタイリング<br>スカート・ワイドパンツとも好相性で、カジュアルにも上品スタイルにも着回し自在。<br>更に、選べるサイズ展開で自分にぴったりのフィット感を選べます。<br>一枚ではもちろん、ジャンパースカートやサロペットの中にも合わせても◎<br><br><font color=\"mediumaquamarine\"><b>【MODE NORM CORE】2025夏アイテム一覧をCHECK！</b></font><br><a href=\"adastriaapp://items?dispNo=0000100016_002001582&orderBy=00\"><b>>>アプリ版</b></font></a><br><a href=\"https://www.dot-st.com/nikoand/disp/itemlist/?dispNo=002001582\" target=\"_blank\"><b>>>ブラウザ版</b></font></a><br><br>ーーー<br>MODENORMCORE　モードノーム　麻　リネン　シアー　夏トップス　カットソー<br>ーーー', '5000.0 JPY', 305.00, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:22:51', '2026-04-02 04:17:53', 'adastria_451812', '', '69cd72d5a7ab618f2967caea', '生活/休闲', '', '女', '青年（18-44岁）', '亚麻100%', 'https://www.dot-st.com/nikoand/disp/item/451812/?COLOR_CD=11', '上装', '卫衣', '套头衫', '', 'pullover', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/niko_and/20260401/item_451812_main_19_1747109077_b.jpg', 0, 0, 2, 0.82695, 0, 1, 1, 0, 0, 3, NULL, '透气，清凉舒适，遮掩手臂线条，宽松版型提升舒适度', '清凉舒适,遮掩手臂线条,宽松版型提升舒适度', '', '采用细番手100%亚麻天竺针织面料，质地轻薄透气,适合高温及潮湿季节穿着的夏季上衣,袖口大量褶皱设计，呈现女性化廓形并修饰手臂线条,异素材拼接设计提升造型感,可搭配裙装、阔腿裤或叠穿在连衣裙、背带裤内外，多场合适用', '纯色', '商品名称为“リネン天竺ドルマンプルオーバー”，属套头式上衣且非卫衣/针织衫，而是轻薄天竺针织T恤感上装，最接近“pullover（套头上衣）”分类。该子类指从头套穿、无前开襟的上衣单品，符合本款设计特点。', 1, 1, 0, 0, 'pullover', NULL, '', 0, NULL, 0, NULL, NULL, '19', 'ブラック(19)', 0);
INSERT INTO `clothing_info` VALUES (19996652, '【PUPPET SUNSUN】联名连帽套头卫衣', '【パペットスンスン】コラボフーディープルオーバー', 0, 200333, 'niko and ...', '', '', '人气角色「PUPPET SUNSUN」与niko and ...首次联名合作，推出充满玩味的连帽卫衣。胸前印有SUNSUN等角色的旅行风景图案，设计俏皮可爱。版型宽松，穿着轻盈舒适，适合日常休闲搭配，一件即可打造具有存在感的造型。', '<b><font color=\"#568BC9\">「パペットスンスン」がニコアンドに初登場！<br>とびきりキュートで元気が出るコラボアイテム！</font></b><br><br>YouTubeやSNSを中心に大人気のキャラクター「パペットスンスン」とニコアンドが、初のコラボレーション！<br><br>スンスンをプリントした、遊び心あふれるフーディーが登場。<br>軽やかな着心地とゆったりとしたシルエットで、デイリー使いにもぴったり。<br>キャッチーなデザインがコーデのアクセントになり、1枚で存在感のあるスタイルが完成します。<br><br>【パペットスンスン】シリーズのアイテムはこちら！<br><a href=\"adastriaapp://items?dispNo=0000100016_002005296&orderBy=00&stock=0\" target=\"_blank\"><font color=\"#568BC9\"><b>＞＞and ST アプリの方はこちら</b></font></a><br><a href=\"https://www.dot-st.com/nikoand/disp/itemlist/?dispNo=002005296&stock=0\" target=\"_blank\"><font color=\"#568BC9\"><b>＞＞ブラウザの方はこちら</b></font></a><br><br>【販売スケジュールの詳細はこちら】<br><a href=\"https://www.dot-st.com/nikoand/info/news/?news_id=2615&brand_id=0000100016\" target=\"_blank\"><font color=\"#568BC9\"><b>＞＞ニュースページ</b></font></a><br><br>【パペットスンスン】<br>「パペットスンスン」の主人公スンスンは、パペットの国<トゥーホック>に住む6才の男の子。親友のノンノンやおじいちゃんのゾンゾンとの日常の出来事をムービーやイラストにして、SNSで発表している。今回、トゥーホックを飛び出したスンスンたちの楽しい旅行風景をデザインしたniko and ...とのオリジナルコレクション。<br><br>ーーー<br>パペットスンスン　PUPPET SUNSUN　コラボ　スンスン　トップス　フーディー　プルオーバー<br>ーーー', '5455.0 JPY', 332.75, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:22:51', '2026-04-02 04:17:54', 'adastria_290587', '', '69cd72d5a7ab618f2967caeb', '生活/休闲', '', '通用', '青年（18-44岁）', '棉60%,涤纶40%', 'https://www.dot-st.com/nikoand/disp/item/290587/?COLOR_CD=03', '上装', '卫衣', '连帽衫', '', 'hoodie', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/niko_and/20260401/item_290587_main_03_1752731452_b.jpg', 0, 0, 2, 0.96135, 0, 1, 1, 0, 0, 3, NULL, '透气', '', '', '与人气角色IP联名合作设计,宽松版型，适合日常休闲穿搭,带帽套头设计，增加造型感,正面大面积角色图案印花，视觉重点突出', '卡通人物（拟人化物体）', '从商品名中的「フーディープルオーバー」以及图片可以看出，这是带帽的套头式上衣，前身没有全开襟拉链，典型属于卫衣类连帽上衣，因此在给定选项中最适合归为“hoodie（连帽卫衣）”。', 0, 0, 0, 0, 'hoodie', NULL, '', 0, NULL, 0, NULL, NULL, '03', 'アニマル(03)', 0);
INSERT INTO `clothing_info` VALUES (19996645, '几何条纹衬衫', '幾何柄ボーダーシャツ', 0, 200333, 'niko and ...', '', '', '这是一款几何图案抢眼的主角单品。采用棉与涤纶混纺面料，具有良好的吸湿性和清爽的穿着感，同时通气性出色，适合炎热季节穿着。几何图案配合带有透视感的设计，为造型增添时髦感，可作为主打上衣单穿，也可以敞开当成外搭衬衫使用，兼具造型感与实用性。夏季既可用来遮挡日晒，也适合在空调环境中作为轻薄外搭。内搭推荐搭配吊带或背心，营造健康清爽的叠穿效果，存在感强的几何图案与牛仔、工装裤等休闲单品十分相配。', '<font color=\"#cd5c5c\"><b>幾何柄が目を惹く主役級な1枚</b></font><br>		<br>■素材特性<br>コットンとポリエステルを使用しているので、吸収性が良くサラっと着用いただけます。<br>通気性抜群で、暑くなる季節に重宝すること間違いなし！<br>		<br>■デザイン<br>着映えする幾何柄と、透け感のあるデザインで旬なコーデにピッタリの1着！<br>メイントップスでもボタンを開けて羽織りとしても着用でき、どちらのスタイルでもコーディネートをキメてくれます。<br>夏の日差し除けや冷房対策にもぴったりです◎<br><br>■おすすめスタイリング	<br>インナーにキャミソールやタンクトップを合わせたヘルシーな着こなしがオススメです。<br>存在感のある幾何学柄はデニムやカーゴパンツなどカジュアルなアイテムと好相性です。<br>		<br>ーーー		<br> トップス　幾何柄　ボーダー　シャツ　シアー<br>ーーー', '5000.0 JPY', 305.00, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:22:52', '2026-04-02 04:17:48', 'adastria_328495', '', '69cd72d5a7ab618f2967cade', '生活/休闲', '', '女', '青年（18-44岁）', '涤纶87%,棉13%', 'https://www.dot-st.com/nikoand/disp/item/328495/?COLOR_CD=80', '上装', '衬衫', '休闲衬衫', '', 'casual shirt', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/niko_and/20260401/item_328495_main_80_1748582422_b.jpg', 0, 0, 2, 0.89584, 0, 1, 1, 0, 0, 3, NULL, '透气，吸湿，轻薄，防晒，遮挡空调风', '吸湿,轻薄,防晒,遮挡空调风', '', '几何波浪条纹图案设计，视觉存在感强,面料具有一定透视感，适合叠穿造型,可单穿也可敞开当外搭衬衫使用,适合搭配牛仔和工装风下装，偏休闲风格', '条纹，其他', '商品名称为“幾何柄ボーダーシャツ”，且版型为有领前开扣的短袖上装，明显属于日常穿着的衬衫类单品，并非正式场合用的正装衬衫，因此在列表中选择“casual shirt（休闲衬衫）”最为贴切。其定义为：用于日常休闲搭配的衬衫款上衣。', 0, 0, 0, 0, 'casual shirt', NULL, '', 0, NULL, 0, NULL, NULL, '80', 'ブルー80', 0);
INSERT INTO `clothing_info` VALUES (19996646, '燕尾褶基本款女式上衣', 'ピンタックベーシックブラウス', 0, 200333, 'niko and ...', '', '', '这款夏季上衣采用手感清爽的纯棉面料，穿着轻盈舒适且透气性良好。前后细致的燕尾褶设计突出女性气质，一件即可打造完整造型。下摆向外自然展开，在修饰身形的同时起到良好的体型遮掩效果，从胸部以下的切换线条也有助于拉长比例。简洁百搭的纯色以及清爽的条纹款，适用于多种日常场合，搭配不同裤装即可展现多样造型。', '<font color=\"#379fcc\"><b>いつでもどこでも決まる！マルチな夏ブラウス！</b></font><br><br>■素材特性<br>さらっと着心地のよいコットン素材。<br>通気性が良く快適に着用できます◎<br><br>■デザイン<br>前後のピンタックデザインが女性らしさを演出し1枚でサマになるブラウス♪<br>裾に向かってふわっと広がるシルエットで体形カバーしつつ、胸元からの切り替わりがスタイルアップにも一役◎<br>スタイルを選ばない万能カラーと、爽やかで清涼感があるストライプ柄はシーンレスに活躍してくれること間違いなし！<br><br>■おすすめスタイリング<br>ふわっとシルエットが魅力のブラウスにはパンツスタイルが相性◎<br>ボトムスによって表情を変化するため着回し力抜群です。<br><br>ーーー<br>ブラウス　ピンタック　<br>ーーー', '5000.0 JPY', 305.00, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:22:52', '2026-04-02 04:17:49', 'adastria_425644', '', '69cd72d5a7ab618f2967cae5', '生活/休闲', '', '女', '青年（18-44岁）', '棉100%', 'https://www.dot-st.com/nikoand/disp/item/425644/?COLOR_CD=19', '上装', '衬衫', '女式衬衫', '', 'blouse', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/niko_and/20260401/item_425644_main_19_1746147177_b.jpg', 0, 0, 2, 0.98580, 0, 1, 0, 0, 0, 3, NULL, '透气，舒适穿着，修饰身形，遮盖身材线条', '舒适穿着,修饰身形,遮盖身材线条', '', '前后有细褶装饰设计，增强女性化风格,采用纯棉材质，夏季穿着清爽舒适,下摆向外展开形成伞形轮廓，有较强的体型遮掩效果,提供纯色与条纹款，适合多种日常场景搭配', '条纹', '商品名称为“ピンタックベーシックブラウス”（基本款褶饰衬衫），描述中多次提到“ブラウス”，版型为短袖、女性化上衣，搭配裤装使用，明显属于女式衬衫/上装类别，对应列表中的“blouse”。', 1, 0, 0, 0, 'blouse', NULL, '', 0, NULL, 0, NULL, NULL, '19', 'ブラック(19)', 0);
