INSERT INTO `clothing_info` VALUES (19996648, '透视渐变格纹荷叶短袖衬衫', 'シアーオンブレチェックフリルシャツ', 0, 200333, 'niko and ...', '', '', '采用带有适度光泽感、触感顺滑的轻薄面料，穿着清爽舒适，适合夏季。运用轻盈的透视质感叠加休闲的渐变格纹图案，呈现出兼具优雅与随性的半袖衬衫风格。袖部拼接处点缀立体荷叶装饰，为整体增添适度甜美感与轻松的空气感。在简单造型中也能展现个性与存在感，既可与牛仔单品打造复古休闲气质，也适合作为外搭叠穿在吊带或无袖连衣裙外。', '<font color=\"#fa1460\"><b>程よい透け感で上品な着こなしが叶うシアーチェックシャツ</b></font><br>		<br>■素材特性<br>程よい艶感と滑らかな肌さわりが心地よく、夏でも快適に着用いただけます。<br>		<br>■デザイン<br>軽やかなシアー素材とカジュアルなオンブレチェック柄が上品見えする半袖シャツ。<br>袖の切り替え部分にあしらわれた立体的なフリルが程よい甘さと抜け感をプラス！<br>夏のシンプルスタイルに程よく個性を感じられる一枚です！<br>		<br>■おすすめスタイリング	<br>インディゴデニムに合わせたレトロガーリーなカジュアルスタイルがおすすめです！<br>タンクトップやノースリーブのワンピースに羽織るだけで、ぐっとこなれた印象も。<br>一枚で華やかなチェック柄は、ボトムスをシンプルにまとめるとバランスが◎<br>		<br>ーーー		<br>チェックシャツ　フリル　<br>ーーー', '5000.0 JPY', 305.00, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:22:52', '2026-04-02 04:17:51', 'adastria_323921', '', '69cd72d5a7ab618f2967cae8', '生活/休闲', '', '女', '青年（18-44岁）', '粘胶70%,涤纶30%', 'https://www.dot-st.com/nikoand/disp/item/323921/?COLOR_CD=30', '上装', '衬衫', '女式衬衫', '', 'blouse', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/niko_and/20260401/item_323921_main_30_1747990421_b.jpg', 0, 0, 2, 0.99821, 0, 1, 1, 0, 0, 3, NULL, '透气，轻盈，舒适亲肤', '轻盈,舒适亲肤', '', '半袖设计，适合夏季穿着,肩袖部位有立体褶皱荷叶装饰，增加女性化细节,宽松版型，方便与吊带或无袖连衣裙叠穿,格纹配色具有复古休闲感', '格纹', '从图片和描述看，这是一件女性用的轻薄短袖上衣，有翻领、前门襟排扣、宽松版型，并带有袖部荷叶装饰和格纹图案，更偏向时装衬衫/女式上衣范畴。与列表中“t-shirt”“polo shirt”等基础针织上衣不同，它是有领的梭织衬衫结构；在选项中最接近的是“blouse”，即女式衬衫/雪纺衫类上衣。故选择 sub_category: blouse，定义为：女性穿着的非正式衬衫式上衣，常用轻薄面料与装饰细节。', 1, 0, 0, 0, 'blouse', NULL, '', 0, NULL, 0, NULL, NULL, '30', 'レッド(30)', 0);
INSERT INTO `clothing_info` VALUES (19996649, '透视渐变格纹荷叶短袖衬衫', 'シアーオンブレチェックフリルシャツ', 0, 200333, 'niko and ...', '', '', '采用带有适度光泽感、触感顺滑的轻薄面料，穿着清爽舒适，适合夏季。运用轻盈的透视质感叠加休闲的渐变格纹图案，呈现出兼具优雅与随性的半袖衬衫风格。袖部拼接处点缀立体荷叶装饰，为整体增添适度甜美感与轻松的空气感。在简单造型中也能展现个性与存在感，既可与牛仔单品打造复古休闲气质，也适合作为外搭叠穿在吊带或无袖连衣裙外。', '<font color=\"#fa1460\"><b>程よい透け感で上品な着こなしが叶うシアーチェックシャツ</b></font><br>		<br>■素材特性<br>程よい艶感と滑らかな肌さわりが心地よく、夏でも快適に着用いただけます。<br>		<br>■デザイン<br>軽やかなシアー素材とカジュアルなオンブレチェック柄が上品見えする半袖シャツ。<br>袖の切り替え部分にあしらわれた立体的なフリルが程よい甘さと抜け感をプラス！<br>夏のシンプルスタイルに程よく個性を感じられる一枚です！<br>		<br>■おすすめスタイリング	<br>インディゴデニムに合わせたレトロガーリーなカジュアルスタイルがおすすめです！<br>タンクトップやノースリーブのワンピースに羽織るだけで、ぐっとこなれた印象も。<br>一枚で華やかなチェック柄は、ボトムスをシンプルにまとめるとバランスが◎<br>		<br>ーーー		<br>チェックシャツ　フリル　<br>ーーー', '5000.0 JPY', 305.00, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:22:52', '2026-04-02 04:17:52', 'adastria_323921', '', '69cd72d5a7ab618f2967cae8', '生活/休闲', '', '女', '青年（18-44岁）', '粘胶70%,涤纶30%', 'https://www.dot-st.com/nikoand/disp/item/323921/?COLOR_CD=30', '上装', '衬衫', '女式衬衫', '', 'blouse', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/niko_and/20260401/item_323921_main_71_1747990428_b.jpg', 0, 0, 6, 0.82815, 0, 1, 1, 0, 0, 3, NULL, '透气，轻盈，舒适亲肤', '轻盈,舒适亲肤', '', '半袖设计，适合夏季穿着,肩袖部位有立体褶皱荷叶装饰，增加女性化细节,宽松版型，方便与吊带或无袖连衣裙叠穿,格纹配色具有复古休闲感', '格纹', '从图片和描述看，这是一件女性用的轻薄短袖上衣，有翻领、前门襟排扣、宽松版型，并带有袖部荷叶装饰和格纹图案，更偏向时装衬衫/女式上衣范畴。与列表中“t-shirt”“polo shirt”等基础针织上衣不同，它是有领的梭织衬衫结构；在选项中最接近的是“blouse”，即女式衬衫/雪纺衫类上衣。故选择 sub_category: blouse，定义为：女性穿着的非正式衬衫式上衣，常用轻薄面料与装饰细节。', 1, 1, 0, 0, 'blouse', NULL, '', 0, NULL, 0, NULL, NULL, '71', 'ライム(71)', 0);
INSERT INTO `clothing_info` VALUES (19996642, '荷叶袖格纹女式衬衫上衣', '袖フリルチェックブラウス', 0, 200333, 'niko and ...', '', '', '提升夏日氛围感的荷叶袖格纹女式衬衫上衣。\n\n■ 面料特点\n再生纤维（纤维素）与棉混纺的柔软触感材质，吸湿性和吸水性良好，在闷热天气也能保持舒适。\n\n■ 设计\n轻薄透感的格纹结构为夏日穿搭增加适度的清爽感。蓬松有动感的荷叶袖设计，在修饰手臂的同时成为俏丽亮点。也可作为薄外套式开衫叠穿，适合室内空调环境的温差应对。\n\n■ 搭配建议\n推荐与宽松的阔腿裤组合成休闲造型，脚上搭配凉鞋，作为夏日外出时的亮眼单品。', '<font color=\"#fa843a\"><b>夏のムードを急上昇させるフリルチェックブラウス</b></font><br>		<br>■素材特性<br>再生繊維(セルロース)とコットンをミックスした肌ざわりやわらか素材。<br>吸湿性・吸水性が高く蒸し暑い日でも快適です！<br><br>■デザイン<br>シアーチェック柄が程よい抜け感をプラスしてくれる夏ブラウス！<br>ふわっと動きのある袖フリルデザインは、腕回りをさりげなくカバーしながら可愛いアクセントに！<br>羽織としても使えるので冷房対策にもおすすめ◎<br>		<br>■おすすめスタイリング	<br>ゆったりとしたワイドパンツと合わせたカジュアルコーデがおすすめです。<br>足元はラフにサンダルスタイルで！夏のお出かけにも映える1枚です◎<br><br>ーーー		<br>チェックシャツ　フリル　ブラウス<br>ーーー', '5000.0 JPY', 305.00, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:22:53', '2026-04-02 04:17:46', 'adastria_290570', '', '69cd72d5a7ab618f2967cad8', '生活/休闲', '', '女', '青年（18-44岁）', '棉54%,涤纶8%', 'https://www.dot-st.com/nikoand/disp/item/290570/?COLOR_CD=60', '上装', '衬衫', '女式衬衫', '', 'blouse', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/niko_and/20260401/item_290570_main_60_1750034451_b.jpg', 0, 0, 2, 0.94269, 0, 1, 1, 0, 0, 3, NULL, '透气，吸湿排汗，凉爽舒适，遮臂修饰身形', '凉爽舒适,遮臂修饰身形', '', '使用再生纤维与棉混纺，强调环保与柔软触感,加入少量亚麻提升夏季清凉感和质感,袖部大面积荷叶边设计，增加体积感并修饰手臂线条,轻薄半透明格纹组织营造通透夏日感,可作开衫式外搭，兼具单穿与叠穿功能', '格纹', '从商品名“袖フリルチェックブラウス”和版型来看，这是女性轻薄上衣，前开门襟、有领、纽扣、可单穿也可外搭，典型为“blouse（女式衬衫上衣）”版型，因此选择 sub_category: blouse。其定义为女式上装，通常为织物面料、带门襟或装饰细节的衬衫/上衣款。', 1, 0, 0, 0, 'blouse', NULL, '', 0, NULL, 0, NULL, NULL, '60', 'イエローチェック(60)', 0);
