INSERT INTO `clothing_info` VALUES (19996644, '荷叶袖格纹女式衬衫上衣', '袖フリルチェックブラウス', 0, 200333, 'niko and ...', '', '', '提升夏日氛围感的荷叶袖格纹女式衬衫上衣。\n\n■ 面料特点\n再生纤维（纤维素）与棉混纺的柔软触感材质，吸湿性和吸水性良好，在闷热天气也能保持舒适。\n\n■ 设计\n轻薄透感的格纹结构为夏日穿搭增加适度的清爽感。蓬松有动感的荷叶袖设计，在修饰手臂的同时成为俏丽亮点。也可作为薄外套式开衫叠穿，适合室内空调环境的温差应对。\n\n■ 搭配建议\n推荐与宽松的阔腿裤组合成休闲造型，脚上搭配凉鞋，作为夏日外出时的亮眼单品。', '<font color=\"#fa843a\"><b>夏のムードを急上昇させるフリルチェックブラウス</b></font><br>		<br>■素材特性<br>再生繊維(セルロース)とコットンをミックスした肌ざわりやわらか素材。<br>吸湿性・吸水性が高く蒸し暑い日でも快適です！<br><br>■デザイン<br>シアーチェック柄が程よい抜け感をプラスしてくれる夏ブラウス！<br>ふわっと動きのある袖フリルデザインは、腕回りをさりげなくカバーしながら可愛いアクセントに！<br>羽織としても使えるので冷房対策にもおすすめ◎<br>		<br>■おすすめスタイリング	<br>ゆったりとしたワイドパンツと合わせたカジュアルコーデがおすすめです。<br>足元はラフにサンダルスタイルで！夏のお出かけにも映える1枚です◎<br><br>ーーー		<br>チェックシャツ　フリル　ブラウス<br>ーーー', '5000.0 JPY', 305.00, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:22:53', '2026-04-02 04:17:47', 'adastria_290570', '', '69cd72d5a7ab618f2967cad8', '生活/休闲', '', '女', '青年（18-44岁）', '棉54%,涤纶8%', 'https://www.dot-st.com/nikoand/disp/item/290570/?COLOR_CD=60', '上装', '衬衫', '女式衬衫', '', 'blouse', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/niko_and/20260401/item_290570_main_80_1749085319_b.jpg', 0, 0, 2, 0.99462, 0, 1, 1, 0, 0, 3, NULL, '透气，吸湿排汗，凉爽舒适，遮臂修饰身形', '凉爽舒适,遮臂修饰身形', '', '使用再生纤维与棉混纺，强调环保与柔软触感,加入少量亚麻提升夏季清凉感和质感,袖部大面积荷叶边设计，增加体积感并修饰手臂线条,轻薄半透明格纹组织营造通透夏日感,可作开衫式外搭，兼具单穿与叠穿功能', '格纹', '从商品名“袖フリルチェックブラウス”和版型来看，这是女性轻薄上衣，前开门襟、有领、纽扣、可单穿也可外搭，典型为“blouse（女式衬衫上衣）”版型，因此选择 sub_category: blouse。其定义为女式上装，通常为织物面料、带门襟或装饰细节的衬衫/上衣款。', 1, 2, 0, 0, 'blouse', NULL, '', 0, NULL, 0, NULL, NULL, '80', 'ブルーチェック(80)', 0);
INSERT INTO `clothing_info` VALUES (19996641, '荷叶拼接荷叶下摆T恤', 'フリル切り替えペプラムTシャツ', 0, 200333, 'niko and ...', '', '', '这是一款兼具女性感和休闲感的上衣。采用肌肤触感清爽的100%棉材质，具有良好的透气性和吸湿性，穿着清凉舒适。设计上，荷叶元素不过分甜美，适合成熟休闲风格。伞状的荷叶下摆不显身材曲线，袖部双层荷叶设计可巧妙修饰手臂。在气温升高的季节，一件即可完成造型，是提升日常穿搭质感的单品。搭配宽松牛仔裤可打造中和荷叶甜度的休闲风，变换成铅笔裙或干练长裤，则能胜任办公室穿搭。', '<font color=\"#18b830\"><b>フェミニンとカジュアルのいいとこどりが叶う優秀トップス！</b></font><br><br>■素材特性<br>肌触りがさらっとした綿100%素材。<br>通気性・吸湿性に優れている為、涼しく着ていただけます。<br><br>■デザイン<br>フリルだけど甘すぎないデザインで、大人カジュアルにぴったりの1枚。<br>ペプラムシルエットで体のラインを拾わず、袖のダブルフリルは腕周りをさりげなくカバーしてくれます◎<br>気温が上がるこの時期に、1枚でスタイリングが完成するお洒落アイテムです！<br><br>■おすすめスタイリング<br>ルーズ感のあるデニムを合わせたカジュアルスタイルがおすすめ◎<br>フリルの甘さを中和し、ちょうどよい大人かわいいが叶います！<br>タイトスカートやきれいめパンツに切り替えるとオフィスコーデにも大変身です！<br><br>ーーー<br>プルオーバー　フリル　ペプラム　着回し<br>ーーー<br><br>', '3637.0 JPY', 221.86, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:22:54', '2026-04-02 04:17:45', 'adastria_491112', '', '69cd72d5a7ab618f2967cad6', '生活/休闲', '', '女', '青年（18-44岁）', '棉100%', 'https://www.dot-st.com/nikoand/disp/item/491112/?COLOR_CD=95', '上装', 'T恤', 'T恤', '', 't-shirt', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/niko_and/20260401/item_491112_main_95_1749015929_b.jpg', 0, 0, 6, 0.50754, 0, 1, 1, 0, 0, 3, NULL, '透气，吸湿排汗，凉爽舒适，遮掩身形线条，修饰手臂线条', '凉爽舒适,遮掩身形线条,修饰手臂线条', '', '上身为T恤针织面料，下摆为布帛拼接形成荷叶边与伞摆轮廓,采用全棉为主的材质，提升肌肤触感与透气性,双层荷叶袖设计增强女性化装饰效果,宽松剪裁，不贴身，适合日常通勤与休闲穿着', '纯色', '从版型和款式看，这是圆领短袖、上身为针织T恤结构、下摆做荷叶拼接形成伞形廓形的“ペプラムTシャツ”，属于典型的时尚款T恤，因此选择子类目为 t-shirt。t-shirt 的定义是以针织T恤结构为主、套头、短袖或长袖的上衣，本款完全符合。', 0, 0, 0, 0, 't-shirt', NULL, '', 0, NULL, 0, NULL, NULL, '95', 'ラベンダー95', 0);
INSERT INTO `clothing_info` VALUES (19996639, '【wiggle wiggle】联名 多款图案衬衫', '【wiggle wiggle(ウィグルウィグル)】コラボ アソートパターンシャツ', 0, 200333, 'niko and ...', '', '', '这是一款与韩国多彩趣味生活方式品牌 wiggle wiggle 首次联名的衬衫。面料具有良好的垂坠感，手感柔软细腻。整体印有 wiggle wiggle 标志性的快乐感满版图案，不同配色上点缀热带多彩水果、可爱有趣的玉米片元素、啤酒和薯片等主题，充满玩味与个性。廓形宽松，可以作为中性款穿着，不同衣长的 M、L 尺码适合多种身形。可与短裤、凉鞋搭配，打造夏日休闲度假风造型，也可以叠穿在 T 恤外，营造时髦层次感，适合与朋友或伴侣成套或错纹搭配穿着。', '<font color=\"#f734c3\"><b>wiggle wiggle meets niko and ...<br>カラフルでポップなライフスタイルブランドとの初コラボ！</b></font><br>■素材特性<br>落ち感のある柔らかくしなやかな手触りが特徴です。<br><br>■デザイン<br>wiggle wiggleらしいハッピーな総柄をプリントしたユニークで楽しいシャツ。<br>トロピカルでカラフルなフルーツや、ポップでキュートなコーンフレークモチーフ、ビールとポテトチップスの最高の組み合わせなどカラーによってこだわりポイントがいっぱい◎<br>ゆったりとしたシルエットで、丈感の違うM、L展開はユニセックスとしても着用いただけます。<br><br>■おすすめスタイリング<br>ショートパンツやサンダルと合わせた、夏らしいカジュアルなリゾートスタイルが◎<br>Tシャツの上に羽織ったレイヤードスタイルで今っぽく仕上げるのも！<br>友達やパートナーとおそろいや柄違いで着るのもおすすめです！<br><br><font color=\"#f734c3\"><b>【wiggle wiggle(ウィグルウィグル)】コラボアイテム一覧はこちら</b></font><br><a href=\"adastriaapp://items?dispNo=0000100016_002001602&orderBy=00\" target=\"_blank\"><b>>>アプリ版</b></a><br><a href=\"https://www.dot-st.com/nikoand/disp/itemlist/?dispNo=002001602\" target=\"_blank\"><b>>>ブラウザ版</b></a><br><br>【wiggle wiggle(ウィグルウィグル)】<br>韓国で誕生したライフスタイルブランドです。<br> \"Maximal HAPPINESS\"をテーマに、ファッション雑貨やスマホアクセサリー、インテリア小物など、カラフルで遊び心あふれるアイテムを展開。<br>日常に楽しさや鮮やかさを添える独自のスタイルで、Z世代から30代を中心に、幅広い層から支持されています。<br>他にはない大胆なカラーリングと、感性に響くユニークなデザインで、いつもの日常にわくわくする気分をプラス。 <br>心がはずむような“かわいい”を通して、wiggle wiggleのハッピーな世界をCheck！！<br><br>ーーー<br>wiggle wiggle　コラボ　シャツ　柄シャツ　羽織　レイヤード<br>ーーー', '6364.0 JPY', 388.20, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:22:57', '2026-04-02 04:17:43', 'adastria_451751', '', '69cd72d5a7ab618f2967cad4', '生活/休闲', '', '通用', '青年（18-44岁）', '粘胶100%', 'https://www.dot-st.com/nikoand/disp/item/451751/?COLOR_CD=19', '上装', '衬衫', '休闲衬衫', '', 'casual shirt', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/niko_and/20260401/item_451751_main_19_1746095205_b.jpg', 0, 0, 2, 0.95809, 0, 1, 1, 0, 0, 3, NULL, '垂坠感好，手感柔软顺滑，版型宽松舒适，适合叠穿造型，度假风穿搭友好', '垂坠感好,手感柔软顺滑,版型宽松舒适,适合叠穿造型,度假风穿搭友好', '', '与wiggle wiggle品牌联名合作,整体为缤纷有趣的食物主题图案设计,适合与朋友或伴侣进行情侣装或团体搭配,提供不同衣长的M、L尺码以满足中性穿着需求', '食品/饮料，物体', '从商品名称“アソートパターンシャツ”和描述中的“シャツ”“羽織”可以看出，这是日常穿着的休闲衬衫款式，非正装衬衫也非T恤类。版型宽松、短袖、可作为开衫式外搭，符合“casual shirt（休闲衬衫）”的定义，即用于日常休闲场景的衬衫类上衣。', 1, 0, 0, 0, 'casual shirt', NULL, '', 0, NULL, 0, NULL, NULL, '19', 'ブラック(19)', 0);
INSERT INTO `clothing_info` VALUES (19996640, '【wiggle wiggle】联名 多款图案衬衫', '【wiggle wiggle(ウィグルウィグル)】コラボ アソートパターンシャツ', 0, 200333, 'niko and ...', '', '', '这是一款与韩国多彩趣味生活方式品牌 wiggle wiggle 首次联名的衬衫。面料具有良好的垂坠感，手感柔软细腻。整体印有 wiggle wiggle 标志性的快乐感满版图案，不同配色上点缀热带多彩水果、可爱有趣的玉米片元素、啤酒和薯片等主题，充满玩味与个性。廓形宽松，可以作为中性款穿着，不同衣长的 M、L 尺码适合多种身形。可与短裤、凉鞋搭配，打造夏日休闲度假风造型，也可以叠穿在 T 恤外，营造时髦层次感，适合与朋友或伴侣成套或错纹搭配穿着。', '<font color=\"#f734c3\"><b>wiggle wiggle meets niko and ...<br>カラフルでポップなライフスタイルブランドとの初コラボ！</b></font><br>■素材特性<br>落ち感のある柔らかくしなやかな手触りが特徴です。<br><br>■デザイン<br>wiggle wiggleらしいハッピーな総柄をプリントしたユニークで楽しいシャツ。<br>トロピカルでカラフルなフルーツや、ポップでキュートなコーンフレークモチーフ、ビールとポテトチップスの最高の組み合わせなどカラーによってこだわりポイントがいっぱい◎<br>ゆったりとしたシルエットで、丈感の違うM、L展開はユニセックスとしても着用いただけます。<br><br>■おすすめスタイリング<br>ショートパンツやサンダルと合わせた、夏らしいカジュアルなリゾートスタイルが◎<br>Tシャツの上に羽織ったレイヤードスタイルで今っぽく仕上げるのも！<br>友達やパートナーとおそろいや柄違いで着るのもおすすめです！<br><br><font color=\"#f734c3\"><b>【wiggle wiggle(ウィグルウィグル)】コラボアイテム一覧はこちら</b></font><br><a href=\"adastriaapp://items?dispNo=0000100016_002001602&orderBy=00\" target=\"_blank\"><b>>>アプリ版</b></a><br><a href=\"https://www.dot-st.com/nikoand/disp/itemlist/?dispNo=002001602\" target=\"_blank\"><b>>>ブラウザ版</b></a><br><br>【wiggle wiggle(ウィグルウィグル)】<br>韓国で誕生したライフスタイルブランドです。<br> \"Maximal HAPPINESS\"をテーマに、ファッション雑貨やスマホアクセサリー、インテリア小物など、カラフルで遊び心あふれるアイテムを展開。<br>日常に楽しさや鮮やかさを添える独自のスタイルで、Z世代から30代を中心に、幅広い層から支持されています。<br>他にはない大胆なカラーリングと、感性に響くユニークなデザインで、いつもの日常にわくわくする気分をプラス。 <br>心がはずむような“かわいい”を通して、wiggle wiggleのハッピーな世界をCheck！！<br><br>ーーー<br>wiggle wiggle　コラボ　シャツ　柄シャツ　羽織　レイヤード<br>ーーー', '6364.0 JPY', 388.20, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:22:57', '2026-04-02 04:17:44', 'adastria_451751', '', '69cd72d5a7ab618f2967cad4', '生活/休闲', '', '通用', '青年（18-44岁）', '粘胶100%', 'https://www.dot-st.com/nikoand/disp/item/451751/?COLOR_CD=19', '上装', '衬衫', '休闲衬衫', '', 'casual shirt', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/niko_and/20260401/item_451751_main_62_1746095192_b.jpg', 0, 0, 2, 0.97662, 0, 1, 1, 0, 0, 3, NULL, '垂坠感好，手感柔软顺滑，版型宽松舒适，适合叠穿造型，度假风穿搭友好', '垂坠感好,手感柔软顺滑,版型宽松舒适,适合叠穿造型,度假风穿搭友好', '', '与wiggle wiggle品牌联名合作,整体为缤纷有趣的食物主题图案设计,适合与朋友或伴侣进行情侣装或团体搭配,提供不同衣长的M、L尺码以满足中性穿着需求', '食品/饮料，物体', '从商品名称“アソートパターンシャツ”和描述中的“シャツ”“羽織”可以看出，这是日常穿着的休闲衬衫款式，非正装衬衫也非T恤类。版型宽松、短袖、可作为开衫式外搭，符合“casual shirt（休闲衬衫）”的定义，即用于日常休闲场景的衬衫类上衣。', 1, 1, 0, 0, 'casual shirt', NULL, '', 0, NULL, 0, NULL, NULL, '62', 'クリーム(62)', 0);
INSERT INTO `clothing_info` VALUES (19996637, '天鹅绒蝴蝶结带胸杯吊带背心', 'ベロアリボンカップ付きキャミソール', 0, 200333, 'niko and ...', '', '', '这是一款兼具设计感与舒适度的成熟女性吊带背心。采用具有柔和光泽和细腻触感的天鹅绒面料，上品的贝罗阿材质带来丰富而高级的视觉效果，并配有内置胸杯。肩部点缀纤细的蝴蝶结，突显女性气质。高质感面料与细节设计，使其既适合作为内搭单品，也可以单穿打造成熟风格造型。可搭配牛仔裤或工装裤等休闲下装，营造平衡感造型，也适合与透视衬衫或蕾丝开衫叠穿，呈现轻松而优雅的办公室风格。', '<font color=\"#0d6ef7\"><b>デザイン性と着心地の良さを両立させたオトナのキャミソール</b></font><br>		<br>■素材特性<br>柔らかな光沢と肌触りが特徴のベロア素材です。<br><br>■デザイン<br>上品なベロア素材がリッチな印象を演出してくれるカップ付きキャミソール。<br>肩にあしらわれた華奢なリボンが、女性らしさを引き立てるアクセントに。<br>上質な素材とディテールはインナーとしてはもちろん、あえて一枚で着たオトナスタイリングが◎<br>		<br>■おすすめスタイリング	<br>デニムやカーゴパンツなどのカジュアルなボトムスを合わせるとバランスよくまとまります◎<br>シアーシャツやレースカーディガンと合わせて、抜け感のある上品なオフィススタイリングにも！<br>		<br>ーーー		<br>カップ付きキャミ　ベロアキャミ<br>ーーー', '2728.0 JPY', 166.41, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:22:58', '2026-04-02 04:17:42', 'adastria_491114', '', '69cd72d5a7ab618f2967cad0', '生活/休闲', '', '女', '青年（18-44岁）', '棉80%,涤纶20%', 'https://www.dot-st.com/nikoand/disp/item/491114/?COLOR_CD=15', '上装', '背心', '吊带背心', '', 'camisole', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/niko_and/20260401/item_491114_main_15_1751851832_b.jpg', 0, 0, 6, 0.69413, 0, 1, 1, 0, 0, 3, NULL, '内置胸杯，修饰身形，提升女性化气质，适合作为打底或单穿', '内置胸杯,修饰身形,提升女性化气质,适合作为打底或单穿', '', '采用具有柔和光泽感的贝罗阿面料,肩部细窄吊带并在肩上系蝴蝶结装饰,自带胸杯设计无需另穿文胸,既可作为内搭也可单穿打造成熟女性风格,适合与牛仔裤或工装裤搭配形成休闲混搭感,可与薄纱衬衫或蕾丝开衫叠穿以增加造型层次', '纯色', '该单品为细肩带、无袖、贴身剪裁且自带胸杯的上衣，商品名中注明“カップ付きキャミソール”，明显属于内外皆可穿的吊带背心类型，因此选择子类目“camisole（吊带背心）”。camisole 指的是细肩带、通常贴身、可作内衣或外穿上衣的款式。', 1, 0, 0, 0, 'camisole', NULL, '', 0, NULL, 0, NULL, NULL, '15', 'グレー(15)', 0);
