INSERT INTO `clothing_info` VALUES (19996635, '网纱叠穿感花卉照片印花T恤', 'チュールレイヤーフラワーフォトTシャツ', 0, 200333, 'niko and ...', '', '', '一件即可穿出特别感的叠穿风T恤。采用柔软、肌肤触感良好的纯棉面料，外层拼接带有透视感的网纱。简洁大人感的照片风花卉图案与网纱的组合，为日常造型增添层次与时髦感。飘逸轻盈的网纱让整体在休闲风格中多了一些灵动与洒脱，是兼具“流行感”和“经典感”的个性设计上衣。适合搭配彩色裤装和运动鞋打造随性休闲造型，也可与简约下装、配饰或夏日感包袋组合，让上衣成为造型焦点。关键词：网纱单品、叠穿风、前幅印花、拼接设计。', '<font color=\"#07d143\"><b>一枚で特別感を味わえるレイヤード風Tシャツ</b></font><br>		<br>■素材特性<br>柔らかく肌触りの良いコットンと、透け感のあるチュール素材を使用しています。<br>		<br>■デザイン<br>シンプルでオトナなグラフィック×チュールの組み合わせがいつものスタイリングを格上げしてくれるTシャツ。<br>ひらりと揺れるチュールはカジュアルテイストにほどよく抜け感をプラスしてくれます。<br>一枚でサマになるちょっと個性派なデザイントップスは\"今っぽさ\"と\"定番\"のいいとこどりアイテムです◎<br><br>■おすすめスタイリング	<br>こなれカジュアルなスタイリングにはカラーパンツやスニーカーで思いっきりラフなアイテムを！<br>トップスを主役にしたシンプルなボトムスを合わせた日は、アクセサリーや夏っぽいバッグでアクセントをプラスしてみては♪<br>		<br>ーーー		<br>チュールアイテム　レイヤード風　フロントプリント　ドッキング<br>ーーー', '4091.0 JPY', 249.55, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:23:52', '2026-04-02 04:17:40', 'adastria_492901', '', '69cd72d5a7ab618f2967cac4', '生活/休闲', '', '女', '青年（18-44岁）', '棉100%', 'https://www.dot-st.com/nikoand/disp/item/492901/?COLOR_CD=15', '上装', 'T恤', 'T恤', '', 't-shirt', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/niko_and/20260401/item_492901_main_15_1750903411_b.jpg', 0, 0, 2, 0.65222, 0, 1, 1, 0, 0, 3, NULL, '透气，舒适亲肤，时尚造型', '舒适亲肤,时尚造型', '', '前幅花卉照片感印花图案,外层层叠轻薄网纱营造飘逸效果,T恤与网纱一体式拼接设计,适合日常休闲与夏季穿搭', '花卉图案，文字', '从图片和描述来看，该产品为短袖圆领、宽松版型的上衣，主体材质为棉质针织面料，搭配外层一圈飘逸的“チュール”（网纱）做叠穿效果，但内里结构仍是典型T恤版型，有前幅印花，适合作为日常休闲上装穿着，因此最合适的品类是“t-shirt（T恤）”。t-shirt 的定义是以针织面料为主、具备T恤基础版型的休闲上衣，本款完全符合。', 1, 0, 0, 0, 't-shirt', NULL, '', 0, NULL, 0, NULL, NULL, '15', 'グレー(15)', 0);
