INSERT INTO `clothing_info` VALUES (19996632, '荷叶边透视蝴蝶结背心', 'フリルシアーリボンベスト', 0, 200333, 'niko and ...', '', '', '低调荷叶边点缀的大人甜美风百搭背心。采用兼具粘胶纤维柔软触感与聚酯纤维轻盈感的面料，既有自然质感，又不失优雅气质。只需叠穿在简单的T恤或衬衫外，就能瞬间提升造型的华丽感。前中心蝴蝶结系带与克制的荷叶边细节，为整体增添不过分甜腻的成熟女性气质。提供黑色与白色基础色，便于与各种单品自由搭配，是日常穿搭中实用的加分单品。', '<font color=\"lightcoral\"><b>控えめフリルが大人可愛い、着回し自在の万能ベスト</b></font><br><br>■素材特性<br>レーヨンの柔らかさとポリエステルの軽やかさを合わせた素材感。<br>ナチュラル感がありつつ、上品な雰囲気で着て頂けます。<br><br>■デザイン<br>シンプルなTシャツやブラウスに重ねるだけで一気に華やかな印象に。<br>フロントのリボンと控えめなフリルが、甘さを抑えた大人フェミニンさをプラスします◎<br>ブラックとホワイトのベーシックカラーで、どんなコーデにも合わせやすい一枚です！<br><br>■おすすめスタイリング<br>カットソーからブラウスまで、様々なトップスに合う万能アイテム。<br>パンツの色や柄で変化をつけたスタイリングもおすすめです◎<br><br>ーーー<br>ベスト　フリル　リボン　シアー　プラスワンアイテム<br>ーーー', '4546.0 JPY', 277.31, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:23:54', '2026-04-02 04:17:37', 'adastria_496098', '', '69cd72d5a7ab618f2967cabf', '生活/休闲', '', '女', '青年（18-44岁）', '粘胶78%,涤纶22%', 'https://www.dot-st.com/nikoand/disp/item/496098/?COLOR_CD=10', '上装', '背心', '马甲背心', '', 'vest', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/niko_and/20260401/item_496098_main_10_1747995177_b.jpg', 0, 0, 6, 0.66577, 0, 1, 1, 0, 0, 3, NULL, '易于叠穿，增加造型层次感', '易于叠穿,增加造型层次感', '', '前中系带蝴蝶结设计,下摆荷叶边装饰,面料具有轻薄微透视效果,基础黑白配色，易于搭配,适合叠穿在T恤或衬衫外', '纯色', '根据商品名“フリルシアーリボンベスト”和图片可见，这是无袖开前、用于叠穿的上衣，不是连衣裙或围巾类，也不是功能性内衣，最符合“vest（背心/马甲类上衣）”。该款为轻薄外搭马甲式上衣。\n\n选择的子类：vest\n该子类的定义：无袖、覆盖上身躯干、可单穿或叠穿在其他上衣外的服装款式，常用于造型叠搭或轻度保暖。', 0, 0, 0, 0, 'vest', NULL, '', 0, NULL, 0, NULL, NULL, '10', 'ホワイト(10)', 0);
INSERT INTO `clothing_info` VALUES (19996633, '荷叶饰带法式袖女式衬衫上衣', 'フリルテープフレンチブラウス', 0, 200333, 'niko and ...', '', '', '这是一款既显得利落得体又具有蓬松舒适穿着感的夏季棉质上衣。采用轻盈柔软的100%纯棉面料，带来轻快透气的穿着体验。胸前点缀低调的荷叶饰带，作为优雅的视觉亮点，营造成熟女性的柔美气质。整体为法式袖设计，既保持清爽感，又有一定遮臂效果。适合在夏季作为一件即可提升造型的上衣，也可以敞开前襟，叠穿在印花或字母T恤、背心外，打造随性有层次感的穿搭风格。', '<font color=\"#ffa200\"><b>きちんと見えて、ふんわり着心地の良い夏ブラウス</b></font><br>		<br>■素材特性<br>軽やかでふんわりとした綿100％素材です。<br>		<br>■デザイン<br>控えめなフリルテープが上品なアクセントに！オトナフェミニンなフレンチスリーブブラウス。<br>同素材で施された主張しすぎないフリルデザインは、きちんと感と女性らしさを両立させるバランスの良いデザインです◎<br>一枚で着映えするのに頑張りすぎていない、これからのシーズンに頼れる一枚です！<br>		<br>■おすすめスタイリング	<br>夏のワントーンコーデでまとめたオトナのお出かけスタイルがおすすめです！<br>あえて前を開けてロゴTシャツやタンクトップの上から羽織ったレイヤードコーデも◎<br>		<br>ーーー		<br>フリルブラウス　レイヤード　羽織<br>ーーー', '5455.0 JPY', 332.75, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:23:54', '2026-04-02 04:17:38', 'adastria_492900', '', '69cd72d5a7ab618f2967cac5', '生活/休闲', '', '女', '青年（18-44岁）', '棉100%', 'https://www.dot-st.com/nikoand/disp/item/492900/?COLOR_CD=19', '上装', '衬衫', '女式衬衫', '', 'blouse', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/niko_and/20260401/item_492900_main_19_1749085760_b.jpg', 0, 0, 2, 0.97976, 0, 1, 1, 0, 0, 3, NULL, '透气，舒适穿着，轻盈，修饰身形，易于搭配', '舒适穿着,轻盈,修饰身形,易于搭配', '', '采用100%纯棉面料，质地轻盈柔软，适合夏季穿着,前幅加入同色系褶皱荷叶装饰，增加纵向线条感与设计感,法式袖设计，兼顾清凉感与上臂遮饰效果,版型略宽松，营造轻松不紧绷的上身效果,可单穿也可作为开襟小外搭叠穿，造型方式多样', '纯色', '从商品名“フリルテープフレンチブラウス”和描述中的“フレンチスリーブブラウス”可以确定是女士上装衬衫类单品，带门襟纽扣、可单穿或作为开襟小外搭，面料为梭织棉而非针织T恤，因此更符合“blouse（女式衬衫/上衣）”的定义，而不是t-shirt或衬衫等其他类别。', 1, 0, 0, 0, 'blouse', NULL, '', 0, NULL, 0, NULL, NULL, '19', 'ブラック(19)', 0);
INSERT INTO `clothing_info` VALUES (19996634, '荷叶饰带法式袖女式衬衫上衣', 'フリルテープフレンチブラウス', 0, 200333, 'niko and ...', '', '', '这是一款既显得利落得体又具有蓬松舒适穿着感的夏季棉质上衣。采用轻盈柔软的100%纯棉面料，带来轻快透气的穿着体验。胸前点缀低调的荷叶饰带，作为优雅的视觉亮点，营造成熟女性的柔美气质。整体为法式袖设计，既保持清爽感，又有一定遮臂效果。适合在夏季作为一件即可提升造型的上衣，也可以敞开前襟，叠穿在印花或字母T恤、背心外，打造随性有层次感的穿搭风格。', '<font color=\"#ffa200\"><b>きちんと見えて、ふんわり着心地の良い夏ブラウス</b></font><br>		<br>■素材特性<br>軽やかでふんわりとした綿100％素材です。<br>		<br>■デザイン<br>控えめなフリルテープが上品なアクセントに！オトナフェミニンなフレンチスリーブブラウス。<br>同素材で施された主張しすぎないフリルデザインは、きちんと感と女性らしさを両立させるバランスの良いデザインです◎<br>一枚で着映えするのに頑張りすぎていない、これからのシーズンに頼れる一枚です！<br>		<br>■おすすめスタイリング	<br>夏のワントーンコーデでまとめたオトナのお出かけスタイルがおすすめです！<br>あえて前を開けてロゴTシャツやタンクトップの上から羽織ったレイヤードコーデも◎<br>		<br>ーーー		<br>フリルブラウス　レイヤード　羽織<br>ーーー', '5455.0 JPY', 332.75, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:23:54', '2026-04-02 04:17:39', 'adastria_492900', '', '69cd72d5a7ab618f2967cac5', '生活/休闲', '', '女', '青年（18-44岁）', '棉100%', 'https://www.dot-st.com/nikoand/disp/item/492900/?COLOR_CD=19', '上装', '衬衫', '女式衬衫', '', 'blouse', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/niko_and/20260401/item_492900_main_11_1751589849_b.jpg', 0, 0, 2, 0.95909, 0, 1, 1, 0, 0, 3, NULL, '透气，舒适穿着，轻盈，修饰身形，易于搭配', '舒适穿着,轻盈,修饰身形,易于搭配', '', '采用100%纯棉面料，质地轻盈柔软，适合夏季穿着,前幅加入同色系褶皱荷叶装饰，增加纵向线条感与设计感,法式袖设计，兼顾清凉感与上臂遮饰效果,版型略宽松，营造轻松不紧绷的上身效果,可单穿也可作为开襟小外搭叠穿，造型方式多样', '纯色', '从商品名“フリルテープフレンチブラウス”和描述中的“フレンチスリーブブラウス”可以确定是女士上装衬衫类单品，带门襟纽扣、可单穿或作为开襟小外搭，面料为梭织棉而非针织T恤，因此更符合“blouse（女式衬衫/上衣）”的定义，而不是t-shirt或衬衫等其他类别。', 1, 1, 0, 0, 'blouse', NULL, '', 0, NULL, 0, NULL, NULL, '11', 'オフ(11)', 0);
INSERT INTO `clothing_info` VALUES (19996631, '拼接印花双拉链T恤', 'アソートプリントダブルZIPTシャツ', 0, 200333, 'niko and ...', '', '', '采用触感柔软的100%纯棉面料，穿着舒适，兼具良好的透气性与速干性，适合暖季穿着。前身配有双向拉链，并搭配品牌感的复古风英文字母印花，充满俏皮与玩味。侧边加入褶裥设计，营造立体感与有收放对比的轮廓。既可以敞开当作外搭，也能利用双拉链调节贴合度和造型，是夏日穿搭中既有个性又实穿的一件单品。适合与牛仔裤或裙装搭配，为简约夏季造型增添独特风格。', '<font color=\"#f5278e\"><b>無邪気な遊び心をちりばめたダブルジップTシャツ！ </b></font><br><br>■素材特性<br>着心地やわらかなコットン100％素材。<br>通気性、速乾性に優れていてこれからの時期に快適に使用いただけます！<br><br>■デザイン<br>ダブルジップとニコアンドらしいビンテージ風なプリントを施した遊び心の詰まった1枚！<br>サイドにタックが入っていることで立体感があり、メリハリあるシルエットが◎<br>ジップを開けた羽織りとしての着方はもちろん、ダブルジップのため体型・着心地に合わせてフィット感を調整できるのも魅力です。<br><br>■おすすめスタイリング<br>デニム素材のボトムスと合わせたメンズライクや、スカートと合わせたスタイリッシュなスタイリングと相性◎<br>シンプルになりやすい夏コーデに、ちょっと人とは違う“らしさ”を楽しめるアイテムです！<br><br>ーーー<br>Tシャツ　半袖　ダブルジップ　プリント<br>ーーー', '4546.0 JPY', 277.31, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:23:55', '2026-04-02 04:17:37', 'adastria_496214', '', '69cd72d5a7ab618f2967cac0', '生活/休闲', '', '通用', '青年（18-44岁）', '棉100%', 'https://www.dot-st.com/nikoand/disp/item/496214/?COLOR_CD=51', '上装', 'T恤', 'T恤', '', 't-shirt', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/niko_and/20260401/item_496214_main_51_1748929645_b.jpg', 0, 0, 2, 0.83731, 0, 1, 1, 0, 0, 3, NULL, '透气，速干，舒适穿着，版型立体有型', '舒适穿着,版型立体有型', '', '前中双向拉链设计，可根据体型与喜好调节松紧与开合方式,侧边褶裥设计增强立体感与轮廓感,前身具有复古风格英文字母图案印花,适合搭配牛仔裤或裙装，兼顾休闲与时尚感', '字母', '从商品名“ダブルZIPTシャツ”和描述中的“Tシャツ　半袖　ダブルジップ　プリント”可以明确看出这是短袖上衣，版型与功能均为典型T恤，只是前门襟加入双向拉链设计，因此归类为“t-shirt（T恤）”最为准确。t-shirt 的定义：一般指针织面料制作、套头或前开、短袖或长袖的休闲上衣，本款完全符合这一特征。', 0, 0, 0, 0, 't-shirt', NULL, '', 0, NULL, 0, NULL, NULL, '51', 'オートミール(51)', 0);
INSERT INTO `clothing_info` VALUES (19996629, '【WILLIAM B.ELIOTT】蕾丝拼接裹身半裙', '【WILLIAM B.ELIOTT】レーシーラップスカート', 0, 200333, 'niko and ...', '', '', '“WILLIAM B.ELIOTT”全新25SS第二弹系列登场。\n\n■ 面料特性  \n结合了棉的柔软质感和尼龙的轻盈特性。\n\n■ 设计  \n以两种风格各异的蕾丝如同拼布般组合而成的裹身半裙。  \n不仅可以系在腰间作为裙装，也可以像束胸上衣一样变换穿法，是提升搭配感的加分单品。  \n配色为具有复古气息的米白色与成熟感的棕色两种。\n\n■ 穿搭建议  \n只需叠穿在裤装外即可享受更高级的时髦层次感。  \n推荐利用其透视感，与牛仔裤等下装搭配。\n\n【WILLIAM B.ELIOTT】  \n通过表现时间流逝之美学，将男性的力量感与女性的高雅气质融合的新品牌。  \n在融入传统男装元素设计的同时注入现代气息，为拥有不受流行左右、具备独到审美的女性推出系列单品。', '<font color=\"#e9967a\"><b>「WILLIAM B.ELIOTT」待望の第2弾25SSコレクションが登場</b></font><br><br>■素材特性<br>コットンの柔らかな風合い、ナイロンの軽さが魅力です。<br><br>■デザイン<br>2種類の表情の異なるレースをパッチワークのように組み合わせた巻きスカートです。<br>腰に巻くだけでなく、ビスチェのようにアレンジができるプラスワンアイテム◎<br>カラーはヴィンテージ感のあるアイボリーと大人っぽいブラウンの２色展開です！<br><br>■おすすめスタイリング<br>パンツの上からレイヤードするだけでワンランク上のお洒落が楽しめます。<br>透け感を活かしてデニムパンツと合わせるのがおすすめ◎<br><br><font color=\"#e9967a\"><b>【WILLIAM B.ELIOTT(ウィリアムビーエリオット)】アイテム一覧はこちら</b></font><br><a href=\"adastriaapp://items?dispNo=0000100016_002001595&orderBy=00\" target=\"_blank\"><b>>>アプリ版</b></font></a><br><a href=\"https://www.dot-st.com/nikoand/disp/itemlist/?dispNo=002001595\"_blank\"><b>>>ブラウザ版</b></font></a><br><br>【WILLIAM B.ELIOTT】<br>時間の経過の美学を表現し、男性的な力強さと女性的な高雅さが融合した新ブランド「WILLIAM B.ELIOTT」。<br>トラディショナルなメンズアイテムの意匠を取り入れながらも現代的な空気感を纏ったアイテムを、流行にとらわれない確かな審美眼を持った女性に向けて展開します。<br><br>ーーー<br>WILLIAM B.ELIOTT　ウィリアムビーエリオット　スカート　ラップスカート<br>ーーー', '5455.0 JPY', 332.75, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:23:57', '2026-04-02 04:17:35', 'adastria_234896', '', '69cd72d5a7ab618f2967cab9', '生活/休闲', '', '女', '青年（18-44岁）', '棉78%,锦纶22%', 'https://www.dot-st.com/nikoand/disp/item/234896/?COLOR_CD=11', '裙装', '半身裙', '半身裙', '', 'skirt', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/niko_and/20260401/item_234896_main_11_1747102180_b.jpg', 0, 0, 2, 0.99781, 0, 1, 0, 0, 0, 3, NULL, '透气，轻盈，装饰性强，可多种穿法/搭配方式', '轻盈,装饰性强,可多种穿法/搭配方式', '', '采用两种不同风格的蕾丝拼接，具有复古感和层次感,可作为围裹式半裙，也可上身当作类似束胸/小上衣造型,推荐与牛仔裤、长裤叠穿，利用蕾丝的透视效果,整体风格融合中性力量感与女性优雅气质', '花卉图案', '商品名称为“レーシーラップスカート”，日文说明中多次提到“巻きスカート”“スカート ラップスカート”，且图片中也显示为系带式半身裙，主要穿法是围在腰部进行下装叠穿，因此归类为“skirt（半身裙）”。skirt 的定义为：穿在腰部以下的下装服饰，可为直筒或围裹式等各种款式，本品正符合该类别。', 1, 0, 0, 0, 'skirt', NULL, '', 0, NULL, 0, NULL, NULL, '11', 'オフ11', 0);
INSERT INTO `clothing_info` VALUES (19996630, '【WILLIAM B.ELIOTT】蕾丝拼接裹身半裙', '【WILLIAM B.ELIOTT】レーシーラップスカート', 0, 200333, 'niko and ...', '', '', '“WILLIAM B.ELIOTT”全新25SS第二弹系列登场。\n\n■ 面料特性  \n结合了棉的柔软质感和尼龙的轻盈特性。\n\n■ 设计  \n以两种风格各异的蕾丝如同拼布般组合而成的裹身半裙。  \n不仅可以系在腰间作为裙装，也可以像束胸上衣一样变换穿法，是提升搭配感的加分单品。  \n配色为具有复古气息的米白色与成熟感的棕色两种。\n\n■ 穿搭建议  \n只需叠穿在裤装外即可享受更高级的时髦层次感。  \n推荐利用其透视感，与牛仔裤等下装搭配。\n\n【WILLIAM B.ELIOTT】  \n通过表现时间流逝之美学，将男性的力量感与女性的高雅气质融合的新品牌。  \n在融入传统男装元素设计的同时注入现代气息，为拥有不受流行左右、具备独到审美的女性推出系列单品。', '<font color=\"#e9967a\"><b>「WILLIAM B.ELIOTT」待望の第2弾25SSコレクションが登場</b></font><br><br>■素材特性<br>コットンの柔らかな風合い、ナイロンの軽さが魅力です。<br><br>■デザイン<br>2種類の表情の異なるレースをパッチワークのように組み合わせた巻きスカートです。<br>腰に巻くだけでなく、ビスチェのようにアレンジができるプラスワンアイテム◎<br>カラーはヴィンテージ感のあるアイボリーと大人っぽいブラウンの２色展開です！<br><br>■おすすめスタイリング<br>パンツの上からレイヤードするだけでワンランク上のお洒落が楽しめます。<br>透け感を活かしてデニムパンツと合わせるのがおすすめ◎<br><br><font color=\"#e9967a\"><b>【WILLIAM B.ELIOTT(ウィリアムビーエリオット)】アイテム一覧はこちら</b></font><br><a href=\"adastriaapp://items?dispNo=0000100016_002001595&orderBy=00\" target=\"_blank\"><b>>>アプリ版</b></font></a><br><a href=\"https://www.dot-st.com/nikoand/disp/itemlist/?dispNo=002001595\"_blank\"><b>>>ブラウザ版</b></font></a><br><br>【WILLIAM B.ELIOTT】<br>時間の経過の美学を表現し、男性的な力強さと女性的な高雅さが融合した新ブランド「WILLIAM B.ELIOTT」。<br>トラディショナルなメンズアイテムの意匠を取り入れながらも現代的な空気感を纏ったアイテムを、流行にとらわれない確かな審美眼を持った女性に向けて展開します。<br><br>ーーー<br>WILLIAM B.ELIOTT　ウィリアムビーエリオット　スカート　ラップスカート<br>ーーー', '5455.0 JPY', 332.75, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:23:57', '2026-04-02 04:17:36', 'adastria_234896', '', '69cd72d5a7ab618f2967cab9', '生活/休闲', '', '女', '青年（18-44岁）', '棉78%,锦纶22%', 'https://www.dot-st.com/nikoand/disp/item/234896/?COLOR_CD=11', '裙装', '半身裙', '半身裙', '', 'skirt', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/niko_and/20260401/item_234896_main_50_1744625145_b.jpg', 0, 0, 1, 0.79748, 0, -2, 0, 0, 0, 3, NULL, '透气，轻盈，装饰性强，可多种穿法/搭配方式', '轻盈,装饰性强,可多种穿法/搭配方式', '', '采用两种不同风格的蕾丝拼接，具有复古感和层次感,可作为围裹式半裙，也可上身当作类似束胸/小上衣造型,推荐与牛仔裤、长裤叠穿，利用蕾丝的透视效果,整体风格融合中性力量感与女性优雅气质', '花卉图案', '商品名称为“レーシーラップスカート”，日文说明中多次提到“巻きスカート”“スカート ラップスカート”，且图片中也显示为系带式半身裙，主要穿法是围在腰部进行下装叠穿，因此归类为“skirt（半身裙）”。skirt 的定义为：穿在腰部以下的下装服饰，可为直筒或围裹式等各种款式，本品正符合该类别。', 1, 1, 0, 0, 'skirt', NULL, '', 0, NULL, 0, NULL, NULL, '50', 'ブラウン50', 0);
INSERT INTO `clothing_info` VALUES (19996627, '[MODE NORM CORE] 波浪镂空边窄版长裙', '[MODE NORM CORE]ナミナミスカラップナロースカート', 0, 200333, 'niko and ...', '', '', '透视感拿捏得当，呈现成熟氛围的针织窄版长裙。整体采用如同钩针编织般的精致镂空花样，触感清爽柔和。以 MODE NORM CORE 的原创配色打造，具有独特存在感。细直筒的 I 字轮廓配合适度透视效果，为造型增加轻盈感与时髦度。裙摆的波浪形镂空边是吸睛亮点，一件就能成为造型焦点。腰部为橡筋+内抽绳设计，穿着舒适，搭配遮住臀部的长款上衣也很合适。针织材质带来自然垂坠与优良的贴身感。既可搭配附属衬裙单穿，也可在无衬裙状态下叠穿裤装，打造多种层次造型。', '<font color=\"#ff3b86\"><b>透けすぎないシアー感が絶妙な大人感<br>パッと目を惹くニットナロースカート</b></font><br><br>■素材特性<br>かぎ編みのような丁寧な透かし編み。<br>さらっと優しい心地よい肌触り。<br>モードノーム別注オリジナルカラー。<br><br>■デザイン<br>透かし編みがポイントになった細見えするIラインのニットスカート。<br>程よいシアー感が、スタイリング全体に抜け感をプラス。<br>裾のスカラップ編みもポイントになっており、一枚で映えるアイテム。<br>ゴムウエスト＋内紐の楽な穿き心地で、腰回りが隠れる長めトップスとの相性も◎<br>ニット素材なのでしなやかな落ち感＆着心地バツグンなのも嬉しい。<br><br>■おすすめスタイリング<br>付属のペチコートとあわせ、そのままスカートとしての着用はもちろん、<br>ペチコート無しでパンツと合わせたレイヤードスタイルなど、様々なスタイリングをお楽しみいただけます。<br><br><font color=\"#ff3b86\"><b>【MODE NORM CORE】2025春アイテム一覧をCHECK！</b></font><br><a href=\"adastriaapp://items?dispNo=0000100016_002001548&orderBy=00\"><b>>>アプリ版</b></font></a><br><a href=\"https://www.dot-st.com/nikoand/disp/itemlist/?dispNo=002001548\" target=\"_blank\"><b>>>ブラウザ版</b></font></a><br><br>ーーー<br>MODENORMCORE　モードノーム　ボトムス　ニットスカート　レイヤード　クロシェ<br>ーーー', '5455.0 JPY', 332.75, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:24:00', '2026-04-02 04:17:33', 'adastria_284179', '', '69cd72d5a7ab618f2967cab2', '生活/休闲', '', '女', '青年（18-44岁）', '粘胶88%,锦纶12%', 'https://www.dot-st.com/nikoand/disp/item/284179/?COLOR_CD=70', '裙装', '半身裙', '长裙', '', 'maxi skirt', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/niko_and/20260401/item_284179_main_70_1741594682_b.webp', 0, 0, 8, 0.74760, 0, 1, 1, 0, 0, 3, NULL, '透气，舒适穿着，修饰身形显瘦，弹性良好', '舒适穿着,修饰身形显瘦,弹性良好', '', '针织透空花样设计，具有一定透视感,下摆采用波浪形镂空花边（荷叶边/扇贝边）设计,附带可拆卸衬裙，可作为半透裙或叠穿单品使用,中高腰设计配合橡筋腰头与内抽绳，方便调节松紧,I字直筒窄裙版型，垂坠感好，突出纵向线条', '波浪纹', '商品为“ニットナロースカート”，图片中为长及脚踝的直筒窄版针织裙，属于长度到脚踝/接近脚踝的长裙范畴，因此在给定列表中最接近的是“maxi skirt（长款半身裙）”。定义：maxi skirt 指长度及脚踝或更长的半身裙，本品完全符合这一特征。', 1, 0, 0, 0, 'maxi skirt', NULL, '', 0, NULL, 0, NULL, NULL, '70', 'グリーン70', 0);
