'80', 'ブルー80', 0);
INSERT INTO `clothing_info` VALUES (19996625, '[MODE NORM CORE] 随机褶皱防风长裙', '[MODE NORM CORE] ランダムギャザーシャカスカート', 0, 200333, 'niko and ...', '', '', '人气“沙沙感”面料推出的新款裙装，简约却令人不由自主地被吸引，华丽蓬松的廓形十分抢眼的褶皱裙。\n\n■ 材质特性\n采用尼龙牛津布，兼具柔韧、轻盈与耐用性，日常打理轻松。新推出具有洒脱感的扎染花色，可营造出随性时髦的穿搭氛围。\n\n■ 设计\n随机切换的拼接设计打造富有层次感的梯形分层长裙。斜向的分层线条削弱了甜美感，呈现更偏利落摩登的气质。可通过旋转腰部改变开衩位置，以不同方向穿着，塑造多种造型，同时不勾勒腿部线条，具有良好的身形遮盖效果，360°呈现不同氛围。\n\n■ 穿搭建议\n既适合与宽松上装搭配营造休闲随性风格，也适合搭配短款上衣打造健康利落的造型，在多种风格中自由切换。', '<font color=\"steelblue\"><b>人気のシャカ素材でスカートが登場<br>シンプルなのに、思わず目を奪われる..。<br>華やかなボリューム感が印象的なギャザースカート</b></font><br><br>■素材特性<br>ナイロンオックスを使用し、しなやかで軽量でありながら頑丈さも兼ね揃えています。<br>日々のお手入れも簡単なイージーケアも魅力。<br>こなれ感たっぷりの着こなしが叶うタイダイ柄も新登場。<br><br>■デザイン<br>ランダムな切り替えデザインが目を惹くティアードスカート。<br>ティアードの切り替えが斜めに入る事で甘くなりすぎず辛口モードに。<br>ウエストを回すことでスリットの位置を変えても楽しめます。<br>足のラインを拾わない体型カバーにもピッタリなアイテム。<br>また360°雰囲気を変えて着用することができるのもポイント。<br><br>■おすすめスタイリング<br>オーバーサイズと合わせたカジュアルなスタイリングはもちろん、<br>コンパクトトップスと合わせたヘルシーな着こなしもオススメです。<br>幅広いテイストでスタイリングを楽しんで！<br><br><font color=\"steelblue\"><b>【MODE NORM CORE】2025夏アイテム一覧をCHECK！</b></font><br><a href=\"adastriaapp://items?dispNo=0000100016_002001582&orderBy=00\"><b>>>アプリ版</b></font></a><br><a href=\"https://www.dot-st.com/nikoand/disp/itemlist/?dispNo=002001582\" target=\"_blank\"><b>>>ブラウザ版</b></font></a><br><br>ーーー<br>MODENORMCORE　モードノーム　ティアードスカート　ギャザー　ナイロン　春スカート　シャカシャカ<br>ーーー', '6000.0 JPY', 366.00, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:24:01', '2026-04-02 04:17:31', 'adastria_291270', '', '69cd72d5a7ab618f2967cab0', '生活/休闲', '', '女', '青年（18-44岁）', '锦纶100%', 'https://www.dot-st.com/nikoand/disp/item/291270/?COLOR_CD=85', '裙装', '半身裙', '长裙', '', 'maxi skirt', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/niko_and/20260401/item_291270_main_85_1744097625_b.webp', 0, 0, 2, 0.97718, 0, 1, 0, 0, 0, 3, NULL, '透气，易打理，遮肉显瘦，轻量', '易打理,遮肉显瘦,轻量', '', '采用尼龙牛津布，兼具轻盈与耐用,随机切换的斜向拼接层叠结构，形成不规则分层效果,腰部可旋转改变开衩位置，实现多面造型,整体呈现夏季感的扎染视觉效果,适合搭配宽松或合身上衣，风格跨度大', '', '从图片和描述看，该单品为覆盖脚踝的长款裙装，关键词有「ティアードスカート」「春スカート」「ギャザースカート」，长度为拖地/及踝，属于长款半身裙范畴，因此在提供的列表中选择「maxi skirt」最合适，定义为：女性穿着的及踝或更长长度的长裙。', 0, 0, 0, 0, 'maxi skirt', NULL, '', 0, NULL, 0, NULL, NULL, '85', 'サックスプリント(85)', 0);
INSERT INTO `clothing_info` VALUES (19996626, '钩针拼接迷你半身裙', 'かぎ針コンビミニスカート', 0, 200333, 'niko and ...', '', '', '采用含棉材质，面料结实耐用。手工编织风的复古质感与迷你长度版型相结合，呈现本季感十足的半身裙。自然的材质感与充满工艺感的总柄设计，使叠穿造型更具季节氛围，轻松完成层次搭配。既能搭配休闲风，也可以演绎女性化风格，体现品牌特有的混搭气质。可作为围裹式半身裙，也可以当作束胸/小背心穿着，大幅拓展搭配方式。关键词：钩针编织、叠穿、迷你裙、钩织风。', '<font color=\"#ffbf00\"><b>いつものスタイリングにプラスワンアイテム</b></font><br>		<br>■素材特性<br>コットン使用なので丈夫でしっかりした生地が特徴です。<br>		<br>■デザイン<br>手編み風のレトロな風合いとミニ丈のシルエットが今年っぽいスカート！<br>ナチュラルな素材感とクラフト感漂う総柄デザインはシーズンムードを高めるレイヤードスタイルが簡単に完成します◎<br>カジュアルにもフェミニンにも着まわせる、niko and ...らしいミックススタイルが楽しめる一枚です！<br>		<br>■おすすめスタイリング	<br>とろみのあるナチュラルなシャツをフロントインして足元はサンダルを合わせると夏らしいお出かけスタイルの完成！<br>巻きスカートとしてもビスチェとしても合わせることができ、スタイリングの幅をグッと広げてくれます。<br>		<br>ーーー		<br>カギ編み　レイヤード　ミニスカート　クロシェ風<br>ーーー', '5455.0 JPY', 332.75, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:24:01', '2026-04-02 04:17:32', 'adastria_329657', '', '69cd72d5a7ab618f2967cab6', '生活/休闲', '', '女', '青年（18-44岁）', '棉50%,涤纶43%,锦纶5%,粘胶2%', 'https://www.dot-st.com/nikoand/disp/item/329657/?COLOR_CD=10', '裙装', '半身裙', '半身裙', '', 'skirt', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/niko_and/20260401/item_329657_main_10_1749085601_b.jpg', 0, 0, 2, 0.97751, 0, 1, 1, 0, 0, 3, NULL, '坚固耐用，可多种穿法，层次搭配，装饰性增强造型感', '坚固耐用,可多种穿法,层次搭配,装饰性增强造型感', '', '采用棉混纺纱线，兼顾手感与结构感,手编风格呈现复古气质,可作为半身裙、围裹式裙或搭配成马甲/束身上衣,适合叠穿在裤装或连衣裙外，增强造型层次感,整体为钩织花块组合的总柄设计', '花卉图案', '商品名称为「かぎ針コンビミニスカート」，日文中明确为迷你长度的スカート（半身裙），图片中也显示为围裹在裤子外侧的短裙式下装，并非裤子、上衣或家纺用品。因此在提供的服装分类中，最适合归为“skirt（半身裙）”，即女性下装类、腰部固定、覆盖大腿的裙装。', 0, 0, 0, 0, 'skirt', NULL, '', 0, NULL, 0, NULL, NULL, '10', 'モノトーン(10)', 0);
INSERT INTO `clothing_info` VALUES (19996624, '【CONVERSE】ALL STAR LIGHT PLTS 2 GE OX 低帮厚底帆布鞋', '【CONVERSE(コンバース)】ALL STAR LIGHT PLTS 2 GE OX', 0, 200333, 'niko and ...', '', '', '作为 All Star Light 轻量系列的鞋款，通过对鞋底进行全新设计，加入波浪感细节，并将外底从侧面略微露出，呈现富有动感的造型。采用轻量厚底结构，减轻脚部负担，同时拉长腿部比例。搭配金色鞋孔，营造出优雅精致的氛围，是兼具经典与时尚感的一双帆布休闲鞋。品牌 CONVERSE 源于由马キス・ミルズ・コンバース创立的橡胶鞋公司，其代表作 All Star 自1917年问世以来，经典轮廓延续至今，持续受到广泛喜爱。', '<font color=\"#EE7948\"><b>気分まで軽くなる軽量のオールスター</b></font><br><br>オールスター ライトのソールアレンジモデル。<br>ウェーブのディテールを取り入れ、アウトソールがサイドからわずかに見える設計など、動きのあるデザインがポイントの軽量厚底を採用。<br>ゴールドハトメをあしらったエレガントな雰囲気の一足です。<br><br>【CONVERSE(コンバース)】<br>マーキス・ミルズ・コンバースが設立したコンバース・ラバー・シュー・カンパニーが起源。 <br>コンバースの代表作は、スニーカー史上最も多く販売され且、最も長く履き続けられている「永久定番」オールスター。<br>1917年の誕生以来、そのスタイルは現在もほとんど変わることなく生産され続けられています。<br>また、その他にもジャックパーセルやプロレザーなど長年愛され続け、スニーカー史に名を残す名作が揃っています。<br><br>ーーー<br>CONVERSE　コンバース　ALL STAR 　オールスター　ライト　スニーカー　厚底<br>ーーー', '10000.0 JPY', 610.00, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:24:03', '2026-04-02 04:17:31', 'adastria_637798', '', '69cd72d5a7ab618f2967caae', '生活/休闲', '', '通用', '青年（18-44岁）', NULL, 'https://www.dot-st.com/nikoand/disp/item/637798/?COLOR_CD=19', '其他服饰/物品', '其他', NULL, '', 'shoes', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/niko_and/20260401/item_637798_main_19_1774587116_b.jpg', 0, 0, 9, 0.99857, 0, 1, 0, 0, 0, 3, NULL, '轻量，增高厚底，装饰性金属孔眼', '轻量,增高厚底,装饰性金属孔眼', 'E.V.A中底减重技术', '经典低帮系带款式，基于CONVERSE ALL STAR 轮廓设计,采用波浪感线条的厚底设计，侧面可见外底细节，增加视觉动感,黑色帆布鞋面配金色鞋眼，整体风格更显优雅精致,品牌延续百年经典造型，易于日常穿搭', '纯色，纯色', '该商品为CONVERSE帆布休闲鞋，从品名、描述和图片都可以看出是低帮系带运动休闲鞋，属于穿在脚上的鞋类而非服装或家纺，因此在给定列表中最合适的类别是“shoes（鞋类）”，定义为日常或运动穿着的各类鞋品。', 0, 0, 0, 0, 'shoes', NULL, '', 0, NULL, 0, NULL, NULL, '19', 'ブラック(19)', 0);
INSERT INTO `clothing_info` VALUES (19996622, 'FINE亚麻斜纹背带连体裤', 'FINEリネンツイルサロペット', 0, 200333, 'niko and ...', '', '', '适合日常休闲场景穿着的成熟女性背带连体裤。\n\n■ 面料特性\n采用法式亚麻，手感细腻、发色优良，具有天然的接触冷感和吸水性等功能。亚麻材质坚韧耐用，穿着越久越能体现出独特风合，逐渐变得更加柔滑贴肤。\n\n■ 设计\n运用有垂坠感的斜纹组织打造的背带连体裤。胸前做成缓和的V字剪裁，突显女性化轮廓。裤脚配有平织抽绳，可收紧穿着，以改变整体廓形，带来造型变化。\n\n■ 搭配建议\n推荐搭配简单T恤，打造干净利落的纯色叠穿造型，不过度修饰即可呈现成熟随性的背带裤穿搭。', '<font color=\"#1eb307\"><b>カジュアルシーンに活躍するオトナサロペ</b></font><br><br>■素材特性<br>フレンチリネンは肌触りや発色が良く、接触冷感や吸水性など天然機能に優れた素材。<br>リネンは丈夫な素材で使うほどに風合いが増し、なめらかに肌に馴染んでいきます。<br><br>■デザイン<br>落ち感がきちんと見えするツイルサロペット。<br>胸当てをなだらかなVカットにデザインし、女性らしさを意識したシルエットに◎<br>裾には平紐が付いているので、絞って着ていただくとシルエットの変化をお楽しみいただけます！<br><br>■おすすめスタイリング<br>シンプルなTシャツを合わせたソリッドコーデがこなれ感が出てGOOD！<br>あえて着飾りすぎないほうが大人っぽくサロペットを着こなせます♪<br><br>ーーー<br>サロペット　ソリッドコーデ　フレンチリネン　大人サロペ<br>ーーー', '9091.0 JPY', 554.55, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:24:04', '2026-04-02 04:17:29', 'adastria_142557', '', '69cd72d5a7ab618f2967ca9e', '生活/休闲', '', '女', '青年（18-44岁）', '亚麻100%', 'https://www.dot-st.com/nikoand/disp/item/142557/?COLOR_CD=19', '下装', '工装裤', '工装连体裤', '', 'overalls', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/niko_and/20260401/item_142557_main_19_1749174932_b.jpg', 0, 0, 2, 0.55119, 0, 1, 0, 0, 0, 3, NULL, '接触冷感，吸湿排汗，透气，耐用，凉爽穿着感', '耐用,凉爽穿着感', '', '使用法式亚麻材质，手感柔滑，颜色饱满,随穿着时间推移，面料风合和柔软度提升,胸前V字剪裁提升女性化轮廓,裤脚配有平织抽绳，可变化轮廓,适合与简单T恤叠搭的休闲造型', '纯色', '从商品名称“サロペット・オールインワン”和图片来看，这是带肩带、胸片、连体裤型的单品，中文通常称为背带裤/连体工装裤，对应列表中最接近的为“overalls”。该类目定义为带背带和胸当、从上到下连为一体的裤装形式，适合本款“FINEリネンツイルサロペット”的版型特点。', 0, 0, 0, 0, 'overalls', NULL, '', 0, NULL, 0, NULL, NULL, '19', 'ブラック19', 0);
INSERT INTO `clothing_info` VALUES (19996623, '【adidas Originals】Gazelle Bold 厚底凉鞋', '【adidas Originals (アディダスオリジナルス)】ガゼル ボールド サンダル', 0, 200333, 'niko and ...', '', '', '这款 Gazelle Bold 凉鞋以 adidas 经典鞋型为基础，加入厚底平台设计，在传统元素中注入清新的夏日气息，彰显鲜明个性，适合日常多种穿搭。鞋面采用耐久性良好的真皮与合成材质，配以柔软纺织内衬，提升穿着舒适度；坚固的橡胶外底在街头行走时提供稳定支撑。标志性的三条纹与品牌识别细节展现 adidas Originals 的经典风格，为日常衣橱增添自信与风格。', '<font color=\"#EE7948\"><b>スポーツにインスパイアされたデザインが<br>フレッシュでオーセンティックな個性を与えるサンダル。</b></font><br><br>アディダスのクラシックなシルエットをベースにプラットフォームの厚底エッジを取り入れたのが、このガゼル ボールド サンダル。<br>伝統的なデザインとフレッシュな夏の雰囲気を融合させた存在感を放つ一足で、普段の装いに幅広く使っていける。<br><br>耐久性に優れたレザーと合成素材のアッパーは洗練された仕上がり。<br>ソフトなテキスタイルの裏地で快適さを高めているほか、頑丈なラバーアウトソールがストリートでも足元をしっかり安定させる。<br><br>シグネチャーのスリーストライプスは、アディダス オリジナルスのアイデンティティを表現。<br>大胆なキャラクターが、ワードローブの定番に時代を超えた自信とスタイルをもたらす。<br><br>【adidas Originals (アディダス オリジナルス)】<br>adidas Originalsは、adidasの豊かなスポーツの伝統にインスピレーションを受け、2001 年に設立されたストリートスポーツウェアブランドです。<br>adidas の歴史を継承しながら、スポーツにおける信念や創造性を、現代のユースカルチャーに反映したプロダクトを通じて、ブランドのレガシーを進化させ続けています。<br>1972年に初めて使用されたアイコニックなトレフォイルロゴをシンボルマークに、クリエイティブな人々に支持されているアディダス オリジナルスは、ストリートカルチャーに向けたスポーツウェアブランドのパイオニアとして道を切り開き続けます。<br><br>ーーー<br>adidas Originals　アディダス オリジナル　Gazelle Bold Sandal　ガゼルボールド　サンダル　厚底<br>ーーー', '11000.0 JPY', 671.00, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:24:04', '2026-04-02 04:17:30', 'adastria_587140', '', '69cd72d5a7ab618f2967caad', '生活/休闲，差旅/商务', '', '通用', '青年（18-44岁）', '皮革100%', 'https://www.dot-st.com/nikoand/disp/item/587140/?COLOR_CD=82', '其他服饰/物品', '其他', NULL, '', 'shoes', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/niko_and/20260401/item_587140_main_82_1774594621_b.jpg', 0, 0, 9, 0.99902, 0, 1, 0, 0, 0, 3, NULL, '透气，舒适缓震，耐久耐磨，稳固支撑，厚底增高', '舒适缓震,耐久耐磨,稳固支撑,厚底增高', '', '采用经典adidas Gazelle轮廓并做厚底平台改良,甲材为天然皮革与合成材质，兼顾质感与耐用,柔软纺织内衬提升脚感与舒适度,橡胶外底提供抓地力与街头行走稳定性,标志性三条纹与三叶草元素强化品牌识别,适合夏季穿着的开孔凉鞋结构', '纯色，条纹', '商品为带鞋底、用于行走的运动风凉鞋，并非服装或家纺类纺织品，且品类字段为「シューズ」，最匹配枚举中的“shoes（鞋类）”。“shoes”定义为穿在脚上的鞋履产品，本品为adidas厚底运动凉鞋，完全符合该子类。', 0, 0, 0, 0, 'shoes', NULL, '', 0, NULL, 0, NULL, NULL, '82', 'クリアスカイ×ゴールドメタリック(82)', 0);
INSERT INTO `clothing_info` VALUES (19996621, '【adidas Originals】Gazelle Bold 厚底凉鞋', '【adidas Originals (アディダスオリジナルス)】ガゼル ボールド サンダル', 0, 200333, 'niko and ...', '', '', '以大胆的平台厚底设计，将舒适度与个性风格融合一体的 Gazelle Bold 凉鞋。将复古运动装元素与现代感相结合，在经典设计基础上加入优质交叉绑带与厚底造型，带来醒目的轮廓。极其柔软的脚床与纺织内里，给予每一步良好的缓冲与舒适脚感。鞋舌上的经典文字与锯齿状三条纹延续品牌传统。全能百搭的外观适合日常多种造型，在保持永不过时风格的同时，提供夏日所需的舒适体验，是夏季街头穿搭的理想之选。', '<font color=\"#EE7948\"><b>大胆なプラットフォームデザインで<br>快適さと個性的なスタイルを実現したサンダル。</b></font><br><br>レトロなスポーツウェアとモダンなセンスが融合したガゼル ボールド サンダル。<br>お馴染みのデザインに新たな解釈を加えたこのサンダルは、プレミアムなクロスバンデージを組み合わせた大胆なプラットフォームスタイルが特徴。<br><br>極めてソフトなフットベッドとテキスタイルライニングが一歩ごとにクッション性と快適さをキープ。<br>クラシックなシュータンの文字とギザギザのスリーストライプスがアディダスの伝統を感じさせる。<br><br>オールラウンドに使えるデザインで存在感を放つこのサンダルは、タイムレスなスタイルと晴れた日に必要な快適さを融合させ、毎日の装いを引き立てる。<br>夏の定番フットウェアとして活躍させて、人と違う装いを楽しもう。<br><br>【adidas Originals (アディダス オリジナルス)】<br>adidas Originalsは、adidasの豊かなスポーツの伝統にインスピレーションを受け、2001 年に設立されたストリートスポーツウェアブランドです。<br>adidas の歴史を継承しながら、スポーツにおける信念や創造性を、現代のユースカルチャーに反映したプロダクトを通じて、ブランドのレガシーを進化させ続けています。<br>1972年に初めて使用されたアイコニックなトレフォイルロゴをシンボルマークに、クリエイティブな人々に支持されているアディダス オリジナルスは、ストリートカルチャーに向けたスポーツウェアブランドのパイオニアとして道を切り開き続けます。<br><br>ーーー<br>adidas Originals　アディダス オリジナル　Gazelle Bold Sandal　ガゼルボールド　サンダル　厚底<br>ーーー', '11000.0 JPY', 671.00, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:24:05', '2026-04-02 04:17:28', 'adastria_587139', '', '69cd72d5a7ab618f2967ca9b', '生活/休闲', '', '通用', '青年（18-44岁）', '皮革100%', 'https://www.dot-st.com/nikoand/disp/item/587139/?COLOR_CD=19', '其他服饰/物品', '其他', NULL, '', 'shoes', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/niko_and/20260401/item_587139_main_19_1774593454_b.jpg', 0, 0, 9, 0.99905, 0, 1, 0, 0, 0, 3, NULL, '高弹力，缓震舒适，厚底增高，抓地力，日常行走舒适', '缓震舒适,厚底增高,抓地力,日常行走舒适', '', '大胆的平台厚底设计,经典三条纹与鞋舌文字突出品牌传统,优质交叉绑带结构提供包裹感,鞋垫非常柔软，行走时脚感舒适,纺织内里提升脚感与透气性,适合夏季及晴天穿着', '纯色，纯色', '从商品名称“サンダル（凉鞋）”、品类“シューズ”，以及图片中可见为露趾、露跟、带厚底平台结构的运动风凉鞋可判断，这是一款脚上穿着的鞋类而非服装或家纺。所有服装子类（如t-shirt、pants等）都不适用，最贴切的是列表中的“shoes”，其定义为各类鞋履产品的统称，包含凉鞋、运动鞋等，因此选择 sub_category: shoes。', 0, 0, 0, 0, 'shoes', NULL, '', 0, NULL, 0, NULL, NULL, '19', 'コアブラック×ゴールドメタリック(19)', 0);
INSERT INTO `clothing_info` VALUES (19996619, '图案仿珍珠胸针', 'モチーフパール調ブローチ', 0, 200333, 'niko and ...', '', '', '带有微妙曲线造型与仿珍珠组合的优雅胸针。可为夹克、开衫、披肩等单品增添亮点，使简约穿搭立刻变得华丽有型，更具高级感。适合各类正式或特别场合配戴。', '<font color=\"#F69896\"><b>いつもの持ち物にアクセントをプラス</b></font><br><br>ニュアンスのある曲線とパール調の組み合わせが上品なブローチ。<br>ジャケットやカーディガン、ストールなどにアクセントをプラスしてくれるアイテムです。<br>シンプルなスタイリングもぱっと華やかな印象になり、こなれ感がアップしますよ。<br><br>ーーー<br>アクセサリー　ブローチ　ハート　パール調　オケージョン<br>ーーー', '1200.0 JPY', 73.20, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:24:10', '2026-04-02 04:17:26', 'adastria_282995', '', '69cd72d5a7ab618f2967ca99', '生活/休闲', '', '通用', '青年（18-44岁）', '合金50%,樹脂50%', 'https://www.dot-st.com/nikoand/disp/item/282995/?COLOR_CD=20', '其他服饰/物品', '其他', '配件', '', 'accessories', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/niko_and/20260401/item_282995_main_20_1736302297_b.jpg', 0, 0, 9, 0.78587, 0, -1, 0, 0, 0, 3, NULL, '搭配装饰，提升造型精致感', '搭配装饰,提升造型精致感', '', '珍珠样式点缀，提升整体优雅感,抽象心形/曲线轮廓设计，线条感强,适合搭配夹克、开衫、披肩等服饰用作点缀', '纯色，纯色', '商品名称为“モチーフパール調ブローチ（图案珍珠风胸针）”，且图片显示为一枚金属与仿珍珠组合的别针配饰，不属于服装或家纺类纺织品，而是用来点缀衣物的首饰配件。综合判断，应归入配饰大类中的“accessories（配饰）”这一子类。其最合适的定义为：用于搭配服装、起到装饰与造型点缀作用的非服装本体的小物件。', 1, 0, 0, 0, 'accessories', NULL, '', 0, NULL, 0, NULL, NULL, '20', 'ピンク(20)', 0);
INSERT INTO `clothing_info` VALUES (19996620, '图案仿珍珠胸针', 'モチーフパール調ブローチ', 0, 200333, 'niko and ...', '', '', '带有微妙曲线造型与仿珍珠组合的优雅胸针。可为夹克、开衫、披肩等单品增添亮点，使简约穿搭立刻变得华丽有型，更具高级感。适合各类正式或特别场合配戴。', '<font color=\"#F69896\"><b>いつもの持ち物にアクセントをプラス</b></font><br><br>ニュアンスのある曲線とパール調の組み合わせが上品なブローチ。<br>ジャケットやカーディガン、ストールなどにアクセントをプラスしてくれるアイテムです。<br>シンプルなスタイリングもぱっと華やかな印象になり、こなれ感がアップしますよ。<br><br>ーーー<br>アクセサリー　ブローチ　ハート　パール調　オケージョン<br>ーーー', '1200.0 JPY', 73.20, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:24:10', '2026-04-02 04:17:27', 'adastria_282995', '', '69cd72d5a7ab618f2967ca99', '生活/休闲', '', '通用', '青年（18-44岁）', '合金50%,樹脂50%', 'https://www.dot-st.com/nikoand/disp/item/282995/?COLOR_CD=20', '其他服饰/物品', '其他', '配件', '', 'accessories', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/niko_and/20260401/item_282995_main_60_1736302299_b.jpg', 0, 0, 9, 0.96822, 0, -1, 0, 0, 0, 3, NULL, '搭配装饰，提升造型精致感', '搭配装饰,提升造型精致感', '', '珍珠样式点缀，提升整体优雅感,抽象心形/曲线轮廓设计，线条感强,适合搭配夹克、开衫、披肩等服饰用作点缀', '纯色，纯色', '商品名称为“モチーフパール調ブローチ（图案珍珠风胸针）”，且图片显示为一枚金属与仿珍珠组合的别针配饰，不属于服装或家纺类纺织品，而是用来点缀衣物的首饰配件。综合判断，应归入配饰大类中的“accessories（配饰）”这一子类。其最合适的定义为：用于搭配服装、起到装饰与造型点缀作用的非服装本体的小物件。', 1, 1, 0, 0, 'accessories', NULL, '', 0, NULL, 0, NULL, NULL, '60', 'イエロー(60)', 0);
INSERT INTO `clothing_info` VALUES (19996617, '饱满立体爱心耳夹', 'ぷっくりハートイヤリング', 0, 200333, 'niko and ...', '', '', '简约百搭的立体爱心耳夹，饱满圆润的心形造型十分可爱，适中的体积为脸部增添精致亮点。不受季节限制，适合搭配多种风格造型。', '<font color=\"#F69896\"><b>シンプルで使いやすいハートモチーフ</b></font><br><br>ぷっくりとした立体的なハートモチーフが可愛いイヤリング。<br>程よいボリューム感が、お顔まわりにアクセントをプラスします。<br>季節問わず、幅広いコーディネートにおすすめです。<br><br>ーーー<br>アクセサリー　イヤリング　ハート<br>ーーー', '1700.0 JPY', 103.70, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:24:11', '2026-04-02 04:17:25', 'adastria_291421', '', '69cd72d5a7ab618f2967ca97', '生活/休闲', '', '通用', '青年（18-44岁）', '合金70%,真鍮30%', 'https://www.dot-st.com/nikoand/disp/item/291421/?COLOR_CD=15', '其他服饰/物品', '其他', '配件', '', 'accessories', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/niko_and/20260401/item_291421_main_15_1740984202_b.jpg', 0, 0, 8, 0.98275, 0, -1, 0, 0, 0, 3, NULL, '装饰点缀，提升整体造型感', '装饰点缀,提升整体造型感', '', '心形立体造型，增添甜美感,体积适中，适合日常佩戴,一年四季都易于搭配不同穿搭风格,采用合金及黄铜材质制作', '纯色', '从商品名称和描述“ぷっくりハートイヤリング”可知是耳饰配件，不属于服装、家纺或袜帽手套等品类，整体用途为装饰造型，因此应归入配饰类。给定枚举中最贴近的是“accessories”，定义为各类搭配用饰品、首饰配件等，与本商品“耳夹/耳环”属性最匹配。', 1, 0, 0, 0, 'accessories', NULL, '', 0, NULL, 0, NULL, NULL, '15', 'グレー(15)', 0);
INSERT INTO `clothing_info` VALUES (19996618, '饱满立体爱心耳夹', 'ぷっくりハートイヤリング', 0, 200333, 'niko and ...', '', '', '简约百搭的立体爱心耳夹，饱满圆润的心形造型十分可爱，适中的体积为脸部增添精致亮点。不受季节限制，适合搭配多种风格造型。', '<font color=\"#F69896\"><b>シンプルで使いやすいハートモチーフ</b></font><br><br>ぷっくりとした立体的なハートモチーフが可愛いイヤリング。<br>程よいボリューム感が、お顔まわりにアクセントをプラスします。<br>季節問わず、幅広いコーディネートにおすすめです。<br><br>ーーー<br>アクセサリー　イヤリング　ハート<br>ーーー', '1700.0 JPY', 103.70, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:24:11', '2026-04-02 04:17:26', 'adastria_291421', '', '69cd72d5a7ab618f2967ca97', '生活/休闲', '', '通用', '青年（18-44岁）', '合金70%,真鍮30%', 'https://www.dot-st.com/nikoand/disp/item/291421/?COLOR_CD=15', '其他服饰/物品', '其他', '配件', '', 'accessories', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/niko_and/20260401/item_291421_main_60_1739409817_b.jpg', 0, 0, 9, 0.99586, 0, -1, 0, 0, 0, 3, NULL, '装饰点缀，提升整体造型感', '装饰点缀,提升整体造型感', '', '心形立体造型，增添甜美感,体积适中，适合日常佩戴,一年四季都易于搭配不同穿搭风格,采用合金及黄铜材质制作', '纯色', '从商品名称和描述“ぷっくりハートイヤリング”可知是耳饰配件，不属于服装、家纺或袜帽手套等品类，整体用途为装饰造型，因此应归入配饰类。给定枚举中最贴近的是“accessories”，定义为各类搭配用饰品、首饰配件等，与本商品“耳夹/耳环”属性最匹配。', 1, 1, 0, 0, 'accessories', NULL, '', 0, NULL, 0, NULL, NULL, '60', 'イエロー(60)', 0);
INSERT INTO `clothing_info` VALUES (19996614, '【抗菌防臭】多款标语刺绣棒球帽', '《抗菌防臭》アソートロゴ刺繍キャップ', 0, 200333, 'niko and ...', '', '', '这款棒球帽具有复古感的外观，是日常佩戴的理想选择。根据不同颜色在前片配以相应字体与英文信息，在简约中展现个性。全年都容易与各种造型搭配，为穿搭增添适度休闲感。内侧汗带经过抗菌防臭整理，可抑制细菌滋生，减少异味产生。', '<font color=\"#EE7948\"><b>抗菌防臭機能付き<br>デイリーユースにぴったりのアソートデザイン</b></font><br><br>ヴィンテージライクな表情がポイントのベースボールキャップ。<br>各カラーに合わせたフォントとメッセージをフロントに施し、シンプルながらも個性が光るデザインに。<br>季節問わずどんなコーディネートにも馴染みやすく、程よくカジュアルダウンしてくれます。<br><br>■DEODORANT（抗菌防臭）<br>汗帯に細菌の増殖を抑え、臭いの発生を抑制する加工をしています。<br><br>ーーー<br>帽子　キャップ　ロゴキャップ　抗菌防臭　デオドラント<br>ーーー', '2719.0 JPY', 165.86, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:24:20', '2026-04-02 04:17:22', 'adastria_661603', '', '69cd72d5a7ab618f2967ca8c', '生活/休闲', '', '通用', '青年（18-44岁）', '棉100%', 'https://www.dot-st.com/nikoand/disp/item/661603/?COLOR_CD=54', '配饰', '帽子', NULL, '', 'baseball cap', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/niko_and/20260401/item_661603_main_54_1774921302_b.jpg', 0, 0, 9, 0.99726, 0, 1, 0, 0, 0, 3, NULL, '除臭/抗异味，抗菌，日常遮阳，装饰搭配', '日常遮阳,装饰搭配', '抗菌防臭整理,汗带抑菌加工', '棒球帽款式，前片有英文刺绣标语,多色可选，每色搭配不同字体与信息,复古感外观设计，适合全年搭配,内侧汗带部位进行功能性加工以抑制异味', '字母', '该产品为有硬帽檐、弧形遮阳前沿和分片帽身结构的日常头饰，描述中多次提到“ベースボールキャップ（棒球帽）”，并带有前片LOGO刺绣，符合“baseball cap”即棒球帽的定义：前端有帽檐、用于遮阳与休闲搭配的休闲运动风帽子。', 1, 0, 0, 0, 'baseball cap', NULL, '', 0, NULL, 0, NULL, NULL, '54', 'キャメル(54)', 0);
