INSERT INTO `clothing_info` VALUES (19996616, '【抗菌防臭】多款标语刺绣棒球帽', '《抗菌防臭》アソートロゴ刺繍キャップ', 0, 200333, 'niko and ...', '', '', '这款棒球帽具有复古感的外观，是日常佩戴的理想选择。根据不同颜色在前片配以相应字体与英文信息，在简约中展现个性。全年都容易与各种造型搭配，为穿搭增添适度休闲感。内侧汗带经过抗菌防臭整理，可抑制细菌滋生，减少异味产生。', '<font color=\"#EE7948\"><b>抗菌防臭機能付き<br>デイリーユースにぴったりのアソートデザイン</b></font><br><br>ヴィンテージライクな表情がポイントのベースボールキャップ。<br>各カラーに合わせたフォントとメッセージをフロントに施し、シンプルながらも個性が光るデザインに。<br>季節問わずどんなコーディネートにも馴染みやすく、程よくカジュアルダウンしてくれます。<br><br>■DEODORANT（抗菌防臭）<br>汗帯に細菌の増殖を抑え、臭いの発生を抑制する加工をしています。<br><br>ーーー<br>帽子　キャップ　ロゴキャップ　抗菌防臭　デオドラント<br>ーーー', '2719.0 JPY', 165.86, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:24:20', '2026-04-02 04:17:24', 'adastria_661603', '', '69cd72d5a7ab618f2967ca8c', '生活/休闲', '', '通用', '青年（18-44岁）', '棉100%', 'https://www.dot-st.com/nikoand/disp/item/661603/?COLOR_CD=54', '配饰', '帽子', NULL, '', 'baseball cap', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/niko_and/20260401/item_661603_main_80_1774921323_b.jpg', 0, 0, 9, 0.82989, 0, 1, 1, 0, 0, 3, NULL, '除臭/抗异味，抗菌，日常遮阳，装饰搭配', '日常遮阳,装饰搭配', '抗菌防臭整理,汗带抑菌加工', '棒球帽款式，前片有英文刺绣标语,多色可选，每色搭配不同字体与信息,复古感外观设计，适合全年搭配,内侧汗带部位进行功能性加工以抑制异味', '字母', '该产品为有硬帽檐、弧形遮阳前沿和分片帽身结构的日常头饰，描述中多次提到“ベースボールキャップ（棒球帽）”，并带有前片LOGO刺绣，符合“baseball cap”即棒球帽的定义：前端有帽檐、用于遮阳与休闲搭配的休闲运动风帽子。', 1, 2, 0, 0, 'baseball cap', NULL, '', 0, NULL, 0, NULL, NULL, '80', 'ブルー(80)', 0);
INSERT INTO `clothing_info` VALUES (19996610, '丝滑感画家长裤', 'トロットペインターパンツ', 0, 200333, 'niko and ...', '', '', '这款画家长裤采用亚麻×人造丝面料，兼具亚麻的良好透气性和人造丝自然垂坠感，触感柔软顺滑，穿着舒适。廓形宽松，既能遮掩身形，又带来轻松自在的穿着体验。以经典工装画家裤为设计基础，调整为更适合日常穿搭的休闲版型，并在裤脚配有抽绳设计，可束紧裤脚，营造不同轮廓，也适用于更为活跃的场景。适合搭配宽松上衣打造慵懒休闲风，也可搭配合身上衣与精致凉鞋，呈现干练又不失随性的造型。', '<font color=\"#ff770f\"><b>今から履きたい！一度履いたら、もう手放せない<br>着心地抜群のペインターパンツ</b></font><br>		<br>■素材特性<br>リネン×レーヨン素材で、リネンの風通しの良さとレーヨンの落ち感のある生地が魅力の素材です。<br>とろっとした柔らかい肌触りで履き心地抜群！<br><br>■デザイン<br>ゆったりとしたルーズなシルエットで、体型カバーをしながらも、リラックス感のある履き心地が魅力のペインターパンツ。<br>ワークウェアの定番であるペインターパンツのデザインをベースにしつつ、カジュアルに着こなせるシルエットにアレンジ！<br>裾を絞ってシルエットの変化を楽しめるドロストコード付きのため、アクティブなシーンにも活躍します！<br>		<br>■おすすめスタイリング	<br>ざっくりとしたトップスを合わせたリラックススタイルや、コンパクトなトップスを合わせたカジュアルテイストが今年らしい◎<br>足元に華奢なサンダルを持ってきたきれいめスタイルもおすすめです！<br>	<br>ーーー		<br>カジュアルパンツ　カーゴパンツ　アクティブ　<br>ーーー', '6000.0 JPY', 366.00, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:24:21', '2026-04-02 04:17:19', 'adastria_497615', '', '69cd72d5a7ab618f2967ca8a', '生活/休闲', '', '女', '青年（18-44岁）', '粘胶75%,亚麻25%', 'https://www.dot-st.com/nikoand/disp/item/497615/?COLOR_CD=52', '下装', '休闲裤', '女士裤装', '', 'pantsuit', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/niko_and/20260401/item_497615_main_52_1749089000_b.jpg', 0, 0, 2, 0.93872, 0, 1, 1, 0, 0, 3, NULL, '透气，舒适，宽松版型便于活动，体型修饰', '舒适,宽松版型便于活动,体型修饰', '', '采用亚麻×人造丝混纺，兼具清爽透气与柔顺垂坠感,裤脚配有抽绳，可自由调整轮廓与长度,宽松廓形，强调放松感与休闲感,以工装风格的画家裤为设计基础，增加口袋等细节', '纯色，纯色', '根据图片和文案可知是下装长裤，日文“ペインターパンツ”即画家裤，属于休闲长裤范畴。在给定枚举中最贴近的是长裤类目，故选择“pantsuit（长裤/西裤类定义中最接近的一般长裤）”作为归类说明。', 1, 0, 0, 0, 'pantsuit', NULL, '', 0, NULL, 0, NULL, NULL, '52', 'アイボリー(52)', 0);
