INSERT INTO `clothing_info` VALUES (19996607, '透感法式无袖背心套装', 'シアーフレンチタンクセット', 0, 200333, 'niko and ...', '', '', '只需叠穿即可打造当下流行的层次造型，是一款满足时髦感的趋势套装单品。外层采用蓬松轻盈、速干性优异的100%涤纶材质，带来凉爽的透感效果。内搭背心使用细密罗纹面料，触感顺滑、贴肤舒适。纤细罗纹背心不过分休闲，配合带有轻微透视感的透感上衣，营造清爽又有女人味的印象。两件均可单独穿着，可与自己喜欢的内搭自由叠加，为夏日容易变得简单的造型增添一丝精致与变化，是适合成熟女性的轻松时髦上衣套装。搭配吊带连衣裙可营造放松的夏日度假氛围，也可以与彩色裤装或牛仔裤组合，打造随性有型的休闲穿搭。', '<font color=\"#f0bf0c\"><b>重ねるだけで、今欲しいが叶うトレンドのレイヤードアイテム！</b></font><br>		<br>■素材特性<br>ふんわり軽く、速乾性にも優れたポリエステル100%を使用。<br>セットのタンクトップは、肌なじみの良い滑らかな風合いの細リブ生地。<br>		<br>■デザイン<br>カジュアル過ぎない細めのリブタンクと、ほんのり透け感が涼しげなシアートップスがセットになった嬉しいアイテム。<br>それぞれ単品使いができる仕様のため、一緒に着るのはもちろん、ご自身のインナーを重ねてきても◎<br>シンプルになりがちな夏のスタイリングにほんの少しスパイスをプラスしてくれる、オトナのラフトップスです！<br>		<br>■おすすめスタイリング	<br>キャミワンピに合わせたリラックス感のある夏のリゾートコーデはいかがですか？<br>カラーパンツやデニムパンツを持ってくると、こなれ感のあるオトナカジュアルコーデに仕上がります！<br>		<br>ーーー		<br>リブタンク　シアートップス　セットアイテム<br>ーーー', '4091.0 JPY', 249.55, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:24:30', '2026-04-02 04:17:16', 'adastria_494808', '', '69cd72d5a7ab618f2967ca89', '生活/休闲', '', '女', '青年（18-44岁）', '涤纶100%', 'https://www.dot-st.com/nikoand/disp/item/494808/?COLOR_CD=60', '上装', '背心', '背心', '', 'tank top', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/niko_and/20260401/item_494808_main_60_1749087172_b.jpg', 0, 0, 4, 0.83381, 0, 1, 0, 0, 0, 3, NULL, '速干，透气，高弹力，轻盈，凉感穿着体验，舒适贴肤', '轻盈,凉感穿着体验,舒适贴肤', '', '外层为轻薄透感设计，适合夏季叠穿造型,内搭为细罗纹面料，增加弹性与包覆感,套装组合可拆分单独穿着，搭配灵活,版型偏休闲宽松，适合度假与日常造型', '纯色', '根据描述“シアーフレンチタンクセット”为一套“细罗纹背心＋透感上衣”的组合，其中内搭为无袖紧身型的タンクトップ，主要贴身作为内搭背心使用，最符合列表中的“tank top（背心）”类别定义：贴身无袖上衣，多用于打底或单穿。因此选择 sub_category 为 tank top。', 1, 0, 0, 0, 'tank top', NULL, '', 0, NULL, 0, NULL, NULL, '60', 'イエロー(60)', 0);
INSERT INTO `clothing_info` VALUES (19996608, '透感法式无袖背心套装', 'シアーフレンチタンクセット', 0, 200333, 'niko and ...', '', '', '只需叠穿即可打造当下流行的层次造型，是一款满足时髦感的趋势套装单品。外层采用蓬松轻盈、速干性优异的100%涤纶材质，带来凉爽的透感效果。内搭背心使用细密罗纹面料，触感顺滑、贴肤舒适。纤细罗纹背心不过分休闲，配合带有轻微透视感的透感上衣，营造清爽又有女人味的印象。两件均可单独穿着，可与自己喜欢的内搭自由叠加，为夏日容易变得简单的造型增添一丝精致与变化，是适合成熟女性的轻松时髦上衣套装。搭配吊带连衣裙可营造放松的夏日度假氛围，也可以与彩色裤装或牛仔裤组合，打造随性有型的休闲穿搭。', '<font color=\"#f0bf0c\"><b>重ねるだけで、今欲しいが叶うトレンドのレイヤードアイテム！</b></font><br>		<br>■素材特性<br>ふんわり軽く、速乾性にも優れたポリエステル100%を使用。<br>セットのタンクトップは、肌なじみの良い滑らかな風合いの細リブ生地。<br>		<br>■デザイン<br>カジュアル過ぎない細めのリブタンクと、ほんのり透け感が涼しげなシアートップスがセットになった嬉しいアイテム。<br>それぞれ単品使いができる仕様のため、一緒に着るのはもちろん、ご自身のインナーを重ねてきても◎<br>シンプルになりがちな夏のスタイリングにほんの少しスパイスをプラスしてくれる、オトナのラフトップスです！<br>		<br>■おすすめスタイリング	<br>キャミワンピに合わせたリラックス感のある夏のリゾートコーデはいかがですか？<br>カラーパンツやデニムパンツを持ってくると、こなれ感のあるオトナカジュアルコーデに仕上がります！<br>		<br>ーーー		<br>リブタンク　シアートップス　セットアイテム<br>ーーー', '4091.0 JPY', 249.55, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:24:30', '2026-04-02 04:17:17', 'adastria_494808', '', '69cd72d5a7ab618f2967ca89', '生活/休闲', '', '女', '青年（18-44岁）', '涤纶100%', 'https://www.dot-st.com/nikoand/disp/item/494808/?COLOR_CD=60', '上装', '背心', '背心', '', 'tank top', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/niko_and/20260401/item_494808_main_11_1749087082_b.jpg', 0, 0, 6, 0.90597, 0, 1, 1, 0, 0, 3, NULL, '速干，透气，高弹力，轻盈，凉感穿着体验，舒适贴肤', '轻盈,凉感穿着体验,舒适贴肤', '', '外层为轻薄透感设计，适合夏季叠穿造型,内搭为细罗纹面料，增加弹性与包覆感,套装组合可拆分单独穿着，搭配灵活,版型偏休闲宽松，适合度假与日常造型', '纯色', '根据描述“シアーフレンチタンクセット”为一套“细罗纹背心＋透感上衣”的组合，其中内搭为无袖紧身型的タンクトップ，主要贴身作为内搭背心使用，最符合列表中的“tank top（背心）”类别定义：贴身无袖上衣，多用于打底或单穿。因此选择 sub_category 为 tank top。', 1, 1, 0, 0, 'tank top', NULL, '', 0, NULL, 0, NULL, NULL, '11', 'オフ(11)', 0);
