INSERT INTO `clothing_info` VALUES (19996605, '抽褶格纹束身吊带上衣', 'シャーリングチェックビスチェ', 0, 200333, 'niko and ...', '', '', '立体感十足的抽褶设计格纹束身上衣。面料手感柔软蓬松，具有舒适的凹凸感，在柔和的布料上进行抽褶加工，呈现富有弹性的穿着感。带有复古气息的经典格纹为日常休闲造型增添亮点。细窄肩带可调节且可拆卸，可根据造型在吊带款与抹胸款之间自由切换。富有弹性的抽褶设计令上身舒适贴合又不过分紧绷，是提升造型感的推荐单品。适合与休闲长裤、半身裙、牛仔单品以及T恤、衬衫、简约连衣裙等进行层叠搭配。', '<font color=\"#47c22e\"><b>立体感のあるシャーリングデザインが魅力のチェックビスチェ</b></font><br>		<br>■素材特性<br>ふんわりと優しい手触りと凹凸感が特徴です。<br>柔らかな生地にシャーリング加工を施し、伸縮性豊かな生地感に仕上げました◎<br>		<br>■デザイン<br>レトロ感のあるクラシックなチェック柄が、オトナのカジュアルスタイルにアクセントをプラスしてくれるビスチェ。<br>調節可能な華奢なストラップは取り外し可能な2WAY仕様のため、スタイルに合わせてお好きなシルエットを楽しめます！<br>伸縮性のあるシャーリングデザインは、ボディラインに心地よくフィットしラインを拾いすぎないところが嬉しいポイント◎<br>周りと差をつけたい人やスタイリングを格上げしたい人に今季おすすめのマストハブアイテムです！<br>		<br>■おすすめスタイリング	<br>リラックス感のあるパンツやハーフデニムとのバランスが◎<br>Tシャツやブラウス、シンプルなワンピなど、様々なアイテムとのレイヤードに最適です！<br>		<br>ーーー		<br>ビスチェ　レイヤード　アクセント　<br>ーーー', '4091.0 JPY', 249.55, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:24:31', '2026-04-02 04:17:15', 'adastria_492898', '', '69cd72d5a7ab618f2967ca84', '生活/休闲', '', '女', '青年（18-44岁）', '涤纶50%,棉50%', 'https://www.dot-st.com/nikoand/disp/item/492898/?COLOR_CD=18', '上装', '背心', '吊带背心', '', 'camisole', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/niko_and/20260401/item_492898_main_18_1747995185_b.jpg', 0, 0, 6, 0.78587, 0, 1, 1, 0, 0, 3, NULL, '高弹力，修饰身形，易于叠穿', '修饰身形,易于叠穿', '', '采用聚酯纤维与棉混纺面料，兼具柔软手感与一定挺括度,整体采用大面积松紧抽褶设计，增加立体感与包容度,肩带可拆卸，可在吊带与抹胸两种穿法间切换,经典复古格纹提升休闲造型的层次感', '格纹', '根据商品名“チェックビスチェ”和图片可见，这是覆盖上身的短款吊带式上衣，用于叠穿，不是内衣文胸，也不是常规T恤或背心，更接近时装类的吊带上衣，因此在给定列表中选择“camisole（吊带背心/吊带上衣）”最为合适。该类目定义为带细肩带、可单穿或打底叠穿的上衣，与本款可拆卸细肩带、短款上身设计高度吻合。', 1, 0, 0, 0, 'camisole', NULL, '', 0, NULL, 0, NULL, NULL, '18', 'チャコール(18)', 0);
INSERT INTO `clothing_info` VALUES (19996606, '抽褶格纹束身吊带上衣', 'シャーリングチェックビスチェ', 0, 200333, 'niko and ...', '', '', '立体感十足的抽褶设计格纹束身上衣。面料手感柔软蓬松，具有舒适的凹凸感，在柔和的布料上进行抽褶加工，呈现富有弹性的穿着感。带有复古气息的经典格纹为日常休闲造型增添亮点。细窄肩带可调节且可拆卸，可根据造型在吊带款与抹胸款之间自由切换。富有弹性的抽褶设计令上身舒适贴合又不过分紧绷，是提升造型感的推荐单品。适合与休闲长裤、半身裙、牛仔单品以及T恤、衬衫、简约连衣裙等进行层叠搭配。', '<font color=\"#47c22e\"><b>立体感のあるシャーリングデザインが魅力のチェックビスチェ</b></font><br>		<br>■素材特性<br>ふんわりと優しい手触りと凹凸感が特徴です。<br>柔らかな生地にシャーリング加工を施し、伸縮性豊かな生地感に仕上げました◎<br>		<br>■デザイン<br>レトロ感のあるクラシックなチェック柄が、オトナのカジュアルスタイルにアクセントをプラスしてくれるビスチェ。<br>調節可能な華奢なストラップは取り外し可能な2WAY仕様のため、スタイルに合わせてお好きなシルエットを楽しめます！<br>伸縮性のあるシャーリングデザインは、ボディラインに心地よくフィットしラインを拾いすぎないところが嬉しいポイント◎<br>周りと差をつけたい人やスタイリングを格上げしたい人に今季おすすめのマストハブアイテムです！<br>		<br>■おすすめスタイリング	<br>リラックス感のあるパンツやハーフデニムとのバランスが◎<br>Tシャツやブラウス、シンプルなワンピなど、様々なアイテムとのレイヤードに最適です！<br>		<br>ーーー		<br>ビスチェ　レイヤード　アクセント　<br>ーーー', '4091.0 JPY', 249.55, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:24:31', '2026-04-02 04:17:15', 'adastria_492898', '', '69cd72d5a7ab618f2967ca84', '生活/休闲', '', '女', '青年（18-44岁）', '涤纶50%,棉50%', 'https://www.dot-st.com/nikoand/disp/item/492898/?COLOR_CD=18', '上装', '背心', '吊带背心', '', 'camisole', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/niko_and/20260401/item_492898_main_70_1747995188_b.jpg', 0, 0, 2, 0.99243, 0, 1, 1, 0, 0, 3, NULL, '高弹力，修饰身形，易于叠穿', '修饰身形,易于叠穿', '', '采用聚酯纤维与棉混纺面料，兼具柔软手感与一定挺括度,整体采用大面积松紧抽褶设计，增加立体感与包容度,肩带可拆卸，可在吊带与抹胸两种穿法间切换,经典复古格纹提升休闲造型的层次感', '格纹', '根据商品名“チェックビスチェ”和图片可见，这是覆盖上身的短款吊带式上衣，用于叠穿，不是内衣文胸，也不是常规T恤或背心，更接近时装类的吊带上衣，因此在给定列表中选择“camisole（吊带背心/吊带上衣）”最为合适。该类目定义为带细肩带、可单穿或打底叠穿的上衣，与本款可拆卸细肩带、短款上身设计高度吻合。', 1, 1, 0, 0, 'camisole', NULL, '', 0, NULL, 0, NULL, NULL, '70', 'グリーン(70)', 0);
INSERT INTO `clothing_info` VALUES (19996602, '【CITY CREEK】清凉凝胶颈部围巾', '【CITY CREEK】ヒンヤリジェル', 0, 200333, 'niko and ...', '', '', '来自【CITY CREEK】的防暑清凉小物，以冷感凝胶搭配接触冷感面料围巾使用。围巾采用接触冷感面料制作，颈部接触面积大，能充分感受到清凉感。凝胶可反复冷却使用，使用时不会产生水滴，佩戴保持干爽舒适。非常适合户外、休闲、音乐节、公园露营等活跃场景，也适合通勤通学时的防暑降温，是炎热季节值得备上一条的实用配件。CITY CREEK 是将城市生活与户外自然连接的原创户外家具与工具系列，本品亦延续该系列的户外及室内双重使用设定。', '<b><font color=\"olivedrab\">【CITY CREEK】から暑さ対策グッズが登場！</font></b><br><br>暑さ対策にピッタリなヒンヤリアイテムがCITY CREEKから登場！<br><br>ジェルを入れるスカーフは接触冷感生地を使用。<br><br>首元の接触面が広く、冷たさをしっかり感じられます。<br><br>繰り返し使え、水滴が出ないので快適に使えるのもポイント◎<br><br>アウトドア・レジャー、フェスなどアクティブなシーンや通勤通学の暑さ対策にもピッタリ。<br><br>これからの季節に１つ持っておきたいアイテムです！<br><br>□冷却時間<br>冷蔵庫での冷却時間目安･･･1～2時間程度<br>冷凍庫での冷却時間目安･･･30分～1時間程度<br>※持続時間は、体温や使用環境(外気温)によって異なります。<br><br>【CITY CREEK(シティクリーク)】の2025年、新作アイテム一覧はこちらの！<br><a href=\"adastriaapp://items?dispNo=0000100016_002005148004&orderBy=00\" target=\"_blank\"><font color=\"olivedrab\"><b>＞＞and ST アプリの方はこちら</b></font></a><br><a href=\"https://www.dot-st.com/nikoand/disp/itemlist/?dispNo=002005148004\" target=\"_blank\"><font color=\"olivedrab\"><b>＞＞ブラウザの方はこちら</b></font></a><br><br>【CITY CREEK(シティクリーク)】シリーズのアイテムをチェック！<br><a href=\"adastriaapp://items?dispNo=0000100016_002005148&orderBy=00\" target=\"_blank\"><font color=\"olivedrab\"><b>＞＞and ST アプリの方はこちら</b></font></a><br><a href=\"https://www.dot-st.com/nikoand/disp/itemlist/?dispNo=002005148\" target=\"_blank\"><font color=\"olivedrab\"><b>＞＞ブラウザの方はこちら</b></font></a><br><br>【CITY CREEK（シティクリーク）】<br>意味は「CITY＝街」、「CREEK＝小川」。<br>都会と自然をつなぐ小川（クリーク）のように、フィールドだけでなく室内での使用も想定して誕生した<br>niko and ...オリジナルのアウトドアファニチャー＆ツールシリーズです。<br><br>ーーー<br>CITY CREEK　シティクリーク　レジャー　ピクニック　アウトドア　フェス　公園　キャンプ　暑さ対策　接触冷感生地<br>ーーー', '1200.0 JPY', 73.20, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:24:51', '2026-04-02 04:17:12', 'adastria_329092', '', '69cd72d5a7ab618f2967ca7f', '露营，徒步/登山，跑步，生活/休闲', '', '通用', '青年（18-44岁）', '锦纶90%,氨纶10%', 'https://www.dot-st.com/nikoand/disp/item/329092/?COLOR_CD=15', '其他服饰/物品', '其他', '配件', '', 'accessories', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/niko_and/20260401/item_329092_main_15_1745303935_b.jpg', 0, 0, 8, 0.89998, 0, 1, 0, 0, 0, 3, NULL, '接触冷感，降温，舒适佩戴，可重复使用', '降温,舒适佩戴,可重复使用', '吸水高分子材料冷凝技术,接触冷感面料应用', '通过将冷却凝胶放入围巾使用，增加颈部冷却接触面积,水滴不外渗，佩戴过程更加干爽舒适,适用于户外、通勤通学及室内使用,为品牌户外工具系列中的防暑配件类产品', '其他', '从名称和描述看，这是“【CITY CREEK】ヒンヤリジェル（清凉凝胶）”，实际以“ジェルを入れるスカーフ（可放入凝胶的围巾）”形式佩戴在颈部，用于户外和通勤的防暑降温。它不是服装主体、也不是床品或窗帘地毯等家纺，而是功能性穿戴小物，最接近列表中的配饰类，因此选择 sub_category 为“accessories（配饰）”。‘accessories’在这里可定义为：非主要服装结构、用于搭配或增强功能的穿戴类小物，如围巾、颈巾、帽子等。', 1, 0, 0, 0, 'accessories', NULL, '', 0, NULL, 0, NULL, NULL, '15', 'グレー(15)', 0);
