INSERT INTO `clothing_info` VALUES (19996596, '【HELLO KITTY】不锈钢水瓶', '【HELLO KITTY】ステンレスボトル', 0, 31749818, 'LOWRYS FARM', '', '', 'HELLO KITTY×LOWRYS FARM 第7弹联名款不锈钢水瓶。瓶盖是立体造型的哈啰凯蒂头像，采用硅胶材质，具有可爱立体效果。饮口可在吸管款与普通直饮款之间自由替换，满足不同饮水习惯。此款为保冷专用不锈钢水瓶。联名系列由多个人气品牌推出原创单品，与三丽鸥角色一起探索新的喜好。', 'HELLO KITTY×LOWRYS FARMのコラボレーションvol.7<br><br>ハローキティのお顔がキャップになっているのがポイントのステンレスボトル。<br>キャップはシリコン素材の立体になっています。<br>飲み口がストローバージョンと、通常バージョンと付け替え出来る仕様です。<br>※保冷専用のステンレスボトルです。<br><br><br>◆サンリオキャラクターズコラボについて<br>\"サンリオキャラクターズと一緒にPlay fashion!”<br>第7弾はand STで人気の10ブランド『GLOBAL WORK』『studio CLIP』『LOWRYS FARM』『JEANASIS』『BAYFLOW』『Heather』『repipi armario』『Elura』『ALAND』『10C REPIPI』のオリジナルアイテムが登場！<br>サンリオキャラクターズと一緒に新しい\"好き”を見つけにいこう！<br><br>(c)2026 SANRIO CO., LTD. APPROVAL NO. L664055', '3000.0 JPY', 183.00, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:25:23', '2026-04-02 04:17:07', 'adastria_641555', '', '69cd72d5a7ab618f2967ca72', '生活/休闲', '', '通用', '青少年（13-17岁）', NULL, 'https://www.dot-st.com/lowrysfarm/disp/item/641555/?COLOR_CD=09', '其他服饰/物品', '其他', '配件', '', 'accessories', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/lowrys_farm/20260401/item_641555_main_09_1767688365_b.jpg', 0, 0, 8, 0.80941, 0, 1, 0, 0, 0, 3, NULL, '保冷，便携', '保冷,便携', '', 'HELLO KITTY 合作款造型独特，瓶盖为立体角色头部设计,瓶身带人物图案装饰，整体卡通感强,可更换两种饮用方式的饮口（吸管式与普通直饮式）,瓶体为不锈钢材料，具备一定保冷性能,配有弹性材质提手，方便携带', '卡通人物（拟人化物体）', '产品为HELLO KITTY造型不锈钢水瓶，属于随身携带的小物件配饰类，并非服装或家纺用品，在提供的列表中最匹配的类别是“accessories（配饰）”，该类可涵盖水瓶等非服装功能性小件。', 1, 0, 0, 0, 'accessories', NULL, '', 0, NULL, 0, NULL, NULL, '09', 'BLK(09)', 0);
