INSERT INTO `clothing_info` VALUES (19996591, '【KIDS】LOGO中筒袜', '【KIDS】ロゴソックス', 0, 31749818, 'LOWRYS FARM', '', '', '使用旭化成具有优异除臭性的纱线制作，脚尖和脚跟部位做了加固处理。采用具有冲击力的LOGO字样与配色设计，可爱又有存在感，是LOWRYS FARM KIDS的定番款式的夏日延伸单品。简单造型中作为亮点单品很合适，本季推荐与短裤搭配出运动感风格。脚跟和脚尖的加固设计不易破洞，让每天都能根据心情和穿搭来选择“Match”的袜子。', 'ーーー<br>■素材■<br>旭化成の消臭性に優れた糸を使用しています。<br>つま先かかとも補強。<br><br>■デザイン■<br>インパクトのあるロゴデザインと配色がかわいいソックス！<br>ローリーズファームキッズの定番、<a href=\'https://www.dot-st.com/lowrysfarm/disp/item/286765/\'>カラーソックス</a>の同型で夏らしいアイテムです。<br>シンプルなスタイリングのポイントにぴったりで、今季はショーツとスポーティーな雰囲気で合わせるのがおすすめです！<br>かかととつま先も補強されていて穴が開きにくいのもポイント。<br>その日の気分やスタイリングに『Match』したソックス選びを楽しんでいただきたいです！<br>ーーー<br>', '500.0 JPY', 30.50, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:25:25', '2026-04-02 04:17:03', 'adastria_660116', '', '69cd72d5a7ab618f2967ca75', '生活/休闲', '', '通用', '儿童（4-12岁）', NULL, 'https://www.dot-st.com/lowrysfarm/disp/item/660116/?COLOR_CD=09', '配饰', '袜子', NULL, '', 'crew socks', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/lowrys_farm/20260401/item_660116_main_09_1774837959_b.jpg', 0, 0, 1, 0.92047, 0, -2, 0, 0, 0, 3, NULL, '除臭/抗异味，增强耐磨，增强支撑性', '增强耐磨,增强支撑性', '旭化成消臭功能纱线', '儿童中筒运动风短袜设计，侧面大LOGO字样增强视觉效果,脚尖和脚跟区域加固设计，提升耐穿度并不易破洞,适合搭配短裤等运动休闲造型', '字母，文字', '根据图片和描述可知这是儿童用中筒袜，袜筒长度在脚踝以上、小腿中部以下，英文通常归类为“crew socks”。在给定列表中与这种中筒日常功能袜最接近的子类就是“crew socks（中筒袜）”，因此选择该分类。', 1, 0, 0, 0, 'crew socks', NULL, '', 0, NULL, 0, NULL, NULL, '09', 'ブラック(09)', 0);
