INSERT INTO `clothing_info` VALUES (19996594, '【KIDS】LOGO中筒袜', '【KIDS】ロゴソックス', 0, 31749818, 'LOWRYS FARM', '', '', '使用旭化成具有优异除臭性的纱线制作，脚尖和脚跟部位做了加固处理。采用具有冲击力的LOGO字样与配色设计，可爱又有存在感，是LOWRYS FARM KIDS的定番款式的夏日延伸单品。简单造型中作为亮点单品很合适，本季推荐与短裤搭配出运动感风格。脚跟和脚尖的加固设计不易破洞，让每天都能根据心情和穿搭来选择“Match”的袜子。', 'ーーー<br>■素材■<br>旭化成の消臭性に優れた糸を使用しています。<br>つま先かかとも補強。<br><br>■デザイン■<br>インパクトのあるロゴデザインと配色がかわいいソックス！<br>ローリーズファームキッズの定番、<a href=\'https://www.dot-st.com/lowrysfarm/disp/item/286765/\'>カラーソックス</a>の同型で夏らしいアイテムです。<br>シンプルなスタイリングのポイントにぴったりで、今季はショーツとスポーティーな雰囲気で合わせるのがおすすめです！<br>かかととつま先も補強されていて穴が開きにくいのもポイント。<br>その日の気分やスタイリングに『Match』したソックス選びを楽しんでいただきたいです！<br>ーーー<br>', '500.0 JPY', 30.50, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:25:25', '2026-04-02 04:17:05', 'adastria_660116', '', '69cd72d5a7ab618f2967ca75', '生活/休闲', '', '通用', '儿童（4-12岁）', NULL, 'https://www.dot-st.com/lowrysfarm/disp/item/660116/?COLOR_CD=09', '配饰', '袜子', NULL, '', 'crew socks', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/lowrys_farm/20260401/item_660116_main_05_1774840485_b.jpg', 0, 0, 4, 0.74869, 0, 1, 0, 0, 0, 3, NULL, '除臭/抗异味，增强耐磨，增强支撑性', '增强耐磨,增强支撑性', '旭化成消臭功能纱线', '儿童中筒运动风短袜设计，侧面大LOGO字样增强视觉效果,脚尖和脚跟区域加固设计，提升耐穿度并不易破洞,适合搭配短裤等运动休闲造型', '字母，文字', '根据图片和描述可知这是儿童用中筒袜，袜筒长度在脚踝以上、小腿中部以下，英文通常归类为“crew socks”。在给定列表中与这种中筒日常功能袜最接近的子类就是“crew socks（中筒袜）”，因此选择该分类。', 1, 3, 0, 0, 'crew socks', NULL, '', 0, NULL, 0, NULL, NULL, '05', 'オフ(05)', 0);
INSERT INTO `clothing_info` VALUES (19996595, '【KIDS】LOGO中筒袜', '【KIDS】ロゴソックス', 0, 31749818, 'LOWRYS FARM', '', '', '使用旭化成具有优异除臭性的纱线制作，脚尖和脚跟部位做了加固处理。采用具有冲击力的LOGO字样与配色设计，可爱又有存在感，是LOWRYS FARM KIDS的定番款式的夏日延伸单品。简单造型中作为亮点单品很合适，本季推荐与短裤搭配出运动感风格。脚跟和脚尖的加固设计不易破洞，让每天都能根据心情和穿搭来选择“Match”的袜子。', 'ーーー<br>■素材■<br>旭化成の消臭性に優れた糸を使用しています。<br>つま先かかとも補強。<br><br>■デザイン■<br>インパクトのあるロゴデザインと配色がかわいいソックス！<br>ローリーズファームキッズの定番、<a href=\'https://www.dot-st.com/lowrysfarm/disp/item/286765/\'>カラーソックス</a>の同型で夏らしいアイテムです。<br>シンプルなスタイリングのポイントにぴったりで、今季はショーツとスポーティーな雰囲気で合わせるのがおすすめです！<br>かかととつま先も補強されていて穴が開きにくいのもポイント。<br>その日の気分やスタイリングに『Match』したソックス選びを楽しんでいただきたいです！<br>ーーー<br>', '500.0 JPY', 30.50, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:25:25', '2026-04-02 04:17:06', 'adastria_660116', '', '69cd72d5a7ab618f2967ca75', '生活/休闲', '', '通用', '儿童（4-12岁）', NULL, 'https://www.dot-st.com/lowrysfarm/disp/item/660116/?COLOR_CD=09', '配饰', '袜子', NULL, '', 'crew socks', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/lowrys_farm/20260401/item_660116_main_82_1774837973_b.jpg', 0, 0, 1, 0.85785, 0, -2, 0, 0, 0, 3, NULL, '除臭/抗异味，增强耐磨，增强支撑性', '增强耐磨,增强支撑性', '旭化成消臭功能纱线', '儿童中筒运动风短袜设计，侧面大LOGO字样增强视觉效果,脚尖和脚跟区域加固设计，提升耐穿度并不易破洞,适合搭配短裤等运动休闲造型', '字母，文字', '根据图片和描述可知这是儿童用中筒袜，袜筒长度在脚踝以上、小腿中部以下，英文通常归类为“crew socks”。在给定列表中与这种中筒日常功能袜最接近的子类就是“crew socks（中筒袜）”，因此选择该分类。', 1, 4, 0, 0, 'crew socks', NULL, '', 0, NULL, 0, NULL, NULL, '82', 'ブルー(82)', 0);
INSERT INTO `clothing_info` VALUES (19996590, '褶裥蓬感茧型长裤', 'タックボリュームコクーンパンツ', 0, 31749818, 'LOWRYS FARM', '', '', '采用具有沙沙触感、仿水洗复古感的面料制成的茧型长裤。材质轻盈但具有一定挺括度，可以很好地表现饱满的茧型轮廓。圆润的茧型剪裁，可以修饰并遮盖臀部与大腿区域。前片加入褶裥设计，兼具利落感与造型感，后腰为松紧设计，提升穿着舒适度。这是一条契合当下流行趋势的茧型长裤。建议与偏紧凑、短款或合身的上装搭配，营造当下感的造型平衡。可根据不同上装风格，在休闲与略显优雅正式的穿搭之间自由切换，具有很强的搭配性。', 'ーーー<br>■素材■<br>シャリ感のある手触りと、洗いざらしたようなヴィンテージ感のあるコクーンパンツ。<br>軽量ながらも張り感がでるため、コクーンのシルエットが美しく表現される素材となっています。<br><br>■デザイン■<br>丸みを帯びたコクーンシルエットが、ヒップから太もも周りをカバーします。<br>フロントタックを施すことで、きちんと感もありつつ後ろウエストはゴム仕様で着心地の良さを実現。<br>今年らしいコクーンシルエットのパンツです。	<br>ーーー<br>■スタイリング■	<br>コンパクトなトップスを合わせて、今年らしいバランスでのスタイルがおすすめ。<br>トップスによってカジュアルにもキレイ目の合わせにもマッチする着回し力抜群のアイテムです。		<br>', '6355.0 JPY', 387.65, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:25:54', '2026-04-02 04:17:02', 'adastria_327284', '', '69cd72d5a7ab618f2967ca6b', '生活/休闲', '', '女', '青年（18-44岁）', '棉64%,涤纶36%', 'https://www.dot-st.com/lowrysfarm/disp/item/327284/?COLOR_CD=08', '下装', '西裤', '裤装', '', 'trousers', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/lowrys_farm/20260401/item_327284_main_08_1744171472_b.jpg', 0, 0, 2, 0.58253, 0, 1, 1, 0, 0, 3, NULL, '修饰腿型，遮盖臀部和大腿，轻量，有挺括感', '修饰腿型,遮盖臀部和大腿,轻量,有挺括感', '', '锥形茧型版型，从臀部到大腿有宽松弧度,前片有打褶设计，后腰为松紧设计，提高舒适度,面料具有沙沙手感和仿水洗的复古感,既可搭配休闲上衣也可搭配偏正式上衣，搭配场景灵活', '纯色', '从商品名称“タックボリュームコクーンパンツ”和图片来看，是女性用的长裤，下装、腰头有松紧、整体为茧型轮廓，明显属于日常穿着的长款裤子，对应列表中最接近的类别是“trousers（长裤）”。定义：trousers 为覆盖双腿、通常长度到脚踝的日常长裤款式。', 0, 0, 0, 0, 'trousers', NULL, '', 0, NULL, 0, NULL, NULL, '08', 'アイボリー(08)', 0);
INSERT INTO `clothing_info` VALUES (19996585, '【官网先行预订】篮纹宽腿裤', '【WEB先行予約】バスケットワイドパンツ', 0, 31749818, 'LOWRYS FARM', '', '', '■素材■\n采用以聚酯纤维表现出亚麻般质感的仿麻面料。粗犷的多比组织与干爽的手感是其特点，很适合即将到来的季节。\n\n■设计■\n在前片加入较深的褶裥，使腰部周围更为宽松的宽腿裤。略高腰的设定，具有出色的拉长腿部比例效果。后腰为松紧设计，穿着轻松舒适。\n\n■搭配■\n推荐与同面料单品成套穿着。高腰与深褶设计，让上衣束进裤腰的穿法也十分有型。', 'ーーー<br>■素材■<br>ポリエステルで麻のような雰囲気を表現したリネンライクファブリック。<br>ざっくりとしたドビー組織でドライタッチな風合いが特徴的でこれからの時期にピッタリです。<br><br>■デザイン■<br>深めのタックを入れウエスト周りにゆとりを持たせたワイドパンツ。<br>ややハイウエストでの設定なので足長効果抜群です。<br>後ウエストはゴム仕様なので楽に着用していただけます。<br>ーーー<br>■スタイリング■<br>同素材のアイテムとのセットアップでの着用がオススメ。<br>ハイウエストで深めのタックが入っているのでインスタイルでも決まります。	<br><br>', '6000.0 JPY', 366.00, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:25:55', '2026-04-02 04:16:58', 'adastria_637610', '', '69cd72d5a7ab618f2967ca61', '生活/休闲', '', '女', '青年（18-44岁）', '涤纶100%', 'https://www.dot-st.com/lowrysfarm/disp/item/637610/?COLOR_CD=08', '下装', '休闲裤', '阔腿裤', '', 'palazzo pants', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/lowrys_farm/20260401/item_637610_main_08_1774345773_b.jpg', 0, 0, 2, 0.97578, 0, 1, 1, 0, 0, 3, NULL, '透气，显瘦修饰身形，舒适穿着，适合春夏季节', '显瘦修饰身形,舒适穿着,适合春夏季节', '仿麻感聚酯纤维面料', '采用聚酯纤维打造的仿麻感面料，具有干爽手感和粗犷的多比组织纹理,高腰深褶设计，拉长腿部比例，突出腰线,后腰松紧设计，兼顾版型和舒适度,可与同面料上装搭配，完成成套造型', '纯色，纯色', '从图片和描述来看，这是女装下装裤子，裤腿非常宽松、垂感强，整体是高腰宽腿廓形，属于典型的宽腿长裤轮廓。相比普通trousers更偏向时装感的阔腿裤风格，因此在给定列表中最接近的是“palazzo pants（阔腿裤）”。该子类通常指腰部合体、裤腿从上到下宽直、长度到脚面的女式阔腿长裤，符合本款产品的设计特征。', 1, 0, 0, 0, 'palazzo pants', NULL, '', 0, NULL, 0, NULL, NULL, '08', 'アイボリー08', 0);
INSERT INTO `clothing_info` VALUES (19996586, '【官网先行预订】篮纹宽腿裤', '【WEB先行予約】バスケットワイドパンツ', 0, 31749818, 'LOWRYS FARM', '', '', '■素材■\n采用以聚酯纤维表现出亚麻般质感的仿麻面料。粗犷的多比组织与干爽的手感是其特点，很适合即将到来的季节。\n\n■设计■\n在前片加入较深的褶裥，使腰部周围更为宽松的宽腿裤。略高腰的设定，具有出色的拉长腿部比例效果。后腰为松紧设计，穿着轻松舒适。\n\n■搭配■\n推荐与同面料单品成套穿着。高腰与深褶设计，让上衣束进裤腰的穿法也十分有型。', 'ーーー<br>■素材■<br>ポリエステルで麻のような雰囲気を表現したリネンライクファブリック。<br>ざっくりとしたドビー組織でドライタッチな風合いが特徴的でこれからの時期にピッタリです。<br><br>■デザイン■<br>深めのタックを入れウエスト周りにゆとりを持たせたワイドパンツ。<br>ややハイウエストでの設定なので足長効果抜群です。<br>後ウエストはゴム仕様なので楽に着用していただけます。<br>ーーー<br>■スタイリング■<br>同素材のアイテムとのセットアップでの着用がオススメ。<br>ハイウエストで深めのタックが入っているのでインスタイルでも決まります。	<br><br>', '6000.0 JPY', 366.00, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:25:55', '2026-04-02 04:16:58', 'adastria_637610', '', '69cd72d5a7ab618f2967ca61', '生活/休闲', '', '女', '青年（18-44岁）', '涤纶100%', 'https://www.dot-st.com/lowrysfarm/disp/item/637610/?COLOR_CD=08', '下装', '休闲裤', '阔腿裤', '', 'palazzo pants', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/lowrys_farm/20260401/item_637610_main_18_1771744687_b.jpg', 0, 0, 1, 0.87137, 0, -2, 0, 0, 0, 3, NULL, '透气，显瘦修饰身形，舒适穿着，适合春夏季节', '显瘦修饰身形,舒适穿着,适合春夏季节', '仿麻感聚酯纤维面料', '采用聚酯纤维打造的仿麻感面料，具有干爽手感和粗犷的多比组织纹理,高腰深褶设计，拉长腿部比例，突出腰线,后腰松紧设计，兼顾版型和舒适度,可与同面料上装搭配，完成成套造型', '纯色，纯色', '从图片和描述来看，这是女装下装裤子，裤腿非常宽松、垂感强，整体是高腰宽腿廓形，属于典型的宽腿长裤轮廓。相比普通trousers更偏向时装感的阔腿裤风格，因此在给定列表中最接近的是“palazzo pants（阔腿裤）”。该子类通常指腰部合体、裤腿从上到下宽直、长度到脚面的女式阔腿长裤，符合本款产品的设计特征。', 1, 1, 0, 0, 'palazzo pants', NULL, '', 0, NULL, 0, NULL, NULL, '18', 'チャコールグレー18', 0);
