INSERT INTO `clothing_info` VALUES (19996583, '麂皮流苏迷你半身裙', 'スエードフリンジミニスカート', 0, 31749818, 'LOWRYS FARM', '', '', '采用具有微绒起毛效果的仿麂皮面料，质地顺滑，手感细腻舒适。整体为本季感强烈的仿麂皮流苏迷你裙设计，无里布但面料不透，可安心单穿。腰部为全松紧设计，便于穿脱和与其他单品叠穿。与喇叭裤、牛仔裤等下装叠穿时，下摆流苏在行走间形成摆动效果，为造型增添亮点，一件即可打造时髦风格。', 'ーーー<br>■素材■<br>マイクロタッチの起毛感に仕上げる事で、滑らかで肌触りの良い風合いが特徴のフェイクスウェード生地を使用しています。<br><br>■デザイン■<br>フェイクスエードを使用した今年らしいフリンジミニスカート。<br>裏地は無しですが透けないので安心して一枚での着用もできます。<br>ウエストはオールゴム仕様になっていてレイヤードも楽にできるサイズ感にしています。<br>ーーー<br>■デザイン■<br>フレアパンツやデニムなどとレイヤードすると裾のフリンジがコーデのアクセントになります。<br>取り入れるだけで今っぽいスタイルが完成するアイテムです。', '5446.0 JPY', 332.21, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:25:57', '2026-04-02 04:16:56', 'adastria_574900', '', '69cd72d4a7ab618f2967ca5a', '生活/休闲', '', '女', '青年（18-44岁）', '涤纶100%', 'https://www.dot-st.com/lowrysfarm/disp/item/574900/?COLOR_CD=55', '裙装', '半身裙', '半身裙', '', 'skirt', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/lowrys_farm/20260401/item_574900_main_55_1750750205_b.jpg', 0, 0, 2, 0.84938, 0, 1, 1, 0, 0, 3, NULL, '舒适亲肤，不易走光，易于叠穿', '舒适亲肤,不易走光,易于叠穿', '', '仿麂皮质感，表面有细腻起毛手感,下摆长流苏装饰，增强摆动感和造型感,无衬里设计但面料不透,全松紧腰围，穿脱方便并适合叠穿造型,迷你裙长度，可与牛仔裤、喇叭裤等下装搭配形成层次感', '纯色', '商品名称为“スエードフリンジミニスカート”，日文中“スカート”明确指裙子；图片中也能看到是围绕腰部的下装单品，下摆有长流苏，整体轮廓为半身裙款式。因此归类为下装里的“skirt（半身裙）”。定义：skirt 指围绕腰部向下延伸、无裤腿结构的下装，可为迷你、中长或长款等各种长度。', 1, 0, 0, 0, 'skirt', NULL, '', 0, NULL, 0, NULL, NULL, '55', 'ブラウン55', 0);
INSERT INTO `clothing_info` VALUES (19996584, '麂皮流苏迷你半身裙', 'スエードフリンジミニスカート', 0, 31749818, 'LOWRYS FARM', '', '', '采用具有微绒起毛效果的仿麂皮面料，质地顺滑，手感细腻舒适。整体为本季感强烈的仿麂皮流苏迷你裙设计，无里布但面料不透，可安心单穿。腰部为全松紧设计，便于穿脱和与其他单品叠穿。与喇叭裤、牛仔裤等下装叠穿时，下摆流苏在行走间形成摆动效果，为造型增添亮点，一件即可打造时髦风格。', 'ーーー<br>■素材■<br>マイクロタッチの起毛感に仕上げる事で、滑らかで肌触りの良い風合いが特徴のフェイクスウェード生地を使用しています。<br><br>■デザイン■<br>フェイクスエードを使用した今年らしいフリンジミニスカート。<br>裏地は無しですが透けないので安心して一枚での着用もできます。<br>ウエストはオールゴム仕様になっていてレイヤードも楽にできるサイズ感にしています。<br>ーーー<br>■デザイン■<br>フレアパンツやデニムなどとレイヤードすると裾のフリンジがコーデのアクセントになります。<br>取り入れるだけで今っぽいスタイルが完成するアイテムです。', '5446.0 JPY', 332.21, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:25:57', '2026-04-02 04:16:57', 'adastria_574900', '', '69cd72d4a7ab618f2967ca5a', '生活/休闲', '', '女', '青年（18-44岁）', '涤纶100%', 'https://www.dot-st.com/lowrysfarm/disp/item/574900/?COLOR_CD=55', '裙装', '半身裙', '半身裙', '', 'skirt', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/lowrys_farm/20260401/item_574900_main_09_1750750127_b.jpg', 0, 0, 2, 0.93122, 0, 1, 1, 0, 0, 3, NULL, '舒适亲肤，不易走光，易于叠穿', '舒适亲肤,不易走光,易于叠穿', '', '仿麂皮质感，表面有细腻起毛手感,下摆长流苏装饰，增强摆动感和造型感,无衬里设计但面料不透,全松紧腰围，穿脱方便并适合叠穿造型,迷你裙长度，可与牛仔裤、喇叭裤等下装搭配形成层次感', '纯色', '商品名称为“スエードフリンジミニスカート”，日文中“スカート”明确指裙子；图片中也能看到是围绕腰部的下装单品，下摆有长流苏，整体轮廓为半身裙款式。因此归类为下装里的“skirt（半身裙）”。定义：skirt 指围绕腰部向下延伸、无裤腿结构的下装，可为迷你、中长或长款等各种长度。', 1, 1, 0, 0, 'skirt', NULL, '', 0, NULL, 0, NULL, NULL, '09', 'ブラック09', 0);
INSERT INTO `clothing_info` VALUES (19996582, '【THE NORTH FACE】防晒护颈帽 / SUNSHIELD CAP', '【THE NORTH FACE(ザ・ノース・フェイス)】SUNSHIELD CAP', 0, 31749823, 'BAYFLOW', '', '', '采用环保再生尼龙材质制作的防晒护颈帽。帽体侧面的网眼区域与护颈遮挡部分经过防虫处理，可有效减少蚊虫干扰；通过按扣即可轻松拆卸护颈部分，对颈部和后颈进行日晒防护。帽子两侧配有可固定帽檐的按扣，下巴系带可拆卸，后部抽绳调节可根据头围调节贴合度。具备UV防护功能（UPF15-30，紫外线阻隔率85%以上），适合春季残雪期到多个季节在强烈日照环境下的户外活动使用。', 'ーーー<br>環境に配慮したリサイクルナイロン素材を使用したサンシールドキャップです。<br>本体のメッシュ部とシールド部には虫よけ加工をプラス。スナップボタンで簡単に取り外しができるシールド部は、首周りの日焼け対策に効果的です。<br>両サイドにバイザー止めのスナップボタン付きで、あご紐は取り外し式。後部のアジャスターコードにより頭周りのフィット感の調節が可能です。<br>UVケア（UPF15-30、紫外線カット率85％以上）機能付きで、日差しが強い春の残雪期から幅広いシーズンで活用できます。<br>ーーー<br><br><br><b>【THE NORTH FACE(ザ・ノース・フェイス)】<br>1968年カリフォルニア州バークレーで創業。1969年ダウンウェアの原型となるシェラパーカーを発表以来、フレーム入りバックパック、<br>ドーム型テントなどの数々のイノベーションを送り出し、常に「今のベストであること」をスローガンに革新を続ける世界のトップアウトドアブランド。<b>/<br>', '6500.0 JPY', 396.50, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:27:32', '2026-04-02 04:16:55', 'adastria_117886', '', '69cd72d5a7ab618f2967ca60', '露营，徒步/登山，跑步，生活/休闲，高尔夫，差旅/商务', '', '通用', '青年（18-44岁）', '锦纶100%', 'https://www.dot-st.com/bayflow/disp/item/117886/?COLOR_CD=19', '配饰', '帽子', NULL, '', 'baseball cap', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/bayflow/20260401/item_117886_main_19_1730885141_b.jpg', 0, 0, 8, 0.54392, 0, 1, 0, 0, 0, 3, NULL, '防晒，透气，防蚊虫，可拆卸护颈遮阳片，可拆卸下巴系带，头围可调节，环保再生尼龙材质', '可拆卸护颈遮阳片,可拆卸下巴系带,头围可调节,环保再生尼龙材质', '防紫外线UVケア（UPF15-30）,防虫处理面料', '采用再生尼龙材质，兼顾环保与功能性,帽体侧面为网眼结构，提升透气性,后部抽绳调节结构增强贴合度和防风性,适用于春季残雪期到多个季节的强日照环境使用', '纯色', '从图片和描述看，这是户外品牌THE NORTH FACE的遮阳帽，前端有硬质帽檐，整体为软顶结构，带有可拆卸后挡片（护颈）和下巴系带，典型属于功能性棒球帽/遮阳帽范畴。在给定类目中没有更细的“sun cap”“outdoor cap”等选项，“baseball cap（棒球帽）”是最接近的帽子子类。其定义可理解为：带突出前檐、软顶结构、用于日常或户外防晒与休闲穿戴的帽子。', 0, 0, 0, 0, 'baseball cap', NULL, '', 0, NULL, 0, NULL, NULL, '19', 'ﾌﾞﾗｯｸ19', 0);
INSERT INTO `clothing_info` VALUES (19996580, '【CONVERSE】ALL STAR AGED OX 低帮帆布鞋', '【CONVERSE／コンバース】ALL STAR AGED OX', 0, 31749823, 'BAYFLOW', '', '', '这是ALL STAR AGED系列的配色款式，鞋面采用经过水洗处理的帆布材质，呈现自然做旧质感。提供经典海军蓝和亮眼信号红两种配色。配置方面包括：经过水洗处理的鞋面，本白色并带有光泽感的侧围胶条，6毫米宽棉质鞋带，高光泽金属鞋带孔眼，以及由高密度聚氨酯泡沫搭配橡胶海绵组成、具有良好缓震性的鞋垫。鞋楦以前掌前翘较低的经典轮廓为特征，整体呈现复古的ALL STAR风格。品牌源自CONVERSE RUBBER SHOE COMPANY，ALL STAR自1917年问世以来款式几乎未曾改变，并与JACK PURCELL、PRO LEATHER等一同构成经久不衰的经典运动鞋系列。', 'ーーー<br>オールスター エイジドのカラーアレンジモデル。<br>洗い加工を施したキャンバス素材をアッパーに採用。<br>クラシックネイビー、シグナルレッドの2カラー展開。<br><br>ALL STAR AGED SPEC<br>・洗い加工を施したアッパー<br>・艶出し加工を施した生成りテープ<br>・6ミリ幅のコットンシューレース<br>・光沢の強いハトメ<br>・クッション性に優れた高密度ウレタンフォームとラバースポンジのインソール<br>・トウスプリングを低めに設定したクラシックなシルエットのラスト<br>ーーー<br><br><b>【CONVERSE(コンバース)】<br>マーキス・M・コンバースが設立したコンバース・ラバー・シュー・カンパニーが起源。<br>コンバースの代表作である“オールスター”は1917年の誕生以来、<br>そのスタイルは現在もほとんど変わることなく生産され続けられています。<br>また、その他にもジャックパーセルやプロレザーなど長年愛され続け、<br>スニーカー史に名を残す名作が揃っています。</b>', '9000.0 JPY', 549.00, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:27:33', '2026-04-02 04:16:53', 'adastria_640708', '', '69cd72d4a7ab618f2967ca59', '生活/休闲', '', '通用', '青年（18-44岁）', NULL, 'https://www.dot-st.com/bayflow/disp/item/640708/?COLOR_CD=30', '其他服饰/物品', '其他', NULL, '', 'shoes', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/bayflow/20260401/item_640708_main_30_1774586510_b.jpg', 0, 0, 9, 0.99879, 0, 1, 0, 0, 0, 3, NULL, '缓震舒适，耐穿耐用', '缓震舒适,耐穿耐用', '高密度聚氨酯泡沫鞋垫', '低帮系带设计，适合日常搭配,鞋面为水洗处理帆布，更有复古感,鞋带为6毫米宽棉质鞋带，提升质感,鞋带孔为高光泽金属孔眼，视觉更醒目,鞋侧包边为做旧光泽处理的本白色胶条，突出AGED风格,前掌鞋楦前翘高度较低，呈经典复古轮廓,品牌为经典帆布鞋品牌，设计延续ALL STAR传统风格', '纯色', '从产品名称“ALL STAR”、品牌CONVERSE以及图片可以清晰看出，这是经典低帮帆布“球鞋/运动鞋”，属于穿在脚上的鞋履，并非服装或家纺用品。给定枚举中最接近且正确的类别是“shoes（鞋子）”，其定义为：覆盖足部、用于行走和日常穿着的鞋类产品，本商品完全符合这一点。', 1, 0, 0, 0, 'shoes', NULL, '', 0, NULL, 0, NULL, NULL, '30', 'ﾚｯﾄﾞ30', 0);
