INSERT INTO `clothing_info` VALUES (19996574, '〈预订〉【柔软穿着感】网眼感牛仔常规版裤【弹力・腰侧松紧设计】', '≪予約≫［柔らかい穿き心地］メッシュデニムレギュラーパンツ【ストレッチ・ウエストイージー仕様】', 0, 31749823, 'BAYFLOW', '', '', '采用表面具有凹凸感、呈现类似网眼效果的弹力牛仔面料，加入亚麻混纺，兼具季节感与舒适度。锥形剪裁简洁百搭，不挑上装。腰部两侧为松紧设计，穿着轻松舒适。通过做旧加工增强质感，非常适合夏季简约造型的搭配。推荐与具有度假感的衬衫或宽松T恤等单品组合穿着。', '<font color=#FF0040><b>予約期間中ポイント2倍!!</b></font><br><br>ーーー<br>POINT<br>[1]　メッシュのような表情のストレッチデニム生地<br>[2]　ウエスト横がゴムのイージー仕様<br>[3]　夏に穿きやすい生地感ながら、加工感をしっかりと出したデニムパンツ<br>ーーー<br><br>[fabric]<br>素材の表面に凹凸感があり、メッシュのような表情のストレッチデニム生地を使用。<br>リネンブレンドで季節感のある生地。<br><br>[design]<br>クセのないテーパードのデザインで、合わせるトップスを選ばないパンツ。<br>ウエスト横がゴムのイージー仕様で楽に穿ける。<br>しっかりと加工感を出しているので、シンプルになりがちな夏のスタイリングにぴったりのアイテム。<br><br>[styling]<br>リゾート感のあるシャツや、オーバーサイズのTシャツ等の合わせがおすすめ。', '8173.0 JPY', 498.55, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:27:42', '2026-04-02 04:16:48', 'adastria_639577', '', '69cd72d4a7ab618f2967ca53', '生活/休闲', '', '通用', '青年（18-44岁）', '棉88%,亚麻10%,氨纶2%', 'https://www.dot-st.com/bayflow/disp/item/639577/?COLOR_CD=82', '下装', '休闲裤', '女士裤装', '', 'pantsuit', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/bayflow/20260401/item_639577_main_82_1774928783_b.jpg', 0, 0, 2, 0.73747, 0, 1, 1, 0, 0, 3, NULL, '高弹力，舒适穿着，透气凉爽，弹力腰头设计', '舒适穿着,透气凉爽,弹力腰头设计', '', '表面具有类似网眼的凹凸纹理，增加季节感与透气性,加入亚麻混纺，提升夏季穿着的清爽感,腰侧采用松紧设计，提升穿脱与穿着的舒适度,锥形版型，便于搭配各类上装,做旧加工感增强夏季穿搭的造型感', '纯色', '从品类“パンツ”和描述“テーパードのデザインで…パンツ”可判断为长裤，下装裤装，不是家纺或上装，也不是短裤或裙装。款式为日常锥形休闲裤，对应列表中最接近的裤装大类为“pantsuit”，这里将其理解为长裤/裤装类别使用。', 1, 0, 0, 0, 'pantsuit', NULL, '', 0, NULL, 0, NULL, NULL, '82', 'ﾗｲﾄﾌﾞﾙｰ82', 0);
INSERT INTO `clothing_info` VALUES (19996575, '〈预订〉【柔软穿着感】网眼感牛仔常规版裤【弹力・腰侧松紧设计】', '≪予約≫［柔らかい穿き心地］メッシュデニムレギュラーパンツ【ストレッチ・ウエストイージー仕様】', 0, 31749823, 'BAYFLOW', '', '', '采用表面具有凹凸感、呈现类似网眼效果的弹力牛仔面料，加入亚麻混纺，兼具季节感与舒适度。锥形剪裁简洁百搭，不挑上装。腰部两侧为松紧设计，穿着轻松舒适。通过做旧加工增强质感，非常适合夏季简约造型的搭配。推荐与具有度假感的衬衫或宽松T恤等单品组合穿着。', '<font color=#FF0040><b>予約期間中ポイント2倍!!</b></font><br><br>ーーー<br>POINT<br>[1]　メッシュのような表情のストレッチデニム生地<br>[2]　ウエスト横がゴムのイージー仕様<br>[3]　夏に穿きやすい生地感ながら、加工感をしっかりと出したデニムパンツ<br>ーーー<br><br>[fabric]<br>素材の表面に凹凸感があり、メッシュのような表情のストレッチデニム生地を使用。<br>リネンブレンドで季節感のある生地。<br><br>[design]<br>クセのないテーパードのデザインで、合わせるトップスを選ばないパンツ。<br>ウエスト横がゴムのイージー仕様で楽に穿ける。<br>しっかりと加工感を出しているので、シンプルになりがちな夏のスタイリングにぴったりのアイテム。<br><br>[styling]<br>リゾート感のあるシャツや、オーバーサイズのTシャツ等の合わせがおすすめ。', '8173.0 JPY', 498.55, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:27:42', '2026-04-02 04:16:49', 'adastria_639577', '', '69cd72d4a7ab618f2967ca53', '生活/休闲', '', '通用', '青年（18-44岁）', '棉88%,亚麻10%,氨纶2%', 'https://www.dot-st.com/bayflow/disp/item/639577/?COLOR_CD=82', '下装', '休闲裤', '女士裤装', '', 'pantsuit', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/bayflow/20260401/item_639577_main_87_1774928790_b.jpg', 0, 0, 2, 0.86322, 0, 1, 1, 0, 0, 3, NULL, '高弹力，舒适穿着，透气凉爽，弹力腰头设计', '舒适穿着,透气凉爽,弹力腰头设计', '', '表面具有类似网眼的凹凸纹理，增加季节感与透气性,加入亚麻混纺，提升夏季穿着的清爽感,腰侧采用松紧设计，提升穿脱与穿着的舒适度,锥形版型，便于搭配各类上装,做旧加工感增强夏季穿搭的造型感', '纯色', '从品类“パンツ”和描述“テーパードのデザインで…パンツ”可判断为长裤，下装裤装，不是家纺或上装，也不是短裤或裙装。款式为日常锥形休闲裤，对应列表中最接近的裤装大类为“pantsuit”，这里将其理解为长裤/裤装类别使用。', 1, 1, 0, 0, 'pantsuit', NULL, '', 0, NULL, 0, NULL, NULL, '87', 'ｲﾝﾃﾞｨｺﾞ87', 0);
INSERT INTO `clothing_info` VALUES (19996576, '【预订】柔软好穿网眼质感牛仔工装裤【弹力・松紧腰设计】', '≪予約≫［柔らかくて穿きやすい］メッシュデニムペインターパンツ【ストレッチ・ウエストイージー仕様】', 0, 31749823, 'BAYFLOW', '', '', '采用表面具有凹凸感、呈现网眼质感的弹力牛仔面料，加入亚麻混纺，带来符合季节感的清爽穿着体验。BAYFLOW 经典工装风格的画匠裤版型，腰部两侧为松紧橡筋设计，穿着轻松舒适，同时通过明显的水洗与做旧加工，营造出具有存在感的牛仔质感，使夏季造型不显单调。右大腿处的小口袋增添低调细节，适合搭配具有度假感的衬衫或宽松 T 恤。', '<font color=#FF0040><b>予約期間中ポイント2倍!!</b></font><br><br>ーーー<br>POINT<br>[1]　メッシュのような表情のストレッチデニム生地<br>[2]　ウエスト横がゴムのイージー仕様<br>[3]　夏に穿きやすい生地感ながら、加工感をしっかりと出したデニムパンツ<br>ーーー<br><br>[fabric]<br>素材の表面に凹凸感がある、メッシュのような表情のストレッチデニム生地を使用。<br>リネンブレンドで季節感のある生地。<br><br>[design]<br>BAYFLOWでの定番のペインターデザイン。<br>ウエスト横がゴムのイージー仕様で楽に穿ける。<br>しっかりと加工感を出しているので、シンプルになりがちな夏のスタイリングにぴったりのアイテム。<br>右太もものミニポケットもさりげないポイント。<br><br>[styling]<br>リゾート感のあるシャツや、オーバーサイズのTシャツ等の合わせがおすすめ。<br>', '8173.0 JPY', 498.55, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:27:42', '2026-04-02 04:16:50', 'adastria_639575', '', '69cd72d4a7ab618f2967ca56', '生活/休闲', '', '男', '青年（18-44岁）', '棉88%,亚麻10%,氨纶2%', 'https://www.dot-st.com/bayflow/disp/item/639575/?COLOR_CD=86', '下装', '休闲裤', '女士裤装', '', 'pantsuit', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/bayflow/20260401/item_639575_main_86_1774934898_b.jpg', 0, 0, 2, 0.85712, 0, 1, 1, 0, 0, 3, NULL, '透气，高弹力，舒适，轻量，凉爽适夏，穿脱方便', '舒适,轻量,凉爽适夏,穿脱方便', '', '网眼感凹凸纹理牛仔面料,亚麻混纺增加季节感与透气性,腰侧松紧橡筋设计提升舒适度,右大腿处设有迷你口袋装饰与收纳,适合搭配度假风衬衫或宽松T恤', '纯色，纯色', '从商品名称与图片可知，这是长款牛仔“ペインターパンツ”，属于下装长裤类，而非上装或套装，也不是家纺用品。给定枚举中没有专门的“pants”或“jeans”通用标签，在靠近的选项里，真正表示长裤类别的只有“trousers”“dresspants”等。考虑到它是休闲工装风牛仔长裤，最接近的定义是“trousers”（长裤类统称），因此将其归入长裤子类“trousers”。【trousers：指日常穿着的长裤，下装单品，覆盖腰部到脚踝，用于休闲或通勤场景。】', 1, 0, 0, 0, 'pantsuit', NULL, '', 0, NULL, 0, NULL, NULL, '86', 'ﾌﾞﾙｰ86', 0);
