INSERT INTO `clothing_info` VALUES (19996578, '【预订】〈弹力〉软质牛仔常规长裤', '≪予約≫【ストレッチ】ソフトデニムレギュラーパンツ', 0, 31749823, 'BAYFLOW', '', '', '以SOFT&EASY为概念开发的6盎司轻量弹力牛仔面料，带来与薄牛仔不相符的优异延展性和舒适穿着感。略微修身的西裤式剪裁，腰部为松紧设计，营造轻松随性的牛仔长裤造型。推荐搭配略宽松版型的上装。', '<font color=#FF0040><b>予約期間中ポイント2倍!!</b></font><br><br>ーーー<br>POINT<br>[1]　軽量&ストレッチで穿き心地◎<br>[2]　トラウザー型のシルエットで合わせるトップスを選ばないアイテム<br>[3]　イージーパンツ仕様で楽に穿けるデニムパンツ<br>ーーー<br><br>[fabric]<br>SOFT&EASYをコンセプトに開発した6オンスの軽量ストレッチデニム生地を使用。<br>薄手のデニムらしからぬ伸び感で穿き心地が抜群。<br><br>[design]<br>ややスリムなトラウザー型のシルエット。<br>ウエストはイージー仕様でリラックス感のあるデニムパンツ。<br><br>[styling]<br>少し大きめなサイズ感のトップス合わせがおすすめ。<br>', '8173.0 JPY', 498.55, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:27:42', '2026-04-02 04:16:52', 'adastria_639560', '', '69cd72d4a7ab618f2967ca55', '生活/休闲', '', '通用', '青年（18-44岁）', '棉98%,氨纶2%', 'https://www.dot-st.com/bayflow/disp/item/639560/?COLOR_CD=88', '下装', '西裤', '裤装', '', 'trousers', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/bayflow/20260401/item_639560_main_88_1774595527_b.jpg', 0, 0, 6, 0.85640, 0, 1, 1, 0, 0, 3, NULL, '高弹力，轻量，舒适穿着', '轻量,舒适穿着', '', '6盎司轻量牛仔面料,腰部松紧设计，易于穿脱,版型略修身的长裤轮廓', '纯色', '从图片和描述看，这是长裤类服装，采用丹宁面料，整体为全长裤筒、带裤腰和口袋的典型下装，不是短裤也不是牛仔专门分类（如直筒牛仔裤列表中没有对应选项）。在给定枚举中，与“ソフトデニムレギュラーパンツ”“トラウザー型シルエット”最匹配的是“trousers”，即常规长裤类别。trousers：指腰部固定、覆盖下肢至脚踝的长裤类下装，包括休闲与正装长裤。', 1, 0, 0, 0, 'trousers', NULL, '', 0, NULL, 0, NULL, NULL, '88', 'ﾈｲﾋﾞｰ88', 0);
