INSERT INTO `clothing_info` VALUES (19996571, '【Manhattan Portage】背后印花T恤', '【Manhattan Portage(マンハッタンポーテージ)】バックプリントTシャツ', 0, 31749823, 'BAYFLOW', '', '', '使用14/- OE（空纺）纱线编织，带来干爽触感与硬朗氛围。版型为盒型的放松剪影。背部印花以1920年代“咆哮的二十年代”之后约100年的现在为背景，将不断发展的曼哈顿街景（曼哈顿LOGO）作为主题，运用象征美国国旗的红、蓝等色彩，营造略带动感的形象和配色。黑色款以夜晚的城市夜景为灵感，灰色款则以晨光沐浴下的城市为意象进行配色设计。\n\n【Manhattan Portage（曼哈顿ポーテージ）】\nManhattan Portage自1983年创立以来，一直以“New York Tough”为核心理念。品牌包袋在各处可见，已成为人人皆可拥有的包款。即便在享誉全球的同时，仍始终坚守源自纽约市的品牌根基。在瞬息万变的都市节奏中，以“打造人人都能一直使用的包袋”为概念，开发出简约且耐用的产品，如今已是街头时尚中不可或缺的品牌之一，以描绘曼哈顿天际线的醒目红色标志而备受追捧。', 'ーーー<br>ドライ感とタフな雰囲気を14/- OE (空紡) 糸で編み立てました。<br>サイズ感はボックス型のリラックスシルエット。<br>プリント柄に関しては、ROARING TWENTIES（1920年代）から歩む事約100年後の現在、<br>アメリカの象徴として発展したマンハッタンの街並み（マンハッタンのLOGO)をモチーフにアメリカの象徴的な国旗の色赤、青、ブルーを使い少しアクティブなイメージを感じさせるデザインで作成色展開。<br>ブラックボディは夜の夜景、グレーボディは朝の光を浴びた街をイメージした配色にしています。<br>ーーー<br><br><b>【Manhattan Portage（マンハッタンポーテージ）】<br>Manhattan Portageが1983年に実現しようと試みたシンプルな哲学、それが“New York Tough”。<br>Manhattan Portageのバッグは実に至るところで見かけられ、誰もが持っているバッグとなった。<br>世界中で人気を博す一方で、Manhattan PortageはそのルーツであるNYCに忠実であり続けている。<br>1983年にアメリカのニューヨークで創立。<br>都会において、時代がスピーディーに移り変わりゆく中でも、「誰もがずっと使い続けることのできるバッグを」<br>というコンセプトの元に、シンプルかつ耐久性の高い商品を開発している。<br>今やストリートファッションには欠かせないブランド。マンハッタンの街並みが描かれた赤いロゴが有名で、絶大な人気を誇っている。</b>', '5800.0 JPY', 353.80, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:27:48', '2026-04-02 04:16:46', 'adastria_666579', '', '69cd72d4a7ab618f2967ca4a', '生活/休闲', '', '通用', '青年（18-44岁）', '棉100%', 'https://www.dot-st.com/bayflow/disp/item/666579/?COLOR_CD=19', '上装', 'T恤', 'T恤', '', 't-shirt', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/bayflow/20260401/item_666579_main_19_1774597141_b.jpg', 0, 0, 7, 0.98891, 0, 1, 1, 0, 0, 3, NULL, '透气，耐用', '耐用', '', '14番手OE空纺纱针织，具有干爽触感和硬挺质感,盒型宽松版型，休闲感强,背部大面积品牌与城市图案印花设计,以曼哈顿城市和美国国旗红蓝配色为灵感的设计概念', '文字，物体', '从商品名“バックプリントTシャツ”以及图片可以看出，这是短袖圆领、针织面料制作的上衣，版型为休闲盒型轮廓，典型为“T恤（t-shirt）”款式。因此选择子类为“t-shirt”，即日常针织短袖上衣类别。', 1, 0, 0, 0, 't-shirt', NULL, '', 0, NULL, 0, NULL, NULL, '19', 'ﾌﾞﾗｯｸ19', 0);
INSERT INTO `clothing_info` VALUES (19996572, '【Manhattan Portage】背后印花T恤', '【Manhattan Portage(マンハッタンポーテージ)】バックプリントTシャツ', 0, 31749823, 'BAYFLOW', '', '', '使用14/- OE（空纺）纱线编织，带来干爽触感与硬朗氛围。版型为盒型的放松剪影。背部印花以1920年代“咆哮的二十年代”之后约100年的现在为背景，将不断发展的曼哈顿街景（曼哈顿LOGO）作为主题，运用象征美国国旗的红、蓝等色彩，营造略带动感的形象和配色。黑色款以夜晚的城市夜景为灵感，灰色款则以晨光沐浴下的城市为意象进行配色设计。\n\n【Manhattan Portage（曼哈顿ポーテージ）】\nManhattan Portage自1983年创立以来，一直以“New York Tough”为核心理念。品牌包袋在各处可见，已成为人人皆可拥有的包款。即便在享誉全球的同时，仍始终坚守源自纽约市的品牌根基。在瞬息万变的都市节奏中，以“打造人人都能一直使用的包袋”为概念，开发出简约且耐用的产品，如今已是街头时尚中不可或缺的品牌之一，以描绘曼哈顿天际线的醒目红色标志而备受追捧。', 'ーーー<br>ドライ感とタフな雰囲気を14/- OE (空紡) 糸で編み立てました。<br>サイズ感はボックス型のリラックスシルエット。<br>プリント柄に関しては、ROARING TWENTIES（1920年代）から歩む事約100年後の現在、<br>アメリカの象徴として発展したマンハッタンの街並み（マンハッタンのLOGO)をモチーフにアメリカの象徴的な国旗の色赤、青、ブルーを使い少しアクティブなイメージを感じさせるデザインで作成色展開。<br>ブラックボディは夜の夜景、グレーボディは朝の光を浴びた街をイメージした配色にしています。<br>ーーー<br><br><b>【Manhattan Portage（マンハッタンポーテージ）】<br>Manhattan Portageが1983年に実現しようと試みたシンプルな哲学、それが“New York Tough”。<br>Manhattan Portageのバッグは実に至るところで見かけられ、誰もが持っているバッグとなった。<br>世界中で人気を博す一方で、Manhattan PortageはそのルーツであるNYCに忠実であり続けている。<br>1983年にアメリカのニューヨークで創立。<br>都会において、時代がスピーディーに移り変わりゆく中でも、「誰もがずっと使い続けることのできるバッグを」<br>というコンセプトの元に、シンプルかつ耐久性の高い商品を開発している。<br>今やストリートファッションには欠かせないブランド。マンハッタンの街並みが描かれた赤いロゴが有名で、絶大な人気を誇っている。</b>', '5800.0 JPY', 353.80, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:27:48', '2026-04-02 04:16:47', 'adastria_666579', '', '69cd72d4a7ab618f2967ca4a', '生活/休闲', '', '通用', '青年（18-44岁）', '棉100%', 'https://www.dot-st.com/bayflow/disp/item/666579/?COLOR_CD=19', '上装', 'T恤', 'T恤', '', 't-shirt', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/bayflow/20260401/item_666579_main_11_1774597114_b.jpg', 0, 0, 5, 0.83138, 0, 1, 1, 0, 0, 3, NULL, '透气，耐用', '耐用', '', '14番手OE空纺纱针织，具有干爽触感和硬挺质感,盒型宽松版型，休闲感强,背部大面积品牌与城市图案印花设计,以曼哈顿城市和美国国旗红蓝配色为灵感的设计概念', '文字，物体', '从商品名“バックプリントTシャツ”以及图片可以看出，这是短袖圆领、针织面料制作的上衣，版型为休闲盒型轮廓，典型为“T恤（t-shirt）”款式。因此选择子类为“t-shirt”，即日常针织短袖上衣类别。', 1, 1, 0, 0, 't-shirt', NULL, '', 0, NULL, 0, NULL, NULL, '11', 'ｵﾌﾎﾜｲﾄ11', 0);
