INSERT INTO `clothing_info` VALUES (19996569, '【预订】细带平底凉鞋', '≪予約≫ストラップフラットサンダル', 0, 31749823, 'BAYFLOW', '', '', '纤细鞋带设计，营造柔美女性印象的平底凉鞋。让脚部线条显得利落，同时打造带有轻盈感的穿搭效果。采用舒适贴合脚型的结构，适合日常频繁穿着。简约设计，既能搭配偏优雅的造型，也能轻松融入休闲风格，是一款百搭单品。', 'ーーー<br>華奢なストラップが女性らしい印象のフラットサンダル。<br>足元をすっきりと見せつつ、抜け感のあるスタイリングが完成します。<br>フレフィット仕様で履き心地が良く、デイリー使いにもおすすめ。<br>シンプルなデザインなので、きれいめにもカジュアルにも合わせやすい万能アイテムです。<br>ーーー', '5900.0 JPY', 359.90, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:27:57', '2026-04-02 04:16:44', 'adastria_660745', '', '69cd72d4a7ab618f2967ca49', '生活/休闲', '', '女', '青年（18-44岁）', '皮革100%', 'https://www.dot-st.com/bayflow/disp/item/660745/?COLOR_CD=19', '其他服饰/物品', '其他', NULL, '', 'shoes', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/bayflow/20260401/item_660745_main_19_1773647562_b.jpg', 0, 0, 9, 0.86644, 0, 1, 0, 0, 0, 3, NULL, '舒适穿着感', '舒适穿着感', '', '细带设计，视觉上显腿部纤细,平底款式，适合日常长时间行走,可搭配通勤和休闲多种风格,使用合成皮革鞋面和合成底材质', '纯色，纯色', '根据商品名称“ストラップフラットサンダル”和图片可见，这是露趾平底凉鞋，属于穿在脚上的鞋类，而非服装或家纺，因此从列表中选择最接近的“shoes”。“shoes”定义为各种鞋履产品，本商品为细带平底凉鞋，完全符合鞋类范畴。', 1, 0, 0, 0, 'shoes', NULL, '', 0, NULL, 0, NULL, NULL, '19', 'ﾌﾞﾗｯｸ19', 0);
INSERT INTO `clothing_info` VALUES (19996570, '【预订】细带平底凉鞋', '≪予約≫ストラップフラットサンダル', 0, 31749823, 'BAYFLOW', '', '', '纤细鞋带设计，营造柔美女性印象的平底凉鞋。让脚部线条显得利落，同时打造带有轻盈感的穿搭效果。采用舒适贴合脚型的结构，适合日常频繁穿着。简约设计，既能搭配偏优雅的造型，也能轻松融入休闲风格，是一款百搭单品。', 'ーーー<br>華奢なストラップが女性らしい印象のフラットサンダル。<br>足元をすっきりと見せつつ、抜け感のあるスタイリングが完成します。<br>フレフィット仕様で履き心地が良く、デイリー使いにもおすすめ。<br>シンプルなデザインなので、きれいめにもカジュアルにも合わせやすい万能アイテムです。<br>ーーー', '5900.0 JPY', 359.90, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:27:57', '2026-04-02 04:16:45', 'adastria_660745', '', '69cd72d4a7ab618f2967ca49', '生活/休闲', '', '女', '青年（18-44岁）', '皮革100%', 'https://www.dot-st.com/bayflow/disp/item/660745/?COLOR_CD=19', '其他服饰/物品', '其他', NULL, '', 'shoes', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/bayflow/20260401/item_660745_main_12_1773647559_b.jpg', 0, 0, 9, 0.76057, 0, 1, 0, 0, 0, 3, NULL, '舒适穿着感', '舒适穿着感', '', '细带设计，视觉上显腿部纤细,平底款式，适合日常长时间行走,可搭配通勤和休闲多种风格,使用合成皮革鞋面和合成底材质', '纯色，纯色', '根据商品名称“ストラップフラットサンダル”和图片可见，这是露趾平底凉鞋，属于穿在脚上的鞋类，而非服装或家纺，因此从列表中选择最接近的“shoes”。“shoes”定义为各种鞋履产品，本商品为细带平底凉鞋，完全符合鞋类范畴。', 1, 1, 0, 0, 'shoes', NULL, '', 0, NULL, 0, NULL, NULL, '12', 'ｼﾙﾊﾞｰ12', 0);
INSERT INTO `clothing_info` VALUES (19996567, '≪预订≫【可成套穿搭】卡拉米半袖西装外套', '≪予約≫[セットアップ着用可能]カラミハーフスリーブジャケット', 0, 31749823, 'BAYFLOW', '', '', '宽松廓形设计的半袖西装式夹克。\n———\n推荐要点：\n[1] 采用适合穿到夏季的清爽柔软面料\n[2] 宽翻折设计的袖口\n[3] 可从休闲到干练通勤风多场合穿着\n[4] 可与同面料单品组成套装穿搭\n\n【面料】\n选用多色纱线织就的卡拉米面料。表面清凉干爽，同时保有柔软手感。提供偏米色的象牙米与偏黑色的两种配色。\n\n【设计】\n宽翻折袖口是亮点。双排扣搭配翻盖口袋设计，兼具正式感与休闲感，是一款顺应潮流的单品。\n\n【穿搭】\n推荐与牛仔裤或吊带裙搭配。同面料短裤也可搭配成套造型。', '<font color=#FF0040><b>予約期間中ポイント2倍!!</b></font><br><br>オーバーシルエットデザインの半袖テーラードジャケット<br>ーーー<br>★おすすめポイント★<br>[1]夏まで着用できるサラッとした柔らかい素材感<br>[2]太めターンUPデザインスリーブ<br>[3]カジュアル～キレイ目まで対応<br>[4]セットアップ着用可能<br>ーーー<br><br>[fabric]<br>多色で織り上げた、からみ素材を使用。<br>清涼感のあるさらっとした表面でありながら柔らかく仕上げた風合いが特徴。<br>アイボリーベージュ系とブラック系の2色展開。<br><br>[design]<br>太めターンUPデザインスリーブがポイント。<br>ダブル前でフラップポケットデザインのきちんと感がありながら、素材と袖デザインでカジュアルに落とし込んだトレンド感のあるアイテム。<br><br>[styling]<br>デニムやキャミワンピースコーデがおすすめ。<br>同素材でショートパンツとのセットアップコーディネートも可能。<br><br><b>【セットアップ着用可能なボトムスはこちら】</b><br>カラミショートパンツ<br>ブラウザの方は>><a href=\"https://www.dot-st.com/bayflow/disp/item/661931/\"><b>こちら</b></font></a><br>アプリの方は>><a href=\"adastriaapp://item?itemCode=661931\"><b>こちら</b></font></a><br>', '6800.0 JPY', 414.80, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:27:58', '2026-04-02 04:16:43', 'adastria_661930', '', '69cd72d4a7ab618f2967ca3c', '生活/休闲', '', '女', '青年（18-44岁）', '涤纶100%', 'https://www.dot-st.com/bayflow/disp/item/661930/?COLOR_CD=55', '上装', '西装外套', '西装外套', '', 'blazer', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/bayflow/20260401/item_661930_main_55_1774856892_b.jpg', 0, 0, 1, 0.99953, 0, -2, 0, 0, 0, 3, NULL, '透气，清凉感，轻盈垂坠，适合夏季穿着', '清凉感,轻盈垂坠,适合夏季穿着', '', '多色纱线经纬交织形成的“卡拉米”织物结构，表面清爽干爽同时保持柔软触感,宽松廓形与半袖设计，适合叠穿与休闲正装混搭,双排扣与翻盖口袋设计增强正式感，同时通过面料与袖口翻折细节弱化拘谨感,提供与同面料短裤组合成套穿搭的搭配方案', '纯色', '从产品名“ハーフスリーブジャケット”和描述中“ダブル前でフラップポケット”“テーラードジャケット”可以看出，这是有翻驳领、双排扣、带翻盖口袋的西装式上装，版型为半袖、宽松廓形，但整体仍是偏正式的西服外套款式。与列表中的“jacket”相比，它更接近带西装领的“blazer（西装外套）”。因此选择子类为“blazer（西装外套）”，即带翻领、结构感较强，可用于休闲与正装混搭的外套。', 1, 0, 0, 0, 'blazer', NULL, '', 0, NULL, 0, NULL, NULL, '55', 'ﾍﾞｰｼﾞｭ55', 0);
