INSERT INTO `clothing_info` VALUES (19996565, '【预订】〈可成套搭配〉KARAMI 织短裤', '≪予約≫[セットアップ着用可能]カラミショートパンツ', 0, 31749823, 'BAYFLOW', '', '', '营造利落正式感的褶皱短裤。\n\n【面料】\n采用多色纱交织而成的カラミ材质，表面清爽干练同时具有柔软手感，带来清凉舒适的穿着体验。提供偏米白的米色系与黑色系两种颜色。\n\n【设计】\n腰部配有双纽扣设计，后腰为松紧结构，穿着轻松舒适。前片加入中心压褶，在保持轻松感的同时呈现利落感的流行单品。\n\n【穿搭】\n推荐与Logo T恤或宽松衬衫搭配。也可以与同材质的短袖夹克组合，打造成套造型。', '<font color=#FF0040><b>予約期間中ポイント2倍!!</b></font><br><br>きちんと感のでるタックショートパンツ<br>ーーー<br>★おすすめポイント★<br>[1]シワになりにくい素材<br>[2]ウエストのボタンがアクセントに<br>[3]後ろゴム入りで楽ちん<br>[4]セットアップ着用可能<br>ーーー<br><br>[fabric]<br>多色で織り上げた、カラミ素材を使用。<br>清涼感のあるさらっとした表面でありながら柔らかく仕上げた風合いが特徴。<br>アイボリーベージュ系とブラック系の2色展開。<br><br>[design]<br>ウエストに2つボタンをつけたデザイン<br>後ろゴムいりで楽ちんな仕様に。<br>センタープレスいりで、きちんと感のあるトレンドアイテム。<br><br>[styling]<br>ロゴTシャツやゆるめのシャツとのコーデがおすすめ。<br>同素材のジャケットとのセットアップコーディネートも可能。<br><br><b>【セットアップ着用可能なジャケットはこちら】</b><br>カラミハーフスリーブジャケット<br>ブラウザの方は>><a href=\"https://www.dot-st.com/bayflow/disp/item/661930/\"><b>こちら</b></font></a><br>アプリの方は>><a href=\"adastriaapp://item?itemCode=661930\"><b>こちら</b></font></a>', '5446.0 JPY', 332.21, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:28:00', '2026-04-02 04:16:41', 'adastria_661931', '', '69cd72d4a7ab618f2967ca3b', '生活/休闲', '', '女', '青年（18-44岁）', '涤纶100%', 'https://www.dot-st.com/bayflow/disp/item/661931/?COLOR_CD=55', '下装', '短裤', '短裤', '', 'shorts', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/bayflow/20260401/item_661931_main_55_1774856966_b.jpg', 0, 0, 1, 0.99505, 0, -2, 0, 0, 0, 3, NULL, '透气，清凉感，不易起皱，舒适穿着，可成套穿着', '清凉感,不易起皱,舒适穿着,可成套穿着', '', '多色纱交织的カラミ织物，表面干爽清凉又柔软,后腰松紧设计提升舒适度与适配度,前中心压褶设计强调利落正式感,可与同面料短袖夹克搭配成套造型', '其他', '商品名称为“カラミショートパンツ”，说明是短裤；图片中裤长在大腿中上部、裤脚宽松，典型女式休闲短裤版型，因此从列表中选择“shorts（短裤）”作为最合适的 sub_category。shorts 指长度至大腿或膝上的下装裤款，用于日常或休闲穿着。', 1, 0, 0, 0, 'shorts', NULL, '', 0, NULL, 0, NULL, NULL, '55', 'ﾍﾞｰｼﾞｭ55', 0);
