INSERT INTO `clothing_info` VALUES (19996563, '拼接条纹吊带连衣裙／网络预售', 'キリカエストライプキャミワンピース/WEB先行予約', 0, 200336, 'A part by', '', '', '采用曲线拼接设计，营造独特且修饰身形的吊带连衣裙。肩带可调节长度，适合身材娇小或喜欢不同穿着长度的女性，无论是提高领口还是穿成拖地长款都别具风格。色彩以夏季深棕色和海军蓝为主，凸显成熟稳重气质。\n面料兼具再生纤维和麻的特性，既有垂坠感，又保留自然质感，配以细针条纹图案，整体呈现干练的成熟女性风格。布料手感清爽，适合夏季穿着。可单穿，也可以搭配外套、无袖针织或logo T恤进行叠搭造型。', 'ーーー<br>・曲線の切り替えでおしゃれ見え<br>・シルエットもきれいでる唯一無二のデザインのキャミワンピース	<br>ーーー<br><br>【デザインと特徴】							<br>・肩ひもで着丈調整可能で、小柄さんも◎首を詰めても、ずるっとマキシ丈で着てもかわいい。		<br>・夏のダークなブラウンとネイビーの色展開でどちらも大人っぽく。				<br><br>【素材特徴】									<br>・レーヨンの落ち感とリネンのナチュラル感に、ピンストライプの大人っぽさが絶妙なバランスのよい生地								<br>・さらっとした質感で夏も涼しく<br><br>【スタイリング】<br>・１枚でも、ジャケット合わせもかわいいです。<br>・ノースリニットや、ロゴＴシャツも中にいれても◎<br><br>【洗濯可否】<br>手洗いでのお手入れが可能です。<br>', '15000.0 JPY', 915.00, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:30:04', '2026-04-02 04:16:39', 'adastria_672040', '', '69cd72d4a7ab618f2967ca34', '生活/休闲', '', '女', '青年（18-44岁）', '粘胶16%,涤纶5%,亚麻4%', 'https://www.dot-st.com/apartbylowrys/disp/item/672040/?COLOR_CD=58', '裙装', '连衣裙', '吊带裙', '', 'slip dress', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/a_part_by/20260401/item_672040_main_58_1774597244_b.jpg', 0, 0, 3, 0.63020, 0, -2, 0, 0, 0, 3, NULL, '透气，凉爽舒适', '凉爽舒适', '', '可通过肩带调节裙长，适合不同身高人群,曲线拼接剪裁，突出飘逸廓形,细针条纹提升成熟感与显瘦效果,适合单穿或与外套、针织衫、T恤叠搭', '条纹', '商品名称为“キャミワンピース”，说明是吊带款连衣裙；版型为细肩带、无袖、长及脚踝并且可以单穿或内搭，整体为一片式裙身，最符合西文分类中的“slip dress（吊带裙/内搭感连衣裙）”定义。slip dress 通常为肩带细、线条简洁、可作为连衣裙或内搭层穿，本商品特征与之高度一致。', 1, 0, 0, 0, 'slip dress', NULL, '', 0, NULL, 0, NULL, NULL, '58', 'ブラウンチェック(58)', 0);
INSERT INTO `clothing_info` VALUES (19996564, '拼接条纹吊带连衣裙／网络预售', 'キリカエストライプキャミワンピース/WEB先行予約', 0, 200336, 'A part by', '', '', '采用曲线拼接设计，营造独特且修饰身形的吊带连衣裙。肩带可调节长度，适合身材娇小或喜欢不同穿着长度的女性，无论是提高领口还是穿成拖地长款都别具风格。色彩以夏季深棕色和海军蓝为主，凸显成熟稳重气质。\n面料兼具再生纤维和麻的特性，既有垂坠感，又保留自然质感，配以细针条纹图案，整体呈现干练的成熟女性风格。布料手感清爽，适合夏季穿着。可单穿，也可以搭配外套、无袖针织或logo T恤进行叠搭造型。', 'ーーー<br>・曲線の切り替えでおしゃれ見え<br>・シルエットもきれいでる唯一無二のデザインのキャミワンピース	<br>ーーー<br><br>【デザインと特徴】							<br>・肩ひもで着丈調整可能で、小柄さんも◎首を詰めても、ずるっとマキシ丈で着てもかわいい。		<br>・夏のダークなブラウンとネイビーの色展開でどちらも大人っぽく。				<br><br>【素材特徴】									<br>・レーヨンの落ち感とリネンのナチュラル感に、ピンストライプの大人っぽさが絶妙なバランスのよい生地								<br>・さらっとした質感で夏も涼しく<br><br>【スタイリング】<br>・１枚でも、ジャケット合わせもかわいいです。<br>・ノースリニットや、ロゴＴシャツも中にいれても◎<br><br>【洗濯可否】<br>手洗いでのお手入れが可能です。<br>', '15000.0 JPY', 915.00, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:30:04', '2026-04-02 04:16:40', 'adastria_672040', '', '69cd72d4a7ab618f2967ca34', '生活/休闲', '', '女', '青年（18-44岁）', '粘胶16%,涤纶5%,亚麻4%', 'https://www.dot-st.com/apartbylowrys/disp/item/672040/?COLOR_CD=58', '裙装', '连衣裙', '吊带裙', '', 'slip dress', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/a_part_by/20260401/item_672040_main_88_1774597241_b.jpg', 0, 0, 2, 0.83345, 0, 1, 1, 0, 0, 3, NULL, '透气，凉爽舒适', '凉爽舒适', '', '可通过肩带调节裙长，适合不同身高人群,曲线拼接剪裁，突出飘逸廓形,细针条纹提升成熟感与显瘦效果,适合单穿或与外套、针织衫、T恤叠搭', '条纹', '商品名称为“キャミワンピース”，说明是吊带款连衣裙；版型为细肩带、无袖、长及脚踝并且可以单穿或内搭，整体为一片式裙身，最符合西文分类中的“slip dress（吊带裙/内搭感连衣裙）”定义。slip dress 通常为肩带细、线条简洁、可作为连衣裙或内搭层穿，本商品特征与之高度一致。', 1, 1, 0, 0, 'slip dress', NULL, '', 0, NULL, 0, NULL, NULL, '88', 'ネイビーチェック(88)', 0);
INSERT INTO `clothing_info` VALUES (19996561, '撞色V领长款连衣裙 / 网络先行预订', 'ハイショクＶネックワンピース/WEB先行予約', 0, 200336, 'A part by', '', '', '郁金香袖搭配撞色滚边是亮点的V领连衣裙。\n\n【设计与特点】\n・略窄肩宽的泡泡袖叠加V领设计，带来利落修长的视觉效果。\n・背部采用方形领口，增添优雅感。\n・胸围区域略微合身，下摆呈轻微A字轮廓，成熟女性也易于驾驭。\n・两侧配有口袋。\n\n【面料特点】\n・采用表面呈波状细小凹凸的沙卡面料。\n・凹凸结构减少与肌肤的接触面积，穿着清爽，适合夏季。\n・质地轻盈，不易起皱，日常打理方便。\n\n【搭配建议】\n・可搭配迷你包与高跟凉鞋，适用于较为华丽的出席场合。\n・配运动鞋则更显休闲随性。', 'ーーー<br>チューリップ袖の配色パイピングがポイントのVネックワンピース			<br>ーーー<br><br>【デザインと特徴】							<br>・肩幅狭めのパフ袖、さらにVネックのデザインが重なりすっきりとした印象に。		<br>・背中側はスクエアにして上品に仕上げました。			<br>・バスト周辺は少しすっき、裾に向かって少しAラインにして大人も着やすくシルエットに。		<br>・両脇ポケット付き				<br>		<br>			<br>【素材特徴】									<br>・表面に波状の細かい凹凸を出したサッカー生地				<br>・凹凸があるので肌に触れる面積が少なく、さらりとした着心地で夏にピッタリ			<br>・軽くしわになりにくく、洗濯後のお手入れも簡単				<br><br>【スタイリング】<br>・ミニバッグやヒールサンダル合わせで華やかなシーンにも使えそうです◎				<br>・スニーカーでカジュアルに。<br><br>【洗濯可否】<br>手洗いでのお手入れが可能です。<br>', '12000.0 JPY', 732.00, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:30:05', '2026-04-02 04:16:37', 'adastria_669999', '', '69cd72d4a7ab618f2967ca32', '生活/休闲', '', '女', '青年（18-44岁）', '涤纶99%,氨纶1%', 'https://www.dot-st.com/apartbylowrys/disp/item/669999/?COLOR_CD=09', '裙装', '连衣裙', '长裙', '', 'maxi dress', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/a_part_by/20260401/item_669999_main_09_1774594137_b.jpg', 0, 0, 6, 0.89893, 0, 1, 1, 0, 0, 3, NULL, '透气，凉爽舒适，易打理/不易起皱', '凉爽舒适,易打理/不易起皱', '', '采用表面有波状细小凹凸的沙卡面料，减少肌肤接触面积，适合夏季穿着,版型上胸围略合身，下摆微A字，方便成熟女性日常穿着,肩宽收窄加V领设计，背面方领，整体显瘦且更显优雅,两侧配有口袋，增加日常实用性,袖口配色滚边设计，增强视觉层次感', '纯色', '从商品名“Vネックワンピース”和图片看到，这是长度到脚踝附近的一件一体式连衣裙，裙身较长、版型略呈A字，属于长款连衣裙范畴。根据提供的分类列表，最贴切的类别是“maxi dress（长款连衣裙）”，指裙长及踝或拖地的连衣裙，适合日常或稍正式场合穿着。', 1, 0, 0, 0, 'maxi dress', NULL, '', 0, NULL, 0, NULL, NULL, '09', 'ブラック(09)', 0);
INSERT INTO `clothing_info` VALUES (19996562, '撞色V领长款连衣裙 / 网络先行预订', 'ハイショクＶネックワンピース/WEB先行予約', 0, 200336, 'A part by', '', '', '郁金香袖搭配撞色滚边是亮点的V领连衣裙。\n\n【设计与特点】\n・略窄肩宽的泡泡袖叠加V领设计，带来利落修长的视觉效果。\n・背部采用方形领口，增添优雅感。\n・胸围区域略微合身，下摆呈轻微A字轮廓，成熟女性也易于驾驭。\n・两侧配有口袋。\n\n【面料特点】\n・采用表面呈波状细小凹凸的沙卡面料。\n・凹凸结构减少与肌肤的接触面积，穿着清爽，适合夏季。\n・质地轻盈，不易起皱，日常打理方便。\n\n【搭配建议】\n・可搭配迷你包与高跟凉鞋，适用于较为华丽的出席场合。\n・配运动鞋则更显休闲随性。', 'ーーー<br>チューリップ袖の配色パイピングがポイントのVネックワンピース			<br>ーーー<br><br>【デザインと特徴】							<br>・肩幅狭めのパフ袖、さらにVネックのデザインが重なりすっきりとした印象に。		<br>・背中側はスクエアにして上品に仕上げました。			<br>・バスト周辺は少しすっき、裾に向かって少しAラインにして大人も着やすくシルエットに。		<br>・両脇ポケット付き				<br>		<br>			<br>【素材特徴】									<br>・表面に波状の細かい凹凸を出したサッカー生地				<br>・凹凸があるので肌に触れる面積が少なく、さらりとした着心地で夏にピッタリ			<br>・軽くしわになりにくく、洗濯後のお手入れも簡単				<br><br>【スタイリング】<br>・ミニバッグやヒールサンダル合わせで華やかなシーンにも使えそうです◎				<br>・スニーカーでカジュアルに。<br><br>【洗濯可否】<br>手洗いでのお手入れが可能です。<br>', '12000.0 JPY', 732.00, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:30:05', '2026-04-02 04:16:38', 'adastria_669999', '', '69cd72d4a7ab618f2967ca32', '生活/休闲', '', '女', '青年（18-44岁）', '涤纶99%,氨纶1%', 'https://www.dot-st.com/apartbylowrys/disp/item/669999/?COLOR_CD=09', '裙装', '连衣裙', '长裙', '', 'maxi dress', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/a_part_by/20260401/item_669999_main_53_1774594178_b.jpg', 0, 0, 2, 0.99611, 0, 1, 1, 0, 0, 3, NULL, '透气，凉爽舒适，易打理/不易起皱', '凉爽舒适,易打理/不易起皱', '', '采用表面有波状细小凹凸的沙卡面料，减少肌肤接触面积，适合夏季穿着,版型上胸围略合身，下摆微A字，方便成熟女性日常穿着,肩宽收窄加V领设计，背面方领，整体显瘦且更显优雅,两侧配有口袋，增加日常实用性,袖口配色滚边设计，增强视觉层次感', '纯色', '从商品名“Vネックワンピース”和图片看到，这是长度到脚踝附近的一件一体式连衣裙，裙身较长、版型略呈A字，属于长款连衣裙范畴。根据提供的分类列表，最贴切的类别是“maxi dress（长款连衣裙）”，指裙长及踝或拖地的连衣裙，适合日常或稍正式场合穿着。', 1, 1, 0, 0, 'maxi dress', NULL, '', 0, NULL, 0, NULL, NULL, '53', 'ライトベージュ(53)', 0);
INSERT INTO `clothing_info` VALUES (19996558, '多比蕾丝吊带迷你连衣裙', 'ドビーレースキャミミニワンピース', 0, 200339, 'Heather', '', '', '【设计】\n浪漫氛围的棉质蕾丝迷你连衣裙。运用流行的花边蕾丝点缀，呈现清新可爱的感觉。通过提高腰线切割，使裙摆不会过于蓬松，同时起到修饰身材比例的效果。\n【搭配】\n从春季适合叠穿的造型到夏季单穿都很出彩，是一款可长季节活用的单品。与牛仔裤或运动裤叠穿也十分可爱。', 'ーーー<br>【デザイン】<br>ロマンティックなムードのコットンレースの<br>ミニワンピース。<br>トレンドのピコレースを施し、<br>清楚で可愛いアイテムに仕上げました。<br>ウエスト位置を高めで切り替えることで<br>ふわっとしすぎずスタイルアップを叶えています。<br>ーーー<br>【スタイリング】<br>レイヤードが可愛い春のコーデから1枚で映える夏のコーデまで<br>ロングシーズン活躍するアイテム！<br>デニムやスウェットパンツとのレイヤードスタイルも可愛い◎', '8000.0 JPY', 488.00, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:30:29', '2026-04-02 04:16:35', 'adastria_326289', '', '69cd72d4a7ab618f2967ca28', '生活/休闲', '', '女', '青年（18-44岁）', '棉100%', 'https://www.dot-st.com/heather/disp/item/326289/?COLOR_CD=09', '裙装', '连衣裙', '迷你裙', '', 'mini dress', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/heather/20260401/item_326289_main_09_1738226318_b.jpg', 0, 0, 2, 0.76329, 0, 1, 1, 0, 0, 3, NULL, '修饰身材，长季节可穿着', '修饰身材,长季节可穿着', '', '迷你长度吊带连衣裙版型,高腰切割提升身材比例,裙摆微微蓬松但不过分蓬松,搭配牛仔裤或运动裤可做叠穿造型,黑色棉质蕾丝外观更显清爽可爱,适合春夏季穿着', '点', '商品名为「キャミミニワンピース」，图片中为短款长度、带细吊带、整体为一件式的连衣裙，裙摆在大腿上方，明显属于迷你长度的连衣裙，因此选择女装连衣裙类中的「mini dress」。mini dress 指长度在大腿附近的短款连衣裙。', 0, 0, 0, 0, 'mini dress', NULL, '', 0, NULL, 0, NULL, NULL, '09', 'ブラック　09', 0);
INSERT INTO `clothing_info` VALUES (19996559, '【官网限定价】荷叶肩连体裤', '【WEB限定価格】フリルショルダーオールインワン', 0, 200339, 'Heather', '', '', '【设计】\n盛夏也能大显身手的一件式连体裤，单穿就很有存在感。肩部采用流行的荷叶边设计，胸前大面积抽褶设计与宽松裤腿形成对比，具有一定显瘦拉长比例效果。使用不易显皱的面料，也很适合旅行等场景。\n【搭配】\n下装可从露肤感较强的凉鞋到休闲运动鞋自由搭配，再加上棒球帽或饰品点缀也很可爱。', 'ーーー<br>【デザイン】<br>真夏に重宝する、1枚で着映えするオールインワン。<br>ショルダーデザインにトレンドのフリルディテールを◎<br>胸元のシャーリングとワイドなレングスでコントラストをつけ<br>スタイルアップ効果も期待できます。<br>しわが目立ちにくい素材なので旅行などのシーンにもおすすめ！<br>ーーー<br>【スタイリング】<br>足元は抜け感のあるサンダルからカジュアルなスニーカーまで<br>幅広く合わせていただけます。<br>キャップやアクセをプラスしても可愛い◎', '9000.0 JPY', 549.00, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:30:29', '2026-04-02 04:16:36', 'adastria_497376', '', '69cd72d4a7ab618f2967ca33', '生活/休闲，差旅/商务', '', '女', '青年（18-44岁）', '涤纶92%,粘胶7%,氨纶1%', 'https://www.dot-st.com/heather/disp/item/497376/?COLOR_CD=05', '孕妇衣', '孕妇衣', '孕妇背带裤', '', 'jumpsuit', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/heather/20260401/item_497376_main_05_1746788489_b.jpg', 0, 0, 8, 0.86515, 0, 1, 1, 0, 0, 3, NULL, '透气，不易起皱，修饰身材，适合夏季穿着', '不易起皱,修饰身材,适合夏季穿着', '', '肩部荷叶边设计，增加女性化装饰感,胸前大面积松紧褶皱设计，增强贴合度与弹性,裤腿为宽松阔腿版型，提升舒适度与垂坠感,适合单穿即可完成造型，减少搭配难度,适合作为旅行携带服装，抗皱便于打理', '花卉图案', '商品为一件连体下装，上身为吊带/肩带式设计，下身为宽腿裤型，整体为一体式连身结构，日文分类为“サロペット・オールインワン”，并在名称中标明“オールインワン（连体裤/连体装）”，结合图片可确定为日常时装类连体裤，最贴近提供列表中的“jumpsuit（连身裤/连体装）”。该子类定义为：上身与下身连为一体、通常为长裤型的连体服饰，用于日常或休闲穿着，本商品完全符合该定义。', 1, 0, 0, 0, 'jumpsuit', NULL, '', 0, NULL, 0, NULL, NULL, '05', 'オフホワイト花柄　05', 0);
INSERT INTO `clothing_info` VALUES (19996560, '【官网限定价】荷叶肩连体裤', '【WEB限定価格】フリルショルダーオールインワン', 0, 200339, 'Heather', '', '', '【设计】\n盛夏也能大显身手的一件式连体裤，单穿就很有存在感。肩部采用流行的荷叶边设计，胸前大面积抽褶设计与宽松裤腿形成对比，具有一定显瘦拉长比例效果。使用不易显皱的面料，也很适合旅行等场景。\n【搭配】\n下装可从露肤感较强的凉鞋到休闲运动鞋自由搭配，再加上棒球帽或饰品点缀也很可爱。', 'ーーー<br>【デザイン】<br>真夏に重宝する、1枚で着映えするオールインワン。<br>ショルダーデザインにトレンドのフリルディテールを◎<br>胸元のシャーリングとワイドなレングスでコントラストをつけ<br>スタイルアップ効果も期待できます。<br>しわが目立ちにくい素材なので旅行などのシーンにもおすすめ！<br>ーーー<br>【スタイリング】<br>足元は抜け感のあるサンダルからカジュアルなスニーカーまで<br>幅広く合わせていただけます。<br>キャップやアクセをプラスしても可愛い◎', '9000.0 JPY', 549.00, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:30:29', '2026-04-02 04:16:37', 'adastria_497376', '', '69cd72d4a7ab618f2967ca33', '生活/休闲，差旅/商务', '', '女', '青年（18-44岁）', '涤纶92%,粘胶7%,氨纶1%', 'https://www.dot-st.com/heather/disp/item/497376/?COLOR_CD=05', '孕妇衣', '孕妇衣', '孕妇背带裤', '', 'jumpsuit', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/heather/20260401/item_497376_main_18_1747739659_b.jpg', 0, 0, 4, 0.52309, 0, 1, 1, 0, 0, 3, NULL, '透气，不易起皱，修饰身材，适合夏季穿着', '不易起皱,修饰身材,适合夏季穿着', '', '肩部荷叶边设计，增加女性化装饰感,胸前大面积松紧褶皱设计，增强贴合度与弹性,裤腿为宽松阔腿版型，提升舒适度与垂坠感,适合单穿即可完成造型，减少搭配难度,适合作为旅行携带服装，抗皱便于打理', '花卉图案', '商品为一件连体下装，上身为吊带/肩带式设计，下身为宽腿裤型，整体为一体式连身结构，日文分类为“サロペット・オールインワン”，并在名称中标明“オールインワン（连体裤/连体装）”，结合图片可确定为日常时装类连体裤，最贴近提供列表中的“jumpsuit（连身裤/连体装）”。该子类定义为：上身与下身连为一体、通常为长裤型的连体服饰，用于日常或休闲穿着，本商品完全符合该定义。', 1, 1, 0, 0, 'jumpsuit', NULL, '', 0, NULL, 0, NULL, NULL, '18', 'グレー系チェック　18', 0);
INSERT INTO `clothing_info` VALUES (19996557, '【10C REPIPI】NEW ERA 棒球帽', '【10C REPIPI】NEWERAYTH', 0, 31749822, 'repipi armario', '', '', '中性化的帽型设计，男女都易于佩戴。后部配有调节装置，可根据头围自由调节尺寸。采用柔软触感并经过水洗处理的纯棉面料，呈现出仿旧质感，上头即可营造出自然随性的造型氛围。无论是辣妹风、休闲风还是甜美风都能轻松搭配，是适合日常佩戴的百搭棒球帽。', 'ーーー<br>男女問わず着用しやすいシルエット。<br><br>アジャスターでサイズ調整可能です◎<br>柔らかな被り心地でウォッシュド加工を施したコットン生地。<br>使い込んだようなデザインで被るだけでこなれ感が。<br>ぎゃるスタイルにもカジュアルにも、あまめスタイルにも使える<br>デイリー使いにピッタリな万能キャップです◎<br>ーーー', '3800.0 JPY', 231.80, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:30:31', '2026-04-02 04:16:34', 'adastria_652782', '', '69cd72d4a7ab618f2967ca2a', '生活/休闲', '', '通用', '青少年（13-17岁）', '棉100%', 'https://www.dot-st.com/repipiarmario/disp/item/652782/?COLOR_CD=92', '配饰', '帽子', NULL, '', 'baseball cap', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/repipi_armario/20260401/item_652782_main_92_1774945270_b.jpg', 0, 0, 9, 0.85280, 0, 1, 1, 0, 0, 3, NULL, '可调节尺寸', '可调节尺寸', '', '柔软棉质面料，水洗做旧效果,日常百搭风格，适合多种穿搭,帽前有立体刺绣标志图案', '字母', '从图片和描述看，这是有帽檐、六片结构并配有后幅调节带的经典棒球帽造型，且商品类别为“帽子”，适合日常休闲佩戴，因此在提供的服饰细分类中，最贴切的是“baseball cap（棒球帽）”，其定义为带有硬质前檐、包覆头部并多用于休闲与户外场景的帽款。', 0, 0, 0, 0, 'baseball cap', NULL, '', 0, NULL, 0, NULL, NULL, '92', 'パープル92', 0);
INSERT INTO `clothing_info` VALUES (19996555, '【10C REPIPI】NEWERA 字母刺绣帽', '【10C REPIPI】NEWERAYTH', 0, 31749822, 'repipi armario', '', '', '男女皆可轻松驾驭的基础帽型，通过后部调节带即可调整尺寸。采用柔软的棉质面料并辅以水洗做旧工艺，呈现出如同常年使用的自然质感，仅需戴上就能营造随性时髦的氛围。无论是辣妹风、休闲风还是偏甜美的穿搭都适用，是非常适合日常佩戴的百搭棒球帽。', 'ーーー<br>男女問わず着用しやすいシルエット。<br><br>アジャスターでサイズ調整可能です◎<br>柔らかな被り心地でウォッシュド加工を施したコットン生地。<br>使い込んだようなデザインで被るだけでこなれ感が。<br>ぎゃるスタイルにもカジュアルにも、あまめスタイルにも使える<br>デイリー使いにピッタリな万能キャップです◎<br>ーーー', '3600.0 JPY', 219.60, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:30:36', '2026-04-02 04:16:32', 'adastria_652155', '', '69cd72d4a7ab618f2967ca23', '生活/休闲', '', '通用', '青少年（13-17岁）', '棉100%', 'https://www.dot-st.com/repipiarmario/disp/item/652155/?COLOR_CD=09', '其他服饰/物品', '其他', NULL, '', 'hat', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/repipi_armario/20260401/item_652155_main_09_1774436407_b.jpg', 0, 0, 9, 0.64603, 0, 1, 1, 0, 0, 3, NULL, '舒适佩戴，可调节尺寸', '舒适佩戴,可调节尺寸', '', '洗水做旧效果的棉质帽身,男女皆宜的基础轮廓,日常搭配友好的百搭设计,前片有醒目的字母/标志刺绣装饰', '字母', '从图片可见为有帽檐的棒球帽轮廓，并且商品类目为「帽子」，描述中提到「万能キャップ」，整体明显是头部佩戴的配饰，而非服装或家纺类产品。因此在提供的列表中应归类为「hat」，即帽子类配饰。hat：指佩戴在头部，用于遮阳、防护或装饰的各类帽饰，包括棒球帽、渔夫帽等。', 1, 0, 0, 0, 'hat', NULL, '', 0, NULL, 0, NULL, NULL, '09', 'ブラック09', 0);
INSERT INTO `clothing_info` VALUES (19996556, '【10C REPIPI】NEWERA 字母刺绣帽', '【10C REPIPI】NEWERAYTH', 0, 31749822, 'repipi armario', '', '', '男女皆可轻松驾驭的基础帽型，通过后部调节带即可调整尺寸。采用柔软的棉质面料并辅以水洗做旧工艺，呈现出如同常年使用的自然质感，仅需戴上就能营造随性时髦的氛围。无论是辣妹风、休闲风还是偏甜美的穿搭都适用，是非常适合日常佩戴的百搭棒球帽。', 'ーーー<br>男女問わず着用しやすいシルエット。<br><br>アジャスターでサイズ調整可能です◎<br>柔らかな被り心地でウォッシュド加工を施したコットン生地。<br>使い込んだようなデザインで被るだけでこなれ感が。<br>ぎゃるスタイルにもカジュアルにも、あまめスタイルにも使える<br>デイリー使いにピッタリな万能キャップです◎<br>ーーー', '3600.0 JPY', 219.60, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:30:36', '2026-04-02 04:16:33', 'adastria_652155', '', '69cd72d4a7ab618f2967ca23', '生活/休闲', '', '通用', '青少年（13-17岁）', '棉100%', 'https://www.dot-st.com/repipiarmario/disp/item/652155/?COLOR_CD=09', '其他服饰/物品', '其他', NULL, '', 'hat', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/repipi_armario/20260401/item_652155_main_08_1774945787_b.jpg', 0, 0, 9, 0.53585, 0, 1, -1, 0, 0, 3, NULL, '舒适佩戴，可调节尺寸', '舒适佩戴,可调节尺寸', '', '洗水做旧效果的棉质帽身,男女皆宜的基础轮廓,日常搭配友好的百搭设计,前片有醒目的字母/标志刺绣装饰', '字母', '从图片可见为有帽檐的棒球帽轮廓，并且商品类目为「帽子」，描述中提到「万能キャップ」，整体明显是头部佩戴的配饰，而非服装或家纺类产品。因此在提供的列表中应归类为「hat」，即帽子类配饰。hat：指佩戴在头部，用于遮阳、防护或装饰的各类帽饰，包括棒球帽、渔夫帽等。', 1, 1, 0, 0, 'hat', NULL, '', 0, NULL, 0, NULL, NULL, '08', 'ナチュラル08', 0);
INSERT INTO `clothing_info` VALUES (19996553, 'Acid护膝罩套', 'Acidニーカバー', 0, 31749822, 'repipi armario', '', '', '人气Acid加工护膝罩套登场。只要穿上就能起到拉长比例、优化造型的效果。与同材质的Acid设计上衣或下装搭配穿着，可以让整体造型更有统一感，更显时髦。', 'ーーー<br>レピピで大人気のAcid加工のニーカバーが登場。<br>履くだけでスタイルアップが叶う優秀アイテム。<br>同素材のAcidデザインのトップスやボトムスと一緒に着用いただくと<br>コーデに統一感が出てよりお洒落見えします。<br>ーーー', '2719.0 JPY', 165.86, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:30:47', '2026-04-02 04:16:31', 'adastria_670811', '', '69cd72d4a7ab618f2967ca15', '生活/休闲', '', '女', '青少年（13-17岁）', '棉81%,涤纶19%', 'https://www.dot-st.com/repipiarmario/disp/item/670811/?COLOR_CD=82', '其他服饰/物品', '其他', '配件', '', 'accessories', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/repipi_armario/20260401/item_670811_main_82_1774844107_b.jpg', 0, 0, 1, 0.96021, 0, -2, 0, 0, 0, 3, NULL, '装饰搭配，修饰腿型，造型显高显瘦', '装饰搭配,修饰腿型,造型显高显瘦', '', 'Acid做旧风格水洗效果，具有统一系列可搭配的设计感,与同面料上衣、下装成套搭配提升整体造型感,为膝盖位置提供一定遮挡与装饰效果', '其他', '从商品名称“Acidニーカバー”和图片来看，这是套在膝盖位置的装饰性覆盖单品，不属于常规上装、下装或袜子，而是穿搭配件。它不是完整裤装或裙装，也非护膝功能运动装备，更接近时尚类配饰，因此在给定列表中选择“accessories（配饰）”最为合适。该子类定义为搭配服装的附属时尚单品，用于完善造型和风格。', 1, 0, 0, 0, 'accessories', NULL, '', 0, NULL, 0, NULL, NULL, '82', 'Acidブルー82', 0);
