INSERT INTO `clothing_info` VALUES (19996551, '【预售】木质手柄纸编托特包', '【先行予約】ウッドハンドルペーパート', 0, 200167, 'Elura', '', '', '采用天然感纸质材料，细致镂空编织，并搭配木质圆环手柄，是一款点亮夏日造型的主角级包款。利落的方形轮廓弱化甜美感，为整体造型增添都市而干练的印象。内置防透视里布与覆盖布，有效遮挡包内物品，日常必需品可稳妥收纳。木质手柄握感舒适，轻盈又便于携带，从简约连衣裙到牛仔穿搭，只需一只包就能为造型增添季节感与精致度。', 'ーーー<br><font size=\"2pt\" color=\"#c82c55\"><b>＼目を惹くウッドハンドルと、涼やかな透かし編み／</b></font><br><br>ナチュラルなペーパー素材を繊細な透かし編みに仕立て、<br>ウッドリングのハンドルを添えた、夏を彩る主役級バッグ。<br>すっきりとしたスクエアフォルムが甘さを抑え、<br>スタイリングを都会的でシャープな印象へと導きます。<br><br>「中身が見えすぎるのが心配」というお悩みも、<br>透けを防止する裏地と荷物を覆って守ってくれる被せ布付きで解消。<br>デイリーの必需品がしっかり収まる安心のキャパシティと、<br>手に馴染むウッドハンドルの持ちやすさが、<br>夏のお出かけをより快適に、より軽やかに変えてくれます。<br>シンプルなワンピースからデニムスタイルまで、<br>持つだけで季節の洗練をプラスしてくれる一品です。<br><br>ーーー<br><br>【気になる商品は「お気に入り」登録を】<br>&#9825;ハートマークをクリックし、お気に入りに登録すると<br>在庫残り僅かや再入荷通知などの情報を受け取ることができます。', '7900.0 JPY', 481.90, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:30:57', '2026-04-02 04:16:29', 'adastria_646461', '', '69cd72d4a7ab618f2967ca10', '生活/休闲', '', '女', '青年（18-44岁）', NULL, 'https://www.dot-st.com/elura/disp/item/646461/?COLOR_CD=55', '其他服饰/物品', '其他', '配件', '', 'accessories', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/elura/20260401/item_646461_main_55_1774261609_b.jpg', 0, 0, 4, 0.46850, 0, 1, 1, 0, 0, 3, NULL, '容量适中，便于手提，防止包内物品过度外露', '容量适中,便于手提,防止包内物品过度外露', '', '木质手柄设计，兼具装饰性和握持舒适度,主体采用纸质编织材质，呈现夏日清凉感,包身采用镂空编织结构，具有良好透气观感,内配防透视里布和覆盖布，保护隐私与物品,简洁方形轮廓，提升整体利落感与都市感', '其他', '该产品为手提包，主要功能是收纳随身物品并搭配夏日造型，不属于服装或家纺类别，因此在给定列表中最适合归为“accessories（配饰）”。“accessories”定义为服装以外的搭配用品，如包袋、帽子等，本款木质手柄纸编包正是典型的时尚配饰类单品。', 1, 0, 0, 0, 'accessories', NULL, '', 0, NULL, 0, NULL, NULL, '55', 'ブラウン55', 0);
INSERT INTO `clothing_info` VALUES (19996552, '【预售】木质手柄纸编托特包', '【先行予約】ウッドハンドルペーパート', 0, 200167, 'Elura', '', '', '采用天然感纸质材料，细致镂空编织，并搭配木质圆环手柄，是一款点亮夏日造型的主角级包款。利落的方形轮廓弱化甜美感，为整体造型增添都市而干练的印象。内置防透视里布与覆盖布，有效遮挡包内物品，日常必需品可稳妥收纳。木质手柄握感舒适，轻盈又便于携带，从简约连衣裙到牛仔穿搭，只需一只包就能为造型增添季节感与精致度。', 'ーーー<br><font size=\"2pt\" color=\"#c82c55\"><b>＼目を惹くウッドハンドルと、涼やかな透かし編み／</b></font><br><br>ナチュラルなペーパー素材を繊細な透かし編みに仕立て、<br>ウッドリングのハンドルを添えた、夏を彩る主役級バッグ。<br>すっきりとしたスクエアフォルムが甘さを抑え、<br>スタイリングを都会的でシャープな印象へと導きます。<br><br>「中身が見えすぎるのが心配」というお悩みも、<br>透けを防止する裏地と荷物を覆って守ってくれる被せ布付きで解消。<br>デイリーの必需品がしっかり収まる安心のキャパシティと、<br>手に馴染むウッドハンドルの持ちやすさが、<br>夏のお出かけをより快適に、より軽やかに変えてくれます。<br>シンプルなワンピースからデニムスタイルまで、<br>持つだけで季節の洗練をプラスしてくれる一品です。<br><br>ーーー<br><br>【気になる商品は「お気に入り」登録を】<br>&#9825;ハートマークをクリックし、お気に入りに登録すると<br>在庫残り僅かや再入荷通知などの情報を受け取ることができます。', '7900.0 JPY', 481.90, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:30:57', '2026-04-02 04:16:30', 'adastria_646461', '', '69cd72d4a7ab618f2967ca10', '生活/休闲', '', '女', '青年（18-44岁）', NULL, 'https://www.dot-st.com/elura/disp/item/646461/?COLOR_CD=55', '其他服饰/物品', '其他', '配件', '', 'accessories', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/elura/20260401/item_646461_main_52_1774260574_b.jpg', 0, 0, 9, 0.87168, 0, 1, 0, 0, 0, 3, NULL, '容量适中，便于手提，防止包内物品过度外露', '容量适中,便于手提,防止包内物品过度外露', '', '木质手柄设计，兼具装饰性和握持舒适度,主体采用纸质编织材质，呈现夏日清凉感,包身采用镂空编织结构，具有良好透气观感,内配防透视里布和覆盖布，保护隐私与物品,简洁方形轮廓，提升整体利落感与都市感', '其他', '该产品为手提包，主要功能是收纳随身物品并搭配夏日造型，不属于服装或家纺类别，因此在给定列表中最适合归为“accessories（配饰）”。“accessories”定义为服装以外的搭配用品，如包袋、帽子等，本款木质手柄纸编包正是典型的时尚配饰类单品。', 1, 1, 0, 0, 'accessories', NULL, '', 0, NULL, 0, NULL, NULL, '52', 'ベージュ52', 0);
INSERT INTO `clothing_info` VALUES (19996547, '【预售】罗马布伞摆长裙', '【先行予約】ポンチフレアスカート', 0, 200167, 'Elura', '', '', '弹性极佳的伞摆长裙。适中的厚度感罗马布料，可自然遮盖腿部线条。具备接触冷感功能，夏季穿着也清凉舒适。面料不易变形，可在家机洗。高弹力针织材质，让长时间穿着也无压力。还能与同材质上衣成套穿着，演绎时髦套装造型。质感为表面顺滑、厚度适中的罗马布，成分为50%粘纤、40%尼龙、10%聚氨酯，兼具接触冷感与可机洗功能。既可与同材质套头上衣搭配打造精致造型，也可以配T恤和凉鞋，呈现轻松的大人感休闲风。', 'ーーー<br><font size=\"3\"color=\"#c82c55\"><b>伸縮性抜群の秀逸フレアスカート。</b></font><br><br>【悩みに“効く”ポイント】<br>程よい厚みのポンチ素材が、脚のラインも自然にカバーします。<br>接触冷感機能が付いているので、夏も涼しく快適に使えます。<br>型崩れしにくいポンチ素材なので、自宅で洗えるのも嬉しいポイント。<br>伸縮性抜群のジャージー素材で、長時間の着用もストレスフリー。<br>同素材のトップスを合わせ、旬のセットアップも楽しめる一着。<br><br>◆<a href=\"https://www.dot-st.com/elura/disp/item/664873\"><b><font size=\"2\" color=\"blue\">同素材のトップスはこちら</a></font></b><br><br>【MATERIAL & FUNCTION】<br>質感：滑らかな表面感で程よい厚みのポンチ素材<br>素材：レーヨン50%、ナイロン40%、ポリウレタン10%<br>機能：接触冷感、マシンウォッシャブル<br>ーーー<br>【スタイリング】<br>キレイ目：同素材のプルオーバーと合わせた、こなれセットアップ。<br>カジュアル：Ｔシャツやサンダルを合わせれば、こなれた大人の休日スタイルに♪<br><br>【商品の取り扱いについて】<br>洗濯：家庭用洗濯機（ネット使用）でお手入れ簡単です。<br>ケア：強い摩擦によるテカリを防ぐため、裏返し洗いが安心。<br><br>【気になる商品は「お気に入り」登録を】<br>&#9825;ハートマークをクリックし、お気に入りに登録すると<br>在庫残り僅かや再入荷通知などの情報を受け取ることができます。', '8000.0 JPY', 488.00, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:30:58', '2026-04-02 04:16:26', 'adastria_664870', '', '69cd72d4a7ab618f2967ca06', '生活/休闲', '', '女', '青年（18-44岁）', '粘胶50%,锦纶40%,氨纶10%', 'https://www.dot-st.com/elura/disp/item/664870/?COLOR_CD=18', '裙装', '半身裙', '长裙', '', 'maxi skirt', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/elura/20260401/item_664870_main_18_1774946514_b.jpg', 0, 0, 2, 0.49436, 0, 1, 0, 0, 0, 3, NULL, '接触冷感，高弹力，机洗可洗，遮掩腿部线条，长时间穿着舒适', '机洗可洗,遮掩腿部线条,长时间穿着舒适', '接触冷感整理', '采用质感顺滑且有一定厚度的ポンチ针织面料,面料不易变形，适合日常反复穿着,同面料可搭配上衣形成成套造型,适合夏季穿着同时兼顾遮肉效果', '纯色', '从图片看裙长明显过踝、小腿以下，属于长款裙；版型为大摆伞形廓形，对应“flared”设计，结合日常时装属性，应归为“maxi skirt（长款裙）”。', 1, 0, 0, 0, 'maxi skirt', NULL, '', 0, NULL, 0, NULL, NULL, '18', 'チャコール18', 0);
