INSERT INTO `clothing_info` VALUES (19996549, '多款图案大版丝巾', 'アソート大判スカーフ', 0, 200167, 'Elura', '', '', '这款具有优雅光泽感的大尺寸丝巾，以多样混合图案呈现。顺滑的质感不仅能优雅点缀颈部，也可作为包包的装饰、替代腰带系于腰间，甚至能做成类似束胸上衣的造型，使用方式十分灵活。每一款图案都各具表情，只需叠搭在简约T恤或针织衫之上，就能瞬间营造洗练氛围。从换季时节到盛夏，都能为衣橱增添无限搭配可能，是为成熟女性打造的丝巾单品。', 'ーーー<br><font size=\"2pt\" color=\"#c82c55\"><b>＼纏う、巻く、結ぶ。アソート柄でマルチに活躍／</b></font><br><br>上品な光沢のある大判サイズのスカーフが、<br>多彩なアソート柄で登場しました。<br><br>なめらかな質感が首元をエレガントに彩るのはもちろん、<br>バッグのアクセントやベルト代わりの腰巻き、<br>さらにはビスチェ風のアレンジまで、使い方は自由自在です。<br><br>一つひとつ表情が異なるアソート柄は、<br>シンプルなTシャツやニットに重ねるだけで、<br>瞬時に洗練されたムードへと引き上げてくれます。<br>季節の変わり目から真夏のアクセントまで、<br>ワードローブに無限の可能性を添える、<br>大人のためのスカーフです。<br><br>ーーー<br><br>【気になる商品は「お気に入り」登録を】<br>&#9825;ハートマークをクリックし、お気に入りに登録すると<br>在庫残り僅かや再入荷通知などの情報を受け取ることができます。', '4700.0 JPY', 286.70, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:30:58', '2026-04-02 04:16:27', 'adastria_682587', '', '69cd72d4a7ab618f2967ca0f', '生活/休闲', '', '通用', '青年（18-44岁）', '涤纶100%', 'https://www.dot-st.com/elura/disp/item/682587/?COLOR_CD=09', '其他服饰/物品', '其他', '配件', '', 'accessories', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/elura/20260401/item_682587_main_09_1774845617_b.jpg', 0, 0, 9, 0.74349, 0, 1, 1, 0, 0, 3, NULL, '装饰搭配，保暖护颈', '装饰搭配,保暖护颈', '', '大尺寸方形设计，可作围巾、披肩、腰带、包袋装饰等多种系法,多款混合图案可选，提升穿搭精致感,具有优雅光泽与顺滑手感，适合春夏作为造型点缀', '方形', '产品名称为“大判スカーフ”，描述中多次提到“スカーフ”“纏う、巻く、結ぶ”“バッグのアクセントやベルト代わり”等，用途是围在颈部、做腰带或包包装饰，明显属于穿搭配饰而非服装主体或家纺用品。因此在提供的类目中选“accessories（配饰类）”最合适，定义为搭配造型用的小物件。', 1, 0, 0, 0, 'accessories', NULL, '', 0, NULL, 0, NULL, NULL, '09', 'ブラック09', 0);
