INSERT INTO `clothing_info` VALUES (19996541, '薄纱混色连帽衬衫', 'ボイルシャンブレフードシャツ', 0, 200167, 'Elura', '', '', '≪空调房对策≫兼具体型修饰效果的透视感衬衫外套。\n\n【特点与优势】\n长款设计可自然遮住臀部，实现轻松体型遮掩。适度的透视感营造季节氛围，是一款兼具优雅与时髦感的当季感衬衫。面料具有上品的轻薄透视效果，同时可以手洗护理。夏季既可作为防空调的薄外搭，也是日常出门易于随手披上的百搭单品。\n\n【材质与功能】\n质感：具有适度透视感与垂坠感的轻盈薄纱质地（波纹感薄纱）。\n材质：聚酯纤维83%，棉17%。\n功能：支持家庭手洗，易于日常打理。\n\n【搭配建议】\n搭配修身半身裙，可营造利落都市感造型。与牛仔、凉鞋组合，则呈现松弛有度的大人休闲风。', 'ーーー<br><font size=\"3\"color=\"#c82c55\"><b>≪冷房対策≫体型カバーも叶うシアーシャツ</b></font><br><br>【悩みに“効く”ポイント】<br>長め丈でお尻も隠せて、体型カバーも自然に叶えます。<br>程よいシアー感で季節感も演出。品よく決まる旬顔のシャツ。<br>上品な透け感なのに、手洗いでケアできるのも嬉しいポイント。<br>夏の冷房対策にも◎。手軽に羽織れる万能アイテム。<br><br>【MATERIAL & FUNCTION】<br>質感：程よい透け感と落ち感のある、軽やかなボイル素材<br>素材：ポリエステル 83％、綿 17％<br>機能：ハンドウォッシャブル<br>ーーー<br>【スタイリング】<br>キレイ目：タイトスカートと合わせ、洗練された都会的な旬コーデに。<br>カジュアル：デニムやサンダルを合わせ、こなれた大人のリラックス感♪<br><br>【商品の取り扱いについて】<br>洗濯：家庭用手洗いでのお手入れが可能です。<br>ケア：素材の特性上、強い力が加わると縫い目が開くためご注意。<br><br>【気になる商品は「お気に入り」登録を】<br>&#9825;ハートマークをクリックし、お気に入りに登録すると<br>在庫残り僅かや再入荷通知などの情報を受け取ることができます。', '7000.0 JPY', 427.00, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:31:00', '2026-04-02 04:16:20', 'adastria_636883', '', '69cd72d4a7ab618f2967ca05', '生活/休闲', '', '女', '青年（18-44岁）', '涤纶83%,棉17%', 'https://www.dot-st.com/elura/disp/item/636883/?COLOR_CD=09', '上装', '卫衣', '连帽衫', '', 'hoodie', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/elura/20260401/item_636883_main_09_1774924295_b.jpg', 0, 0, 6, 0.95525, 0, 1, 1, 0, 0, 3, NULL, '透气，体型遮掩，防晒/遮挡紫外线（冷房和日晒场景的遮挡），轻盈垂坠，手洗方便护理', '体型遮掩,防晒/遮挡紫外线（冷房和日晒场景的遮挡）,轻盈垂坠,手洗方便护理', '可家庭手洗功能（Hand washable）', '长款设计，可遮挡臀部，有视觉显瘦与体型修饰效果,带帽设计，增加休闲感与实用性,采用轻盈有垂感的薄纱式雪纺感面料，具有适度透视感,适合作为夏季冷气房外搭，兼具防晒与保暖过冷气功能,适合搭配紧身裙、牛仔裤等多种风格造型', '纯色，纯色', '从图片看，产品为长袖前开襟上衣，带明显帽子和帽绳，可作为外搭穿着，整体版型宽松，具备“连帽上衣”的典型特征；虽为衬衫式门襟，但日文名中“フードシャツ”也强调连帽设计。综合版型与用途，最贴近的品类为“hoodie（连帽上衣）”。hoodie：指带帽的套头或开襟上衣，偏休闲外搭风格。', 1, 0, 0, 0, 'hoodie', NULL, '', 0, NULL, 0, NULL, NULL, '09', 'ブラック09', 0);
INSERT INTO `clothing_info` VALUES (19996542, '薄纱混色连帽衬衫', 'ボイルシャンブレフードシャツ', 0, 200167, 'Elura', '', '', '≪空调房对策≫兼具体型修饰效果的透视感衬衫外套。\n\n【特点与优势】\n长款设计可自然遮住臀部，实现轻松体型遮掩。适度的透视感营造季节氛围，是一款兼具优雅与时髦感的当季感衬衫。面料具有上品的轻薄透视效果，同时可以手洗护理。夏季既可作为防空调的薄外搭，也是日常出门易于随手披上的百搭单品。\n\n【材质与功能】\n质感：具有适度透视感与垂坠感的轻盈薄纱质地（波纹感薄纱）。\n材质：聚酯纤维83%，棉17%。\n功能：支持家庭手洗，易于日常打理。\n\n【搭配建议】\n搭配修身半身裙，可营造利落都市感造型。与牛仔、凉鞋组合，则呈现松弛有度的大人休闲风。', 'ーーー<br><font size=\"3\"color=\"#c82c55\"><b>≪冷房対策≫体型カバーも叶うシアーシャツ</b></font><br><br>【悩みに“効く”ポイント】<br>長め丈でお尻も隠せて、体型カバーも自然に叶えます。<br>程よいシアー感で季節感も演出。品よく決まる旬顔のシャツ。<br>上品な透け感なのに、手洗いでケアできるのも嬉しいポイント。<br>夏の冷房対策にも◎。手軽に羽織れる万能アイテム。<br><br>【MATERIAL & FUNCTION】<br>質感：程よい透け感と落ち感のある、軽やかなボイル素材<br>素材：ポリエステル 83％、綿 17％<br>機能：ハンドウォッシャブル<br>ーーー<br>【スタイリング】<br>キレイ目：タイトスカートと合わせ、洗練された都会的な旬コーデに。<br>カジュアル：デニムやサンダルを合わせ、こなれた大人のリラックス感♪<br><br>【商品の取り扱いについて】<br>洗濯：家庭用手洗いでのお手入れが可能です。<br>ケア：素材の特性上、強い力が加わると縫い目が開くためご注意。<br><br>【気になる商品は「お気に入り」登録を】<br>&#9825;ハートマークをクリックし、お気に入りに登録すると<br>在庫残り僅かや再入荷通知などの情報を受け取ることができます。', '7000.0 JPY', 427.00, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:31:00', '2026-04-02 04:16:21', 'adastria_636883', '', '69cd72d4a7ab618f2967ca05', '生活/休闲', '', '女', '青年（18-44岁）', '涤纶83%,棉17%', 'https://www.dot-st.com/elura/disp/item/636883/?COLOR_CD=09', '上装', '卫衣', '连帽衫', '', 'hoodie', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/elura/20260401/item_636883_main_25_1774924290_b.jpg', 0, 0, 2, 0.68412, 0, 1, 1, 0, 0, 3, NULL, '透气，体型遮掩，防晒/遮挡紫外线（冷房和日晒场景的遮挡），轻盈垂坠，手洗方便护理', '体型遮掩,防晒/遮挡紫外线（冷房和日晒场景的遮挡）,轻盈垂坠,手洗方便护理', '可家庭手洗功能（Hand washable）', '长款设计，可遮挡臀部，有视觉显瘦与体型修饰效果,带帽设计，增加休闲感与实用性,采用轻盈有垂感的薄纱式雪纺感面料，具有适度透视感,适合作为夏季冷气房外搭，兼具防晒与保暖过冷气功能,适合搭配紧身裙、牛仔裤等多种风格造型', '纯色，纯色', '从图片看，产品为长袖前开襟上衣，带明显帽子和帽绳，可作为外搭穿着，整体版型宽松，具备“连帽上衣”的典型特征；虽为衬衫式门襟，但日文名中“フードシャツ”也强调连帽设计。综合版型与用途，最贴近的品类为“hoodie（连帽上衣）”。hoodie：指带帽的套头或开襟上衣，偏休闲外搭风格。', 1, 1, 0, 0, 'hoodie', NULL, '', 0, NULL, 0, NULL, NULL, '25', 'ピンク25', 0);
INSERT INTO `clothing_info` VALUES (19996543, '薄纱混色连帽衬衫', 'ボイルシャンブレフードシャツ', 0, 200167, 'Elura', '', '', '≪空调房对策≫兼具体型修饰效果的透视感衬衫外套。\n\n【特点与优势】\n长款设计可自然遮住臀部，实现轻松体型遮掩。适度的透视感营造季节氛围，是一款兼具优雅与时髦感的当季感衬衫。面料具有上品的轻薄透视效果，同时可以手洗护理。夏季既可作为防空调的薄外搭，也是日常出门易于随手披上的百搭单品。\n\n【材质与功能】\n质感：具有适度透视感与垂坠感的轻盈薄纱质地（波纹感薄纱）。\n材质：聚酯纤维83%，棉17%。\n功能：支持家庭手洗，易于日常打理。\n\n【搭配建议】\n搭配修身半身裙，可营造利落都市感造型。与牛仔、凉鞋组合，则呈现松弛有度的大人休闲风。', 'ーーー<br><font size=\"3\"color=\"#c82c55\"><b>≪冷房対策≫体型カバーも叶うシアーシャツ</b></font><br><br>【悩みに“効く”ポイント】<br>長め丈でお尻も隠せて、体型カバーも自然に叶えます。<br>程よいシアー感で季節感も演出。品よく決まる旬顔のシャツ。<br>上品な透け感なのに、手洗いでケアできるのも嬉しいポイント。<br>夏の冷房対策にも◎。手軽に羽織れる万能アイテム。<br><br>【MATERIAL & FUNCTION】<br>質感：程よい透け感と落ち感のある、軽やかなボイル素材<br>素材：ポリエステル 83％、綿 17％<br>機能：ハンドウォッシャブル<br>ーーー<br>【スタイリング】<br>キレイ目：タイトスカートと合わせ、洗練された都会的な旬コーデに。<br>カジュアル：デニムやサンダルを合わせ、こなれた大人のリラックス感♪<br><br>【商品の取り扱いについて】<br>洗濯：家庭用手洗いでのお手入れが可能です。<br>ケア：素材の特性上、強い力が加わると縫い目が開くためご注意。<br><br>【気になる商品は「お気に入り」登録を】<br>&#9825;ハートマークをクリックし、お気に入りに登録すると<br>在庫残り僅かや再入荷通知などの情報を受け取ることができます。', '7000.0 JPY', 427.00, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:31:00', '2026-04-02 04:16:22', 'adastria_636883', '', '69cd72d4a7ab618f2967ca05', '生活/休闲', '', '女', '青年（18-44岁）', '涤纶83%,棉17%', 'https://www.dot-st.com/elura/disp/item/636883/?COLOR_CD=09', '上装', '卫衣', '连帽衫', '', 'hoodie', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/elura/20260401/item_636883_main_50_1774924300_b.jpg', 0, 0, 2, 0.98911, 0, 1, 1, 0, 0, 3, NULL, '透气，体型遮掩，防晒/遮挡紫外线（冷房和日晒场景的遮挡），轻盈垂坠，手洗方便护理', '体型遮掩,防晒/遮挡紫外线（冷房和日晒场景的遮挡）,轻盈垂坠,手洗方便护理', '可家庭手洗功能（Hand washable）', '长款设计，可遮挡臀部，有视觉显瘦与体型修饰效果,带帽设计，增加休闲感与实用性,采用轻盈有垂感的薄纱式雪纺感面料，具有适度透视感,适合作为夏季冷气房外搭，兼具防晒与保暖过冷气功能,适合搭配紧身裙、牛仔裤等多种风格造型', '纯色，纯色', '从图片看，产品为长袖前开襟上衣，带明显帽子和帽绳，可作为外搭穿着，整体版型宽松，具备“连帽上衣”的典型特征；虽为衬衫式门襟，但日文名中“フードシャツ”也强调连帽设计。综合版型与用途，最贴近的品类为“hoodie（连帽上衣）”。hoodie：指带帽的套头或开襟上衣，偏休闲外搭风格。', 1, 2, 0, 0, 'hoodie', NULL, '', 0, NULL, 0, NULL, NULL, '50', 'グレージュ50', 0);
INSERT INTO `clothing_info` VALUES (19996544, '薄纱香槟色衬衫连衣裙', 'ボイルシャンブレーシャツワンピ', 0, 200167, 'Elura', '', '', '【显瘦设计要点】\n修长的纵向I字线条，只需随意披上即可带来显瘦视觉效果。采用轻盈的薄纱材质，轮廓流畅，兼具修饰身形与优雅气质。具有上质感的轻透效果，同时可在家中进行手洗打理。夏日也能作为冷气房的防凉外搭，是点亮休闲时光的百搭衬衫连衣裙。\n\n【材质与功能】\n质感：适度透视与自然垂坠感兼具的轻盈薄纱面料\n材质：聚酯纤维83%、棉17%\n功能：可家庭手洗\n\n【穿搭建议】\n优雅风格：扣上纽扣突出纵向线条，呈现精致的连衣裙造型。\n休闲风格：前襟全开做外搭，营造自然随性的I字廓形层次感。', 'ーーー<br><font size=\"3\"color=\"#c82c55\"><b>Iラインで細みえ。ボイルシャツワンピース</b></font><br><br>【悩みに“効く”ポイント】<br>縦のIラインが、羽織るだけで細みえ効果を叶えます。<br>軽やかなボイル素材でシルエットも美しく。着痩せも狙える一着。<br>上質な透け感なのに。自宅で手洗いできるのも嬉しいポイント。<br>夏の冷房対策にも◎。休日を彩る万能なシャツワンピースです。<br><br>【MATERIAL & FUNCTION】<br>質感：程よい透け感と落ち感のある、軽やかなボイル素材<br>素材：ポリエステル 83％、綿 17％<br>機能：ハンドウォッシャブル<br><br>【スタイリング】<br>キレイ目：ボタンを閉めて縦ラインを強調。上品なワンピスタイルに。<br>カジュアル：前を全開にして羽織れば、こなれたIラインコーデ♪<br><br>【商品の取り扱いについて】<br>洗濯：家庭用手洗いでのお手入れが可能です。<br>ケア：素材の特性上、強い力が加わると縫い目が開くためご注意。<br><br>【気になる商品は「お気に入り」登録を】<br>&#9825;ハートマークをクリックし、お気に入りに登録すると<br>在庫残り僅かや再入荷通知などの情報を受け取ることができます。', '8000.0 JPY', 488.00, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:31:00', '2026-04-02 04:16:23', 'adastria_636884', '', '69cd72d4a7ab618f2967ca04', '生活/休闲', '', '女', '青年（18-44岁）', '涤纶83%,棉17%', 'https://www.dot-st.com/elura/disp/item/636884/?COLOR_CD=09', '裙装', '连衣裙', '衬衫裙', '', 'shirt dress', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/elura/20260401/item_636884_main_09_1774924499_b.jpg', 0, 0, 2, 0.89538, 0, 1, 1, 0, 0, 3, NULL, '透气，轻盈飘逸，显瘦修身，可手洗，遮阳防晒感，空调房防凉', '轻盈飘逸,显瘦修身,可手洗,遮阳防晒感,空调房防凉', '可家庭手洗整理技术', '采用轻盈有垂感的波纹感薄纱类面料（voile），具有适度透视感,I字纵向线条剪裁，视觉上有显瘦效果,可单穿为衬衫连衣裙，也可敞开作防晒/外搭,适合夏季及空调环境叠穿使用', '纯色', '从商品名“ボイルシャンブレーシャツワンピ”和图片来看，这是前开襟、有领、有门襟和袖口设计的衬衫式连衣裙，长度过膝，可单穿也可当外搭，典型属于 shirt dress（衬衫连衣裙）。\n\n选择的子类：shirt dress\n\n该子类定义：shirt dress 指上身结构类似衬衫（有翻领/立领、门襟、纽扣、袖口等细节），但整体为一件式裙装、通常长度在膝上至小腿之间，可作为连衣裙或外搭穿着的款式。', 1, 0, 0, 0, 'shirt dress', NULL, '', 0, NULL, 0, NULL, NULL, '09', 'ブラック09', 0);
INSERT INTO `clothing_info` VALUES (19996545, '薄纱香槟色衬衫连衣裙', 'ボイルシャンブレーシャツワンピ', 0, 200167, 'Elura', '', '', '【显瘦设计要点】\n修长的纵向I字线条，只需随意披上即可带来显瘦视觉效果。采用轻盈的薄纱材质，轮廓流畅，兼具修饰身形与优雅气质。具有上质感的轻透效果，同时可在家中进行手洗打理。夏日也能作为冷气房的防凉外搭，是点亮休闲时光的百搭衬衫连衣裙。\n\n【材质与功能】\n质感：适度透视与自然垂坠感兼具的轻盈薄纱面料\n材质：聚酯纤维83%、棉17%\n功能：可家庭手洗\n\n【穿搭建议】\n优雅风格：扣上纽扣突出纵向线条，呈现精致的连衣裙造型。\n休闲风格：前襟全开做外搭，营造自然随性的I字廓形层次感。', 'ーーー<br><font size=\"3\"color=\"#c82c55\"><b>Iラインで細みえ。ボイルシャツワンピース</b></font><br><br>【悩みに“効く”ポイント】<br>縦のIラインが、羽織るだけで細みえ効果を叶えます。<br>軽やかなボイル素材でシルエットも美しく。着痩せも狙える一着。<br>上質な透け感なのに。自宅で手洗いできるのも嬉しいポイント。<br>夏の冷房対策にも◎。休日を彩る万能なシャツワンピースです。<br><br>【MATERIAL & FUNCTION】<br>質感：程よい透け感と落ち感のある、軽やかなボイル素材<br>素材：ポリエステル 83％、綿 17％<br>機能：ハンドウォッシャブル<br><br>【スタイリング】<br>キレイ目：ボタンを閉めて縦ラインを強調。上品なワンピスタイルに。<br>カジュアル：前を全開にして羽織れば、こなれたIラインコーデ♪<br><br>【商品の取り扱いについて】<br>洗濯：家庭用手洗いでのお手入れが可能です。<br>ケア：素材の特性上、強い力が加わると縫い目が開くためご注意。<br><br>【気になる商品は「お気に入り」登録を】<br>&#9825;ハートマークをクリックし、お気に入りに登録すると<br>在庫残り僅かや再入荷通知などの情報を受け取ることができます。', '8000.0 JPY', 488.00, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:31:00', '2026-04-02 04:16:24', 'adastria_636884', '', '69cd72d4a7ab618f2967ca04', '生活/休闲', '', '女', '青年（18-44岁）', '涤纶83%,棉17%', 'https://www.dot-st.com/elura/disp/item/636884/?COLOR_CD=09', '裙装', '连衣裙', '衬衫裙', '', 'shirt dress', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/elura/20260401/item_636884_main_25_1774924493_b.jpg', 0, 0, 2, 0.94912, 0, 1, 1, 0, 0, 3, NULL, '透气，轻盈飘逸，显瘦修身，可手洗，遮阳防晒感，空调房防凉', '轻盈飘逸,显瘦修身,可手洗,遮阳防晒感,空调房防凉', '可家庭手洗整理技术', '采用轻盈有垂感的波纹感薄纱类面料（voile），具有适度透视感,I字纵向线条剪裁，视觉上有显瘦效果,可单穿为衬衫连衣裙，也可敞开作防晒/外搭,适合夏季及空调环境叠穿使用', '纯色', '从商品名“ボイルシャンブレーシャツワンピ”和图片来看，这是前开襟、有领、有门襟和袖口设计的衬衫式连衣裙，长度过膝，可单穿也可当外搭，典型属于 shirt dress（衬衫连衣裙）。\n\n选择的子类：shirt dress\n\n该子类定义：shirt dress 指上身结构类似衬衫（有翻领/立领、门襟、纽扣、袖口等细节），但整体为一件式裙装、通常长度在膝上至小腿之间，可作为连衣裙或外搭穿着的款式。', 1, 1, 0, 0, 'shirt dress', NULL, '', 0, NULL, 0, NULL, NULL, '25', 'ピンク25', 0);
