INSERT INTO `clothing_info` VALUES (19996539, '【预售】植物印花吊带上衣', '【先行予約】ボタニカルプルオーバー', 0, 200167, 'Elura', '', '', '夏日出彩的植物印花吊带上衣。具有存在感的植物图案为日常穿搭增添华丽亮点，叠穿T恤即可让简约单品瞬间变得时髦；与同面料裤装搭配还能营造度假感成套造型。采用带微光泽、顺滑质感的缎面面料，呈现适合成熟女性的高级光泽感。面料与里料均为100%聚酯纤维。造型上可与同素材的裤子搭配，打造吸睛的华丽套装；也可叠搭牛仔裤，利用下摆的喇叭感，营造轻松的大人休闲风格。', 'ーーー<br><font size=\"3\"color=\"#c82c55\"><b>夏に映えるボタニカル柄キャミソール</b></font><br><br>【悩みに“効く”ポイント】<br>夏の主役になるボタニカル柄が、いつものコーデも華やかに彩ります。<br>Tシャツとの重ね着も自在、いつものシンプル服も一気に洒落見えします。<br>同素材のパンツを合わせれば、リゾート風セットアップも楽しめる。<br><br>◆<a href=\"https://www.dot-st.com/elura/disp/item/661874\"><b><font size=\"2\" color=\"blue\">同素材のワイドパンツはこちら</a></font></b><br><br>【MATERIAL & FUNCTION】<br>質感：大人が着やすい、微光沢で滑らかなサテン素材<br>素材：ポリエステル 100%（表地・裏地）<br><br>ーー<br>【スタイリング】<br>リゾートLOOK：同素材のパンツと合わせ、視線を集める華やかなセットアップに♪<br>デイリーLOOK：デニムパンツに重ね、裾のフレア感を活かした大人カジュアルもおすすめ。<br><br>【商品の取り扱いについて】<br>洗濯：家庭用洗濯機（ネット使用）でお手入れ簡単です。<br>　　　プリント部分の昇華移染注意(熱や圧力による気化で他の生地に色が移る可能性があります。)<br>ケア：プリントと光沢を長く保つため、裏返し洗いが安心。<br><br>【気になる商品は「お気に入り」登録を】<br>&#9825;ハートマークをクリックし、お気に入りに登録すると<br>在庫残り僅かや再入荷通知などの情報を受け取ることができます。', '5000.0 JPY', 305.00, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:31:01', '2026-04-02 04:16:19', 'adastria_661878', '', '69cd72d4a7ab618f2967c9ff', '生活/休闲', '', '女', '青年（18-44岁）', '涤纶100%', 'https://www.dot-st.com/elura/disp/item/661878/?COLOR_CD=55', '上装', '背心', '吊带背心', '', 'camisole', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/elura/20260401/item_661878_main_55_1774951034_b.jpg', 0, 0, 2, 0.84731, 0, 1, 1, 0, 0, 3, NULL, '易打理，舒适穿着，修饰身形/显瘦', '易打理,舒适穿着,修饰身形/显瘦', '', '采用微光泽顺滑的缎面面料，呈现成熟感光泽,表里布均为聚酯纤维，质地轻盈不易皱,具有具有层次感的下摆喇叭廓形，增强飘逸感,可与同面料裤装搭配实现度假风成套造型,适合与T恤叠穿，提升日常搭配的时髦度,印花区域存在升华移染风险，需注意熨烫与洗涤温度', '花卉图案', '从图片和描述来看，这是无袖、细肩带款式的上衣，日文中称为“キャミソール”，中文对应为吊带背心/吊带上衣，符合列表中的“camisole”类别定义，即以肩带支撑、适合夏季单穿或打底的上装。', 1, 0, 0, 0, 'camisole', NULL, '', 0, NULL, 0, NULL, NULL, '55', 'ブラウン55', 0);
