INSERT INTO `clothing_info` VALUES (19996533, '【预售】Ponte肩部纽扣套头上衣', '【先行予約】ポンチ肩ボタンプルオーバー', 0, 200167, 'Elura', '', '', '采用质感细腻、具有安心感的适中厚度Ponte针织面料制成，既舒适又能呈现利落的精致外观。面料富有弹性，穿着无拘束，并具备接触冷感功能，夏季也能保持清爽舒适。金色肩部纽扣成为优雅亮点，可自然修饰身体线条。同面料半裙搭配可打造都市感套装修身造型，也可与牛仔裤组合成带有肩部纽扣亮点的优雅休闲风格。', 'ーーー<br><font size=\"3\"color=\"#c82c55\"><b>楽ちんなのにキレイ見え。ポンチ素材の優秀プルオーバー</b></font><br><br>【悩みに“効く”ポイント】<br>程よい厚みのポンチ素材が、体のラインも自然にカバー。<br>ゴールドの肩ボタンが上品なアクセントに。<br>伸縮性抜群なジャージー素材なので、毎日ノンストレスな着心地。<br>接触冷感機能が付いているので、夏も涼しく快適に使えます。<br>同素材のスカートを合わせれば、旬のセットアップも楽しめる一着です。<br><br>◆<a href=\"https://www.dot-st.com/elura/disp/item/664870\"><b><font size=\"2\" color=\"blue\">同素材のスカートはこちら</a></font></b><br><br>【MATERIAL & FUNCTION】<br>質感：滑らかな表情で、安心感のある程よい厚みのポンチ素材<br>素材：レーヨン 50%、ナイロン 40%、ポリウレタン 10%<br>機能：接触冷感、マシンウォッシャブル(ネット使用)<br>ーーー<br>【スタイリング】<br>キレイ目：同素材のスカートと合わせて、都会的なセットアップスタイルに♪<br>カジュアル：デニムパンツを合わせ、肩ボタンを際立たせた上品カジュアル。<br><br>【商品の取り扱いについて】<br>洗濯：家庭用洗濯機（ネット使用）でお手入れ簡単です。<br>ケア：強い摩擦によるテカリを防ぐため、裏返し洗いが安心。<br><br>【気になる商品は「お気に入り」登録を】<br>&#9825;ハートマークをクリックし、お気に入りに登録すると<br>在庫残り僅かや再入荷通知などの情報を受け取ることができます。', '6000.0 JPY', 366.00, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:31:02', '2026-04-02 04:16:14', 'adastria_664873', '', '69cd72d4a7ab618f2967c9fd', '生活/休闲', '', '女', '青年（18-44岁）', '粘胶50%,锦纶40%,氨纶10%', 'https://www.dot-st.com/elura/disp/item/664873/?COLOR_CD=56', '上装', '卫衣', '套头衫', '', 'pullover', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/elura/20260401/item_664873_main_56_1774951676_b.jpg', 0, 0, 2, 0.99264, 0, 1, 1, 0, 0, 3, NULL, '接触冷感，高弹力，可机洗，修饰身形，易打理', '可机洗,修饰身形,易打理', '接触冷感功能', '使用中等厚度的ポンチ针织面料，垂坠感好且有一定挺括度,肩部金色装饰钮扣提升精致感与设计感,版型宽松，可自然遮掩身体线条,适合与同面料半裙组合成套装穿着', '纯色，纯色', '从图片和描述看，这是女款长袖上衣，套头设计、无前开门襟，以针织ポンチ面料制作，日文名称中含有“プルオーバー”，符合“pullover（套头上衣）”的定义，因此选择 sub_category 为 pullover（套头上衣）。pullover 指无拉链或前开扣的套头式上衣，如针织衫或卫衣等。', 1, 0, 0, 0, 'pullover', NULL, '', 0, NULL, 0, NULL, NULL, '56', 'モカ56', 0);
INSERT INTO `clothing_info` VALUES (19996534, '【预售】Ponte肩部纽扣套头上衣', '【先行予約】ポンチ肩ボタンプルオーバー', 0, 200167, 'Elura', '', '', '采用质感细腻、具有安心感的适中厚度Ponte针织面料制成，既舒适又能呈现利落的精致外观。面料富有弹性，穿着无拘束，并具备接触冷感功能，夏季也能保持清爽舒适。金色肩部纽扣成为优雅亮点，可自然修饰身体线条。同面料半裙搭配可打造都市感套装修身造型，也可与牛仔裤组合成带有肩部纽扣亮点的优雅休闲风格。', 'ーーー<br><font size=\"3\"color=\"#c82c55\"><b>楽ちんなのにキレイ見え。ポンチ素材の優秀プルオーバー</b></font><br><br>【悩みに“効く”ポイント】<br>程よい厚みのポンチ素材が、体のラインも自然にカバー。<br>ゴールドの肩ボタンが上品なアクセントに。<br>伸縮性抜群なジャージー素材なので、毎日ノンストレスな着心地。<br>接触冷感機能が付いているので、夏も涼しく快適に使えます。<br>同素材のスカートを合わせれば、旬のセットアップも楽しめる一着です。<br><br>◆<a href=\"https://www.dot-st.com/elura/disp/item/664870\"><b><font size=\"2\" color=\"blue\">同素材のスカートはこちら</a></font></b><br><br>【MATERIAL & FUNCTION】<br>質感：滑らかな表情で、安心感のある程よい厚みのポンチ素材<br>素材：レーヨン 50%、ナイロン 40%、ポリウレタン 10%<br>機能：接触冷感、マシンウォッシャブル(ネット使用)<br>ーーー<br>【スタイリング】<br>キレイ目：同素材のスカートと合わせて、都会的なセットアップスタイルに♪<br>カジュアル：デニムパンツを合わせ、肩ボタンを際立たせた上品カジュアル。<br><br>【商品の取り扱いについて】<br>洗濯：家庭用洗濯機（ネット使用）でお手入れ簡単です。<br>ケア：強い摩擦によるテカリを防ぐため、裏返し洗いが安心。<br><br>【気になる商品は「お気に入り」登録を】<br>&#9825;ハートマークをクリックし、お気に入りに登録すると<br>在庫残り僅かや再入荷通知などの情報を受け取ることができます。', '6000.0 JPY', 366.00, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:31:02', '2026-04-02 04:16:15', 'adastria_664873', '', '69cd72d4a7ab618f2967c9fd', '生活/休闲', '', '女', '青年（18-44岁）', '粘胶50%,锦纶40%,氨纶10%', 'https://www.dot-st.com/elura/disp/item/664873/?COLOR_CD=56', '上装', '卫衣', '套头衫', '', 'pullover', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/elura/20260401/item_664873_main_18_1774951630_b.jpg', 0, 0, 6, 0.89182, 0, 1, 1, 0, 0, 3, NULL, '接触冷感，高弹力，可机洗，修饰身形，易打理', '可机洗,修饰身形,易打理', '接触冷感功能', '使用中等厚度的ポンチ针织面料，垂坠感好且有一定挺括度,肩部金色装饰钮扣提升精致感与设计感,版型宽松，可自然遮掩身体线条,适合与同面料半裙组合成套装穿着', '纯色，纯色', '从图片和描述看，这是女款长袖上衣，套头设计、无前开门襟，以针织ポンチ面料制作，日文名称中含有“プルオーバー”，符合“pullover（套头上衣）”的定义，因此选择 sub_category 为 pullover（套头上衣）。pullover 指无拉链或前开扣的套头式上衣，如针织衫或卫衣等。', 1, 1, 0, 0, 'pullover', NULL, '', 0, NULL, 0, NULL, NULL, '18', 'チャコール18', 0);
INSERT INTO `clothing_info` VALUES (19996535, '【预售】夏日感抽绳T恤', '【先行予約】サマ見えドロストTシャツ', 0, 200167, 'Elura', '', '', '———\n夏季舒适度满分的多功能抽绳T恤。\n具备UV防护和接触冷感功能，是夏日必备单品。下摆抽绳可自由调整轮廓，打造随性有型的造型。配有减轻汗渍显现的功能，即使在炎热天气外出也能安心穿着。法式短袖设计，有助于遮挡上臂线条，是适合成熟女性的百搭T恤。\n\n【材质与功能】\n质感：触感柔软，带有微微光泽的精致面料。\n素材：棉70%、聚酯纤维30%。\n功能：UV防护、接触冷感、汗渍减轻、可机洗（建议使用洗衣袋）。\n\n【搭配建议】\n偏优雅：与紧身半裙搭配，营造干练通勤风格。\n偏休闲：与牛仔裤搭配，轻松演绎随性放松风。', 'ーーー<br><font size=\"3\"color=\"#c82c55\"><b>夏快適に過ごす、多機能ドロストＴシャツ</b></font><br><br>【悩みに“効く”ポイント】<br>UVカットや冷感機能もついた、夏のMust-Buyアイテム。<br>裾のドロストでシルエットも自由に、こなれ感抜群なデザイン。<br>汗染み軽減機能も付いているので、暑い日のお出かけも安心です。<br>フレンチスリーブで二の腕もカバーできる、大人の万能Ｔシャツです。<br><br><a href=\"https://www.dot-st.com/elura/disp/itemlist/?dispNo=002001328001\"><b><font size=\"2\" color=\"blue\">Tシャツ ALLアイテムはこちら</a></font></b><br><br>【MATERIAL & FUNCTION】<br>質感：肌触りが良く、微光沢のあるキレイ見え素材<br>素材：綿 70%、ポリエステル 30%<br>機能：UVカット、接触冷感、汗ジミ軽減、マシンウォッシャブル(ネット使用)<br>ーーー<br>【スタイリング】<br>キレイ目：タイトスカートと合わせて、すっきりお仕事スタイルに♪<br>カジュアル：デニムパンツを合わせれば、こなれリラックススタイルに。<br><br>【商品の取り扱いについて】<br>洗濯：家庭でのお手入れが可能です。<br>ケア：型崩れを防ぎ、長く愛用いただくためにネット使用が安心<br><br>【気になる商品は「お気に入り」登録を】<br>&#9825;ハートマークをクリックし、お気に入りに登録すると<br>在庫残り僅かや再入荷通知などの情報を受け取ることができます。', '4500.0 JPY', 274.50, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:31:02', '2026-04-02 04:16:15', 'adastria_661800', '', '69cd72d4a7ab618f2967c9f9', '生活/休闲', '', '女', '青年（18-44岁）', '棉70%,涤纶30%', 'https://www.dot-st.com/elura/disp/item/661800/?COLOR_CD=09', '上装', 'T恤', 'T恤', '', 't-shirt', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/elura/20260401/item_661800_main_09_1774924788_b.jpg', 0, 0, 2, 0.94384, 0, 1, 1, 0, 0, 3, NULL, '防晒，接触冷感，防静水压，温度调节，汗渍减轻，可机洗', '汗渍减轻,可机洗', 'UVカット功能,接触冷感功能,汗ジミ軽减加工', '采用棉与聚酯混纺，面料有微光泽，呈现干净利落的外观,裾部配有抽绳设计，可自由调整衣身轮廓，增加造型变化,法式短袖设计，可在视觉上修饰并遮挡上臂线条,适合搭配职场感紧身裙或休闲牛仔裤，多场景易穿搭', '纯色', '从商品名“ドロストTシャツ”和版型来看，这是短袖、套头、针织面料的基础上衣，整体属于经典T恤版型，并非衬衫或针织衫等其他品类，因此选择子类为 t-shirt（T恤，上身单穿的休闲针织短袖上衣）。', 1, 0, 0, 0, 't-shirt', NULL, '', 0, NULL, 0, NULL, NULL, '09', 'ブラック09', 0);
