INSERT INTO `clothing_info` VALUES (19996537, '【预售】夏日感抽绳T恤', '【先行予約】サマ見えドロストTシャツ', 0, 200167, 'Elura', '', '', '———\n夏季舒适度满分的多功能抽绳T恤。\n具备UV防护和接触冷感功能，是夏日必备单品。下摆抽绳可自由调整轮廓，打造随性有型的造型。配有减轻汗渍显现的功能，即使在炎热天气外出也能安心穿着。法式短袖设计，有助于遮挡上臂线条，是适合成熟女性的百搭T恤。\n\n【材质与功能】\n质感：触感柔软，带有微微光泽的精致面料。\n素材：棉70%、聚酯纤维30%。\n功能：UV防护、接触冷感、汗渍减轻、可机洗（建议使用洗衣袋）。\n\n【搭配建议】\n偏优雅：与紧身半裙搭配，营造干练通勤风格。\n偏休闲：与牛仔裤搭配，轻松演绎随性放松风。', 'ーーー<br><font size=\"3\"color=\"#c82c55\"><b>夏快適に過ごす、多機能ドロストＴシャツ</b></font><br><br>【悩みに“効く”ポイント】<br>UVカットや冷感機能もついた、夏のMust-Buyアイテム。<br>裾のドロストでシルエットも自由に、こなれ感抜群なデザイン。<br>汗染み軽減機能も付いているので、暑い日のお出かけも安心です。<br>フレンチスリーブで二の腕もカバーできる、大人の万能Ｔシャツです。<br><br><a href=\"https://www.dot-st.com/elura/disp/itemlist/?dispNo=002001328001\"><b><font size=\"2\" color=\"blue\">Tシャツ ALLアイテムはこちら</a></font></b><br><br>【MATERIAL & FUNCTION】<br>質感：肌触りが良く、微光沢のあるキレイ見え素材<br>素材：綿 70%、ポリエステル 30%<br>機能：UVカット、接触冷感、汗ジミ軽減、マシンウォッシャブル(ネット使用)<br>ーーー<br>【スタイリング】<br>キレイ目：タイトスカートと合わせて、すっきりお仕事スタイルに♪<br>カジュアル：デニムパンツを合わせれば、こなれリラックススタイルに。<br><br>【商品の取り扱いについて】<br>洗濯：家庭でのお手入れが可能です。<br>ケア：型崩れを防ぎ、長く愛用いただくためにネット使用が安心<br><br>【気になる商品は「お気に入り」登録を】<br>&#9825;ハートマークをクリックし、お気に入りに登録すると<br>在庫残り僅かや再入荷通知などの情報を受け取ることができます。', '4500.0 JPY', 274.50, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:31:02', '2026-04-02 04:16:17', 'adastria_661800', '', '69cd72d4a7ab618f2967c9f9', '生活/休闲', '', '女', '青年（18-44岁）', '棉70%,涤纶30%', 'https://www.dot-st.com/elura/disp/item/661800/?COLOR_CD=09', '上装', 'T恤', 'T恤', '', 't-shirt', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/elura/20260401/item_661800_main_50_1774924793_b.webp', 0, 0, 2, 0.86024, 0, 1, 1, 0, 0, 3, NULL, '防晒，接触冷感，防静水压，温度调节，汗渍减轻，可机洗', '汗渍减轻,可机洗', 'UVカット功能,接触冷感功能,汗ジミ軽减加工', '采用棉与聚酯混纺，面料有微光泽，呈现干净利落的外观,裾部配有抽绳设计，可自由调整衣身轮廓，增加造型变化,法式短袖设计，可在视觉上修饰并遮挡上臂线条,适合搭配职场感紧身裙或休闲牛仔裤，多场景易穿搭', '纯色', '从商品名“ドロストTシャツ”和版型来看，这是短袖、套头、针织面料的基础上衣，整体属于经典T恤版型，并非衬衫或针织衫等其他品类，因此选择子类为 t-shirt（T恤，上身单穿的休闲针织短袖上衣）。', 1, 2, 0, 0, 't-shirt', NULL, '', 0, NULL, 0, NULL, NULL, '50', 'グレージュ50', 0);
