INSERT INTO `clothing_info` VALUES (19996526, '【预售】冷感斗篷针织马甲', '【先行予約】冷感ポンチョニットジレ', 0, 200167, 'Elura', '', '', '———\n体型也能遮盖的斗篷式针织马甲【接触冷感】\n\n【针对身形烦恼的要点】\n宽松斗篷版型，可自然遮盖在意的身形线条。身宽设计充裕，与T恤叠穿也不臃肿。具备接触冷感功能，夏季穿着也清爽舒适。采用可水洗材质，打理轻松，是夏季必入的一件。\n\n【材质与功能】\n质感：触感清爽顺滑，带有凉感的针织材质。\n素材：人造丝61%、锦纶39%。\n功能：接触冷感、可机洗（建议使用洗衣袋）。\n\n【穿搭建议】\n通勤/优雅：与同材质连衣裙搭配，呈现上品造型。\n休闲：与印花LOGO T恤、阔腿裤搭配，营造随性休闲风格。', 'ーーー<br><font size=\"3\"color=\"#c82c55\"><b>体型カバーも叶う ポンチョジレ≪接触冷感≫</b></font><br><br>【悩みに“効く”ポイント】<br>ゆったりポンチョ型が、気になる体のラインも自然にカバー。<br>身幅に余裕がある設計なので、Ｔシャツとのレイヤードももたつかない。<br>接触冷感機能が付いているので、夏も涼しく快適に使えます。<br>洗える素材なのでお手入れも楽ちん。夏のMust-Buyな一着。<br><br>◆<a href=\"https://www.dot-st.com/elura/disp/item/664890\"><b><font size=\"2\" color=\"blue\">同素材のワンピースはこちら</a></font></b><br><br>【MATERIAL & FUNCTION】<br>質感：サラリとした肌触りで、清涼感のあるニット素材<br>素材：レーヨン 61%、ナイロン 39%<br>機能：接触冷感、マシンウォッシャブル(ネット使用)<br>ーーー<br>【スタイリング】<br>キレイ目：同素材のワンピースに合わせた上品スタイル♪<br>カジュアル：ロゴＴシャツとワイドパンツを合わせれば、こなれカジュアルに。<br><br>【商品の取り扱いについて】<br>洗濯：家庭用洗濯機（ネット使用）平干しでのお手入れを推奨。<br>ケア：ニットの風合いを保つため、洗濯後は形を整えて平干しが安心。<br><br>【気になる商品は「お気に入り」登録を】<br>&#9825;ハートマークをクリックし、お気に入りに登録すると<br>在庫残り僅かや再入荷通知などの情報を受け取ることができます。', '8000.0 JPY', 488.00, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:31:03', '2026-04-02 04:16:08', 'adastria_664875', '', '69cd72d4a7ab618f2967c9ec', '生活/休闲', '', '女', '青年（18-44岁）', '粘胶61%,锦纶39%', 'https://www.dot-st.com/elura/disp/item/664875/?COLOR_CD=09', '上装', '背心', '马甲背心', '', 'vest', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/elura/20260401/item_664875_main_09_1773713888_b.jpg', 0, 0, 2, 0.94927, 0, 1, 1, 0, 0, 3, NULL, '接触冷感，温度调节，可机洗，体型遮挡，清凉感', '可机洗,体型遮挡,清凉感', '接触冷感功能纱线/整理', '宽松斗篷版型，侧面开口设计，方便与T恤、连衣裙叠穿,针织梭织感清爽，适合夏季搭配使用,设计用于遮盖身形线条，提升穿着者安心感', '纯色，纯色', '从商品名“ポンチョニットジレ”和图片来看，这是无袖、开前门襟、用于叠穿的外搭单品，日语“ジレ”对应英文中的“vest”。虽然整体呈斗篷式宽松廓形，但本质仍是无袖马甲式针织外搭，因此在给定列表中选择“vest”最为合适。Vest：指无袖、通常开前门襟、穿在内搭外面的上装，用于叠穿和造型。', 1, 0, 0, 0, 'vest', NULL, '', 0, NULL, 0, NULL, NULL, '09', 'ブラック09', 0);
