INSERT INTO `clothing_info` VALUES (19996529, '【预售】显瘦夏日褶饰T恤', '【先行予約】サマ見えタックTシャツ', 0, 200167, 'Elura', '', '', '———\n通过腰部打褶打造高腰视觉效果的夏日感T恤。\n腰部褶饰拉高腰线，实现显高显瘦效果。\n类似荷叶下摆的廓形可以很好地遮住小腹和腰部，修饰身形。\n立体感轮廓设计，即使单穿也足够有存在感，是一件非常出彩的T恤。\n同时具备防紫外线、接触冷感功能，是夏季必入单品。\n配有减轻汗渍显现的功能，炎热天出门也能安心。\n\n【材质与机能】\n质感：手感舒适，带有微光泽的干净利落面料。\n材质：棉70%、聚酯纤维30%。\n功能：防紫外线、接触冷感、汗渍减轻、可机洗（建议使用洗衣袋）。\n\n【穿搭建议】\n通勤感：搭配窄裙，拉长下半身比例，营造修长I字线条。\n休闲感：与修身牛仔裤搭配，利用下摆的蓬松感打造时髦造型。', 'ーーー<br><font size=\"3\"color=\"#c82c55\"><b>ウエストタックで腰高効果抜群のサマ見えＴシャツ</b></font><br><br>【悩みに“効く”ポイント】<br>ウエストタックによる腰高効果で、スタイルアップも叶えます。<br>ペプラムシルエットでお腹も隠せて、腰回りも綺麗にカバー。<br>立体的なフォルムなので、一枚で着映える優秀なTシャツ。<br>UVカットや冷感機能もついた、夏のMust-Buyアイテム。<br>汗染み軽減機能も付いているので、暑い日のお出かけも安心です。<br><br><a href=\"https://www.dot-st.com/elura/disp/itemlist/?dispNo=002001328001\"><b><font size=\"2\" color=\"blue\">Tシャツ ALLアイテムはこちら</a></font></b><br><br>【MATERIAL & FUNCTION】<br>質感：肌触りが良く、微光沢のあるキレイ見え素材<br>素材：綿 70%、ポリエステル 30%<br>機能：UVカット、接触冷感、汗ジミ軽減、マシンウォッシャブル(ネット使用)<br>ーーー<br>【スタイリング】<br>キレイ目：タイトスカートと合わせ、脚長効果抜群なＩライン姿に。<br>カジュアル：細身のデニムを合わせ、裾のふんわり感を活かした旬コーデ♪<br><br>【商品の取り扱いについて】<br>洗濯：家庭用洗濯機（ネット使用）でお手入れ簡単です。<br>ケア：タックの美しさを保つため、形を整えてから干すのが安心。<br><br>【気になる商品は「お気に入り」登録を】<br>&#9825;ハートマークをクリックし、お気に入りに登録すると<br>在庫残り僅かや再入荷通知などの情報を受け取ることができます。', '4500.0 JPY', 274.50, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:31:03', '2026-04-02 04:16:10', 'adastria_661803', '', '69cd72d4a7ab618f2967c9f1', '生活/休闲', '', '女', '青年（18-44岁）', '棉70%,涤纶30%', 'https://www.dot-st.com/elura/disp/item/661803/?COLOR_CD=58', '上装', 'T恤', 'T恤', '', 't-shirt', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/elura/20260401/item_661803_main_58_1774951273_b.jpg', 0, 0, 2, 0.87969, 0, 1, 1, 0, 0, 3, NULL, '防晒，接触冷感，除臭/抗异味，汗渍不明显，可机洗，修饰身形，遮肚遮胯', '汗渍不明显,可机洗,修饰身形,遮肚遮胯', 'UVカット功能,接触冷感功能,汗ジミ軽減機能', '腰部打褶设计，提升腰线比例,下摆呈略带荷叶感的伞摆/类似荷叶边造型,版型偏宽松，单穿即可提升造型感,面料有微光泽，兼顾休闲与通勤感', '纯色', '商品名称为「タックTシャツ」，描述中多次强调是Tシャツ，版型为短袖圆领上衣，长度虽略长但整体仍属针织T恤范畴，不是衬衫或上衣外套，因此选择 sub_category: t-shirt。t-shirt 定义为以针织面料为主、圆领或简洁领型、用于日常穿着的上衣，本商品完全符合。', 1, 0, 0, 0, 't-shirt', NULL, '', 0, NULL, 0, NULL, NULL, '58', 'ダークブラウン58', 0);
