INSERT INTO `clothing_info` VALUES (19996523, '【预售】夏日感字母印花T恤', '【先行予約】サマ見えロゴTシャツ', 0, 200167, 'Elura', '', '', '方正的盒型轮廓，不贴身不显体型，能够自然遮掩身材线条。通过精心拿捏的尺寸感和LOGO设计，营造出轻松又有质感的氛围。衣长经过计算，下摆外穿时也能呈现利落好看的比例。搭载UV防护和接触冷感功能，是夏季必备单品。还具备减轻汗渍显现的功能，让外出更加安心。\n\n质感：手感柔软、带有微光泽感的干净质感面料。\n素材：棉70%、聚酯纤维30%。\n功能：接触冷感、UV防护、汗渍减轻、可机洗。\n\n搭配建议：\n与窄裙搭配，打造成熟利落的对比感造型。\n与彩色裤装搭配，利用下摆线条突出当季感的休闲穿搭。', 'ーーー<br><font size=\"3\"color=\"#c82c55\"><b>ボクシーラインで体型カバー。大人のロゴTシャツ</b></font><br><br>【悩みに“効く”ポイント】<br>ボクシーラインが、体のラインも拾わず自然にカバーします。<br>絶妙なサイジングとロゴデザインが、こなれ感も演出。<br>計算された丈感なので、ボトムスアウトも綺麗に決まる一着。<br>UVカットや冷感機能もついた、夏のMust-Buyアイテム。<br>汗染み軽減機能も付いているので、お出かけも安心です。<br><br>【MATERIAL & FUNCTION】<br>質感：肌触りが良く、微光沢のあるキレイ見え素材<br>素材：綿 70%、ポリエステル 30%<br>機能：接触冷感、UVカット、汗ジミ軽減、マシンウォッシャブル(ネット使用)<br><br>【スタイリング】<br>キレイ目：ナロースカートと合わせ、大人なメリハリを利かせた装いに♪<br>カジュアル：カラーパンツを合わせ、裾のラインを活かした旬コーデに。<br><br>【商品の取り扱いについて}<br>洗濯：家庭用洗濯機（ネット使用）でお手入れ簡単です。<br>ケア：プリント部分の美しさを保つため、裏返し洗いが安心。<br><br>【気になる商品は「お気に入り」登録を】<br>&#9825;ハートマークをクリックし、お気に入りに登録すると<br>在庫残り僅かや再入荷通知などの情報を受け取ることができます。', '4500.0 JPY', 274.50, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:31:04', '2026-04-02 04:16:05', 'adastria_666208', '', '69cd72d4a7ab618f2967c9e3', '生活/休闲', '', '女', '青年（18-44岁）', '棉70%,涤纶30%', 'https://www.dot-st.com/elura/disp/item/666208/?COLOR_CD=50', '上装', 'T恤', 'T恤', '', 't-shirt', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/elura/20260401/item_666208_main_50_1774946648_b.jpg', 0, 0, 2, 0.69628, 0, 1, 1, 0, 0, 3, NULL, '防晒，接触冷感，防紫外线，遮掩身材线条，减轻汗渍痕迹，易打理，机洗方便', '遮掩身材线条,减轻汗渍痕迹,易打理,机洗方便', '接触冷感整理,UVカット功能整理,防汗渍功能整理', '宽松盒型版型，有利于修饰身材比例,微光泽的干净面料，兼顾休闲与稍正式场合,前幅英文Logo印花增强设计感,衣长经过计算，既可外穿遮胯也便于与各种下装搭配', '文字', '根据商品名“サマ見えロゴTシャツ”和图片可见短袖圆领、胸前英文Logo印花、典型针织T恤结构，属于日常穿着的短袖上衣，因此选择子类为 t-shirt（T恤）。t-shirt 的定义是：以针织面料为主、带短袖或长袖的套头式上衣，常用于休闲场合，本商品完全符合这一特征。', 1, 0, 0, 0, 't-shirt', NULL, '', 0, NULL, 0, NULL, NULL, '50', 'グレージュ50', 0);
INSERT INTO `clothing_info` VALUES (19996524, '【预售】夏日感字母印花T恤', '【先行予約】サマ見えロゴTシャツ', 0, 200167, 'Elura', '', '', '方正的盒型轮廓，不贴身不显体型，能够自然遮掩身材线条。通过精心拿捏的尺寸感和LOGO设计，营造出轻松又有质感的氛围。衣长经过计算，下摆外穿时也能呈现利落好看的比例。搭载UV防护和接触冷感功能，是夏季必备单品。还具备减轻汗渍显现的功能，让外出更加安心。\n\n质感：手感柔软、带有微光泽感的干净质感面料。\n素材：棉70%、聚酯纤维30%。\n功能：接触冷感、UV防护、汗渍减轻、可机洗。\n\n搭配建议：\n与窄裙搭配，打造成熟利落的对比感造型。\n与彩色裤装搭配，利用下摆线条突出当季感的休闲穿搭。', 'ーーー<br><font size=\"3\"color=\"#c82c55\"><b>ボクシーラインで体型カバー。大人のロゴTシャツ</b></font><br><br>【悩みに“効く”ポイント】<br>ボクシーラインが、体のラインも拾わず自然にカバーします。<br>絶妙なサイジングとロゴデザインが、こなれ感も演出。<br>計算された丈感なので、ボトムスアウトも綺麗に決まる一着。<br>UVカットや冷感機能もついた、夏のMust-Buyアイテム。<br>汗染み軽減機能も付いているので、お出かけも安心です。<br><br>【MATERIAL & FUNCTION】<br>質感：肌触りが良く、微光沢のあるキレイ見え素材<br>素材：綿 70%、ポリエステル 30%<br>機能：接触冷感、UVカット、汗ジミ軽減、マシンウォッシャブル(ネット使用)<br><br>【スタイリング】<br>キレイ目：ナロースカートと合わせ、大人なメリハリを利かせた装いに♪<br>カジュアル：カラーパンツを合わせ、裾のラインを活かした旬コーデに。<br><br>【商品の取り扱いについて}<br>洗濯：家庭用洗濯機（ネット使用）でお手入れ簡単です。<br>ケア：プリント部分の美しさを保つため、裏返し洗いが安心。<br><br>【気になる商品は「お気に入り」登録を】<br>&#9825;ハートマークをクリックし、お気に入りに登録すると<br>在庫残り僅かや再入荷通知などの情報を受け取ることができます。', '4500.0 JPY', 274.50, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:31:04', '2026-04-02 04:16:06', 'adastria_666208', '', '69cd72d4a7ab618f2967c9e3', '生活/休闲', '', '女', '青年（18-44岁）', '棉70%,涤纶30%', 'https://www.dot-st.com/elura/disp/item/666208/?COLOR_CD=50', '上装', 'T恤', 'T恤', '', 't-shirt', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/elura/20260401/item_666208_main_58_1774950878_b.jpg', 0, 0, 2, 0.53380, 0, 1, 1, 0, 0, 3, NULL, '防晒，接触冷感，防紫外线，遮掩身材线条，减轻汗渍痕迹，易打理，机洗方便', '遮掩身材线条,减轻汗渍痕迹,易打理,机洗方便', '接触冷感整理,UVカット功能整理,防汗渍功能整理', '宽松盒型版型，有利于修饰身材比例,微光泽的干净面料，兼顾休闲与稍正式场合,前幅英文Logo印花增强设计感,衣长经过计算，既可外穿遮胯也便于与各种下装搭配', '文字', '根据商品名“サマ見えロゴTシャツ”和图片可见短袖圆领、胸前英文Logo印花、典型针织T恤结构，属于日常穿着的短袖上衣，因此选择子类为 t-shirt（T恤）。t-shirt 的定义是：以针织面料为主、带短袖或长袖的套头式上衣，常用于休闲场合，本商品完全符合这一特征。', 1, 1, 0, 0, 't-shirt', NULL, '', 0, NULL, 0, NULL, NULL, '58', 'ダークブラウン58', 0);
