INSERT INTO `clothing_info` VALUES (19996519, '【预售】清爽显瘦开领长款上衣', '【先行予約】サラサラ着映えスキッパーチュニック', 0, 200167, 'Elura', '', '', '每年都非常人气的显气质开领长款上衣再次登场。宽松不贴身的版型，保持良好通风，穿着清凉舒适。适度开口的领口能自然修饰颈部与锁骨线条。搭配上品印花图案，为日常通勤增添华丽感。采用不易起皱的材质，打理轻松省心。质地为触感清爽的薄型乔其纱面料，带来清凉舒适的肌肤感受。与同材质裤装搭配即可享受时髦成套造型；搭配牛仔裤或凉鞋也能演绎兼具休闲与优雅的大人风格。', 'ーーー<br><font size=\"3\"color=\"#c82c55\"><b>毎年大人気◎着映えスキッパーチュニックが今年も登場</b></font><br><br>【悩みに“効く”ポイント】<br>体から離れるシルエットで、風通しも良く涼しく着られます。<br>ほどよい開きの襟ぐりは、着用するだけでデコルテも綺麗に。<br>上品なプリント柄も魅力で、毎日の通勤シーンを華やかに演出。<br>しわになりにくい素材なので、お手入れ楽ちんなのも嬉しい♪<br>同素材のパンツを合わせれば、旬のセットアップも楽しめる一着です<br><br>◆<a href=\"https://www.dot-st.com/elura/disp/item/666211\"><b><font size=\"2\" color=\"blue\">同素材のワイドパンツはこちら</a></font></b><br><br>【MATERIAL & FUNCTION】<br>質感：サラサラとした肌触りで、清涼感のある薄手のジョーゼット素材<br>素材：ポリエステル 100%<br><br>ーーー<br>【スタイリング】<br>キレイ目：同素材のパンツと合わせ、都会的で品のあるセットアップに。<br>カジュアル：デニムやサンダルを合わせ、大人の余裕漂うスタイル♪<br><br>【商品の取り扱いについて】<br>洗濯：家庭用洗濯機（ネット使用）でお手入れ簡単です。<br>ケア：プリントの美しさを保つため、裏返し洗いが安心。<br><br>【気になる商品は「お気に入り」登録を】<br>&#9825;ハートマークをクリックし、お気に入りに登録すると<br>在庫残り僅かや再入荷通知などの情報を受け取ることができます。', '6000.0 JPY', 366.00, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:31:05', '2026-04-02 04:16:02', 'adastria_661810', '', '69cd72d4a7ab618f2967c9e5', '生活/休闲', '', '女', '青年（18-44岁）', '涤纶100%', 'https://www.dot-st.com/elura/disp/item/661810/?COLOR_CD=05', '上装', '卫衣', '罩衫', '', 'tunic', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/elura/20260401/item_661810_main_05_1774325628_b.jpg', 0, 0, 2, 0.50972, 0, 1, 1, 0, 0, 3, NULL, '透气，凉爽触感，不易起皱，易打理', '凉爽触感,不易起皱,易打理', '', '薄型乔其纱质感，夏季清凉舒适,宽松不贴身版型，提升通风性与遮体性,V字开领设计修饰颈部与锁骨线条,具有优雅印花图案，适合通勤穿搭,可与同面料裤子组成成套搭配', '点', '根据商品名“スキッパーチュニック”和图片可见，这是长度覆盖髋部、版型宽松、带开领（skipper 领型）的上衣，介于上衣与短连衣裙之间，典型日常女装“tunic（束腰长上衣/罩衫）”样式。故选择子类别：tunic。tunic 的定义：长度通常到大腿上部或中部、版型相对宽松，可单穿或与裤装叠搭的长款上衣。', 1, 0, 0, 0, 'tunic', NULL, '', 0, NULL, 0, NULL, NULL, '05', 'ホワイトドット05', 0);
