INSERT INTO `clothing_info` VALUES (19996521, '【预售】清爽显瘦开领长款上衣', '【先行予約】サラサラ着映えスキッパーチュニック', 0, 200167, 'Elura', '', '', '每年都非常人气的显气质开领长款上衣再次登场。宽松不贴身的版型，保持良好通风，穿着清凉舒适。适度开口的领口能自然修饰颈部与锁骨线条。搭配上品印花图案，为日常通勤增添华丽感。采用不易起皱的材质，打理轻松省心。质地为触感清爽的薄型乔其纱面料，带来清凉舒适的肌肤感受。与同材质裤装搭配即可享受时髦成套造型；搭配牛仔裤或凉鞋也能演绎兼具休闲与优雅的大人风格。', 'ーーー<br><font size=\"3\"color=\"#c82c55\"><b>毎年大人気◎着映えスキッパーチュニックが今年も登場</b></font><br><br>【悩みに“効く”ポイント】<br>体から離れるシルエットで、風通しも良く涼しく着られます。<br>ほどよい開きの襟ぐりは、着用するだけでデコルテも綺麗に。<br>上品なプリント柄も魅力で、毎日の通勤シーンを華やかに演出。<br>しわになりにくい素材なので、お手入れ楽ちんなのも嬉しい♪<br>同素材のパンツを合わせれば、旬のセットアップも楽しめる一着です<br><br>◆<a href=\"https://www.dot-st.com/elura/disp/item/666211\"><b><font size=\"2\" color=\"blue\">同素材のワイドパンツはこちら</a></font></b><br><br>【MATERIAL & FUNCTION】<br>質感：サラサラとした肌触りで、清涼感のある薄手のジョーゼット素材<br>素材：ポリエステル 100%<br><br>ーーー<br>【スタイリング】<br>キレイ目：同素材のパンツと合わせ、都会的で品のあるセットアップに。<br>カジュアル：デニムやサンダルを合わせ、大人の余裕漂うスタイル♪<br><br>【商品の取り扱いについて】<br>洗濯：家庭用洗濯機（ネット使用）でお手入れ簡単です。<br>ケア：プリントの美しさを保つため、裏返し洗いが安心。<br><br>【気になる商品は「お気に入り」登録を】<br>&#9825;ハートマークをクリックし、お気に入りに登録すると<br>在庫残り僅かや再入荷通知などの情報を受け取ることができます。', '6000.0 JPY', 366.00, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:31:05', '2026-04-02 04:16:04', 'adastria_661810', '', '69cd72d4a7ab618f2967c9e5', '生活/休闲', '', '女', '青年（18-44岁）', '涤纶100%', 'https://www.dot-st.com/elura/disp/item/661810/?COLOR_CD=05', '上装', '卫衣', '罩衫', '', 'tunic', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/elura/20260401/item_661810_main_02_1774951139_b.jpg', 0, 0, 6, 0.74620, 0, 1, 1, 0, 0, 3, NULL, '透气，凉爽触感，不易起皱，易打理', '凉爽触感,不易起皱,易打理', '', '薄型乔其纱质感，夏季清凉舒适,宽松不贴身版型，提升通风性与遮体性,V字开领设计修饰颈部与锁骨线条,具有优雅印花图案，适合通勤穿搭,可与同面料裤子组成成套搭配', '点', '根据商品名“スキッパーチュニック”和图片可见，这是长度覆盖髋部、版型宽松、带开领（skipper 领型）的上衣，介于上衣与短连衣裙之间，典型日常女装“tunic（束腰长上衣/罩衫）”样式。故选择子类别：tunic。tunic 的定义：长度通常到大腿上部或中部、版型相对宽松，可单穿或与裤装叠搭的长款上衣。', 1, 2, 0, 0, 'tunic', NULL, '', 0, NULL, 0, NULL, NULL, '02', 'ホワイトムジ02', 0);
INSERT INTO `clothing_info` VALUES (19996522, '【预售】清爽显瘦开领长款上衣', '【先行予約】サラサラ着映えスキッパーチュニック', 0, 200167, 'Elura', '', '', '每年都非常人气的显气质开领长款上衣再次登场。宽松不贴身的版型，保持良好通风，穿着清凉舒适。适度开口的领口能自然修饰颈部与锁骨线条。搭配上品印花图案，为日常通勤增添华丽感。采用不易起皱的材质，打理轻松省心。质地为触感清爽的薄型乔其纱面料，带来清凉舒适的肌肤感受。与同材质裤装搭配即可享受时髦成套造型；搭配牛仔裤或凉鞋也能演绎兼具休闲与优雅的大人风格。', 'ーーー<br><font size=\"3\"color=\"#c82c55\"><b>毎年大人気◎着映えスキッパーチュニックが今年も登場</b></font><br><br>【悩みに“効く”ポイント】<br>体から離れるシルエットで、風通しも良く涼しく着られます。<br>ほどよい開きの襟ぐりは、着用するだけでデコルテも綺麗に。<br>上品なプリント柄も魅力で、毎日の通勤シーンを華やかに演出。<br>しわになりにくい素材なので、お手入れ楽ちんなのも嬉しい♪<br>同素材のパンツを合わせれば、旬のセットアップも楽しめる一着です<br><br>◆<a href=\"https://www.dot-st.com/elura/disp/item/666211\"><b><font size=\"2\" color=\"blue\">同素材のワイドパンツはこちら</a></font></b><br><br>【MATERIAL & FUNCTION】<br>質感：サラサラとした肌触りで、清涼感のある薄手のジョーゼット素材<br>素材：ポリエステル 100%<br><br>ーーー<br>【スタイリング】<br>キレイ目：同素材のパンツと合わせ、都会的で品のあるセットアップに。<br>カジュアル：デニムやサンダルを合わせ、大人の余裕漂うスタイル♪<br><br>【商品の取り扱いについて】<br>洗濯：家庭用洗濯機（ネット使用）でお手入れ簡単です。<br>ケア：プリントの美しさを保つため、裏返し洗いが安心。<br><br>【気になる商品は「お気に入り」登録を】<br>&#9825;ハートマークをクリックし、お気に入りに登録すると<br>在庫残り僅かや再入荷通知などの情報を受け取ることができます。', '6000.0 JPY', 366.00, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:31:05', '2026-04-02 04:16:04', 'adastria_661810', '', '69cd72d4a7ab618f2967c9e5', '生活/休闲', '', '女', '青年（18-44岁）', '涤纶100%', 'https://www.dot-st.com/elura/disp/item/661810/?COLOR_CD=05', '上装', '卫衣', '罩衫', '', 'tunic', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/elura/20260401/item_661810_main_88_1773710932_b.jpg', 0, 0, 2, 0.99031, 0, 1, 1, 0, 0, 3, NULL, '透气，凉爽触感，不易起皱，易打理', '凉爽触感,不易起皱,易打理', '', '薄型乔其纱质感，夏季清凉舒适,宽松不贴身版型，提升通风性与遮体性,V字开领设计修饰颈部与锁骨线条,具有优雅印花图案，适合通勤穿搭,可与同面料裤子组成成套搭配', '点', '根据商品名“スキッパーチュニック”和图片可见，这是长度覆盖髋部、版型宽松、带开领（skipper 领型）的上衣，介于上衣与短连衣裙之间，典型日常女装“tunic（束腰长上衣/罩衫）”样式。故选择子类别：tunic。tunic 的定义：长度通常到大腿上部或中部、版型相对宽松，可单穿或与裤装叠搭的长款上衣。', 1, 3, 0, 0, 'tunic', NULL, '', 0, NULL, 0, NULL, NULL, '88', 'ネイビーセンガ88', 0);
INSERT INTO `clothing_info` VALUES (19996517, '【预售】植物印花阔腿裤', '【先行予約】ボタニカルワイドパンツ', 0, 200167, 'Elura', '', '', '夏日造型中醒目的植物印花阔腿裤。只需搭配简约T恤，就能呈现出成熟有型的休闲感造型，也可以与同面料吊带上衣搭配成套装。缎面材质带有细腻微光泽，质感顺滑，上身优雅大方，成熟女性也易于驾驭。\\n\\n【材质与质感】\\n质感：适合成熟女性的微光泽感，触感顺滑的缎面质地。\\n成分：聚酯纤维100%。\\n\\n【搭配建议】\\n度假风造型：与同面料吊带上衣搭配，打造华丽的套装度假造型。\\n日常造型：推荐与夏季针织上衣、凉鞋等单品组合，呈现兼具优雅与放松感的穿搭。', 'ーーー<br><font size=\"3\"color=\"#c82c55\"><b>夏に映えるボタニカル柄ワイドパンツ</b></font><br><font color=\"#000000\"><b>※低身長さん向けElkotona(エルコトナ)サイズあり</b></font><br><br>【悩みに“効く”ポイント】<br>夏のリゾート気分を高める、華やかなボタニカル柄が主役級の一枚。<br>シンプルなＴシャツと合わせるだけで、大人のこなれた洒落感が完成。<br>同素材のキャミとのセットアップも可能。<br>サテン素材の微光沢が上品で大人も着やすい柄ワイドパンツです。<br><br>◆<a href=\"https://www.dot-st.com/elura/disp/item/661878\"><b><font size=\"2\" color=\"blue\">同素材のキャミソールはこちら</a></font></b><br><br>【MATERIAL & FUNCTION】<br>質感：大人が着やすい、微光沢で滑らかなサテン素材<br>素材：ポリエステル 100%<br>ーーー<br>【スタイリング】<br>リゾートLOOK：同素材のキャミソールと合わせ、華やかなセットアップ姿に♪<br>デイリーLOOK：サマーニットやサンダルを合わせた、品のあるリラクシーコーデもおすすめ。<br><br>【商品の取り扱いについて】<br>洗濯：家庭用洗濯機（ネット使用）でお手入れ簡単です。<br>          プリント部分の昇華移染注意(熱や圧力による気化で他の生地に色が移る可能性があります。)<br>ケア：プリントと光沢を長く保つため、裏返し洗いが安心。<br><br>【気になる商品は「お気に入り」登録を】<br>&#9825;ハートマークをクリックし、お気に入りに登録すると<br>在庫残り僅かや再入荷通知などの情報を受け取ることができます。', '8000.0 JPY', 488.00, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:31:10', '2026-04-02 04:16:00', 'adastria_661874', '', '69cd72d4a7ab618f2967c9d3', '生活/休闲，差旅/商务，瑜伽', '', '女', '青年（18-44岁）', '涤纶100%', 'https://www.dot-st.com/elura/disp/item/661874/?COLOR_CD=88', '下装', '休闲裤', '阔腿裤', '', 'palazzo pants', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/elura/20260401/item_661874_main_88_1774951103_b.jpg', 0, 0, 6, 0.50899, 0, 1, 1, 0, 0, 3, NULL, '舒适，轻盈，易打理', '舒适,轻盈,易打理', '', '采用微光泽感的缎面材质，表面顺滑有光泽,宽松版型的阔腿裤，裤型飘逸有垂坠感,大面积植物波希风印花，适合夏季与度假穿搭,可与同材质吊带上衣组成套装造型,有适合低身高人群的特别尺码 Elkotona 尺寸,家用洗衣机可水洗，护理方便', '花卉图案，叶子', '从商品名“ボタニカルワイドパンツ”和图片可以看出，这是一条裤腿非常宽松、从腰到裤脚基本呈直筒/宽摆、整体廓形飘逸的长裤，属于典型的阔腿裤样式。与备选类别中最接近的是“palazzo pants（阔腿裤）”，指裤管宽大、垂坠感强、常用于休闲和度假场景的女装长裤，因此选择 sub_category 为 “palazzo pants（阔腿裤：裤腿极宽、版型飘逸的长裤）”。', 1, 0, 0, 0, 'palazzo pants', NULL, '', 0, NULL, 0, NULL, NULL, '88', 'ネイビー88', 0);
INSERT INTO `clothing_info` VALUES (19996518, '【预售】植物印花阔腿裤', '【先行予約】ボタニカルワイドパンツ', 0, 200167, 'Elura', '', '', '夏日造型中醒目的植物印花阔腿裤。只需搭配简约T恤，就能呈现出成熟有型的休闲感造型，也可以与同面料吊带上衣搭配成套装。缎面材质带有细腻微光泽，质感顺滑，上身优雅大方，成熟女性也易于驾驭。\\n\\n【材质与质感】\\n质感：适合成熟女性的微光泽感，触感顺滑的缎面质地。\\n成分：聚酯纤维100%。\\n\\n【搭配建议】\\n度假风造型：与同面料吊带上衣搭配，打造华丽的套装度假造型。\\n日常造型：推荐与夏季针织上衣、凉鞋等单品组合，呈现兼具优雅与放松感的穿搭。', 'ーーー<br><font size=\"3\"color=\"#c82c55\"><b>夏に映えるボタニカル柄ワイドパンツ</b></font><br><font color=\"#000000\"><b>※低身長さん向けElkotona(エルコトナ)サイズあり</b></font><br><br>【悩みに“効く”ポイント】<br>夏のリゾート気分を高める、華やかなボタニカル柄が主役級の一枚。<br>シンプルなＴシャツと合わせるだけで、大人のこなれた洒落感が完成。<br>同素材のキャミとのセットアップも可能。<br>サテン素材の微光沢が上品で大人も着やすい柄ワイドパンツです。<br><br>◆<a href=\"https://www.dot-st.com/elura/disp/item/661878\"><b><font size=\"2\" color=\"blue\">同素材のキャミソールはこちら</a></font></b><br><br>【MATERIAL & FUNCTION】<br>質感：大人が着やすい、微光沢で滑らかなサテン素材<br>素材：ポリエステル 100%<br>ーーー<br>【スタイリング】<br>リゾートLOOK：同素材のキャミソールと合わせ、華やかなセットアップ姿に♪<br>デイリーLOOK：サマーニットやサンダルを合わせた、品のあるリラクシーコーデもおすすめ。<br><br>【商品の取り扱いについて】<br>洗濯：家庭用洗濯機（ネット使用）でお手入れ簡単です。<br>          プリント部分の昇華移染注意(熱や圧力による気化で他の生地に色が移る可能性があります。)<br>ケア：プリントと光沢を長く保つため、裏返し洗いが安心。<br><br>【気になる商品は「お気に入り」登録を】<br>&#9825;ハートマークをクリックし、お気に入りに登録すると<br>在庫残り僅かや再入荷通知などの情報を受け取ることができます。', '8000.0 JPY', 488.00, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:31:10', '2026-04-02 04:16:01', 'adastria_661874', '', '69cd72d4a7ab618f2967c9d3', '生活/休闲，差旅/商务，瑜伽', '', '女', '青年（18-44岁）', '涤纶100%', 'https://www.dot-st.com/elura/disp/item/661874/?COLOR_CD=88', '下装', '休闲裤', '阔腿裤', '', 'palazzo pants', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/elura/20260401/item_661874_main_55_1774951081_b.jpg', 0, 0, 2, 0.93895, 0, 1, 1, 0, 0, 3, NULL, '舒适，轻盈，易打理', '舒适,轻盈,易打理', '', '采用微光泽感的缎面材质，表面顺滑有光泽,宽松版型的阔腿裤，裤型飘逸有垂坠感,大面积植物波希风印花，适合夏季与度假穿搭,可与同材质吊带上衣组成套装造型,有适合低身高人群的特别尺码 Elkotona 尺寸,家用洗衣机可水洗，护理方便', '花卉图案，叶子', '从商品名“ボタニカルワイドパンツ”和图片可以看出，这是一条裤腿非常宽松、从腰到裤脚基本呈直筒/宽摆、整体廓形飘逸的长裤，属于典型的阔腿裤样式。与备选类别中最接近的是“palazzo pants（阔腿裤）”，指裤管宽大、垂坠感强、常用于休闲和度假场景的女装长裤，因此选择 sub_category 为 “palazzo pants（阔腿裤：裤腿极宽、版型飘逸的长裤）”。', 1, 1, 0, 0, 'palazzo pants', NULL, '', 0, NULL, 0, NULL, NULL, '55', 'ブラウン55', 0);
INSERT INTO `clothing_info` VALUES (19996516, '【男女通用】PUMA／SQUID GAME T7 ICONIC 直筒长裤（卫衣面料）', '【UNISEX】PUMA／SQUID GAME T7  ICONIC ストレートパンツ（ウラケ）', 0, 200334, 'ALAND', '', '', '这是人气韩国电视剧《鱿鱼游戏》和 PUMA 的联名单品。采用具有高档质感的天鹅绒风格面料，裤身带有 PUMA 插画图案，左裤腿配有《鱿鱼游戏》联名标志，并可与同系列上衣搭配成套穿着。', 'ーーー<br><font size=\"2pt\"><b><font color=\"#0c9e3f\">イカゲーム×PUMAのコラボアイテム</font></b></font><br>ーーー<br><br>【POINT】<br>・大人気韓国ドラマ”イカゲーム”とPUMAのコラボアイテム<br>・高級感あるベロア素材にPUMAのイラスト入り<br>・左足にはイカゲームのロゴ入り<br>・セットアップでも着れるジャージは<a href=\'https://www.dot-st.com/aland/disp/item/260045/\'>こちら</a><br>', '10000.0 JPY', 610.00, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:31:12', '2026-04-02 04:15:59', 'adastria_260048', '', '69cd72d4a7ab618f2967c9d9', '生活/休闲', '', '通用', '青年（18-44岁）', '棉74%,涤纶24%,氨纶2%', 'https://www.dot-st.com/aland/disp/item/260048/?COLOR_CD=19', '下装', '西裤', '裤装', '', 'trousers', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/aland/20260401/item_260048_main_19_1733105391_b.jpg', 0, 0, 6, 0.66819, 0, 1, 0, 0, 0, 3, NULL, '舒适，保暖性较好，有弹性', '舒适,保暖性较好,有弹性', '品牌联名设计', '与韩国电视剧《鱿鱼游戏》联名，带有联名标志与图案,采用高档感天鹅绒风格面料，表面有整体字母图案,腰部与裤型偏休闲直筒版型，适合成套搭配为运动套装', '字母，品牌标识', '从商品名称“ストレートパンツ（ウラケ）”以及图片可以看出，这是长裤、直筒版型，下装而非上装，也不是家纺类产品。结合休闲运动风格，最合适归类为“trousers（长裤/裤装）”。trousers 指覆盖双腿、通常从腰部到脚踝的裤子，本产品完全符合这一定义。', 0, 0, 0, 0, 'trousers', NULL, '', 0, NULL, 0, NULL, NULL, '19', 'ブラック（19）', 0);
INSERT INTO `clothing_info` VALUES (19996515, 'LAND MUSEUM／颜料感网眼连帽卫衣', 'LAND MUSEUM／ピグメントメッシュパーカー', 0, 200334, 'ALAND', '', '', '春季也能穿着的网眼连帽卫衣。整体廓形宽松，有松弛感，营造随性氛围。通过更换内搭单品可以呈现不同造型，具有轻微透视感，内搭会若隐若现。可用于休闲、古着混搭、美式休闲、韩系等多种风格穿搭，和各种下装都容易搭配。内搭可选择黑白等单色款式，也适合叠穿彩色或带印花图案的上衣，强化层次感。品牌LAND MUSEUM追求跨越极简与街头、打破性别边界的自我表达风格，以细致的细节设计和均衡的廓形带来舒适的穿着体验。', 'ーーー<br><font size=\"2pt\"><b><font color=\"#122ee6\">春まで使えるメッシュパーカー</font></b></font><br>ーーー<br><br>【POINT】<br>・全体的にゆとりを持たせた抜け感のあるシルエット。  <br>・合わせるインナーによって違った雰囲気が楽しめます。<br>・中のインナーが薄っすらみえる、程よい透け感<br><br>【STYLING】<br>・カジュアル、古着ミックス、アメカジ、韓国系など様々なスタイルを楽しめる万能アイテムでボトムス選びに困りません<br>・インナーはモノトーンで合わせるのはもちろん、色物やプリントデザインされたトップスをレイヤードするのもおすすめです。<br><br>▼LAND MUSEUMのラインナップはコチラ<br><a href=\"https://www.dot-st.com/aland/disp/itemlist/?dispNo=002100168\"><font color=\"#1111cc\">＞ブラウザでご覧の方はコチラ</font></a><br><a href=\"adastriaapp://items?dispNo=0000100041_002100168\"><font color=\"#1111cc\">＞アプリでご覧の方はコチラ</font></a> <br><br>＜LAND MUSEUM／ランドミュージアム＞<br>LANDMUSEUMは、ミニマルとストリート・ジェンダーの境界を越えて、自分のアイデンティティを表現できるスタイルを追求し<br>細かいディティールとバランスの取れたシルエットで快適な着用感を提供します。', '9719.0 JPY', 592.86, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:31:37', '2026-04-02 04:15:58', 'adastria_291852', '', '69cd72d4a7ab618f2967c9cc', '生活/休闲', '', '通用', '青年（18-44岁）', '棉100%', 'https://www.dot-st.com/aland/disp/item/291852/?COLOR_CD=55', '上装', '卫衣', '连帽衫', '', 'hoodie', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/aland/20260401/item_291852_main_55_1774855600_b.jpg', 0, 0, 2, 0.95281, 0, 1, 1, 0, 0, 3, NULL, '透气，层次穿搭，宽松版型提升舒适度', '层次穿搭,宽松版型提升舒适度', '', '整体宽松廓形，拉链开襟连帽设计,大网眼结构，具有一定透视感，便于内搭显露层次,前身双贴袋设计，增加休闲感和实用性,中性风格，适合多种街头与古着混搭造型', '纯色，纯色', '从图片和描述看，这是带帽的长袖上衣，前中为全开拉链、带抽绳帽子和袋鼠式贴袋，整体为休闲卫衣式版型，而且为针织/网眼面料的连帽上衣，最符合列表中的“hoodie（连帽卫衣/连帽上衣）”分类定义。', 0, 0, 0, 0, 'hoodie', NULL, '', 0, NULL, 0, NULL, NULL, '55', 'ベージュ（55）', 0);
INSERT INTO `clothing_info` VALUES (19996513, 'STOCKHOLM SYNDROME／DINOSAUR 连帽卫衣', 'STOCKHOLM SYNDROME／DINOSAUR フーディ―', 0, 200334, 'ALAND', '', '', '手绘风格插画图案设计，个性鲜明的连帽卫衣款式。由品牌 STOCKHOLM SYNDROME 推出，以自由表达又能引发大众共鸣的图像设计为特色，将心理概念融入图案创作之中。', 'ーーー<br><b><font size=\"2pt\"><font color=\"#45a80c\">手書きイラストデザインが個性的なパーカー！</font></font></b><br>ーーー<br><br>▼STOCKHOLM SYNDROMEのラインナップはコチラ<br><a href=\"https://www.dot-st.com/aland/disp/itemlist/?dispNo=002100003\"><font color=\"#1111cc\">＞ブラウザでご覧の方はコチラ</font></a><br><a href=\"adastriaapp://items?dispNo=0000100041_002100003><font color=\"#1111cc\">＞アプリでご覧の方はコチラ</font></a><br><br>＜STOCKHOLM SYNDROME／ストックホルムシンドローム＞<br>STOCKHOLM SYNDROME（ストックホルム症候群）は人質が誘拐犯に共感と同情とプラスの感情を抱いてしまう心理的現象です。<br>自由に表現しながらも大衆が共感できるデザインをすることで<br>人質を大衆、誘拐犯を私たちSTOCKHOLM SYNDROMEに重ね合わせています。', '14082.0 JPY', 859.00, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:31:38', '2026-04-02 04:15:57', 'adastria_625333', '', '69cd72d4a7ab618f2967c9c3', '生活/休闲', '', '通用', '青年（18-44岁）', '棉100%', 'https://www.dot-st.com/aland/disp/item/625333/?COLOR_CD=20', '上装', '卫衣', '连帽衫', '', 'hoodie', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/aland/20260401/item_625333_main_20_1763105328_b.jpg', 0, 0, 2, 0.65025, 0, 1, 1, 0, 0, 3, NULL, '保暖', '', '', '宽松版型连帽设计,前幅大面积图案印花,风格偏街头感与个性表达,罗纹袖口和下摆提升造型感', '人物图案（人形，人体），卡通人物（拟人化物体），文字', '从图片和描述看，这是带帽、有前幅大面积图案印花的套头上衣，属于典型的“连帽卫衣”款式，英文常称为 hoodie。与 sweatshirt 相比，其明显特征是有立体帽子与抽绳结构，因此选择子类目“hoodie（连帽卫衣）”。', 1, 0, 0, 0, 'hoodie', NULL, '', 0, NULL, 0, NULL, NULL, '20', 'ピンク（20）', 0);
INSERT INTO `clothing_info` VALUES (19996514, 'STOCKHOLM SYNDROME／DINOSAUR 连帽卫衣', 'STOCKHOLM SYNDROME／DINOSAUR フーディ―', 0, 200334, 'ALAND', '', '', '手绘风格插画图案设计，个性鲜明的连帽卫衣款式。由品牌 STOCKHOLM SYNDROME 推出，以自由表达又能引发大众共鸣的图像设计为特色，将心理概念融入图案创作之中。', 'ーーー<br><b><font size=\"2pt\"><font color=\"#45a80c\">手書きイラストデザインが個性的なパーカー！</font></font></b><br>ーーー<br><br>▼STOCKHOLM SYNDROMEのラインナップはコチラ<br><a href=\"https://www.dot-st.com/aland/disp/itemlist/?dispNo=002100003\"><font color=\"#1111cc\">＞ブラウザでご覧の方はコチラ</font></a><br><a href=\"adastriaapp://items?dispNo=0000100041_002100003><font color=\"#1111cc\">＞アプリでご覧の方はコチラ</font></a><br><br>＜STOCKHOLM SYNDROME／ストックホルムシンドローム＞<br>STOCKHOLM SYNDROME（ストックホルム症候群）は人質が誘拐犯に共感と同情とプラスの感情を抱いてしまう心理的現象です。<br>自由に表現しながらも大衆が共感できるデザインをすることで<br>人質を大衆、誘拐犯を私たちSTOCKHOLM SYNDROMEに重ね合わせています。', '14082.0 JPY', 859.00, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:31:38', '2026-04-02 04:15:58', 'adastria_625333', '', '69cd72d4a7ab618f2967c9c3', '生活/休闲', '', '通用', '青年（18-44岁）', '棉100%', 'https://www.dot-st.com/aland/disp/item/625333/?COLOR_CD=20', '上装', '卫衣', '连帽衫', '', 'hoodie', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/aland/20260401/item_625333_main_52_1763105330_b.jpg', 0, 0, 2, 0.97751, 0, 1, 1, 0, 0, 3, NULL, '保暖', '', '', '宽松版型连帽设计,前幅大面积图案印花,风格偏街头感与个性表达,罗纹袖口和下摆提升造型感', '人物图案（人形，人体），卡通人物（拟人化物体），文字', '从图片和描述看，这是带帽、有前幅大面积图案印花的套头上衣，属于典型的“连帽卫衣”款式，英文常称为 hoodie。与 sweatshirt 相比，其明显特征是有立体帽子与抽绳结构，因此选择子类目“hoodie（连帽卫衣）”。', 1, 1, 0, 0, 'hoodie', NULL, '', 0, NULL, 0, NULL, NULL, '52', 'アイボリー（52）', 0);
INSERT INTO `clothing_info` VALUES (19996509, '洗衣液 / ecostore', 'ランドリーリキッド / ecostore', 0, 200332, 'TODAY’S SPECIAL', '', '', '这是一款浓缩型液体洗衣剂，能够有效去除日常的汗渍和皮脂污渍，不仅对肌肤温和，也能让衣物保持洁净。\n即使不添加柔顺剂，衣物和毛巾也不易变得僵硬，洗后手感较为柔软。可选择无香型、天竺葵&橙子、尤加利等香型。\n\n【品牌介绍：ecostore（エコストア）】\necostore 于 1993 年在新西兰北部沿海地区由夫妻档创立，致力于不使用有害、无用化学物质的清洁和身体护理产品，让人们在健康优先、洁净的环境中生活。品牌在奥克兰自有工厂生产家用洗涤剂及身体护理、婴儿护理等用品，并在澳大利亚、美国及亚洲销售。\n所有简约外观的容器均源自甘蔗制成，具备可回归土壤的生物降解设计。产品中的清洗成分（界面活性剂）全部为植物来源，不使用任何石油系界面活性剂。原产国为日本。', '<!--ーーー--><br>毎日の汗や皮脂汚れをしっかり落とす、濃縮タイプの液体洗剤。<br>お肌に優しいだけでなく、衣類を清潔に仕上げます。<br><br>柔軟剤を入れなくてもごわつくことも少なく、衣類やタオルが固くならないのも嬉しいポイント。<br>無香料、ゼラニウム＆オレンジ、ユーカリからお選びください。<br><br><b>ecostore(エコストア)</b><br>1993年、ニュージーランドのノースランド地方沿岸部でマルコム&メラニー ･ ランズ夫妻によって設立。<br>その約10年前に小川が流れる原生林が生い茂った谷間に、文明に汚されていない土地を発見したことをきっかけに、有害、不要な化学物質を一切使わないクリーニング&ボディケア製品を創り出しています。<br>健康を最優先し、清潔な環境で生活することができるようにしました。<br>オークランドの自社工場で生産した家庭用洗剤やボディケア&ベビーケア製品を、オーストラリア、米国、アジアで販売しています。<br>シンプルな容器はすべてサトウキビからできており、土に返る生分解設計。<br>洗浄成分(界面活性剤)はすべて植物由来で、石油由来界面活性剤を一切使用していません。<br><br><br>原産国 : 日本<!--ーーー--><br>内容量 : 500ml<br><br><b>\"ecostore(エコストア)\"アイテム一覧はこちら</b><br><a href=\"https://www.dot-st.com/todaysspecial/disp/itemlist/?dispNo=002005058\" target=\"_blank\"><font size=\"2\" color=\"blue\">ブラウザでみる</a></font></b> | <a href=\"adastriaapp://items?dispNo=0000100084_002005058&orderBy=00\" target=\"_blank\"><font size=\"2\" color=\"blue\">アプリでみる</a></font></b><br><br>', '800.0 JPY', 48.80, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:32:11', '2026-04-02 04:15:53', 'adastria_643795', '', '69cd72d4a7ab618f2967c9bb', '生活/休闲', '', '通用', '青年（18-44岁）', NULL, 'https://www.dot-st.com/todaysspecial/disp/item/643795/?COLOR_CD=01', '其他服饰/物品', '其他', '配件', '', 'accessories', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/today’s_special/20260401/item_643795_main_01_1774830475_b.jpg', 0, 0, 9, 0.99840, 0, 1, 0, 0, 0, 3, NULL, '温和亲肤，高效清洁汗渍和皮脂污渍，减少衣物和毛巾变硬，无香料及多种香型选择，使用植物来源清洁成分，不使用石油系界面活性剂，生物降解设计，环保包装', '温和亲肤,高效清洁汗渍和皮脂污渍,减少衣物和毛巾变硬,无香料及多种香型选择,使用植物来源清洁成分,不使用石油系界面活性剂,生物降解设计,环保包装', '植物来源界面活性剂配方,生分解环保配方,甘蔗来源可再生塑料瓶', '属于浓缩型液体洗衣剂，用量相对节省,主打对皮肤温和并保持衣物洁净,无需额外使用柔顺剂也能减轻衣物发硬,提供无香型、天竺葵&橙子、尤加利等不同香型选择,品牌强调不使用有害、无用化学物质,清洁和身体护理产品均以健康优先为理念,包装瓶采用甘蔗制成，能够回归土壤，符合可持续设计,界面活性剂全部为植物来源，不含石油系成分,品牌来自新西兰，在自有工厂生产并销往多国', '纯色', '该商品为“ランドリーリキッド（洗衣液）”，属于家居清洁辅助用品，并非服装或家纺成品。现有分类中没有专门的洗涤剂/清洁剂类，只能归入与服装配搭无直接关系、但在店铺体系内作为周边类目的“accessories”。accessories 在这里可理解为非服装本体的附属/周边用品，最符合此类洗衣液产品的归类。', 1, 0, 0, 0, 'accessories', NULL, '', 0, NULL, 0, NULL, NULL, '01', 'ユーカリ(01)', 0);
