INSERT INTO `clothing_info` VALUES (19996476, '木版印花方巾 / chahat', 'Block Print Bandana / chahat', 0, 200332, 'TODAY’S SPECIAL', '', '', '既可以用来包裹便当盒，也可以当作手帕使用。\n\n印度的木版印花是一种类似版画的工艺，用木制印版将颜色一层层盖印在布面上。根据图案设计选择不同硬度的木材制作印版，再按颜色逐层套印。因为是木版，哪怕是直线也会有细微的摇曳感。\n\n同一款图案，每一块布的印花表情也会略有不同，这正是木版印花让人着迷、充满魅力的所在。\n\n原产国：印度。', '<!--ーーー--><br><b>お弁当箱を包むのにも、ハンカチにも。</b><br><br>インドのブロックプリントは、版画のように木版(ブロック)を使って色を布の上に重ねていくプリント技術です。<br>デザインのよって固さの違う木を使い分けで版を作り、色ごとに版を重ねていきます。<br>木版なので、直線でも微妙にその線が揺らいでいます。<br><br>同じデザインなのに少しずつ表情の違うプリント。<br>それがブロックプリントのの愛おしくてたまらないところです。<br><br><br>原産国 : インド<!--ーーー--><br><br>※ブロックプリントはプリントがずれていたり、掠れていたりするのが特徴です。<br>※色落ちすることがありますので念のために他のものとは分けて洗ってください。ご使用前の水通しをおすすめします。<br><br><b>\"タオル・ハンカチ\"アイテム一覧はこちら</b><br><a href=\"https://www.dot-st.com/todaysspecial/disp/itemlist/?dispNo=002005307\" target=\"_blank\"><font size=\"2\" color=\"blue\">ブラウザでみる</a></font></b> | <a href=\"adastriaapp://items?dispNo=0000100084_002005307&orderBy=00\" target=\"_blank\"><font size=\"2\" color=\"blue\">アプリでみる</a></font></b><br><br>', '1200.0 JPY', 73.20, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:32:27', '2026-04-02 04:15:26', 'adastria_786051', '', '69cd72d4a7ab618f2967c9b4', '生活/休闲', '', '通用', '青年（18-44岁）', '棉100%', 'https://www.dot-st.com/todaysspecial/disp/item/786051/?COLOR_CD=13', '其他服饰/物品', '其他', '配件', '', 'accessories', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/today’s_special/20260401/item_786051_main_18_1774847857_b.jpg', 0, 0, 8, 0.47746, 0, 1, 1, 0, 0, 3, NULL, '擦拭吸水，多用途包裹与装饰', '擦拭吸水,多用途包裹与装饰', '', '采用印度传统木版块印花工艺，每色单独对版压印,每条手工印花略有错位和擦痕，形成独特表情与手作感,可作为便当包布、手帕、随身小方巾等多功能使用,产地为印度，强调手工工艺文化属性', '花卉图案', '从商品名称“Block Print Bandana / chahat”和说明中“お弁当箱を包むのにも、ハンカチにも”可知，该产品是用于包裹便当、当手帕的小方巾/头巾类小布物，属于穿戴或随身携带的小配件，而非服装主体或家纺（不是床品、毛巾浴巾、窗帘、地毯等）。在给定的子类列表中，与手帕/头巾最接近的是“accessories”，即各类服饰小配件类别，因此将其归为 sub_category: accessories。', 1, 19, 0, 0, 'accessories', NULL, '', 0, NULL, 0, NULL, NULL, '18', '18(18)', 0);
