INSERT INTO `clothing_info` VALUES (19996451, '【NEW ERA】9TWENTY 棒球帽', '【NEWERA】RA9TWENTY', 0, 31749822, 'repipi armario', '', '', '轻盈的佩戴感是9TWENTY系列的特点，男女皆宜的百搭轮廓设计。既可以融入休闲穿搭，也能作为甜美风格中的反差单品使用，是适合日常使用的高频率佩戴帽款。', 'ーーー<br>ライトな被り心地が特徴の9TWENTY。<br>男女問わず着用しやすいシルエット。<br>カジュアルスタイルにも甘めスタイルの外しアイテムとしても使える<br>デイリー使いにピッタリなヘビロテキャップです◎<br>ーーー', '4200.0 JPY', 256.20, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:32:28', '2026-04-02 04:15:04', 'adastria_652145', '', '69cd72d4a7ab618f2967c9ae', '生活/休闲', '', '通用', '青年（18-44岁）', '棉100%', 'https://www.dot-st.com/repipiarmario/disp/item/652145/?COLOR_CD=09', '配饰', '帽子', NULL, '', 'baseball cap', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/repipi_armario/20260401/item_652145_main_09_1774846268_b.jpg', 0, 0, 9, 0.98258, 0, 1, 0, 0, 0, 3, NULL, '日常搭配，遮挡阳光，提升造型感', '日常搭配,遮挡阳光,提升造型感', '', '男女皆宜的中性版型,轻盈佩戴感,适合日常高频使用,休闲与甜美风格都可搭配,前片有立体LOGO刺绣,水洗旧化色感提升时尚度', '品牌标识，纯色', '该产品为NEW ERA棒球帽9TWENTY款，具有弯檐、前片有立体刺绣LOGO、整体为休闲运动风格，属于典型的棒球帽形态。根据列表中“baseball cap（棒球帽）”的定义——前带帽檐、用于日常及运动搭配的帽类配饰，与本品完全匹配，因此选择 sub_category: baseball cap。', 1, 0, 0, 0, 'baseball cap', NULL, '', 0, NULL, 0, NULL, NULL, '09', 'Acidブラック09', 0);
