INSERT INTO `clothing_info` VALUES (19996455, '【预售】冷感无袖针织长款连衣裙', '【先行予約】冷感タンクニットワンピース', 0, 200167, 'Elura', '', '', '———\n夏日也能保持舒适的清凉感针织连衣裙。\n\n【针对身形烦恼的优点】\n顺直垂坠的I型轮廓，可以让全身线条显得更加修长利落。简约设计，搭配夹克即可用于通勤等正式场合。领口开口不深，能更好地衬托颈部与锁骨线条。采用具有接触冷感功能的面料，夏天穿着也清爽舒适。另外为可在家水洗的材质，适合日常高频穿着。\n\n【MATERIAL & FUNCTION】\n质感：略带干爽触感的精致高针距针织，呈现优雅光泽和垂感。\n素材：人造丝61%、尼龙39%。\n功能：接触冷感。\n\n【造型搭配】\n正式风格：叠搭夹克，营造带有品位的通勤风造型。\n休闲风格：外搭同素材马甲，打造利落大人的度假休闲风。', 'ーーー<br><font size=\"3\"color=\"#c82c55\"><b>夏も快適に。涼感ニットワンピース</b></font><br><br>【悩みに“効く”ポイント】<br>ストンと落ちたIラインシルエットが、全身をすっきり見せてくれます。<br>シンプルなデザインなので、ジャケットを合わせればお仕事シーンも活躍。<br>深すぎない襟ぐりがデコルテを美しく見せてくれます。<br>接触冷感機能が付いているので、夏も涼しく快適に使えます。<br>自宅で洗える素材なので、毎日の着回しもMust-Buyな一着。<br><br>◆<a href=\"https://www.dot-st.com/elura/disp/item/664875\"><b><font size=\"2\" color=\"blue\">同素材のジレはこちら</a></font></b><br><br>【MATERIAL & FUNCTION】<br>質感：シャリ感のある、上品なハイゲージニット<br>素材：レーヨン 61%、ナイロン 39%<br>機能：接触冷感<br>ーーー<br>【スタイリング】<br>キレイ目：ジャケットを合わせて、品格漂うお仕事スタイルに♪<br>カジュアル：同素材のジレを羽織り、こなれた大人のリゾートスタイルに。<br><br>【商品の取り扱いについて】<br>洗濯：家庭用洗濯機（ネット使用）平干しでのお手入れを推奨。<br>ケア：ニットの伸びを防ぐため、ハンガーではなく平干し保管が安心。<br><br>【気になる商品は「お気に入り」登録を】<br>&#9825;ハートマークをクリックし、お気に入りに登録すると<br>在庫残り僅かや再入荷通知などの情報を受け取ることができます。', '8000.0 JPY', 488.00, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:32:28', '2026-04-02 04:15:08', 'adastria_664890', '', '69cd72d4a7ab618f2967c9b1', '生活/休闲，差旅/商务', '', '女', '青年（18-44岁）', '粘胶61%,锦纶39%', 'https://www.dot-st.com/elura/disp/item/664890/?COLOR_CD=50', '裙装', '连衣裙', '长裙', '', 'maxi dress', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/elura/20260401/item_664890_main_50_1773713982_b.jpg', 0, 0, 2, 0.98174, 0, 1, 1, 0, 0, 3, NULL, '接触冷感，透气，高弹力', '透气,高弹力', '接触冷感功能纱线/整理', '无袖坦克式设计，I字直筒廓形修饰身形,高针距精致针织，垂坠感好，适合夏季通勤与休闲,领口开口不深，突出颈部与锁骨线条,可机洗材质，方便日常打理,可与同素材马甲/吉莱成套穿着，增强搭配性', '纯色', '从图片和描述来看，这是一款无袖的长款连衣裙，长度到脚踝附近，呈I字直筒廓形，产品名中“ニットワンピース”表明是针织连衣裙且为夏季冷感款。与列表中“maxi dress”（及踝或拖地长度连衣裙）最吻合，因此选择 sub_category: maxi dress。其定义为：长度在小腿下部至脚踝、整体为一件式的长款连衣裙。', 1, 0, 0, 0, 'maxi dress', NULL, '', 0, NULL, 0, NULL, NULL, '50', 'グレージュ50', 0);
INSERT INTO `clothing_info` VALUES (19996456, '【预售】冷感无袖针织长款连衣裙', '【先行予約】冷感タンクニットワンピース', 0, 200167, 'Elura', '', '', '———\n夏日也能保持舒适的清凉感针织连衣裙。\n\n【针对身形烦恼的优点】\n顺直垂坠的I型轮廓，可以让全身线条显得更加修长利落。简约设计，搭配夹克即可用于通勤等正式场合。领口开口不深，能更好地衬托颈部与锁骨线条。采用具有接触冷感功能的面料，夏天穿着也清爽舒适。另外为可在家水洗的材质，适合日常高频穿着。\n\n【MATERIAL & FUNCTION】\n质感：略带干爽触感的精致高针距针织，呈现优雅光泽和垂感。\n素材：人造丝61%、尼龙39%。\n功能：接触冷感。\n\n【造型搭配】\n正式风格：叠搭夹克，营造带有品位的通勤风造型。\n休闲风格：外搭同素材马甲，打造利落大人的度假休闲风。', 'ーーー<br><font size=\"3\"color=\"#c82c55\"><b>夏も快適に。涼感ニットワンピース</b></font><br><br>【悩みに“効く”ポイント】<br>ストンと落ちたIラインシルエットが、全身をすっきり見せてくれます。<br>シンプルなデザインなので、ジャケットを合わせればお仕事シーンも活躍。<br>深すぎない襟ぐりがデコルテを美しく見せてくれます。<br>接触冷感機能が付いているので、夏も涼しく快適に使えます。<br>自宅で洗える素材なので、毎日の着回しもMust-Buyな一着。<br><br>◆<a href=\"https://www.dot-st.com/elura/disp/item/664875\"><b><font size=\"2\" color=\"blue\">同素材のジレはこちら</a></font></b><br><br>【MATERIAL & FUNCTION】<br>質感：シャリ感のある、上品なハイゲージニット<br>素材：レーヨン 61%、ナイロン 39%<br>機能：接触冷感<br>ーーー<br>【スタイリング】<br>キレイ目：ジャケットを合わせて、品格漂うお仕事スタイルに♪<br>カジュアル：同素材のジレを羽織り、こなれた大人のリゾートスタイルに。<br><br>【商品の取り扱いについて】<br>洗濯：家庭用洗濯機（ネット使用）平干しでのお手入れを推奨。<br>ケア：ニットの伸びを防ぐため、ハンガーではなく平干し保管が安心。<br><br>【気になる商品は「お気に入り」登録を】<br>&#9825;ハートマークをクリックし、お気に入りに登録すると<br>在庫残り僅かや再入荷通知などの情報を受け取ることができます。', '8000.0 JPY', 488.00, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:32:28', '2026-04-02 04:15:09', 'adastria_664890', '', '69cd72d4a7ab618f2967c9b1', '生活/休闲，差旅/商务', '', '女', '青年（18-44岁）', '粘胶61%,锦纶39%', 'https://www.dot-st.com/elura/disp/item/664890/?COLOR_CD=50', '裙装', '连衣裙', '长裙', '', 'maxi dress', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/elura/20260401/item_664890_main_09_1773713980_b.jpg', 0, 0, 6, 0.98118, 0, 1, 1, 0, 0, 3, NULL, '接触冷感，透气，高弹力', '透气,高弹力', '接触冷感功能纱线/整理', '无袖坦克式设计，I字直筒廓形修饰身形,高针距精致针织，垂坠感好，适合夏季通勤与休闲,领口开口不深，突出颈部与锁骨线条,可机洗材质，方便日常打理,可与同素材马甲/吉莱成套穿着，增强搭配性', '纯色', '从图片和描述来看，这是一款无袖的长款连衣裙，长度到脚踝附近，呈I字直筒廓形，产品名中“ニットワンピース”表明是针织连衣裙且为夏季冷感款。与列表中“maxi dress”（及踝或拖地长度连衣裙）最吻合，因此选择 sub_category: maxi dress。其定义为：长度在小腿下部至脚踝、整体为一件式的长款连衣裙。', 1, 1, 0, 0, 'maxi dress', NULL, '', 0, NULL, 0, NULL, NULL, '09', 'ブラック09', 0);
INSERT INTO `clothing_info` VALUES (19996448, 'minna de mirai wo 洗颜洁面粉S 体验装小袋（约5次用量）', 'みんなでみらいを 洗顔クレンジングパウダーS お試しパウチ(約5回分)', 0, 31749754, 'mood is me', '', '', '以縄文昆布带来滋润细腻肌肤。富含美容成分的縄文昆布（保湿成分：ガゴメ）和米糠来源的肌肤调理成分肌醇（保湿成分：イノシトール）相结合，使洗颜洁面粉S相比以往产品更具滋润感，令肌肤柔软细滑。\n使用方法：将适量粉末（约一小勺）倒在手心，加少量清水用指尖调和成糊状后在脸部轻柔清洁，再冲洗干净。如需丰富泡沫，可配合起泡网使用。', '<u>縄文昆布でしっとりなめらか肌に。</u><br><br>美容成分のフコイダンを多く含む縄文昆布※1と米ぬか由来のイノシトール※2を配合した洗顔クレンジングパウダーSはこれまで※3よりもしっとりお肌に。<br>※1ガゴメ(保湿成分)/※2イノシトール(保湿成分)/※3当社従来品比<br><br><u>【使用方法】</u><br>手に粉を適量(小さじ程度)と水を少し加えて指でなじませてペースト状にする。<br>※泡立てる場合は泡立ちネットが便利です。<br><br><u>【内容量】</u><br>5g(約5回分)', '250.0 JPY', 15.25, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:33:10', '2026-04-02 04:15:02', 'adastria_782931', '', '69cd72d3a7ab618f2967c99b', '生活/休闲', '', '通用', '青年（18-44岁）', NULL, 'https://www.dot-st.com/moodisme/disp/item/782931/?COLOR_CD=00', '其他服饰/物品', '其他', '配件', '', 'accessories', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/mood_is_me/20260401/item_782931_main_00_1774598266_b.jpg', 0, 0, 9, 0.99127, 0, 1, 1, 0, 0, 3, NULL, '环保可降解，清洁肌肤，保湿，温和洁面，卸妆功能，角质护理', '清洁肌肤,保湿,温和洁面,卸妆功能,角质护理', '发酵成分应用', '粉末状洁面产品，可与水调和成糊状使用,含富含美容成分的縄文昆布及米糠来源成分,试用装小包装设计，便于携带与体验', '纯色', '商品为“洗顔クレンジングパウダー”（洗面清洁粉），属于日化/个护类产品，并非服装或家纺。给定分类列表中没有专门针对护肤品或化妆品的类别，只能选择一个非服装主体类别。综合考虑，“accessories（配件/杂项）”可作为最接近的归类，用来容纳此类与服装不同的大类商品。此处的 accessories 可理解为：非服装主体、用作搭配或辅助个人形象与使用体验的周边用品。', 0, 0, 0, 0, 'accessories', NULL, '', 0, NULL, 0, NULL, NULL, '00', 'ナシ(00)', 0);
INSERT INTO `clothing_info` VALUES (19996449, 'minnade miraiwo 洗颜卸妆粉S（补充装）', 'みんなでみらいを　洗顔クレンジングパウダーS(詰め替え用)', 0, 31749754, 'mood is me', '', '', '以“绳文昆布”打造水润细腻肌肤。富含美容成分褐藻糖胶的绳文昆布※1与源自米糠的肌醇※2复配，使洗颜卸妆粉S相比以往产品※3令肌肤更加水润柔滑。\n※1 ガゴメ（保湿成分）／※2 肌醇（保湿成分）／※3 与本公司以往产品相比\n\n使用方法：\n取适量粉末（约一小匙）置于手心，加少量清水，用指尖调和至糊状后轻柔清洗面部。若需要泡沫，可配合起泡网使用。', '<u>縄文昆布でしっとりなめらか肌に。</u><br><br>美容成分のフコイダンを多く含む縄文昆布※1と米ぬか由来のイノシトール※2を配合した洗顔クレンジングパウダーSはこれまで※3よりもしっとりお肌に。<br>※1ガゴメ(保湿成分)/※2イノシトール(保湿成分)/※3当社従来品比<br><br><u>【使用方法】</u><br>手に粉を適量(小さじ程度)と水を少し加えて指でなじませてペースト状にする。<br>※泡立てる場合は泡立ちネットが便利です。<br><br><u>【内容量】</u><br>70g(詰め替え用)', '2200.0 JPY', 134.20, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:33:10', '2026-04-02 04:15:03', 'adastria_782930', '', '69cd72d3a7ab618f2967c9a4', '', '', '通用', '青年（18-44岁）', NULL, 'https://www.dot-st.com/moodisme/disp/item/782930/?COLOR_CD=00', '其他服饰/物品', '其他', '配件', '', 'accessories', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/mood_is_me/20260401/item_782930_main_00_1774511756_b.jpg', 0, 0, 9, 0.97526, 0, 1, 0, 0, 0, 3, NULL, '保湿，清洁肌肤，温和洗卸，滋润肌肤', '保湿,清洁肌肤,温和洗卸,滋润肌肤', '发酵技术,美容成分添加', '为洗脸与卸妆双用的洁面粉形态产品,添加富含褐藻糖胶的“縄文昆布”成分，强调保湿与润泽效果,添加米糠来源的肌肤调理成分肌醇，提升洗后柔软度,为粉末状产品，使用时以少量水调和成糊状使用,为补充装规格，便于环保与反复续用', '纯色', '商品为“洗顔クレンジングパウダー（洁面卸妆粉）”补充装，属于化妆品/美容用品范畴，而非服装或家纺类产品。在提供的类别中没有专门的美容仪或化妆品选项，只能归入与服装无直接关联、最为笼统的“accessories（配件）”类。此处将“accessories”理解为非服装主体的附属类产品，是当前列表中最接近的定义。', 0, 0, 0, 0, 'accessories', NULL, '', 0, NULL, 0, NULL, NULL, '00', 'ナシ(00)', 0);
INSERT INTO `clothing_info` VALUES (19996450, '大家的未来 洗颜卸妆洁面粉 S', 'みんなでみらいを　洗顔クレンジングパウダーS', 0, 31749754, 'mood is me', '', '', '以縄文昆布带来水润细腻肌肤。富含美容成分岩藻多糖的縄文昆布与米糠来源的肌醇配合，使这款洗颜卸妆洁面粉相比以往产品更具滋润感。\n\n用法：取适量粉末于手中，加入少量清水，用指尖调和成糊状后用于清洁肌肤。也可配合起泡网使用以获得丰富泡沫。\n\n内容量：70g', '<u>縄文昆布でしっとりなめらか肌に。</u><br><br>美容成分のフコイダンを多く含む縄文昆布※1と米ぬか由来のイノシトール※2を配合した洗顔クレンジングパウダーSはこれまで※3よりもしっとりお肌に。<br>※1ガゴメ(保湿成分)/※2イノシトール(保湿成分)/※3当社従来品比<br><br><u>【使用方法】</u><br>手に粉を適量(小さじ程度)と水を少し加えて指でなじませてペースト状にする。<br>※泡立てる場合は泡立ちネットが便利です。<br><br><u>【内容量】</u><br>70g', '2500.0 JPY', 152.50, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:33:10', '2026-04-02 04:15:03', 'adastria_782883', '', '69cd72d4a7ab618f2967c9af', '', '', '通用', '青年（18-44岁）', NULL, 'https://www.dot-st.com/moodisme/disp/item/782883/?COLOR_CD=00', '其他服饰/物品', '其他', '配件', '', 'accessories', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/mood_is_me/20260401/item_782883_main_00_1774511116_b.jpg', 0, 0, 9, 0.57831, 0, 1, 0, 0, 0, 3, NULL, '温和清洁，保湿滋润，洁面卸妆二合一，帮助调理肌肤状态', '温和清洁,保湿滋润,洁面卸妆二合一,帮助调理肌肤状态', '发酵护肤成分应用', '使用含丰富岩藻多糖的縄文昆布成分,添加米糠来源的肌肤调理成分肌醇,添加小麦麸皮等植物来源成分,粉末状设计，可与水调和成糊状使用,可配合起泡网使用形成泡沫,偏重保湿感受，洗后肤感更柔软', '纯色', '该商品是粉末状洁面卸妆产品，并非服装或家纺类纺织品。在提供的子类列表中没有“化妆品/洗面奶”等对应选项，只能在非服装功能性最弱相关的类别中选择“accessories（配件）”。在本任务体系下，将其归入 accessories（配件类的笼统归类）最为合适。', 0, 0, 0, 0, 'accessories', NULL, '', 0, NULL, 0, NULL, NULL, '00', 'ナシ(00)', 0);
INSERT INTO `clothing_info` VALUES (19996446, '大家的未来 米糠酵素洗颜卸妆粉（补充装）', 'みんなでみらいを 米ぬか酵素洗顔クレンジング(詰め替え用)', 0, 31749754, 'mood is me', '', '', '令肌肤水润光滑的无添加米糠酵素洗颜卸妆产品。无需二次清洁，卸妆与洗脸一步完成，即使是防水型彩妆也能轻松卸除。能帮助去除毛孔污垢和角栓，洗后肌肤触感细腻柔滑。使用起泡网可打出丰盈泡沫。洗净后排水中的成分可被有益微生物分解，不仅呵护肌肤，也兼顾河流与自然环境。', 'しっとりスベスベお肌に。無添加の米ぬか酵素洗顔クレンジング。<br>Ｗ洗顔不要でクレンジングと洗顔が一度にでき、なんとウォータープルーフのメイクでも簡単にオフ出来ます。<br>毛穴の汚れや角栓もキレイになって、洗い上がりはしっとりスベスベ肌に。<br>泡立ちネットを使えばモコモコ泡立ちます。そして洗い流した排水は有益な微生物が分解してくれるので、お肌をキレイにするだけではなく、川や自然にも配慮した製品です。<br><br><u>【使用方法】</u><br>手に粉を適量(小さじ程度)と水を少し加えて指でなじませてペースト状にする。<br>※泡立てる場合は泡立ちネットが便利です。<br><br><u>【内容量】</u><br>70g(詰め替え)', '1800.0 JPY', 109.80, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:33:11', '2026-04-02 04:15:00', 'adastria_782933', '', '69cd72d3a7ab618f2967c990', '生活/休闲', '', '通用', '青年（18-44岁）', NULL, 'https://www.dot-st.com/moodisme/disp/item/782933/?COLOR_CD=00', '其他服饰/物品', '其他', '配件', '', 'accessories', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/mood_is_me/20260401/item_782933_main_00_1774494337_b.jpg', 0, 0, 9, 0.98971, 0, -1, 0, 0, 0, 3, NULL, '清洁肌肤，卸妆，温和去角质，细致毛孔，滋润保湿感', '清洁肌肤,卸妆,温和去角质,细致毛孔,滋润保湿感', '酵素洁面技术,发酵护肤成分', '无添加配方，更温和亲肤,可卸除防水型彩妆,粉末状，加水后可调成糊状使用,使用起泡网可形成丰富泡沫,排水中成分可被有益微生物分解，更加环保,采用米糠与小麦麸皮等天然来源成分', '纯色', '商品是“米ぬか酵素洗顔クレンジング(詰め替え用)”洁面卸妆粉，属于美容日化用品，并非服装或家用纺织品。在提供的子类列表中没有专门针对化妆品/洗面奶的分类，只能选择与服装无关、最不容易引起误解的广义类目。综合来看，选用“accessories”作为兜底分类最合适。这里的“accessories”理解为非服装主体的附属品/其他类产品。', 0, 0, 0, 0, 'accessories', NULL, '', 0, NULL, 0, NULL, NULL, '00', 'ナシ(00)', 0);
INSERT INTO `clothing_info` VALUES (19996447, 'みんなでみらいを 米糠酵素洗颜卸妆粉', 'みんなでみらいを 米ぬか酵素洗顔クレンジング', 0, 31749754, 'mood is me', '', '', '让肌肤水润细腻的无添加米糠酵素洗颜卸妆粉。无需二次清洁，可同时完成卸妆和洗脸，连防水型彩妆也能轻松卸除。能清洁毛孔污垢和角栓，洗后肌肤水润光滑。使用起泡网可打出丰富泡沫。排水中的成分可被有益微生物分解，不仅呵护肌肤，也兼顾河流与自然环境。使用时，将适量粉末与少量清水在手中调和成糊状后洁面，如需泡沫可配合起泡网。', '<u>しっとりスベスベお肌に。無添加の米ぬか酵素洗顔クレンジング。</u><br><br>Ｗ洗顔不要でクレンジングと洗顔が一度にでき、なんとウォータープルーフのメイクでも簡単にオフ出来ます。<br>毛穴の汚れや角栓もキレイになって、洗い上がりはしっとりスベスベ肌に。<br>泡立ちネットを使えばモコモコ泡立ちます。そして洗い流した排水は有益な微生物が分解してくれるので、お肌をキレイにするだけではなく、川や自然にも配慮した製品です。<br><br><u>【使用方法】</u><br>手に粉を適量(小さじ程度)と水を少し加えて指でなじませてペースト状にする。<br>※泡立てる場合は泡立ちネットが便利です。<br><br><u>【内容量】</u><br>70g', '2100.0 JPY', 128.10, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:33:11', '2026-04-02 04:15:01', 'adastria_782932', '', '69cd72d3a7ab618f2967c997', '生活/休闲', '', '通用', '青年（18-44岁）', NULL, 'https://www.dot-st.com/moodisme/disp/item/782932/?COLOR_CD=00', '其他服饰/物品', '其他', '配件', '', 'accessories', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/mood_is_me/20260401/item_782932_main_00_1774493126_b.jpg', 0, 0, 9, 0.99553, 0, 1, 0, 0, 0, 3, NULL, '清洁卸妆，洗脸洁面，去除毛孔污垢，去角栓，保湿滋润', '清洁卸妆,洗脸洁面,去除毛孔污垢,去角栓,保湿滋润', '酵素洁面技术,发酵护肤成分', '无添加配方，温和亲肤,米糠与小麦麸为主要来源的粉末形态,可卸除防水型彩妆,使用后肌肤有滋润光滑的触感,排水可被有益微生物分解，环保友好', '纯色，纯色', '该商品是“米ぬか酵素洗顔クレンジング”粉状洁面卸妆产品，属于化妆品/美容用品而非服装或家纺。给定子类列表中没有专门的化妆品类别，只能归入非服装配饰类的兜底分类“accessories”。在本任务框架下，“accessories”可被理解为与穿着搭配或个人护理相关的附属品，其最贴近此类美妆品的广义定义：个人形象与护理相关的小物或用品。', 0, 0, 0, 0, 'accessories', NULL, '', 0, NULL, 0, NULL, NULL, '00', 'ナシ(00)', 0);
INSERT INTO `clothing_info` VALUES (19996444, 'みんなでみらいを 米糠油精华液', 'みんなでみらいを　米ぬかオイルセラム', 0, 31749754, 'mood is me', '', '', '天然源自大米的养肤精华，以水层保湿与油层锁水的双层结构，为角质层深处补充水分并形成保护膜。富含米胚芽油（润肤成分），温和包裹肌肤，防止水分蒸发，令肌肤柔软细腻并持续滋润。添加的谷维素（肌肤调理成分）帮助维持肌肤健康状态，平衡肌肤水分，令肤感柔润舒适。可在使用洗面产品和化妆水后，摇匀取适量轻柔涂抹于面部，再以双手按压帮助吸收；也可在洗脸后作为前导精华使用，帮助后续保养更好吸收。', '<u>天然由来の米の恵み。2層ケアでやさしく輝く肌へ。</u><br><br>水層のうるおい × 油層のヴェール、2つの層で、角質層のすみずみまで保湿。<br>コメ胚芽油※1（エモリエント成分）が肌をやさしく包み込み、水分の蒸発を防ぎながら、しっとりとした柔らかさをキープし、うるおいを与えます。<br>オリザノール※2（整肌成分）が肌をすこやかに整える。<br>水分バランスをサポートし、肌に優しく、しっとりとした肌に整えてくれます。<br><br><u>【使用方法】</u><br>＜使い方１＞<br>米ぬかシリーズで洗顔と化粧水の後に、振って適量を手に取り、顔に優しくなじませてからハンドプレスで肌に浸透させます。<br><br>＜使い方２＞<br>米ぬかシリーズで洗顔した後、ブースターとして使用。振って適量を手に取り、顔に優しくなじませてからハンドプレスで肌に浸透させます。', '3500.0 JPY', 213.50, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:33:12', '2026-04-02 04:14:58', 'adastria_782954', '', '69cd72d3a7ab618f2967c98f', '生活/休闲', '', '通用', '青年（18-44岁）', NULL, 'https://www.dot-st.com/moodisme/disp/item/782954/?COLOR_CD=00', '其他服饰/物品', '其他', '配件', '', 'accessories', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/mood_is_me/20260401/item_782954_main_00_1774504932_b.jpg', 0, 0, 9, 0.99603, 0, 1, 0, 0, 0, 3, NULL, '保湿滋润，柔软肌肤，调理肌肤状态，平衡水油，舒缓肌肤', '保湿滋润,柔软肌肤,调理肌肤状态,平衡水油,舒缓肌肤', '双层水油配方,添加神经酰胺衍生物,天然植物精油复配', '主打米糠与米胚芽油的天然来源概念,水油双层设计，使用前需摇匀,含有调理肌肤的米糠相关成分和酒粕提取物,加入多种精油，具有一定芳香护理体验,强调温和、适合敏感肌的保湿护理', '纯色，纯色', '商品为“米ぬかオイルセラム”面部精华油，属于护肤品/美容品，并非服装或家纺类实物，只能在当前可选列表中选择最接近的“accessories”。在本任务服装/家纺导向的分类体系下，没有专门的“cosmetics”类目，因此将其视作搭配型非服装主品的附属品，归入“accessories”（配饰/附属品）这一最合适的残差类别。Definition：accessories——非主体服装的附属类产品，包含无法归入其它服装或家纺子类但与个人使用相关的小物品。', 0, 0, 0, 0, 'accessories', NULL, '', 0, NULL, 0, NULL, NULL, '00', 'ナシ(00)', 0);
INSERT INTO `clothing_info` VALUES (19996445, 'みんなでみらいを 粘土洗颜卸妆', 'みんなでみらいを クレイ洗顔クレンジング', 0, 31749754, 'mood is me', '', '', '含有保湿成分高岭土，质地更加细腻，带来温和肤感的粉末洗颜卸妆产品。在维持肌肤水润的同时，也能有效卸除妆容和日常污垢。使用时取适量粉末加少量水调和成糊状后清洁面部。', 'カオリン(保湿成分)配合でより優しく！粒子も細かく、肌あたり優しい洗顔クレンジング。<br>うるおいを保ちながら、しっかりメイクもオフ。<br><br><u>【使用方法】</u><br>手に粉を適量(小さじ程度)と水を少し加えて指でなじませてペースト状にする。※泡立てる場合は泡立ちネットが便利です。<br><br><u>【内容量】</u><br>70g', '2500.0 JPY', 152.50, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:33:12', '2026-04-02 04:14:59', 'adastria_782950', '', '69cd72d3a7ab618f2967c991', '生活/休闲', '', '通用', '青年（18-44岁）', NULL, 'https://www.dot-st.com/moodisme/disp/item/782950/?COLOR_CD=00', '其他服饰/物品', '其他', '配件', '', 'accessories', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/mood_is_me/20260401/item_782950_main_00_1774501357_b.jpg', 0, 0, 9, 0.98893, 0, 1, 0, 0, 0, 3, NULL, '温和清洁，卸妆，保湿滋润，去除污垢和老废角质，呵护敏感肌肤，支持环保理念', '温和清洁,卸妆,保湿滋润,去除污垢和老废角质,呵护敏感肌肤,支持环保理念', '发酵技术应用于护肤成分', '粉末状配方，使用时加水调和成糊状,添加高岭土帮助吸附污垢，同时保持肌肤水润,颗粒细腻，减少对皮肤的摩擦刺激,添加米糠、米胚芽等来源的成分，强调天然感,不属于传统纺织品或服饰类产品，为粉末型洗颜卸妆产品', '其他', '该产品实际为粉末状的“洗脸卸妆产品”，属于护肤清洁类，并非服装或家纺。给定枚举中没有“化妆品/护肤品”相关选项，只能选择与服饰无关、最接近“非服装附属品”的类别，因此选择了“accessories（配件）”。在本任务框架下，accessories 被作为一个兜底类目，用于无法归入服装、家纺的其他产品。', 0, 0, 0, 0, 'accessories', NULL, '', 0, NULL, 0, NULL, NULL, '00', 'ナシ(00)', 0);
INSERT INTO `clothing_info` VALUES (19996443, 'みんなでみらいを 米糠酵素洗颜卸妆 体验装小袋（约5次用量）', 'みんなでみらいを 米ぬか酵素洗顔クレンジング お試しパウチ(約5回分)', 0, 31749754, 'mood is me', '', '', '让肌肤水润光滑的无添加米糠酵素洗颜卸妆产品。无需二次洁面，卸妆与洗脸一次完成，连防水型彩妆也能轻松去除。能清洁毛孔污垢和角栓，洗后肌肤柔润细滑。使用起泡网可打出丰富泡沫。洗净后排出的水分可被有益微生物分解，不仅令肌肤洁净，也兼顾河流和自然环境。使用时将适量粉末置于手心，加少量清水调和成糊状后清洁肌肤，也可搭配起泡网使用。净含量5g，约可使用5次。', '<u>しっとりスベスベお肌に。無添加の米ぬか酵素洗顔クレンジング。</u><br><br>Ｗ洗顔不要でクレンジングと洗顔が一度にでき、なんとウォータープルーフのメイクでも簡単にオフ出来ます。<br>毛穴の汚れや角栓もキレイになって、洗い上がりはしっとりスベスベ肌に。<br>泡立ちネットを使えばモコモコ泡立ちます。そして洗い流した排水は有益な微生物が分解してくれるので、お肌をキレイにするだけではなく、川や自然にも配慮した製品です。<br><br><u>【使用方法】</u><br>手に粉を適量(小さじ程度)と水を少し加えて指でなじませてペースト状にする。<br>※泡立てる場合は泡立ちネットが便利です。<br><br><u>【内容量】</u><br>5g(約5回分)', '200.0 JPY', 12.20, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:33:13', '2026-04-02 04:14:58', 'adastria_782948', '', '69cd72d3a7ab618f2967c98a', '生活/休闲', '', '通用', '青年（18-44岁）', NULL, 'https://www.dot-st.com/moodisme/disp/item/782948/?COLOR_CD=00', '其他服饰/物品', '其他', '配件', '', 'accessories', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/mood_is_me/20260401/item_782948_main_00_1774495123_b.jpg', 0, 0, 9, 0.99100, 0, 1, 0, 0, 0, 3, NULL, '温和清洁，卸妆，深层清洁毛孔，保湿滋润，以天然成分为主', '温和清洁,卸妆,深层清洁毛孔,保湿滋润,以天然成分为主', '酵素洁面技术,发酵护肤成分', '米糠、麦麸等植物来源成分配方,无添加配方，减少对皮肤负担,粉末状，加水调和成糊或打泡使用,可卸除防水型彩妆,排水可被有益微生物分解，更加环保,小包装试用装，约5次用量', '纯色，纯色', '商品为“米ぬか酵素洗顔クレンジング”洁面卸妆粉末，属于日化/美容产品，并非服装或家纺类纺织品。在给定的服装/家纺子类目中，没有专门针对护肤品的选项，只能选择最不冲突、与主体服装无直接矛盾的“accessories（配件）”作为技术性占位分类。这里的“accessories”理解为非服装主体的附属品。', 0, 0, 0, 0, 'accessories', NULL, '', 0, NULL, 0, NULL, NULL, '00', 'ナシ(00)', 0);
INSERT INTO `clothing_info` VALUES (19996441, '大家与未来 米糠护肤喷雾水', 'みんなでみらいを　米ぬかスキンケアローション', 0, 31749754, 'mood is me', '', '', '以大米的力量，激发肌肤本来的水润力的护肤喷雾水。\n以芦荟液汁（调理肌肤成分）为基底，加入米糠来源的肌醇（保湿成分）和稻糠甾醇（保湿成分）。\n细腻呵护干燥肌肤，令肌肤纹理细腻、柔滑水润。\n洗脸后喷洒于干燥的肌肤，质地清爽水感，使用感轻盈不黏腻。', '<u>お米の力で、肌本来のうるおいを引きだすスキンケアローション。</u><br><br>アロエベラ液汁(整肌成分)をベースに、米ぬか由来のイノシトール(保湿成分)とオリザノール(保湿成分)をプラス。<br>乾いた肌に寄り添い、キメの整ったしっとりなめらかな肌へと導くローション。<br>洗顔後の乾いた肌を包み込みます。さらさらタイプでみずみずしく、さっぱりとした使い心地。<br><br><u>【内容量】</u><br>100g', '2700.0 JPY', 164.70, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:33:14', '2026-04-02 04:14:56', 'adastria_782952', '', '69cd72d3a7ab618f2967c986', '生活/休闲', '', '通用', '青年（18-44岁）', NULL, 'https://www.dot-st.com/moodisme/disp/item/782952/?COLOR_CD=00', '其他服饰/物品', '其他', '配件', '', 'accessories', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/mood_is_me/20260401/item_782952_main_00_1774503871_b.jpg', 0, 0, 9, 0.99314, 0, 1, 0, 0, 0, 3, NULL, '保湿，滋润肌肤，调理肤质，舒缓干燥', '保湿,滋润肌肤,调理肤质,舒缓干燥', '', '以芦荟液汁为基底，突出温和保湿,添加米糠来源肌醇和稻糠甾醇，强化保湿与修护,使用米糠发酵提取物，具有发酵型护肤特色,质地清爽水润，使用感偏清爽不黏腻,主打通过“米的力量”激发肌肤自身保湿力的理念', '其他', '商品为“米ぬかスキンケアローション”，用途是护肤化妆水，属于非服装、非家纺类的美容护理产品。在给定分类中没有专门的护肤品/化妆品类目，只能归入与服饰无直接关系、泛用的“accessories”作为其他类目使用。这里的“accessories”理解为服装体系以外的附属品/杂项，是最接近的分类。', 0, 0, 0, 0, 'accessories', NULL, '', 0, NULL, 0, NULL, NULL, '00', 'ナシ(00)', 0);
INSERT INTO `clothing_info` VALUES (19996442, 'minna de mirai wo 粘土洗颜卸妆粉（补充装）', 'みんなでみらいを　クレイ洗顔クレンジング (詰め替え用)', 0, 31749754, 'mood is me', '', '', '添加具有保湿成分的高岭土，质地更加温和，粉质细腻，触肤柔和的洗颜卸妆产品。在保持肌肤水润的同时，也能有效卸除彩妆。\n\n使用方法：\n将适量粉末置于手心（约一小匙），加入少量清水，用指尖调和成糊状后清洁肌肤。如需起泡，可搭配起泡网使用。', 'カオリン(保湿成分)配合でより優しく！粒子も細かく、肌あたり優しい洗顔クレンジング。<br>うるおいを保ちながら、しっかりメイクもオフ。<br><br><u>【使用方法】</u><br>手に粉を適量(小さじ程度)と水を少し加えて指でなじませてペースト状にする。※泡立てる場合は泡立ちネットが便利です。<br><br><u>【内容量】</u><br>70g(詰め替え用）', '2200.0 JPY', 134.20, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:33:14', '2026-04-02 04:14:57', 'adastria_782951', '', '69cd72d3a7ab618f2967c988', '', '', '通用', '青年（18-44岁）', NULL, 'https://www.dot-st.com/moodisme/disp/item/782951/?COLOR_CD=00', '其他服饰/物品', '其他', '配件', '', 'accessories', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/mood_is_me/20260401/item_782951_main_00_1774502522_b.jpg', 0, 0, 9, 0.99253, 0, 1, 1, 0, 0, 3, NULL, '温和清洁，卸妆，保湿，滋润肌肤', '温和清洁,卸妆,保湿,滋润肌肤', '发酵技术', '粉末状形态，可加水调成糊状使用,可泡沫清洗，可搭配起泡网使用,为洗脸兼具卸妆功能的多效产品,为环保补充装包装形式', '纯色，纯色', '商品为“クレイ洗顔クレンジング(詰め替え用)”粉末状洁面卸妆产品，属于洗护类化妆品，并非服装或家纺类纺织品。给定子类列表中没有专门的美妆/护肤分类，只能选择与服装无直接对应关系、最为中性的“accessories”。在本任务语境下，将此类非服装类小物归入“accessories（配件/附属品）”最为合适。accessories 在此理解为：非服装主体、用于搭配或辅助使用的各类小物或附属品。', 0, 0, 0, 0, 'accessories', NULL, '', 0, NULL, 0, NULL, NULL, '00', 'ナシ(00)', 0);
INSERT INTO `clothing_info` VALUES (19996440, '玻璃杯 NASSER 240ml / ADERIA', 'タンブラー ナッセル 240ml / ADERIA', 0, 200332, 'TODAY’S SPECIAL', '', '', '采用适合日常使用的口部强化玻璃，耐用安心。内侧模具纹理让玻璃在光线下熠熠生辉，为餐桌增添华丽气氛。\n\nADERIA（アデリア）是以1819年创立的玻璃制造商石塚硝子为前身的品牌。创始人石塚岩三郎在长崎学习玻璃制造，归乡途中在现今岐阜县可児市一带开设玻璃店，由此起家。之后企业迁至名古屋，目前总部位于爱知县，从日用器皿到保存容器，持续推出多种玻璃制品。\n\n产地：日本', '<!--ーーー--><br>日常使いに最適な口部強化ガラスを採用。<br>内モールがガラスをキラキラ輝かせ、食卓を華やかに彩ります。<br><br><b>ADERIA(アデリア)</b><br>1819年創業のガラスメーカー石塚硝子が前身のアデリア。<br>創業者の石塚 岩三郎氏が長崎でガラス製造を学び、故郷の下総国への帰途の途中に立ち寄った土田村（現在の岐阜県可児市）でビードロ屋を開いたことに由来。<br>その後名古屋へ移転し、現在は愛知県に本社を置く。生活の器から、保存容器まで様々なガラス製品を生みだしています。<br><br><br>原産国 : 日本<!--ーーー--><br>容量 : 240ml<br>食洗機 〇<br><br><b>\"グラス\"アイテム一覧はこちら</b><br><a href=\"https://www.dot-st.com/todaysspecial/disp/itemlist/?dispNo=002005161\" target=\"_blank\"><font size=\"2\" color=\"blue\">ブラウザでみる</a></font></b> | <a href=\"adastriaapp://items?dispNo=0000100084_002005161&orderBy=00\" target=\"_blank\"><font size=\"2\" color=\"blue\">アプリでみる</a></font></b><br><br><br>---------------------------------<br>＜価格改定のお知らせ＞<br>2026/04/01より原材料の高騰により価格改定をさせて頂きます。<br>商品タグに記載している価格が旧価格のものが混在しておりますが、<br>現在はこちらの価格での販売となります。<br>ご了承下さいますよう、お願い申し上げます。<br>---------------------------------<br><br>', '545.0 JPY', 33.24, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:33:15', '2026-04-02 04:14:55', 'adastria_346215', '', '69cd72d3a7ab618f2967c97d', '生活/休闲', '', '通用', '青年（18-44岁）', 'ガラス100%', 'https://www.dot-st.com/todaysspecial/disp/item/346215/?COLOR_CD=00', '其他服饰/物品', '其他', '配件', '', 'accessories', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/today’s_special/20260401/item_346215_main_00_1739499179_b.jpg', 0, 0, 9, 0.76459, 0, 1, 0, 0, 0, 3, NULL, '可用于日常饮水，可用洗碗机清洗', '可用于日常饮水,可用洗碗机清洗', '', '采用口部强化玻璃，更加耐用安全,内侧模具纹理使玻璃在光线下呈现闪耀效果,日本制造,适合搭配餐桌增添装饰性', '纯色，纯色', '从商品名称和描述看，这是容量为240ml的玻璃“タンブラー”（水杯/玻璃杯），属于餐厨类小物，不是服装或家纺。提供的类别中没有专门的厨房器皿或杯具类目，只能归入最接近的通用类“accessories（配饰/小物）”。该子类在本任务体系中通常用作非服装、小件物品的兜底分类，因此选择“accessories”最为合适。', 0, 0, 0, 0, 'accessories', NULL, '', 0, NULL, 0, NULL, NULL, '00', 'タンブラー ナッセル 240ml (00)', 0);
INSERT INTO `clothing_info` VALUES (19996436, '可旋转蜂蜜勺 / leye', 'くるりとハチミツスプーン / leye', 0, 200332, 'TODAY’S SPECIAL', '', '', 'V字形勺头利用表面张力可舀取足量蜂蜜，轻轻旋转即可干净利落地切断蜂蜜，不易滴落。不锈钢一体结构，易于清洗并保持卫生。迷你尺寸，适合在小瓶等容器中使用。产地：日本（新潟县）。', '<!--ーーー--><br>V字の表面張力でたっぷりすくえ、くるりと回すだけでピタッとすっきり切れます。 	<br>ステンレス一体構造で洗いやすく清潔に保てます。<br>また小瓶などでも掬いやすいミニサイズです。<br><br>原産国 : 日本(新潟県)<br><!--ーーー--><br><br>レンジ×　オーブン×　食洗機〇<br><br><b>\"leye\"シリーズはこちら</b><br><a href=\"https://www.dot-st.com/todaysspecial/disp/itemlist/?dispNo=002005110\" target=\"_blank\"><b><font size=\"2\" color=\"blue\">ブラウザでみる</a></font></b> | <a href=\"adastriaapp://items?dispNo=0000100084_002005110&orderBy=00\" target=\"_blank\"><b><font size=\"2\" color=\"blue\">アプリでみる</a></font></b><br><br><b>\"キッチンツール\"シリーズはこちら</b><br><a href=\"https://www.dot-st.com/todaysspecial/disp/itemlist/?dispNo=002005230\" target=\"_blank\"><b><font size=\"2\" color=\"blue\">ブラウザでみる</a></font></b> | <a href=\"adastriaapp://items?dispNo=0000100084_002005230&orderBy=00\" target=\"_blank\"><b><font size=\"2\" color=\"blue\">アプリでみる</a></font></b><br>', '1000.0 JPY', 61.00, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:33:16', '2026-04-02 04:14:52', 'adastria_343038', '', '69cd72d3a7ab618f2967c96b', '生活/休闲', '', '通用', '青年（18-44岁）', 'ステンレス鋼(クロム18%)100%', 'https://www.dot-st.com/todaysspecial/disp/item/343038/?COLOR_CD=10', '其他服饰/物品', '其他', '配件', '', 'accessories', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/today’s_special/20260401/item_343038_main_10_1747877147_b.jpg', 0, 0, 9, 0.90682, 0, -1, 0, 0, 0, 3, NULL, '易清洗，便于舀取蜂蜜，减少滴落，适合小瓶口使用', '易清洗,便于舀取蜂蜜,减少滴落,适合小瓶口使用', '', 'V字形勺头利用表面张力便于舀取蜂蜜,旋转动作即可利落切断蜂蜜、不易滴落,不锈钢一体成型结构，减少缝隙更卫生,小巧尺寸方便伸入小瓶中使用,产地为日本新潟县', '纯色，纯色', '该产品是厨房用蜂蜜勺，属于非服装类的小工具配件，不归入任何服装、家纺主类目，只能使用列表中最接近的“accessories”。在本任务给定的类目中，“accessories”为泛指配件、附属小物的类别，定义可以理解为：不直接穿在身上的小型功能性或装饰性物件。蜂蜜勺正是此类日常配件用品，因此选择“accessories”。', 0, 0, 0, 0, 'accessories', NULL, '', 0, NULL, 0, NULL, NULL, '10', 'くるりとハチミツスプーン / leye(10)', 0);
INSERT INTO `clothing_info` VALUES (19996437, '可叠放玻璃杯 / Pasabahce', 'スタック カップ / Pasabahce', 0, 200332, 'TODAY’S SPECIAL', '', '', '来自土耳其最大玻璃制造商 Pasabahce（帕夏巴赫）的玻璃杯。造型简洁，易于使用和清洗，可相互叠放，适合每天反复使用。成套购入，用于日常餐桌与饮水场景。原产国：土耳其。容量约260ml，适用洗碗机。', '<!--ーーー--><br>トルコ最大のガラス産業Pasabahce(パシャバチェ)のグラス。<br>使いやすく洗いやすく、スタッキングができる、毎日繰り返し使うのにぴったりなグラスです。<br><br>まとめて揃えて、日常使いに。<br><br><br>原産国 : トルコ<!--ーーー--><br>容量 : 260ml<br>レンジ ×  オーブン ×  食洗機 〇<br><br><b>\"グラス\"アイテム一覧はこちら</b><br><a href=\"https://www.dot-st.com/todaysspecial/disp/itemlist/?dispNo=002005161\" target=\"_blank\"><font size=\"2\" color=\"blue\">ブラウザでみる</a></font></b> | <a href=\"adastriaapp://items?dispNo=0000100084_002005161&orderBy=00\" target=\"_blank\"><font size=\"2\" color=\"blue\">アプリでみる</a></font></b><br><br>', '546.0 JPY', 33.31, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:33:16', '2026-04-02 04:14:53', 'adastria_670080', '', '69cd72d3a7ab618f2967c972', '生活/休闲', '', '通用', '青年（18-44岁）', 'ガラス100%', 'https://www.dot-st.com/todaysspecial/disp/item/670080/?COLOR_CD=00', '其他服饰/物品', '其他', '配件', '', 'accessories', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/today’s_special/20260401/item_670080_main_00_1773990345_b.jpg', 0, 0, 9, 0.98685, 0, 1, 0, 0, 0, 3, NULL, '易清洗，可叠放收纳，日常使用方便', '易清洗,可叠放收纳,日常使用方便', '', '土耳其品牌Pasabahce玻璃杯,适合日常反复使用,支持洗碗机清洗,容量约260ml', '纯色，纯色', '该产品为Pasabahce品牌的玻璃“スタック カップ（可叠放杯/玻璃杯）”，属于餐厨用品而非服装家纺类。给定枚举中没有专门的餐具或杯子类目，只能在非服装的泛用类目中选择“accessories”。在本任务的定义下，“accessories”可作为非服装、非家纺小物件的最合适归类。sub_category: accessories，理解为：与穿戴或家居相关但不属于主要服装/家纺大件的配件、小物品类别。', 0, 0, 0, 0, 'accessories', NULL, '', 0, NULL, 0, NULL, NULL, '00', 'スタック カップ(00)', 0);
INSERT INTO `clothing_info` VALUES (19996438, 'CHUMMY CLEAR 迷你密封罐 S2 350ml / 星硝 - CELLAR MATE', 'チャーミークリアー S2 350ml / 星硝 - セラーメイト', 0, 200332, 'TODAY’S SPECIAL', '', '', '适合存放盐、胡椒等日常调味料，以及绿茶、红茶等茶叶、腌渍菜、梅干、蜂蜜柠檬等自制常备菜。也可用于棉签、化妆棉等各种小物的收纳，是一款造型简洁的通用保存容器。\n\n瓶身与盖子均为透明材质，从任何角度都能一眼看清内部内容物。盖子只需轻轻旋转即可开合，即使烹饪时单手腾不开也能轻松操作。瓶身、盖子与密封圈都可完全拆解，便于彻底清洗并保持卫生。\n\n产地：日本。注意本品非耐热玻璃，请勿在冷冻室、微波炉、烤箱及洗碗机中使用。', '<!--ーーー--><br>塩、コショウなどの毎日使う調味料や、緑茶、紅茶などの茶葉のストック、ピクルスに梅干し、ハチミツレモンなどの手づくりの常備菜。<br>綿棒やコットンなど、あらゆるものの保存に最適なシンプルな保存容器です。<br> <br>本体、フタともにすべてが透明なので、どこから見ても中身が一目でわかります。<br>フタは、少し回すだけで開閉できる仕様になっており、お料理で片手が使えないときにも便利。<br>本体、フタ、パッキンはすべて分解でき、隅々まですっきり洗えて、清潔に保てるのもうれしいポイントです。<br><br><br>原産国 : 日本<!--ーーー--><br>容量 : 350ml<br>耐熱温度差 : (熱変形温度)42℃<br>冷凍 ×<br>レンジ × オーブン × 食洗機 ×<br><br>※耐熱ガラスではありません。冷凍庫でのご使用はお控えください。<br><br><b>\"星硝 - セラーメイト\"アイテム一覧はこちら</b><br><a href=\"https://www.dot-st.com/todaysspecial/disp/itemlist/?dispNo=002005118\" target=\"_blank\"><font size=\"2\" color=\"blue\">ブラウザでみる</a></font></b> | <a href=\"adastriaapp://items?dispNo=0000100084_002005118&orderBy=00\" target=\"_blank\"><font size=\"2\" color=\"blue\">アプリでみる</a></font></b><br><b>\"保存容器\"アイテム一覧はこちら</b><br><a href=\"https://www.dot-st.com/todaysspecial/disp/itemlist/?dispNo=002005227\" target=\"_blank\"><font size=\"2\" color=\"blue\">ブラウザでみる</a></font></b> | <a href=\"adastriaapp://items?dispNo=0000100084_002005227&orderBy=00\" target=\"_blank\"><font size=\"2\" color=\"blue\">アプリでみる</a></font></b><br><br>', '600.0 JPY', 36.60, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:33:16', '2026-04-02 04:14:53', 'adastria_346513', '', '69cd72d3a7ab618f2967c976', '', '', '通用', '青年（18-44岁）', NULL, 'https://www.dot-st.com/todaysspecial/disp/item/346513/?COLOR_CD=00', '其他服饰/物品', '其他', '配件', '', 'accessories', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/today’s_special/20260401/item_346513_main_00_1739519141_b.jpg', 0, 0, 9, 0.97995, 0, -1, 0, 0, 0, 3, NULL, '收纳整理，密封保存，便于观察内容物，易于开合，易清洗', '收纳整理,密封保存,便于观察内容物,易于开合,易清洗', '', '适合存放调味料、茶叶、腌渍食品和小物件,瓶身和盖子全透明，便于辨认内容物,通过旋转少量即可开闭的结构设计提高使用方便性,各部件可完全拆解，便于清洁和保持卫生,非耐热玻璃，不能用于冷冻、微波炉、烤箱和洗碗机', '纯色', '该商品是厨房用透明密封保存容器，并非服装或家纺成品，在本分类列表中最接近的是附属类“accessories（配件）”。它不是衣物、床品、窗帘、毛巾、地毯、靠垫或桌布等纺织品成衣，因此归入“accessories”更合适。accessories 在这里可理解为日常生活中搭配使用的功能性小物或收纳类配件。', 0, 0, 0, 0, 'accessories', NULL, '', 0, NULL, 0, NULL, NULL, '00', 'チャーミークリアー S2 350ml(00)', 0);
INSERT INTO `clothing_info` VALUES (19996439, '再生玻璃 杯子 330ml', 'リユーズガラス グラス 330ml', 0, 200332, 'TODAY’S SPECIAL', '', '', '使用不再需要或被丢弃的玻璃再利用制作的饮用杯。通过将多块玻璃熔化后，在模具中吹制成型的“型吹成形”工艺完成，由工匠一只一只手工制作。由于是手工制品，尺寸和形状会有个体差异，表面可能出现气泡、细小皱纹、色点或轻微歪斜，这些都是手作器物特有的温润质感。采用再生玻璃材料，兼顾实用与环保，可作为日常饮水、冷饮等用途的玻璃杯使用。原产国：中国。', '<!--ーーー--><br><b>不要なガラスを再利用して作られたグラス。</b><br><br>一度は捨てられたり不要になったガラスを、再利用して作られたグラス。<br>いくつものガラスを溶かして型の中で息を吹き込みながら作る「型吹き成形」という技法で作られています。<br>一つ一つ職人の手によって作られているため、<br>サイズや形状の個体差や、表面に気泡やしわなどが見られる場合がありますが、ハンドメイドならではの温かみとしてお楽しみいただければと思います。<br><br><br>原産国 : 中国<!--ーーー--><br>容量 : 330ml<br>レンジ ×  オーブン ×  食洗機 ×<br><br>※こちらのリューズガラスは、再生ガラスを使用した環境に優しいサステナブルな製品でございます。<br>ハンドメイドのため、ガラスの流れや小さな気泡、色むら、黒い斑点、サイズや形状の個体差や歪みがある場合がございます。製品の個性としてお楽しみください。<br><br><b>\"グラス\"アイテム一覧はこちら</b><br><a href=\"https://www.dot-st.com/todaysspecial/disp/itemlist/?dispNo=002005161\" target=\"_blank\"><font size=\"2\" color=\"blue\">ブラウザでみる</a></font></b> | <a href=\"adastriaapp://items?dispNo=0000100084_002005161&orderBy=00\" target=\"_blank\"><font size=\"2\" color=\"blue\">アプリでみる</a></font></b><br><br>', '850.0 JPY', 51.85, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:33:16', '2026-04-02 04:14:54', 'adastria_611686', '', '69cd72d3a7ab618f2967c978', '生活/休闲', '', '通用', '青年（18-44岁）', 'ガラス100%', 'https://www.dot-st.com/todaysspecial/disp/item/611686/?COLOR_CD=00', '其他服饰/物品', '其他', '配件', '', 'accessories', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/today’s_special/20260401/item_611686_main_00_1765152395_b.jpg', 0, 0, 9, 0.99414, 0, 1, 0, 0, 0, 3, NULL, '环保可循环利用', '环保可循环利用', '再生材料应用', '采用废弃玻璃再生利用，符合可持续理念,通过型吹成形工艺，由工匠手工制作,表面可能存在气泡、皱纹、色差和轻微形变，体现手工质感,容量约330ml，适合作为日常饮水杯使用', '纯色', '该产品是“リユーズガラス グラス 330ml”，属于厨房与餐桌用玻璃杯，不是服装或家纺类。给定枚举中没有专门的餐具/杯子类目，只能选择最接近的“accessories”。在此语境下，“accessories”可理解为非服装的配件和小物，涵盖此类玻璃杯等生活杂货，因此将其归为 sub_category: accessories（配件/杂货类）。', 0, 0, 0, 0, 'accessories', NULL, '', 0, NULL, 0, NULL, NULL, '00', 'リユーズガラス グラス 330ml(00)', 0);
INSERT INTO `clothing_info` VALUES (19996434, '榨汁壶 / 东屋・白岳窑', 'ジューサー / 東屋 ･ 白岳窯', 0, 200332, 'TODAY’S SPECIAL', '', '', '在传统柠檬榨汁器上加上带手柄的小壶设计。容量可容纳一颗柠檬以上的果汁，也可以直接在壶内混合调味料使用。注出口处釉药刻意涂得较薄，使断流更干净、不易滴漏。壶身可以接住约一颗柠檬的果汁，仍有余量空间。可将榨好的果汁与酱油、清酒、高汤等搭配，制作原创沙拉酱或酱汁。产地为日本长崎县。可使用微波炉和洗碗机，不可用于烤箱。', '<!--ーーー--><br><b>馴染みのレモン絞り器にハンドル付きのポットをつけました。</b><br><br>レモン1個分以上の容量で調味料をそのまま混ぜることも。<br>注ぎ口の釉薬を薄くすることで切れがよく液だれしにくい構造に。	<br>ポット部分は、レモン１個分の果汁を受けとめて、まだ余裕のある容量です。<br>絞った果汁と醤油、酒、だしと合わせて、オリジナルのドレッシングやソースを作ることもできます。<br><br><br>原産国 : 日本(長崎県)<!--ーーー--><br>容量 : 240ml<br>レンジ 〇  オーブン ×  食洗機 〇<br><br><b>\"東屋\"アイテム一覧はこちら</b><br><a href=\"https://www.dot-st.com/todaysspecial/disp/itemlist/?dispNo=002005406\" target=\"_blank\"><font size=\"2\" color=\"blue\">ブラウザでみる</a></font></b> | <a href=\"adastriaapp://items?dispNo=0000100084_002005406&orderBy=00\" target=\"_blank\"><font size=\"2\" color=\"blue\">アプリでみる</a></font></b><br><b>\"キッチンツール\"アイテム一覧はこちら</b><br><a href=\"https://www.dot-st.com/todaysspecial/disp/itemlist/?dispNo=002005230\" target=\"_blank\"><font size=\"2\" color=\"blue\">ブラウザでみる</a></font></b> | <a href=\"adastriaapp://items?dispNo=0000100084_002005230&orderBy=00\" target=\"_blank\"><font size=\"2\" color=\"blue\">アプリでみる</a></font></b><br><br>', '4800.0 JPY', 292.80, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:33:17', '2026-04-02 04:14:50', 'adastria_343886', '', '69cd72d3a7ab618f2967c963', '', '', '通用', '青年（18-44岁）', '天草陶石50%,石灰釉50%', 'https://www.dot-st.com/todaysspecial/disp/item/343886/?COLOR_CD=01', '其他服饰/物品', '其他', '配件', '', 'accessories', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/today’s_special/20260401/item_343886_main_01_1757313405_b.jpg', 0, 0, 9, 0.71684, 0, -1, 0, 0, 0, 3, NULL, '可用于混合调味汁和酱汁', '可用于混合调味汁和酱汁', '', '带手柄和注出口的一体式柑橘榨汁器设计,注出口釉层变薄以减少滴漏,容量约为一个柠檬以上果汁量，可直接制作调味汁和酱汁,可微波加热且可使用洗碗机清洗,日本长崎县制造', '纯色，纯色', '商品是一款陶瓷柑橘榨汁器/小壶（厨房工具），并非服装或家用纺织品，如床品、窗帘、毛巾、地毯、靠垫或桌布等。提供的子类列表中没有专门针对厨房陶瓷器具的分类，只能从通用类中选择最合适的“accessories（配件）”。这里将其理解为生活杂货配件，非穿戴类用品，故选择 sub_category: accessories。定义：accessories 在本任务中可扩展为与穿着无关的小物件或辅助用品，例如厨房用小工具等。', 0, 0, 0, 0, 'accessories', NULL, '', 0, NULL, 0, NULL, NULL, '01', 'ジューサー / 東屋 ･ 白岳窯(01)', 0);
INSERT INTO `clothing_info` VALUES (19996435, '豆腐滤水盒', '豆腐の水切り', 0, 200332, 'TODAY’S SPECIAL', '', '', '适用于豆腐、蔬菜、酸奶等食材的滤水与保存。配有滤篮，既可当保存容器，又能用于沥水。只需将豆腐放入滤篮中静置即可完成滤水处理，也可用于蔬菜和酸奶的滤水。若在网状部分铺上纱布或布巾，滤水效果更佳。产地为日本新潟县。', '<!--ーーー--><br><b>豆腐、野菜、ヨーグルトなどの水切りに。</b><br><br>保存はもちろん、ザル付きなので水切りにも使える便利な容器。<br>ざるに豆腐を入れておくだけで、簡単に豆腐の水切りができる便利アイテム。<br>豆腐以外にも、野菜やヨーグルトの水切りにも使えます。<br>網部分にふきんを敷けば、より効果的に水切りができます。<br><br>原産国 : 日本(新潟県)<br><!--ーーー--><br><br>バット：135×190×72mm<br>ざる：幅138×181×68mm	<br>レンジ ×  食洗機 ×<br><br><br><b>\"保存容器\"アイテム一覧はこちら</b><br><a href=\"https://www.dot-st.com/todaysspecial/disp/itemlist/?dispNo=002005227\" target=\"_blank\"><font size=\"2\" color=\"blue\">ブラウザでみる</a></font></b> | <a href=\"\" target=\"_blank\"><font size=\"2\" color=\"blue\">アプリでみる</a></font></b><br><br><br>', '3600.0 JPY', 219.60, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:33:17', '2026-04-02 04:14:51', 'adastria_345547', '', '69cd72d3a7ab618f2967c965', '生活/休闲', '', '通用', '青年（18-44岁）', 'ステンレス鋼100%', 'https://www.dot-st.com/todaysspecial/disp/item/345547/?COLOR_CD=10', '其他服饰/物品', '其他', '配件', '', 'accessories', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/today’s_special/20260401/item_345547_main_10_1740128005_b.jpg', 0, 0, 9, 0.99753, 0, 1, 1, 0, 0, 3, NULL, '厨房收纳，食材水切，食材保存', '厨房收纳,食材水切,食材保存', '', '配有内置滤网/笊篱结构，可直接完成豆腐、蔬菜、酸奶等的沥水,容器与滤网组合设计，集水切与保存功能于一体,日本（新潟县）生产，采用金属材质，耐用度较高', '纯色，纯色', '该商品是用于厨房中豆腐、蔬菜、酸奶等食材水切与保存的不锈钢容器，并非服装或家纺类产品。在给定的子类列表中没有专门的“厨房用品”或“收纳容器”类别，只能在与服装直接无关、最泛用的类别中选择。综合考虑后选用“accessories（配件）”来归类这类非穿戴型但与生活相关的功能性小物。accessories 在这里可理解为辅助性日用配件，较其他服装子类更合适。', 0, 0, 0, 0, 'accessories', NULL, '', 0, NULL, 0, NULL, NULL, '10', '豆腐の水切り(10)', 0);
INSERT INTO `clothing_info` VALUES (19996431, '耐热玻璃密封罐 400ml', '耐熱ガラス キャニスター 400ml', 0, 200332, 'TODAY’S SPECIAL', '', '', '配有不锈钢材质的盖子，外观简洁利落，是一款玻璃密封罐。盖子内侧带有硅胶密封圈，可牢固密封，安心存放食材。罐身采用耐热玻璃，可用于微波炉加热料理内容物（使用时请取下盖子）。附带勺子，适合保存和取用咖啡豆、茶叶、麦片等干货食材。', '<!--ーーー--><br><b>ステンレス製の蓋がスタイリッシュな印象のガラス製キャニスター。</b><br><br>蓋にはシリコン製のパッキンが付いているのでしっかりと密閉でき、食材を安心して保存できます。<br>さらにガラス部分は耐熱ガラスを使用していて、電子レンジにも対応しているので、料理の温めにもお使いいただけます。<br>(※蓋部分は電子レンジ非対応なので取り外して使用してください)。<br>スプーン付きなのでコーヒー豆や茶葉、シリアルなどの保存時に便利です。<br><br><br><!--ーーー--><br>内容量 : 400ml<br>レンジ 〇  オーブン ×  食洗機 〇(※ガラス部分のみ)<br><br><br><b>\"耐熱ガラス キャニスター 600ml\"はこちら</b><br><a href=\"https://www.dot-st.com/andemiu/disp/item/343586/\" target=\"_blank\"><font size=\"2\" color=\"blue\">ブラウザでみる</a></font></b> | <a href=\"adastriaapp://item?itemCode=343586\" target=\"_blank\"><font size=\"2\" color=\"blue\">アプリでみる</a></font></b><br><b>\"コーヒー ･ ティー用品\"アイテム一覧はこちら</b><br><a href=\"https://www.dot-st.com/todaysspecial/disp/itemlist/?dispNo=002005573\" target=\"_blank\"><font size=\"2\" color=\"blue\">ブラウザでみる</a></font></b> | <a href=\"adastriaapp://items?dispNo=0000100084_002005573&orderBy=00\" target=\"_blank\"><font size=\"2\" color=\"blue\">アプリでみる</a></font></b><br><br>', '1350.0 JPY', 82.35, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:33:18', '2026-04-02 04:14:47', 'adastria_343585', '', '69cd72d3a7ab618f2967c95a', '生活/休闲', '', '通用', '青年（18-44岁）', NULL, 'https://www.dot-st.com/todaysspecial/disp/item/343585/?COLOR_CD=10', '其他服饰/物品', '其他', '配件', '', 'accessories', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/today’s_special/20260401/item_343585_main_10_1739329534_b.jpg', 0, 0, 9, 0.99019, 0, 1, 0, 0, 0, 3, NULL, '密封保存，耐热，可微波加热，适用于咖啡豆和茶叶等干货收纳', '密封保存,耐热,可微波加热,适用于咖啡豆和茶叶等干货收纳', '', '配有不锈钢盖和硅胶密封圈,玻璃部分为耐热玻璃，可用于微波炉加热,容量为400ml，适合厨房收纳使用,附带量勺，方便舀取食材', '纯色，纯色', '该商品是厨房用耐热玻璃密封罐，并非服装或家用纺织品（如床品、窗帘、地毯等），在给定的服饰类子类列表中没有专门的“容器/厨房用品”选项。综合考量，只能归入与服装无直接关系且最泛化的类别“accessories（配件）”。在此语境下，“accessories”可被理解为非主体服装类商品的附属或周边品类，用于归类这类生活杂货。', 0, 0, 0, 0, 'accessories', NULL, '', 0, NULL, 0, NULL, NULL, '10', '耐熱ガラス キャニスター 400ml(10)', 0);
INSERT INTO `clothing_info` VALUES (19996432, 'ANIMAL MUG 白色 / かしわ窯×TODAY\'S SPECIAL 动物马克杯', 'ANIMAL MUG ホワイト / かしわ窯×TODAY&#39;S SPECIAL', 0, 200332, 'TODAY’S SPECIAL', '', '', '这是一款在富于表情的动物浮雕上施以素雅白色釉料制成的原创马克杯。既可作为日常饮用的杯子，也适合作为家居装饰或收纳小物的容器。产地为日本爱知县。', '<!--ーーー--><br>表情豊かなレリーフの動物たちに、プレーンな白い釉薬を施したオリジナルのマグです。<br>マグとしてはもちろんインテリアや容れ物にも。<br><br><br>原産国 : 日本(愛知県)<!--ーーー--><br>容量 : 300ml<br>レンジ ×  オーブン ×  食洗機 ×<br><br><b>\"かしわ窯\"アイテム一覧はこちら</b><br><a href=\"https://www.dot-st.com/todaysspecial/disp/itemlist/?dispNo=002005501\" target=\"_blank\"><font size=\"2\" color=\"blue\">ブラウザでみる</a></font></b> | <a href=\"adastriaapp://items?dispNo=0000100084_002005501&orderBy=00\" target=\"_blank\"><font size=\"2\" color=\"blue\">アプリでみる</a></font></b><br><b>\"マグカップ\"アイテム一覧はこちら</b><br><a href=\"https://www.dot-st.com/todaysspecial/disp/itemlist/?dispNo=002005481\" target=\"_blank\"><font size=\"2\" color=\"blue\">ブラウザでみる</a></font></b> | <a href=\"adastriaapp://items?dispNo=0000100084_002005481&orderBy=00\" target=\"_blank\"><font size=\"2\" color=\"blue\">アプリでみる</a></font></b><br><br>', '2600.0 JPY', 158.60, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:33:18', '2026-04-02 04:14:48', 'adastria_346162', '', '69cd72d3a7ab618f2967c95f', '', '', '通用', '青年（18-44岁）', '陶器100%', 'https://www.dot-st.com/todaysspecial/disp/item/346162/?COLOR_CD=01', '其他服饰/物品', '其他', '配件', '', 'accessories', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/today’s_special/20260401/item_346162_main_01_1739518626_b.jpg', 0, 0, 9, 0.96414, 0, 1, 1, 0, 0, 3, NULL, '家居装饰，盛放饮品，收纳小物', '家居装饰,盛放饮品,收纳小物', '', '陶器材质，产地为日本爱知县,杯身有立体动物浮雕造型，造型感强,表面施以素雅白釉，整体风格简洁,既可作马克杯，也可作为装饰或容器使用', '纯色，纯色', '该产品是陶器马克杯，用于饮用与摆件，不属于服装、床品、窗帘、毛巾、地毯、靠垫或桌布范畴，只能归入列表中最接近的杂项类“accessories（配饰/杂项用品）”。“accessories”在这里可理解为非服装类的小型生活物件，是最适合的定义。', 1, 0, 0, 0, 'accessories', NULL, '', 0, NULL, 0, NULL, NULL, '01', 'ELEPHANT(01)', 0);
INSERT INTO `clothing_info` VALUES (19996433, 'ANIMAL MUG 白色 / かしわ窯×TODAY\'S SPECIAL 动物马克杯', 'ANIMAL MUG ホワイト / かしわ窯×TODAY&#39;S SPECIAL', 0, 200332, 'TODAY’S SPECIAL', '', '', '这是一款在富于表情的动物浮雕上施以素雅白色釉料制成的原创马克杯。既可作为日常饮用的杯子，也适合作为家居装饰或收纳小物的容器。产地为日本爱知县。', '<!--ーーー--><br>表情豊かなレリーフの動物たちに、プレーンな白い釉薬を施したオリジナルのマグです。<br>マグとしてはもちろんインテリアや容れ物にも。<br><br><br>原産国 : 日本(愛知県)<!--ーーー--><br>容量 : 300ml<br>レンジ ×  オーブン ×  食洗機 ×<br><br><b>\"かしわ窯\"アイテム一覧はこちら</b><br><a href=\"https://www.dot-st.com/todaysspecial/disp/itemlist/?dispNo=002005501\" target=\"_blank\"><font size=\"2\" color=\"blue\">ブラウザでみる</a></font></b> | <a href=\"adastriaapp://items?dispNo=0000100084_002005501&orderBy=00\" target=\"_blank\"><font size=\"2\" color=\"blue\">アプリでみる</a></font></b><br><b>\"マグカップ\"アイテム一覧はこちら</b><br><a href=\"https://www.dot-st.com/todaysspecial/disp/itemlist/?dispNo=002005481\" target=\"_blank\"><font size=\"2\" color=\"blue\">ブラウザでみる</a></font></b> | <a href=\"adastriaapp://items?dispNo=0000100084_002005481&orderBy=00\" target=\"_blank\"><font size=\"2\" color=\"blue\">アプリでみる</a></font></b><br><br>', '2600.0 JPY', 158.60, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:33:18', '2026-04-02 04:14:49', 'adastria_346162', '', '69cd72d3a7ab618f2967c95f', '', '', '通用', '青年（18-44岁）', '陶器100%', 'https://www.dot-st.com/todaysspecial/disp/item/346162/?COLOR_CD=01', '其他服饰/物品', '其他', '配件', '', 'accessories', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/today’s_special/20260401/item_346162_main_03_1739518664_b.jpg', 0, 0, 9, 0.89748, 0, 1, 1, 0, 0, 3, NULL, '家居装饰，盛放饮品，收纳小物', '家居装饰,盛放饮品,收纳小物', '', '陶器材质，产地为日本爱知县,杯身有立体动物浮雕造型，造型感强,表面施以素雅白釉，整体风格简洁,既可作马克杯，也可作为装饰或容器使用', '纯色，纯色', '该产品是陶器马克杯，用于饮用与摆件，不属于服装、床品、窗帘、毛巾、地毯、靠垫或桌布范畴，只能归入列表中最接近的杂项类“accessories（配饰/杂项用品）”。“accessories”在这里可理解为非服装类的小型生活物件，是最适合的定义。', 1, 1, 0, 0, 'accessories', NULL, '', 0, NULL, 0, NULL, NULL, '03', 'LION(03)', 0);
INSERT INTO `clothing_info` VALUES (19996429, '红包封套 花结 3枚装', 'のし袋 花結び 3枚入', 0, 200332, 'TODAY’S SPECIAL', '', '', '采用丝网印刷工艺制作的简约礼金袋，适合出生祝贺等各种喜庆场合使用。产地为日本。内含3枚。', '<!--ーーー--><br>シルク印刷されてシンプルなのし袋。<br>出産祝いなど、行事のお祝いごとに。<br><br><br>原産国 : 日本<!--ーーー--><br>内容量 : 3枚<br><br><b>\"祝儀袋\"アイテム一覧はこちら</b><br><a href=\"https://www.dot-st.com/todaysspecial/disp/itemlist/?dispNo=002005866\" target=\"_blank\"><font size=\"2\" color=\"blue\">ブラウザでみる</a></font></b> | <a href=\"adastriaapp://items?dispNo=0000100084_002005866&orderBy=00\" target=\"_blank\"><font size=\"2\" color=\"blue\">アプリでみる</a></font></b><br><br>', '340.0 JPY', 20.74, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:34:04', '2026-04-02 04:14:46', 'adastria_361847', '', '69cd72d3a7ab618f2967c951', '生活/休闲', '', '通用', '青年（18-44岁）', '紙100%', 'https://www.dot-st.com/todaysspecial/disp/item/361847/?COLOR_CD=00', '其他服饰/物品', '其他', '配件', '', 'accessories', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/today’s_special/20260401/item_361847_main_00_1774832018_b.jpg', 0, 0, 9, 0.79397, 0, -1, 0, 0, 0, 3, NULL, '礼金包装，馈赠祝福，适用于庆祝场合', '礼金包装,馈赠祝福,适用于庆祝场合', '', '日本产纸制礼金袋,采用丝网印刷图案，视觉简洁干净,适合用于出生祝贺等各类喜庆场合,每包包含3枚礼金袋,正面为红色花结设计，象征可多次庆贺的场合', '其他', '商品是“のし袋”（礼金袋），属于文具礼品小物，不是服装或家纺。给定类目中最接近的是可归入随身/礼赠相关的小配件，因此选择“accessories（配饰/杂项小物）”作为子类定义。Accessories 在这里可理解为非服装类的小型附属品或礼品用具。', 0, 0, 0, 0, 'accessories', NULL, '', 0, NULL, 0, NULL, NULL, '00', '花結び(00)', 0);
INSERT INTO `clothing_info` VALUES (19996430, '白竹席纹荞麦碗形竹笊篱 5.5寸 / 公长斋小菅', '白竹ござ目蕎麦椀ざる 5.5寸 / 公長齋小菅', 0, 200332, 'TODAY’S SPECIAL', '', '', '这款使用白竹制作的碗形荞麦盛器，由日本职人一件一件手工编织而成，细致的工艺充分体现了手作的巧妙与用心。带有高台设计，可作为盛放食材的器皿使用。也适合摆放在桌面作为水果篮，或在厨房、居家空间中用作收纳小物的竹制器具与装饰品。原产国为日本。', '<!--ーーー--><br><b>一つ一つ手づくりのお椀型のざる。</b><br><br>白竹を使った椀型の蕎麦盛り器は、日本の職人の手先の器用さ、丁寧さをしみじみと感じる細かい手仕事による製品。<br>高台付きなので食材のうつわとしてもお使いいただけます。<br>卓上の果物入れでも台所道具として、インテリアとして小物の収納にもおすすめです。<br><br><br>原産国 : 日本 <!--ーーー--><br><br><b>\"公長斎小菅\"アイテム一覧はこちら</b><br><a href=\"https://www.dot-st.com/todaysspecial/disp/itemlist/?dispNo=002005248\" target=\"_blank\"><font size=\"2\" color=\"blue\">ブラウザでみる</a></font></b> | <a href=\"adastriaapp://items?dispNo=0000100084_002005248&orderBy=00\" target=\"_blank\"><font size=\"2\" color=\"blue\">アプリでみる</a></font></b><br><b>\"竹ざる ･ 竹かご\"アイテム一覧はこちら</b><br><a href=\"https://www.dot-st.com/todaysspecial/disp/itemlist/?dispNo=002005447\" target=\"_blank\"><font size=\"2\" color=\"blue\">ブラウザでみる</a></font></b> | <a href=\"adastriaapp://items?dispNo=0000100084_002005447&orderBy=00\" target=\"_blank\"><font size=\"2\" color=\"blue\">アプリでみる</a></font></b><br><b>\"ざる ･ ボウル\"アイテム一覧はこちら</b><br><a href=\"https://www.dot-st.com/todaysspecial/disp/itemlist/?dispNo=002005224\" target=\"_blank\"><font size=\"2\" color=\"blue\">ブラウザでみる</a></font></b> | <a href=\"adastriaapp://items?dispNo=0000100084_002005224&orderBy=00\" target=\"_blank\"><font size=\"2\" color=\"blue\">アプリでみる</a></font></b><br><br>', '5400.0 JPY', 329.40, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:34:04', '2026-04-02 04:14:47', 'adastria_347584', '', '69cd72d3a7ab618f2967c95b', '生活/休闲', '', '通用', '青年（18-44岁）', '竹100%', 'https://www.dot-st.com/todaysspecial/disp/item/347584/?COLOR_CD=51', '其他服饰/物品', '其他', '配件', '', 'accessories', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/today’s_special/20260401/item_347584_main_51_1773965636_b.jpg', 0, 0, 9, 0.98876, 0, 1, 0, 0, 0, 3, NULL, '收纳功能，盛装食物，装饰摆设', '收纳功能,盛装食物,装饰摆设', '', '采用日本白竹手工编织，做工精细,碗形结构并带高台设计，兼具器皿与收纳用途,可作蕎麦盛器、水果盘或杂物收纳，具有多用途性', '其他', '该产品是白竹手工编织的碗形竹ざる/竹篮，用于盛放荞麦、果物或作收纳与装饰，并非服装或家纺（床品、窗帘、毛巾、地毯等），最接近的类别是非服装类的小物件与生活配件，因此归入“accessories（配饰/杂项小物）”。accessories 在这里可理解为：不直接穿戴于身、但与生活场景相关的附属性物件。', 0, 0, 0, 0, 'accessories', NULL, '', 0, NULL, 0, NULL, NULL, '51', '白竹ござ目蕎麦椀ざる 5.5寸 (51)', 0);
INSERT INTO `clothing_info` VALUES (19996428, '骨董 彩绘熨斗松竹梅菱形盘', '骨董 色絵熨斗に松竹梅 菱形皿', 0, 200332, 'TODAY’S SPECIAL', '', '', '具有菱形造型与对比鲜明的华丽彩绘，给人留下深刻印象。四边立起的缘部各自绘有优美纹样，深藏青与雅致的红色成为点睛之笔。器形厚度适中，高台宽阔稳固，使用安心。可用来盛放配菜、装盘一品料理等，不仅适合庆祝场合，也适用于日常的多种餐桌情景。时代为明治前期，产地为日本。作为骨董品，手工制作，一件一貌，风合独特。', '<!--ーーー--><br><b>菱形の形とコントラストの効いた華やかな色絵が印象的なうつわ。</b><br><br>立ち上がりの良い四方の縁にはそれぞれ美しい文様が描かれ、濃紺のカラーやシックな印象の赤色がアクセントとなっています。<br>器形は程よく厚みを持たせ、高台も広く安定した安心のつくり。<br>おかずを盛りつけたり、一品料理をのせたり、お祝いの席だけでなくいろいろとお楽しみいただけます。<br><br>時代 : 明治前期<br><br><br>原産国 : 日本<!--ーーー--><br>レンジ ×   オーブン ×  食洗機 ×  <br><br><b>\"骨董\"アイテム一覧はこちら</b><br><a href=\"https://www.dot-st.com/todaysspecial/disp/itemlist/?dispNo=002005326\" target=\"_blank\"><font size=\"2\" color=\"blue\">ブラウザでみる</a></font></b> | <a href=\"adastriaapp://items?dispNo=0000100084_002005326&orderBy=00\" target=\"_blank\"><font size=\"2\" color=\"blue\">アプリでみる</a></font></b><br><b>\"取り皿 ･ 大皿\"アイテム一覧はこちら</b><br><a href=\"https://www.dot-st.com/todaysspecial/disp/itemlist/?dispNo=002005458\" target=\"_blank\"><font size=\"2\" color=\"blue\">ブラウザでみる</a></font></b> | <a href=\"adastriaapp://items?dispNo=0000100084_002005458&orderBy=00\" target=\"_blank\"><font size=\"2\" color=\"blue\">アプリでみる</a></font></b><br><br><b>[ご購入前にご確認ください。]</b><br>※やや個体差がございますが、サイズ感は同じ商品になります。アソートでお選びいたします。<br>※骨董品のため、ひびや欠け、色むら、キズなどがみられる場合がございます。<br>※色や判のずれ、歪みによる若干のがたつき、窯傷などがある場合もございます。<br>※手作りのため、同じ絵柄でも一点一点風合いが異なります。<br>※表情や焼き色に対するイメージの違い等、お客様ご都合の交換や返品はできかねます。あらかじめご了承くださいませ。<br><br>', '4000.0 JPY', 244.00, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:34:06', '2026-04-02 04:14:45', 'adastria_666441', '', '69cd72d3a7ab618f2967c94e', '生活/休闲', '', '通用', '青年（18-44岁）', '陶器100%', 'https://www.dot-st.com/todaysspecial/disp/item/666441/?COLOR_CD=00', '其他服饰/物品', '其他', '配件', '', 'accessories', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/today’s_special/20260401/item_666441_main_00_1769770226_b.jpg', 0, 0, 8, 0.57540, 0, -1, 0, 0, 0, 3, NULL, '家居餐桌装饰，盛放菜肴与小料理', '家居餐桌装饰,盛放菜肴与小料理', '', '明治前期的骨董器物，具有收藏价值,日本产手工制作，每件风合各异,菱形器形，四方立起边缘，厚实且高台稳固,边缘绘有松竹梅等吉祥纹样，适合喜庆场合,不可使用微波炉、烤箱和洗碗机', '花卉图案，叶子，树，物体', '商品为“骨董 色絵熨斗に松竹梅 菱形皿”，是用于盛放菜肴的一只陶器盘子，属于餐厨器皿，并非服装或家纺类。提供的枚举中没有专门的餐具/餐盘类别，只能在非服装类中选择最接近的“accessories（配件/杂项小物）”来归类。此处将其理解为家居生活的小型配件类物件，因此选择 sub_category: accessories，定义为：不属于服装、鞋帽或典型家纺的周边小物与生活配件。', 0, 0, 0, 0, 'accessories', NULL, '', 0, NULL, 0, NULL, NULL, '00', '骨董 色絵熨斗に松竹梅 菱形皿(00)', 0);
INSERT INTO `clothing_info` VALUES (19996427, '柳宗理 呉须纹样汤杯', '柳 宗理 呉須紋付 湯呑', 0, 200335, 'GEORGE’S', '', '', '这是对柳宗理最初设计形态进行再现的复刻版。\n这款看起来有些类似荞麦猪口的小巧汤杯，可以稳稳地托在手心中。由于杯口直径不大，握持时更容易稳固支撑。\n\n【关于和食器系列】\n该系列是柳宗理在1975年为日常使用而设计的和食器。这些被称为和食器系列的器皿，是柳首次有意识地以和食餐具为对象创作的作品。随着生产工厂的变迁，这些器皿经历了各种变更。2022年，借助陶瓷品牌深山的生产技术，并在柳工业设计研究会的监修下，使其再生回归，力求贴近诞生之初柳宗理的设计理念。\n\n【关于染付纹・漩涡】\n结合当时的饮食环境，柳首次在器皿上绘制纹样。这一层层画出的同心圆纹样，以“鸣门漩涡”为意象。', 'ーーー<br>柳宗理がデザインした開発当初の姿の再現を求めた復刻版です。<br>一見するとそば猪口のようにも見えるこちらの湯呑は、手のひらに収まるコンパクトなサイズ感。<br>経が大きすぎないから、持ったときにしっかりと支えることができます。<br>ーーー<br><b>＜和食器シリーズについて＞</b><br>1975年に柳宗理が普段使いの和食器としてデザインしたうつわ。<br>和食器シリーズと呼ばれるこのうつわは、柳が和食用の食器として意識して手がけた最初のうつわ。以降、生産工場の変化に伴い様々な変更が為されたこのうつわを、誕生当時の柳の想いに即し、陶磁器メーカー深山の生産技術を活用し、そして柳工業デザイン研究会の監修を受け、2022年に再生しました。<br><br><b>＜染付紋・渦について＞</b><br>当時の食環境を鑑みて、このうつわには文様があっていいと描いた柳にとって初めての紋様。幾重にも円を描くこの紋様は「鳴門の渦潮」をイメージしています。<br><br><br>※食洗機のご使用は可能ですが、過剰な詰め込みは破損の原因となる可能性がありますので、ご注意ください。<br>※研磨剤や研磨剤入りの洗剤、またはクレンザー、金属たわし等を使用しての洗浄は、表面に傷が付く原因となりますので、ご使用は避け、やわらかいスポンジで洗浄して下さい。', '2200.0 JPY', 134.20, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:34:17', '2026-04-02 04:14:44', 'adastria_669429', '', '69cd72d3a7ab618f2967c945', '生活/休闲', '', '通用', '青年（18-44岁）', '磁器100%', 'https://www.dot-st.com/georges/disp/item/669429/?COLOR_CD=00', '其他服饰/物品', '其他', '配件', '', 'accessories', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/george’s/20260401/item_669429_main_00_1773727001_b.jpg', 0, 0, 9, 0.98933, 0, -1, 0, 0, 0, 3, NULL, '日常饮用器皿', '日常饮用器皿', '陶瓷烧制工艺', '柳宗理设计复刻版，强调还原1975年和食器系列的原始造型与设计理念,采用陶磁器品牌深山的生产技术，并由柳工業デザイン研究会监修,杯身尺寸偏小，方便单手握持和稳固托住,杯身配有以“鸣门漩涡”为意象的同心圆装饰纹样,适用于洗碗机，但不宜过度堆叠以免损坏,建议使用软海绵清洗，避免研磨剂和金属刷以防刮伤表面釉面', '其他', '商品为「湯呑」，属于餐饮用的茶杯/水杯等厨房与桌面用品，并非服装或家纺类，最接近的分类是配合生活使用的小物，因此在给定列表中选择“accessories”。Accessories 在这里可理解为日常生活搭配使用的附属类物件，而非穿着类或家用纺织品类。', 0, 0, 0, 0, 'accessories', NULL, '', 0, NULL, 0, NULL, NULL, '00', 'ホワイト(00)', 0);
INSERT INTO `clothing_info` VALUES (19996426, 'REVOMAX专用瓶底保护套 S 沙色米', 'REVOMAX専用カバーS サンドベージュ', 0, 200335, 'GEORGE’S', '', '', '这是一款REVOMAX水壶专用的底部保护套，可爱又实用。安装后能够防止日常使用时水壶底部产生刮痕，同时还能起到防滑作用。将其装在自己拥有的REVOMAX水壶上，可以设计出专属的个性化水壶外观，也推荐与REVOMAX水壶搭配一起使用。', 'ーーー<br>可愛く保護してくれるREVOMAX専用底カバー<br>ーーー<br><br>専用カバーを装着することで、日々使用する水筒の底に傷がつくのを防いでくれます。<br>滑り止めとしても活躍してくれます。<br><br>お持ちのREVOMAXに装着して自分だけのマイボトルをデザインしましょう♪<br><br>ぜひREVOMAX水筒とご一緒に！<br>', '1000.0 JPY', 61.00, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:34:20', '2026-04-02 04:14:43', 'adastria_666426', '', '69cd72d3a7ab618f2967c943', '生活/休闲', '', '通用', '青年（18-44岁）', NULL, 'https://www.dot-st.com/georges/disp/item/666426/?COLOR_CD=00', '其他服饰/物品', '其他', '配件', '', 'accessories', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/george’s/20260401/item_666426_main_00_1773220932_b.webp', 0, 0, 9, 0.99064, 0, -1, 0, 0, 0, 3, NULL, '防静电，防滑，防止刮擦', '防滑,防止刮擦', '', '厨房与餐桌使用相关配件,用于REVOMAX水壶底部的专用保护套,提升水壶外观可爱度，可个性化搭配颜色', '纯色，纯色', '该产品是REVOMAX水壶的“专用底部保护套”，属于水瓶配件，并非服装或家纺。根据图片和描述，它是套在水壶底部的小件，起到防刮、防滑和装饰作用，更接近“accessories（配件）”的定义，因此选择 sub_category 为 accessories。accessories 在此可理解为与主体用品搭配使用的功能性与装饰性小配件。', 0, 0, 0, 0, 'accessories', NULL, '', 0, NULL, 0, NULL, NULL, '00', 'サンドベージュ(00)', 0);
INSERT INTO `clothing_info` VALUES (19996423, '【童装】尼龙配色短裤【官网预售】', '【KIDS】ナイロンカラーショーツ【WEB先行予約】', 0, 200335, 'GEORGE’S', '', '', '这是一款非常适合“在街上、在海边都想尽情玩耍”的活力儿童穿着的功能性短裤。以成人款为灵感，延续简约利落的设计风格，非常适合与父母做亲子链接穿搭。针对爱跑爱跳的孩子，选用轻盈又结实的高密度尼龙面料，兼具耐磨和舒适性。具有一定撇水和速干特性，海边玩水或公园玩耍时沾到水渍、泥渍也能轻松擦拭并快速干燥。左裤脚加入“General store good neighbors”英文刺绣字样，相比普通印花更有立体质感，让整体造型更有层次。腰部为松紧加抽绳结构，方便随身形调节，也便于孩子自己穿脱。', 'ーーー<br>「街でも、海でも、思いきり遊びたい！」そんなアクティブなキッズにぴったりの、機能派ショートパンツです。<br>ーーー<br>大人のデザインをそのまま落とし込んだミニマルなルックスで、親子でのリンクコーデにも最適な一着です。<br>元気に走り回るキッズのために、軽くて丈夫な高密度ナイロンを採用しました。<br>撥水・速乾で海辺の水遊びや、公園での泥汚れもサッと拭き取れて乾きやすい！<br>左裾には「General store good neighbors」のメッセージを刺繍で配置。プリントにはない立体感が、コーディネートをワンランクアップさせます。<br>ウエストはゴム＆ドローコードで成長に合わせて調整しやすく、自分でお着替えもしやすい仕様です。<br>', '3500.0 JPY', 213.50, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:34:27', '2026-04-02 04:14:41', 'adastria_676265', '', '69cd72d3a7ab618f2967c93e', '生活/休闲，游泳，水上运动', '', '通用', '儿童（4-12岁）', '锦纶100%', 'https://www.dot-st.com/georges/disp/item/676265/?COLOR_CD=09', '下装', '短裤', '短裤', '', 'shorts', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/george’s/20260401/item_676265_main_09_1774922906_b.webp', 0, 0, 2, 0.99851, 0, 1, 1, 0, 0, 3, NULL, '速干，防水，耐用，轻量，易打理', '耐用,轻量,易打理', '', '适合亲子链接穿搭设计,左裾有英文刺绣装饰，增强立体感与质感,腰部橡筋加抽绳结构，方便儿童自行穿脱与调节,高密度尼龙面料，增加强度与挺括度', '字母', '从图片和描述看，是儿童长度在膝上的休闲短裤，腰部为松紧加抽绳设计，适合日常和户外活动，明显属于下装短裤范畴，因此选择子类目“shorts（短裤）”。该子类定义为：日常或运动穿着的及大腿或膝部长度的裤装。', 1, 0, 0, 0, 'shorts', NULL, '', 0, NULL, 0, NULL, NULL, '09', 'ブラック(09)', 0);
INSERT INTO `clothing_info` VALUES (19996424, '【童装】尼龙配色短裤【官网预售】', '【KIDS】ナイロンカラーショーツ【WEB先行予約】', 0, 200335, 'GEORGE’S', '', '', '这是一款非常适合“在街上、在海边都想尽情玩耍”的活力儿童穿着的功能性短裤。以成人款为灵感，延续简约利落的设计风格，非常适合与父母做亲子链接穿搭。针对爱跑爱跳的孩子，选用轻盈又结实的高密度尼龙面料，兼具耐磨和舒适性。具有一定撇水和速干特性，海边玩水或公园玩耍时沾到水渍、泥渍也能轻松擦拭并快速干燥。左裤脚加入“General store good neighbors”英文刺绣字样，相比普通印花更有立体质感，让整体造型更有层次。腰部为松紧加抽绳结构，方便随身形调节，也便于孩子自己穿脱。', 'ーーー<br>「街でも、海でも、思いきり遊びたい！」そんなアクティブなキッズにぴったりの、機能派ショートパンツです。<br>ーーー<br>大人のデザインをそのまま落とし込んだミニマルなルックスで、親子でのリンクコーデにも最適な一着です。<br>元気に走り回るキッズのために、軽くて丈夫な高密度ナイロンを採用しました。<br>撥水・速乾で海辺の水遊びや、公園での泥汚れもサッと拭き取れて乾きやすい！<br>左裾には「General store good neighbors」のメッセージを刺繍で配置。プリントにはない立体感が、コーディネートをワンランクアップさせます。<br>ウエストはゴム＆ドローコードで成長に合わせて調整しやすく、自分でお着替えもしやすい仕様です。<br>', '3500.0 JPY', 213.50, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:34:27', '2026-04-02 04:14:42', 'adastria_676265', '', '69cd72d3a7ab618f2967c93e', '生活/休闲，游泳，水上运动', '', '通用', '儿童（4-12岁）', '锦纶100%', 'https://www.dot-st.com/georges/disp/item/676265/?COLOR_CD=09', '下装', '短裤', '短裤', '', 'shorts', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/george’s/20260401/item_676265_main_30_1774922944_b.jpg', 0, 0, 6, 0.94745, 0, 1, 1, 0, 0, 3, NULL, '速干，防水，耐用，轻量，易打理', '耐用,轻量,易打理', '', '适合亲子链接穿搭设计,左裾有英文刺绣装饰，增强立体感与质感,腰部橡筋加抽绳结构，方便儿童自行穿脱与调节,高密度尼龙面料，增加强度与挺括度', '字母', '从图片和描述看，是儿童长度在膝上的休闲短裤，腰部为松紧加抽绳设计，适合日常和户外活动，明显属于下装短裤范畴，因此选择子类目“shorts（短裤）”。该子类定义为：日常或运动穿着的及大腿或膝部长度的裤装。', 1, 1, 0, 0, 'shorts', NULL, '', 0, NULL, 0, NULL, NULL, '30', 'レッド(30)', 0);
INSERT INTO `clothing_info` VALUES (19996425, '【童装】尼龙配色短裤【官网预售】', '【KIDS】ナイロンカラーショーツ【WEB先行予約】', 0, 200335, 'GEORGE’S', '', '', '这是一款非常适合“在街上、在海边都想尽情玩耍”的活力儿童穿着的功能性短裤。以成人款为灵感，延续简约利落的设计风格，非常适合与父母做亲子链接穿搭。针对爱跑爱跳的孩子，选用轻盈又结实的高密度尼龙面料，兼具耐磨和舒适性。具有一定撇水和速干特性，海边玩水或公园玩耍时沾到水渍、泥渍也能轻松擦拭并快速干燥。左裤脚加入“General store good neighbors”英文刺绣字样，相比普通印花更有立体质感，让整体造型更有层次。腰部为松紧加抽绳结构，方便随身形调节，也便于孩子自己穿脱。', 'ーーー<br>「街でも、海でも、思いきり遊びたい！」そんなアクティブなキッズにぴったりの、機能派ショートパンツです。<br>ーーー<br>大人のデザインをそのまま落とし込んだミニマルなルックスで、親子でのリンクコーデにも最適な一着です。<br>元気に走り回るキッズのために、軽くて丈夫な高密度ナイロンを採用しました。<br>撥水・速乾で海辺の水遊びや、公園での泥汚れもサッと拭き取れて乾きやすい！<br>左裾には「General store good neighbors」のメッセージを刺繍で配置。プリントにはない立体感が、コーディネートをワンランクアップさせます。<br>ウエストはゴム＆ドローコードで成長に合わせて調整しやすく、自分でお着替えもしやすい仕様です。<br>', '3500.0 JPY', 213.50, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:34:27', '2026-04-02 04:14:42', 'adastria_676265', '', '69cd72d3a7ab618f2967c93e', '生活/休闲，游泳，水上运动', '', '通用', '儿童（4-12岁）', '锦纶100%', 'https://www.dot-st.com/georges/disp/item/676265/?COLOR_CD=09', '下装', '短裤', '短裤', '', 'shorts', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/george’s/20260401/item_676265_main_80_1774922926_b.jpg', 0, 0, 2, 0.98529, 0, 1, 1, 0, 0, 3, NULL, '速干，防水，耐用，轻量，易打理', '耐用,轻量,易打理', '', '适合亲子链接穿搭设计,左裾有英文刺绣装饰，增强立体感与质感,腰部橡筋加抽绳结构，方便儿童自行穿脱与调节,高密度尼龙面料，增加强度与挺括度', '字母', '从图片和描述看，是儿童长度在膝上的休闲短裤，腰部为松紧加抽绳设计，适合日常和户外活动，明显属于下装短裤范畴，因此选择子类目“shorts（短裤）”。该子类定义为：日常或运动穿着的及大腿或膝部长度的裤装。', 1, 2, 0, 0, 'shorts', NULL, '', 0, NULL, 0, NULL, NULL, '80', 'ブルー(80)', 0);
INSERT INTO `clothing_info` VALUES (19996420, '【晴雨两用/折叠伞】Wpc.IZA Light＆Slim', '[晴雨兼用/折畳み傘］Wpc.IZA Light＆Slim', 0, 200335, 'GEORGE’S', '', '', '约190g重量、收纳时横向宽度约6cm的轻量纤细折叠伞，在兼顾轻量的同时，展开时直径约90cm，足以为男性提供良好覆盖。附带登山扣，可直接挂在包袋上携带，一键开合，操作顺畅。\n\n凭借优异的遮热性能，显著降低体感温度。采用遮光率100%、UV阻隔率100%的面料，提供完备的紫外线防护。伞布内侧黑色涂层增强遮热效果，在炎炎烈日下体感温度明显下降。\n\n全色系均实现遮光率100%、UV阻隔率100%、UPF50+。伞内侧黑色涂层吸收大量光线反射，减轻由紫外线和可见光反射对肌肤造成的伤害，从而在强光环境下提供更舒适的使用体验。\n\n具备优异遮热性，在炎热、易出汗季节也能维持相对凉爽舒适，炎天下的使用可有效降低出汗量，提升体感舒适度。\n\n面料表面经过特殊整理，实现最高等级5级的撥水性，水滴容易滚落，减轻雨天使用时的负担。同时采用高耐水压面料，即使在较大雨量环境下也能提供可靠防护，但在暴雨或长时间使用时仍可能出现渗水风险。以上功能性数据均基于面料状态测试结果。', '重さ約190g/収納時の横幅約6cmと、大きさと軽量を兼ね備えたスリムなフォルム。<br>軽量でありながら、開いた時の直径は約90cmと男性でもしっかりカバーしてくれるサイズ感を実現。<br>カラビナ付きなのでバッグに取り付けることも可能。<br>ワンアクションでスムーズに開閉できます。<br><br><b>【暑さを凌いで、クールな日常へ。】</b><br>サーモグラフィ検査において、頭頂部表面温度差に14.7℃の差を実証。<br>※傘未使用時との比較（頭頂部）<br>環境：室温25℃×60%RH　照射強度：約800W/平方メートル（JIS L 1951遮熱試験同様強度）　照射時間：20分　照射距離：2.0m<br>試験試料：ポリエステル100％生地(オフホワイト色)/裏面黒色PUコーティング/親骨サイズ58cm<br>製品の種類・環境条件などにより遮熱効果は異なり、感じ方には個人差があります。<br><br>優れた遮熱性で、体感温度を大幅に低減。<br>遮光率・UVカット率100%で、紫外線対策も万全です。<br>生地裏面のコーティングにより、優れた遮熱効果を発揮。<br>炎天下でも、体感温度が大幅に下がります。<br><br><b>【涼感日傘】</b><br>全カラー、遮光率100％、UVカット率100％、UPF50＋を実現<br>※遮光率100％　検査方法：JIS L 1055 A法、生地の状態での測定値<br>※UVカット率100％　検査方法：JIS L 1925、生地の状態での測定値<br>※UPF50＋　検査方法：JIS L 1925、生地の状態での測定値<br><br>傘内側の黒コーティングが照り返しを90％吸収<br>傘の内側で起こる光の反射を大幅に減らして、肌にダメージを与える有害光線から、あなたを守る。<br>※直接肌に照り返された光を吸収するものではありません。<br>※光の反射は紫外線（UV-B・UV-A）・可視光線について測定。<br>※紫外線は紫外線吸収率(分光分析/紫外線(280~400)透過率・反射率より算出)、可視光線は可視光線吸収率(分光分析/可視光線(400~780)透過率・反射率より算出)に基づく。<br>※記載の数値は生地の状態で測定した数値をもとに記載しており、傘本体の性能を示す数値ではありません。<br><br><b>夏の大敵≪汗ばむ季節も、涼しく快適≫</b><br>遮熱性のある生地が、暑さをおさえます。※1<br>炎天下でも快適性をサポートします。<br>・日傘を使用していない場合の発汗量：14.1g ※2<br>・Wpc. IZA を使用した場合の発汗量：10.8g ※2<br><br><b>【雨の日にも、万全の備えを。】</b><br>最高等級の≪撥水力≫<br>生地表面に施した加工により、最高等級5級の撥水性を実現。水滴が転がりやすく、雨の日のストレスを軽減します。<br>・JIS L 1092の規定に準じて生地のはっ水度を測定しています。撥水等級は、最高レベルを5級、最低レベルを1級とした、撥水性の等級です。<br>※記載の結果は生地の状態での測定値であり、傘本体の性能を示す数値ではございません。<br><br>大雨にも耐える≪耐水性≫<br>大雨でも安心な、耐水圧を実現した生地を使用。<br>※激しい雨や長時間の雨傘としてのご使用は、雨漏りや生地に水がしみ込む恐れがございます。<br>またデザインの特性上、完全な防水はっ水加工が難しい場合があり、雨が染み込むことがありますのでご注意ください。<br>・JIS L 1092の規定に準じて生地の耐水度を測定しています。<br>※記載の結果は生地の状態での測定値であり、傘本体の性能を示す数値ではございません。<br>', '4200.0 JPY', 256.20, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:34:29', '2026-04-02 04:14:38', 'adastria_669174', '', '69cd72d3a7ab618f2967c93d', '生活/休闲', '', '通用', '青年（18-44岁）', '涤纶100%', 'https://www.dot-st.com/georges/disp/item/669174/?COLOR_CD=05', '其他服饰/物品', '其他', '配件', '', 'accessories', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/george’s/20260401/item_669174_main_05_1774230870_b.jpg', 0, 0, 1, 0.52627, 0, -2, 0, 0, 0, 3, NULL, '防水，防晒，防紫外线，防尘，遮热，降温，遮光，高撥水性，耐水性，轻量化，折叠便携，防眩光/减弱反射光', '遮热,降温,遮光,高撥水性,耐水性,轻量化,折叠便携,防眩光/减弱反射光', '黑色PU涂层遮热技术,高遮光涂层技术,UPF50+防晒技术,高撥水整理,耐水压测试技术,热成像测试评估遮热效果', '晴雨两用设计，可同时应对强烈日晒和降雨环境,约190g的轻量化结构，收纳宽度约6cm，便于随身携带,展开直径约90cm，可为男性身高体型提供足够覆盖,配有登山扣，可挂在包袋上提升携带便利性,一键开合机构，使用操作简便顺畅,伞内侧黑色涂层可吸收约90%的光线反射，减少对皮肤的有害光线,面料通过多项JIS标准测试，量化遮热、遮光、UV和撥水性能,强调在高温炎热环境下减轻出汗量、提升体感舒适度', '纯色', '该产品为晴雨兼用折叠伞，属于穿搭配件类而非服装或家纺。列表中没有“umbrella”或雨具专门分类，最贴近的是统摄非服装小物的“accessories”。因此选择 sub_category 为“accessories”，即配饰类产品，用于日常遮阳、防雨搭配使用。', 1, 0, 0, 0, 'accessories', NULL, '', 0, NULL, 0, NULL, NULL, '05', 'OFF(05)', 0);
INSERT INTO `clothing_info` VALUES (19996421, '【晴雨两用/折叠伞】Wpc.IZA Light＆Slim', '[晴雨兼用/折畳み傘］Wpc.IZA Light＆Slim', 0, 200335, 'GEORGE’S', '', '', '约190g重量、收纳时横向宽度约6cm的轻量纤细折叠伞，在兼顾轻量的同时，展开时直径约90cm，足以为男性提供良好覆盖。附带登山扣，可直接挂在包袋上携带，一键开合，操作顺畅。\n\n凭借优异的遮热性能，显著降低体感温度。采用遮光率100%、UV阻隔率100%的面料，提供完备的紫外线防护。伞布内侧黑色涂层增强遮热效果，在炎炎烈日下体感温度明显下降。\n\n全色系均实现遮光率100%、UV阻隔率100%、UPF50+。伞内侧黑色涂层吸收大量光线反射，减轻由紫外线和可见光反射对肌肤造成的伤害，从而在强光环境下提供更舒适的使用体验。\n\n具备优异遮热性，在炎热、易出汗季节也能维持相对凉爽舒适，炎天下的使用可有效降低出汗量，提升体感舒适度。\n\n面料表面经过特殊整理，实现最高等级5级的撥水性，水滴容易滚落，减轻雨天使用时的负担。同时采用高耐水压面料，即使在较大雨量环境下也能提供可靠防护，但在暴雨或长时间使用时仍可能出现渗水风险。以上功能性数据均基于面料状态测试结果。', '重さ約190g/収納時の横幅約6cmと、大きさと軽量を兼ね備えたスリムなフォルム。<br>軽量でありながら、開いた時の直径は約90cmと男性でもしっかりカバーしてくれるサイズ感を実現。<br>カラビナ付きなのでバッグに取り付けることも可能。<br>ワンアクションでスムーズに開閉できます。<br><br><b>【暑さを凌いで、クールな日常へ。】</b><br>サーモグラフィ検査において、頭頂部表面温度差に14.7℃の差を実証。<br>※傘未使用時との比較（頭頂部）<br>環境：室温25℃×60%RH　照射強度：約800W/平方メートル（JIS L 1951遮熱試験同様強度）　照射時間：20分　照射距離：2.0m<br>試験試料：ポリエステル100％生地(オフホワイト色)/裏面黒色PUコーティング/親骨サイズ58cm<br>製品の種類・環境条件などにより遮熱効果は異なり、感じ方には個人差があります。<br><br>優れた遮熱性で、体感温度を大幅に低減。<br>遮光率・UVカット率100%で、紫外線対策も万全です。<br>生地裏面のコーティングにより、優れた遮熱効果を発揮。<br>炎天下でも、体感温度が大幅に下がります。<br><br><b>【涼感日傘】</b><br>全カラー、遮光率100％、UVカット率100％、UPF50＋を実現<br>※遮光率100％　検査方法：JIS L 1055 A法、生地の状態での測定値<br>※UVカット率100％　検査方法：JIS L 1925、生地の状態での測定値<br>※UPF50＋　検査方法：JIS L 1925、生地の状態での測定値<br><br>傘内側の黒コーティングが照り返しを90％吸収<br>傘の内側で起こる光の反射を大幅に減らして、肌にダメージを与える有害光線から、あなたを守る。<br>※直接肌に照り返された光を吸収するものではありません。<br>※光の反射は紫外線（UV-B・UV-A）・可視光線について測定。<br>※紫外線は紫外線吸収率(分光分析/紫外線(280~400)透過率・反射率より算出)、可視光線は可視光線吸収率(分光分析/可視光線(400~780)透過率・反射率より算出)に基づく。<br>※記載の数値は生地の状態で測定した数値をもとに記載しており、傘本体の性能を示す数値ではありません。<br><br><b>夏の大敵≪汗ばむ季節も、涼しく快適≫</b><br>遮熱性のある生地が、暑さをおさえます。※1<br>炎天下でも快適性をサポートします。<br>・日傘を使用していない場合の発汗量：14.1g ※2<br>・Wpc. IZA を使用した場合の発汗量：10.8g ※2<br><br><b>【雨の日にも、万全の備えを。】</b><br>最高等級の≪撥水力≫<br>生地表面に施した加工により、最高等級5級の撥水性を実現。水滴が転がりやすく、雨の日のストレスを軽減します。<br>・JIS L 1092の規定に準じて生地のはっ水度を測定しています。撥水等級は、最高レベルを5級、最低レベルを1級とした、撥水性の等級です。<br>※記載の結果は生地の状態での測定値であり、傘本体の性能を示す数値ではございません。<br><br>大雨にも耐える≪耐水性≫<br>大雨でも安心な、耐水圧を実現した生地を使用。<br>※激しい雨や長時間の雨傘としてのご使用は、雨漏りや生地に水がしみ込む恐れがございます。<br>またデザインの特性上、完全な防水はっ水加工が難しい場合があり、雨が染み込むことがありますのでご注意ください。<br>・JIS L 1092の規定に準じて生地の耐水度を測定しています。<br>※記載の結果は生地の状態での測定値であり、傘本体の性能を示す数値ではございません。<br>', '4200.0 JPY', 256.20, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:34:29', '2026-04-02 04:14:39', 'adastria_669174', '', '69cd72d3a7ab618f2967c93d', '生活/休闲', '', '通用', '青年（18-44岁）', '涤纶100%', 'https://www.dot-st.com/georges/disp/item/669174/?COLOR_CD=05', '其他服饰/物品', '其他', '配件', '', 'accessories', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/george’s/20260401/item_669174_main_09_1774230874_b.jpg', 0, 0, 8, 0.76498, 0, 1, 0, 0, 0, 3, NULL, '防水，防晒，防紫外线，防尘，遮热，降温，遮光，高撥水性，耐水性，轻量化，折叠便携，防眩光/减弱反射光', '遮热,降温,遮光,高撥水性,耐水性,轻量化,折叠便携,防眩光/减弱反射光', '黑色PU涂层遮热技术,高遮光涂层技术,UPF50+防晒技术,高撥水整理,耐水压测试技术,热成像测试评估遮热效果', '晴雨两用设计，可同时应对强烈日晒和降雨环境,约190g的轻量化结构，收纳宽度约6cm，便于随身携带,展开直径约90cm，可为男性身高体型提供足够覆盖,配有登山扣，可挂在包袋上提升携带便利性,一键开合机构，使用操作简便顺畅,伞内侧黑色涂层可吸收约90%的光线反射，减少对皮肤的有害光线,面料通过多项JIS标准测试，量化遮热、遮光、UV和撥水性能,强调在高温炎热环境下减轻出汗量、提升体感舒适度', '纯色', '该产品为晴雨兼用折叠伞，属于穿搭配件类而非服装或家纺。列表中没有“umbrella”或雨具专门分类，最贴近的是统摄非服装小物的“accessories”。因此选择 sub_category 为“accessories”，即配饰类产品，用于日常遮阳、防雨搭配使用。', 1, 1, 0, 0, 'accessories', NULL, '', 0, NULL, 0, NULL, NULL, '09', 'BLK(09)', 0);
INSERT INTO `clothing_info` VALUES (19996422, '【晴雨两用/折叠伞】Wpc.IZA Light＆Slim', '[晴雨兼用/折畳み傘］Wpc.IZA Light＆Slim', 0, 200335, 'GEORGE’S', '', '', '约190g重量、收纳时横向宽度约6cm的轻量纤细折叠伞，在兼顾轻量的同时，展开时直径约90cm，足以为男性提供良好覆盖。附带登山扣，可直接挂在包袋上携带，一键开合，操作顺畅。\n\n凭借优异的遮热性能，显著降低体感温度。采用遮光率100%、UV阻隔率100%的面料，提供完备的紫外线防护。伞布内侧黑色涂层增强遮热效果，在炎炎烈日下体感温度明显下降。\n\n全色系均实现遮光率100%、UV阻隔率100%、UPF50+。伞内侧黑色涂层吸收大量光线反射，减轻由紫外线和可见光反射对肌肤造成的伤害，从而在强光环境下提供更舒适的使用体验。\n\n具备优异遮热性，在炎热、易出汗季节也能维持相对凉爽舒适，炎天下的使用可有效降低出汗量，提升体感舒适度。\n\n面料表面经过特殊整理，实现最高等级5级的撥水性，水滴容易滚落，减轻雨天使用时的负担。同时采用高耐水压面料，即使在较大雨量环境下也能提供可靠防护，但在暴雨或长时间使用时仍可能出现渗水风险。以上功能性数据均基于面料状态测试结果。', '重さ約190g/収納時の横幅約6cmと、大きさと軽量を兼ね備えたスリムなフォルム。<br>軽量でありながら、開いた時の直径は約90cmと男性でもしっかりカバーしてくれるサイズ感を実現。<br>カラビナ付きなのでバッグに取り付けることも可能。<br>ワンアクションでスムーズに開閉できます。<br><br><b>【暑さを凌いで、クールな日常へ。】</b><br>サーモグラフィ検査において、頭頂部表面温度差に14.7℃の差を実証。<br>※傘未使用時との比較（頭頂部）<br>環境：室温25℃×60%RH　照射強度：約800W/平方メートル（JIS L 1951遮熱試験同様強度）　照射時間：20分　照射距離：2.0m<br>試験試料：ポリエステル100％生地(オフホワイト色)/裏面黒色PUコーティング/親骨サイズ58cm<br>製品の種類・環境条件などにより遮熱効果は異なり、感じ方には個人差があります。<br><br>優れた遮熱性で、体感温度を大幅に低減。<br>遮光率・UVカット率100%で、紫外線対策も万全です。<br>生地裏面のコーティングにより、優れた遮熱効果を発揮。<br>炎天下でも、体感温度が大幅に下がります。<br><br><b>【涼感日傘】</b><br>全カラー、遮光率100％、UVカット率100％、UPF50＋を実現<br>※遮光率100％　検査方法：JIS L 1055 A法、生地の状態での測定値<br>※UVカット率100％　検査方法：JIS L 1925、生地の状態での測定値<br>※UPF50＋　検査方法：JIS L 1925、生地の状態での測定値<br><br>傘内側の黒コーティングが照り返しを90％吸収<br>傘の内側で起こる光の反射を大幅に減らして、肌にダメージを与える有害光線から、あなたを守る。<br>※直接肌に照り返された光を吸収するものではありません。<br>※光の反射は紫外線（UV-B・UV-A）・可視光線について測定。<br>※紫外線は紫外線吸収率(分光分析/紫外線(280~400)透過率・反射率より算出)、可視光線は可視光線吸収率(分光分析/可視光線(400~780)透過率・反射率より算出)に基づく。<br>※記載の数値は生地の状態で測定した数値をもとに記載しており、傘本体の性能を示す数値ではありません。<br><br><b>夏の大敵≪汗ばむ季節も、涼しく快適≫</b><br>遮熱性のある生地が、暑さをおさえます。※1<br>炎天下でも快適性をサポートします。<br>・日傘を使用していない場合の発汗量：14.1g ※2<br>・Wpc. IZA を使用した場合の発汗量：10.8g ※2<br><br><b>【雨の日にも、万全の備えを。】</b><br>最高等級の≪撥水力≫<br>生地表面に施した加工により、最高等級5級の撥水性を実現。水滴が転がりやすく、雨の日のストレスを軽減します。<br>・JIS L 1092の規定に準じて生地のはっ水度を測定しています。撥水等級は、最高レベルを5級、最低レベルを1級とした、撥水性の等級です。<br>※記載の結果は生地の状態での測定値であり、傘本体の性能を示す数値ではございません。<br><br>大雨にも耐える≪耐水性≫<br>大雨でも安心な、耐水圧を実現した生地を使用。<br>※激しい雨や長時間の雨傘としてのご使用は、雨漏りや生地に水がしみ込む恐れがございます。<br>またデザインの特性上、完全な防水はっ水加工が難しい場合があり、雨が染み込むことがありますのでご注意ください。<br>・JIS L 1092の規定に準じて生地の耐水度を測定しています。<br>※記載の結果は生地の状態での測定値であり、傘本体の性能を示す数値ではございません。<br>', '4200.0 JPY', 256.20, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:34:29', '2026-04-02 04:14:40', 'adastria_669174', '', '69cd72d3a7ab618f2967c93d', '生活/休闲', '', '通用', '青年（18-44岁）', '涤纶100%', 'https://www.dot-st.com/georges/disp/item/669174/?COLOR_CD=05', '其他服饰/物品', '其他', '配件', '', 'accessories', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/george’s/20260401/item_669174_main_10_1774230876_b.jpg', 0, 0, 8, 0.51732, 0, 1, 0, 0, 0, 3, NULL, '防水，防晒，防紫外线，防尘，遮热，降温，遮光，高撥水性，耐水性，轻量化，折叠便携，防眩光/减弱反射光', '遮热,降温,遮光,高撥水性,耐水性,轻量化,折叠便携,防眩光/减弱反射光', '黑色PU涂层遮热技术,高遮光涂层技术,UPF50+防晒技术,高撥水整理,耐水压测试技术,热成像测试评估遮热效果', '晴雨两用设计，可同时应对强烈日晒和降雨环境,约190g的轻量化结构，收纳宽度约6cm，便于随身携带,展开直径约90cm，可为男性身高体型提供足够覆盖,配有登山扣，可挂在包袋上提升携带便利性,一键开合机构，使用操作简便顺畅,伞内侧黑色涂层可吸收约90%的光线反射，减少对皮肤的有害光线,面料通过多项JIS标准测试，量化遮热、遮光、UV和撥水性能,强调在高温炎热环境下减轻出汗量、提升体感舒适度', '纯色', '该产品为晴雨兼用折叠伞，属于穿搭配件类而非服装或家纺。列表中没有“umbrella”或雨具专门分类，最贴近的是统摄非服装小物的“accessories”。因此选择 sub_category 为“accessories”，即配饰类产品，用于日常遮阳、防雨搭配使用。', 1, 2, 0, 0, 'accessories', NULL, '', 0, NULL, 0, NULL, NULL, '10', 'SIL(10)', 0);
INSERT INTO `clothing_info` VALUES (19996415, 'RIVERS Stout Air 550E 水壶', 'RIVERS スタウトエア 550E', 0, 200335, 'GEORGE’S', '', '', '专为“户外多种场景下的多样性和扩展性”而开发的 Stout Air 系列水壶。\n根据露营、登山、涉水活动等不同目的，可选择最适合的容量。550ml 为万能容量，一壶即可覆盖多种用途。\n\n瓶身采用名为“ECOZEN”的不含 BPA 的安全树脂材料，轻量且坚固，焚烧处理时不易提高 CO2 浓度，有助于碳中和，是当下户外领域备受关注的材料之一。可装酒精饮品和热水，在露营时还能作为咖啡壶使用。\n\n瓶盖配有硅胶提带，可用登山扣悬挂，减少丢失风险；在营地桌面空间有限时，也可以挂在雏菊链或天幕杆上使用。内部的防飞溅中盖能在行进间饮水时控制水流，防止液体猛然涌出。\n\n大容量款可在远离水源的营地作为水桶使用，也适合取用山泉水。瓶身带有刻度，烹饪时可直接量取用水。\n\nRivers 是专注“饮具”的日本品牌，围绕蓬勃发展的咖啡文化与户外活动，打造从日常基础水壶、马克杯到户外专用器具等多种产品，以精简的极简设计和丰富功能，深受露营爱好者和咖啡发烧友喜爱。', 'ーーー<br>アウトドアマン必携ボトル。<br>「アウトドアの様々なシーンに合わせたバリエーションと拡張性」をテーマに開発されたスタウトエアです。<br><br>一言でアウトドアと言っても、場所や目的によってドリンクボトルに求められる要素も大きく異なります。キャンプやマウンテニアリング、ウォーターアクティビティ。スタウトエアは目的別に最適な容量が選択可能です。<br>ーーー<br>400ml、550ml、1000mlの3サイズ展開<br>コンパクトな400mlは、ドリンクはもちろん、コーヒー豆やナッツなどの行動食を入れてフードコンテナとしても最適サイズ。550mlは万能サイズ。これ1本でどんな使い方も幅広くカバーできます。1000mlはより多くの水分が必要な夏のハイキングに最適です。<br><br><br><b>軽くて丈夫は必須条件</b><br>本体に使われる「ECOZEN」はBPAフリーの安全な樹脂素材。焼却処分したときでも、CO2 の濃度を上昇させにくく、カーボンニュートラルに貢献することができます。 頑丈且つ軽量なマテリアルで、今やアウトドアでは欠かせない人気素材のひとつです。<br><br><b>スタウトエアはアルコールや熱湯もOK。</b><br>1回で数人分淹れるキャンプでのコーヒータイムにはコーヒーサーバーとしても機能します。<br><br><b>アウトドアで重宝する機能</b><br>フタはシリコーンストラップ付きだから、カラビナでぶら下げてみたり、フタを紛失する心配もありません。テーブルスペースの限られるキャンプでは、デイジーチェーンやタープポールにぶら下げておくこともできます。<br><br>また、スプラッシュガード(中蓋)は移動しながらの水分補給に必須の機能。ボトルを傾けても水が勢いよく飛び出す事がありません。<br><br>1,000mlの大容量は、水場の遠いキャンプサイトでウォータージャグとして使用したり、湧き水を汲むのにも使えます。<br>ボディには目盛りがプリントされているので、調理時に水を計れるのもポイントです。<br><br><br><b>リバーズ / Rivers</b><br>リバーズは「ドリンクウェア」にフォーカスしたプロダクトを展開する日本のブランド。<br>世界的に盛り上がりを見せるコーヒーシーンやアウトドアアクティビティに向けた製品をはじめ、<br>普段使いに欠かせないベーシックなボトルやマグなど、使うごとに心地良さを感じられる道具を生み出しています。<br>削ぎ落とされたミニマルデザインでありつつも機能満載という意外性が魅力の製品は、<br>キャンパーやコーヒーギークを中心としたユーザー層に広がっています。<br><br><br>容量：550ml<br>耐熱温度：ボトル本体90℃、フタ･スプラッシュガード140℃<br>耐冷温度：－40℃<br>食洗機、電子レンジ：不可<br>※熱湯を入れた場合、ボトルが熱くなり、素手で触ると火傷する恐れがあります。熱湯を入れる場合は手袋を使用するか、タオルや手ぬぐいを巻いてご使用ください。', '1700.0 JPY', 103.70, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:34:32', '2026-04-02 04:14:34', 'adastria_351040', '', '69cd72d3a7ab618f2967c931', '露营，攀岩，徒步/登山', '', '通用', '青年（18-44岁）', NULL, 'https://www.dot-st.com/georges/disp/item/351040/?COLOR_CD=09', '其他服饰/物品', '其他', '配件', '', 'accessories', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/george’s/20260401/item_351040_main_09_1738661020_b.jpg', 0, 0, 9, 0.99626, 0, 1, 1, 0, 0, 3, NULL, '轻量，耐用，可装热水和酒精饮品，适合作为咖啡壶使用，容量刻度便于计量，防飞溅中盖设计，带硅胶提带便于悬挂，适合作为水桶/水壶使用', '轻量,耐用,可装热水和酒精饮品,适合作为咖啡壶使用,容量刻度便于计量,防飞溅中盖设计,带硅胶提带便于悬挂,适合作为水桶/水壶使用', 'ECOZEN环保树脂材料,不含BPA', '日本品牌，专注饮具产品,适用于咖啡场景和户外活动,设计简约但功能丰富,瓶身带刻度线，可用于烹饪配水', '文字', '该商品是Rivers品牌的户外水壶/饮水瓶，属于随身携带的小件用品，不是服装或家纺纺织品。在给定分类中最接近的是“accessories（配饰）”。虽然归类在厨房、餐桌用品大类，但本质是便携饮具，按服饰体系只能归入accessories。', 1, 0, 0, 0, 'accessories', NULL, '', 0, NULL, 0, NULL, NULL, '09', 'ブラック(09)', 0);
INSERT INTO `clothing_info` VALUES (19996416, 'RIVERS Stout Air 550E 水壶', 'RIVERS スタウトエア 550E', 0, 200335, 'GEORGE’S', '', '', '专为“户外多种场景下的多样性和扩展性”而开发的 Stout Air 系列水壶。\n根据露营、登山、涉水活动等不同目的，可选择最适合的容量。550ml 为万能容量，一壶即可覆盖多种用途。\n\n瓶身采用名为“ECOZEN”的不含 BPA 的安全树脂材料，轻量且坚固，焚烧处理时不易提高 CO2 浓度，有助于碳中和，是当下户外领域备受关注的材料之一。可装酒精饮品和热水，在露营时还能作为咖啡壶使用。\n\n瓶盖配有硅胶提带，可用登山扣悬挂，减少丢失风险；在营地桌面空间有限时，也可以挂在雏菊链或天幕杆上使用。内部的防飞溅中盖能在行进间饮水时控制水流，防止液体猛然涌出。\n\n大容量款可在远离水源的营地作为水桶使用，也适合取用山泉水。瓶身带有刻度，烹饪时可直接量取用水。\n\nRivers 是专注“饮具”的日本品牌，围绕蓬勃发展的咖啡文化与户外活动，打造从日常基础水壶、马克杯到户外专用器具等多种产品，以精简的极简设计和丰富功能，深受露营爱好者和咖啡发烧友喜爱。', 'ーーー<br>アウトドアマン必携ボトル。<br>「アウトドアの様々なシーンに合わせたバリエーションと拡張性」をテーマに開発されたスタウトエアです。<br><br>一言でアウトドアと言っても、場所や目的によってドリンクボトルに求められる要素も大きく異なります。キャンプやマウンテニアリング、ウォーターアクティビティ。スタウトエアは目的別に最適な容量が選択可能です。<br>ーーー<br>400ml、550ml、1000mlの3サイズ展開<br>コンパクトな400mlは、ドリンクはもちろん、コーヒー豆やナッツなどの行動食を入れてフードコンテナとしても最適サイズ。550mlは万能サイズ。これ1本でどんな使い方も幅広くカバーできます。1000mlはより多くの水分が必要な夏のハイキングに最適です。<br><br><br><b>軽くて丈夫は必須条件</b><br>本体に使われる「ECOZEN」はBPAフリーの安全な樹脂素材。焼却処分したときでも、CO2 の濃度を上昇させにくく、カーボンニュートラルに貢献することができます。 頑丈且つ軽量なマテリアルで、今やアウトドアでは欠かせない人気素材のひとつです。<br><br><b>スタウトエアはアルコールや熱湯もOK。</b><br>1回で数人分淹れるキャンプでのコーヒータイムにはコーヒーサーバーとしても機能します。<br><br><b>アウトドアで重宝する機能</b><br>フタはシリコーンストラップ付きだから、カラビナでぶら下げてみたり、フタを紛失する心配もありません。テーブルスペースの限られるキャンプでは、デイジーチェーンやタープポールにぶら下げておくこともできます。<br><br>また、スプラッシュガード(中蓋)は移動しながらの水分補給に必須の機能。ボトルを傾けても水が勢いよく飛び出す事がありません。<br><br>1,000mlの大容量は、水場の遠いキャンプサイトでウォータージャグとして使用したり、湧き水を汲むのにも使えます。<br>ボディには目盛りがプリントされているので、調理時に水を計れるのもポイントです。<br><br><br><b>リバーズ / Rivers</b><br>リバーズは「ドリンクウェア」にフォーカスしたプロダクトを展開する日本のブランド。<br>世界的に盛り上がりを見せるコーヒーシーンやアウトドアアクティビティに向けた製品をはじめ、<br>普段使いに欠かせないベーシックなボトルやマグなど、使うごとに心地良さを感じられる道具を生み出しています。<br>削ぎ落とされたミニマルデザインでありつつも機能満載という意外性が魅力の製品は、<br>キャンパーやコーヒーギークを中心としたユーザー層に広がっています。<br><br><br>容量：550ml<br>耐熱温度：ボトル本体90℃、フタ･スプラッシュガード140℃<br>耐冷温度：－40℃<br>食洗機、電子レンジ：不可<br>※熱湯を入れた場合、ボトルが熱くなり、素手で触ると火傷する恐れがあります。熱湯を入れる場合は手袋を使用するか、タオルや手ぬぐいを巻いてご使用ください。', '1700.0 JPY', 103.70, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:34:32', '2026-04-02 04:14:35', 'adastria_351040', '', '69cd72d3a7ab618f2967c931', '露营，攀岩，徒步/登山', '', '通用', '青年（18-44岁）', NULL, 'https://www.dot-st.com/georges/disp/item/351040/?COLOR_CD=09', '其他服饰/物品', '其他', '配件', '', 'accessories', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/george’s/20260401/item_351040_main_70_1738661068_b.jpg', 0, 0, 9, 0.99797, 0, 1, 1, 0, 0, 3, NULL, '轻量，耐用，可装热水和酒精饮品，适合作为咖啡壶使用，容量刻度便于计量，防飞溅中盖设计，带硅胶提带便于悬挂，适合作为水桶/水壶使用', '轻量,耐用,可装热水和酒精饮品,适合作为咖啡壶使用,容量刻度便于计量,防飞溅中盖设计,带硅胶提带便于悬挂,适合作为水桶/水壶使用', 'ECOZEN环保树脂材料,不含BPA', '日本品牌，专注饮具产品,适用于咖啡场景和户外活动,设计简约但功能丰富,瓶身带刻度线，可用于烹饪配水', '文字', '该商品是Rivers品牌的户外水壶/饮水瓶，属于随身携带的小件用品，不是服装或家纺纺织品。在给定分类中最接近的是“accessories（配饰）”。虽然归类在厨房、餐桌用品大类，但本质是便携饮具，按服饰体系只能归入accessories。', 1, 1, 0, 0, 'accessories', NULL, '', 0, NULL, 0, NULL, NULL, '70', 'オリーブ(70)', 0);
INSERT INTO `clothing_info` VALUES (19996417, '铝制花朵托盘', 'アルミフラワー トレイ', 0, 200335, 'GEORGE’S', '', '', '以花朵为主题的小托盘，可作为咖啡时间的杯托或盛放小点心的小盘，也适合作为饰品托盘或小物收纳盘使用。低调优雅的哑光色为餐桌增添点缀，既适合日常使用，也适用于待客和派对场合。可与同系列餐具搭配使用。', 'ーーー<br>お花をモチーフにした小さなトレイです。<br><br>カフェタイムのソーサーとしてや、ちょっとしたお菓子の小皿としても◎<br>アクセサリートレーや小物入れとしてもお使いいただけます。<br><br>上品なマットなカラーでテーブルのアクセントにもなり、<br>普段使いはもちろん、おもてなしやパーティーシーンなどにもおすすめ。<br>ーーー<br><br>同シリーズのカトラリーと揃えてお使いいただくのがおすすめです◎<br><br>※食洗機：不可<br>※電子レンジ：不可<br><br>※原材料の高騰のため、2025.7.1より価格改定をさせて頂きます。<br>商品タグに記載している価格につきまして、旧価格のものが混在している場合がございます。<br>ご了承下さいますよう、お願い申し上げます。', '1200.0 JPY', 73.20, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:34:32', '2026-04-02 04:14:36', 'adastria_351342', '', '69cd72d3a7ab618f2967c932', '生活/休闲', '', '通用', '青年（18-44岁）', 'アルミニウム100%', 'https://www.dot-st.com/georges/disp/item/351342/?COLOR_CD=10', '其他服饰/物品', '其他', '配件', '', 'accessories', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/george’s/20260401/item_351342_main_10_1740647707_b.jpg', 0, 0, 9, 0.99537, 0, 1, 0, 0, 0, 3, NULL, '装饰桌面，收纳小物件，盛放点心和小吃', '装饰桌面,收纳小物件,盛放点心和小吃', '', '花朵造型设计，具有装饰性,哑光金属质感，适合作为桌面点缀,可用作咖啡杯托盘、小皿或首饰托盘,不可使用洗碗机和微波炉', '纯色', '该产品是花形小托盘，用于放小点心、咖啡杯或饰品，属于家居配件类小物件，而不是服装或家纺主体。现有分类中没有专门的餐盘/托盘类条目，在服饰与配件相关的枚举里最接近的是“accessories（配饰/小物件）”。因此将其归为 sub_category: accessories，并将其理解为家居装饰与功能性小配件。', 1, 0, 0, 0, 'accessories', NULL, '', 0, NULL, 0, NULL, NULL, '10', 'ガーベラ シルバー(10)', 0);
INSERT INTO `clothing_info` VALUES (19996418, '铝制花朵托盘', 'アルミフラワー トレイ', 0, 200335, 'GEORGE’S', '', '', '以花朵为主题的小托盘，可作为咖啡时间的杯托或盛放小点心的小盘，也适合作为饰品托盘或小物收纳盘使用。低调优雅的哑光色为餐桌增添点缀，既适合日常使用，也适用于待客和派对场合。可与同系列餐具搭配使用。', 'ーーー<br>お花をモチーフにした小さなトレイです。<br><br>カフェタイムのソーサーとしてや、ちょっとしたお菓子の小皿としても◎<br>アクセサリートレーや小物入れとしてもお使いいただけます。<br><br>上品なマットなカラーでテーブルのアクセントにもなり、<br>普段使いはもちろん、おもてなしやパーティーシーンなどにもおすすめ。<br>ーーー<br><br>同シリーズのカトラリーと揃えてお使いいただくのがおすすめです◎<br><br>※食洗機：不可<br>※電子レンジ：不可<br><br>※原材料の高騰のため、2025.7.1より価格改定をさせて頂きます。<br>商品タグに記載している価格につきまして、旧価格のものが混在している場合がございます。<br>ご了承下さいますよう、お願い申し上げます。', '1200.0 JPY', 73.20, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:34:32', '2026-04-02 04:14:36', 'adastria_351342', '', '69cd72d3a7ab618f2967c932', '生活/休闲', '', '通用', '青年（18-44岁）', 'アルミニウム100%', 'https://www.dot-st.com/georges/disp/item/351342/?COLOR_CD=10', '其他服饰/物品', '其他', '配件', '', 'accessories', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/george’s/20260401/item_351342_main_60_1740647843_b.jpg', 0, 0, 9, 0.99271, 0, 1, 0, 0, 0, 3, NULL, '装饰桌面，收纳小物件，盛放点心和小吃', '装饰桌面,收纳小物件,盛放点心和小吃', '', '花朵造型设计，具有装饰性,哑光金属质感，适合作为桌面点缀,可用作咖啡杯托盘、小皿或首饰托盘,不可使用洗碗机和微波炉', '纯色', '该产品是花形小托盘，用于放小点心、咖啡杯或饰品，属于家居配件类小物件，而不是服装或家纺主体。现有分类中没有专门的餐盘/托盘类条目，在服饰与配件相关的枚举里最接近的是“accessories（配饰/小物件）”。因此将其归为 sub_category: accessories，并将其理解为家居装饰与功能性小配件。', 1, 1, 0, 0, 'accessories', NULL, '', 0, NULL, 0, NULL, NULL, '60', 'ポピー ゴールド(60)', 0);
INSERT INTO `clothing_info` VALUES (19996419, 'London Pottery 茶壶 2杯用 600ml', 'London Pottery ティーポット 2カップ 600ml', 0, 200335, 'GEORGE’S', '', '', '这是一款来自英国、在当地家庭长期受到喜爱的 London Pottery 茶壶，兼具圆润造型与高实用性。壶身轮廓饱满圆润，握持手感舒适，整体造型素朴且富有温暖气息。\n\n配有不锈钢茶滤，顶部小手柄造型精致，便于拆装。将特殊结构的茶滤（滤网）装入壶中后，茶滤与壶盖会同时被锁定，倾倒时壶盖不会滑落，使用更安心。\n\n材质为略带象牙色的白色素地，兼具瓷器外观与陶器特性，在较低温度烧成，使色釉和图案的发色效果良好，同时比一般陶器更轻。长期使用中表面可能出现细小裂纹纹理，但不影响正常使用。', 'ーーー<br>まるっこい形と、機能性の高さで、紅茶の国イギリスの家庭で長く愛されているロンドンポタリーのティーポットです。<br><br>ころんとした丸みを帯びたフォルムが手になじむ<br>素朴でぬくもりある TEA POT。<br><br>ステンレス製のティーストレーナー付き<br>オシャレなつまみ部分が脱着しやすく、ポットにセットするとロックされる仕組みになっています。<br>取り外し可能の特殊なストレーナー(フィルター)をセットするだけで、<br>ポットにも蓋にもロックがかかるので、傾けても蓋が落下してきません。<br><br>せっ器とは<br>少しアイボリーがかった磁器のような白い素地に、陶器のような性質を持ち合わせたせっ器は、<br>低めの1200から1250℃で焼かれるため、絵付けや色釉薬の顔料の発色が良く、陶器より軽量なのが特徴です。<br>経年により表面に細かいひびが入ってくることがありますが、ご使用には差し支えありません。<br>ーーー<br>※2カップ用 550ml<br>※最大容積600ml', '4200.0 JPY', 256.20, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:34:32', '2026-04-02 04:14:37', 'adastria_350942', '', '69cd72d3a7ab618f2967c934', '生活/休闲', '', '通用', '青年（18-44岁）', 'せっ器100%', 'https://www.dot-st.com/georges/disp/item/350942/?COLOR_CD=10', '其他服饰/物品', '其他', '配件', '', 'accessories', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/george’s/20260401/item_350942_main_10_1739169800_b.jpg', 0, 0, 9, 0.99064, 0, 1, -1, 0, 0, 3, NULL, '保温性能较好，便于过滤茶叶，壶盖不易滑落，轻量化材质', '保温性能较好,便于过滤茶叶,壶盖不易滑落,轻量化材质', '可拆卸锁定结构茶滤设计', '英国家庭长期使用的经典茶壶造型,圆润壶身造型，握持舒适,附带不锈钢茶滤，滤网可拆卸清洗,倾倒时壶盖和滤网会同时锁定，防止掉落,材质为略带象牙色的白色素地，兼具瓷器外观与陶器特性,低温烧成，色釉与图案发色效果好,较普通陶器更轻，日常使用负担小,长期使用表面可能出现细小开片纹理，不影响使用安全', '纯色', '该产品为“London Pottery”品牌 2 杯容量的 600ml 茶壶，属于厨房与餐桌用品，并非服装、家纺类纺织品。在本分类列表中没有专门的餐具或茶具类目，只能归入最接近的非服装类目“accessories（配件）”。在这里，“accessories”可理解为生活方式类附属用品，包含此类茶壶等非服装、非家纺产品。', 0, 0, 0, 0, 'accessories', NULL, '', 0, NULL, 0, NULL, NULL, '10', 'グレー(10)', 0);
INSERT INTO `clothing_info` VALUES (19996412, '【男款】尼龙彩色短裤【官网预售】', '【MENS】ナイロンカラーショーツ【WEB先行予約】', 0, 200335, 'GEORGE’S', '', '', '集功能性与时尚感于一体的尼龙短裤，采用去除多余装饰的极简设计，自然融入街头风格。可单穿搭配T恤打造随性造型，也可以外搭衬衫营造稍显干练的氛围。面料选用轻量且高耐久性的尼龙，具备出色的速干性能，无论是海边活动还是城市中突遇雨水，都能保持舒适干爽的穿着体验。内里全面采用高透气性的网眼材质，出汗时不粘身，持续保持清爽触感。左裤脚以刺绣方式呈现“General store good neighbors”字样，带来立体而精致的点缀，在简洁外观中展现存在感。腰部为松紧加抽绳设计，兼顾活动自如与贴合度，将都市的洗练感与海边的开阔氛围凝聚于一条混合风格短裤之中。', 'ーーー<br>機能性とファッション性を兼ね備えたナイロンショートパンツ<br>ーーー<br>無駄を削ぎ落としたミニマルなデザインは、ストリートシーンにも自然に溶け込みます。<br>Tシャツ一枚でラフに合わせても、シャツを羽織って少し綺麗めにまとめても、様になります。<br>素材には軽量で耐久性に優れたナイロンを採用。<br>速乾性にも優れており、海辺でのアクティビティはもちろん、突然の雨に見舞われることもある都会の日常でも快適な着心地をキープします。<br>さらに、裏地には通気性の高いメッシュ素材を全面に配し、汗をかいても肌に張り付かず、さらりとした質感を持続。<br>左裾には、ブランドのアイデンティティを示す「General store good neighbors」のメッセージを刺繍で施しました。<br>プリントではなく刺繍にすることで、立体感のある上品な仕上がりに。<br>シンプルでありながらも、確かな存在感を放ちます。<br>ウエストはゴム仕様に加え、ドローコードでサイズ調整が可能。<br>動きやすさとフィット感を両立しました。都会の洗練さと、海の開放感を一枚に凝縮した、まさにハイブリッドなショートパンツ。<br><br><br>', '6000.0 JPY', 366.00, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:34:45', '2026-04-02 04:14:31', 'adastria_676256', '', '69cd72d3a7ab618f2967c92e', '生活/休闲，水上运动', '', '男', '青年（18-44岁）', '锦纶100%', 'https://www.dot-st.com/georges/disp/item/676256/?COLOR_CD=30', '下装', '短裤', '短裤', '', 'shorts', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/george’s/20260401/item_676256_main_30_1774951896_b.jpg', 0, 0, 2, 0.98884, 0, 1, 1, 0, 0, 3, NULL, '速干，透气，耐久，轻量，舒适贴合', '耐久,轻量,舒适贴合', '', '男款宽松版型中裤长度，适合街头与海边双场景穿着,采用全尼龙面料，强调轻量与耐用性,内里使用全层网眼里衬，增强透气性并避免粘身,左裾有英文刺绣标语，增强品牌识别与立体感,腰部橡筋加抽绳结构，方便调节与提高活动自如度', '字母，文字', '从商品名称“ナイロンカラーショーツ”以及图片可以看出，这是男性穿着的中裤长度下装，裤腿较短、宽松，属于典型的短裤款式，对应子类为“shorts（短裤）”。此子类定义为：覆盖大腿上部、不及膝或略过膝的下装裤型，多用于日常或运动场景，本产品完全符合。', 1, 0, 0, 0, 'shorts', NULL, '', 0, NULL, 0, NULL, NULL, '30', 'レッド(30)', 0);
INSERT INTO `clothing_info` VALUES (19996413, '【男款】尼龙彩色短裤【官网预售】', '【MENS】ナイロンカラーショーツ【WEB先行予約】', 0, 200335, 'GEORGE’S', '', '', '集功能性与时尚感于一体的尼龙短裤，采用去除多余装饰的极简设计，自然融入街头风格。可单穿搭配T恤打造随性造型，也可以外搭衬衫营造稍显干练的氛围。面料选用轻量且高耐久性的尼龙，具备出色的速干性能，无论是海边活动还是城市中突遇雨水，都能保持舒适干爽的穿着体验。内里全面采用高透气性的网眼材质，出汗时不粘身，持续保持清爽触感。左裤脚以刺绣方式呈现“General store good neighbors”字样，带来立体而精致的点缀，在简洁外观中展现存在感。腰部为松紧加抽绳设计，兼顾活动自如与贴合度，将都市的洗练感与海边的开阔氛围凝聚于一条混合风格短裤之中。', 'ーーー<br>機能性とファッション性を兼ね備えたナイロンショートパンツ<br>ーーー<br>無駄を削ぎ落としたミニマルなデザインは、ストリートシーンにも自然に溶け込みます。<br>Tシャツ一枚でラフに合わせても、シャツを羽織って少し綺麗めにまとめても、様になります。<br>素材には軽量で耐久性に優れたナイロンを採用。<br>速乾性にも優れており、海辺でのアクティビティはもちろん、突然の雨に見舞われることもある都会の日常でも快適な着心地をキープします。<br>さらに、裏地には通気性の高いメッシュ素材を全面に配し、汗をかいても肌に張り付かず、さらりとした質感を持続。<br>左裾には、ブランドのアイデンティティを示す「General store good neighbors」のメッセージを刺繍で施しました。<br>プリントではなく刺繍にすることで、立体感のある上品な仕上がりに。<br>シンプルでありながらも、確かな存在感を放ちます。<br>ウエストはゴム仕様に加え、ドローコードでサイズ調整が可能。<br>動きやすさとフィット感を両立しました。都会の洗練さと、海の開放感を一枚に凝縮した、まさにハイブリッドなショートパンツ。<br><br><br>', '6000.0 JPY', 366.00, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:34:45', '2026-04-02 04:14:32', 'adastria_676256', '', '69cd72d3a7ab618f2967c92e', '生活/休闲，水上运动', '', '男', '青年（18-44岁）', '锦纶100%', 'https://www.dot-st.com/georges/disp/item/676256/?COLOR_CD=30', '下装', '短裤', '短裤', '', 'shorts', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/george’s/20260401/item_676256_main_09_1774951926_b.jpg', 0, 0, 6, 0.51366, 0, 1, 0, 0, 0, 3, NULL, '速干，透气，耐久，轻量，舒适贴合', '耐久,轻量,舒适贴合', '', '男款宽松版型中裤长度，适合街头与海边双场景穿着,采用全尼龙面料，强调轻量与耐用性,内里使用全层网眼里衬，增强透气性并避免粘身,左裾有英文刺绣标语，增强品牌识别与立体感,腰部橡筋加抽绳结构，方便调节与提高活动自如度', '字母，文字', '从商品名称“ナイロンカラーショーツ”以及图片可以看出，这是男性穿着的中裤长度下装，裤腿较短、宽松，属于典型的短裤款式，对应子类为“shorts（短裤）”。此子类定义为：覆盖大腿上部、不及膝或略过膝的下装裤型，多用于日常或运动场景，本产品完全符合。', 1, 1, 0, 0, 'shorts', NULL, '', 0, NULL, 0, NULL, NULL, '09', 'ブラック(09)', 0);
INSERT INTO `clothing_info` VALUES (19996414, '【男款】尼龙彩色短裤【官网预售】', '【MENS】ナイロンカラーショーツ【WEB先行予約】', 0, 200335, 'GEORGE’S', '', '', '集功能性与时尚感于一体的尼龙短裤，采用去除多余装饰的极简设计，自然融入街头风格。可单穿搭配T恤打造随性造型，也可以外搭衬衫营造稍显干练的氛围。面料选用轻量且高耐久性的尼龙，具备出色的速干性能，无论是海边活动还是城市中突遇雨水，都能保持舒适干爽的穿着体验。内里全面采用高透气性的网眼材质，出汗时不粘身，持续保持清爽触感。左裤脚以刺绣方式呈现“General store good neighbors”字样，带来立体而精致的点缀，在简洁外观中展现存在感。腰部为松紧加抽绳设计，兼顾活动自如与贴合度，将都市的洗练感与海边的开阔氛围凝聚于一条混合风格短裤之中。', 'ーーー<br>機能性とファッション性を兼ね備えたナイロンショートパンツ<br>ーーー<br>無駄を削ぎ落としたミニマルなデザインは、ストリートシーンにも自然に溶け込みます。<br>Tシャツ一枚でラフに合わせても、シャツを羽織って少し綺麗めにまとめても、様になります。<br>素材には軽量で耐久性に優れたナイロンを採用。<br>速乾性にも優れており、海辺でのアクティビティはもちろん、突然の雨に見舞われることもある都会の日常でも快適な着心地をキープします。<br>さらに、裏地には通気性の高いメッシュ素材を全面に配し、汗をかいても肌に張り付かず、さらりとした質感を持続。<br>左裾には、ブランドのアイデンティティを示す「General store good neighbors」のメッセージを刺繍で施しました。<br>プリントではなく刺繍にすることで、立体感のある上品な仕上がりに。<br>シンプルでありながらも、確かな存在感を放ちます。<br>ウエストはゴム仕様に加え、ドローコードでサイズ調整が可能。<br>動きやすさとフィット感を両立しました。都会の洗練さと、海の開放感を一枚に凝縮した、まさにハイブリッドなショートパンツ。<br><br><br>', '6000.0 JPY', 366.00, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:34:45', '2026-04-02 04:14:33', 'adastria_676256', '', '69cd72d3a7ab618f2967c92e', '生活/休闲，水上运动', '', '男', '青年（18-44岁）', '锦纶100%', 'https://www.dot-st.com/georges/disp/item/676256/?COLOR_CD=30', '下装', '短裤', '短裤', '', 'shorts', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/george’s/20260401/item_676256_main_80_1774951936_b.jpg', 0, 0, 2, 0.99655, 0, 1, 1, 0, 0, 3, NULL, '速干，透气，耐久，轻量，舒适贴合', '耐久,轻量,舒适贴合', '', '男款宽松版型中裤长度，适合街头与海边双场景穿着,采用全尼龙面料，强调轻量与耐用性,内里使用全层网眼里衬，增强透气性并避免粘身,左裾有英文刺绣标语，增强品牌识别与立体感,腰部橡筋加抽绳结构，方便调节与提高活动自如度', '字母，文字', '从商品名称“ナイロンカラーショーツ”以及图片可以看出，这是男性穿着的中裤长度下装，裤腿较短、宽松，属于典型的短裤款式，对应子类为“shorts（短裤）”。此子类定义为：覆盖大腿上部、不及膝或略过膝的下装裤型，多用于日常或运动场景，本产品完全符合。', 1, 2, 0, 0, 'shorts', NULL, '', 0, NULL, 0, NULL, NULL, '80', 'ブルー(80)', 0);
INSERT INTO `clothing_info` VALUES (19996408, '【男装】刺绣巴拿马衬衫【官网预售】', '【MENS】刺繍パナマシャツ【WEB先行予約】', 0, 200335, 'GEORGE’S', '', '', '采用具有类似亚麻风格质感的面料，并以精巧的佩斯利刺绣为亮点的巴拿马衬衫。选用通气性优异的材质，在炎热季节也能保持舒适的上身体验。衣身两侧大胆的刺绣图案，营造出精致成熟的度假风格，一件就能打造出富有存在感的造型。', 'ーーー<br>リネンライクな風合いと精巧なペイズリー刺繍が際立つ、パナマシャツ。<br>ーーー<br>通気性に優れた素材を使用し、暑い季節でも快適な着心地を提供します。<br>両サイドに施された大胆な刺繍が、洗練された大人のリゾートスタイルを演出。<br>一枚でサマになる存在感のある一着です。<br>', '7000.0 JPY', 427.00, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:34:46', '2026-04-02 04:14:28', 'adastria_676263', '', '69cd72d3a7ab618f2967c921', '生活/休闲', '', '男', '青年（18-44岁）', '棉93%,亚麻7%', 'https://www.dot-st.com/georges/disp/item/676263/?COLOR_CD=05', '上装', '衬衫', '休闲衬衫', '', 'casual shirt', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/george’s/20260401/item_676263_main_05_1774952125_b.jpg', 0, 0, 6, 0.97649, 0, 1, 1, 0, 0, 3, NULL, '透气，舒适穿着感', '舒适穿着感', '', '采用类似亚麻质感的面料，适合夏季佩戴,两侧大面积精巧佩斯利刺绣，视觉存在感强，度假风格明显,宽松版型短袖设计，便于散热和活动', '佩斯利', '从商品名“パナマシャツ（巴拿马衬衫）”及图片看，这是男士宽松版、有领、前开襟的短袖衬衫，用于日常与度假穿着，属于非正式场合的衬衫，因此选择“casual shirt（休闲衬衫）”。该类别指日常休闲场合穿着的衬衫类上衣。', 1, 0, 0, 0, 'casual shirt', NULL, '', 0, NULL, 0, NULL, NULL, '05', 'オフ(05)', 0);
INSERT INTO `clothing_info` VALUES (19996409, '【男装】刺绣巴拿马衬衫【官网预售】', '【MENS】刺繍パナマシャツ【WEB先行予約】', 0, 200335, 'GEORGE’S', '', '', '采用具有类似亚麻风格质感的面料，并以精巧的佩斯利刺绣为亮点的巴拿马衬衫。选用通气性优异的材质，在炎热季节也能保持舒适的上身体验。衣身两侧大胆的刺绣图案，营造出精致成熟的度假风格，一件就能打造出富有存在感的造型。', 'ーーー<br>リネンライクな風合いと精巧なペイズリー刺繍が際立つ、パナマシャツ。<br>ーーー<br>通気性に優れた素材を使用し、暑い季節でも快適な着心地を提供します。<br>両サイドに施された大胆な刺繍が、洗練された大人のリゾートスタイルを演出。<br>一枚でサマになる存在感のある一着です。<br>', '7000.0 JPY', 427.00, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:34:46', '2026-04-02 04:14:29', 'adastria_676263', '', '69cd72d3a7ab618f2967c921', '生活/休闲', '', '男', '青年（18-44岁）', '棉93%,亚麻7%', 'https://www.dot-st.com/georges/disp/item/676263/?COLOR_CD=05', '上装', '衬衫', '休闲衬衫', '', 'casual shirt', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/george’s/20260401/item_676263_main_15_1774952114_b.jpg', 0, 0, 2, 0.99531, 0, 1, 1, 0, 0, 3, NULL, '透气，舒适穿着感', '舒适穿着感', '', '采用类似亚麻质感的面料，适合夏季佩戴,两侧大面积精巧佩斯利刺绣，视觉存在感强，度假风格明显,宽松版型短袖设计，便于散热和活动', '佩斯利', '从商品名“パナマシャツ（巴拿马衬衫）”及图片看，这是男士宽松版、有领、前开襟的短袖衬衫，用于日常与度假穿着，属于非正式场合的衬衫，因此选择“casual shirt（休闲衬衫）”。该类别指日常休闲场合穿着的衬衫类上衣。', 1, 1, 0, 0, 'casual shirt', NULL, '', 0, NULL, 0, NULL, NULL, '15', 'チャコールグレー(15)', 0);
INSERT INTO `clothing_info` VALUES (19996410, '【男装】总花度假衬衫【官网预售】', '【MENS】ソウガラシャツ【WEB先行予約】', 0, 200335, 'GEORGE’S', '', '', '兼具都市感与放松氛围的男士都市度假风衬衫。低调又有层次的配色，不仅适合海边，也能自然融入城市环境，营造有品位的度假风造型。面料轻盈飘逸，不易黏身，炎热季节也能保持一整天的舒适穿着体验。适度宽松的剪裁可以修饰身形，同时呈现利落印象。可与西裤或休闲长裤搭配，打造轻松又不失格调的成年休闲造型；搭配短裤则瞬间呈现度假感十足的风格。', 'ーーー<br>都会的なムードとリラックス感を両立させた、大人のためのアーバンリゾートシャツ。<br>ーーー<br>派手すぎない絶妙な配色が、海辺だけでなく街中にも馴染む「品のあるリゾートスタイル」を演出します。<br>風をはらむ軽やかな質感が、暑い季節でもベタつきにくく、一日中快適な着心地をキープします。<br>程よくゆとりを持たせたシルエットが、体型をカバーしつつスマートな印象を与えます。<br>スラックスやチノパンと合わせれば、程よく力の抜けた大人のカジュアルアップに。<br>ショートパンツと合わせれば、一気にバカンスモード全開のスタイルが完成します。<br>', '6350.0 JPY', 387.35, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:34:46', '2026-04-02 04:14:30', 'adastria_676262', '', '69cd72d3a7ab618f2967c926', '生活/休闲，差旅/商务', '', '男', '青年（18-44岁）', '涤纶100%', 'https://www.dot-st.com/georges/disp/item/676262/?COLOR_CD=05', '上装', '衬衫', '休闲衬衫', '', 'casual shirt', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/george’s/20260401/item_676262_main_05_1774952014_b.jpg', 0, 0, 2, 0.98662, 0, 1, 1, 0, 0, 3, NULL, '透气，遮肉显瘦，舒适穿着感', '遮肉显瘦,舒适穿着感', '', '都市度假风格印花设计,版型宽松，轮廓感强,适合与休闲长裤或短裤搭配', '花卉图案，树，风景', '从商品名“ソウガラシャツ”和图片可以看出，这是一件男装短袖开襟衬衫，前门襟有纽扣，具备典型衬衫结构，属于日常休闲场景穿着，因此选择“casual shirt（休闲衬衫）”最为合适。casual shirt 指的是用于日常休闲穿着的衬衫款式，一般采用舒适面料和宽松剪裁，并带有印花或图案。', 1, 0, 0, 0, 'casual shirt', NULL, '', 0, NULL, 0, NULL, NULL, '05', 'オフ(05)', 0);
