INSERT INTO `clothing_info` VALUES (19996405, '【雨伞/长伞】Wpc. 竹柄透明伞', '［雨傘/長傘］Wpc.バンブーハンドルビニール傘', 0, 200335, 'GEORGE’S', '', '', '这是一款人气很高、抗风性能出色的16骨时尚透明伞。采用16根伞骨，结构宽阔，具有优异的抗风性，多骨伞特有的优美轮廓在收伞时也能保持利落挺括。伞柄为有节竹制手柄，握感舒适，在简约造型中增添优雅气质。伞骨部分采用轻盈且不易折断、强度高的玻璃纤维材料，设计为可长久使用的不一次性透明伞。为手动开合式手开伞，在开合动作间呈现出优雅气质，即使在空间狭小或人群密集的环境也能轻巧地开合。', 'ーーー<br><b>大人気！風に強い16本骨のおしゃれなビニール傘。</b><br>風に強い16本骨のビニール傘。<br>節があって持ちやすいバンブーハンドルは、シンプルながらも上品な印象を演出します。<br>ーーー<br><b>【風に強い16本骨】</b><br>16本骨傘は骨の数が多く幅広な構造で、耐風性に優れているのが特徴。<br>多骨ならではの美しいシルエットも魅力で、閉じる際もすっきりとスマートにまとめることができます。<br><br><b>【長く使えるビニール傘】</b><br>Wpc.のビニール傘は骨の一部に軽くて折れにくく、強度の高いグラスファイバーを使用しています。<br>愛着を持って大切に長く使っていただける、使い捨てにしないビニール傘です。<br><br><b>≪開閉方法≫</b><br>手動で開ける手開き式。<br>開閉時の動作に上品さを感じられ、狭い場所や近くに人がいる場合でもそっと開閉できます。<br>', '2900.0 JPY', 176.90, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:34:47', '2026-04-02 04:14:26', 'adastria_669184', '', '69cd72d3a7ab618f2967c91a', '生活/休闲', '', '通用', '青年（18-44岁）', 'ポリエチレン100%', 'https://www.dot-st.com/georges/disp/item/669184/?COLOR_CD=51', '其他服饰/物品', '其他', '配件', '', 'accessories', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/george’s/20260401/item_669184_main_51_1774231307_b.jpg', 0, 0, 9, 0.98170, 0, 1, 1, 0, 0, 3, NULL, '防水，防风，耐用，轻量', '防风,耐用,轻量', '玻璃纤维伞骨增强结构', '16骨结构设计，提高抗风性和伞面张力,采用部分玻璃纤维伞骨，具有轻量且不易折断的特点,透明/半透明伞面，便于雨天视野观察,竹节造型手柄，提升握持舒适度与美观度,手动开合结构，便于在狭小空间内安静开合', '纯色，纯色', '该商品为长柄雨伞，并非服装或家纺类，而是穿搭配件中的功能性配饰，最接近列表中的“accessories”（配饰）类别。accessories 的定义：用于搭配或辅助穿着的非服装主体产品，如伞、帽子、包等。本品为雨具配饰，故归为 accessories。', 1, 0, 0, 0, 'accessories', NULL, '', 0, NULL, 0, NULL, NULL, '51', 'ブラウン(51)', 0);
INSERT INTO `clothing_info` VALUES (19996406, '【雨伞/长伞】Wpc. 竹柄透明伞', '［雨傘/長傘］Wpc.バンブーハンドルビニール傘', 0, 200335, 'GEORGE’S', '', '', '这是一款人气很高、抗风性能出色的16骨时尚透明伞。采用16根伞骨，结构宽阔，具有优异的抗风性，多骨伞特有的优美轮廓在收伞时也能保持利落挺括。伞柄为有节竹制手柄，握感舒适，在简约造型中增添优雅气质。伞骨部分采用轻盈且不易折断、强度高的玻璃纤维材料，设计为可长久使用的不一次性透明伞。为手动开合式手开伞，在开合动作间呈现出优雅气质，即使在空间狭小或人群密集的环境也能轻巧地开合。', 'ーーー<br><b>大人気！風に強い16本骨のおしゃれなビニール傘。</b><br>風に強い16本骨のビニール傘。<br>節があって持ちやすいバンブーハンドルは、シンプルながらも上品な印象を演出します。<br>ーーー<br><b>【風に強い16本骨】</b><br>16本骨傘は骨の数が多く幅広な構造で、耐風性に優れているのが特徴。<br>多骨ならではの美しいシルエットも魅力で、閉じる際もすっきりとスマートにまとめることができます。<br><br><b>【長く使えるビニール傘】</b><br>Wpc.のビニール傘は骨の一部に軽くて折れにくく、強度の高いグラスファイバーを使用しています。<br>愛着を持って大切に長く使っていただける、使い捨てにしないビニール傘です。<br><br><b>≪開閉方法≫</b><br>手動で開ける手開き式。<br>開閉時の動作に上品さを感じられ、狭い場所や近くに人がいる場合でもそっと開閉できます。<br>', '2900.0 JPY', 176.90, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:34:47', '2026-04-02 04:14:26', 'adastria_669184', '', '69cd72d3a7ab618f2967c91a', '生活/休闲', '', '通用', '青年（18-44岁）', 'ポリエチレン100%', 'https://www.dot-st.com/georges/disp/item/669184/?COLOR_CD=51', '其他服饰/物品', '其他', '配件', '', 'accessories', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/george’s/20260401/item_669184_main_01_1774231305_b.jpg', 0, 0, 9, 0.93721, 0, 1, 1, 0, 0, 3, NULL, '防水，防风，耐用，轻量', '防风,耐用,轻量', '玻璃纤维伞骨增强结构', '16骨结构设计，提高抗风性和伞面张力,采用部分玻璃纤维伞骨，具有轻量且不易折断的特点,透明/半透明伞面，便于雨天视野观察,竹节造型手柄，提升握持舒适度与美观度,手动开合结构，便于在狭小空间内安静开合', '纯色，纯色', '该商品为长柄雨伞，并非服装或家纺类，而是穿搭配件中的功能性配饰，最接近列表中的“accessories”（配饰）类别。accessories 的定义：用于搭配或辅助穿着的非服装主体产品，如伞、帽子、包等。本品为雨具配饰，故归为 accessories。', 1, 1, 0, 0, 'accessories', NULL, '', 0, NULL, 0, NULL, NULL, '01', 'クリア(01)', 0);
