INSERT INTO `clothing_info` VALUES (19996401, '【新增配色】褶皱设计女式衬衫/网上预售款', '【新色追加】タックデザインブラウス/WEB先行予約', 0, 200336, 'A part by', '', '', '这是一款兼顾通勤与休闲场合的百搭衬衫上衣，不挑下装。整体轮廓宽松舒适，但通过腰部的设计褶皱修饰身形，营造利落显瘦的效果。\n\n袖子加入飘逸的装饰片，呈现柔美女性化气质，同时起到遮掩上臂的作用。后中有纽扣开口，便于套头穿脱。\n\n面料在挺括感和垂坠感之间取得平衡，表面带有细腻的微微凹凸质感。下摆自然散开、富有分量感，非常适合外穿造型穿搭，不论搭配哪种下装都能轻松应对多种场合。', 'ーーー<br>オンオフ兼用でボトムス選ばずに着れる万能ブラウス<br>ゆったりとしたサイズ感なのにスタイルアップ効果◎<br>ーーー<br><br>【デザインと特徴】<br>ONでもOFFでもしっかり着映えのするオールマイティなブラウス。<br>全体的にゆったりとしたサイズ感で着心地がいいのにもかかわらず、<br>ウエストのデザインタックによってシャープにスタイル良く見せてくれます。<br><br>袖はひらひらとしたパーツを付けていてフェミニンな印象に仕上げつつ、二の腕カバーが叶います。<br><br>後ろ中心に釦開きがあり、かぶりで着脱可能です。<br><br>【素材特徴】<br>ハリ感と落ち感のバランスが良く、表面感が少しぽこぽこした表情のある生地です。<br><br>【スタイリング】<br>裾がひらひらとしており、ボリュームがあるため<br>アウトスタイルで着たい方におすすめです◎<br><br>ボトムス選ばず、オンオフ兼用で使える万能アイテムです。<br><br>【洗濯可否】<br>洗濯機での洗濯が可能です。', '9500.0 JPY', 579.50, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:36:35', '2026-04-02 04:14:22', 'adastria_321276', '', '69cd72d3a7ab618f2967c915', '生活/休闲', '', '女', '青年（18-44岁）', '粘胶91%,锦纶9%', 'https://www.dot-st.com/apartbylowrys/disp/item/321276/?COLOR_CD=05', '上装', '衬衫', '女式衬衫', '', 'blouse', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/a_part_by/20260401/item_321276_main_05_1774436840_b.jpg', 0, 0, 6, 0.73871, 0, 1, 1, 0, 0, 3, NULL, '修饰身形，遮掩上臂，易打理，适合通勤与休闲多场合', '修饰身形,遮掩上臂,易打理,适合通勤与休闲多场合', '', '腰部设计褶提升显瘦效果,袖口带有飘逸装饰片增强女性化风格,面料兼具一定挺括感和垂坠感,布面有轻微凹凸颗粒感,后中开扣设计，方便套头穿脱,下摆有较大摆量，适合外穿造型', '纯色', '从版型和描述看，这是女装上衣，带有设计感褶皱、飘逸袖片与较大摆量，下装不限且强调“オンオフ兼用で着映えする万能ブラウス”，明显属于日常与通勤皆可的时尚衬衫/上衣款，而非针织衫或T恤。综合判断最合适的类别为“blouse（女式衬衫/时装上衣）”，其定义为以时装感剪裁与细节为主、适合通勤与日常的非针织上衣。', 1, 0, 0, 0, 'blouse', NULL, '', 0, NULL, 0, NULL, NULL, '05', 'オフホワイト 05', 0);
INSERT INTO `clothing_info` VALUES (19996402, '【新增配色】褶皱设计女式衬衫/网上预售款', '【新色追加】タックデザインブラウス/WEB先行予約', 0, 200336, 'A part by', '', '', '这是一款兼顾通勤与休闲场合的百搭衬衫上衣，不挑下装。整体轮廓宽松舒适，但通过腰部的设计褶皱修饰身形，营造利落显瘦的效果。\n\n袖子加入飘逸的装饰片，呈现柔美女性化气质，同时起到遮掩上臂的作用。后中有纽扣开口，便于套头穿脱。\n\n面料在挺括感和垂坠感之间取得平衡，表面带有细腻的微微凹凸质感。下摆自然散开、富有分量感，非常适合外穿造型穿搭，不论搭配哪种下装都能轻松应对多种场合。', 'ーーー<br>オンオフ兼用でボトムス選ばずに着れる万能ブラウス<br>ゆったりとしたサイズ感なのにスタイルアップ効果◎<br>ーーー<br><br>【デザインと特徴】<br>ONでもOFFでもしっかり着映えのするオールマイティなブラウス。<br>全体的にゆったりとしたサイズ感で着心地がいいのにもかかわらず、<br>ウエストのデザインタックによってシャープにスタイル良く見せてくれます。<br><br>袖はひらひらとしたパーツを付けていてフェミニンな印象に仕上げつつ、二の腕カバーが叶います。<br><br>後ろ中心に釦開きがあり、かぶりで着脱可能です。<br><br>【素材特徴】<br>ハリ感と落ち感のバランスが良く、表面感が少しぽこぽこした表情のある生地です。<br><br>【スタイリング】<br>裾がひらひらとしており、ボリュームがあるため<br>アウトスタイルで着たい方におすすめです◎<br><br>ボトムス選ばず、オンオフ兼用で使える万能アイテムです。<br><br>【洗濯可否】<br>洗濯機での洗濯が可能です。', '9500.0 JPY', 579.50, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:36:35', '2026-04-02 04:14:23', 'adastria_321276', '', '69cd72d3a7ab618f2967c915', '生活/休闲', '', '女', '青年（18-44岁）', '粘胶91%,锦纶9%', 'https://www.dot-st.com/apartbylowrys/disp/item/321276/?COLOR_CD=05', '上装', '衬衫', '女式衬衫', '', 'blouse', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/a_part_by/20260401/item_321276_main_82_1774591337_b.jpg', 0, 0, 6, 0.67095, 0, 1, 1, 0, 0, 3, NULL, '修饰身形，遮掩上臂，易打理，适合通勤与休闲多场合', '修饰身形,遮掩上臂,易打理,适合通勤与休闲多场合', '', '腰部设计褶提升显瘦效果,袖口带有飘逸装饰片增强女性化风格,面料兼具一定挺括感和垂坠感,布面有轻微凹凸颗粒感,后中开扣设计，方便套头穿脱,下摆有较大摆量，适合外穿造型', '纯色', '从版型和描述看，这是女装上衣，带有设计感褶皱、飘逸袖片与较大摆量，下装不限且强调“オンオフ兼用で着映えする万能ブラウス”，明显属于日常与通勤皆可的时尚衬衫/上衣款，而非针织衫或T恤。综合判断最合适的类别为“blouse（女式衬衫/时装上衣）”，其定义为以时装感剪裁与细节为主、适合通勤与日常的非针织上衣。', 1, 1, 0, 0, 'blouse', NULL, '', 0, NULL, 0, NULL, NULL, '82', 'NEWライトブルー 82', 0);
