INSERT INTO `clothing_info` VALUES (19996398, '亚麻混高领针织无袖上衣/官网预售', 'リネンコンハイネックニットノースリーブ/WEB先行予約', 0, 200336, 'A part by', '', '', '贴合身形的无袖针织上衣，勾勒利落的身体线条。身片具有蓬松感与立体感，呈现可爱的杢调视觉效果，小高领设计增添干练气质。面料由人造丝带来的适度光泽感营造出优雅印象，结合亚麻的清爽触感，整体轻盈且穿着凉爽。适合通勤时与直筒裤、夹克搭配打造干练造型，也适合出游时与蓬松裙装组合营造度假氛围。', 'ーーー<br>・ピタッと体に沿うシルエットがきれいなノースリーブニット。<br>ーーー<br><br>【デザインと特徴】									<br>・身頃はふくらみと立体感があり、杢調の表面感がかわいい素材感です。				<br>・プチハイネッでかっこよく決まるアイテムです				<br><br>【素材特徴】											<br>・ヴィスコースが生み出すほどよい光沢感で上品な印象				<br>・リネンのしゃりみで涼しげな素材感				<br>・軽い着用感に仕上がっています				<br><br>【スタイリング】<br>お仕事シーン…ストレートパンツと、ジャケット合わせのハンサムコーデに。<br>お出かけシーン…ボリュームスカート合わせでリゾートコーデに。<br>', '7500.0 JPY', 457.50, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:36:40', '2026-04-02 04:14:20', 'adastria_668104', '', '69cd72d3a7ab618f2967c911', '生活/休闲，差旅/商务', '', '女', '青年（18-44岁）', '棉39%,亚麻19%', 'https://www.dot-st.com/apartbylowrys/disp/item/668104/?COLOR_CD=52', '上装', '背心', '背心', '', 'tank top', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/a_part_by/20260401/item_668104_main_52_1774597118_b.jpg', 0, 0, 1, 0.69305, 0, -2, 0, 0, 0, 3, NULL, '透气，轻盈，凉爽触感，显瘦修身', '轻盈,凉爽触感,显瘦修身', '', '无袖高领设计，贴合身形，适合内搭或单穿,混纺人造丝、棉和亚麻，兼具光泽感与清爽感,表面具有杢调效果和立体感，增加视觉层次', '纯色，纯色', '该单品为女装针织无袖上衣，覆盖躯干、露出肩部和手臂，设计重点在于作为上装穿着而非内衣，整体版型贴身但仍属外穿上衣范畴。从结构和用途看，应归入“tank top（背心/无袖上衣）”类，而非T恤、衬衫等其他上衣类别。tank top 的定义是无袖、肩带较宽、贴身或略宽松的上身服装，本款商品正符合这一特征。', 1, 0, 0, 0, 'tank top', NULL, '', 0, NULL, 0, NULL, NULL, '52', 'ライトベージュ(52)', 0);
