INSERT INTO `clothing_info` VALUES (19996366, '颜料染色亨利领T恤', 'ピグメントヘンリーネックＴ', 0, 31749817, 'LAKOLE', '', '', '采用颜料加工，呈现自然褪色感的亨利领上衣。虽为纯色设计，但面料质感突出，具有存在感。前襟纽扣可开合，便于调节内搭露出程度和整体休闲感。略微宽松的轮廓带来放松的穿着体验，面料柔软、贴肤舒适，与牛仔裤、工装裤等休闲单品搭配效果良好，女性穿着成宽松廓形也同样好看。', 'ーーー<br>ピグメント加工のフェード感が特徴的なカットソー。<br>無地ですが風合いが良くが存在感があります。<br>ボタンを開け閉めすることでインナーの見せ具合やラフ感を調整できるのもポイント。<br>ややゆったりとしたシルエットでリラックス感のある着こなしができます。<br>ーーー<br><br>【素材】<br>柔らかく肌触りの良い素材。<br><br>【スタイリング】<br>デニムやカーゴパンツなどカジュアルなアイテムと相性が良いです。<br>女性が大きめに着てもかわいくきまります。', '3173.0 JPY', 193.55, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:39:07', '2026-04-02 04:13:53', 'adastria_571783', '', '69cd72d3a7ab618f2967c90a', '生活/休闲', '', '通用', '青年（18-44岁）', '棉100%', 'https://www.dot-st.com/lakole/disp/item/571783/?COLOR_CD=15', '上装', 'T恤', '亨利衫', '', 'henley shirt', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/lakole/20260401/item_571783_main_15_1750667542_b.jpg', 0, 0, 2, 0.82148, 0, 1, 1, 0, 0, 3, NULL, '舒适亲肤，宽松版型便于活动', '舒适亲肤,宽松版型便于活动', '', '使用拼接门襟与纽扣设计的亨利领样式,经过颜料染色/水洗处理，呈现褪色感与做旧效果,版型略微宽松，营造休闲放松风格,单穿或与内搭叠穿都适合的设计', '纯色', '根据商品名“ピグメントヘンリーネックＴ”以及图片，可以确认这是带有纽扣门襟的亨利领T恤，上身为针织单面汗布类上衣，不是衬衫类织布。与列表中“henley shirt”（亨利领上衣）定义：前中心有短门襟与纽扣、类似T恤但有开襟设计的上衣，最为吻合，因此选择 sub_category = \"henley shirt\"。', 0, 0, 0, 0, 'henley shirt', NULL, '', 0, NULL, 0, NULL, NULL, '15', 'グレー(15)', 0);
INSERT INTO `clothing_info` VALUES (19996353, '怀中饼 甜酱油 / 黄豆粉 / 原味', 'ふところ餅 みたらし醤油/きなこ/プレーン', 0, 31749817, 'LAKOLE', '', '', '爱知县知多半岛的名点“怀中饼”，常温下也能保持柔软有嚼劲，带来温和的甜味。内含甜酱油味、黄豆粉味和原味三种组合，可以品尝多种风味。表面出现的斑点来源于原材料本身，不影响品质。', 'ーーー<br>愛知県知多半島の名菓、ふところ餅。<br>常温のままでももちっと柔らかく、やさしい甘みを味わえます。<br>みたらし醤油味、きなこ味、プレーン味の3種アソートになっているので、色々な味を楽しめます◎<br>ーーー<br><br>※お餅表面の斑点は原材料由来によるものですので、品質に問題はございません。<br><br>【内容量】<br>8個<br><br>【保存方法】<br>直射日光・高温多湿を避けて保存して下さい。', '330.0 JPY', 20.13, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:39:41', '2026-04-02 04:13:42', 'adastria_679299', '', '69cd72d3a7ab618f2967c909', '生活/休闲', '', '通用', '青年（18-44岁）', NULL, 'https://www.dot-st.com/lakole/disp/item/679299/?COLOR_CD=26', '其他服饰/物品', '其他', '配件', '', 'accessories', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/lakole/20260401/item_679299_main_26_1774602000_b.jpg', 0, 0, 9, 0.99081, 0, -1, 0, 0, 0, 3, NULL, '', '', '', '日本传统甜点食品，常温下口感柔软有嚼劲,包含みたらし酱油、黄豆粉和原味三种口味组合,原材料主要为国产粳米米粉、砂糖、小麦粉、盐、大豆制黄豆粉和酱油,表面斑点为原料自然形成，不影响品质,需避开直射阳光及高温多湿环境保存', '纯色，纯色', '商品是“ふところ餅”等和菓子零食，属于食品杂货，不是服装或家纺类，只能在给定列表中选择最接近的非服装硬类目，因此选用泛用度最高的“accessories”作为归类。accessories 在此理解为附属类商品/杂项，较其他服装子类更合适。', 0, 0, 0, 0, 'accessories', NULL, '', 0, NULL, 0, NULL, NULL, '26', 'ふところ餅 みたらし醤油/きなこ/プレーン', 0);
INSERT INTO `clothing_info` VALUES (19996336, '蝴蝶结雪纺发圈【部分门店限定商品】', 'リボン付きシフォンシュシュ[一部店舗限定アイテム]', 0, 31749817, 'LAKOLE', '', '', '以蝴蝶结为亮点的发圈，采用雪纺材质，设计优雅，只需随手一扎即可完成华丽的发型搭配。', 'ーーー<br>リボンがポイントのシュシュ。<br>シフォン素材で上品なデザインのアイテムです。<br>サッと結ぶだけで華やかなヘアアレンジが完成します。<br>ーーー', '300.0 JPY', 18.30, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:40:47', '2026-04-02 04:13:27', 'adastria_291488', '', '69cd72d3a7ab618f2967c908', '生活/休闲', '', '通用', '青年（18-44岁）', '涤纶100%', 'https://www.dot-st.com/lakole/disp/item/291488/?COLOR_CD=11', '其他服饰/物品', '其他', '配件', '', 'accessories', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/lakole/20260401/item_291488_main_11_1739843607_b.jpg', 0, 0, 1, 0.99097, 0, -2, 0, 0, 0, 3, NULL, '装饰造型，固定头发', '装饰造型,固定头发', '', '配有细长蝴蝶结丝带，增强女性化气质,采用轻薄雪纺材质，视觉上柔软轻盈,一部分店铺限定发饰款式', '纯色，纯色', '该商品为“リボン付きシフォンシュシュ”，属于发圈类发饰，不是服装或家纺。整体功能是扎头发和装饰造型，最适合放在大类为服饰配件的“accessories”下。accessories 的定义为搭配服装使用的配件与装饰性小物，本品正是典型的发饰配件。', 0, 0, 0, 0, 'accessories', NULL, '', 0, NULL, 0, NULL, NULL, '11', 'オフ(11)', 0);
INSERT INTO `clothing_info` VALUES (19996334, '不锈钢蝴蝶耳钉', 'ステンレスバタフライピアス', 0, 31749817, 'LAKOLE', '', '', '蝴蝶图案耳钉，镂空设计带来轻盈通透的视觉效果，营造成熟优雅的气质。不锈钢材质耐水耐汗，适合长时间佩戴。', 'ーーー<br>バタフライモチーフのピアス。<br>抜け感のあるデザインで、大人っぽい印象のアイテムです。<br>ステンレス素材は、水や汗に強く、付けっぱなしでもOKなのも嬉しいポイント。<br>ーーー', '300.0 JPY', 18.30, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:40:48', '2026-04-02 04:13:26', 'adastria_656211', '', '69cd72d3a7ab618f2967c8ff', '生活/休闲', '', '通用', '青年（18-44岁）', 'ステンレス100%', 'https://www.dot-st.com/lakole/disp/item/656211/?COLOR_CD=02', '其他服饰/物品', '其他', '配件', '', 'accessories', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/lakole/20260401/item_656211_main_02_1774853440_b.jpg', 0, 0, 9, 0.99601, 0, -1, 0, 0, 0, 3, NULL, '防水防汗，耐腐蚀，低致敏性', '防水防汗,耐腐蚀,低致敏性', '', '蝴蝶造型装饰性强，适合日常搭配,不镀层不易褪色，可长时间佩戴,造型轻盈，小巧精致', '纯色，物体', '该商品为耳部佩戴的蝴蝶造型金属饰品，不属于服装、家纺等品类，而是典型的配饰类产品。列表中最匹配的类别是“accessories（配饰）”，定义为用于搭配服装、起到装饰作用的非服装类小物件，如首饰、帽子等，本商品正是用来点缀造型的耳饰，因此选 accessories。', 1, 0, 0, 0, 'accessories', NULL, '', 0, NULL, 0, NULL, NULL, '02', 'ゴールド(02)', 0);
