INSERT INTO `clothing_info` VALUES (19996331, '帆布工作围裙', '帆布ワークエプロン', 0, 31749817, 'LAKOLE', '', '', '这是一款中性款经典版型围裙，采用结实的帆布面料制成。颈部系带长度可通过调节扣进行调节。前袋内部设有分隔设计，方便收纳笔和各类小物。既适合厨房使用，也非常适合庭院作业和DIY等场景。', 'ーーー<br>ユニセックスでお使いいただける、定番型のエプロン。<br>しっかりした帆布生地で、首紐の長さはアジャスターで調整可能です。<br>ポケットには仕切りがあり、ペンや小物などの収納にも便利◎<br>キッチンでのご使用はもちろん、庭作業やDIYなどにも大活躍のアイテムです。<br>ーーー', '1000.0 JPY', 61.00, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:40:49', '2026-04-02 04:13:23', 'adastria_644076', '', '69cd72d3a7ab618f2967c8fe', '生活/休闲', '', '通用', '青年（18-44岁）', '棉90%', 'https://www.dot-st.com/lakole/disp/item/644076/?COLOR_CD=19', '其他服饰/物品', '其他', '配件', '', 'accessories', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/lakole/20260401/item_644076_main_19_1774240036_b.jpg', 0, 0, 1, 0.94230, 0, -2, 0, 0, 0, 3, NULL, '防污/防油，耐用，多口袋收纳方便，可调节肩带设计，适合厨房与园艺、DIY等多场景使用', '耐用,多口袋收纳方便,可调节肩带设计,适合厨房与园艺、DIY等多场景使用', '', '使用厚实帆布面料，质感挺括,中性款式，适合不同身形佩戴,前片设有分隔口袋，便于分类收纳小物,颈部系带配有调节扣，便于调节长度', '纯色', '该商品为“帆布ワークエプロン”，为围在身前用于防污、防油和收纳工具的工作围裙，不属于服装的上衣或下装，也不是家纺如床品、窗帘、毛巾、地毯等。围裙在穿搭分类中通常归为配件类，因此最合适的子类是 accessories（配饰类产品，如围裙、围巾、帽子等）。', 1, 0, 0, 0, 'accessories', NULL, '', 0, NULL, 0, NULL, NULL, '19', 'ブラック(19)', 0);
