INSERT INTO `clothing_info` VALUES (19996324, '细窄璀璨戒指【部分门店限定款】', 'ナロービジューリング[一部店舗限定アイテム]', 0, 31749817, 'LAKOLE', '', '', '精致纤细设计的戒指，点缀小颗璀璨装饰，营造优雅高贵的印象。', 'ーーー<br>華奢なデザインのリング。<br>さりげなくあしらったビジューが上品な印象のアイテムです。<br>ーーー', '300.0 JPY', 18.30, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:41:08', '2026-04-02 04:13:17', 'adastria_656301', '', '69cd72d2a7ab618f2967c8eb', '生活/休闲', '', '通用', '青年（18-44岁）', NULL, 'https://www.dot-st.com/lakole/disp/item/656301/?COLOR_CD=01', '其他服饰/物品', '其他', '配件', '', 'accessories', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/lakole/20260401/item_656301_main_01_1773714527_b.jpg', 0, 0, 9, 0.99857, 0, -1, 0, 0, 0, 3, NULL, '', '', '', '一部分门店限定发售,细窄戒圈设计，风格精致简约,镶嵌小颗仿水晶，提升光泽感与华丽感', '纯色', '从商品名称“ナロービジューリング”和图片可见，这是佩戴在手指上的细窄戒指，并非服装、家纺或其他纺织制品。提供的子类列表中没有专门针对戒指的分类，最贴切的是“accessories（配饰）”，这是对戒指、首饰类产品的总称。因此将其归为 sub_category: accessories，定义为：用于装饰穿搭、提升造型的非服装类配件，如首饰、帽子、腰带等。', 1, 0, 0, 0, 'accessories', NULL, '', 0, NULL, 0, NULL, NULL, '01', 'シルバー(01)', 0);
INSERT INTO `clothing_info` VALUES (19996325, '细窄璀璨戒指【部分门店限定款】', 'ナロービジューリング[一部店舗限定アイテム]', 0, 31749817, 'LAKOLE', '', '', '精致纤细设计的戒指，点缀小颗璀璨装饰，营造优雅高贵的印象。', 'ーーー<br>華奢なデザインのリング。<br>さりげなくあしらったビジューが上品な印象のアイテムです。<br>ーーー', '300.0 JPY', 18.30, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:41:08', '2026-04-02 04:13:18', 'adastria_656301', '', '69cd72d2a7ab618f2967c8eb', '生活/休闲', '', '通用', '青年（18-44岁）', NULL, 'https://www.dot-st.com/lakole/disp/item/656301/?COLOR_CD=01', '其他服饰/物品', '其他', '配件', '', 'accessories', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/lakole/20260401/item_656301_main_02_1773714526_b.jpg', 0, 0, 9, 0.99903, 0, -1, 0, 0, 0, 3, NULL, '', '', '', '一部分门店限定发售,细窄戒圈设计，风格精致简约,镶嵌小颗仿水晶，提升光泽感与华丽感', '纯色', '从商品名称“ナロービジューリング”和图片可见，这是佩戴在手指上的细窄戒指，并非服装、家纺或其他纺织制品。提供的子类列表中没有专门针对戒指的分类，最贴切的是“accessories（配饰）”，这是对戒指、首饰类产品的总称。因此将其归为 sub_category: accessories，定义为：用于装饰穿搭、提升造型的非服装类配件，如首饰、帽子、腰带等。', 1, 1, 0, 0, 'accessories', NULL, '', 0, NULL, 0, NULL, NULL, '02', 'ゴールド(02)', 0);
INSERT INTO `clothing_info` VALUES (19996326, '双环项链', 'ダブルリングネックレス', 0, 31749817, 'LAKOLE', '', '', '以双环图案为吊坠装饰的项链。整体存在感适中，适合通勤与休闲等多种场合佩戴。', 'ーーー<br>ダブルリングモチーフをトップにあしらったネックレス。<br>程よい存在感で、オンオフ問わずにお使いいただけます。<br>ーーー', '300.0 JPY', 18.30, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:41:08', '2026-04-02 04:13:19', 'adastria_656318', '', '69cd72d3a7ab618f2967c8f1', '生活/休闲', '', '通用', '青年（18-44岁）', NULL, 'https://www.dot-st.com/lakole/disp/item/656318/?COLOR_CD=01', '其他服饰/物品', '其他', '配件', '', 'accessories', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/lakole/20260401/item_656318_main_01_1774854038_b.jpg', 0, 0, 9, 0.99345, 0, -1, 0, 0, 0, 3, NULL, '装饰搭配，提升造型精致感', '装饰搭配,提升造型精致感', '', '双环造型吊坠设计,适合通勤与休闲多种场合佩戴,金属与玻璃材质组合,细链条款式，存在感适中', '纯色', '商品为“ダブルリングネックレス”，从名称和图片可知是挂在颈部的饰品，并非服装或家纺类产品，最符合列表中的“accessories（配饰）”。accessories 的合适定义是：用于装饰身体或服装的非服装主体类小物，如项链、耳环、手链、帽子、包等，本品正是典型的项链配饰。', 1, 0, 0, 0, 'accessories', NULL, '', 0, NULL, 0, NULL, NULL, '01', 'シルバー(01)', 0);
INSERT INTO `clothing_info` VALUES (19996327, '双环项链', 'ダブルリングネックレス', 0, 31749817, 'LAKOLE', '', '', '以双环图案为吊坠装饰的项链。整体存在感适中，适合通勤与休闲等多种场合佩戴。', 'ーーー<br>ダブルリングモチーフをトップにあしらったネックレス。<br>程よい存在感で、オンオフ問わずにお使いいただけます。<br>ーーー', '300.0 JPY', 18.30, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:41:08', '2026-04-02 04:13:20', 'adastria_656318', '', '69cd72d3a7ab618f2967c8f1', '生活/休闲', '', '通用', '青年（18-44岁）', NULL, 'https://www.dot-st.com/lakole/disp/item/656318/?COLOR_CD=01', '其他服饰/物品', '其他', '配件', '', 'accessories', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/lakole/20260401/item_656318_main_02_1774854040_b.jpg', 0, 0, 9, 0.99796, 0, -1, 0, 0, 0, 3, NULL, '装饰搭配，提升造型精致感', '装饰搭配,提升造型精致感', '', '双环造型吊坠设计,适合通勤与休闲多种场合佩戴,金属与玻璃材质组合,细链条款式，存在感适中', '纯色', '商品为“ダブルリングネックレス”，从名称和图片可知是挂在颈部的饰品，并非服装或家纺类产品，最符合列表中的“accessories（配饰）”。accessories 的合适定义是：用于装饰身体或服装的非服装主体类小物，如项链、耳环、手链、帽子、包等，本品正是典型的项链配饰。', 1, 1, 0, 0, 'accessories', NULL, '', 0, NULL, 0, NULL, NULL, '02', 'ゴールド(02)', 0);
INSERT INTO `clothing_info` VALUES (19996316, '不锈钢线条链条手链【部分门店限定商品】', 'ステンレスケーブルチェーンブレスレット[一部店舗限定アイテム]', 0, 31749817, 'LAKOLE', '', '', '简约的线条链条设计手链，可与其他饰品叠戴搭配。不锈钢材质耐水耐汗，适合长时间持续佩戴。', 'ーーー<br>ケーブルチェーンのシンプルなブレスレット。<br>他のアイテムとの重ね付けもおすすめ。<br>ステンレス素材は、水や汗に強く、付けっぱなしでもOKなのも嬉しいポイント。<br>ーーー', '500.0 JPY', 30.50, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:41:09', '2026-04-02 04:13:10', 'adastria_660716', '', '69cd72d2a7ab618f2967c8da', '生活/休闲', '', '通用', '青年（18-44岁）', 'ステンレス100%', 'https://www.dot-st.com/lakole/disp/item/660716/?COLOR_CD=01', '其他服饰/物品', '其他', '配件', '', 'accessories', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/lakole/20260401/item_660716_main_01_1774852329_b.jpg', 0, 0, 9, 0.99819, 0, 1, 0, 0, 0, 3, NULL, '耐水，耐汗，耐腐蚀/不易生锈', '耐水,耐汗,耐腐蚀/不易生锈', '', '简约线条造型的链条设计，适合叠戴搭配,采用不锈钢材质，适合长时间佩戴,中性风格，男女皆可佩戴', '纯色，纯色', '该产品为“ステンレスケーブルチェーンブレスレット”，从图片和描述看是腕间佩戴的链条手链，不属于服装、床品、窗帘等纺织品大类，而是独立的饰品类，因此最合适的类别是 accessories（配饰）。在本任务提供的子类列表中没有更细分的首饰/手链选项，故选用笼统但最贴切的“accessories”作为子类别，它指的是佩戴在身上的装饰性物品。', 1, 0, 0, 0, 'accessories', NULL, '', 0, NULL, 0, NULL, NULL, '01', 'シルバー(01)', 0);
