INSERT INTO `clothing_info` VALUES (19996320, '不锈钢双圈耳环【部分门店限定款】', 'ステンレスダブルフープピアス[一部店舗限定アイテム]', 0, 31749817, 'LAKOLE', '', '', '双圈造型设计的耳环，简约大方，通勤休闲场合皆可佩戴。不锈钢材质耐水耐汗，适合长时间佩戴。', 'ーーー<br>ダブルフープデザインのピアス。<br>シンプルなデザインで、オンオフ問わずにお使いいただけます。<br>ステンレス素材は、水や汗に強く、付けっぱなしでもOKなのも嬉しいポイント。<br>ーーー', '500.0 JPY', 30.50, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:41:09', '2026-04-02 04:13:14', 'adastria_660713', '', '69cd72d2a7ab618f2967c8e7', '生活/休闲', '', '通用', '青年（18-44岁）', 'ステンレス100%', 'https://www.dot-st.com/lakole/disp/item/660713/?COLOR_CD=02', '其他服饰/物品', '其他', '配件', '', 'accessories', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/lakole/20260401/item_660713_main_02_1774851056_b.jpg', 0, 0, 9, 0.99666, 0, 1, 0, 0, 0, 3, NULL, '耐水，耐汗，可长时间佩戴', '耐水,耐汗,可长时间佩戴', '', '双层圈式造型，造型感强但风格简约百搭,采用不锈钢材质，更耐用不易变色', '纯色，纯色', '该商品为耳环饰品，从品名“ステンレスダブルフープピアス”和图片可见为双圈金属耳环，不属于服装、家纺类，而是佩戴类饰品。在提供的枚举中最匹配的是“accessories（配饰）”，定义为用于装饰搭配的非服装类小物件，如耳环、项链、戒指等，因此选择 sub_category: accessories。', 1, 0, 0, 0, 'accessories', NULL, '', 0, NULL, 0, NULL, NULL, '02', 'ゴールド(02)', 0);
INSERT INTO `clothing_info` VALUES (19996321, '不锈钢双圈耳环【部分门店限定款】', 'ステンレスダブルフープピアス[一部店舗限定アイテム]', 0, 31749817, 'LAKOLE', '', '', '双圈造型设计的耳环，简约大方，通勤休闲场合皆可佩戴。不锈钢材质耐水耐汗，适合长时间佩戴。', 'ーーー<br>ダブルフープデザインのピアス。<br>シンプルなデザインで、オンオフ問わずにお使いいただけます。<br>ステンレス素材は、水や汗に強く、付けっぱなしでもOKなのも嬉しいポイント。<br>ーーー', '500.0 JPY', 30.50, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:41:09', '2026-04-02 04:13:15', 'adastria_660713', '', '69cd72d2a7ab618f2967c8e7', '生活/休闲', '', '通用', '青年（18-44岁）', 'ステンレス100%', 'https://www.dot-st.com/lakole/disp/item/660713/?COLOR_CD=02', '其他服饰/物品', '其他', '配件', '', 'accessories', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/lakole/20260401/item_660713_main_01_1774851054_b.jpg', 0, 0, 9, 0.98449, 0, 1, 0, 0, 0, 3, NULL, '耐水，耐汗，可长时间佩戴', '耐水,耐汗,可长时间佩戴', '', '双层圈式造型，造型感强但风格简约百搭,采用不锈钢材质，更耐用不易变色', '纯色，纯色', '该商品为耳环饰品，从品名“ステンレスダブルフープピアス”和图片可见为双圈金属耳环，不属于服装、家纺类，而是佩戴类饰品。在提供的枚举中最匹配的是“accessories（配饰）”，定义为用于装饰搭配的非服装类小物件，如耳环、项链、戒指等，因此选择 sub_category: accessories。', 1, 1, 0, 0, 'accessories', NULL, '', 0, NULL, 0, NULL, NULL, '01', 'シルバー(01)', 0);
INSERT INTO `clothing_info` VALUES (19996322, '倾斜蝴蝶结戒指', 'インクラインリボンリング', 0, 31749817, 'LAKOLE', '', '', '点缀蝴蝶结图案的戒指，造型简约，不会显得过于甜美，是日常搭配的精致单品。', 'ーーー<br>リボンモチーフをあしらったリング。<br>シンプルなシルエットで、甘くなりすぎないアイテムです。<br>ーーー', '300.0 JPY', 18.30, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:41:09', '2026-04-02 04:13:15', 'adastria_656295', '', '69cd72d3a7ab618f2967c8ee', '生活/休闲', '', '通用', '青年（18-44岁）', '合金90%,ガラス10%', 'https://www.dot-st.com/lakole/disp/item/656295/?COLOR_CD=24', '其他服饰/物品', '其他', '配件', '', 'accessories', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/lakole/20260401/item_656295_main_24_1773708276_b.jpg', 0, 0, 9, 0.99673, 0, -1, 0, 0, 0, 3, NULL, '装饰配饰', '装饰配饰', '', '蝴蝶结造型戒指设计，风格简约不过分甜美,点缀小玻璃装饰，提升精致感,适合作为日常佩戴或搭配女性化造型的配饰', '纯色', '该商品为戒指类首饰，不属于服装或家纺类产品。结合品名“インクラインリボンリング”和图片可见是金属环形配饰，归类于配饰大类最合适，因此选择子类“accessories（配饰类首饰）”。定义：accessories 指戒指、项链、耳环、手链等起装饰作用的时尚配件。', 1, 0, 0, 0, 'accessories', NULL, '', 0, NULL, 0, NULL, NULL, '24', 'ピンクシルバー(24)', 0);
INSERT INTO `clothing_info` VALUES (19996323, '倾斜蝴蝶结戒指', 'インクラインリボンリング', 0, 31749817, 'LAKOLE', '', '', '点缀蝴蝶结图案的戒指，造型简约，不会显得过于甜美，是日常搭配的精致单品。', 'ーーー<br>リボンモチーフをあしらったリング。<br>シンプルなシルエットで、甘くなりすぎないアイテムです。<br>ーーー', '300.0 JPY', 18.30, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:41:09', '2026-04-02 04:13:16', 'adastria_656295', '', '69cd72d3a7ab618f2967c8ee', '生活/休闲', '', '通用', '青年（18-44岁）', '合金90%,ガラス10%', 'https://www.dot-st.com/lakole/disp/item/656295/?COLOR_CD=24', '其他服饰/物品', '其他', '配件', '', 'accessories', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/lakole/20260401/item_656295_main_01_1773708274_b.jpg', 0, 0, 9, 0.99480, 0, -1, 0, 0, 0, 3, NULL, '装饰配饰', '装饰配饰', '', '蝴蝶结造型戒指设计，风格简约不过分甜美,点缀小玻璃装饰，提升精致感,适合作为日常佩戴或搭配女性化造型的配饰', '纯色', '该商品为戒指类首饰，不属于服装或家纺类产品。结合品名“インクラインリボンリング”和图片可见是金属环形配饰，归类于配饰大类最合适，因此选择子类“accessories（配饰类首饰）”。定义：accessories 指戒指、项链、耳环、手链等起装饰作用的时尚配件。', 1, 1, 0, 0, 'accessories', NULL, '', 0, NULL, 0, NULL, NULL, '01', 'シルバー(01)', 0);
INSERT INTO `clothing_info` VALUES (19996312, '不锈钢线条印章戒指【部分门店限定商品】', 'ステンレスシグネットラインリング[一部店舗限定アイテム]', 0, 31749817, 'LAKOLE', '', '', '以线条设计为亮点的戒指，简约却带来华丽印象。不锈钢材质耐水耐汗，适合长时间佩戴，也是令人欣喜的特点。', 'ーーー<br>ラインデザインがポイントのリング。<br>シンプルながらも華やかな印象のアイテムです。<br>ステンレス素材は、水や汗に強く、付けっぱなしでもOKなのも嬉しいポイント。<br>ーーー', '700.0 JPY', 42.70, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:41:10', '2026-04-02 04:13:07', 'adastria_660782', '', '69cd72d2a7ab618f2967c8d6', '生活/休闲', '', '通用', '青年（18-44岁）', 'ステンレス100%', 'https://www.dot-st.com/lakole/disp/item/660782/?COLOR_CD=02', '其他服饰/物品', '其他', '配件', '', 'accessories', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/lakole/20260401/item_660782_main_02_1774856387_b.jpg', 0, 0, 9, 0.99390, 0, 1, 0, 0, 0, 3, NULL, '耐水耐汗，适合长时间佩戴', '耐水耐汗,适合长时间佩戴', '', '一部分门店限定款,线条感装饰设计，造型简约又有存在感,采用不易生锈的金属材质，日常佩戴友好', '纯色', '该产品为“ステンレスシグネットラインリング”，从图片和描述看是戴在手指上的戒指类配饰，不属于服装、家纺（床品、窗帘、毛巾、地毯、靠垫、桌布）这些大类，因此应归入饰品类。现有枚举中最接近的是“accessories（配饰）”，定义为：用于搭配穿着、起装饰作用的非服装主体类商品，如首饰、帽子、围巾等。本商品正是金属戒指，完全符合 accessories 的定义。', 1, 0, 0, 0, 'accessories', NULL, '', 0, NULL, 0, NULL, NULL, '02', 'ゴールド(02)', 0);
