INSERT INTO `clothing_info` VALUES (19996314, '爱心圈式耳环', 'ハートフープピアス', 0, 31749817, 'LAKOLE', '', '', '爱心图案的圈式耳环。金属材质设计，使造型不过分甜美，更容易搭配休闲风格造型。', 'ーーー<br>ハートモチーフのフープピアス。<br>メタル素材なので甘くなりすぎず、カジュアルにも合わせやすいアイテムです。<br>ーーー', '700.0 JPY', 42.70, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:41:10', '2026-04-02 04:13:09', 'adastria_134175', '', '69cd72d2a7ab618f2967c8d8', '生活/休闲', '', '通用', '青年（18-44岁）', '亜鉛合金100%', 'https://www.dot-st.com/lakole/disp/item/134175/?COLOR_CD=02', '其他服饰/物品', '其他', '配件', '', 'accessories', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/lakole/20260401/item_134175_main_02_1719552597_b.jpg', 0, 0, 9, 0.99529, 0, -1, 0, 0, 0, 3, NULL, '', '', '', '金属爱心造型耳环配饰,适合日常休闲与甜美风格搭配,金属材质降低甜腻感，更易与休闲穿搭融合', '纯色', '商品为“ハートフープピアス”，从图片与描述可知是爱心造型的金属耳环，属于配饰类而非服装、家纺等纺织品主件，因此在给定列表中最适合归入“accessories（配饰）”这一大类。accessories 指穿戴在身上的装饰性物品，如耳环、项链、手链等，用于搭配服装、提升造型感。', 0, 0, 0, 0, 'accessories', NULL, '', 0, NULL, 0, NULL, NULL, '02', 'ゴールド02', 0);
INSERT INTO `clothing_info` VALUES (19996315, '设计戒指项链【部分门店限定商品】', 'デザインリングネックレス[一部店舗限定アイテム]', 0, 31749817, 'LAKOLE', '', '', '爱心镂空戒指造型吊坠项链。吊坠侧面点缀亮钻，整体华丽闪耀，适合搭配各种时尚造型。', 'ーーー<br>ハート型にくり抜いた、リングモチーフのネックレス。<br>側面にもビジューをあしらった、華やかなアイテムです。<br>ーーー', '300.0 JPY', 18.30, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:41:10', '2026-04-02 04:13:10', 'adastria_283472', '', '69cd72d2a7ab618f2967c8db', '生活/休闲', '', '女', '青年（18-44岁）', NULL, 'https://www.dot-st.com/lakole/disp/item/283472/?COLOR_CD=01', '其他服饰/物品', '其他', '配件', '', 'accessories', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/lakole/20260401/item_283472_main_01_1734390855_b.jpg', 0, 0, 9, 0.99894, 0, -1, 0, 0, 0, 3, NULL, '装饰搭配', '装饰搭配', '', '心形镂空戒指造型吊坠设计,链条细致轻巧，适合作为日常配饰,部分店铺限定款，具有一定稀缺性', '纯色，纯色', '根据商品名称“デザインリングネックレス”和图片可知，这是带有戒指造型吊坠的项链，属于饰品配件而非服装或家纺。提供的子类列表中没有专门的首饰或项链类别，最接近的类别是“accessories（配饰）”。配饰定义为用于装饰搭配服装的非服装主体类产品，因此将其归为“accessories”。', 0, 0, 0, 0, 'accessories', NULL, '', 0, NULL, 0, NULL, NULL, '01', 'シルバー(01)', 0);
INSERT INTO `clothing_info` VALUES (19996310, '小巧水钻十字架项链', 'プチビジュ－クロスネックレス', 0, 31749817, 'LAKOLE', '', '', '点缀小颗水钻的十字架造型项链，造型精致，具有适度存在感，适合搭配各种风格造型佩戴。', 'ーーー<br>ビジューをあしらったクロスモチーフのネックレス。<br>程よい存在感で、スタイリング問わずにお使いいただけるアイテムです。<br>ーーー', '300.0 JPY', 18.30, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:41:11', '2026-04-02 04:13:05', 'adastria_656320', '', '69cd72d2a7ab618f2967c8cb', '生活/休闲', '', '通用', '青年（18-44岁）', NULL, 'https://www.dot-st.com/lakole/disp/item/656320/?COLOR_CD=01', '其他服饰/物品', '其他', '配件', '', 'accessories', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/lakole/20260401/item_656320_main_01_1774855843_b.jpg', 0, 0, 9, 0.99262, 0, -1, 0, 0, 0, 3, NULL, '装饰搭配', '装饰搭配', '', '十字架吊坠造型，点缀小颗仿水晶饰件，适合多种穿搭风格', '纯色，纯色', '该商品为带有十字架吊坠的项链，属于首饰配件类，与服装、家纺等类别无关。在提供的枚举中最接近的是“accessories（配饰）”，定义为：用于搭配服装、起装饰作用的非服装本体类产品，如首饰、帽子、围巾等。因此将其归为 sub_category: accessories。', 1, 0, 0, 0, 'accessories', NULL, '', 0, NULL, 0, NULL, NULL, '01', 'シルバー(01)', 0);
INSERT INTO `clothing_info` VALUES (19996311, '小巧水钻十字架项链', 'プチビジュ－クロスネックレス', 0, 31749817, 'LAKOLE', '', '', '点缀小颗水钻的十字架造型项链，造型精致，具有适度存在感，适合搭配各种风格造型佩戴。', 'ーーー<br>ビジューをあしらったクロスモチーフのネックレス。<br>程よい存在感で、スタイリング問わずにお使いいただけるアイテムです。<br>ーーー', '300.0 JPY', 18.30, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:41:11', '2026-04-02 04:13:06', 'adastria_656320', '', '69cd72d2a7ab618f2967c8cb', '生活/休闲', '', '通用', '青年（18-44岁）', NULL, 'https://www.dot-st.com/lakole/disp/item/656320/?COLOR_CD=01', '其他服饰/物品', '其他', '配件', '', 'accessories', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/lakole/20260401/item_656320_main_02_1774855845_b.jpg', 0, 0, 9, 0.99538, 0, -1, 0, 0, 0, 3, NULL, '装饰搭配', '装饰搭配', '', '十字架吊坠造型，点缀小颗仿水晶饰件，适合多种穿搭风格', '纯色，纯色', '该商品为带有十字架吊坠的项链，属于首饰配件类，与服装、家纺等类别无关。在提供的枚举中最接近的是“accessories（配饰）”，定义为：用于搭配服装、起装饰作用的非服装本体类产品，如首饰、帽子、围巾等。因此将其归为 sub_category: accessories。', 1, 1, 0, 0, 'accessories', NULL, '', 0, NULL, 0, NULL, NULL, '02', 'ゴールド(02)', 0);
INSERT INTO `clothing_info` VALUES (19996297, '透明圆片耳环', 'クリアプレートピアス', 0, 31749817, 'LAKOLE', '', '', '以金属材质搭配透明圆形部件的耳环设计。造型简约，易于与各种风格造型搭配使用。', 'ーーー<br>メタル素材に、クリアパーツのサークルモチーフを組み合わせたピアス。<br>シンプルなので、どんなスタイリングにも合わせやすいアイテムです。<br>ーーー', '700.0 JPY', 42.70, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:41:19', '2026-04-02 04:12:54', 'adastria_964406', '', '69cd72d2a7ab618f2967c8ca', '生活/休闲', '', '通用', '青年（18-44岁）', '合金50%,樹脂50%', 'https://www.dot-st.com/lakole/disp/item/964406/?COLOR_CD=01', '其他服饰/物品', '其他', '配件', '', 'accessories', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/lakole/20260401/item_964406_main_01_1686896067_b.jpg', 0, 0, 9, 0.96569, 0, 1, 0, 0, 0, 3, NULL, '装饰搭配，提升造型感', '装饰搭配,提升造型感', '', '金属与透明树脂组合设计,圆形几何造型，线条简洁,适合多种日常穿搭风格', '纯色，纯色', '该商品为耳环饰品，不属于服装或家纺，而是穿戴在耳朵上的时尚配饰。根据商品名称“クリアプレートピアス”和图片可知是金属与树脂材质的耳饰，因此最合适的类别是配饰类中的“accessories（饰品/配件）”，定义为搭配服装使用的非服装本体小物，如耳环、项链、戒指等。', 1, 0, 0, 0, 'accessories', NULL, '', 0, NULL, 0, NULL, NULL, '01', 'シルバー01', 0);
INSERT INTO `clothing_info` VALUES (19996298, '透明圆片耳环', 'クリアプレートピアス', 0, 31749817, 'LAKOLE', '', '', '以金属材质搭配透明圆形部件的耳环设计。造型简约，易于与各种风格造型搭配使用。', 'ーーー<br>メタル素材に、クリアパーツのサークルモチーフを組み合わせたピアス。<br>シンプルなので、どんなスタイリングにも合わせやすいアイテムです。<br>ーーー', '700.0 JPY', 42.70, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:41:19', '2026-04-02 04:12:55', 'adastria_964406', '', '69cd72d2a7ab618f2967c8ca', '生活/休闲', '', '通用', '青年（18-44岁）', '合金50%,樹脂50%', 'https://www.dot-st.com/lakole/disp/item/964406/?COLOR_CD=01', '其他服饰/物品', '其他', '配件', '', 'accessories', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/lakole/20260401/item_964406_main_02_1686896070_b.jpg', 0, 0, 9, 0.98049, 0, 1, 0, 0, 0, 3, NULL, '装饰搭配，提升造型感', '装饰搭配,提升造型感', '', '金属与透明树脂组合设计,圆形几何造型，线条简洁,适合多种日常穿搭风格', '纯色，纯色', '该商品为耳环饰品，不属于服装或家纺，而是穿戴在耳朵上的时尚配饰。根据商品名称“クリアプレートピアス”和图片可知是金属与树脂材质的耳饰，因此最合适的类别是配饰类中的“accessories（饰品/配件）”，定义为搭配服装使用的非服装本体小物，如耳环、项链、戒指等。', 1, 1, 0, 0, 'accessories', NULL, '', 0, NULL, 0, NULL, NULL, '02', 'ゴールド02', 0);
INSERT INTO `clothing_info` VALUES (19996278, '波浪金属发夹【部分门店限定商品】', 'ウェーブメタルバレッタ[一部店舗限定アイテム]', 0, 31749817, 'LAKOLE', '', '', '波浪造型设计的发夹，以金属材质打造出酷感气质单品，可轻松搭配休闲或女性化风格造型。', 'ーーー<br>ウェーブデザインのバレッタ。<br>メタル素材でクールに仕上げたアイテムです。<br>カジュアルにもフェミニンにも合わせやすくおすすめ。<br>ーーー', '300.0 JPY', 18.30, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:41:49', '2026-04-02 04:12:38', 'adastria_658922', '', '69cd72d2a7ab618f2967c8c5', '', '', '女', '青年（18-44岁）', '合金100%', 'https://www.dot-st.com/lakole/disp/item/658922/?COLOR_CD=02', '其他服饰/物品', '其他', '配件', '', 'accessories', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/lakole/20260401/item_658922_main_02_1774854530_b.jpg', 0, 0, 9, 0.99277, 0, -1, 0, 0, 0, 3, NULL, '装饰造型', '装饰造型', '', '金属波浪造型设计，风格简约利落，可搭配休闲或女性化穿搭,为部分门店限定发售，具有一定稀缺性', '纯色，纯色', '该商品为“ウェーブメタルバレッタ”，从名称和图片可知是用于固定和装饰头发的金属发夹，而非服装或家纺类产品。提供的子类列表中没有专门的发饰/发夹选项，但有大类“accessories”，与“ヘアアクセサリー”在功能属性上最接近，均属于配饰范畴，因此归类为 accessories。accessories：指非服装主体的装饰或功能性小物，如首饰、帽饰、腰带、发饰等，用于搭配造型。', 1, 0, 0, 0, 'accessories', NULL, '', 0, NULL, 0, NULL, NULL, '02', 'ゴールド(02)', 0);
