INSERT INTO `clothing_info` VALUES (19996273, '镶珍珠格纹发圈【部分门店限定商品】', 'パール付きギンガムシュシュ[一部店舗限定アイテム]', 0, 31749817, 'LAKOLE', '', '', '采用格纹图案的发圈，点缀珍珠装饰，营造华丽感。只需轻松一扎即可完成简单的发型搭配。', 'ーーー<br>ギンガムチェック柄のシュシュ。<br>パールがアクセントになった、華やかなデザインです。<br>サッと結ぶだけで、簡単にヘアアレンジが完成します。<br>ーーー', '300.0 JPY', 18.30, 0, 0, 0, '', 0, 0, '', '2026-03-31 22:41:50', '2026-04-02 04:12:34', 'adastria_658923', '', '69cd72d2a7ab618f2967c8bb', '生活/休闲', '', '通用', '青年（18-44岁）', NULL, 'https://www.dot-st.com/lakole/disp/item/658923/?COLOR_CD=19', '其他服饰/物品', '其他', '配件', '', 'accessories', 0, '', 0, 'https://ssznb-bucket.oss-cn-beijing.aliyuncs.com/eshop/lakole/20260401/item_658923_main_19_1774852671_b.jpg', 0, 0, 9, 0.92426, 0, 1, 0, 0, 0, 3, NULL, '装饰造型，固定头发', '装饰造型,固定头发', '', '搭配珍珠装饰，提升华丽感,采用经典黑白千鸟格风格的细密格纹图案,为发圈结构，便于快速完成简易发型,采用合成橡胶提供弹性伸缩', '维希格', '该商品是用于扎头发的“シュシュ”（发圈），属于头部佩戴的小物配饰，而非服装或家纺类产品。最接近的类别是配饰“accessories”。accessories 的定义是：用于装饰或辅助穿搭的非服装本体类小物，如首饰、发饰、帽饰等，本品与此完全吻合。', 1, 0, 0, 0, 'accessories', NULL, '', 0, NULL, 0, NULL, NULL, '19', 'ブラック(19)', 0);
