INSERT INTO `clothing_pattern_info` VALUES (2086064, 19969263, '纯色', '从图片可见整体为单一纯色灰，无任何可辨识的图案元素与局部印花，因此选择“Solid color（纯色）”。图案构成上仅有一个元素，归类为“Single Element Pattern（单元素图案）”。由于无具象或可识别对象，图案定义采用“Abstract Pattern（抽象图案）”。');
INSERT INTO `clothing_pattern_info` VALUES (2086065, 19969264, '纯色', '从图片可见整体为单一纯色灰，无任何可辨识的图案元素与局部印花，因此选择“Solid color（纯色）”。图案构成上仅有一个元素，归类为“Single Element Pattern（单元素图案）”。由于无具象或可识别对象，图案定义采用“Abstract Pattern（抽象图案）”。');
INSERT INTO `clothing_pattern_info` VALUES (2086066, 19969265, '纯色', '从图片可见整体为单一纯色灰，无任何可辨识的图案元素与局部印花，因此选择“Solid color（纯色）”。图案构成上仅有一个元素，归类为“Single Element Pattern（单元素图案）”。由于无具象或可识别对象，图案定义采用“Abstract Pattern（抽象图案）”。');
INSERT INTO `clothing_pattern_info` VALUES (2086052, 19969260, '文字', '图案覆盖整件短裤，因此选择“整体铺陈（Allover pattern）”；以表面印花呈现，选择“印花（Print）”。图案由文字、字母、数字与与统计/科学信息构成，属于多元素组合，因此选“复合图案（Composed Pattern）”，并在元素维度使用“文字（Text）”“字母（Letter）”“数字（Number）”“科学（Scientific）”。这些内容具有指代现实的可识别信息，故在定义维度选“具象图案（Representational Pattern）”。图形线条与标注以线描方式呈现，风格为“线描效果（Line Drawing Effect）”。');
INSERT INTO `clothing_pattern_info` VALUES (2086053, 19969260, '字母', '图案覆盖整件短裤，因此选择“整体铺陈（Allover pattern）”；以表面印花呈现，选择“印花（Print）”。图案由文字、字母、数字与与统计/科学信息构成，属于多元素组合，因此选“复合图案（Composed Pattern）”，并在元素维度使用“文字（Text）”“字母（Letter）”“数字（Number）”“科学（Scientific）”。这些内容具有指代现实的可识别信息，故在定义维度选“具象图案（Representational Pattern）”。图形线条与标注以线描方式呈现，风格为“线描效果（Line Drawing Effect）”。');
