INSERT INTO `clothing_pattern_info` VALUES (2086049, 19969257, '纯色', '整体为纯色灰面料，没有可见印花或图案元素，故选择“Solid color”。图案构成仅为单一元素，因此为“Single Element Pattern”。无具象或可识别元素，归类为“Abstract Pattern”。');
INSERT INTO `clothing_pattern_info` VALUES (2086050, 19969258, '纯色', '整体为纯色灰面料，没有可见印花或图案元素，故选择“Solid color”。图案构成仅为单一元素，因此为“Single Element Pattern”。无具象或可识别元素，归类为“Abstract Pattern”。');
INSERT INTO `clothing_pattern_info` VALUES (2086051, 19969259, '纯色', '整体为纯色灰面料，没有可见印花或图案元素，故选择“Solid color”。图案构成仅为单一元素，因此为“Single Element Pattern”。无具象或可识别元素，归类为“Abstract Pattern”。');
INSERT INTO `clothing_pattern_info` VALUES (2092109, 19973900, '花卉图案', '外观以重复的花卉元素铺陈在包体上，属于“满版图案（Allover pattern）”；图案实现方式为“刺绣（Embroidery）”；整体由单一花卉元素反复构成，归为“单一元素构成（Single Element Pattern）”；具体元素为“花卉图案（Floral pattern）”；该花卉具有明确可识别的自然形态，因此在图案定义上选择“具象图案（Representational Pattern）”。');
INSERT INTO `clothing_pattern_info` VALUES (2092099, 19973894, '品牌标识', '整体为素色面料，胸前仅有品牌标识，图案呈现为“位置印花（Placement Print）”，工艺为“印花（Print）”，图案构成为“单元素图案（Single Element Pattern）”。元素包含“标志位置（Logo Placement）”与“素色（Solid color）”。该标识属于具象符号，故选择“具象图案（Representational Pattern）”；整体呈简洁克制，归为“极简风格（Minimalist Style）”。');
INSERT INTO `clothing_pattern_info` VALUES (2092100, 19973894, '纯色', '整体为素色面料，胸前仅有品牌标识，图案呈现为“位置印花（Placement Print）”，工艺为“印花（Print）”，图案构成为“单元素图案（Single Element Pattern）”。元素包含“标志位置（Logo Placement）”与“素色（Solid color）”。该标识属于具象符号，故选择“具象图案（Representational Pattern）”；整体呈简洁克制，归为“极简风格（Minimalist Style）”。');
INSERT INTO `clothing_pattern_info` VALUES (2092101, 19973895, '品牌标识', '整体为素色面料，胸前仅有品牌标识，图案呈现为“位置印花（Placement Print）”，工艺为“印花（Print）”，图案构成为“单元素图案（Single Element Pattern）”。元素包含“标志位置（Logo Placement）”与“素色（Solid color）”。该标识属于具象符号，故选择“具象图案（Representational Pattern）”；整体呈简洁克制，归为“极简风格（Minimalist Style）”。');
