INSERT INTO `clothing_pattern_info` VALUES (2092105, 19973897, '品牌标识', '整体为素色面料，胸前仅有品牌标识，图案呈现为“位置印花（Placement Print）”，工艺为“印花（Print）”，图案构成为“单元素图案（Single Element Pattern）”。元素包含“标志位置（Logo Placement）”与“素色（Solid color）”。该标识属于具象符号，故选择“具象图案（Representational Pattern）”；整体呈简洁克制，归为“极简风格（Minimalist Style）”。');
INSERT INTO `clothing_pattern_info` VALUES (2092106, 19973897, '纯色', '整体为素色面料，胸前仅有品牌标识，图案呈现为“位置印花（Placement Print）”，工艺为“印花（Print）”，图案构成为“单元素图案（Single Element Pattern）”。元素包含“标志位置（Logo Placement）”与“素色（Solid color）”。该标识属于具象符号，故选择“具象图案（Representational Pattern）”；整体呈简洁克制，归为“极简风格（Minimalist Style）”。');
INSERT INTO `clothing_pattern_info` VALUES (2092098, 19973893, '纯色', '整体为通版单一色覆盖，属于“Allover pattern（通版）”；图案构成为单元素，选择“Single Element Pattern”。面料无可识别具象图案，仅为“Solid color（素色）”，因此在定义上归类为“Abstract Pattern（抽象图案）”。');
INSERT INTO `clothing_pattern_info` VALUES (2102505, 19982305, '花卉图案', '图案由鞋面局部的 3D 花卉装饰构成，属于“局部图案（Localized Pattern）”；其实现方式为贴饰/拼贴，对应“拼贴（Patchwork）”；整体仅围绕一个元素展开，为“单一元素图案（Single Element Pattern）”；元素本身为花卉，因此选“花卉图案（Floral pattern）”；花朵造型直观可识别，归为“具象图案（Representational Pattern）”；造型简洁克制，选择“极简风格（Minimalist Style）”。');
INSERT INTO `clothing_pattern_info` VALUES (2092095, 19973890, '花卉图案', '图案为同色系花卉元素遍布全身，属于“全面铺陈（Allover pattern）”；工艺由文字与视觉可辨为“压纹（Embossing）”；重复单一花卉元素构成，归于“单元素图案（Single Element Pattern）”；元素类型为“花卉图案（Floral pattern）”；该图案描绘现实物象，归类为“具象图案（Representational Pattern）”；整体简洁低饱和、同色系呈现，具有“极简风格（Minimalist Style）”。');
INSERT INTO `clothing_pattern_info` VALUES (2092094, 19973889, '花卉图案', '服装表面呈现整衣分布的花卉图案，属于“满版（Allover pattern）”；图案通过“压纹（Embossing）”工艺形成，非染印色差而是以立体效果呈现；元素为单一的花卉重复，归为“单一元素图案（Single Element Pattern）”与“花卉图案（Floral pattern）”；花卉属于具象自然元素，因此选择“具象图案（Representational Pattern）”；整体为同色系低对比度、弱视觉干扰的呈现，体现“极简风格（Minimalist Style）”。');
INSERT INTO `clothing_pattern_info` VALUES (2092087, 19973885, '品牌标识', '整体为纯色面料，胸前带品牌标识，属于局部位置的印花（Placement Print），技术为印花（Print），构成为单一元素（Single Element Pattern），元素为Logo摆位（Logo Placement）与纯色（Solid color）。该图案不描绘具体场景或自然物，归类为抽象图案（Abstract Pattern）；风格简洁克制，呈现极简风格（Minimalist Style）。');
INSERT INTO `clothing_pattern_info` VALUES (2092088, 19973885, '纯色', '整体为纯色面料，胸前带品牌标识，属于局部位置的印花（Placement Print），技术为印花（Print），构成为单一元素（Single Element Pattern），元素为Logo摆位（Logo Placement）与纯色（Solid color）。该图案不描绘具体场景或自然物，归类为抽象图案（Abstract Pattern）；风格简洁克制，呈现极简风格（Minimalist Style）。');
INSERT INTO `clothing_pattern_info` VALUES (2092089, 19973886, '品牌标识', '整体为纯色面料，胸前带品牌标识，属于局部位置的印花（Placement Print），技术为印花（Print），构成为单一元素（Single Element Pattern），元素为Logo摆位（Logo Placement）与纯色（Solid color）。该图案不描绘具体场景或自然物，归类为抽象图案（Abstract Pattern）；风格简洁克制，呈现极简风格（Minimalist Style）。');
INSERT INTO `clothing_pattern_info` VALUES (2092090, 19973886, '纯色', '整体为纯色面料，胸前带品牌标识，属于局部位置的印花（Placement Print），技术为印花（Print），构成为单一元素（Single Element Pattern），元素为Logo摆位（Logo Placement）与纯色（Solid color）。该图案不描绘具体场景或自然物，归类为抽象图案（Abstract Pattern）；风格简洁克制，呈现极简风格（Minimalist Style）。');
INSERT INTO `clothing_pattern_info` VALUES (2092091, 19973887, '品牌标识', '整体为纯色面料，胸前带品牌标识，属于局部位置的印花（Placement Print），技术为印花（Print），构成为单一元素（Single Element Pattern），元素为Logo摆位（Logo Placement）与纯色（Solid color）。该图案不描绘具体场景或自然物，归类为抽象图案（Abstract Pattern）；风格简洁克制，呈现极简风格（Minimalist Style）。');
INSERT INTO `clothing_pattern_info` VALUES (2092092, 19973887, '纯色', '整体为纯色面料，胸前带品牌标识，属于局部位置的印花（Placement Print），技术为印花（Print），构成为单一元素（Single Element Pattern），元素为Logo摆位（Logo Placement）与纯色（Solid color）。该图案不描绘具体场景或自然物，归类为抽象图案（Abstract Pattern）；风格简洁克制，呈现极简风格（Minimalist Style）。');
INSERT INTO `clothing_pattern_info` VALUES (2092093, 19973888, '花卉图案', '整体为通体重复的花卉图案，属于全幅排布（Allover pattern）；图案呈现通过压纹工艺（Embossing）形成；图案以单一花卉元素为主（Single Element Pattern），具体元素为花卉（Floral pattern）；花卉来源于现实物象，归为具象图案（Representational Pattern）；整体以同色系低调呈现，风格简洁克制，归于极简风格（Minimalist Style）。');
INSERT INTO `clothing_pattern_info` VALUES (2102504, 19982304, '花卉图案', '整体图案覆盖为“全幅铺陈（Allover pattern）”，主题为重复的“花卉元素（Floral pattern）”，图案表现为简洁单色、细密重复，符合“极简风格（Minimalist Style）”。工艺上图案通过“压花（Embossing）”形成。图案构成以单一元素为主，归为“单一元素图案（Single Element Pattern）”。花卉属于具象题材，因此在图案定义上选择“具象图案（Representational Pattern）”。');
INSERT INTO `clothing_pattern_info` VALUES (2100990, 19981124, '品牌标识', '整体为纯黑色无大面积图案，属于“Solid color（纯色）”。裤身仅在大腿部位有品牌标识，图案位置明确，为“Placement Print（定位印花）”，工艺为“Print（印花）”，且仅单一元素，归为“Single Element Pattern（单元素图案）”。品牌标志本身属于“Logo Placement（标志位置）”，在图案定义上更接近“Representational Pattern（具象）”。整体风格简洁，可归为“Minimalist Style（极简风格）”。');
INSERT INTO `clothing_pattern_info` VALUES (2100991, 19981124, '纯色', '整体为纯黑色无大面积图案，属于“Solid color（纯色）”。裤身仅在大腿部位有品牌标识，图案位置明确，为“Placement Print（定位印花）”，工艺为“Print（印花）”，且仅单一元素，归为“Single Element Pattern（单元素图案）”。品牌标志本身属于“Logo Placement（标志位置）”，在图案定义上更接近“Representational Pattern（具象）”。整体风格简洁，可归为“Minimalist Style（极简风格）”。');
INSERT INTO `clothing_pattern_info` VALUES (2107609, 19986557, '纯色', '整体以单一色为主，辅以局部点状区域与品牌Logo，属于“Localized Pattern/局部图案”与“Placement Print/定位印花”的排布；工艺为“Print/印花”；构成为“Composed Pattern/多元素构成”；图案元素为“Solid color/纯色”“Dot/点状”“Logo Placement/Logo位置”；整体更偏“Abstract Pattern/抽象图案”；风格为“Minimalist Style/极简风格”。');
INSERT INTO `clothing_pattern_info` VALUES (2107610, 19986557, '点', '整体以单一色为主，辅以局部点状区域与品牌Logo，属于“Localized Pattern/局部图案”与“Placement Print/定位印花”的排布；工艺为“Print/印花”；构成为“Composed Pattern/多元素构成”；图案元素为“Solid color/纯色”“Dot/点状”“Logo Placement/Logo位置”；整体更偏“Abstract Pattern/抽象图案”；风格为“Minimalist Style/极简风格”。');
INSERT INTO `clothing_pattern_info` VALUES (2107611, 19986557, '品牌标识', '整体以单一色为主，辅以局部点状区域与品牌Logo，属于“Localized Pattern/局部图案”与“Placement Print/定位印花”的排布；工艺为“Print/印花”；构成为“Composed Pattern/多元素构成”；图案元素为“Solid color/纯色”“Dot/点状”“Logo Placement/Logo位置”；整体更偏“Abstract Pattern/抽象图案”；风格为“Minimalist Style/极简风格”。');
INSERT INTO `clothing_pattern_info` VALUES (2107612, 19986558, '纯色', '整体以单一色为主，辅以局部点状区域与品牌Logo，属于“Localized Pattern/局部图案”与“Placement Print/定位印花”的排布；工艺为“Print/印花”；构成为“Composed Pattern/多元素构成”；图案元素为“Solid color/纯色”“Dot/点状”“Logo Placement/Logo位置”；整体更偏“Abstract Pattern/抽象图案”；风格为“Minimalist Style/极简风格”。');
INSERT INTO `clothing_pattern_info` VALUES (2107613, 19986558, '点', '整体以单一色为主，辅以局部点状区域与品牌Logo，属于“Localized Pattern/局部图案”与“Placement Print/定位印花”的排布；工艺为“Print/印花”；构成为“Composed Pattern/多元素构成”；图案元素为“Solid color/纯色”“Dot/点状”“Logo Placement/Logo位置”；整体更偏“Abstract Pattern/抽象图案”；风格为“Minimalist Style/极简风格”。');
INSERT INTO `clothing_pattern_info` VALUES (2107614, 19986558, '品牌标识', '整体以单一色为主，辅以局部点状区域与品牌Logo，属于“Localized Pattern/局部图案”与“Placement Print/定位印花”的排布；工艺为“Print/印花”；构成为“Composed Pattern/多元素构成”；图案元素为“Solid color/纯色”“Dot/点状”“Logo Placement/Logo位置”；整体更偏“Abstract Pattern/抽象图案”；风格为“Minimalist Style/极简风格”。');
INSERT INTO `clothing_pattern_info` VALUES (2113621, 19991841, '钻石', '包体表面呈现连续的菱形交叉网格，覆盖整个面，因此选择“Allover pattern”；图案结构以单一几何元素为主，选择“Single Element Pattern”；具体元素为“Diamond（菱形）”；该几何网格不指代具体事物，归为“Abstract Pattern”；整体视觉简洁克制，选择“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2113615, 19991838, '纯色', '整体以纯色为主，搭配局部品牌Logo图案，因此布局选择“Placement Print”，工艺为“Print”。图案构成包含底部“Pure Color”与局部“Logo Placement”，故用“Composed Pattern”。由于Logo与文字具有明确指向性，图案定义选“Representational Pattern”。视觉表现简洁克制，选“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2113616, 19991838, '品牌标识', '整体以纯色为主，搭配局部品牌Logo图案，因此布局选择“Placement Print”，工艺为“Print”。图案构成包含底部“Pure Color”与局部“Logo Placement”，故用“Composed Pattern”。由于Logo与文字具有明确指向性，图案定义选“Representational Pattern”。视觉表现简洁克制，选“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2113617, 19991839, '纯色', '整体以纯色为主，搭配局部品牌Logo图案，因此布局选择“Placement Print”，工艺为“Print”。图案构成包含底部“Pure Color”与局部“Logo Placement”，故用“Composed Pattern”。由于Logo与文字具有明确指向性，图案定义选“Representational Pattern”。视觉表现简洁克制，选“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2113618, 19991839, '品牌标识', '整体以纯色为主，搭配局部品牌Logo图案，因此布局选择“Placement Print”，工艺为“Print”。图案构成包含底部“Pure Color”与局部“Logo Placement”，故用“Composed Pattern”。由于Logo与文字具有明确指向性，图案定义选“Representational Pattern”。视觉表现简洁克制，选“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2113619, 19991840, '纯色', '整体以纯色为主，搭配局部品牌Logo图案，因此布局选择“Placement Print”，工艺为“Print”。图案构成包含底部“Pure Color”与局部“Logo Placement”，故用“Composed Pattern”。由于Logo与文字具有明确指向性，图案定义选“Representational Pattern”。视觉表现简洁克制，选“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2113620, 19991840, '品牌标识', '整体以纯色为主，搭配局部品牌Logo图案，因此布局选择“Placement Print”，工艺为“Print”。图案构成包含底部“Pure Color”与局部“Logo Placement”，故用“Composed Pattern”。由于Logo与文字具有明确指向性，图案定义选“Representational Pattern”。视觉表现简洁克制，选“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2113614, 19991837, '纯色', '整体呈现单一纯色，无具体图案元素，故在布局上归为“Allover pattern”，构成为“Single Element Pattern”；图案元素选择“Pure Color”；由于没有具象图形，图案定义归为“Abstract Pattern”；整体视觉简洁克制，符合“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2113613, 19991836, '纯色', '整体为素色双拼设计，不见具体图案元素或排布，因而选择“单元素图案”“素色/纯色”；由于并非具象或具代表性的图形，归类为“抽象图案”。');
INSERT INTO `clothing_pattern_info` VALUES (2113608, 19991832, '品牌标识', '整体为纯色灰/黑配色，正面有品牌标识，属于“定位印花”（Placement Print），技术为“印花”（Print）；图案构成以单一元素为主，归类为“单一元素图案”（Single Element Pattern）；元素为“Logo放置”（Logo Placement）与“纯色”（Solid color）。从图案定义看，Logo具有明确识别性，归为“具象图案”（Representational Pattern）；风格简洁，归为“极简风格”（Minimalist Style）。');
INSERT INTO `clothing_pattern_info` VALUES (2113609, 19991832, '纯色', '整体为纯色灰/黑配色，正面有品牌标识，属于“定位印花”（Placement Print），技术为“印花”（Print）；图案构成以单一元素为主，归类为“单一元素图案”（Single Element Pattern）；元素为“Logo放置”（Logo Placement）与“纯色”（Solid color）。从图案定义看，Logo具有明确识别性，归为“具象图案”（Representational Pattern）；风格简洁，归为“极简风格”（Minimalist Style）。');
INSERT INTO `clothing_pattern_info` VALUES (2113610, 19991833, '品牌标识', '该款背部为大面积方形Logo图案并集中呈现，属于“Placement Print”布局；表现方式为“Print”印花；图案核心为单一Logo元素，归为“Single Element Pattern”；具体元素为品牌标识，选“Logo Placement”；Logo属于符号化设计，不描绘具体具象物体，故选择“Abstract Pattern”；整体视觉简洁克制，因此选“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2113611, 19991834, '品牌标识', '该款背部为大面积方形Logo图案并集中呈现，属于“Placement Print”布局；表现方式为“Print”印花；图案核心为单一Logo元素，归为“Single Element Pattern”；具体元素为品牌标识，选“Logo Placement”；Logo属于符号化设计，不描绘具体具象物体，故选择“Abstract Pattern”；整体视觉简洁克制，因此选“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2113612, 19991835, '品牌标识', '该款背部为大面积方形Logo图案并集中呈现，属于“Placement Print”布局；表现方式为“Print”印花；图案核心为单一Logo元素，归为“Single Element Pattern”；具体元素为品牌标识，选“Logo Placement”；Logo属于符号化设计，不描绘具体具象物体，故选择“Abstract Pattern”；整体视觉简洁克制，因此选“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2113602, 19991829, '品牌标识', '整体以纯色呈现，并在口袋处出现品牌Logo的局部图案，属于“位置印花（Placement Print）”，图案元素为“Logo放置（Logo Placement）”与“纯色（Pure Color）”。由于同时存在纯色面与Logo元素，归为“组合图案（Composed Pattern）”。图案定义选择“具象图案（Representational Pattern）”，因为Logo具有明确识别性。整体视觉简洁，符合“极简风格（Minimalist Style）”。');
INSERT INTO `clothing_pattern_info` VALUES (2113603, 19991829, '纯色', '整体以纯色呈现，并在口袋处出现品牌Logo的局部图案，属于“位置印花（Placement Print）”，图案元素为“Logo放置（Logo Placement）”与“纯色（Pure Color）”。由于同时存在纯色面与Logo元素，归为“组合图案（Composed Pattern）”。图案定义选择“具象图案（Representational Pattern）”，因为Logo具有明确识别性。整体视觉简洁，符合“极简风格（Minimalist Style）”。');
