INSERT INTO `clothing_pattern_info` VALUES (2113606, 19991831, '品牌标识', '整体以纯色呈现，并在口袋处出现品牌Logo的局部图案，属于“位置印花（Placement Print）”，图案元素为“Logo放置（Logo Placement）”与“纯色（Pure Color）”。由于同时存在纯色面与Logo元素，归为“组合图案（Composed Pattern）”。图案定义选择“具象图案（Representational Pattern）”，因为Logo具有明确识别性。整体视觉简洁，符合“极简风格（Minimalist Style）”。');
INSERT INTO `clothing_pattern_info` VALUES (2113607, 19991831, '纯色', '整体以纯色呈现，并在口袋处出现品牌Logo的局部图案，属于“位置印花（Placement Print）”，图案元素为“Logo放置（Logo Placement）”与“纯色（Pure Color）”。由于同时存在纯色面与Logo元素，归为“组合图案（Composed Pattern）”。图案定义选择“具象图案（Representational Pattern）”，因为Logo具有明确识别性。整体视觉简洁，符合“极简风格（Minimalist Style）”。');
INSERT INTO `clothing_pattern_info` VALUES (2113598, 19991825, '品牌标识', '从图片可见帽体为纯色，前幅有单个TNF标志刺绣，属于局部图案布局，因此选择“Localized Pattern”；工艺为“Embroidery”。图案由单一元素构成，选择“Single Element Pattern”。元素为品牌标识，对应“Logo Placement”。该标识可被识别，属“Representational Pattern”。整体风格简洁克制，选择“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2113599, 19991826, '品牌标识', '从图片可见帽体为纯色，前幅有单个TNF标志刺绣，属于局部图案布局，因此选择“Localized Pattern”；工艺为“Embroidery”。图案由单一元素构成，选择“Single Element Pattern”。元素为品牌标识，对应“Logo Placement”。该标识可被识别，属“Representational Pattern”。整体风格简洁克制，选择“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2113600, 19991827, '品牌标识', '从图片可见帽体为纯色，前幅有单个TNF标志刺绣，属于局部图案布局，因此选择“Localized Pattern”；工艺为“Embroidery”。图案由单一元素构成，选择“Single Element Pattern”。元素为品牌标识，对应“Logo Placement”。该标识可被识别，属“Representational Pattern”。整体风格简洁克制，选择“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2113601, 19991828, '品牌标识', '从图片可见帽体为纯色，前幅有单个TNF标志刺绣，属于局部图案布局，因此选择“Localized Pattern”；工艺为“Embroidery”。图案由单一元素构成，选择“Single Element Pattern”。元素为品牌标识，对应“Logo Placement”。该标识可被识别，属“Representational Pattern”。整体风格简洁克制，选择“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2113588, 19991820, '纯色', '整体为纯色基底，属于“Solid color”。仅在左下摆具有品牌标识，位置集中、面积小，归为“Localized Pattern”，元素为“Logo Placement”，技法为“Embroidery”。图案元素单一，归为“Single Element Pattern”。整体无具象图案，以简洁配色呈现，故选择“Abstract Pattern”，风格偏简约，可用“Minimalist Style”描述。');
INSERT INTO `clothing_pattern_info` VALUES (2113589, 19991820, '品牌标识', '整体为纯色基底，属于“Solid color”。仅在左下摆具有品牌标识，位置集中、面积小，归为“Localized Pattern”，元素为“Logo Placement”，技法为“Embroidery”。图案元素单一，归为“Single Element Pattern”。整体无具象图案，以简洁配色呈现，故选择“Abstract Pattern”，风格偏简约，可用“Minimalist Style”描述。');
