INSERT INTO `clothing_pattern_info` VALUES (2113594, 19991823, '纯色', '整体为纯色基底，属于“Solid color”。仅在左下摆具有品牌标识，位置集中、面积小，归为“Localized Pattern”，元素为“Logo Placement”，技法为“Embroidery”。图案元素单一，归为“Single Element Pattern”。整体无具象图案，以简洁配色呈现，故选择“Abstract Pattern”，风格偏简约，可用“Minimalist Style”描述。');
INSERT INTO `clothing_pattern_info` VALUES (2113595, 19991823, '品牌标识', '整体为纯色基底，属于“Solid color”。仅在左下摆具有品牌标识，位置集中、面积小，归为“Localized Pattern”，元素为“Logo Placement”，技法为“Embroidery”。图案元素单一，归为“Single Element Pattern”。整体无具象图案，以简洁配色呈现，故选择“Abstract Pattern”，风格偏简约，可用“Minimalist Style”描述。');
INSERT INTO `clothing_pattern_info` VALUES (2113596, 19991824, '物体', '整体为全幅排布的图案（Allover pattern），以印花工艺呈现（Print），由多个元素构成（Composed Pattern），包含明信片等物体元素（Object pattern）及文字（Text）。图案来源于现实物体，属于再现性（Representational Pattern）。风格强调复古（Vintage Style），并以插画绘制效果呈现（Illustration Effect）。');
INSERT INTO `clothing_pattern_info` VALUES (2113597, 19991824, '文字', '整体为全幅排布的图案（Allover pattern），以印花工艺呈现（Print），由多个元素构成（Composed Pattern），包含明信片等物体元素（Object pattern）及文字（Text）。图案来源于现实物体，属于再现性（Representational Pattern）。风格强调复古（Vintage Style），并以插画绘制效果呈现（Illustration Effect）。');
INSERT INTO `clothing_pattern_info` VALUES (2120075, 19996825, '纯色', '杯子本身为纯色底，因此选择“Pure Color”“Solid color”。图案来源于孩子自由涂鸦，构图不规则且内容抽象，整体归类为“Abstract Pattern”。杯身整体布局简洁，以空白为主，图案集中在局部，视觉上风格偏简洁直观，因此选用“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2120076, 19996825, '纯色', '杯子本身为纯色底，因此选择“Pure Color”“Solid color”。图案来源于孩子自由涂鸦，构图不规则且内容抽象，整体归类为“Abstract Pattern”。杯身整体布局简洁，以空白为主，图案集中在局部，视觉上风格偏简洁直观，因此选用“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2120065, 19996820, '纯色', '花器整体为透明无图案设计，仅呈现纯净玻璃效果，没有任何印花或图形，因此图案元素上选择“Pure Color”和“Solid color”来表示无花纹的单色外观。从整体视觉上看不存在具象图案，属于“Abstract Pattern”范畴。');
INSERT INTO `clothing_pattern_info` VALUES (2120066, 19996820, '纯色', '花器整体为透明无图案设计，仅呈现纯净玻璃效果，没有任何印花或图形，因此图案元素上选择“Pure Color”和“Solid color”来表示无花纹的单色外观。从整体视觉上看不存在具象图案，属于“Abstract Pattern”范畴。');
INSERT INTO `clothing_pattern_info` VALUES (2120067, 19996821, '纯色', '花器整体为透明无图案设计，仅呈现纯净玻璃效果，没有任何印花或图形，因此图案元素上选择“Pure Color”和“Solid color”来表示无花纹的单色外观。从整体视觉上看不存在具象图案，属于“Abstract Pattern”范畴。');
INSERT INTO `clothing_pattern_info` VALUES (2120068, 19996821, '纯色', '花器整体为透明无图案设计，仅呈现纯净玻璃效果，没有任何印花或图形，因此图案元素上选择“Pure Color”和“Solid color”来表示无花纹的单色外观。从整体视觉上看不存在具象图案，属于“Abstract Pattern”范畴。');
INSERT INTO `clothing_pattern_info` VALUES (2120069, 19996822, '纯色', '花盆表面整体为单一色调，没有明显图案元素，因此选择“Pure Color/纯色”和“Solid color/纯色”作为图案元素；整体仅是颜色与立体文字的构成，没有具象图形，归为“Abstract Pattern/抽象图案”；视觉风格简洁干净，没有复杂装饰，符合“Minimalist Style/极简风格”。');
INSERT INTO `clothing_pattern_info` VALUES (2120070, 19996822, '纯色', '花盆表面整体为单一色调，没有明显图案元素，因此选择“Pure Color/纯色”和“Solid color/纯色”作为图案元素；整体仅是颜色与立体文字的构成，没有具象图形，归为“Abstract Pattern/抽象图案”；视觉风格简洁干净，没有复杂装饰，符合“Minimalist Style/极简风格”。');
INSERT INTO `clothing_pattern_info` VALUES (2120071, 19996823, '纯色', '花盆表面整体为单一色调，没有明显图案元素，因此选择“Pure Color/纯色”和“Solid color/纯色”作为图案元素；整体仅是颜色与立体文字的构成，没有具象图形，归为“Abstract Pattern/抽象图案”；视觉风格简洁干净，没有复杂装饰，符合“Minimalist Style/极简风格”。');
INSERT INTO `clothing_pattern_info` VALUES (2120072, 19996823, '纯色', '花盆表面整体为单一色调，没有明显图案元素，因此选择“Pure Color/纯色”和“Solid color/纯色”作为图案元素；整体仅是颜色与立体文字的构成，没有具象图形，归为“Abstract Pattern/抽象图案”；视觉风格简洁干净，没有复杂装饰，符合“Minimalist Style/极简风格”。');
INSERT INTO `clothing_pattern_info` VALUES (2120073, 19996824, '纯色', '从包装上可见糖本身几乎为单一浅棕色颗粒，整体视觉上属于“Pure Color（纯色）”与“Solid color（素色）”效果，没有明显具体图案，因此在图案定义上归为非具象的“Abstract Pattern（抽象图案）”。整体风格简洁，没有复杂装饰，符合“Minimalist Style（极简风格）”的特点。');
INSERT INTO `clothing_pattern_info` VALUES (2120074, 19996824, '纯色', '从包装上可见糖本身几乎为单一浅棕色颗粒，整体视觉上属于“Pure Color（纯色）”与“Solid color（素色）”效果，没有明显具体图案，因此在图案定义上归为非具象的“Abstract Pattern（抽象图案）”。整体风格简洁，没有复杂装饰，符合“Minimalist Style（极简风格）”的特点。');
INSERT INTO `clothing_pattern_info` VALUES (2120040, 19996799, '花卉图案', '杯垫表面整片区域都布满图案，故选择“Allover pattern”。图案通过簇绒/织造形成有色块的花型，更接近“Jacquard”式的结构性图案表现。整体是水果主题和枝叶等组合，因此在构成上为多个元素组合的“Composed Pattern”。元素上既有类花形和叶片，选用“Floral pattern”，同时也属于具体物体类图样，补充“Other patterns”。图案清晰表现出可辨认的水果和枝叶，属于写实具象范畴，因此用“Representational Pattern”。造型略夸张可爱、非写实细节，风格偏插画和卡通感，因此选择“Cartoon Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2120041, 19996799, '其他', '杯垫表面整片区域都布满图案，故选择“Allover pattern”。图案通过簇绒/织造形成有色块的花型，更接近“Jacquard”式的结构性图案表现。整体是水果主题和枝叶等组合，因此在构成上为多个元素组合的“Composed Pattern”。元素上既有类花形和叶片，选用“Floral pattern”，同时也属于具体物体类图样，补充“Other patterns”。图案清晰表现出可辨认的水果和枝叶，属于写实具象范畴，因此用“Representational Pattern”。造型略夸张可爱、非写实细节，风格偏插画和卡通感，因此选择“Cartoon Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2120042, 19996800, '花卉图案', '杯垫表面整片区域都布满图案，故选择“Allover pattern”。图案通过簇绒/织造形成有色块的花型，更接近“Jacquard”式的结构性图案表现。整体是水果主题和枝叶等组合，因此在构成上为多个元素组合的“Composed Pattern”。元素上既有类花形和叶片，选用“Floral pattern”，同时也属于具体物体类图样，补充“Other patterns”。图案清晰表现出可辨认的水果和枝叶，属于写实具象范畴，因此用“Representational Pattern”。造型略夸张可爱、非写实细节，风格偏插画和卡通感，因此选择“Cartoon Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2120043, 19996800, '其他', '杯垫表面整片区域都布满图案，故选择“Allover pattern”。图案通过簇绒/织造形成有色块的花型，更接近“Jacquard”式的结构性图案表现。整体是水果主题和枝叶等组合，因此在构成上为多个元素组合的“Composed Pattern”。元素上既有类花形和叶片，选用“Floral pattern”，同时也属于具体物体类图样，补充“Other patterns”。图案清晰表现出可辨认的水果和枝叶，属于写实具象范畴，因此用“Representational Pattern”。造型略夸张可爱、非写实细节，风格偏插画和卡通感，因此选择“Cartoon Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2120039, 19996798, '条纹', '从图片可以看到整体布面被连续的彩色条纹覆盖，属于整体铺满式图案，因此选择“Allover pattern”。条纹结构通过织造形成，有一定立体感，符合“Jacquard”的结构性图案特征。图案由多条不同颜色组合的条纹构成，而非单一元素，故选“Composed Pattern”。主要元素是规则的纵向“Stripes”。条纹并不表现具体具象物体，而是几何与色块的组合，因此在定义上归为“Abstract Pattern”。整体条纹构成简洁直接，没有复杂写实或复古处理，风格偏简洁明快，故归为“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2120036, 19996796, '纯色', '从图片看，整体为单色羊毛毡底色，搭配一条简洁的对比色线条，没有复杂花纹，因此在元素上归为“Pure Color（纯色）”，构成上属于单一元素的“Single Element Pattern（单一元素图案）”。线条只是简单配色装饰，不具具象含义，整体图案归类为“Abstract Pattern（抽象图案）”。');
INSERT INTO `clothing_pattern_info` VALUES (2120037, 19996797, '纯色', '从图片看杯身为单一奶黄色，无具体图案和花纹，因此选择“Pure Color/纯色”和“Solid color/纯色”作为图案元素。杯体没有局部位置的图案集中，整体视觉为简洁统一，因此可视为抽象的“Abstract Pattern”，且风格上偏向干净利落、装饰极简，所以增加“Minimalist Style/极简风格”来描述整体图案效果。');
INSERT INTO `clothing_pattern_info` VALUES (2120038, 19996797, '纯色', '从图片看杯身为单一奶黄色，无具体图案和花纹，因此选择“Pure Color/纯色”和“Solid color/纯色”作为图案元素。杯体没有局部位置的图案集中，整体视觉为简洁统一，因此可视为抽象的“Abstract Pattern”，且风格上偏向干净利落、装饰极简，所以增加“Minimalist Style/极简风格”来描述整体图案效果。');
INSERT INTO `clothing_pattern_info` VALUES (2120035, 19996795, '纯色', '从图片看整件为单一色牛仔布加纯色袖口拼接，没有明显局部图案，整体色调均匀，属于整体覆盖的“Allover pattern”。图案来源于牛仔组织与灯芯绒条纹结构，本质属于织造纹理，因此在工艺上归入“Jacquard”范畴。整体以面料本身结构与纯色块构成，没有单个独立图案单元，属于“Composed Pattern”而图案元素为“Solid color（纯色）”。整体并不表现具体物体，只是结构与色块，定义上为“Abstract Pattern”，风格简洁低调，归为“Minimalist Style（极简风格）”。');
INSERT INTO `clothing_pattern_info` VALUES (2120034, 19996794, '其他', '包身整体被单一元素“亮片”覆盖，构成统一的“Single Element Pattern”。亮片并非具体图案，而是形成不规则闪烁效果，因此在元素上选择“Other patterns”，在定义上归为非具象的“Abstract Pattern”。亮片反光呈现出类似插画式的闪烁视觉效果，可归入“Illustration Effect”。整体没有具体花朵、条纹或格纹等规则图案。');
INSERT INTO `clothing_pattern_info` VALUES (2120032, 19996792, '其他', '从图片可见裤身整体都有细密纹理，属于整体分布的“Allover pattern”。说明中提到“ハケメチェック”，为织造形成的纹理感格纹，因此归为“Jacquard”，图案由多种细小纹理构成，可视为“Composed Pattern”。视觉上并非明显花朵、条纹等常见元素，更接近低对比度的织纹效果，故在元素上用“Other patterns”概括，在定义上归入“Abstract Pattern”。整体图案简洁低调、装饰性弱，符合“Minimalist Style”的极简风格。');
INSERT INTO `clothing_pattern_info` VALUES (2120033, 19996793, '其他', '从图片可见裤身整体都有细密纹理，属于整体分布的“Allover pattern”。说明中提到“ハケメチェック”，为织造形成的纹理感格纹，因此归为“Jacquard”，图案由多种细小纹理构成，可视为“Composed Pattern”。视觉上并非明显花朵、条纹等常见元素，更接近低对比度的织纹效果，故在元素上用“Other patterns”概括，在定义上归入“Abstract Pattern”。整体图案简洁低调、装饰性弱，符合“Minimalist Style”的极简风格。');
INSERT INTO `clothing_pattern_info` VALUES (2120030, 19996790, '其他', '服装主体为素色大面积拼接，没有明显局部图案，因此整体以“Allover pattern”体现整体性拼接效果；装饰部分为蕾丝花样，用“Lace”表示工艺特征；多块不同材质组合成整体，用“Composed Pattern”体现由多个元素构成的图案关系；蕾丝内部花纹不以具体物体为主题，归为“Other patterns”，在图案定义上选择“Abstract Pattern”更贴切。整体视觉简洁克制，以材质差异为主，因此在风格上选用“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2120031, 19996791, '其他', '服装主体为素色大面积拼接，没有明显局部图案，因此整体以“Allover pattern”体现整体性拼接效果；装饰部分为蕾丝花样，用“Lace”表示工艺特征；多块不同材质组合成整体，用“Composed Pattern”体现由多个元素构成的图案关系；蕾丝内部花纹不以具体物体为主题，归为“Other patterns”，在图案定义上选择“Abstract Pattern”更贴切。整体视觉简洁克制，以材质差异为主，因此在风格上选用“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2120024, 19996787, '纯色', '从图片与描述看，裤子为单一色系，没有花朵、格纹、条纹等具体图案元素，因此选择“Pure Color/纯色”和“Solid color/素色”作为图案元素；整体没有具象图形，归类为“Abstract Pattern/抽象图案”更合适。未体现局部位置印花或特殊排布和工艺，故不添加其他标签。');
INSERT INTO `clothing_pattern_info` VALUES (2120025, 19996787, '纯色', '从图片与描述看，裤子为单一色系，没有花朵、格纹、条纹等具体图案元素，因此选择“Pure Color/纯色”和“Solid color/素色”作为图案元素；整体没有具象图形，归类为“Abstract Pattern/抽象图案”更合适。未体现局部位置印花或特殊排布和工艺，故不添加其他标签。');
INSERT INTO `clothing_pattern_info` VALUES (2120026, 19996788, '纯色', '从图片与描述看，裤子为单一色系，没有花朵、格纹、条纹等具体图案元素，因此选择“Pure Color/纯色”和“Solid color/素色”作为图案元素；整体没有具象图形，归类为“Abstract Pattern/抽象图案”更合适。未体现局部位置印花或特殊排布和工艺，故不添加其他标签。');
INSERT INTO `clothing_pattern_info` VALUES (2120027, 19996788, '纯色', '从图片与描述看，裤子为单一色系，没有花朵、格纹、条纹等具体图案元素，因此选择“Pure Color/纯色”和“Solid color/素色”作为图案元素；整体没有具象图形，归类为“Abstract Pattern/抽象图案”更合适。未体现局部位置印花或特殊排布和工艺，故不添加其他标签。');
INSERT INTO `clothing_pattern_info` VALUES (2120028, 19996789, '纯色', '从图片与描述看，裤子为单一色系，没有花朵、格纹、条纹等具体图案元素，因此选择“Pure Color/纯色”和“Solid color/素色”作为图案元素；整体没有具象图形，归类为“Abstract Pattern/抽象图案”更合适。未体现局部位置印花或特殊排布和工艺，故不添加其他标签。');
INSERT INTO `clothing_pattern_info` VALUES (2120029, 19996789, '纯色', '从图片与描述看，裤子为单一色系，没有花朵、格纹、条纹等具体图案元素，因此选择“Pure Color/纯色”和“Solid color/素色”作为图案元素；整体没有具象图形，归类为“Abstract Pattern/抽象图案”更合适。未体现局部位置印花或特殊排布和工艺，故不添加其他标签。');
INSERT INTO `clothing_pattern_info` VALUES (2120021, 19996784, '花卉图案', '从图片可见整圈都是重复的小花状图案，因此选择“Allover pattern”与“Composed Pattern”来描述整体布满、由多个元素组合的构成。图案通过串联珠子形成，属于立体点缀形式，对应“Beading”。米色与蓝色珠子组合出花朵感，归类为“Floral pattern”。花形较为概括和几何，并非写实，所以在定义维度选择“Abstract Pattern”。整体视觉类似手工随性排列的效果，故在风格上使用“Hand-drawn Style”来体现手作感。');
INSERT INTO `clothing_pattern_info` VALUES (2120022, 19996785, '花卉图案', '从图片可见整圈都是重复的小花状图案，因此选择“Allover pattern”与“Composed Pattern”来描述整体布满、由多个元素组合的构成。图案通过串联珠子形成，属于立体点缀形式，对应“Beading”。米色与蓝色珠子组合出花朵感，归类为“Floral pattern”。花形较为概括和几何，并非写实，所以在定义维度选择“Abstract Pattern”。整体视觉类似手工随性排列的效果，故在风格上使用“Hand-drawn Style”来体现手作感。');
INSERT INTO `clothing_pattern_info` VALUES (2120023, 19996786, '花卉图案', '从图片可见整圈都是重复的小花状图案，因此选择“Allover pattern”与“Composed Pattern”来描述整体布满、由多个元素组合的构成。图案通过串联珠子形成，属于立体点缀形式，对应“Beading”。米色与蓝色珠子组合出花朵感，归类为“Floral pattern”。花形较为概括和几何，并非写实，所以在定义维度选择“Abstract Pattern”。整体视觉类似手工随性排列的效果，故在风格上使用“Hand-drawn Style”来体现手作感。');
INSERT INTO `clothing_pattern_info` VALUES (2120017, 19996782, '纯色', '从图片看衣身为纯色深色面料，没有明显花型，因此选择“Pure Color/纯色”和“Solid color/素色”作为图案元素；整体无局部图案点缀，整件衣服的色块效果可视作“全身一致”的“Allover pattern”。装饰部分采用蕾丝拼接，因此在工艺上选择“Lace”。图案构成上由纯色底布与蕾丝装饰共同形成整体视觉，属于“Composed Pattern”。没有具体具象图案，更偏向抽象与简洁效果，因此在图案定义中选“Abstract Pattern”，图案风格上整体干净简约，所以用“Minimalist Style”描述。');
INSERT INTO `clothing_pattern_info` VALUES (2120018, 19996782, '纯色', '从图片看衣身为纯色深色面料，没有明显花型，因此选择“Pure Color/纯色”和“Solid color/素色”作为图案元素；整体无局部图案点缀，整件衣服的色块效果可视作“全身一致”的“Allover pattern”。装饰部分采用蕾丝拼接，因此在工艺上选择“Lace”。图案构成上由纯色底布与蕾丝装饰共同形成整体视觉，属于“Composed Pattern”。没有具体具象图案，更偏向抽象与简洁效果，因此在图案定义中选“Abstract Pattern”，图案风格上整体干净简约，所以用“Minimalist Style”描述。');
INSERT INTO `clothing_pattern_info` VALUES (2120019, 19996783, '纯色', '从图片看衣身为纯色深色面料，没有明显花型，因此选择“Pure Color/纯色”和“Solid color/素色”作为图案元素；整体无局部图案点缀，整件衣服的色块效果可视作“全身一致”的“Allover pattern”。装饰部分采用蕾丝拼接，因此在工艺上选择“Lace”。图案构成上由纯色底布与蕾丝装饰共同形成整体视觉，属于“Composed Pattern”。没有具体具象图案，更偏向抽象与简洁效果，因此在图案定义中选“Abstract Pattern”，图案风格上整体干净简约，所以用“Minimalist Style”描述。');
INSERT INTO `clothing_pattern_info` VALUES (2120020, 19996783, '纯色', '从图片看衣身为纯色深色面料，没有明显花型，因此选择“Pure Color/纯色”和“Solid color/素色”作为图案元素；整体无局部图案点缀，整件衣服的色块效果可视作“全身一致”的“Allover pattern”。装饰部分采用蕾丝拼接，因此在工艺上选择“Lace”。图案构成上由纯色底布与蕾丝装饰共同形成整体视觉，属于“Composed Pattern”。没有具体具象图案，更偏向抽象与简洁效果，因此在图案定义中选“Abstract Pattern”，图案风格上整体干净简约，所以用“Minimalist Style”描述。');
INSERT INTO `clothing_pattern_info` VALUES (2120010, 19996777, '花卉图案', '裙摆下半部分可以看到集中分布的花卉图案，属于局部区域的装饰，因此选择“Placement Print”和“Composed Pattern”。图案为花朵与枝叶元素，归类为“Floral pattern”，这类花卉图案具有可识别的具象形态，因此在定义上选“Representational Pattern”。整体画风简洁干净，没有复杂的渲染和多余装饰，风格偏“Minimalist Style”。同时商品成分中有“刺繍糸”，说明下摆花型是刺绣工艺，因此加入“Embroidery”标签。');
INSERT INTO `clothing_pattern_info` VALUES (2120011, 19996778, '花卉图案', '裙摆下半部分可以看到集中分布的花卉图案，属于局部区域的装饰，因此选择“Placement Print”和“Composed Pattern”。图案为花朵与枝叶元素，归类为“Floral pattern”，这类花卉图案具有可识别的具象形态，因此在定义上选“Representational Pattern”。整体画风简洁干净，没有复杂的渲染和多余装饰，风格偏“Minimalist Style”。同时商品成分中有“刺繍糸”，说明下摆花型是刺绣工艺，因此加入“Embroidery”标签。');
INSERT INTO `clothing_pattern_info` VALUES (2120012, 19996779, '花卉图案', '裙摆下半部分可以看到集中分布的花卉图案，属于局部区域的装饰，因此选择“Placement Print”和“Composed Pattern”。图案为花朵与枝叶元素，归类为“Floral pattern”，这类花卉图案具有可识别的具象形态，因此在定义上选“Representational Pattern”。整体画风简洁干净，没有复杂的渲染和多余装饰，风格偏“Minimalist Style”。同时商品成分中有“刺繍糸”，说明下摆花型是刺绣工艺，因此加入“Embroidery”标签。');
INSERT INTO `clothing_pattern_info` VALUES (2120013, 19996780, '纯色', '从图片和描述看，整体为纯色设计，没有明显花朵、条纹或格纹等具体图案元素，因此选择图案元素中的“Pure Color”和“Solid color”表示纯色外观。图案定义上，纯色不具具体具象图案，更接近“Abstract Pattern”的抽象图案分类。无明显局部印花或复杂排布，也未提及印花等工艺，故不添加其他维度标签。');
INSERT INTO `clothing_pattern_info` VALUES (2120014, 19996780, '纯色', '从图片和描述看，整体为纯色设计，没有明显花朵、条纹或格纹等具体图案元素，因此选择图案元素中的“Pure Color”和“Solid color”表示纯色外观。图案定义上，纯色不具具体具象图案，更接近“Abstract Pattern”的抽象图案分类。无明显局部印花或复杂排布，也未提及印花等工艺，故不添加其他维度标签。');
INSERT INTO `clothing_pattern_info` VALUES (2120015, 19996781, '纯色', '从图片和描述看，整体为纯色设计，没有明显花朵、条纹或格纹等具体图案元素，因此选择图案元素中的“Pure Color”和“Solid color”表示纯色外观。图案定义上，纯色不具具体具象图案，更接近“Abstract Pattern”的抽象图案分类。无明显局部印花或复杂排布，也未提及印花等工艺，故不添加其他维度标签。');
INSERT INTO `clothing_pattern_info` VALUES (2120016, 19996781, '纯色', '从图片和描述看，整体为纯色设计，没有明显花朵、条纹或格纹等具体图案元素，因此选择图案元素中的“Pure Color”和“Solid color”表示纯色外观。图案定义上，纯色不具具体具象图案，更接近“Abstract Pattern”的抽象图案分类。无明显局部印花或复杂排布，也未提及印花等工艺，故不添加其他维度标签。');
INSERT INTO `clothing_pattern_info` VALUES (2120007, 19996774, '花卉图案', '从图片可见，下摆部分布料上布满连续分布的小花图案，因此属于整体覆盖的“Allover pattern”，整体图案由多朵花组成，归为“Composed Pattern”。花朵以线条和局部填充表现，属于“Floral pattern”，这些花形有清晰可辨的具象形态，所以图案定义选择“Representational Pattern”。图案呈现方式类似刺绣花样，具有手绘感轮廓，故在技法上用“Embroidery”，风格上归入“Hand-drawn Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2120008, 19996775, '花卉图案', '从图片可见，下摆部分布料上布满连续分布的小花图案，因此属于整体覆盖的“Allover pattern”，整体图案由多朵花组成，归为“Composed Pattern”。花朵以线条和局部填充表现，属于“Floral pattern”，这些花形有清晰可辨的具象形态，所以图案定义选择“Representational Pattern”。图案呈现方式类似刺绣花样，具有手绘感轮廓，故在技法上用“Embroidery”，风格上归入“Hand-drawn Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2120009, 19996776, '花卉图案', '从图片可见，下摆部分布料上布满连续分布的小花图案，因此属于整体覆盖的“Allover pattern”，整体图案由多朵花组成，归为“Composed Pattern”。花朵以线条和局部填充表现，属于“Floral pattern”，这些花形有清晰可辨的具象形态，所以图案定义选择“Representational Pattern”。图案呈现方式类似刺绣花样，具有手绘感轮廓，故在技法上用“Embroidery”，风格上归入“Hand-drawn Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119999, 19996769, '花卉图案', '从图片与文案可见，整件上衣由多块不同花型的面料组合，所以使用“Composed Pattern（组合图案）”，整体分布于全身，属于“Allover pattern（满身图案）”。部分区域为刺绣花样，对应“Embroidery（刺绣）”，部分为提花组织，对应“Jacquard（提花）”，还有明显的镂空花样，对应“Lace（蕾丝）”。花型以植物花朵为主，选择“Floral pattern（花卉图案）”。图案为可识别的花卉形象，因此在图案定义上归为“Representational Pattern（具象图案）”。花朵轮廓略带手绘感，选用“Hand-drawn Style（手绘风格）”来体现其表现方式。');
INSERT INTO `clothing_pattern_info` VALUES (2120000, 19996770, '花卉图案', '从图片与文案可见，整件上衣由多块不同花型的面料组合，所以使用“Composed Pattern（组合图案）”，整体分布于全身，属于“Allover pattern（满身图案）”。部分区域为刺绣花样，对应“Embroidery（刺绣）”，部分为提花组织，对应“Jacquard（提花）”，还有明显的镂空花样，对应“Lace（蕾丝）”。花型以植物花朵为主，选择“Floral pattern（花卉图案）”。图案为可识别的花卉形象，因此在图案定义上归为“Representational Pattern（具象图案）”。花朵轮廓略带手绘感，选用“Hand-drawn Style（手绘风格）”来体现其表现方式。');
INSERT INTO `clothing_pattern_info` VALUES (2120001, 19996771, '纯色', '从图片来看整体为纯白色，没有明显花朵、几何等对比色图案，属于单一色面料，因此选择“Pure Color”和“Solid color”。蕾丝纹理虽有花样，但并非强烈具象图案，更偏装饰性的抽象肌理，故在图案定义上归为“Abstract Pattern”。整体视觉简洁干净，没有复杂花色，可视为“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2120002, 19996771, '纯色', '从图片来看整体为纯白色，没有明显花朵、几何等对比色图案，属于单一色面料，因此选择“Pure Color”和“Solid color”。蕾丝纹理虽有花样，但并非强烈具象图案，更偏装饰性的抽象肌理，故在图案定义上归为“Abstract Pattern”。整体视觉简洁干净，没有复杂花色，可视为“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2120003, 19996772, '纯色', '从图片来看整体为纯白色，没有明显花朵、几何等对比色图案，属于单一色面料，因此选择“Pure Color”和“Solid color”。蕾丝纹理虽有花样，但并非强烈具象图案，更偏装饰性的抽象肌理，故在图案定义上归为“Abstract Pattern”。整体视觉简洁干净，没有复杂花色，可视为“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2120004, 19996772, '纯色', '从图片来看整体为纯白色，没有明显花朵、几何等对比色图案，属于单一色面料，因此选择“Pure Color”和“Solid color”。蕾丝纹理虽有花样，但并非强烈具象图案，更偏装饰性的抽象肌理，故在图案定义上归为“Abstract Pattern”。整体视觉简洁干净，没有复杂花色，可视为“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2120005, 19996773, '纯色', '从图片来看整体为纯白色，没有明显花朵、几何等对比色图案，属于单一色面料，因此选择“Pure Color”和“Solid color”。蕾丝纹理虽有花样，但并非强烈具象图案，更偏装饰性的抽象肌理，故在图案定义上归为“Abstract Pattern”。整体视觉简洁干净，没有复杂花色，可视为“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2120006, 19996773, '纯色', '从图片来看整体为纯白色，没有明显花朵、几何等对比色图案，属于单一色面料，因此选择“Pure Color”和“Solid color”。蕾丝纹理虽有花样，但并非强烈具象图案，更偏装饰性的抽象肌理，故在图案定义上归为“Abstract Pattern”。整体视觉简洁干净，没有复杂花色，可视为“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119997, 19996768, '纯色', '从图片看，产品主体为单一浅色，没有可识别的花卉、条纹或卡通等具体图案，因此在图案元素上归为“Pure Color（纯色）”和“Solid color（素色）”。整体外观简洁干净，没有复杂装饰或明显图形构成，属于抽象的色块与形状关系，因此在图案定义上选择“Abstract Pattern（抽象图案）”。其视觉风格偏向简洁、现代设计语言，所以风格维度上选择“Minimalist Style（极简风格）”。');
INSERT INTO `clothing_pattern_info` VALUES (2119998, 19996768, '纯色', '从图片看，产品主体为单一浅色，没有可识别的花卉、条纹或卡通等具体图案，因此在图案元素上归为“Pure Color（纯色）”和“Solid color（素色）”。整体外观简洁干净，没有复杂装饰或明显图形构成，属于抽象的色块与形状关系，因此在图案定义上选择“Abstract Pattern（抽象图案）”。其视觉风格偏向简洁、现代设计语言，所以风格维度上选择“Minimalist Style（极简风格）”。');
INSERT INTO `clothing_pattern_info` VALUES (2119994, 19996765, '条纹', '从图片与描述看，裙身整体布满细针条纹，因此选择“Allover pattern”表示全身布满的连续图案；条纹结构有可能由织造纹路形成，故使用“Jacquard”来表示结构性条纹效果；整体由多条细条纹重复构成，为多元素的组合图案，选用“Composed Pattern”；具体元素为纵向“Stripes（条纹）”；该条纹并不表现具体物体，属于抽象几何，因此在图案定义上选择“Abstract Pattern”；整体风格简单克制、线条利落，因此在图案风格上使用“Minimalist Style”来体现极简感。');
INSERT INTO `clothing_pattern_info` VALUES (2119995, 19996766, '条纹', '从图片与描述看，裙身整体布满细针条纹，因此选择“Allover pattern”表示全身布满的连续图案；条纹结构有可能由织造纹路形成，故使用“Jacquard”来表示结构性条纹效果；整体由多条细条纹重复构成，为多元素的组合图案，选用“Composed Pattern”；具体元素为纵向“Stripes（条纹）”；该条纹并不表现具体物体，属于抽象几何，因此在图案定义上选择“Abstract Pattern”；整体风格简单克制、线条利落，因此在图案风格上使用“Minimalist Style”来体现极简感。');
INSERT INTO `clothing_pattern_info` VALUES (2119990, 19996763, '纯色', '从图片看帽体为单一深色牛仔布，没有明显装饰图案或花纹，因此在图案元素上选用“Pure Color（纯色）”和“Solid color（素色）”。牛仔布本身的经纬纹理不构成具象图案，整体视觉属于非具象的简洁色面，因此在图案定义上归为“Abstract Pattern（抽象图案）”。');
INSERT INTO `clothing_pattern_info` VALUES (2119991, 19996763, '纯色', '从图片看帽体为单一深色牛仔布，没有明显装饰图案或花纹，因此在图案元素上选用“Pure Color（纯色）”和“Solid color（素色）”。牛仔布本身的经纬纹理不构成具象图案，整体视觉属于非具象的简洁色面，因此在图案定义上归为“Abstract Pattern（抽象图案）”。');
INSERT INTO `clothing_pattern_info` VALUES (2119992, 19996764, '纯色', '从图片看帽体为单一深色牛仔布，没有明显装饰图案或花纹，因此在图案元素上选用“Pure Color（纯色）”和“Solid color（素色）”。牛仔布本身的经纬纹理不构成具象图案，整体视觉属于非具象的简洁色面，因此在图案定义上归为“Abstract Pattern（抽象图案）”。');
INSERT INTO `clothing_pattern_info` VALUES (2119993, 19996764, '纯色', '从图片看帽体为单一深色牛仔布，没有明显装饰图案或花纹，因此在图案元素上选用“Pure Color（纯色）”和“Solid color（素色）”。牛仔布本身的经纬纹理不构成具象图案，整体视觉属于非具象的简洁色面，因此在图案定义上归为“Abstract Pattern（抽象图案）”。');
INSERT INTO `clothing_pattern_info` VALUES (2119988, 19996761, '条纹', '袖子部分整体为条纹元素覆盖，属于“Stripes”条纹图案，并在袖子范围内连续出现，可视为“Composed Pattern”的组合图案与“Allover pattern”式分布。图案呈印花效果，对应“Print”。整体只是简单条纹，没有具象图形，因此在定义上归为“Abstract Pattern”。整体风格干净简洁，符合“Minimalist Style”的极简风格。');
INSERT INTO `clothing_pattern_info` VALUES (2119989, 19996762, '条纹', '袖子部分整体为条纹元素覆盖，属于“Stripes”条纹图案，并在袖子范围内连续出现，可视为“Composed Pattern”的组合图案与“Allover pattern”式分布。图案呈印花效果，对应“Print”。整体只是简单条纹，没有具象图形，因此在定义上归为“Abstract Pattern”。整体风格干净简洁，符合“Minimalist Style”的极简风格。');
INSERT INTO `clothing_pattern_info` VALUES (2119982, 19996755, '花卉图案', '从图片和描述可见，服装领口和袖口处有花朵图案，并明确说明为“フラワー刺繍”，所以工艺类型选择“Embroidery（刺绣）”。花朵与枝叶等元素组合分布在领口与袖口局部区域，属于多个元素组合，因此用“Composed Pattern（组合图案）”。图案元素为花卉，故选择“Floral pattern（花卉图案）”。花朵具有可辨认的具象形态，因此在图案定义维度选“Figurative Pattern（具象图案）”。从视觉效果看，花卉线条细腻，有手绘感而非写实印刷，故在风格上选“Hand-drawn Style（手绘风格）”。');
INSERT INTO `clothing_pattern_info` VALUES (2119983, 19996756, '花卉图案', '从图片和描述可见，服装领口和袖口处有花朵图案，并明确说明为“フラワー刺繍”，所以工艺类型选择“Embroidery（刺绣）”。花朵与枝叶等元素组合分布在领口与袖口局部区域，属于多个元素组合，因此用“Composed Pattern（组合图案）”。图案元素为花卉，故选择“Floral pattern（花卉图案）”。花朵具有可辨认的具象形态，因此在图案定义维度选“Figurative Pattern（具象图案）”。从视觉效果看，花卉线条细腻，有手绘感而非写实印刷，故在风格上选“Hand-drawn Style（手绘风格）”。');
INSERT INTO `clothing_pattern_info` VALUES (2119984, 19996757, '其他', '包袋表面的织纹呈现整体性图案效果，属于“Allover pattern”。说明中提到“ジャガード柄”，属于通过织造形成纹样的“Jacquard”。整体图案由多种纹理和块面组合，不是单一元素，因此选“Composed Pattern”。图案主要是抽象织纹归为“Other patterns”，整体无具体具象图形，归为“Abstract Pattern”。视觉风格简洁低调，以纯黑为主、局部提花和透明拼接，符合“Minimalist Style”的极简风格特征。');
INSERT INTO `clothing_pattern_info` VALUES (2119985, 19996758, '花卉图案', '裤子整体被花型覆盖，因此选择“Allover pattern”。面料为通体花型蕾丝，图案由结构呈现而非单纯印花，故在工艺上标注为“Lace”。图案由多朵花及枝叶组合构成，属于组合式构图，因此选“Composed Pattern”。花朵与叶片清晰可辨，是具象的自然元素，所以选“Floral pattern”，并在图案定义中归为“Representational Pattern”。整体花型并不夸张复杂，偏克制冷静，故在风格维度选择“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119986, 19996759, '花卉图案', '裤子整体被花型覆盖，因此选择“Allover pattern”。面料为通体花型蕾丝，图案由结构呈现而非单纯印花，故在工艺上标注为“Lace”。图案由多朵花及枝叶组合构成，属于组合式构图，因此选“Composed Pattern”。花朵与叶片清晰可辨，是具象的自然元素，所以选“Floral pattern”，并在图案定义中归为“Representational Pattern”。整体花型并不夸张复杂，偏克制冷静，故在风格维度选择“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119987, 19996760, '花卉图案', '裤子整体被花型覆盖，因此选择“Allover pattern”。面料为通体花型蕾丝，图案由结构呈现而非单纯印花，故在工艺上标注为“Lace”。图案由多朵花及枝叶组合构成，属于组合式构图，因此选“Composed Pattern”。花朵与叶片清晰可辨，是具象的自然元素，所以选“Floral pattern”，并在图案定义中归为“Representational Pattern”。整体花型并不夸张复杂，偏克制冷静，故在风格维度选择“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119978, 19996753, '纯色', '从图片可见衣身整体为单一深色，没有花朵、条纹、格子等明显图案元素，是干净的纯色面料，因此选择“Pure Color”和“Solid color”作为图案元素维度标签。整体无具体具象图形或文字，只体现颜色和结构变化，属于非具象装饰效果，因此在图案定义维度选择“Abstract Pattern”。');
INSERT INTO `clothing_pattern_info` VALUES (2119979, 19996753, '纯色', '从图片可见衣身整体为单一深色，没有花朵、条纹、格子等明显图案元素，是干净的纯色面料，因此选择“Pure Color”和“Solid color”作为图案元素维度标签。整体无具体具象图形或文字，只体现颜色和结构变化，属于非具象装饰效果，因此在图案定义维度选择“Abstract Pattern”。');
INSERT INTO `clothing_pattern_info` VALUES (2119980, 19996754, '纯色', '从图片可见衣身整体为单一深色，没有花朵、条纹、格子等明显图案元素，是干净的纯色面料，因此选择“Pure Color”和“Solid color”作为图案元素维度标签。整体无具体具象图形或文字，只体现颜色和结构变化，属于非具象装饰效果，因此在图案定义维度选择“Abstract Pattern”。');
INSERT INTO `clothing_pattern_info` VALUES (2119981, 19996754, '纯色', '从图片可见衣身整体为单一深色，没有花朵、条纹、格子等明显图案元素，是干净的纯色面料，因此选择“Pure Color”和“Solid color”作为图案元素维度标签。整体无具体具象图形或文字，只体现颜色和结构变化，属于非具象装饰效果，因此在图案定义维度选择“Abstract Pattern”。');
INSERT INTO `clothing_pattern_info` VALUES (2119971, 19996746, '其他', '从图片上看，裤身整体有大面积统一的水洗与做旧色差效果，因此选择“Allover pattern（整体图案）”和“Composed Pattern（组合图案）”。这类效果是通过水洗/喷洗等工艺形成的色彩变化，可归入“Print（印花/效果处理）”范畴。具体图案元素并非规则条纹或格纹，而是不规则的明暗晕染，所以用“Other patterns（其他图案）”来概括，整体更偏向“Abstract Pattern（抽象图案）”。视觉风格具有旧化、磨耗质感，带有复古气息，因此选择“Vintage Style（复古风格）”。');
INSERT INTO `clothing_pattern_info` VALUES (2119972, 19996747, '其他', '从图片上看，裤身整体有大面积统一的水洗与做旧色差效果，因此选择“Allover pattern（整体图案）”和“Composed Pattern（组合图案）”。这类效果是通过水洗/喷洗等工艺形成的色彩变化，可归入“Print（印花/效果处理）”范畴。具体图案元素并非规则条纹或格纹，而是不规则的明暗晕染，所以用“Other patterns（其他图案）”来概括，整体更偏向“Abstract Pattern（抽象图案）”。视觉风格具有旧化、磨耗质感，带有复古气息，因此选择“Vintage Style（复古风格）”。');
INSERT INTO `clothing_pattern_info` VALUES (2119973, 19996748, '其他', '从图片上看，裤身整体有大面积统一的水洗与做旧色差效果，因此选择“Allover pattern（整体图案）”和“Composed Pattern（组合图案）”。这类效果是通过水洗/喷洗等工艺形成的色彩变化，可归入“Print（印花/效果处理）”范畴。具体图案元素并非规则条纹或格纹，而是不规则的明暗晕染，所以用“Other patterns（其他图案）”来概括，整体更偏向“Abstract Pattern（抽象图案）”。视觉风格具有旧化、磨耗质感，带有复古气息，因此选择“Vintage Style（复古风格）”。');
INSERT INTO `clothing_pattern_info` VALUES (2119974, 19996749, '其他', '从图片上看，裤身整体有大面积统一的水洗与做旧色差效果，因此选择“Allover pattern（整体图案）”和“Composed Pattern（组合图案）”。这类效果是通过水洗/喷洗等工艺形成的色彩变化，可归入“Print（印花/效果处理）”范畴。具体图案元素并非规则条纹或格纹，而是不规则的明暗晕染，所以用“Other patterns（其他图案）”来概括，整体更偏向“Abstract Pattern（抽象图案）”。视觉风格具有旧化、磨耗质感，带有复古气息，因此选择“Vintage Style（复古风格）”。');
INSERT INTO `clothing_pattern_info` VALUES (2119975, 19996750, '花卉图案', '从图片看，整体面料上布满花卉与图案元素，属于「Allover pattern 全幅图案」，视觉上为印花工艺，故选择「Print」。图案由多种元素组合而成，非单一元素，因此归为「Composed Pattern」。主要元素为花朵与枝叶等，选择「Floral pattern」。整体图案偏具象又带抽象感，但无法对应具体具象物体场景，归类为「Abstract Pattern」。图案呈现类似插画式的细节与配色，风格上更接近「Illustration Effect」。');
INSERT INTO `clothing_pattern_info` VALUES (2119976, 19996751, '花卉图案', '从图片看，整体面料上布满花卉与图案元素，属于「Allover pattern 全幅图案」，视觉上为印花工艺，故选择「Print」。图案由多种元素组合而成，非单一元素，因此归为「Composed Pattern」。主要元素为花朵与枝叶等，选择「Floral pattern」。整体图案偏具象又带抽象感，但无法对应具体具象物体场景，归类为「Abstract Pattern」。图案呈现类似插画式的细节与配色，风格上更接近「Illustration Effect」。');
INSERT INTO `clothing_pattern_info` VALUES (2119977, 19996752, '其他', '从图片看，透明与提花面料拼接区域的装饰集中在局部，符合“Placement Print”的局部图案布局特征；整体由透明区与提花纹理区组合构成，属于“Composed Pattern”的组合构成；提花部分呈现抽象不规则花纹或纹饰，只能归为“Other patterns”；整体图案依然可以辨识为具体装饰纹样而非纯几何概念，故归为“Representational Pattern”；整体视觉简洁、以大面积纯色和少量纹理为主，风格偏“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119962, 19996740, '纯色', '从图片和描述看，裙子为单一纯色，没有花卉、条纹、格纹等具体图案元素，因此选择“Pure Color”和“Solid color”来体现其纯色设计。整体没有具象图形或文字，只是颜色本身的表现形式，归类为“Abstract Pattern”作为图案定义。');
INSERT INTO `clothing_pattern_info` VALUES (2119963, 19996740, '纯色', '从图片和描述看，裙子为单一纯色，没有花卉、条纹、格纹等具体图案元素，因此选择“Pure Color”和“Solid color”来体现其纯色设计。整体没有具象图形或文字，只是颜色本身的表现形式，归类为“Abstract Pattern”作为图案定义。');
INSERT INTO `clothing_pattern_info` VALUES (2119964, 19996741, '纯色', '从图片和描述看，裙子为单一纯色，没有花卉、条纹、格纹等具体图案元素，因此选择“Pure Color”和“Solid color”来体现其纯色设计。整体没有具象图形或文字，只是颜色本身的表现形式，归类为“Abstract Pattern”作为图案定义。');
INSERT INTO `clothing_pattern_info` VALUES (2119965, 19996741, '纯色', '从图片和描述看，裙子为单一纯色，没有花卉、条纹、格纹等具体图案元素，因此选择“Pure Color”和“Solid color”来体现其纯色设计。整体没有具象图形或文字，只是颜色本身的表现形式，归类为“Abstract Pattern”作为图案定义。');
INSERT INTO `clothing_pattern_info` VALUES (2119966, 19996742, '其他', '从图片和文案“ジャガード生地”可知裙身部分为整体性提花图案，因此选择“Jacquard”以及整体铺满式的“Allover pattern”，且图案与素色布料拼接构成整体造型，归为“Composed Pattern”。提花纹样并非具体花卉或动物，较抽象，故用“Other patterns”并在定义上选“Abstract Pattern”。整体图案简洁低调，偏摩登极简感，因此在风格上选择“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119967, 19996743, '其他', '从图片和文案“ジャガード生地”可知裙身部分为整体性提花图案，因此选择“Jacquard”以及整体铺满式的“Allover pattern”，且图案与素色布料拼接构成整体造型，归为“Composed Pattern”。提花纹样并非具体花卉或动物，较抽象，故用“Other patterns”并在定义上选“Abstract Pattern”。整体图案简洁低调，偏摩登极简感，因此在风格上选择“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119968, 19996744, '其他', '从图片和文案“ジャガード生地”可知裙身部分为整体性提花图案，因此选择“Jacquard”以及整体铺满式的“Allover pattern”，且图案与素色布料拼接构成整体造型，归为“Composed Pattern”。提花纹样并非具体花卉或动物，较抽象，故用“Other patterns”并在定义上选“Abstract Pattern”。整体图案简洁低调，偏摩登极简感，因此在风格上选择“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119969, 19996745, '纯色', '从图片看，裙身为深色纯色面料，没有花朵、格纹、字母等具体图案元素，因此在图案元素维度上选用“Pure Color（纯色）”和“Solid color（纯色块）”。整体仅通过剪裁线与结构变化形成视觉效果，没有具象图像或场景，所以在图案定义维度归为“Abstract Pattern（抽象图案）”。风格上图案呈现极简、干练的视觉印象，因此在风格效果维度选择“Minimalist Style（极简风格）”。');
INSERT INTO `clothing_pattern_info` VALUES (2119970, 19996745, '纯色', '从图片看，裙身为深色纯色面料，没有花朵、格纹、字母等具体图案元素，因此在图案元素维度上选用“Pure Color（纯色）”和“Solid color（纯色块）”。整体仅通过剪裁线与结构变化形成视觉效果，没有具象图像或场景，所以在图案定义维度归为“Abstract Pattern（抽象图案）”。风格上图案呈现极简、干练的视觉印象，因此在风格效果维度选择“Minimalist Style（极简风格）”。');
INSERT INTO `clothing_pattern_info` VALUES (2119960, 19996738, '纯色', '从图片看帽子为纯色无任何图案与logo，仅有结构线与扣件，因此在图案元素上选择“Pure Color”，构成上为单一元素所以选“Single Element Pattern”，整体没有具象图形或花卉等，归为“Abstract Pattern”。没有明显印花布局或特殊工艺图案，因此不选择其他标签。');
INSERT INTO `clothing_pattern_info` VALUES (2119961, 19996739, '纯色', '从图片看帽子为纯色无任何图案与logo，仅有结构线与扣件，因此在图案元素上选择“Pure Color”，构成上为单一元素所以选“Single Element Pattern”，整体没有具象图形或花卉等，归为“Abstract Pattern”。没有明显印花布局或特殊工艺图案，因此不选择其他标签。');
INSERT INTO `clothing_pattern_info` VALUES (2119954, 19996732, '条纹', '从图片来看，整件背心表面布满细密纵向纹路，属于整体覆盖的“Allover pattern（整体图案）”，图案是由织造结构形成的罗纹纹路，因此归为“Jacquard（提花/组织纹理图案）”。这些纵向纹路均匀排布，构成整体“Composed Pattern（组合图案）”。纵向线性元素可归为“Stripes（条纹）”，但并非具象物体，只是结构性条纹，所以在定义上属于“Abstract Pattern（抽象图案）”。整体视觉简洁干净，风格偏“Minimalist Style（极简风格）”。');
INSERT INTO `clothing_pattern_info` VALUES (2119955, 19996733, '条纹', '从图片来看，整件背心表面布满细密纵向纹路，属于整体覆盖的“Allover pattern（整体图案）”，图案是由织造结构形成的罗纹纹路，因此归为“Jacquard（提花/组织纹理图案）”。这些纵向纹路均匀排布，构成整体“Composed Pattern（组合图案）”。纵向线性元素可归为“Stripes（条纹）”，但并非具象物体，只是结构性条纹，所以在定义上属于“Abstract Pattern（抽象图案）”。整体视觉简洁干净，风格偏“Minimalist Style（极简风格）”。');
INSERT INTO `clothing_pattern_info` VALUES (2119956, 19996734, '条纹', '从图片来看，整件背心表面布满细密纵向纹路，属于整体覆盖的“Allover pattern（整体图案）”，图案是由织造结构形成的罗纹纹路，因此归为“Jacquard（提花/组织纹理图案）”。这些纵向纹路均匀排布，构成整体“Composed Pattern（组合图案）”。纵向线性元素可归为“Stripes（条纹）”，但并非具象物体，只是结构性条纹，所以在定义上属于“Abstract Pattern（抽象图案）”。整体视觉简洁干净，风格偏“Minimalist Style（极简风格）”。');
