INSERT INTO `clothing_pattern_info` VALUES (2119958, 19996736, '条纹', '从图片来看，整件背心表面布满细密纵向纹路，属于整体覆盖的“Allover pattern（整体图案）”，图案是由织造结构形成的罗纹纹路，因此归为“Jacquard（提花/组织纹理图案）”。这些纵向纹路均匀排布，构成整体“Composed Pattern（组合图案）”。纵向线性元素可归为“Stripes（条纹）”，但并非具象物体，只是结构性条纹，所以在定义上属于“Abstract Pattern（抽象图案）”。整体视觉简洁干净，风格偏“Minimalist Style（极简风格）”。');
INSERT INTO `clothing_pattern_info` VALUES (2119959, 19996737, '条纹', '从图片来看，整件背心表面布满细密纵向纹路，属于整体覆盖的“Allover pattern（整体图案）”，图案是由织造结构形成的罗纹纹路，因此归为“Jacquard（提花/组织纹理图案）”。这些纵向纹路均匀排布，构成整体“Composed Pattern（组合图案）”。纵向线性元素可归为“Stripes（条纹）”，但并非具象物体，只是结构性条纹，所以在定义上属于“Abstract Pattern（抽象图案）”。整体视觉简洁干净，风格偏“Minimalist Style（极简风格）”。');
INSERT INTO `clothing_pattern_info` VALUES (2119949, 19996728, '条纹', '从图片和描述看，衣身整体为连续横向多色条纹，因此选择“全身图案 Allover pattern”和“条纹 Stripes”，图案覆盖全身且为多元素组合，归为“组合图案 Composed Pattern”。图案是通过色织/印花方式表现，归入“Print”。条纹仅为抽象几何排列，没有具体形象，故定义为“抽象图案 Abstract Pattern”。整体条纹风格简洁克制，没有复杂细节与装饰，适合归为“极简风格 Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119950, 19996729, '条纹', '从图片和描述看，衣身整体为连续横向多色条纹，因此选择“全身图案 Allover pattern”和“条纹 Stripes”，图案覆盖全身且为多元素组合，归为“组合图案 Composed Pattern”。图案是通过色织/印花方式表现，归入“Print”。条纹仅为抽象几何排列，没有具体形象，故定义为“抽象图案 Abstract Pattern”。整体条纹风格简洁克制，没有复杂细节与装饰，适合归为“极简风格 Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119951, 19996730, '条纹', '从图片和描述看，衣身整体为连续横向多色条纹，因此选择“全身图案 Allover pattern”和“条纹 Stripes”，图案覆盖全身且为多元素组合，归为“组合图案 Composed Pattern”。图案是通过色织/印花方式表现，归入“Print”。条纹仅为抽象几何排列，没有具体形象，故定义为“抽象图案 Abstract Pattern”。整体条纹风格简洁克制，没有复杂细节与装饰，适合归为“极简风格 Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119946, 19996725, '格纹', '从图片及描述“ミニチェック柄”可见衣身整体布满细小格纹，因此选择“Allover pattern”和“check”，并归为整体构成的“Composed Pattern”。格纹源自现实中常见的几何格子，属于具象图案，所以选“Representational Pattern”。风格简洁低调，格纹细密规整，没有夸张装饰，符合“Minimalist Style”。面料格纹通过织造形成而非夸张印花，可用“Jacquard”表示该类织造图案。');
INSERT INTO `clothing_pattern_info` VALUES (2119947, 19996726, '格纹', '从图片及描述“ミニチェック柄”可见衣身整体布满细小格纹，因此选择“Allover pattern”和“check”，并归为整体构成的“Composed Pattern”。格纹源自现实中常见的几何格子，属于具象图案，所以选“Representational Pattern”。风格简洁低调，格纹细密规整，没有夸张装饰，符合“Minimalist Style”。面料格纹通过织造形成而非夸张印花，可用“Jacquard”表示该类织造图案。');
INSERT INTO `clothing_pattern_info` VALUES (2119948, 19996727, '格纹', '从图片及描述“ミニチェック柄”可见衣身整体布满细小格纹，因此选择“Allover pattern”和“check”，并归为整体构成的“Composed Pattern”。格纹源自现实中常见的几何格子，属于具象图案，所以选“Representational Pattern”。风格简洁低调，格纹细密规整，没有夸张装饰，符合“Minimalist Style”。面料格纹通过织造形成而非夸张印花，可用“Jacquard”表示该类织造图案。');
INSERT INTO `clothing_pattern_info` VALUES (2119944, 19996723, '点', '从图片可见裙身整体布满规则圆点，因此选择“Dot”作为主要图案元素；圆点遍布全裙，属于“全幅式排布”，对应“Allover pattern”，且是一整块布料上的连续图案，归为“Composed Pattern”。图案来源于具体可识别形状而非纯抽象，故选“Figurative Pattern”。工艺上为常见波点印花，判断为“Print”。整体风格简洁清爽，无复杂装饰，图案呈现克制干净，因此在风格维度选择“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119945, 19996724, '点', '从图片可见裙身整体布满规则圆点，因此选择“Dot”作为主要图案元素；圆点遍布全裙，属于“全幅式排布”，对应“Allover pattern”，且是一整块布料上的连续图案，归为“Composed Pattern”。图案来源于具体可识别形状而非纯抽象，故选“Figurative Pattern”。工艺上为常见波点印花，判断为“Print”。整体风格简洁清爽，无复杂装饰，图案呈现克制干净，因此在风格维度选择“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119941, 19996720, '其他', '整体以统一规则的网眼结构铺满全身，属于“Allover pattern”且为整体性的“Composed Pattern”。网眼由针织结构形成，可视为一种“Jacquard”式组织效果，其视觉呈现为规则的几何小孔，因此在元素上归为“Other patterns”。图案并不具象具体物体，整体偏抽象感，故选择“Abstract Pattern”，且整体线条简洁干净，风格偏“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119942, 19996721, '其他', '整体以统一规则的网眼结构铺满全身，属于“Allover pattern”且为整体性的“Composed Pattern”。网眼由针织结构形成，可视为一种“Jacquard”式组织效果，其视觉呈现为规则的几何小孔，因此在元素上归为“Other patterns”。图案并不具象具体物体，整体偏抽象感，故选择“Abstract Pattern”，且整体线条简洁干净，风格偏“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119943, 19996722, '其他', '整体以统一规则的网眼结构铺满全身，属于“Allover pattern”且为整体性的“Composed Pattern”。网眼由针织结构形成，可视为一种“Jacquard”式组织效果，其视觉呈现为规则的几何小孔，因此在元素上归为“Other patterns”。图案并不具象具体物体，整体偏抽象感，故选择“Abstract Pattern”，且整体线条简洁干净，风格偏“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119935, 19996717, '纯色', '从图片可见整件衣服整体为纯色面料，仅有边缘处细线撞色，并无明显花朵、几何、动物等具体图案元素，因此在图案元素维度选择“Pure Color（纯色）”与“Solid color（素色）”描述其无图案的特征。在图案定义维度上，这类无具体具象图案的设计归入“Abstract Pattern（抽象图案）”，以表示整体视觉效果偏向简洁抽象而非具象图案。未见整体排布图案或特殊工艺印花，因此不选择其他图案标签。');
INSERT INTO `clothing_pattern_info` VALUES (2119936, 19996717, '纯色', '从图片可见整件衣服整体为纯色面料，仅有边缘处细线撞色，并无明显花朵、几何、动物等具体图案元素，因此在图案元素维度选择“Pure Color（纯色）”与“Solid color（素色）”描述其无图案的特征。在图案定义维度上，这类无具体具象图案的设计归入“Abstract Pattern（抽象图案）”，以表示整体视觉效果偏向简洁抽象而非具象图案。未见整体排布图案或特殊工艺印花，因此不选择其他图案标签。');
INSERT INTO `clothing_pattern_info` VALUES (2119937, 19996718, '纯色', '从图片可见整件衣服整体为纯色面料，仅有边缘处细线撞色，并无明显花朵、几何、动物等具体图案元素，因此在图案元素维度选择“Pure Color（纯色）”与“Solid color（素色）”描述其无图案的特征。在图案定义维度上，这类无具体具象图案的设计归入“Abstract Pattern（抽象图案）”，以表示整体视觉效果偏向简洁抽象而非具象图案。未见整体排布图案或特殊工艺印花，因此不选择其他图案标签。');
INSERT INTO `clothing_pattern_info` VALUES (2119938, 19996718, '纯色', '从图片可见整件衣服整体为纯色面料，仅有边缘处细线撞色，并无明显花朵、几何、动物等具体图案元素，因此在图案元素维度选择“Pure Color（纯色）”与“Solid color（素色）”描述其无图案的特征。在图案定义维度上，这类无具体具象图案的设计归入“Abstract Pattern（抽象图案）”，以表示整体视觉效果偏向简洁抽象而非具象图案。未见整体排布图案或特殊工艺印花，因此不选择其他图案标签。');
INSERT INTO `clothing_pattern_info` VALUES (2119939, 19996719, '纯色', '从图片可见整件衣服整体为纯色面料，仅有边缘处细线撞色，并无明显花朵、几何、动物等具体图案元素，因此在图案元素维度选择“Pure Color（纯色）”与“Solid color（素色）”描述其无图案的特征。在图案定义维度上，这类无具体具象图案的设计归入“Abstract Pattern（抽象图案）”，以表示整体视觉效果偏向简洁抽象而非具象图案。未见整体排布图案或特殊工艺印花，因此不选择其他图案标签。');
INSERT INTO `clothing_pattern_info` VALUES (2119940, 19996719, '纯色', '从图片可见整件衣服整体为纯色面料，仅有边缘处细线撞色，并无明显花朵、几何、动物等具体图案元素，因此在图案元素维度选择“Pure Color（纯色）”与“Solid color（素色）”描述其无图案的特征。在图案定义维度上，这类无具体具象图案的设计归入“Abstract Pattern（抽象图案）”，以表示整体视觉效果偏向简洁抽象而非具象图案。未见整体排布图案或特殊工艺印花，因此不选择其他图案标签。');
INSERT INTO `clothing_pattern_info` VALUES (2119932, 19996714, '纯色', '从图片来看整体为单一色调，没有明显图案元素，属于“Pure Color/纯色”。色面并非完全均匀，而是带有颜料染造成的整体褪色与做旧效果，因此视为整体铺开的“Allover pattern/全幅图案”，工艺上对应“Print/印花类颜料处理”，整体色块构成“Composed Pattern/组合图案”，图案并不表现具体物体，归为“Abstract Pattern/抽象图案”。这种仿旧、褪色效果具有“Vintage Style/复古风格”的视觉特征。');
INSERT INTO `clothing_pattern_info` VALUES (2119933, 19996715, '纯色', '从图片来看整体为单一色调，没有明显图案元素，属于“Pure Color/纯色”。色面并非完全均匀，而是带有颜料染造成的整体褪色与做旧效果，因此视为整体铺开的“Allover pattern/全幅图案”，工艺上对应“Print/印花类颜料处理”，整体色块构成“Composed Pattern/组合图案”，图案并不表现具体物体，归为“Abstract Pattern/抽象图案”。这种仿旧、褪色效果具有“Vintage Style/复古风格”的视觉特征。');
INSERT INTO `clothing_pattern_info` VALUES (2119934, 19996716, '纯色', '从图片来看整体为单一色调，没有明显图案元素，属于“Pure Color/纯色”。色面并非完全均匀，而是带有颜料染造成的整体褪色与做旧效果，因此视为整体铺开的“Allover pattern/全幅图案”，工艺上对应“Print/印花类颜料处理”，整体色块构成“Composed Pattern/组合图案”，图案并不表现具体物体，归为“Abstract Pattern/抽象图案”。这种仿旧、褪色效果具有“Vintage Style/复古风格”的视觉特征。');
INSERT INTO `clothing_pattern_info` VALUES (2119930, 19996712, '字母', '衣身整体为素色，仅在前胸位置有一处“BROOKLYN”字母装饰，因此属于局部的“Placement Print/局部图案”，字母以立体贴布形式呈现，对应“Embroidery/刺绣工艺”及“Single Element Pattern/单一元素图案”。图案元素为字母，所以选择“Letter/字母”。整体图案可被识别为具体文字，故归类为“Representational Pattern/具象图案”，风格干净简洁，因此补充“Minimalist Style/极简风格”。');
INSERT INTO `clothing_pattern_info` VALUES (2119931, 19996713, '字母', '衣身整体为素色，仅在前胸位置有一处“BROOKLYN”字母装饰，因此属于局部的“Placement Print/局部图案”，字母以立体贴布形式呈现，对应“Embroidery/刺绣工艺”及“Single Element Pattern/单一元素图案”。图案元素为字母，所以选择“Letter/字母”。整体图案可被识别为具体文字，故归类为“Representational Pattern/具象图案”，风格干净简洁，因此补充“Minimalist Style/极简风格”。');
INSERT INTO `clothing_pattern_info` VALUES (2119929, 19996711, '纯色', '从图片看，面料为单一深色，无可见格纹、条纹或其他具象图案，因此在图案元素上选择“Pure Color（纯色）”。整体没有局部图案或大面积印花，属于极简、无装饰的设计风格，因此在图案定义上归为“Abstract Pattern（抽象图案）”、并在风格维度选择“Minimalist Style（极简风格）”，对应其干净利落的商务西装外观。');
INSERT INTO `clothing_pattern_info` VALUES (2119927, 19996710, '纯色', '实物为纯色连衣裙，表面没有可见花朵、条纹、格纹等具体图案元素，因此在图案元素维度选择“Pure Color/纯色”和“Solid color/素色”。整体没有具象图形或可辨识对象，仅为单一色块归纳，定义上更接近“Abstract Pattern/抽象图案”这一图案定义类别。未见局部位置印花或织花，因此不选其他布局或工艺类标签。');
INSERT INTO `clothing_pattern_info` VALUES (2119928, 19996710, '纯色', '实物为纯色连衣裙，表面没有可见花朵、条纹、格纹等具体图案元素，因此在图案元素维度选择“Pure Color/纯色”和“Solid color/素色”。整体没有具象图形或可辨识对象，仅为单一色块归纳，定义上更接近“Abstract Pattern/抽象图案”这一图案定义类别。未见局部位置印花或织花，因此不选其他布局或工艺类标签。');
INSERT INTO `clothing_pattern_info` VALUES (2119925, 19996708, '其他', '裙身整体以多段蕾丝拼接和细褶装饰贯穿，属于整体布满的“Allover pattern”效果；装饰方式是织造花型的“Lace”而非单纯印花；多种装饰带组合成“Composed Pattern”；蕾丝花型本身较为简洁、不以具体花朵等具象图案为主，更接近“Other patterns”，整体图案偏抽象感，因此选择“Abstract Pattern”；视觉风格简洁克制，没有复杂浓艳的图案表现，所以归为“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119926, 19996709, '其他', '裙身整体以多段蕾丝拼接和细褶装饰贯穿，属于整体布满的“Allover pattern”效果；装饰方式是织造花型的“Lace”而非单纯印花；多种装饰带组合成“Composed Pattern”；蕾丝花型本身较为简洁、不以具体花朵等具象图案为主，更接近“Other patterns”，整体图案偏抽象感，因此选择“Abstract Pattern”；视觉风格简洁克制，没有复杂浓艳的图案表现，所以归为“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119923, 19996706, '花卉图案', '耳饰为局部花朵造型，因此用“Placement Print（局部图案）”和“Single Element Pattern（单一元素图案）”描述图案构成；造型元素为花朵，故选择“Floral pattern（花卉图案）”；花朵形象具象可辨，属于“Figurative Pattern（具象图案）”；整体造型简洁干净，没有复杂装饰风格，归为“Minimalist Style（极简风格）”。');
INSERT INTO `clothing_pattern_info` VALUES (2119924, 19996707, '花卉图案', '耳饰为局部花朵造型，因此用“Placement Print（局部图案）”和“Single Element Pattern（单一元素图案）”描述图案构成；造型元素为花朵，故选择“Floral pattern（花卉图案）”；花朵形象具象可辨，属于“Figurative Pattern（具象图案）”；整体造型简洁干净，没有复杂装饰风格，归为“Minimalist Style（极简风格）”。');
INSERT INTO `clothing_pattern_info` VALUES (2119920, 19996703, '纯色', '鞋面以大色块拼接为主，没有具体花卉、动物等具象图案，因此元素上归为“Pure Color”，整体由多种纯色拼接构成，属于“Composed Pattern”。拼接覆盖鞋面形成整体效果，可视作“Allover pattern”，而这些色块与线条不表现具体对象，归类为“Abstract Pattern”。');
INSERT INTO `clothing_pattern_info` VALUES (2119921, 19996704, '纯色', '鞋面以大色块拼接为主，没有具体花卉、动物等具象图案，因此元素上归为“Pure Color”，整体由多种纯色拼接构成，属于“Composed Pattern”。拼接覆盖鞋面形成整体效果，可视作“Allover pattern”，而这些色块与线条不表现具体对象，归类为“Abstract Pattern”。');
INSERT INTO `clothing_pattern_info` VALUES (2119922, 19996705, '纯色', '鞋面以大色块拼接为主，没有具体花卉、动物等具象图案，因此元素上归为“Pure Color”，整体由多种纯色拼接构成，属于“Composed Pattern”。拼接覆盖鞋面形成整体效果，可视作“Allover pattern”，而这些色块与线条不表现具体对象，归类为“Abstract Pattern”。');
INSERT INTO `clothing_pattern_info` VALUES (2119914, 19996697, '其他', '从图片看，胸前只有一块矩形图案，属于局部位置的“Placement Print 定位印花”，图案通过印花工艺呈现，因此选择“Print”。整体图案集中在单一区域，构成单一主要视觉元素，归为“Single Element Pattern”。图案由几何块面与网格组合而成，难以归入花卉、条纹或格子等常见元素，故用“Other patterns”表示。整体为几何块状非具象构成，属于“Abstract Pattern 抽象图案”。版面简洁、块面布局干净克制，因此在风格上归为“Minimalist Style 极简风格”。');
INSERT INTO `clothing_pattern_info` VALUES (2119915, 19996698, '其他', '从图片看，胸前只有一块矩形图案，属于局部位置的“Placement Print 定位印花”，图案通过印花工艺呈现，因此选择“Print”。整体图案集中在单一区域，构成单一主要视觉元素，归为“Single Element Pattern”。图案由几何块面与网格组合而成，难以归入花卉、条纹或格子等常见元素，故用“Other patterns”表示。整体为几何块状非具象构成，属于“Abstract Pattern 抽象图案”。版面简洁、块面布局干净克制，因此在风格上归为“Minimalist Style 极简风格”。');
INSERT INTO `clothing_pattern_info` VALUES (2119916, 19996699, '其他', '从图片看，胸前只有一块矩形图案，属于局部位置的“Placement Print 定位印花”，图案通过印花工艺呈现，因此选择“Print”。整体图案集中在单一区域，构成单一主要视觉元素，归为“Single Element Pattern”。图案由几何块面与网格组合而成，难以归入花卉、条纹或格子等常见元素，故用“Other patterns”表示。整体为几何块状非具象构成，属于“Abstract Pattern 抽象图案”。版面简洁、块面布局干净克制，因此在风格上归为“Minimalist Style 极简风格”。');
INSERT INTO `clothing_pattern_info` VALUES (2119917, 19996700, '其他', '从图片看，胸前只有一块矩形图案，属于局部位置的“Placement Print 定位印花”，图案通过印花工艺呈现，因此选择“Print”。整体图案集中在单一区域，构成单一主要视觉元素，归为“Single Element Pattern”。图案由几何块面与网格组合而成，难以归入花卉、条纹或格子等常见元素，故用“Other patterns”表示。整体为几何块状非具象构成，属于“Abstract Pattern 抽象图案”。版面简洁、块面布局干净克制，因此在风格上归为“Minimalist Style 极简风格”。');
INSERT INTO `clothing_pattern_info` VALUES (2119918, 19996701, '其他', '从图片看，胸前只有一块矩形图案，属于局部位置的“Placement Print 定位印花”，图案通过印花工艺呈现，因此选择“Print”。整体图案集中在单一区域，构成单一主要视觉元素，归为“Single Element Pattern”。图案由几何块面与网格组合而成，难以归入花卉、条纹或格子等常见元素，故用“Other patterns”表示。整体为几何块状非具象构成，属于“Abstract Pattern 抽象图案”。版面简洁、块面布局干净克制，因此在风格上归为“Minimalist Style 极简风格”。');
INSERT INTO `clothing_pattern_info` VALUES (2119919, 19996702, '花卉图案', '从图片看，白色蕾丝集中分布在领口和袖口局部位置，因此在布局上更接近“Placement Print（局部图案）”而非整身铺满。蕾丝呈现花朵与花边造型，可视为“Floral pattern（花卉图案）”，属于“Single Element Pattern（单一元素图案）”。蕾丝花形具象可辨认，所以图案定义选择“Representational Pattern（具象图案）”。蕾丝花型轮廓有手绘般的不规则感，可对应“Hand-drawn Style（手绘风格）”。工艺上虽属蕾丝编织与镂空效果，但在图案维度近似“Embroidery（刺绣类装饰）”，用以表示其装饰性立体花形图案。');
INSERT INTO `clothing_pattern_info` VALUES (2119908, 19996691, '字母', '图案为衣身前幅大面积的字母Logo，属于整体布局的“Allover pattern”倾向，同时以“Print”工艺呈现。在构成上由字母元素组合而成，属于“Composed Pattern”。核心元素是英文字母Logo，因此选用“Letter”。图案明确表达文字信息，属于具象含义的“Representational Pattern”。整体设计简洁清爽，因此风格上归为“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119909, 19996692, '字母', '图案为衣身前幅大面积的字母Logo，属于整体布局的“Allover pattern”倾向，同时以“Print”工艺呈现。在构成上由字母元素组合而成，属于“Composed Pattern”。核心元素是英文字母Logo，因此选用“Letter”。图案明确表达文字信息，属于具象含义的“Representational Pattern”。整体设计简洁清爽，因此风格上归为“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119910, 19996693, '字母', '图案为衣身前幅大面积的字母Logo，属于整体布局的“Allover pattern”倾向，同时以“Print”工艺呈现。在构成上由字母元素组合而成，属于“Composed Pattern”。核心元素是英文字母Logo，因此选用“Letter”。图案明确表达文字信息，属于具象含义的“Representational Pattern”。整体设计简洁清爽，因此风格上归为“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119911, 19996694, '字母', '图案为衣身前幅大面积的字母Logo，属于整体布局的“Allover pattern”倾向，同时以“Print”工艺呈现。在构成上由字母元素组合而成，属于“Composed Pattern”。核心元素是英文字母Logo，因此选用“Letter”。图案明确表达文字信息，属于具象含义的“Representational Pattern”。整体设计简洁清爽，因此风格上归为“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119912, 19996695, '字母', '图案为衣身前幅大面积的字母Logo，属于整体布局的“Allover pattern”倾向，同时以“Print”工艺呈现。在构成上由字母元素组合而成，属于“Composed Pattern”。核心元素是英文字母Logo，因此选用“Letter”。图案明确表达文字信息，属于具象含义的“Representational Pattern”。整体设计简洁清爽，因此风格上归为“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119913, 19996696, '字母', '图案为衣身前幅大面积的字母Logo，属于整体布局的“Allover pattern”倾向，同时以“Print”工艺呈现。在构成上由字母元素组合而成，属于“Composed Pattern”。核心元素是英文字母Logo，因此选用“Letter”。图案明确表达文字信息，属于具象含义的“Representational Pattern”。整体设计简洁清爽，因此风格上归为“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119907, 19996690, '佩斯利', '从图片和说明中的“ペイズリー柄のプリント”可见，全身布满规则重复的佩斯利图案，因此在布局上属于“Allover pattern 全身满印”，在工艺上属于“Print 印花”，图案由多个纹样组合构成，故为“Composed Pattern 组合图案”。图案元素本身是经典“Paisley 佩斯利”，属于可辨认的具象装饰纹样，因此在图案定义上选择“Representational Pattern 具象图案”更合适。');
INSERT INTO `clothing_pattern_info` VALUES (2119905, 19996689, '纯色', '从图片看整体为纯黑色，没有可见图案或花纹，因此在图案元素上选择“Pure Color（纯色）”和“Solid color（素色）”。各部位颜色一致属整体统一的“Allover pattern（整体布满式布局）”，没有局部定位图案。制作方式为普通染色/印染，归入“Print（印染类）”，整体由颜色这一单一元素构成，属于“Composed Pattern（组合图案）而非单一图形。没有具象图案，抽象上归为“Abstract Pattern（抽象图案）”。风格简单克制，故选择“Minimalist Style（极简风格）”。');
INSERT INTO `clothing_pattern_info` VALUES (2119906, 19996689, '纯色', '从图片看整体为纯黑色，没有可见图案或花纹，因此在图案元素上选择“Pure Color（纯色）”和“Solid color（素色）”。各部位颜色一致属整体统一的“Allover pattern（整体布满式布局）”，没有局部定位图案。制作方式为普通染色/印染，归入“Print（印染类）”，整体由颜色这一单一元素构成，属于“Composed Pattern（组合图案）而非单一图形。没有具象图案，抽象上归为“Abstract Pattern（抽象图案）”。风格简单克制，故选择“Minimalist Style（极简风格）”。');
INSERT INTO `clothing_pattern_info` VALUES (2119897, 19996683, '条纹', '从图片和文案看，整件衬衫以连续条纹为主，因此选择“Allover pattern（整体图案）”与“Stripes（条纹）”，属于整体排布的条纹图案；背部和局部有“Stranger Things”等文字与标志性元素，因此加入“Letter（文字）”。文案说明有“刺繍やプリント等を施した”，对应工艺选择“Embroidery（刺绣）”和“Print（印花）”。条纹加文字与标志元素共同构成整体设计，所以为“Composed Pattern（组合图案）”。整体图案来源于剧集形象，有明确可识别对象，图像含义清晰，因此在图案定义上归为“Figurative Pattern（具象图案）”。视觉风格干净简洁、线条规整，故在风格维度选择“Minimalist Style（极简风格）”。');
INSERT INTO `clothing_pattern_info` VALUES (2119898, 19996683, '字母', '从图片和文案看，整件衬衫以连续条纹为主，因此选择“Allover pattern（整体图案）”与“Stripes（条纹）”，属于整体排布的条纹图案；背部和局部有“Stranger Things”等文字与标志性元素，因此加入“Letter（文字）”。文案说明有“刺繍やプリント等を施した”，对应工艺选择“Embroidery（刺绣）”和“Print（印花）”。条纹加文字与标志元素共同构成整体设计，所以为“Composed Pattern（组合图案）”。整体图案来源于剧集形象，有明确可识别对象，图像含义清晰，因此在图案定义上归为“Figurative Pattern（具象图案）”。视觉风格干净简洁、线条规整，故在风格维度选择“Minimalist Style（极简风格）”。');
INSERT INTO `clothing_pattern_info` VALUES (2119899, 19996684, '其他', '帽子表面覆盖有整体性的多色图案，因此使用“Allover pattern”，图案属于印花工艺，选择“Print”。画面由多种色块和痕迹组合成画面，故为“Composed Pattern”。具体元素难以归类为花卉、条纹等常规图案，适合作为“Other patterns”。整体图案以抽象笔触和色块构成，没有具体具象形象，因此定义为“Abstract Pattern”。呈现类似手绘涂抹和绘画质感的视觉效果，选用“Illustration Effect”来描述其风格。');
INSERT INTO `clothing_pattern_info` VALUES (2119900, 19996685, '其他', '帽子表面覆盖有整体性的多色图案，因此使用“Allover pattern”，图案属于印花工艺，选择“Print”。画面由多种色块和痕迹组合成画面，故为“Composed Pattern”。具体元素难以归类为花卉、条纹等常规图案，适合作为“Other patterns”。整体图案以抽象笔触和色块构成，没有具体具象形象，因此定义为“Abstract Pattern”。呈现类似手绘涂抹和绘画质感的视觉效果，选用“Illustration Effect”来描述其风格。');
INSERT INTO `clothing_pattern_info` VALUES (2119901, 19996686, '其他', '帽子表面覆盖有整体性的多色图案，因此使用“Allover pattern”，图案属于印花工艺，选择“Print”。画面由多种色块和痕迹组合成画面，故为“Composed Pattern”。具体元素难以归类为花卉、条纹等常规图案，适合作为“Other patterns”。整体图案以抽象笔触和色块构成，没有具体具象形象，因此定义为“Abstract Pattern”。呈现类似手绘涂抹和绘画质感的视觉效果，选用“Illustration Effect”来描述其风格。');
INSERT INTO `clothing_pattern_info` VALUES (2119902, 19996687, '纯色', '从图片看整件衣服为单一纯色，无局部图案或位置印花，因此在布局上归为“Allover pattern”，在构成上为整体统一的“Composed Pattern”。图案元素层面属于无图案的“Pure Color/纯色、Solid color”。没有具象图形，故在图案定义上归为“Abstract Pattern”，整体风格简洁克制，适合“Minimalist Style（极简风格）”。');
INSERT INTO `clothing_pattern_info` VALUES (2119903, 19996687, '纯色', '从图片看整件衣服为单一纯色，无局部图案或位置印花，因此在布局上归为“Allover pattern”，在构成上为整体统一的“Composed Pattern”。图案元素层面属于无图案的“Pure Color/纯色、Solid color”。没有具象图形，故在图案定义上归为“Abstract Pattern”，整体风格简洁克制，适合“Minimalist Style（极简风格）”。');
INSERT INTO `clothing_pattern_info` VALUES (2119904, 19996688, '纯色', '从图片看裤子整体为单一深色，没有可辨识的花卉、条纹或格纹等具体图案元素，因此归类为“Pure Color（纯色）”，图案定义上属于“Abstract Pattern（抽象图案）”，即没有具象可识别形象的纯色表面。未见局部印花或刺绣，故不添加其他布局或工艺类标签。');
INSERT INTO `clothing_pattern_info` VALUES (2119888, 19996676, '纯色', '从图片看服装整体为单一纯色，没有花卉、条纹等具体图案元素，因此选择图案元素中的「Pure Color」与「Single Element Pattern」来表示单一元素、纯色效果。此类无具象图案的设计在图案定义上归为「Abstract Pattern」，即抽象图案（实为无图案的极简效果）。未见明显印花或局部图案，故未选择排布类或工艺类标签。');
INSERT INTO `clothing_pattern_info` VALUES (2119889, 19996677, '纯色', '从图片和描述看，衣身为单一色调，没有明显图案，仅有荷叶边等结构性装饰，因此在图案元素上归为“Pure Color/纯色”。整体没有具象花卉或动物等具象图案，也没有明确可识别的主题，只是纯色与褶饰带来的视觉变化，所以在图案定义上选择“Abstract Pattern/抽象图案”。');
INSERT INTO `clothing_pattern_info` VALUES (2119890, 19996678, '纯色', '从图片和描述看，衣身为单一色调，没有明显图案，仅有荷叶边等结构性装饰，因此在图案元素上归为“Pure Color/纯色”。整体没有具象花卉或动物等具象图案，也没有明确可识别的主题，只是纯色与褶饰带来的视觉变化，所以在图案定义上选择“Abstract Pattern/抽象图案”。');
INSERT INTO `clothing_pattern_info` VALUES (2119891, 19996679, '纯色', '从图片和描述看，衣身为单一色调，没有明显图案，仅有荷叶边等结构性装饰，因此在图案元素上归为“Pure Color/纯色”。整体没有具象花卉或动物等具象图案，也没有明确可识别的主题，只是纯色与褶饰带来的视觉变化，所以在图案定义上选择“Abstract Pattern/抽象图案”。');
INSERT INTO `clothing_pattern_info` VALUES (2119892, 19996680, '花卉图案', '衣身上半部分密集布置花朵图案，集中在肩胸位置，因此选用“Placement Print（局部图案布局）”。图案通过刺绣工艺呈现，故选择“Embroidery（刺绣）”。整体由多朵花和不同位置组合构成，而非单一元素，归为“Composed Pattern（组合图案）”。花朵形态明显，属于“Floral pattern（花卉图案）”，图案可清晰辨认具象物体，因此在定义上选“Figurative Pattern（具象图案）”。花形边缘线条略带手绘感，不是照片写实效果，故在风格上选“Hand-drawn Style（手绘风格）”。');
INSERT INTO `clothing_pattern_info` VALUES (2119893, 19996681, '纯色', '从图片看，这件T恤整体为纯色，没有可见图案或logo，仅呈现单一色块。因此在图案元素上选择“Pure Color（纯色）”和“Solid color（纯色）”。没有具体具象元素或花纹，整体属于“Abstract Pattern（抽象图案）”定义范畴。在风格维度上，视觉效果干净利落、无多余装饰，属于“Minimalist Style（极简风格）”。');
INSERT INTO `clothing_pattern_info` VALUES (2119894, 19996681, '纯色', '从图片看，这件T恤整体为纯色，没有可见图案或logo，仅呈现单一色块。因此在图案元素上选择“Pure Color（纯色）”和“Solid color（纯色）”。没有具体具象元素或花纹，整体属于“Abstract Pattern（抽象图案）”定义范畴。在风格维度上，视觉效果干净利落、无多余装饰，属于“Minimalist Style（极简风格）”。');
INSERT INTO `clothing_pattern_info` VALUES (2119895, 19996682, '纯色', '从图片看，这件T恤整体为纯色，没有可见图案或logo，仅呈现单一色块。因此在图案元素上选择“Pure Color（纯色）”和“Solid color（纯色）”。没有具体具象元素或花纹，整体属于“Abstract Pattern（抽象图案）”定义范畴。在风格维度上，视觉效果干净利落、无多余装饰，属于“Minimalist Style（极简风格）”。');
INSERT INTO `clothing_pattern_info` VALUES (2119896, 19996682, '纯色', '从图片看，这件T恤整体为纯色，没有可见图案或logo，仅呈现单一色块。因此在图案元素上选择“Pure Color（纯色）”和“Solid color（纯色）”。没有具体具象元素或花纹，整体属于“Abstract Pattern（抽象图案）”定义范畴。在风格维度上，视觉效果干净利落、无多余装饰，属于“Minimalist Style（极简风格）”。');
INSERT INTO `clothing_pattern_info` VALUES (2119882, 19996670, '纯色', '从图片看整体为单一深灰色，没有可见花纹或图形元素，因此在图案元素维度选择“Pure Color（纯色）”。没有局部位置印花或复杂构图，更接近极简的整体效果，在图案定义上归为抽象类“Abstract Pattern（抽象图案）”，图案风格上体现为“Minimalist Style（极简风格）”，突出干净简洁的视觉。');
INSERT INTO `clothing_pattern_info` VALUES (2119883, 19996671, '纯色', '从图片看整体为单一深灰色，没有可见花纹或图形元素，因此在图案元素维度选择“Pure Color（纯色）”。没有局部位置印花或复杂构图，更接近极简的整体效果，在图案定义上归为抽象类“Abstract Pattern（抽象图案）”，图案风格上体现为“Minimalist Style（极简风格）”，突出干净简洁的视觉。');
INSERT INTO `clothing_pattern_info` VALUES (2119884, 19996672, '纯色', '从图片和文字来看，包身以纯黑色为主，没有明显印花或图案元素，因此在图案元素上选择“Pure Color（纯色）”。整体装饰主要是立体织带流苏和结构线条，而非具体具象图案，所以在图案定义上归为“Abstract Pattern（抽象图案）”，用形状和结构营造视觉效果。未见明显排布印花或刺绣等工艺，因此不再增加其他图案标签。');
INSERT INTO `clothing_pattern_info` VALUES (2119885, 19996673, '条纹', '从图片和描述“グラデーションストライプ”“シャツ　ストライプ　柄”可见整体为连续条纹覆盖，故选“Allover pattern”和元素“Stripes”，属于整体构成的“Composed Pattern”。条纹通过不同纱线与色彩组成，图案并非具象物体，因此在定义上归入“Abstract Pattern”。面料本身用不同纱线组织出条纹肌理，更接近织造形成的图案效果，因此在工艺上标注为“Jacquard”。整体条纹简洁克制，没有复杂装饰风格，故图案风格归类为“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119886, 19996674, '条纹', '从图片和描述“グラデーションストライプ”“シャツ　ストライプ　柄”可见整体为连续条纹覆盖，故选“Allover pattern”和元素“Stripes”，属于整体构成的“Composed Pattern”。条纹通过不同纱线与色彩组成，图案并非具象物体，因此在定义上归入“Abstract Pattern”。面料本身用不同纱线组织出条纹肌理，更接近织造形成的图案效果，因此在工艺上标注为“Jacquard”。整体条纹简洁克制，没有复杂装饰风格，故图案风格归类为“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119887, 19996675, '条纹', '从图片和描述“グラデーションストライプ”“シャツ　ストライプ　柄”可见整体为连续条纹覆盖，故选“Allover pattern”和元素“Stripes”，属于整体构成的“Composed Pattern”。条纹通过不同纱线与色彩组成，图案并非具象物体，因此在定义上归入“Abstract Pattern”。面料本身用不同纱线组织出条纹肌理，更接近织造形成的图案效果，因此在工艺上标注为“Jacquard”。整体条纹简洁克制，没有复杂装饰风格，故图案风格归类为“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119881, 19996669, '字母', '帽身以纯色为主，仅在前片局部有字母logo图案，因此选“Placement Print（定位图案）”和“Single Element Pattern（单一元素图案）”。logo通过刺绣呈现，工艺上归为“Embroidery（刺绣）”。图案元素为英文字母，选择“Letter（字母）”。整体图案能直接辨认，属具象表达，所以用“Representational Pattern（具象图案）”。风格简洁干净，没有复杂修饰，归类为“Minimalist Style（极简风格）”。');
INSERT INTO `clothing_pattern_info` VALUES (2119870, 19996662, '人物图案（人形，人体）', '从图片可见图案集中在胸前小区域，因此属于局部的「Placement Print（定位印花）」；图案是直接印在衣身上的，工艺上归类为「Print（印花）」；胸前只有单一小图形，所以选「Single Element Pattern（单一元素图案）」。图案为具象的卡通人物/形象，因此元素选了「Figure pattern（人物/形象图案）」，整体是可辨认的具体形象而非抽象纹理，故定义为「Representational Pattern（具象图案）」。画风夸张可爱，线条简洁，属于「Cartoon Style（卡通风格）」。');
INSERT INTO `clothing_pattern_info` VALUES (2119871, 19996663, '纯色', '从图片看，整体为单一纯色，没有明显图案元素，因此在图案元素上选择“Pure Color/纯色”，定义上对应“Abstract Pattern/抽象图案”。服装为整件面料统一色调，属于整体覆盖式的“Allover pattern/整体图案”布局，工艺以普通染色针织面料呈现，也归入“Print/印花”大类。整体视觉简洁低调，因此在风格上采用“Minimalist Style/极简风格”。图案构成上只有颜色这一单一要素，归为“Composed Pattern/组合图案”以适配结构维度标注。');
INSERT INTO `clothing_pattern_info` VALUES (2119872, 19996664, '纯色', '从图片看，整体为单一纯色，没有明显图案元素，因此在图案元素上选择“Pure Color/纯色”，定义上对应“Abstract Pattern/抽象图案”。服装为整件面料统一色调，属于整体覆盖式的“Allover pattern/整体图案”布局，工艺以普通染色针织面料呈现，也归入“Print/印花”大类。整体视觉简洁低调，因此在风格上采用“Minimalist Style/极简风格”。图案构成上只有颜色这一单一要素，归为“Composed Pattern/组合图案”以适配结构维度标注。');
INSERT INTO `clothing_pattern_info` VALUES (2119873, 19996665, '文字', '衣身前幅只有一块大图案，位置集中，因此归类为「Placement Print」。图案以印花工艺呈现，选用「Print」。整体由一组角色和文字构成，属于「Single Element Pattern」。元素上包含球队文字与品牌字样，所以选用「Text」，同时有PEANUTS卡通角色，因此使用「Character pattern」。图案内容清晰可辨，故在定义上为「Figurative Pattern」。配合做旧褪色视觉与复古配色，风格上归为「Vintage Style」。');
INSERT INTO `clothing_pattern_info` VALUES (2119874, 19996665, '卡通人物（拟人化物体）', '衣身前幅只有一块大图案，位置集中，因此归类为「Placement Print」。图案以印花工艺呈现，选用「Print」。整体由一组角色和文字构成，属于「Single Element Pattern」。元素上包含球队文字与品牌字样，所以选用「Text」，同时有PEANUTS卡通角色，因此使用「Character pattern」。图案内容清晰可辨，故在定义上为「Figurative Pattern」。配合做旧褪色视觉与复古配色，风格上归为「Vintage Style」。');
