INSERT INTO `clothing_pattern_info` VALUES (2119880, 19996668, '卡通人物（拟人化物体）', '衣身前幅只有一块大图案，位置集中，因此归类为「Placement Print」。图案以印花工艺呈现，选用「Print」。整体由一组角色和文字构成，属于「Single Element Pattern」。元素上包含球队文字与品牌字样，所以选用「Text」，同时有PEANUTS卡通角色，因此使用「Character pattern」。图案内容清晰可辨，故在定义上为「Figurative Pattern」。配合做旧褪色视觉与复古配色，风格上归为「Vintage Style」。');
INSERT INTO `clothing_pattern_info` VALUES (2119861, 19996658, '纯色', '从图片看整体为纯色设计，裤脚边小标识属于局部点缀，因此选用“Placement Print”以及“Pure Color”“Solid color”来表示以纯色为主、局部有小图案标识的设计。整体没有具象图案元素，更偏向简洁抽象效果，所以在定义上选择“Abstract Pattern”，风格上归为“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119862, 19996658, '纯色', '从图片看整体为纯色设计，裤脚边小标识属于局部点缀，因此选用“Placement Print”以及“Pure Color”“Solid color”来表示以纯色为主、局部有小图案标识的设计。整体没有具象图案元素，更偏向简洁抽象效果，所以在定义上选择“Abstract Pattern”，风格上归为“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119863, 19996659, '纯色', '从图片看整体为纯色设计，裤脚边小标识属于局部点缀，因此选用“Placement Print”以及“Pure Color”“Solid color”来表示以纯色为主、局部有小图案标识的设计。整体没有具象图案元素，更偏向简洁抽象效果，所以在定义上选择“Abstract Pattern”，风格上归为“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119864, 19996659, '纯色', '从图片看整体为纯色设计，裤脚边小标识属于局部点缀，因此选用“Placement Print”以及“Pure Color”“Solid color”来表示以纯色为主、局部有小图案标识的设计。整体没有具象图案元素，更偏向简洁抽象效果，所以在定义上选择“Abstract Pattern”，风格上归为“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119865, 19996660, '纯色', '从图片看整体为纯色设计，裤脚边小标识属于局部点缀，因此选用“Placement Print”以及“Pure Color”“Solid color”来表示以纯色为主、局部有小图案标识的设计。整体没有具象图案元素，更偏向简洁抽象效果，所以在定义上选择“Abstract Pattern”，风格上归为“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119866, 19996660, '纯色', '从图片看整体为纯色设计，裤脚边小标识属于局部点缀，因此选用“Placement Print”以及“Pure Color”“Solid color”来表示以纯色为主、局部有小图案标识的设计。整体没有具象图案元素，更偏向简洁抽象效果，所以在定义上选择“Abstract Pattern”，风格上归为“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119867, 19996661, '品牌标识', '从图片和描述看，胸前图案集中在局部区域，因此选用“Placement Print（局部图案）”；通过印花方式呈现角色与文字，所以为“Print（印花）”。图案由角色形象、船锚等元素和英文LOGO组成，属于“Single Element Pattern（单元图案组合）”，并包含品牌与店名信息，因此加入“Logo Placement（LOGO图案）”。人物角色归为“Figure pattern（人物图案）”，冰淇淋店吉祥物和相关物件属于“Object pattern（物件图案）”。整体图案能清晰表现具体形象，故在定义上为“Representational Pattern（具象图案）”。绘制风格偏插画和卡通，线条简化、色块鲜明，因此选择“Illustration Effect（插画效果）”和“Cartoon Style（卡通风格）”。');
INSERT INTO `clothing_pattern_info` VALUES (2119868, 19996661, '人物图案（人形，人体）', '从图片和描述看，胸前图案集中在局部区域，因此选用“Placement Print（局部图案）”；通过印花方式呈现角色与文字，所以为“Print（印花）”。图案由角色形象、船锚等元素和英文LOGO组成，属于“Single Element Pattern（单元图案组合）”，并包含品牌与店名信息，因此加入“Logo Placement（LOGO图案）”。人物角色归为“Figure pattern（人物图案）”，冰淇淋店吉祥物和相关物件属于“Object pattern（物件图案）”。整体图案能清晰表现具体形象，故在定义上为“Representational Pattern（具象图案）”。绘制风格偏插画和卡通，线条简化、色块鲜明，因此选择“Illustration Effect（插画效果）”和“Cartoon Style（卡通风格）”。');
INSERT INTO `clothing_pattern_info` VALUES (2119869, 19996661, '物体', '从图片和描述看，胸前图案集中在局部区域，因此选用“Placement Print（局部图案）”；通过印花方式呈现角色与文字，所以为“Print（印花）”。图案由角色形象、船锚等元素和英文LOGO组成，属于“Single Element Pattern（单元图案组合）”，并包含品牌与店名信息，因此加入“Logo Placement（LOGO图案）”。人物角色归为“Figure pattern（人物图案）”，冰淇淋店吉祥物和相关物件属于“Object pattern（物件图案）”。整体图案能清晰表现具体形象，故在定义上为“Representational Pattern（具象图案）”。绘制风格偏插画和卡通，线条简化、色块鲜明，因此选择“Illustration Effect（插画效果）”和“Cartoon Style（卡通风格）”。');
INSERT INTO `clothing_pattern_info` VALUES (2119858, 19996655, '其他', '从图片看，胸前以规则重复的花形镂空方块为主，没有明显的印花布局区分，可视作整体由单一元素反复构成，因此选择“Single Element Pattern”。具体元素是几何化的花朵/放射状图形，并非经典格纹、条纹等常见基础元素，归入“Other patterns”更合适。整体图案偏装饰性和抽象化，没有明确具象物体，对应“Abstract Pattern”。');
INSERT INTO `clothing_pattern_info` VALUES (2119859, 19996656, '其他', '从图片看，胸前以规则重复的花形镂空方块为主，没有明显的印花布局区分，可视作整体由单一元素反复构成，因此选择“Single Element Pattern”。具体元素是几何化的花朵/放射状图形，并非经典格纹、条纹等常见基础元素，归入“Other patterns”更合适。整体图案偏装饰性和抽象化，没有明确具象物体，对应“Abstract Pattern”。');
INSERT INTO `clothing_pattern_info` VALUES (2119860, 19996657, '其他', '从图片看，胸前以规则重复的花形镂空方块为主，没有明显的印花布局区分，可视作整体由单一元素反复构成，因此选择“Single Element Pattern”。具体元素是几何化的花朵/放射状图形，并非经典格纹、条纹等常见基础元素，归入“Other patterns”更合适。整体图案偏装饰性和抽象化，没有明确具象物体，对应“Abstract Pattern”。');
INSERT INTO `clothing_pattern_info` VALUES (2119854, 19996653, '纯色', '从图片和描述看，这件衬衫以单一自然色为主，没有明显花纹或图案，因此选择“Pure Color/纯色”和“Solid color/纯色”作为图案元素。整体没有具象图形，更偏向无图案或极简效果，因此在图案定义上归为“Abstract Pattern/抽象图案”，风格上属于“Minimalist Style/极简风格”，体现简约耐看设计。');
INSERT INTO `clothing_pattern_info` VALUES (2119855, 19996653, '纯色', '从图片和描述看，这件衬衫以单一自然色为主，没有明显花纹或图案，因此选择“Pure Color/纯色”和“Solid color/纯色”作为图案元素。整体没有具象图形，更偏向无图案或极简效果，因此在图案定义上归为“Abstract Pattern/抽象图案”，风格上属于“Minimalist Style/极简风格”，体现简约耐看设计。');
