INSERT INTO `clothing_pattern_info` VALUES (2119851, 19996650, '纯色', '从图片与描述看，整体为素色设计，没有花朵、条纹等具体图案元素，因此选择“Pure Color（纯色）”。图案层面并无具象图形，可视为“Abstract Pattern（抽象图案定义）”。整体风格简洁干净，无复杂装饰，归为“Minimalist Style（极简风格）”。');
INSERT INTO `clothing_pattern_info` VALUES (2119852, 19996651, '纯色', '从图片与描述看，整体为素色设计，没有花朵、条纹等具体图案元素，因此选择“Pure Color（纯色）”。图案层面并无具象图形，可视为“Abstract Pattern（抽象图案定义）”。整体风格简洁干净，无复杂装饰，归为“Minimalist Style（极简风格）”。');
INSERT INTO `clothing_pattern_info` VALUES (2119853, 19996652, '卡通人物（拟人化物体）', '胸前只有一块集中区域的角色与场景图案，因此选择“Placement Print”和“Single Element Pattern”。图案为角色形象及其旅行场景，是“Character pattern”，属于具象的“Figurative Pattern”。呈现方式类似插画和截图拼贴，整体风格偏插画感，所以选择“Print”和“Illustration Effect”。');
INSERT INTO `clothing_pattern_info` VALUES (2119845, 19996645, '条纹', '从图片可见整件衣服布满重复的几何条纹，因此在布局上属于“Allover pattern”，整体由印花方式呈现，因此选择“Print”，并由多种几何元素组合成图案，所以是“Composed Pattern”。图案主要是水平“Stripes”与锯齿、波浪等几何线形组合，难以归入具体具象对象，因此在元素上补充“Other patterns”。整体为非具象几何装饰，故在定义上归为“Abstract Pattern”。图案线条规整、配色克制，没有复杂写实细节，风格上偏“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119846, 19996645, '其他', '从图片可见整件衣服布满重复的几何条纹，因此在布局上属于“Allover pattern”，整体由印花方式呈现，因此选择“Print”，并由多种几何元素组合成图案，所以是“Composed Pattern”。图案主要是水平“Stripes”与锯齿、波浪等几何线形组合，难以归入具体具象对象，因此在元素上补充“Other patterns”。整体为非具象几何装饰，故在定义上归为“Abstract Pattern”。图案线条规整、配色克制，没有复杂写实细节，风格上偏“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119847, 19996646, '条纹', '实物有纯色款与条纹款描述，其中条纹属于整体布满的“全幅图案（Allover pattern）”，通过织纹或印花呈现，因此选择“Print”。条纹与底色共同构成一整套图案，所以用“Composed Pattern”。元素上为规则重复的“Stripes（条纹）”，不具具象含义，因此在定义上归为“Abstract Pattern”。整体风格简洁清爽，没有复杂装饰，属于“Minimalist Style（极简风格）”。');
INSERT INTO `clothing_pattern_info` VALUES (2119848, 19996647, '条纹', '实物有纯色款与条纹款描述，其中条纹属于整体布满的“全幅图案（Allover pattern）”，通过织纹或印花呈现，因此选择“Print”。条纹与底色共同构成一整套图案，所以用“Composed Pattern”。元素上为规则重复的“Stripes（条纹）”，不具具象含义，因此在定义上归为“Abstract Pattern”。整体风格简洁清爽，没有复杂装饰，属于“Minimalist Style（极简风格）”。');
INSERT INTO `clothing_pattern_info` VALUES (2119849, 19996648, '格纹', '整体服装覆盖统一的格纹，所以选择“Allover pattern”“check”并归为“Composed Pattern”。图案以染织/印花方式呈现，因此选择“Print”。格纹是具体可识别的几何图案，属于“Representational Pattern”。整体配色和线条简洁，没有复杂装饰效果，因此图案风格归为“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119850, 19996649, '格纹', '整体服装覆盖统一的格纹，所以选择“Allover pattern”“check”并归为“Composed Pattern”。图案以染织/印花方式呈现，因此选择“Print”。格纹是具体可识别的几何图案，属于“Representational Pattern”。整体配色和线条简洁，没有复杂装饰效果，因此图案风格归为“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119842, 19996642, '格纹', '从图片可见全身布满规则格纹，因此在布局上选“Allover pattern”，整体为连续重复图案；格纹由组织结构形成而非单纯表面印刷，偏向“Jacquard”；整件由多条线条格子组合，属于“Composed Pattern”；具体元素为“Plaid”格纹；图案清晰可辨、具象呈现格子结构，所以在图案定义上用“Representational Pattern”；风格简洁不复杂，无多余装饰，整体偏“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119843, 19996643, '格纹', '从图片可见全身布满规则格纹，因此在布局上选“Allover pattern”，整体为连续重复图案；格纹由组织结构形成而非单纯表面印刷，偏向“Jacquard”；整件由多条线条格子组合，属于“Composed Pattern”；具体元素为“Plaid”格纹；图案清晰可辨、具象呈现格子结构，所以在图案定义上用“Representational Pattern”；风格简洁不复杂，无多余装饰，整体偏“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119844, 19996644, '格纹', '从图片可见全身布满规则格纹，因此在布局上选“Allover pattern”，整体为连续重复图案；格纹由组织结构形成而非单纯表面印刷，偏向“Jacquard”；整件由多条线条格子组合，属于“Composed Pattern”；具体元素为“Plaid”格纹；图案清晰可辨、具象呈现格子结构，所以在图案定义上用“Representational Pattern”；风格简洁不复杂，无多余装饰，整体偏“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119841, 19996641, '纯色', '从图片看衣身为单一色彩，没有任何花纹或图案装饰，因此图案元素选择“Pure Color（纯色）”。整体没有具象图像或具体对象，仅通过廓形与结构形成视觉效果，所以在图案定义维度上归为“Abstract Pattern（抽象图案）”。未见印花或织纹图案分布，故不选择其他图案标签。');
INSERT INTO `clothing_pattern_info` VALUES (2119837, 19996639, '食品/饮料', '从图片和描述看，整件衣服布满重复的小图案，因此选择“Allover pattern”。图案是通过印花方式呈现，符合“Print”。图案元素包含多种食物与物品组合，如水果、玉米片、啤酒和薯片等，是多元素构成，所以选“Composed Pattern”和“Food/Drink”“Object pattern”。这些图案具有卡通化、可爱风格，因此使用“Cartoon Style”。整体图案都是可辨认的具体事物，属于具象图案，所以在定义维度选择“Figurative Pattern”。');
INSERT INTO `clothing_pattern_info` VALUES (2119838, 19996639, '物体', '从图片和描述看，整件衣服布满重复的小图案，因此选择“Allover pattern”。图案是通过印花方式呈现，符合“Print”。图案元素包含多种食物与物品组合，如水果、玉米片、啤酒和薯片等，是多元素构成，所以选“Composed Pattern”和“Food/Drink”“Object pattern”。这些图案具有卡通化、可爱风格，因此使用“Cartoon Style”。整体图案都是可辨认的具体事物，属于具象图案，所以在定义维度选择“Figurative Pattern”。');
INSERT INTO `clothing_pattern_info` VALUES (2119839, 19996640, '食品/饮料', '从图片和描述看，整件衣服布满重复的小图案，因此选择“Allover pattern”。图案是通过印花方式呈现，符合“Print”。图案元素包含多种食物与物品组合，如水果、玉米片、啤酒和薯片等，是多元素构成，所以选“Composed Pattern”和“Food/Drink”“Object pattern”。这些图案具有卡通化、可爱风格，因此使用“Cartoon Style”。整体图案都是可辨认的具体事物，属于具象图案，所以在定义维度选择“Figurative Pattern”。');
INSERT INTO `clothing_pattern_info` VALUES (2119840, 19996640, '物体', '从图片和描述看，整件衣服布满重复的小图案，因此选择“Allover pattern”。图案是通过印花方式呈现，符合“Print”。图案元素包含多种食物与物品组合，如水果、玉米片、啤酒和薯片等，是多元素构成，所以选“Composed Pattern”和“Food/Drink”“Object pattern”。这些图案具有卡通化、可爱风格，因此使用“Cartoon Style”。整体图案都是可辨认的具体事物，属于具象图案，所以在定义维度选择“Figurative Pattern”。');
INSERT INTO `clothing_pattern_info` VALUES (2119835, 19996637, '纯色', '从图片上看，衣身没有明显的花朵、条纹等具体图案元素，整体为单一色调，因此在图案元素上归为“Pure Color（纯色）”。由于没有具象图形，仅是颜色与材质带来的视觉效果，在图案定义维度上选择“Abstract Pattern（抽象图案）”更为贴切。未见大面积位置印花或复杂排布，因此不再添加其他布局或工艺类标签。');
INSERT INTO `clothing_pattern_info` VALUES (2119836, 19996638, '纯色', '从图片上看，衣身没有明显的花朵、条纹等具体图案元素，整体为单一色调，因此在图案元素上归为“Pure Color（纯色）”。由于没有具象图形，仅是颜色与材质带来的视觉效果，在图案定义维度上选择“Abstract Pattern（抽象图案）”更为贴切。未见大面积位置印花或复杂排布，因此不再添加其他布局或工艺类标签。');
INSERT INTO `clothing_pattern_info` VALUES (2119831, 19996635, '花卉图案', '从商品名“フラワーフォトTシャツ”和图中可见，前幅局部有花卉照片感图案，因此布局上选“Placement Print（局部图案）”；图案以印花方式呈现，选择“Print”。图案主要集中在前胸一块区域，属于单一主题构成，因此用“Single Element Pattern”。元素上可以清楚看到“花卉图案”，并包含英文文案，所以选“Floral pattern”和“Text”。整体图案具象可辨认，为具体的花和文字，故“Figurative Pattern”。呈现方式类似插画/照片感设计，不是写实油画，选风格类的“Illustration Effect”最贴切。');
INSERT INTO `clothing_pattern_info` VALUES (2119832, 19996635, '文字', '从商品名“フラワーフォトTシャツ”和图中可见，前幅局部有花卉照片感图案，因此布局上选“Placement Print（局部图案）”；图案以印花方式呈现，选择“Print”。图案主要集中在前胸一块区域，属于单一主题构成，因此用“Single Element Pattern”。元素上可以清楚看到“花卉图案”，并包含英文文案，所以选“Floral pattern”和“Text”。整体图案具象可辨认，为具体的花和文字，故“Figurative Pattern”。呈现方式类似插画/照片感设计，不是写实油画，选风格类的“Illustration Effect”最贴切。');
INSERT INTO `clothing_pattern_info` VALUES (2119833, 19996636, '花卉图案', '从商品名“フラワーフォトTシャツ”和图中可见，前幅局部有花卉照片感图案，因此布局上选“Placement Print（局部图案）”；图案以印花方式呈现，选择“Print”。图案主要集中在前胸一块区域，属于单一主题构成，因此用“Single Element Pattern”。元素上可以清楚看到“花卉图案”，并包含英文文案，所以选“Floral pattern”和“Text”。整体图案具象可辨认，为具体的花和文字，故“Figurative Pattern”。呈现方式类似插画/照片感设计，不是写实油画，选风格类的“Illustration Effect”最贴切。');
INSERT INTO `clothing_pattern_info` VALUES (2119834, 19996636, '文字', '从商品名“フラワーフォトTシャツ”和图中可见，前幅局部有花卉照片感图案，因此布局上选“Placement Print（局部图案）”；图案以印花方式呈现，选择“Print”。图案主要集中在前胸一块区域，属于单一主题构成，因此用“Single Element Pattern”。元素上可以清楚看到“花卉图案”，并包含英文文案，所以选“Floral pattern”和“Text”。整体图案具象可辨认，为具体的花和文字，故“Figurative Pattern”。呈现方式类似插画/照片感设计，不是写实油画，选风格类的“Illustration Effect”最贴切。');
INSERT INTO `clothing_pattern_info` VALUES (2119828, 19996632, '纯色', '从图片看，面料以单一纯色为主，没有明显花朵、格纹等具体图案元素，因此图案元素选择“Pure Color/纯色”，整体效果属于“Abstract Pattern/抽象图案定义”。整件服装统一色调分布在全身，视作“Allover pattern/整体分布图案”，呈现极简风格，故加入“Minimalist Style/极简风格”。颜色呈现为常规染色，归类为“Print/印染工艺”，整体为单一元素构成，选择“Composed Pattern/组合图案”以概括整体纯色构成。');
INSERT INTO `clothing_pattern_info` VALUES (2119829, 19996633, '纯色', '服装整体为单一深色无明显图案元素，因此选择“Pure Color（纯色）”作为图案元素；没有具体具象图形，属于“Abstract Pattern（抽象图案）”；整体视觉简洁干练、无多余花纹，风格偏“Minimalist Style（极简风格）”。');
INSERT INTO `clothing_pattern_info` VALUES (2119830, 19996634, '纯色', '服装整体为单一深色无明显图案元素，因此选择“Pure Color（纯色）”作为图案元素；没有具体具象图形，属于“Abstract Pattern（抽象图案）”；整体视觉简洁干练、无多余花纹，风格偏“Minimalist Style（极简风格）”。');
INSERT INTO `clothing_pattern_info` VALUES (2119827, 19996631, '字母', '衣身前片仅在胸前局部位置有大面积文字与图形，因此归类为“Placement Print（位置印花）”。通过印花方式呈现LOGO与文字内容，对应“Print（印花工艺）”。主要图案元素是英文字母与标识，为单一类型图案，故选“Single Element Pattern（单一元素图案）”与“Letter（字母图案）”。字母内容可被识别，有具体含义，因此整体属于“Representational Pattern（具象图案）”。视觉上采用旧化感与复古配色，呈现品牌感老校队风格，因此选用“Vintage Style（复古风格）”。');
INSERT INTO `clothing_pattern_info` VALUES (2119825, 19996629, '花卉图案', '从图片可见裙身整体以蕾丝花型覆盖，所以选择“Allover pattern（整体图案）”和“Composed Pattern（组合图案）”。说明中明确提到使用两种不同风格的蕾丝拼接，属于“Lace（蕾丝工艺）”。蕾丝上是典型的花朵纹样，因此选“Floral pattern（花卉图案）”，这类具体可辨认的花朵属于“Representational Pattern（具象图案）”。品牌与配色强调复古感，蕾丝花纹也呈现旧时感受，因此加入“Vintage Style（复古风格）”。');
INSERT INTO `clothing_pattern_info` VALUES (2119826, 19996630, '花卉图案', '从图片可见裙身整体以蕾丝花型覆盖，所以选择“Allover pattern（整体图案）”和“Composed Pattern（组合图案）”。说明中明确提到使用两种不同风格的蕾丝拼接，属于“Lace（蕾丝工艺）”。蕾丝上是典型的花朵纹样，因此选“Floral pattern（花卉图案）”，这类具体可辨认的花朵属于“Representational Pattern（具象图案）”。品牌与配色强调复古感，蕾丝花纹也呈现旧时感受，因此加入“Vintage Style（复古风格）”。');
INSERT INTO `clothing_pattern_info` VALUES (2119823, 19996627, '波浪纹', '裙身布满规则重复的波浪状镂空花样，因此使用“Allover pattern（满版图案）”与“Composed Pattern（组合图案）”。花样通过针织结构形成，非后期印花，归为“Jacquard（提花）”。图案元素主要是连续起伏的线条与波浪造型，故用“Wave stripe pattern（波浪条纹图案）”。整体为抽象几何感而非具体物象，选择“Abstract Pattern（抽象图案）”作为图案定义。视觉效果干净利落、以简单重复纹样为主，因此风格归类为“Minimalist Style（极简风格）”。');
INSERT INTO `clothing_pattern_info` VALUES (2119824, 19996628, '波浪纹', '裙身布满规则重复的波浪状镂空花样，因此使用“Allover pattern（满版图案）”与“Composed Pattern（组合图案）”。花样通过针织结构形成，非后期印花，归为“Jacquard（提花）”。图案元素主要是连续起伏的线条与波浪造型，故用“Wave stripe pattern（波浪条纹图案）”。整体为抽象几何感而非具体物象，选择“Abstract Pattern（抽象图案）”作为图案定义。视觉效果干净利落、以简单重复纹样为主，因此风格归类为“Minimalist Style（极简风格）”。');
INSERT INTO `clothing_pattern_info` VALUES (2119822, 19996626, '花卉图案', '从图片可以看到整条裙子表面被花块图案完全覆盖，因此选择“Allover pattern（整体式图案）”和“Composed Pattern（组合图案）”。这些花块是由不同色块组合的结构性图案，更接近针织/钩编形成的花型，因此在技法上用“Jacquard（提花类图案）”来归类。花块中心呈花朵造型，故在元素维度选择“Floral pattern（花卉图案）”。花卉图案具有具象形态，所以在图案定义中选“Figurative Pattern（具象图案）”。整体配色和花块组合给人复古手工感，因此在风格维度选“Vintage Style（复古风格）”。');
INSERT INTO `clothing_pattern_info` VALUES (2119820, 19996624, '纯色', '从图片来看鞋面为黑色单一色块，只有对比色车线和鞋带，没有花朵、格纹等具体图案元素，因此选用“Pure Color/纯色”和“Solid color/素色”作为图案元素。鞋面并非局部图案点缀，而是整体以纯色呈现，属于抽象概念上的无图案风格，所以在图案定义上归为“Abstract Pattern/抽象图案”。视觉效果简洁干净，缺乏复杂装饰，可归类为“Minimalist Style/极简风格”。');
INSERT INTO `clothing_pattern_info` VALUES (2119821, 19996624, '纯色', '从图片来看鞋面为黑色单一色块，只有对比色车线和鞋带，没有花朵、格纹等具体图案元素，因此选用“Pure Color/纯色”和“Solid color/素色”作为图案元素。鞋面并非局部图案点缀，而是整体以纯色呈现，属于抽象概念上的无图案风格，所以在图案定义上归为“Abstract Pattern/抽象图案”。视觉效果简洁干净，缺乏复杂装饰，可归类为“Minimalist Style/极简风格”。');
INSERT INTO `clothing_pattern_info` VALUES (2119817, 19996622, '纯色', '从图片看整条背带裤为单一纯色，无明显局部图案或位置印花，因此采用整体统一的“Allover pattern”布局，并以“Pure Color/纯色”作为主要图案元素，整体属于“Composed Pattern”中的单一元素构成。面料本身为斜纹组织，看不到额外印花或提花花型，可视作无具体具象图案、偏“Abstract Pattern/抽象图案”，整体视觉效果简洁干练，归为“Minimalist Style/极简风格”。“Jacquard”用于表示面料结构纹理而非表面花纹。');
INSERT INTO `clothing_pattern_info` VALUES (2119818, 19996623, '纯色', '鞋面主体为单一色块为主，因此选择“Pure Color（纯色）”；两侧有经典三条纹装饰，属于“Stripes（条纹）”元素。整体图案以品牌标志性线条为识别，具象表达品牌形象，归为“Representational Pattern（具象图案）”；视觉上设计简洁干净，无复杂装饰，风格为“Minimalist Style（极简风格）”。');
INSERT INTO `clothing_pattern_info` VALUES (2119819, 19996623, '条纹', '鞋面主体为单一色块为主，因此选择“Pure Color（纯色）”；两侧有经典三条纹装饰，属于“Stripes（条纹）”元素。整体图案以品牌标志性线条为识别，具象表达品牌形象，归为“Representational Pattern（具象图案）”；视觉上设计简洁干净，无复杂装饰，风格为“Minimalist Style（极简风格）”。');
INSERT INTO `clothing_pattern_info` VALUES (2119815, 19996621, '纯色', '从图片来看，鞋面为单一深色，没有花朵、格纹等具体图案元素，仅有结构线与品牌条纹，因此在图案元素维度选用“Pure Color（纯色）”和“Solid color（素色）”。整体没有具象图形或文字排布，归类为“Abstract Pattern（抽象图案）”以体现非具象的外观效果。风格上图案极简、以纯色和简单线条呈现，因此在风格维度选择“Minimalist Style（极简风格）”。');
INSERT INTO `clothing_pattern_info` VALUES (2119816, 19996621, '纯色', '从图片来看，鞋面为单一深色，没有花朵、格纹等具体图案元素，仅有结构线与品牌条纹，因此在图案元素维度选用“Pure Color（纯色）”和“Solid color（素色）”。整体没有具象图形或文字排布，归类为“Abstract Pattern（抽象图案）”以体现非具象的外观效果。风格上图案极简、以纯色和简单线条呈现，因此在风格维度选择“Minimalist Style（极简风格）”。');
INSERT INTO `clothing_pattern_info` VALUES (2119811, 19996619, '纯色', '从图片看，金属部分为单一金属色搭配单一仿珍珠色，没有花纹，因此使用“Pure Color（纯色）”“Solid color（纯色）”作为图案元素。整体仅由抽象曲线轮廓构成，没有具象花朵或动物等图案，属于“Abstract Pattern（抽象图案）”。风格极简流畅，缺乏复杂装饰和多余细节，因此在风格维度上选择“Minimalist Style（极简风格）”。');
INSERT INTO `clothing_pattern_info` VALUES (2119812, 19996619, '纯色', '从图片看，金属部分为单一金属色搭配单一仿珍珠色，没有花纹，因此使用“Pure Color（纯色）”“Solid color（纯色）”作为图案元素。整体仅由抽象曲线轮廓构成，没有具象花朵或动物等图案，属于“Abstract Pattern（抽象图案）”。风格极简流畅，缺乏复杂装饰和多余细节，因此在风格维度上选择“Minimalist Style（极简风格）”。');
INSERT INTO `clothing_pattern_info` VALUES (2119813, 19996620, '纯色', '从图片看，金属部分为单一金属色搭配单一仿珍珠色，没有花纹，因此使用“Pure Color（纯色）”“Solid color（纯色）”作为图案元素。整体仅由抽象曲线轮廓构成，没有具象花朵或动物等图案，属于“Abstract Pattern（抽象图案）”。风格极简流畅，缺乏复杂装饰和多余细节，因此在风格维度上选择“Minimalist Style（极简风格）”。');
INSERT INTO `clothing_pattern_info` VALUES (2119814, 19996620, '纯色', '从图片看，金属部分为单一金属色搭配单一仿珍珠色，没有花纹，因此使用“Pure Color（纯色）”“Solid color（纯色）”作为图案元素。整体仅由抽象曲线轮廓构成，没有具象花朵或动物等图案，属于“Abstract Pattern（抽象图案）”。风格极简流畅，缺乏复杂装饰和多余细节，因此在风格维度上选择“Minimalist Style（极简风格）”。');
INSERT INTO `clothing_pattern_info` VALUES (2119809, 19996617, '纯色', '耳夹表面为单一金属色，没有复杂图案，因此使用“Pure Color”表示纯色元素；整体没有具象图案或具体形象，归入“Abstract Pattern”更合适；造型简洁干净，仅以心形轮廓呈现，风格偏极简，因此加入“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119810, 19996618, '纯色', '耳夹表面为单一金属色，没有复杂图案，因此使用“Pure Color”表示纯色元素；整体没有具象图案或具体形象，归入“Abstract Pattern”更合适；造型简洁干净，仅以心形轮廓呈现，风格偏极简，因此加入“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119806, 19996614, '字母', '从图片和描述看，帽子前片只有局部文字图案，因此选择“Placement Print”和“Single Element Pattern”。图案形式为英文标语，属于“Letter”，整体仅文字元素，可归入“Figurative Pattern”中的具象图案类别。视觉上设计简洁、干净，没有复杂装饰，符合“Minimalist Style”。工艺上文字是以刺绣方式呈现，因此选用“Embroidery”。');
INSERT INTO `clothing_pattern_info` VALUES (2119807, 19996615, '字母', '从图片和描述看，帽子前片只有局部文字图案，因此选择“Placement Print”和“Single Element Pattern”。图案形式为英文标语，属于“Letter”，整体仅文字元素，可归入“Figurative Pattern”中的具象图案类别。视觉上设计简洁、干净，没有复杂装饰，符合“Minimalist Style”。工艺上文字是以刺绣方式呈现，因此选用“Embroidery”。');
INSERT INTO `clothing_pattern_info` VALUES (2119808, 19996616, '字母', '从图片和描述看，帽子前片只有局部文字图案，因此选择“Placement Print”和“Single Element Pattern”。图案形式为英文标语，属于“Letter”，整体仅文字元素，可归入“Figurative Pattern”中的具象图案类别。视觉上设计简洁、干净，没有复杂装饰，符合“Minimalist Style”。工艺上文字是以刺绣方式呈现，因此选用“Embroidery”。');
INSERT INTO `clothing_pattern_info` VALUES (2119798, 19996610, '纯色', '从图片看整条裤子为单一素色，没有花卉、条纹、格纹等明显图案，因此选择“Pure Color”“Solid color”作为图案元素。整体无具象图形或图案构成，可视为“Abstract Pattern”。视觉风格简洁克制，没有多余装饰，符合“Minimalist Style”的极简风格。');
INSERT INTO `clothing_pattern_info` VALUES (2119799, 19996610, '纯色', '从图片看整条裤子为单一素色，没有花卉、条纹、格纹等明显图案，因此选择“Pure Color”“Solid color”作为图案元素。整体无具象图形或图案构成，可视为“Abstract Pattern”。视觉风格简洁克制，没有多余装饰，符合“Minimalist Style”的极简风格。');
INSERT INTO `clothing_pattern_info` VALUES (2119800, 19996611, '纯色', '从图片看整条裤子为单一素色，没有花卉、条纹、格纹等明显图案，因此选择“Pure Color”“Solid color”作为图案元素。整体无具象图形或图案构成，可视为“Abstract Pattern”。视觉风格简洁克制，没有多余装饰，符合“Minimalist Style”的极简风格。');
INSERT INTO `clothing_pattern_info` VALUES (2119801, 19996611, '纯色', '从图片看整条裤子为单一素色，没有花卉、条纹、格纹等明显图案，因此选择“Pure Color”“Solid color”作为图案元素。整体无具象图形或图案构成，可视为“Abstract Pattern”。视觉风格简洁克制，没有多余装饰，符合“Minimalist Style”的极简风格。');
