INSERT INTO `clothing_pattern_info` VALUES (2119803, 19996612, '纯色', '从图片看整条裤子为单一素色，没有花卉、条纹、格纹等明显图案，因此选择“Pure Color”“Solid color”作为图案元素。整体无具象图形或图案构成，可视为“Abstract Pattern”。视觉风格简洁克制，没有多余装饰，符合“Minimalist Style”的极简风格。');
INSERT INTO `clothing_pattern_info` VALUES (2119804, 19996613, '纯色', '从图片看整条裤子为单一素色，没有花卉、条纹、格纹等明显图案，因此选择“Pure Color”“Solid color”作为图案元素。整体无具象图形或图案构成，可视为“Abstract Pattern”。视觉风格简洁克制，没有多余装饰，符合“Minimalist Style”的极简风格。');
INSERT INTO `clothing_pattern_info` VALUES (2119805, 19996613, '纯色', '从图片看整条裤子为单一素色，没有花卉、条纹、格纹等明显图案，因此选择“Pure Color”“Solid color”作为图案元素。整体无具象图形或图案构成，可视为“Abstract Pattern”。视觉风格简洁克制，没有多余装饰，符合“Minimalist Style”的极简风格。');
INSERT INTO `clothing_pattern_info` VALUES (2119795, 19996607, '纯色', '从图片上看，外层上衣整体为单一色调，没有明显图案，仅呈现均匀的色块效果，因此选择“Pure Color/纯色”，属于整体铺满的“Allover pattern”，且为“Composed Pattern”中以单一元素构成。色面由染色或印染工艺实现，归入“Print”。整体没有具象图形，归类为“Abstract Pattern”，风格简洁，选用“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119796, 19996608, '纯色', '从图片上看，外层上衣整体为单一色调，没有明显图案，仅呈现均匀的色块效果，因此选择“Pure Color/纯色”，属于整体铺满的“Allover pattern”，且为“Composed Pattern”中以单一元素构成。色面由染色或印染工艺实现，归入“Print”。整体没有具象图形，归类为“Abstract Pattern”，风格简洁，选用“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119797, 19996609, '纯色', '从图片上看，外层上衣整体为单一色调，没有明显图案，仅呈现均匀的色块效果，因此选择“Pure Color/纯色”，属于整体铺满的“Allover pattern”，且为“Composed Pattern”中以单一元素构成。色面由染色或印染工艺实现，归入“Print”。整体没有具象图形，归类为“Abstract Pattern”，风格简洁，选用“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119793, 19996605, '格纹', '从图片与描述可见整体为一整面复古格纹，因此在布局上选择“Allover pattern”，属于整幅覆盖图案；图案方式为普通印花或织就效果，归入“Print”；格纹由多条线条和色块组合而成，属于“Composed Pattern”；具体元素为“check（格纹）”；格纹图案可被直接辨认，因此在定义上选“Representational Pattern”；风格上强调复古感，格纹呈经典老派气质，故采用“Vintage Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119794, 19996606, '格纹', '从图片与描述可见整体为一整面复古格纹，因此在布局上选择“Allover pattern”，属于整幅覆盖图案；图案方式为普通印花或织就效果，归入“Print”；格纹由多条线条和色块组合而成，属于“Composed Pattern”；具体元素为“check（格纹）”；格纹图案可被直接辨认，因此在定义上选“Representational Pattern”；风格上强调复古感，格纹呈经典老派气质，故采用“Vintage Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119789, 19996602, '其他', '图片中围巾整体布面都布满细小色块，是连续分布的整体性花纹，因此选择“Allover pattern”。图案明显为印制效果，故使用“Print”。花纹由许多细小元素组合成整体视觉，属于“Composed Pattern”。元素是抽象色块，不属于花卉、条纹等具体类别，因此用“Other patterns”。整体是非写实的抽象图案，于是选择“Abstract Pattern”作为图案定义。图案结构简洁、色彩低饱和，视觉风格偏简洁克制，所以归为“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119790, 19996603, '其他', '图片中围巾整体布面都布满细小色块，是连续分布的整体性花纹，因此选择“Allover pattern”。图案明显为印制效果，故使用“Print”。花纹由许多细小元素组合成整体视觉，属于“Composed Pattern”。元素是抽象色块，不属于花卉、条纹等具体类别，因此用“Other patterns”。整体是非写实的抽象图案，于是选择“Abstract Pattern”作为图案定义。图案结构简洁、色彩低饱和，视觉风格偏简洁克制，所以归为“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119791, 19996604, '纯色', '刀刃和手柄均为单一色块，没有具体图案元素，因此选择“Pure Color”和“Solid color”来表示整体为素色设计。整体外观没有具象图案，更偏向简洁造型，故在图案定义上归为“Abstract Pattern”。视觉风格上线条简洁、无多余装饰，体现“Minimalist Style”极简风格。');
INSERT INTO `clothing_pattern_info` VALUES (2119792, 19996604, '纯色', '刀刃和手柄均为单一色块，没有具体图案元素，因此选择“Pure Color”和“Solid color”来表示整体为素色设计。整体外观没有具象图案，更偏向简洁造型，故在图案定义上归为“Abstract Pattern”。视觉风格上线条简洁、无多余装饰，体现“Minimalist Style”极简风格。');
INSERT INTO `clothing_pattern_info` VALUES (2119785, 19996598, '其他', '袜子整体呈现大面积不规则扎染效果，因此选择“Allover pattern”和“Composed Pattern”。工艺上为“Tie-dye（扎染）”。图案元素为多色晕染和不规则条状花纹，难以归类为具体花卉或几何，故用“Other patterns”概括。整体图案偏意象化而非具象物体，所以在定义上选“Abstract Pattern”。扎染带有手工感和笔触感，视觉效果类似手作，因此风格上采用“Hand-drawn Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119786, 19996599, '其他', '袜子整体呈现大面积不规则扎染效果，因此选择“Allover pattern”和“Composed Pattern”。工艺上为“Tie-dye（扎染）”。图案元素为多色晕染和不规则条状花纹，难以归类为具体花卉或几何，故用“Other patterns”概括。整体图案偏意象化而非具象物体，所以在定义上选“Abstract Pattern”。扎染带有手工感和笔触感，视觉效果类似手作，因此风格上采用“Hand-drawn Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119787, 19996600, '其他', '袜子整体呈现大面积不规则扎染效果，因此选择“Allover pattern”和“Composed Pattern”。工艺上为“Tie-dye（扎染）”。图案元素为多色晕染和不规则条状花纹，难以归类为具体花卉或几何，故用“Other patterns”概括。整体图案偏意象化而非具象物体，所以在定义上选“Abstract Pattern”。扎染带有手工感和笔触感，视觉效果类似手作，因此风格上采用“Hand-drawn Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119788, 19996601, '其他', '袜子整体呈现大面积不规则扎染效果，因此选择“Allover pattern”和“Composed Pattern”。工艺上为“Tie-dye（扎染）”。图案元素为多色晕染和不规则条状花纹，难以归类为具体花卉或几何，故用“Other patterns”概括。整体图案偏意象化而非具象物体，所以在定义上选“Abstract Pattern”。扎染带有手工感和笔触感，视觉效果类似手作，因此风格上采用“Hand-drawn Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119783, 19996596, '卡通人物（拟人化物体）', '瓶身图案集中分布在下部区域，属于局部装饰，因此选择“Placement Print”。图案以印刷方式呈现，选用“Print”。图案由多个小方框角色头像组成，为多元素组合，故用“Composed Pattern”。角色均为卡通人物与IP形象，因此选“Character pattern”。整体图案清晰可辨，具象表达角色形象，归为“Representational Pattern”。风格明显是可爱卡通IP形象，故选择“Cartoon Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119784, 19996597, '卡通人物（拟人化物体）', '瓶身图案集中分布在下部区域，属于局部装饰，因此选择“Placement Print”。图案以印刷方式呈现，选用“Print”。图案由多个小方框角色头像组成，为多元素组合，故用“Composed Pattern”。角色均为卡通人物与IP形象，因此选“Character pattern”。整体图案清晰可辨，具象表达角色形象，归为“Representational Pattern”。风格明显是可爱卡通IP形象，故选择“Cartoon Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119773, 19996591, '字母', '袜身上有大面积分布的英文单词“Match”等文字，因此整体归为“Letter”和“Text”元素；这些文字围绕LOGO构成一个主要视觉，属于“Single Element Pattern”。文字通过织造呈现，符合“Jacquard”工艺特征，分布在袜筒与脚面区域，可视为整体的“Allover pattern”布局。图案内容有明确可识别的文字含义，因此在图案定义上选择“Representational Pattern”。整体设计简洁，仅有黑底白字，无复杂装饰，风格归为“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119774, 19996591, '文字', '袜身上有大面积分布的英文单词“Match”等文字，因此整体归为“Letter”和“Text”元素；这些文字围绕LOGO构成一个主要视觉，属于“Single Element Pattern”。文字通过织造呈现，符合“Jacquard”工艺特征，分布在袜筒与脚面区域，可视为整体的“Allover pattern”布局。图案内容有明确可识别的文字含义，因此在图案定义上选择“Representational Pattern”。整体设计简洁，仅有黑底白字，无复杂装饰，风格归为“Minimalist Style”。');
