INSERT INTO `clothing_pattern_info` VALUES (2119782, 19996595, '文字', '袜身上有大面积分布的英文单词“Match”等文字，因此整体归为“Letter”和“Text”元素；这些文字围绕LOGO构成一个主要视觉，属于“Single Element Pattern”。文字通过织造呈现，符合“Jacquard”工艺特征，分布在袜筒与脚面区域，可视为整体的“Allover pattern”布局。图案内容有明确可识别的文字含义，因此在图案定义上选择“Representational Pattern”。整体设计简洁，仅有黑底白字，无复杂装饰，风格归为“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119772, 19996590, '纯色', '从图片可见裤子为单一浅色，没有任何花纹、条纹或图案装饰，因此在图案元素上选择“Pure Color（纯色）”。整体无具体具象图案或主题，可视为抽象意义上的无图案设计，所以在图案定义维度上选择“Abstract Pattern（抽象图案）”。');
INSERT INTO `clothing_pattern_info` VALUES (2119762, 19996585, '纯色', '从图片看，裤子整体呈现单一色调，没有明显花朵、条纹或格纹等具体图案元素，因此选择“Pure Color/纯色”和“Solid color/素色”。面料表面虽有轻微织纹感但并非具象图案，所以在图案定义上归为“Abstract Pattern/抽象图案”。织物纹理均匀分布于整个面料，因此在布局上属于“Allover pattern/满版图案”。说明中提到多比组织和仿麻纹理，属于通过织造形成的肌理效果，对应“Jacquard/提花”类织造图案工艺标签。');
INSERT INTO `clothing_pattern_info` VALUES (2119763, 19996585, '纯色', '从图片看，裤子整体呈现单一色调，没有明显花朵、条纹或格纹等具体图案元素，因此选择“Pure Color/纯色”和“Solid color/素色”。面料表面虽有轻微织纹感但并非具象图案，所以在图案定义上归为“Abstract Pattern/抽象图案”。织物纹理均匀分布于整个面料，因此在布局上属于“Allover pattern/满版图案”。说明中提到多比组织和仿麻纹理，属于通过织造形成的肌理效果，对应“Jacquard/提花”类织造图案工艺标签。');
