INSERT INTO `clothing_pattern_info` VALUES (2119771, 19996589, '纯色', '从图片看，裤子整体呈现单一色调，没有明显花朵、条纹或格纹等具体图案元素，因此选择“Pure Color/纯色”和“Solid color/素色”。面料表面虽有轻微织纹感但并非具象图案，所以在图案定义上归为“Abstract Pattern/抽象图案”。织物纹理均匀分布于整个面料，因此在布局上属于“Allover pattern/满版图案”。说明中提到多比组织和仿麻纹理，属于通过织造形成的肌理效果，对应“Jacquard/提花”类织造图案工艺标签。');
INSERT INTO `clothing_pattern_info` VALUES (2119760, 19996583, '纯色', '从图片和描述来看，裙子为单一棕色，无花纹、格纹等复杂图案，因此选择“Pure Color（纯色）”和“Single Element Pattern（单一元素图案）”来表示仅有单色没有组合花型。整体没有具象图案或具象主题，归类为“Abstract Pattern（抽象图案）”最为合适。');
INSERT INTO `clothing_pattern_info` VALUES (2119761, 19996584, '纯色', '从图片和描述来看，裙子为单一棕色，无花纹、格纹等复杂图案，因此选择“Pure Color（纯色）”和“Single Element Pattern（单一元素图案）”来表示仅有单色没有组合花型。整体没有具象图案或具象主题，归类为“Abstract Pattern（抽象图案）”最为合适。');
INSERT INTO `clothing_pattern_info` VALUES (2119759, 19996582, '纯色', '从图片可见帽子整体为纯黑色，无明显装饰图案，仅有品牌标识，所以在图案元素上选择“Pure Color（纯色）”。整体没有具象花卉、动物或几何构成，属于无具体具象元素的“Abstract Pattern（抽象图案）”范畴。没有连续花纹或特殊排布，因此不再添加其它布局或风格类标签。');
INSERT INTO `clothing_pattern_info` VALUES (2119757, 19996580, '纯色', '从图片看鞋面为纯色帆布，没有花朵、条纹、格纹等具体图案元素，只是单一红色，因此选择“Pure Color/纯色”作为图案元素；整体仅是颜色呈现而非具象图形，所以在图案定义维度选择“Abstract Pattern/抽象图案”，未再添加其他布局或工艺类标签。');
INSERT INTO `clothing_pattern_info` VALUES (2119758, 19996581, '纯色', '从图片看鞋面为纯色帆布，没有花朵、条纹、格纹等具体图案元素，只是单一红色，因此选择“Pure Color/纯色”作为图案元素；整体仅是颜色呈现而非具象图形，所以在图案定义维度选择“Abstract Pattern/抽象图案”，未再添加其他布局或工艺类标签。');
INSERT INTO `clothing_pattern_info` VALUES (2119749, 19996574, '纯色', '裤子整体为单一浅色牛仔，未见明显花纹或图案，因此在图案元素维度选择“Pure Color”/纯色；牛仔的做旧与色差属于非具象的色块变化，可归类为“Abstract Pattern”抽象图案定义，用于描述这种非具体图形的视觉效果。未出现花朵、条纹、格纹等具体元素图案，所以不再添加其它图案标签。');
INSERT INTO `clothing_pattern_info` VALUES (2119750, 19996575, '纯色', '裤子整体为单一浅色牛仔，未见明显花纹或图案，因此在图案元素维度选择“Pure Color”/纯色；牛仔的做旧与色差属于非具象的色块变化，可归类为“Abstract Pattern”抽象图案定义，用于描述这种非具体图形的视觉效果。未出现花朵、条纹、格纹等具体元素图案，所以不再添加其它图案标签。');
INSERT INTO `clothing_pattern_info` VALUES (2119751, 19996576, '纯色', '从图片来看，裤子为单一水洗牛仔蓝色，没有花朵、条纹、格子等具体图案元素，因此在图案元素维度选择“Pure Color”和“Solid color”来描述其纯色效果。整体没有局部位置图案或拼接图案，属于整体统一色调，且洗水与做旧形成的色差只是抽象的色块变化，没有具象物体，因此在图案定义维度选用“Abstract Pattern”来概括这种抽象、非具象的色彩变化效果。');
INSERT INTO `clothing_pattern_info` VALUES (2119752, 19996576, '纯色', '从图片来看，裤子为单一水洗牛仔蓝色，没有花朵、条纹、格子等具体图案元素，因此在图案元素维度选择“Pure Color”和“Solid color”来描述其纯色效果。整体没有局部位置图案或拼接图案，属于整体统一色调，且洗水与做旧形成的色差只是抽象的色块变化，没有具象物体，因此在图案定义维度选用“Abstract Pattern”来概括这种抽象、非具象的色彩变化效果。');
INSERT INTO `clothing_pattern_info` VALUES (2119753, 19996577, '纯色', '从图片来看，裤子为单一水洗牛仔蓝色，没有花朵、条纹、格子等具体图案元素，因此在图案元素维度选择“Pure Color”和“Solid color”来描述其纯色效果。整体没有局部位置图案或拼接图案，属于整体统一色调，且洗水与做旧形成的色差只是抽象的色块变化，没有具象物体，因此在图案定义维度选用“Abstract Pattern”来概括这种抽象、非具象的色彩变化效果。');
INSERT INTO `clothing_pattern_info` VALUES (2119754, 19996577, '纯色', '从图片来看，裤子为单一水洗牛仔蓝色，没有花朵、条纹、格子等具体图案元素，因此在图案元素维度选择“Pure Color”和“Solid color”来描述其纯色效果。整体没有局部位置图案或拼接图案，属于整体统一色调，且洗水与做旧形成的色差只是抽象的色块变化，没有具象物体，因此在图案定义维度选用“Abstract Pattern”来概括这种抽象、非具象的色彩变化效果。');
INSERT INTO `clothing_pattern_info` VALUES (2119755, 19996578, '纯色', '从图片看，裤子为单一深色牛仔效果，没有明显花纹或图案元素，因此在图案元素维度选用“Pure Color”。整体只是基本色面料，没有具象图形或特定主题构成，所以在图案定义维度选择“Abstract Pattern”。未见其他排布方式或工艺印花的特征，因此不添加额外标签。');
INSERT INTO `clothing_pattern_info` VALUES (2119756, 19996579, '纯色', '从图片看，裤子为单一深色牛仔效果，没有明显花纹或图案元素，因此在图案元素维度选用“Pure Color”。整体只是基本色面料，没有具象图形或特定主题构成，所以在图案定义维度选择“Abstract Pattern”。未见其他排布方式或工艺印花的特征，因此不添加额外标签。');
INSERT INTO `clothing_pattern_info` VALUES (2119743, 19996571, '文字', '从图片可见图案集中在背部，为局部的大面积图案，因此选择“Placement Print”。图案采用印花工艺呈现品牌LOGO与城市线条，所以用“Print”。主体由品牌文字“Text”和城市天际线等“Object pattern”构成，整体围绕单一品牌主题，归类为“Single Element Pattern”。图案以线条构成城市轮廓与字样，具象可识别但高度简化，更偏抽象感，因此在图案定义中选择“Abstract Pattern”，并且整体以简洁构成与单色线条表现，风格上符合“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119744, 19996571, '物体', '从图片可见图案集中在背部，为局部的大面积图案，因此选择“Placement Print”。图案采用印花工艺呈现品牌LOGO与城市线条，所以用“Print”。主体由品牌文字“Text”和城市天际线等“Object pattern”构成，整体围绕单一品牌主题，归类为“Single Element Pattern”。图案以线条构成城市轮廓与字样，具象可识别但高度简化，更偏抽象感，因此在图案定义中选择“Abstract Pattern”，并且整体以简洁构成与单色线条表现，风格上符合“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119745, 19996572, '文字', '从图片可见图案集中在背部，为局部的大面积图案，因此选择“Placement Print”。图案采用印花工艺呈现品牌LOGO与城市线条，所以用“Print”。主体由品牌文字“Text”和城市天际线等“Object pattern”构成，整体围绕单一品牌主题，归类为“Single Element Pattern”。图案以线条构成城市轮廓与字样，具象可识别但高度简化，更偏抽象感，因此在图案定义中选择“Abstract Pattern”，并且整体以简洁构成与单色线条表现，风格上符合“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119746, 19996572, '物体', '从图片可见图案集中在背部，为局部的大面积图案，因此选择“Placement Print”。图案采用印花工艺呈现品牌LOGO与城市线条，所以用“Print”。主体由品牌文字“Text”和城市天际线等“Object pattern”构成，整体围绕单一品牌主题，归类为“Single Element Pattern”。图案以线条构成城市轮廓与字样，具象可识别但高度简化，更偏抽象感，因此在图案定义中选择“Abstract Pattern”，并且整体以简洁构成与单色线条表现，风格上符合“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119747, 19996573, '文字', '从图片可见图案集中在背部，为局部的大面积图案，因此选择“Placement Print”。图案采用印花工艺呈现品牌LOGO与城市线条，所以用“Print”。主体由品牌文字“Text”和城市天际线等“Object pattern”构成，整体围绕单一品牌主题，归类为“Single Element Pattern”。图案以线条构成城市轮廓与字样，具象可识别但高度简化，更偏抽象感，因此在图案定义中选择“Abstract Pattern”，并且整体以简洁构成与单色线条表现，风格上符合“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119748, 19996573, '物体', '从图片可见图案集中在背部，为局部的大面积图案，因此选择“Placement Print”。图案采用印花工艺呈现品牌LOGO与城市线条，所以用“Print”。主体由品牌文字“Text”和城市天际线等“Object pattern”构成，整体围绕单一品牌主题，归类为“Single Element Pattern”。图案以线条构成城市轮廓与字样，具象可识别但高度简化，更偏抽象感，因此在图案定义中选择“Abstract Pattern”，并且整体以简洁构成与单色线条表现，风格上符合“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119739, 19996569, '纯色', '从图片看鞋面为单一色，无明显装饰图案，因此在元素上选择“Pure Color/纯色”和“Solid color/纯色”，图案定义上属于无具象形象的“Abstract Pattern/抽象图案”，整体视觉风格简洁干净，可归为“Minimalist Style/极简风格”。');
INSERT INTO `clothing_pattern_info` VALUES (2119740, 19996569, '纯色', '从图片看鞋面为单一色，无明显装饰图案，因此在元素上选择“Pure Color/纯色”和“Solid color/纯色”，图案定义上属于无具象形象的“Abstract Pattern/抽象图案”，整体视觉风格简洁干净，可归为“Minimalist Style/极简风格”。');
INSERT INTO `clothing_pattern_info` VALUES (2119741, 19996570, '纯色', '从图片看鞋面为单一色，无明显装饰图案，因此在元素上选择“Pure Color/纯色”和“Solid color/纯色”，图案定义上属于无具象形象的“Abstract Pattern/抽象图案”，整体视觉风格简洁干净，可归为“Minimalist Style/极简风格”。');
INSERT INTO `clothing_pattern_info` VALUES (2119742, 19996570, '纯色', '从图片看鞋面为单一色，无明显装饰图案，因此在元素上选择“Pure Color/纯色”和“Solid color/纯色”，图案定义上属于无具象形象的“Abstract Pattern/抽象图案”，整体视觉风格简洁干净，可归为“Minimalist Style/极简风格”。');
INSERT INTO `clothing_pattern_info` VALUES (2119737, 19996567, '纯色', '从图片和描述看，服装为米色纯色，无明显图案或印花，因此在图案元素上选择“Pure Color（纯色）”。整体没有具象花卉、动物或几何等具象元素，属于没有具体对象的非具象图案表现，所以在图案定义维度选择“Abstract Pattern（抽象图案）”。未提及印花、提花或刺绣工艺，因此不添加其他图案工艺或布局标签。');
INSERT INTO `clothing_pattern_info` VALUES (2119738, 19996568, '纯色', '从图片和描述看，服装为米色纯色，无明显图案或印花，因此在图案元素上选择“Pure Color（纯色）”。整体没有具象花卉、动物或几何等具象元素，属于没有具体对象的非具象图案表现，所以在图案定义维度选择“Abstract Pattern（抽象图案）”。未提及印花、提花或刺绣工艺，因此不添加其他图案工艺或布局标签。');
INSERT INTO `clothing_pattern_info` VALUES (2119735, 19996565, '其他', '面料为多色纱交织而成的カラミ材质，整体织纹在全身均匀分布，因此选择“Allover pattern”和“Composed Pattern”。这种纹理是通过织造结构形成的整体花纹，属于“Jacquard”类的结构性图案，可归入“Other patterns”。图案没有具体具象元素，更偏向抽象几何感，所以在图案定义上选“Abstract Pattern”。整体视觉简洁低调，因此风格归为“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119736, 19996566, '其他', '面料为多色纱交织而成的カラミ材质，整体织纹在全身均匀分布，因此选择“Allover pattern”和“Composed Pattern”。这种纹理是通过织造结构形成的整体花纹，属于“Jacquard”类的结构性图案，可归入“Other patterns”。图案没有具体具象元素，更偏向抽象几何感，所以在图案定义上选“Abstract Pattern”。整体视觉简洁低调，因此风格归为“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119733, 19996563, '条纹', '从图片和描述看，整体为细针条纹覆盖整个裙身，属于“Allover pattern 全幅图案”，图案以印染方式呈现，对应“Print”。条纹在不同拼接裁片间连续构成整体效果，属于“Composed Pattern 组合图案”。具体元素为纵向细条纹，因此选“Stripes 条纹”。条纹并不表现具体物体，归为“Abstract Pattern 抽象图案”。视觉风格简洁克制，没有多余装饰，符合“Minimalist Style 极简风格”。');
INSERT INTO `clothing_pattern_info` VALUES (2119734, 19996564, '条纹', '从图片和描述看，整体为细针条纹覆盖整个裙身，属于“Allover pattern 全幅图案”，图案以印染方式呈现，对应“Print”。条纹在不同拼接裁片间连续构成整体效果，属于“Composed Pattern 组合图案”。具体元素为纵向细条纹，因此选“Stripes 条纹”。条纹并不表现具体物体，归为“Abstract Pattern 抽象图案”。视觉风格简洁克制，没有多余装饰，符合“Minimalist Style 极简风格”。');
INSERT INTO `clothing_pattern_info` VALUES (2119731, 19996561, '纯色', '从图片看整件裙子为纯黑色，只在袖口有细窄撞色滚边，没有明显大面积图案，整体属于“Pure Color/纯色”效果；整体视觉元素单一，故归为“Single Element Pattern/单一元素图案”。图案并非具象物体或具体形象，因此在图案定义上选择“Abstract Pattern/抽象图案”。');
INSERT INTO `clothing_pattern_info` VALUES (2119732, 19996562, '纯色', '从图片看整件裙子为纯黑色，只在袖口有细窄撞色滚边，没有明显大面积图案，整体属于“Pure Color/纯色”效果；整体视觉元素单一，故归为“Single Element Pattern/单一元素图案”。图案并非具象物体或具体形象，因此在图案定义上选择“Abstract Pattern/抽象图案”。');
INSERT INTO `clothing_pattern_info` VALUES (2119728, 19996558, '点', '面料表面整体都有细小的点状花纹，因此选择「Allover pattern」和元素「Dot」，整体由重复小元素构成，归为「Composed Pattern」，图案并非具象物体而是抽象点状，故选「Abstract Pattern」。从视觉上看图案简洁低调，没有复杂多元素组合，所以用「Minimalist Style」来描述风格。点状效果来自组织结构而非大面积印花，故技法选择「Jacquard」。');
INSERT INTO `clothing_pattern_info` VALUES (2119729, 19996559, '花卉图案', '从图片看为整体布面布满细小花朵元素，因此选择“Allover pattern（整体图案）”与“Floral pattern（花卉图案）”，属于多种元素组合构成的整体图案，所以用“Composed Pattern（组合图案）”。图案以印花方式呈现，故选“Print（印花）”。花朵具有具体可辨识形态，因此在图案定义上归为“Representational Pattern（具象图案）”。整体花型较细碎低调、颜色克制，风格简洁，因此在风格维度选择“Minimalist Style（极简风格）”。');
INSERT INTO `clothing_pattern_info` VALUES (2119730, 19996560, '花卉图案', '从图片看为整体布面布满细小花朵元素，因此选择“Allover pattern（整体图案）”与“Floral pattern（花卉图案）”，属于多种元素组合构成的整体图案，所以用“Composed Pattern（组合图案）”。图案以印花方式呈现，故选“Print（印花）”。花朵具有具体可辨识形态，因此在图案定义上归为“Representational Pattern（具象图案）”。整体花型较细碎低调、颜色克制，风格简洁，因此在风格维度选择“Minimalist Style（极简风格）”。');
INSERT INTO `clothing_pattern_info` VALUES (2119727, 19996557, '字母', '帽子前片位置有局部字母标志图案，因此选择“Placement Print（局部图案布局）”。从工艺上看是立体感很强的线迹图形，属于“Embroidery（刺绣）”。图案元素是单一的大字母标识，所以选“Single Element Pattern（单一元素图案）”与“Letter（字母）”。图案清晰写实，可以辨认具体含义，归为“Representational Pattern（具象图案）”，整体构图简洁干净，因此风格上选择“Minimalist Style（极简风格）”。');
INSERT INTO `clothing_pattern_info` VALUES (2119725, 19996555, '字母', '帽前的字母/标志集中在前片位置，因此选择「Placement Print」和「Single Element Pattern」，图案元素为字母LOGO，对应「Letter」，属于具有具体含义的「具象图案（Representational Pattern）」。品牌与标志呈简洁干净的视觉效果，因此在风格上归为「Minimalist Style」。刺绣方式呈现LOGO，所以加入「Embroidery」。');
INSERT INTO `clothing_pattern_info` VALUES (2119726, 19996556, '字母', '帽前的字母/标志集中在前片位置，因此选择「Placement Print」和「Single Element Pattern」，图案元素为字母LOGO，对应「Letter」，属于具有具体含义的「具象图案（Representational Pattern）」。品牌与标志呈简洁干净的视觉效果，因此在风格上归为「Minimalist Style」。刺绣方式呈现LOGO，所以加入「Embroidery」。');
INSERT INTO `clothing_pattern_info` VALUES (2119723, 19996553, '其他', '整体呈现均匀分布的Acid水洗效果，因此用“Allover pattern”和“Print”描述其通铺式做旧效果；图案并非单一元素，而是整片布面形成的整体效果，选“Composed Pattern”；具体元素属于不规则水洗痕迹，归为“Other patterns”；图案并不具象某种具体物体，适合“Abstract Pattern”；水洗做旧视觉带有复古味道，因此选“Vintage Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119724, 19996554, '其他', '整体呈现均匀分布的Acid水洗效果，因此用“Allover pattern”和“Print”描述其通铺式做旧效果；图案并非单一元素，而是整片布面形成的整体效果，选“Composed Pattern”；具体元素属于不规则水洗痕迹，归为“Other patterns”；图案并不具象某种具体物体，适合“Abstract Pattern”；水洗做旧视觉带有复古味道，因此选“Vintage Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119721, 19996551, '其他', '包身整体以规则重复的镂空编织纹样覆盖，属于整体铺满式布局，因此选用“Allover pattern”。编织纹样由多种线条与孔洞组合形成整体图案，而非单一元素，所以使用“Composed Pattern”。具体纹样为抽象的几何与孔洞组合，不属于花卉、条纹等常见具象元素，归入“Other patterns”，并在定义上选择“Abstract Pattern”。整体视觉简洁、有序，以结构变化为主，符合理性简约的“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119722, 19996552, '其他', '包身整体以规则重复的镂空编织纹样覆盖，属于整体铺满式布局，因此选用“Allover pattern”。编织纹样由多种线条与孔洞组合形成整体图案，而非单一元素，所以使用“Composed Pattern”。具体纹样为抽象的几何与孔洞组合，不属于花卉、条纹等常见具象元素，归入“Other patterns”，并在定义上选择“Abstract Pattern”。整体视觉简洁、有序，以结构变化为主，符合理性简约的“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119717, 19996547, '纯色', '从图片看整条裙子为单一色面，无局部位置图案，整体统一，因此使用“Allover pattern”和“Composed Pattern”。没有织花或刺绣等立体工艺痕迹，默认以整体色面效果归为“Print”。图案元素为无任何图形或花纹的纯色面料，所以用“Pure Color”，整体呈简洁极简风格，对应“Minimalist Style”。没有具象图案，归类为“Abstract Pattern”。');
INSERT INTO `clothing_pattern_info` VALUES (2119718, 19996548, '纯色', '从图片看整条裙子为单一色面，无局部位置图案，整体统一，因此使用“Allover pattern”和“Composed Pattern”。没有织花或刺绣等立体工艺痕迹，默认以整体色面效果归为“Print”。图案元素为无任何图形或花纹的纯色面料，所以用“Pure Color”，整体呈简洁极简风格，对应“Minimalist Style”。没有具象图案，归类为“Abstract Pattern”。');
INSERT INTO `clothing_pattern_info` VALUES (2119719, 19996549, '方形', '图片中整块丝巾上由同心方形线条组成连续图案，覆盖整个面料，因此使用“Allover pattern”和“Composed Pattern”。图案显然是印制上的，选择“Print”。元素上是规则的“Square”几何线条组合，无其他具象花卉或动植物。整体为几何构成的抽象视觉效果，所以定义为“Abstract Pattern”。线条简洁、配色克制，整体风格偏“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119720, 19996550, '方形', '图片中整块丝巾上由同心方形线条组成连续图案，覆盖整个面料，因此使用“Allover pattern”和“Composed Pattern”。图案显然是印制上的，选择“Print”。元素上是规则的“Square”几何线条组合，无其他具象花卉或动植物。整体为几何构成的抽象视觉效果，所以定义为“Abstract Pattern”。线条简洁、配色克制，整体风格偏“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119708, 19996541, '纯色', '从图片看整件服装为统一的纯黑色，没有可辨识的花朵、条纹等具体图案元素，因此选用“Pure Color/纯色”和“Solid color/纯色”作为图案元素。颜色和明暗变化仅是整体肌理效果，缺少具象主题，所以在定义上更符合“Abstract Pattern/抽象图案”。色块覆盖全身，因此在布局上归为“Allover pattern/整体覆盖图案”，并作为整体一体化设计，选择“Composed Pattern/组合图案”来表示整体统一的色面构成。');
INSERT INTO `clothing_pattern_info` VALUES (2119709, 19996541, '纯色', '从图片看整件服装为统一的纯黑色，没有可辨识的花朵、条纹等具体图案元素，因此选用“Pure Color/纯色”和“Solid color/纯色”作为图案元素。颜色和明暗变化仅是整体肌理效果，缺少具象主题，所以在定义上更符合“Abstract Pattern/抽象图案”。色块覆盖全身，因此在布局上归为“Allover pattern/整体覆盖图案”，并作为整体一体化设计，选择“Composed Pattern/组合图案”来表示整体统一的色面构成。');
INSERT INTO `clothing_pattern_info` VALUES (2119710, 19996542, '纯色', '从图片看整件服装为统一的纯黑色，没有可辨识的花朵、条纹等具体图案元素，因此选用“Pure Color/纯色”和“Solid color/纯色”作为图案元素。颜色和明暗变化仅是整体肌理效果，缺少具象主题，所以在定义上更符合“Abstract Pattern/抽象图案”。色块覆盖全身，因此在布局上归为“Allover pattern/整体覆盖图案”，并作为整体一体化设计，选择“Composed Pattern/组合图案”来表示整体统一的色面构成。');
INSERT INTO `clothing_pattern_info` VALUES (2119711, 19996542, '纯色', '从图片看整件服装为统一的纯黑色，没有可辨识的花朵、条纹等具体图案元素，因此选用“Pure Color/纯色”和“Solid color/纯色”作为图案元素。颜色和明暗变化仅是整体肌理效果，缺少具象主题，所以在定义上更符合“Abstract Pattern/抽象图案”。色块覆盖全身，因此在布局上归为“Allover pattern/整体覆盖图案”，并作为整体一体化设计，选择“Composed Pattern/组合图案”来表示整体统一的色面构成。');
INSERT INTO `clothing_pattern_info` VALUES (2119712, 19996543, '纯色', '从图片看整件服装为统一的纯黑色，没有可辨识的花朵、条纹等具体图案元素，因此选用“Pure Color/纯色”和“Solid color/纯色”作为图案元素。颜色和明暗变化仅是整体肌理效果，缺少具象主题，所以在定义上更符合“Abstract Pattern/抽象图案”。色块覆盖全身，因此在布局上归为“Allover pattern/整体覆盖图案”，并作为整体一体化设计，选择“Composed Pattern/组合图案”来表示整体统一的色面构成。');
INSERT INTO `clothing_pattern_info` VALUES (2119713, 19996543, '纯色', '从图片看整件服装为统一的纯黑色，没有可辨识的花朵、条纹等具体图案元素，因此选用“Pure Color/纯色”和“Solid color/纯色”作为图案元素。颜色和明暗变化仅是整体肌理效果，缺少具象主题，所以在定义上更符合“Abstract Pattern/抽象图案”。色块覆盖全身，因此在布局上归为“Allover pattern/整体覆盖图案”，并作为整体一体化设计，选择“Composed Pattern/组合图案”来表示整体统一的色面构成。');
INSERT INTO `clothing_pattern_info` VALUES (2119714, 19996544, '纯色', '从图片看整件为单一纯色，没有花朵、条纹、格子等具体图案元素，因此选择“Pure Color/纯色”作为图案元素。整体仅是色块与轻微透感形成的视觉效果，属于“Abstract Pattern/抽象图案”的范畴。未见明显局部画面或边框布局，因此不再添加其它布局或技法类标签。');
INSERT INTO `clothing_pattern_info` VALUES (2119715, 19996545, '纯色', '从图片看整件为单一纯色，没有花朵、条纹、格子等具体图案元素，因此选择“Pure Color/纯色”作为图案元素。整体仅是色块与轻微透感形成的视觉效果，属于“Abstract Pattern/抽象图案”的范畴。未见明显局部画面或边框布局，因此不再添加其它布局或技法类标签。');
INSERT INTO `clothing_pattern_info` VALUES (2119716, 19996546, '纯色', '从图片看整件为单一纯色，没有花朵、条纹、格子等具体图案元素，因此选择“Pure Color/纯色”作为图案元素。整体仅是色块与轻微透感形成的视觉效果，属于“Abstract Pattern/抽象图案”的范畴。未见明显局部画面或边框布局，因此不再添加其它布局或技法类标签。');
INSERT INTO `clothing_pattern_info` VALUES (2119706, 19996539, '花卉图案', '整体为连续分布的植物花叶图案，覆盖全身，因此选择“Allover pattern”；图案明显为印刷呈现，对应“Print”；由多种枝叶、花形组合构成，属于“Composed Pattern”；主要元素是植物花叶，归为“Floral pattern”；图案并非写实，而是概括与装饰化处理，因此在定义上更接近“Abstract Pattern”。');
INSERT INTO `clothing_pattern_info` VALUES (2119707, 19996540, '花卉图案', '整体为连续分布的植物花叶图案，覆盖全身，因此选择“Allover pattern”；图案明显为印刷呈现，对应“Print”；由多种枝叶、花形组合构成，属于“Composed Pattern”；主要元素是植物花叶，归为“Floral pattern”；图案并非写实，而是概括与装饰化处理，因此在定义上更接近“Abstract Pattern”。');
INSERT INTO `clothing_pattern_info` VALUES (2119698, 19996533, '纯色', '从图片看，衣身为单一色调，没有可见花朵、几何等具体图案，因此使用“Pure Color”和“Solid color”来表示纯色元素。整体色块均匀覆盖衣身，属于“Allover pattern”，且色彩效果来源于整体染色，归入“Print”和“Composed Pattern”。图案本身不表现具体事物，仅为单色面，属于抽象表现，因此选“Figurative Pattern”中更贴近非具象表达的标签。整体视觉简洁干净，无多余装饰，风格上归为“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119699, 19996533, '纯色', '从图片看，衣身为单一色调，没有可见花朵、几何等具体图案，因此使用“Pure Color”和“Solid color”来表示纯色元素。整体色块均匀覆盖衣身，属于“Allover pattern”，且色彩效果来源于整体染色，归入“Print”和“Composed Pattern”。图案本身不表现具体事物，仅为单色面，属于抽象表现，因此选“Figurative Pattern”中更贴近非具象表达的标签。整体视觉简洁干净，无多余装饰，风格上归为“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119700, 19996534, '纯色', '从图片看，衣身为单一色调，没有可见花朵、几何等具体图案，因此使用“Pure Color”和“Solid color”来表示纯色元素。整体色块均匀覆盖衣身，属于“Allover pattern”，且色彩效果来源于整体染色，归入“Print”和“Composed Pattern”。图案本身不表现具体事物，仅为单色面，属于抽象表现，因此选“Figurative Pattern”中更贴近非具象表达的标签。整体视觉简洁干净，无多余装饰，风格上归为“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119701, 19996534, '纯色', '从图片看，衣身为单一色调，没有可见花朵、几何等具体图案，因此使用“Pure Color”和“Solid color”来表示纯色元素。整体色块均匀覆盖衣身，属于“Allover pattern”，且色彩效果来源于整体染色，归入“Print”和“Composed Pattern”。图案本身不表现具体事物，仅为单色面，属于抽象表现，因此选“Figurative Pattern”中更贴近非具象表达的标签。整体视觉简洁干净，无多余装饰，风格上归为“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119702, 19996535, '纯色', '从图片看，整件T恤为纯色无明显图案装饰，因此图案元素选择“Pure Color（纯色）”。整体没有具象花卉或字符等具体形象，属于抽象意义上的无图案表面，所以在图案定义上归类为“Abstract Pattern（抽象图案）”。视觉风格简单利落、无多余装饰，符合“Minimalist Style（极简风格）”的特征。');
INSERT INTO `clothing_pattern_info` VALUES (2119703, 19996536, '纯色', '从图片看，整件T恤为纯色无明显图案装饰，因此图案元素选择“Pure Color（纯色）”。整体没有具象花卉或字符等具体形象，属于抽象意义上的无图案表面，所以在图案定义上归类为“Abstract Pattern（抽象图案）”。视觉风格简单利落、无多余装饰，符合“Minimalist Style（极简风格）”的特征。');
INSERT INTO `clothing_pattern_info` VALUES (2119704, 19996537, '纯色', '从图片看，整件T恤为纯色无明显图案装饰，因此图案元素选择“Pure Color（纯色）”。整体没有具象花卉或字符等具体形象，属于抽象意义上的无图案表面，所以在图案定义上归类为“Abstract Pattern（抽象图案）”。视觉风格简单利落、无多余装饰，符合“Minimalist Style（极简风格）”的特征。');
INSERT INTO `clothing_pattern_info` VALUES (2119705, 19996538, '纯色', '从图片看，整件T恤为纯色无明显图案装饰，因此图案元素选择“Pure Color（纯色）”。整体没有具象花卉或字符等具体形象，属于抽象意义上的无图案表面，所以在图案定义上归类为“Abstract Pattern（抽象图案）”。视觉风格简单利落、无多余装饰，符合“Minimalist Style（极简风格）”的特征。');
INSERT INTO `clothing_pattern_info` VALUES (2119688, 19996526, '纯色', '从图片看整体为纯黑色无明显图案，仅为素色面料，因此选用“Pure Color/纯色”和“Solid color/纯色”。没有局部位置图案或复杂结构，整体视觉属于抽象概念上的素色效果，所以在图案定义上归为“Abstract Pattern/抽象图案”。风格上图案极简，无多余装饰，因此在风格维度选择“Minimalist Style/极简风格”。');
INSERT INTO `clothing_pattern_info` VALUES (2119689, 19996526, '纯色', '从图片看整体为纯黑色无明显图案，仅为素色面料，因此选用“Pure Color/纯色”和“Solid color/纯色”。没有局部位置图案或复杂结构，整体视觉属于抽象概念上的素色效果，所以在图案定义上归为“Abstract Pattern/抽象图案”。风格上图案极简，无多余装饰，因此在风格维度选择“Minimalist Style/极简风格”。');
