INSERT INTO `clothing_pattern_info` VALUES (2119692, 19996528, '纯色', '从图片看整体为纯黑色无明显图案，仅为素色面料，因此选用“Pure Color/纯色”和“Solid color/纯色”。没有局部位置图案或复杂结构，整体视觉属于抽象概念上的素色效果，所以在图案定义上归为“Abstract Pattern/抽象图案”。风格上图案极简，无多余装饰，因此在风格维度选择“Minimalist Style/极简风格”。');
INSERT INTO `clothing_pattern_info` VALUES (2119693, 19996528, '纯色', '从图片看整体为纯黑色无明显图案，仅为素色面料，因此选用“Pure Color/纯色”和“Solid color/纯色”。没有局部位置图案或复杂结构，整体视觉属于抽象概念上的素色效果，所以在图案定义上归为“Abstract Pattern/抽象图案”。风格上图案极简，无多余装饰，因此在风格维度选择“Minimalist Style/极简风格”。');
INSERT INTO `clothing_pattern_info` VALUES (2119694, 19996529, '纯色', '从图片看整件衣服为单一色，无明显局部图案，因此按整体面料视为「Allover pattern」，工艺上为普通面料染色，对应「Print」。图案构成上没有单一图形重复式点缀，而是整体纯色效果，归入「Composed Pattern」。图案元素为无花纹的纯色，所以选「Pure Color」，整体没有具象图案，属于「Abstract Pattern」。视觉风格简洁干练，没有复杂装饰，因此风格选择「Minimalist Style」。');
INSERT INTO `clothing_pattern_info` VALUES (2119695, 19996530, '纯色', '从图片看整件衣服为单一色，无明显局部图案，因此按整体面料视为「Allover pattern」，工艺上为普通面料染色，对应「Print」。图案构成上没有单一图形重复式点缀，而是整体纯色效果，归入「Composed Pattern」。图案元素为无花纹的纯色，所以选「Pure Color」，整体没有具象图案，属于「Abstract Pattern」。视觉风格简洁干练，没有复杂装饰，因此风格选择「Minimalist Style」。');
INSERT INTO `clothing_pattern_info` VALUES (2119696, 19996531, '纯色', '从图片看整件衣服为单一色，无明显局部图案，因此按整体面料视为「Allover pattern」，工艺上为普通面料染色，对应「Print」。图案构成上没有单一图形重复式点缀，而是整体纯色效果，归入「Composed Pattern」。图案元素为无花纹的纯色，所以选「Pure Color」，整体没有具象图案，属于「Abstract Pattern」。视觉风格简洁干练，没有复杂装饰，因此风格选择「Minimalist Style」。');
INSERT INTO `clothing_pattern_info` VALUES (2119697, 19996532, '纯色', '从图片看整件衣服为单一色，无明显局部图案，因此按整体面料视为「Allover pattern」，工艺上为普通面料染色，对应「Print」。图案构成上没有单一图形重复式点缀，而是整体纯色效果，归入「Composed Pattern」。图案元素为无花纹的纯色，所以选「Pure Color」，整体没有具象图案，属于「Abstract Pattern」。视觉风格简洁干练，没有复杂装饰，因此风格选择「Minimalist Style」。');
INSERT INTO `clothing_pattern_info` VALUES (2119685, 19996523, '文字', '从图片看，前胸位置有一处英文“Au revoir”及小字排版，为局部的文字印花，因此图案布局选用“Placement Print”，工艺为“Print”。整体仅有一处文字元素，所以为“Single Element Pattern”。图案元素是英文文字，因此选择“Text”。文字表达具体内容，属于具象信息，因此图案定义为“Representational Pattern”。整体排版简洁、留白多、无复杂装饰，风格归类为“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119686, 19996524, '文字', '从图片看，前胸位置有一处英文“Au revoir”及小字排版，为局部的文字印花，因此图案布局选用“Placement Print”，工艺为“Print”。整体仅有一处文字元素，所以为“Single Element Pattern”。图案元素是英文文字，因此选择“Text”。文字表达具体内容，属于具象信息，因此图案定义为“Representational Pattern”。整体排版简洁、留白多、无复杂装饰，风格归类为“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119687, 19996525, '文字', '从图片看，前胸位置有一处英文“Au revoir”及小字排版，为局部的文字印花，因此图案布局选用“Placement Print”，工艺为“Print”。整体仅有一处文字元素，所以为“Single Element Pattern”。图案元素是英文文字，因此选择“Text”。文字表达具体内容，属于具象信息，因此图案定义为“Representational Pattern”。整体排版简洁、留白多、无复杂装饰，风格归类为“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119681, 19996519, '点', '从图片可见整件衣服布满均匀的小点，属于整体铺满式图案，因此选择“Allover pattern”和“Composed Pattern”。图案是通过印花工艺呈现，故选“Print”。图案元素为不规则小圆点，归入“Dot”。这些点并不表现具体事物，属于抽象视觉效果，所以在图案定义中选择“Abstract Pattern”。整体画面简洁克制，没有复杂配色和多余装饰，因此在风格上选“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119682, 19996520, '点', '从图片可见整件衣服布满均匀的小点，属于整体铺满式图案，因此选择“Allover pattern”和“Composed Pattern”。图案是通过印花工艺呈现，故选“Print”。图案元素为不规则小圆点，归入“Dot”。这些点并不表现具体事物，属于抽象视觉效果，所以在图案定义中选择“Abstract Pattern”。整体画面简洁克制，没有复杂配色和多余装饰，因此在风格上选“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119683, 19996521, '点', '从图片可见整件衣服布满均匀的小点，属于整体铺满式图案，因此选择“Allover pattern”和“Composed Pattern”。图案是通过印花工艺呈现，故选“Print”。图案元素为不规则小圆点，归入“Dot”。这些点并不表现具体事物，属于抽象视觉效果，所以在图案定义中选择“Abstract Pattern”。整体画面简洁克制，没有复杂配色和多余装饰，因此在风格上选“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119684, 19996522, '点', '从图片可见整件衣服布满均匀的小点，属于整体铺满式图案，因此选择“Allover pattern”和“Composed Pattern”。图案是通过印花工艺呈现，故选“Print”。图案元素为不规则小圆点，归入“Dot”。这些点并不表现具体事物，属于抽象视觉效果，所以在图案定义中选择“Abstract Pattern”。整体画面简洁克制，没有复杂配色和多余装饰，因此在风格上选“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119677, 19996517, '花卉图案', '从图片可以看到整条裤子覆盖着连续的植物图案，因此选择“Allover pattern”表示满身分布的图案；图案是以印花形式呈现，所以选“Print”。整体由多种植物枝叶组合成一整片花草图案，而不是单一元素，故为“Composed Pattern”。元素上是叶片和花草，归为“Floral pattern”和“Leaves”。这些植物图案具象可辨，所以在图案定义上归为“Figurative Pattern”。线条略带手绘感、轮廓不完全工整，因此风格上选择“Hand-drawn Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119678, 19996517, '叶子', '从图片可以看到整条裤子覆盖着连续的植物图案，因此选择“Allover pattern”表示满身分布的图案；图案是以印花形式呈现，所以选“Print”。整体由多种植物枝叶组合成一整片花草图案，而不是单一元素，故为“Composed Pattern”。元素上是叶片和花草，归为“Floral pattern”和“Leaves”。这些植物图案具象可辨，所以在图案定义上归为“Figurative Pattern”。线条略带手绘感、轮廓不完全工整，因此风格上选择“Hand-drawn Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119679, 19996518, '花卉图案', '从图片可以看到整条裤子覆盖着连续的植物图案，因此选择“Allover pattern”表示满身分布的图案；图案是以印花形式呈现，所以选“Print”。整体由多种植物枝叶组合成一整片花草图案，而不是单一元素，故为“Composed Pattern”。元素上是叶片和花草，归为“Floral pattern”和“Leaves”。这些植物图案具象可辨，所以在图案定义上归为“Figurative Pattern”。线条略带手绘感、轮廓不完全工整，因此风格上选择“Hand-drawn Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119680, 19996518, '叶子', '从图片可以看到整条裤子覆盖着连续的植物图案，因此选择“Allover pattern”表示满身分布的图案；图案是以印花形式呈现，所以选“Print”。整体由多种植物枝叶组合成一整片花草图案，而不是单一元素，故为“Composed Pattern”。元素上是叶片和花草，归为“Floral pattern”和“Leaves”。这些植物图案具象可辨，所以在图案定义上归为“Figurative Pattern”。线条略带手绘感、轮廓不完全工整，因此风格上选择“Hand-drawn Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119675, 19996516, '字母', '从图片中可以看到整条裤子布面都布满规则重复的字母与标识，属于“Allover pattern 全幅图案”，且是由多个字母与品牌元素组合构成，因此选“Composed Pattern 组合图案”。图案以字母和品牌标识为主，归为“Letter 字母”和“Logo Placement 标志图案”。这些图案是可辨认的具体符号，属于“Representational Pattern 具象图案”。风格上以简洁重复的品牌字样为主，没有复杂绘画效果，偏“Minimalist Style 极简风格”。从面料组织与图案同色浮现的效果来看，更像组织结构形成的花型，因此在工艺上选择“Jacquard 提花”。');
INSERT INTO `clothing_pattern_info` VALUES (2119676, 19996516, '品牌标识', '从图片中可以看到整条裤子布面都布满规则重复的字母与标识，属于“Allover pattern 全幅图案”，且是由多个字母与品牌元素组合构成，因此选“Composed Pattern 组合图案”。图案以字母和品牌标识为主，归为“Letter 字母”和“Logo Placement 标志图案”。这些图案是可辨认的具体符号，属于“Representational Pattern 具象图案”。风格上以简洁重复的品牌字样为主，没有复杂绘画效果，偏“Minimalist Style 极简风格”。从面料组织与图案同色浮现的效果来看，更像组织结构形成的花型，因此在工艺上选择“Jacquard 提花”。');
INSERT INTO `clothing_pattern_info` VALUES (2119673, 19996515, '纯色', '从图片看服装为单一浅色，无任何明显图案或标识，仅有面料结构形成的视觉效果，因此在图案元素上选择“Pure Color／Solid color”。整体没有具象花纹或图像，可视为“Abstract Pattern”。没有看到局部定位花或复杂布局，所以不添加其他布局类或工艺类标签。');
INSERT INTO `clothing_pattern_info` VALUES (2119674, 19996515, '纯色', '从图片看服装为单一浅色，无任何明显图案或标识，仅有面料结构形成的视觉效果，因此在图案元素上选择“Pure Color／Solid color”。整体没有具象花纹或图像，可视为“Abstract Pattern”。没有看到局部定位花或复杂布局，所以不添加其他布局类或工艺类标签。');
INSERT INTO `clothing_pattern_info` VALUES (2119667, 19996513, '人物图案（人形，人体）', '衣身前幅只有一处集中图案，属于“Placement Print（局部位置印花）”，通过“Print（印花）”方式呈现。图案由恐龙角色、笑脸、卡通头像等组合构成，整体可视为多元素组合但集中于一个画面，因此归为“Single Element Pattern（单一元素图案）”下的“Figure pattern（人物图案）”与“Character pattern（角色图案）”，并包含“Text（文字）”。整体以涂鸦感、手绘线条呈现，风格明显是“Illustration Effect（插画效果）”。这些图案都具象可辨认，故在定义上属于“Figurative Pattern（具象图案）”。');
INSERT INTO `clothing_pattern_info` VALUES (2119668, 19996513, '卡通人物（拟人化物体）', '衣身前幅只有一处集中图案，属于“Placement Print（局部位置印花）”，通过“Print（印花）”方式呈现。图案由恐龙角色、笑脸、卡通头像等组合构成，整体可视为多元素组合但集中于一个画面，因此归为“Single Element Pattern（单一元素图案）”下的“Figure pattern（人物图案）”与“Character pattern（角色图案）”，并包含“Text（文字）”。整体以涂鸦感、手绘线条呈现，风格明显是“Illustration Effect（插画效果）”。这些图案都具象可辨认，故在定义上属于“Figurative Pattern（具象图案）”。');
INSERT INTO `clothing_pattern_info` VALUES (2119669, 19996513, '文字', '衣身前幅只有一处集中图案，属于“Placement Print（局部位置印花）”，通过“Print（印花）”方式呈现。图案由恐龙角色、笑脸、卡通头像等组合构成，整体可视为多元素组合但集中于一个画面，因此归为“Single Element Pattern（单一元素图案）”下的“Figure pattern（人物图案）”与“Character pattern（角色图案）”，并包含“Text（文字）”。整体以涂鸦感、手绘线条呈现，风格明显是“Illustration Effect（插画效果）”。这些图案都具象可辨认，故在定义上属于“Figurative Pattern（具象图案）”。');
INSERT INTO `clothing_pattern_info` VALUES (2119670, 19996514, '人物图案（人形，人体）', '衣身前幅只有一处集中图案，属于“Placement Print（局部位置印花）”，通过“Print（印花）”方式呈现。图案由恐龙角色、笑脸、卡通头像等组合构成，整体可视为多元素组合但集中于一个画面，因此归为“Single Element Pattern（单一元素图案）”下的“Figure pattern（人物图案）”与“Character pattern（角色图案）”，并包含“Text（文字）”。整体以涂鸦感、手绘线条呈现，风格明显是“Illustration Effect（插画效果）”。这些图案都具象可辨认，故在定义上属于“Figurative Pattern（具象图案）”。');
INSERT INTO `clothing_pattern_info` VALUES (2119671, 19996514, '卡通人物（拟人化物体）', '衣身前幅只有一处集中图案，属于“Placement Print（局部位置印花）”，通过“Print（印花）”方式呈现。图案由恐龙角色、笑脸、卡通头像等组合构成，整体可视为多元素组合但集中于一个画面，因此归为“Single Element Pattern（单一元素图案）”下的“Figure pattern（人物图案）”与“Character pattern（角色图案）”，并包含“Text（文字）”。整体以涂鸦感、手绘线条呈现，风格明显是“Illustration Effect（插画效果）”。这些图案都具象可辨认，故在定义上属于“Figurative Pattern（具象图案）”。');
INSERT INTO `clothing_pattern_info` VALUES (2119672, 19996514, '文字', '衣身前幅只有一处集中图案，属于“Placement Print（局部位置印花）”，通过“Print（印花）”方式呈现。图案由恐龙角色、笑脸、卡通头像等组合构成，整体可视为多元素组合但集中于一个画面，因此归为“Single Element Pattern（单一元素图案）”下的“Figure pattern（人物图案）”与“Character pattern（角色图案）”，并包含“Text（文字）”。整体以涂鸦感、手绘线条呈现，风格明显是“Illustration Effect（插画效果）”。这些图案都具象可辨认，故在定义上属于“Figurative Pattern（具象图案）”。');
INSERT INTO `clothing_pattern_info` VALUES (2119663, 19996509, '纯色', '瓶身主色为单一的白色，可视为“Pure Color（纯色）”。正面标签为黑白照片及文字排版，属于抽象化的信息与图像组合，没有明显具象图案，因此在图案定义维度上归为“Abstract Pattern（抽象图案）”。');
INSERT INTO `clothing_pattern_info` VALUES (2119664, 19996510, '纯色', '瓶身主色为单一的白色，可视为“Pure Color（纯色）”。正面标签为黑白照片及文字排版，属于抽象化的信息与图像组合，没有明显具象图案，因此在图案定义维度上归为“Abstract Pattern（抽象图案）”。');
INSERT INTO `clothing_pattern_info` VALUES (2119665, 19996511, '纯色', '瓶身主色为单一的白色，可视为“Pure Color（纯色）”。正面标签为黑白照片及文字排版，属于抽象化的信息与图像组合，没有明显具象图案，因此在图案定义维度上归为“Abstract Pattern（抽象图案）”。');
INSERT INTO `clothing_pattern_info` VALUES (2119666, 19996512, '纯色', '瓶身整体为纯色背景，因此选择“Pure Color”。标签区域只有简单文字与人物照片构成，没有连续重复的具体图案元素，整体更接近抽象视觉信息，故在图案定义上归为“Abstract Pattern”。');
INSERT INTO `clothing_pattern_info` VALUES (2119661, 19996507, '点', '从图片上看裤子整体布满细小圆点，属于整体铺满式图案，因此选择“Allover pattern”。图案是通过印花方式呈现，选用“Print”。整体由重复的小圆点构成，而非单一大型图形，所以为“Composed Pattern”。圆点本身对应“Dot”这一图案元素。点状分布没有具体具象事物含义，归为“Abstract Pattern”。圆点规则、简洁，整体给人干净利落的视觉感受，因此在风格上选用“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119662, 19996508, '点', '从图片上看裤子整体布满细小圆点，属于整体铺满式图案，因此选择“Allover pattern”。图案是通过印花方式呈现，选用“Print”。整体由重复的小圆点构成，而非单一大型图形，所以为“Composed Pattern”。圆点本身对应“Dot”这一图案元素。点状分布没有具体具象事物含义，归为“Abstract Pattern”。圆点规则、简洁，整体给人干净利落的视觉感受，因此在风格上选用“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119611, 19996457, '花卉图案', '从图片来看，整个方巾表面布满重复的小花图案，因此选用“Allover pattern”表示满版布局；图案是通过木版印花完成，属于表面印制，选择“Print”；花朵与枝叶反复组合成整体图案，属于多元素组合图案，因此用“Composed Pattern”；具体元素是小花朵，所以使用“Floral pattern”；图案能清晰表现花的形象，属于具象再现，因此选“Representational Pattern”作为图案定义；笔触与线条带有手绘感、略显随意和不规则，因此使用“Hand-drawn Style”来说明其风格。');
INSERT INTO `clothing_pattern_info` VALUES (2119612, 19996458, '花卉图案', '从图片来看，整个方巾表面布满重复的小花图案，因此选用“Allover pattern”表示满版布局；图案是通过木版印花完成，属于表面印制，选择“Print”；花朵与枝叶反复组合成整体图案，属于多元素组合图案，因此用“Composed Pattern”；具体元素是小花朵，所以使用“Floral pattern”；图案能清晰表现花的形象，属于具象再现，因此选“Representational Pattern”作为图案定义；笔触与线条带有手绘感、略显随意和不规则，因此使用“Hand-drawn Style”来说明其风格。');
