INSERT INTO `clothing_pattern_info` VALUES (2119660, 19996506, '花卉图案', '从图片来看，整个方巾表面布满重复的小花图案，因此选用“Allover pattern”表示满版布局；图案是通过木版印花完成，属于表面印制，选择“Print”；花朵与枝叶反复组合成整体图案，属于多元素组合图案，因此用“Composed Pattern”；具体元素是小花朵，所以使用“Floral pattern”；图案能清晰表现花的形象，属于具象再现，因此选“Representational Pattern”作为图案定义；笔触与线条带有手绘感、略显随意和不规则，因此使用“Hand-drawn Style”来说明其风格。');
INSERT INTO `clothing_pattern_info` VALUES (2119601, 19996451, '品牌标识', '帽子主体为单一水洗色，整体接近“Pure Color 纯色”，前片位置有品牌字母LOGO刺绣，属于“Placement Print 定位图案”和“Logo Placement 标志位置图案”，且通过“Embroidery 刺绣”工艺呈现，整体图案构成以单一元素为主，因此选“Single Element Pattern 单一元素图案”。LOGO并不表现具体景物，更偏抽象符号，归为“Abstract Pattern 抽象图案”。水洗旧化效果带来复古气质，因此添加“Vintage Style 复古风格”。');
INSERT INTO `clothing_pattern_info` VALUES (2119602, 19996451, '纯色', '帽子主体为单一水洗色，整体接近“Pure Color 纯色”，前片位置有品牌字母LOGO刺绣，属于“Placement Print 定位图案”和“Logo Placement 标志位置图案”，且通过“Embroidery 刺绣”工艺呈现，整体图案构成以单一元素为主，因此选“Single Element Pattern 单一元素图案”。LOGO并不表现具体景物，更偏抽象符号，归为“Abstract Pattern 抽象图案”。水洗旧化效果带来复古气质，因此添加“Vintage Style 复古风格”。');
