INSERT INTO `clothing_pattern_info` VALUES (2119605, 19996453, '品牌标识', '帽子主体为单一水洗色，整体接近“Pure Color 纯色”，前片位置有品牌字母LOGO刺绣，属于“Placement Print 定位图案”和“Logo Placement 标志位置图案”，且通过“Embroidery 刺绣”工艺呈现，整体图案构成以单一元素为主，因此选“Single Element Pattern 单一元素图案”。LOGO并不表现具体景物，更偏抽象符号，归为“Abstract Pattern 抽象图案”。水洗旧化效果带来复古气质，因此添加“Vintage Style 复古风格”。');
INSERT INTO `clothing_pattern_info` VALUES (2119606, 19996453, '纯色', '帽子主体为单一水洗色，整体接近“Pure Color 纯色”，前片位置有品牌字母LOGO刺绣，属于“Placement Print 定位图案”和“Logo Placement 标志位置图案”，且通过“Embroidery 刺绣”工艺呈现，整体图案构成以单一元素为主，因此选“Single Element Pattern 单一元素图案”。LOGO并不表现具体景物，更偏抽象符号，归为“Abstract Pattern 抽象图案”。水洗旧化效果带来复古气质，因此添加“Vintage Style 复古风格”。');
INSERT INTO `clothing_pattern_info` VALUES (2119607, 19996454, '品牌标识', '帽子主体为单一水洗色，整体接近“Pure Color 纯色”，前片位置有品牌字母LOGO刺绣，属于“Placement Print 定位图案”和“Logo Placement 标志位置图案”，且通过“Embroidery 刺绣”工艺呈现，整体图案构成以单一元素为主，因此选“Single Element Pattern 单一元素图案”。LOGO并不表现具体景物，更偏抽象符号，归为“Abstract Pattern 抽象图案”。水洗旧化效果带来复古气质，因此添加“Vintage Style 复古风格”。');
INSERT INTO `clothing_pattern_info` VALUES (2119608, 19996454, '纯色', '帽子主体为单一水洗色，整体接近“Pure Color 纯色”，前片位置有品牌字母LOGO刺绣，属于“Placement Print 定位图案”和“Logo Placement 标志位置图案”，且通过“Embroidery 刺绣”工艺呈现，整体图案构成以单一元素为主，因此选“Single Element Pattern 单一元素图案”。LOGO并不表现具体景物，更偏抽象符号，归为“Abstract Pattern 抽象图案”。水洗旧化效果带来复古气质，因此添加“Vintage Style 复古风格”。');
INSERT INTO `clothing_pattern_info` VALUES (2119609, 19996455, '纯色', '从图片看主体为单一色调，无明显装饰性图案，因此图案元素归为“Pure Color 纯色”，整体视觉属于“Abstract Pattern 抽象图案定义”和“Minimalist Style 极简风格”。针织面料整体均匀呈现在整件裙身上，属于“Allover pattern 全幅分布”，图案构成可视为面料整体效果的“Composed Pattern 组合图案”。纱线本身的组织呈现的是针织结构图案效果，近似“Jacquard”式整体组织感，而非局部印花或贴饰。');
INSERT INTO `clothing_pattern_info` VALUES (2119610, 19996456, '纯色', '从图片看主体为单一色调，无明显装饰性图案，因此图案元素归为“Pure Color 纯色”，整体视觉属于“Abstract Pattern 抽象图案定义”和“Minimalist Style 极简风格”。针织面料整体均匀呈现在整件裙身上，属于“Allover pattern 全幅分布”，图案构成可视为面料整体效果的“Composed Pattern 组合图案”。纱线本身的组织呈现的是针织结构图案效果，近似“Jacquard”式整体组织感，而非局部印花或贴饰。');
INSERT INTO `clothing_pattern_info` VALUES (2119598, 19996448, '纯色', '包装主色为纯色背景，可归为“Pure Color（纯色）”。表面有抽象树枝/珊瑚状线条装饰，并非具体具象图案，因此整体图案定义更接近“Abstract Pattern（抽象图案）”，无明显满版重复花型，故不再添加其他布局或技法标签。');
INSERT INTO `clothing_pattern_info` VALUES (2119599, 19996449, '纯色', '包装主体为纯色粉红色大面积色块，可归为“Pure Color（纯色）”。正面仅有简单白色线条树枝状图形与文字装饰，没有连续图案或具象花纹，因此在图案定义上更适合作为“Abstract Pattern（抽象图案）”。整体不存在复杂花朵、条纹或格纹之类的具体元素，故仅选这两类标签。');
INSERT INTO `clothing_pattern_info` VALUES (2119600, 19996450, '纯色', '瓶身整体以纯色为主，因此选择“Pure Color（纯色）”。正面印有抽象枝状图案与文字装饰，这类不具具体具象含义的装饰性图形更接近“Abstract Pattern（抽象图案）”。没有连续满版花纹或特定主题场景，因此只选取这两项元素与定义。');
INSERT INTO `clothing_pattern_info` VALUES (2119595, 19996446, '纯色', '包装主体为单一米色粉末，无明显装饰性图案，因此以“Pure Color（纯色）”和“Solid color（纯色）”属性为主导；粉末本身形成自然不规则的视觉效果，可视作无具体形象的“Abstract Pattern（抽象图案）”。未见其他排布方式或具体图案元素。');
INSERT INTO `clothing_pattern_info` VALUES (2119596, 19996447, '纯色', '瓶身主体以单一淡色为主，整体观感接近“Pure Color/纯色”“Solid color/纯色”背景，仅有简约树形logo和文字装饰，无复杂图案构成，整体属于偏抽象概念表达，因此在图案定义上更符合“Abstract Pattern/抽象图案”，整体风格简洁克制，可归为“Minimalist Style/极简风格”。');
INSERT INTO `clothing_pattern_info` VALUES (2119597, 19996447, '纯色', '瓶身主体以单一淡色为主，整体观感接近“Pure Color/纯色”“Solid color/纯色”背景，仅有简约树形logo和文字装饰，无复杂图案构成，整体属于偏抽象概念表达，因此在图案定义上更符合“Abstract Pattern/抽象图案”，整体风格简洁克制，可归为“Minimalist Style/极简风格”。');
INSERT INTO `clothing_pattern_info` VALUES (2119592, 19996444, '纯色', '瓶身为简洁的单色渐变透明设计，无复杂图案，主视觉为纯色玻璃与简单线条树状标志，因此在图案元素上选用“Pure Color”“Solid color”，整体属于抽象图案“Abstract Pattern”，且视觉风格极为干净克制，归为“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119593, 19996444, '纯色', '瓶身为简洁的单色渐变透明设计，无复杂图案，主视觉为纯色玻璃与简单线条树状标志，因此在图案元素上选用“Pure Color”“Solid color”，整体属于抽象图案“Abstract Pattern”，且视觉风格极为干净克制，归为“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119594, 19996445, '其他', '瓶身正面只有一棵抽象树枝图形和品牌文字，图案集中在局部区域，因此选“Placement Print（定位图案）”“Single Element Pattern（单一元素图案）”。图形通过印刷呈现，故用“Print（印花）”。树枝图案不属于花卉、几何等常见枚举，只能归入“Other patterns（其他图案）”，整体为简化处理的线条树枝，更偏“Abstract Pattern（抽象图案）”，视觉上简洁干净，所以选“Minimalist Style（极简风格）”。');
INSERT INTO `clothing_pattern_info` VALUES (2119590, 19996443, '纯色', '从图片看，包装主体为单一浅色底，属“Pure Color/纯色”和“Solid color/纯色”图案元素，仅有简洁的树枝状图形与文字装饰，整体没有复杂场景或具象图案，因此在图案定义上归为“Abstract Pattern/抽象图案”。整体视觉极为简洁克制，没有多余装饰效果，风格可归入“Minimalist Style/极简风格”。');
INSERT INTO `clothing_pattern_info` VALUES (2119591, 19996443, '纯色', '从图片看，包装主体为单一浅色底，属“Pure Color/纯色”和“Solid color/纯色”图案元素，仅有简洁的树枝状图形与文字装饰，整体没有复杂场景或具象图案，因此在图案定义上归为“Abstract Pattern/抽象图案”。整体视觉极为简洁克制，没有多余装饰效果，风格可归入“Minimalist Style/极简风格”。');
INSERT INTO `clothing_pattern_info` VALUES (2119587, 19996441, '其他', '瓶身正面有单一树枝状线条图案和文字，属于局部装饰，因此选择“Placement Print”和“Single Element Pattern”。图案通过印刷方式呈现，使用“Print”。线性树枝图形属于几何/抽象意象，归为“Other patterns”，整体不具象，选择“Abstract Pattern”。整体设计简洁克制，因此用“Minimalist Style”描述风格。');
INSERT INTO `clothing_pattern_info` VALUES (2119588, 19996442, '纯色', '包装整体为单色块设计，没有具体花卉或卡通等具体图案元素，因此选择“Pure Color”和“Solid color”来表示其以纯色为主的视觉效果；整体图形和文字排版较为抽象简洁，没有具象图案，故在图案定义上归为“Abstract Pattern”；整体风格清爽干净，装饰元素极少，所以在风格维度选择“Minimalist Style”体现极简设计感。');
INSERT INTO `clothing_pattern_info` VALUES (2119589, 19996442, '纯色', '包装整体为单色块设计，没有具体花卉或卡通等具体图案元素，因此选择“Pure Color”和“Solid color”来表示其以纯色为主的视觉效果；整体图形和文字排版较为抽象简洁，没有具象图案，故在图案定义上归为“Abstract Pattern”；整体风格清爽干净，装饰元素极少，所以在风格维度选择“Minimalist Style”体现极简设计感。');
INSERT INTO `clothing_pattern_info` VALUES (2119585, 19996440, '纯色', '从图片看，这是一款透明玻璃杯，表面没有任何彩色图案或具象花纹，仅有杯身造型和内侧起伏形成的光影效果，因此在图案元素维度选用“Pure Color（纯色）”和“Solid color（素色）”。由于玻璃折射造成的视觉效果并非具体物体或具象图形，整体可视为“Abstract Pattern（抽象图案）”。未见排布明确的印花或纹样，因此不选择其他图案布局与技法标签。');
INSERT INTO `clothing_pattern_info` VALUES (2119586, 19996440, '纯色', '从图片看，这是一款透明玻璃杯，表面没有任何彩色图案或具象花纹，仅有杯身造型和内侧起伏形成的光影效果，因此在图案元素维度选用“Pure Color（纯色）”和“Solid color（素色）”。由于玻璃折射造成的视觉效果并非具体物体或具象图形，整体可视为“Abstract Pattern（抽象图案）”。未见排布明确的印花或纹样，因此不选择其他图案布局与技法标签。');
INSERT INTO `clothing_pattern_info` VALUES (2119579, 19996436, '纯色', '从图片看产品为单色金属银色，无任何装饰性图案与图形元素，因此在图案元素维度选择“Pure Color/纯色”和“Solid color/纯色款”。整体仅为功能造型，没有具象花纹或图像，故在图案定义上归入“Abstract Pattern/抽象图案”。视觉风格上线条简洁，造型极简，无多余装饰，符合“Minimalist Style/极简风格”的特征。');
INSERT INTO `clothing_pattern_info` VALUES (2119580, 19996436, '纯色', '从图片看产品为单色金属银色，无任何装饰性图案与图形元素，因此在图案元素维度选择“Pure Color/纯色”和“Solid color/纯色款”。整体仅为功能造型，没有具象花纹或图像，故在图案定义上归入“Abstract Pattern/抽象图案”。视觉风格上线条简洁，造型极简，无多余装饰，符合“Minimalist Style/极简风格”的特征。');
INSERT INTO `clothing_pattern_info` VALUES (2119581, 19996437, '纯色', '杯体为透明无色玻璃，没有任何装饰图案或彩色印花，因此在图案元素维度上归为“Pure Color（纯色）”和“Solid color（素色）”。整体外观仅是透明材质与简单造型，没有具象花纹或图像，图案定义上属于“Abstract Pattern（抽象图案）”，风格上呈现干净简洁的“Minimalist Style（极简风格）”。');
INSERT INTO `clothing_pattern_info` VALUES (2119582, 19996437, '纯色', '杯体为透明无色玻璃，没有任何装饰图案或彩色印花，因此在图案元素维度上归为“Pure Color（纯色）”和“Solid color（素色）”。整体外观仅是透明材质与简单造型，没有具象花纹或图像，图案定义上属于“Abstract Pattern（抽象图案）”，风格上呈现干净简洁的“Minimalist Style（极简风格）”。');
INSERT INTO `clothing_pattern_info` VALUES (2119583, 19996438, '纯色', '容器整体为透明无花纹设计，可视为“Pure Color（纯色）”，没有复杂图案，图案定义上更接近“Abstract Pattern（抽象图案）”，风格上呈现极简、干净的外观，因此使用“Minimalist Style（极简风格）”来描述其视觉效果。');
INSERT INTO `clothing_pattern_info` VALUES (2119584, 19996439, '纯色', '杯身整体为透明浅绿色的纯色外观，无任何图案装饰，因此在图案元素上选择“Pure Color（纯色）”，图案定义上属于没有具象图形的“Abstract Pattern（抽象图案）”。整体视觉简洁克制，没有多余装饰，符合“Minimalist Style（极简风格）”的特征。');
INSERT INTO `clothing_pattern_info` VALUES (2119575, 19996434, '纯色', '从图片看，这是一只通体白色的陶瓷榨汁壶，没有任何花纹或装饰色块，属于单一色表面，因此选择图案元素“Pure Color（纯色）”和“Solid color（纯色）”。表面无具象图案，仅是造型本身的视觉效果，所以图案定义上归为“Abstract Pattern（抽象图案）”。整体视觉风格简洁克制，没有多余装饰，符合“Minimalist Style（极简风格）”。');
INSERT INTO `clothing_pattern_info` VALUES (2119576, 19996434, '纯色', '从图片看，这是一只通体白色的陶瓷榨汁壶，没有任何花纹或装饰色块，属于单一色表面，因此选择图案元素“Pure Color（纯色）”和“Solid color（纯色）”。表面无具象图案，仅是造型本身的视觉效果，所以图案定义上归为“Abstract Pattern（抽象图案）”。整体视觉风格简洁克制，没有多余装饰，符合“Minimalist Style（极简风格）”。');
INSERT INTO `clothing_pattern_info` VALUES (2119577, 19996435, '纯色', '从图片看，产品表面为单一金属色，没有任何装饰性图案或花纹，因此在图案元素上归为“Pure Color/纯色”和“Solid color/素色”。整体不存在具象图案或具备特定主题的图案组合，只是纯色表面，所以在图案定义上选择“Abstract Pattern/抽象图案”以表示无具体图像的简单外观。');
INSERT INTO `clothing_pattern_info` VALUES (2119578, 19996435, '纯色', '从图片看，产品表面为单一金属色，没有任何装饰性图案或花纹，因此在图案元素上归为“Pure Color/纯色”和“Solid color/素色”。整体不存在具象图案或具备特定主题的图案组合，只是纯色表面，所以在图案定义上选择“Abstract Pattern/抽象图案”以表示无具体图像的简单外观。');
INSERT INTO `clothing_pattern_info` VALUES (2119569, 19996431, '纯色', '罐身与盖子表面无明显装饰性图案，仅呈透明与金属色等单一色调，因此使用“Pure Color（纯色）”和“Solid color（纯色）”来表示图案元素维度。整体没有具象图形或具代表性图案，仅是简洁的纯色与材质对比，所以在图案定义维度上归为“Abstract Pattern（抽象图案）”。');
INSERT INTO `clothing_pattern_info` VALUES (2119570, 19996431, '纯色', '罐身与盖子表面无明显装饰性图案，仅呈透明与金属色等单一色调，因此使用“Pure Color（纯色）”和“Solid color（纯色）”来表示图案元素维度。整体没有具象图形或具代表性图案，仅是简洁的纯色与材质对比，所以在图案定义维度上归为“Abstract Pattern（抽象图案）”。');
INSERT INTO `clothing_pattern_info` VALUES (2119571, 19996432, '纯色', '杯子整体为素白色，没有额外彩色图案，仅依靠立体造型呈现，因此图案元素上选用“Pure Color”和“Solid color”。浮雕动物形象并非通过平面印花呈现，整体视觉更偏向造型感和形式感，可归入“Abstract Pattern”。风格简洁克制，没有复杂装饰，适合使用“Minimalist Style”来描述其图案风格。');
INSERT INTO `clothing_pattern_info` VALUES (2119572, 19996432, '纯色', '杯子整体为素白色，没有额外彩色图案，仅依靠立体造型呈现，因此图案元素上选用“Pure Color”和“Solid color”。浮雕动物形象并非通过平面印花呈现，整体视觉更偏向造型感和形式感，可归入“Abstract Pattern”。风格简洁克制，没有复杂装饰，适合使用“Minimalist Style”来描述其图案风格。');
INSERT INTO `clothing_pattern_info` VALUES (2119573, 19996433, '纯色', '杯子整体为素白色，没有额外彩色图案，仅依靠立体造型呈现，因此图案元素上选用“Pure Color”和“Solid color”。浮雕动物形象并非通过平面印花呈现，整体视觉更偏向造型感和形式感，可归入“Abstract Pattern”。风格简洁克制，没有复杂装饰，适合使用“Minimalist Style”来描述其图案风格。');
INSERT INTO `clothing_pattern_info` VALUES (2119574, 19996433, '纯色', '杯子整体为素白色，没有额外彩色图案，仅依靠立体造型呈现，因此图案元素上选用“Pure Color”和“Solid color”。浮雕动物形象并非通过平面印花呈现，整体视觉更偏向造型感和形式感，可归入“Abstract Pattern”。风格简洁克制，没有复杂装饰，适合使用“Minimalist Style”来描述其图案风格。');
INSERT INTO `clothing_pattern_info` VALUES (2119567, 19996429, '其他', '封面上只有一个位于中央水平位置的红色花结图案，属于局部位置装饰，所以选择“Placement Print”和“Single Element Pattern”。图案通过印刷方式呈现，因此选“Print”。花结属于符号性装饰元素，不在具体动植物或几何标准分类中，故用“Other patterns”概括。整体图案以象征性为主，没有具体写实对象，因此在定义上更接近“Abstract Pattern”。画面极简、留白丰富，只有一条线和一个结，所以选“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119568, 19996430, '其他', '整体以竹篾反复交错编织形成连续性的网格状效果，覆盖全器身，因此在布局上属于“Allover pattern 全幅图案”。图案来源于编织结构本身而非印花，最接近“Jacquard”这一依靠组织结构形成花纹的类型。从整体观感来看，是由反复的编织纹路构成的整体视觉，因此是“Composed Pattern 组合图案”。具体元素为规则却非典型格纹或条纹，更适合归入“Other patterns 其他图案”。该纹样并不表现具体物象，属于“Abstract Pattern 抽象图案”。风格上线条简洁、没有多余装饰，呈现“Minimalist Style 极简风格”。');
INSERT INTO `clothing_pattern_info` VALUES (2119563, 19996428, '花卉图案', '盘内外布满纹样，因此选择“Allover pattern”。装饰通过彩绘完成，对应“Print”。盘面由多种元素组合，如松竹梅植物、熨斗等物件，属于“Composed Pattern”。可见松、竹、梅等植物，使用“Floral pattern”“Leaves”“Tree”，同时熨斗等器物图案对应“Object pattern”。整体图案具象可辨，归为“Figurative Pattern”。线条与上色带有手绘感，因此选用“Hand-drawn Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119564, 19996428, '叶子', '盘内外布满纹样，因此选择“Allover pattern”。装饰通过彩绘完成，对应“Print”。盘面由多种元素组合，如松竹梅植物、熨斗等物件，属于“Composed Pattern”。可见松、竹、梅等植物，使用“Floral pattern”“Leaves”“Tree”，同时熨斗等器物图案对应“Object pattern”。整体图案具象可辨，归为“Figurative Pattern”。线条与上色带有手绘感，因此选用“Hand-drawn Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119565, 19996428, '树', '盘内外布满纹样，因此选择“Allover pattern”。装饰通过彩绘完成，对应“Print”。盘面由多种元素组合，如松竹梅植物、熨斗等物件，属于“Composed Pattern”。可见松、竹、梅等植物，使用“Floral pattern”“Leaves”“Tree”，同时熨斗等器物图案对应“Object pattern”。整体图案具象可辨，归为“Figurative Pattern”。线条与上色带有手绘感，因此选用“Hand-drawn Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119566, 19996428, '物体', '盘内外布满纹样，因此选择“Allover pattern”。装饰通过彩绘完成，对应“Print”。盘面由多种元素组合，如松竹梅植物、熨斗等物件，属于“Composed Pattern”。可见松、竹、梅等植物，使用“Floral pattern”“Leaves”“Tree”，同时熨斗等器物图案对应“Object pattern”。整体图案具象可辨，归为“Figurative Pattern”。线条与上色带有手绘感，因此选用“Hand-drawn Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119562, 19996427, '其他', '杯身外侧只有一组局部蓝色同心圆团状纹饰，因此在布局上属于局部装饰，选用“Placement Print”，整体是以印绘方式呈现，选用“Print”。纹样元素只有这一组几何化的漩涡图案，故用“Single Element Pattern”。具体图案为同心圆组合，不属于常见花卉、条纹等，归为“Other patterns”。该几何漩涡并不具象描绘具体物体，而是抽象化表达“鸣门漩涡”的意象，所以图案定义选择“Abstract Pattern”。整体线条简洁、配色单一，风格上偏“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119560, 19996426, '纯色', '图片与描述显示该底部保护套为单一沙色，无明显花纹或图案，因此在图案元素上选用“Pure Color（纯色）”和“Solid color（素色）”。整体没有具象图形或具体对象，只是颜色块，属于“Abstract Pattern（抽象图案）”。视觉效果简洁干净，没有复杂装饰，风格上归类为“Minimalist Style（极简风格）”。');
INSERT INTO `clothing_pattern_info` VALUES (2119561, 19996426, '纯色', '图片与描述显示该底部保护套为单一沙色，无明显花纹或图案，因此在图案元素上选用“Pure Color（纯色）”和“Solid color（素色）”。整体没有具象图形或具体对象，只是颜色块，属于“Abstract Pattern（抽象图案）”。视觉效果简洁干净，没有复杂装饰，风格上归类为“Minimalist Style（极简风格）”。');
INSERT INTO `clothing_pattern_info` VALUES (2119557, 19996423, '字母', '短裤主体为纯色，没有整体铺满的花型，只在左裤脚有一处英文信息装饰，因此归类为局部的“Placement Print（局部图案布局）”。文字是通过“Embroidery（刺绣）”工艺呈现，形成单一装饰元素，属于“Single Element Pattern（单一元素图案）”以及具体元素“Letter（文字）”。整体图案直接表达可读信息，因此选为“Representational Pattern（具象图案）”，风格简洁干净，没有复杂装饰，归入“Minimalist Style（极简风格）”。');
INSERT INTO `clothing_pattern_info` VALUES (2119558, 19996424, '字母', '短裤主体为纯色，没有整体铺满的花型，只在左裤脚有一处英文信息装饰，因此归类为局部的“Placement Print（局部图案布局）”。文字是通过“Embroidery（刺绣）”工艺呈现，形成单一装饰元素，属于“Single Element Pattern（单一元素图案）”以及具体元素“Letter（文字）”。整体图案直接表达可读信息，因此选为“Representational Pattern（具象图案）”，风格简洁干净，没有复杂装饰，归入“Minimalist Style（极简风格）”。');
INSERT INTO `clothing_pattern_info` VALUES (2119559, 19996425, '字母', '短裤主体为纯色，没有整体铺满的花型，只在左裤脚有一处英文信息装饰，因此归类为局部的“Placement Print（局部图案布局）”。文字是通过“Embroidery（刺绣）”工艺呈现，形成单一装饰元素，属于“Single Element Pattern（单一元素图案）”以及具体元素“Letter（文字）”。整体图案直接表达可读信息，因此选为“Representational Pattern（具象图案）”，风格简洁干净，没有复杂装饰，归入“Minimalist Style（极简风格）”。');
INSERT INTO `clothing_pattern_info` VALUES (2119554, 19996420, '纯色', '从图片看伞面为单一纯色，没有花朵、条纹、格纹等具体图案元素，因此图案元素选择“Pure Color（纯色）”。整体没有具象形象或可识别物体，属于非具象的简单色面呈现，所以图案定义选为“Abstract Pattern（抽象图案）”。未见其他排布方式、技法或风格特效，故不添加额外图案标签。');
INSERT INTO `clothing_pattern_info` VALUES (2119555, 19996421, '纯色', '从图片看伞面为单一纯色，没有花朵、条纹、格纹等具体图案元素，因此图案元素选择“Pure Color（纯色）”。整体没有具象形象或可识别物体，属于非具象的简单色面呈现，所以图案定义选为“Abstract Pattern（抽象图案）”。未见其他排布方式、技法或风格特效，故不添加额外图案标签。');
INSERT INTO `clothing_pattern_info` VALUES (2119556, 19996422, '纯色', '从图片看伞面为单一纯色，没有花朵、条纹、格纹等具体图案元素，因此图案元素选择“Pure Color（纯色）”。整体没有具象形象或可识别物体，属于非具象的简单色面呈现，所以图案定义选为“Abstract Pattern（抽象图案）”。未见其他排布方式、技法或风格特效，故不添加额外图案标签。');
INSERT INTO `clothing_pattern_info` VALUES (2119549, 19996415, '文字', '瓶身只有品牌 Logo、刻度线等局部文字与标记，因此属于“Placement Print”与“Print”，构成单一元素图案“Single Element Pattern”，核心图案元素为“Text（文字）”。整体没有具象图像，更偏抽象信息表达，归为“Abstract Pattern”，并且视觉极简，符合“Minimalist Style（极简风格）”。');
INSERT INTO `clothing_pattern_info` VALUES (2119550, 19996416, '文字', '瓶身只有品牌 Logo、刻度线等局部文字与标记，因此属于“Placement Print”与“Print”，构成单一元素图案“Single Element Pattern”，核心图案元素为“Text（文字）”。整体没有具象图像，更偏抽象信息表达，归为“Abstract Pattern”，并且视觉极简，符合“Minimalist Style（极简风格）”。');
INSERT INTO `clothing_pattern_info` VALUES (2119551, 19996417, '纯色', '托盘整体为单一金属色，没有明显图案，仅有花瓣和花心的浮雕造型，因此在图案元素上归类为“Pure Color（纯色）”。整体造型依靠形状和凹凸线条表现花朵意象，而非具体印花细节，更偏向几何化与意象化，因此在图案定义上选择“Abstract Pattern（抽象图案）”。');
INSERT INTO `clothing_pattern_info` VALUES (2119552, 19996418, '纯色', '托盘整体为单一金属色，没有明显图案，仅有花瓣和花心的浮雕造型，因此在图案元素上归类为“Pure Color（纯色）”。整体造型依靠形状和凹凸线条表现花朵意象，而非具体印花细节，更偏向几何化与意象化，因此在图案定义上选择“Abstract Pattern（抽象图案）”。');
INSERT INTO `clothing_pattern_info` VALUES (2119553, 19996419, '纯色', '从图片和描述看，茶壶整体为单一色釉覆盖，因此归为“Pure Color/纯色”，属于“Single Element Pattern/单一要素图案”，色釉均匀覆盖整个壶体，可视为“Allover pattern/整体图案”。图案不表现具体物体，因此在定义上更接近“Abstract Pattern/抽象图案”，整体视觉风格简洁统一，可归类为“Minimalist Style/极简风格”。');
INSERT INTO `clothing_pattern_info` VALUES (2119543, 19996412, '字母', '从图片与描述看，裤身主体为纯色，无整体满版图案，仅在左裾有小面积英文信息装饰，因此选择“Placement Print（局部图案布局）”以及图案类型为“Letter（字母）”“Text（文字）”，且只由这一类元素构成，归为“Single Element Pattern（单一元素图案）”。品牌标语采用刺绣方式呈现，所以技术类型为“Embroidery（刺绣）”。整体图案直接表达品牌与标语含义，属于具象信息表达，因此在定义上选择“Representational Pattern（具象图案）”。整体视觉简洁克制，无复杂装饰，风格偏“Minimalist Style（极简风格）”。');
INSERT INTO `clothing_pattern_info` VALUES (2119544, 19996412, '文字', '从图片与描述看，裤身主体为纯色，无整体满版图案，仅在左裾有小面积英文信息装饰，因此选择“Placement Print（局部图案布局）”以及图案类型为“Letter（字母）”“Text（文字）”，且只由这一类元素构成，归为“Single Element Pattern（单一元素图案）”。品牌标语采用刺绣方式呈现，所以技术类型为“Embroidery（刺绣）”。整体图案直接表达品牌与标语含义，属于具象信息表达，因此在定义上选择“Representational Pattern（具象图案）”。整体视觉简洁克制，无复杂装饰，风格偏“Minimalist Style（极简风格）”。');
