INSERT INTO `clothing_pattern_info` VALUES (2119547, 19996414, '字母', '从图片与描述看，裤身主体为纯色，无整体满版图案，仅在左裾有小面积英文信息装饰，因此选择“Placement Print（局部图案布局）”以及图案类型为“Letter（字母）”“Text（文字）”，且只由这一类元素构成，归为“Single Element Pattern（单一元素图案）”。品牌标语采用刺绣方式呈现，所以技术类型为“Embroidery（刺绣）”。整体图案直接表达品牌与标语含义，属于具象信息表达，因此在定义上选择“Representational Pattern（具象图案）”。整体视觉简洁克制，无复杂装饰，风格偏“Minimalist Style（极简风格）”。');
INSERT INTO `clothing_pattern_info` VALUES (2119548, 19996414, '文字', '从图片与描述看，裤身主体为纯色，无整体满版图案，仅在左裾有小面积英文信息装饰，因此选择“Placement Print（局部图案布局）”以及图案类型为“Letter（字母）”“Text（文字）”，且只由这一类元素构成，归为“Single Element Pattern（单一元素图案）”。品牌标语采用刺绣方式呈现，所以技术类型为“Embroidery（刺绣）”。整体图案直接表达品牌与标语含义，属于具象信息表达，因此在定义上选择“Representational Pattern（具象图案）”。整体视觉简洁克制，无复杂装饰，风格偏“Minimalist Style（极简风格）”。');
INSERT INTO `clothing_pattern_info` VALUES (2119535, 19996408, '佩斯利', '从图片可见图案集中分布在衣身两侧和袖子局部，因此使用“Placement Print（定位图案）”；图案是以车线绣出的装饰，工艺为“Embroidery（刺绣）”。多组佩斯利和花纹组合成整体，属于“Composed Pattern（组合图案）”，具体元素为“Paisley（腰果花/佩斯利纹）”。整体图案有明确可识别的装饰性花纹，归为“Representational Pattern（具象图案）”。图案线条感强、类似插画描绘方式，因此选择“Illustration Effect（插画效果）”。');
INSERT INTO `clothing_pattern_info` VALUES (2119536, 19996409, '佩斯利', '从图片可见图案集中分布在衣身两侧和袖子局部，因此使用“Placement Print（定位图案）”；图案是以车线绣出的装饰，工艺为“Embroidery（刺绣）”。多组佩斯利和花纹组合成整体，属于“Composed Pattern（组合图案）”，具体元素为“Paisley（腰果花/佩斯利纹）”。整体图案有明确可识别的装饰性花纹，归为“Representational Pattern（具象图案）”。图案线条感强、类似插画描绘方式，因此选择“Illustration Effect（插画效果）”。');
INSERT INTO `clothing_pattern_info` VALUES (2119537, 19996410, '花卉图案', '从图片可见整件衬衫布满棕榈树、岛屿等图案，因此属于“Allover pattern”且由多种元素组合，选“Composed Pattern”。图案是以印花方式呈现，选择“Print”。元素方面包含“Floral pattern”（棕榈类植物）、“Tree”以及海岛“Landscape”。图案具象可辨，因此在定义上为“Representational Pattern”。整体呈插画式手绘感，故选择“Illustration Effect”。');
INSERT INTO `clothing_pattern_info` VALUES (2119538, 19996410, '树', '从图片可见整件衬衫布满棕榈树、岛屿等图案，因此属于“Allover pattern”且由多种元素组合，选“Composed Pattern”。图案是以印花方式呈现，选择“Print”。元素方面包含“Floral pattern”（棕榈类植物）、“Tree”以及海岛“Landscape”。图案具象可辨，因此在定义上为“Representational Pattern”。整体呈插画式手绘感，故选择“Illustration Effect”。');
INSERT INTO `clothing_pattern_info` VALUES (2119539, 19996410, '风景', '从图片可见整件衬衫布满棕榈树、岛屿等图案，因此属于“Allover pattern”且由多种元素组合，选“Composed Pattern”。图案是以印花方式呈现，选择“Print”。元素方面包含“Floral pattern”（棕榈类植物）、“Tree”以及海岛“Landscape”。图案具象可辨，因此在定义上为“Representational Pattern”。整体呈插画式手绘感，故选择“Illustration Effect”。');
