INSERT INTO `clothing_pattern_info` VALUES (2119542, 19996411, '风景', '从图片可见整件衬衫布满棕榈树、岛屿等图案，因此属于“Allover pattern”且由多种元素组合，选“Composed Pattern”。图案是以印花方式呈现，选择“Print”。元素方面包含“Floral pattern”（棕榈类植物）、“Tree”以及海岛“Landscape”。图案具象可辨，因此在定义上为“Representational Pattern”。整体呈插画式手绘感，故选择“Illustration Effect”。');
INSERT INTO `clothing_pattern_info` VALUES (2119529, 19996405, '纯色', '从图片看伞面为单一半透明色，没有花朵、条纹、格纹等具体图案元素，因此在元素维度选用“Pure Color/纯色”和“Solid color/素色”。整体没有具象图形，只是均匀着色的伞面，所以在图案定义维度归类为“Abstract Pattern/抽象图案”。未体现局部印花或复杂构图，因此不选择其他布局或风格标签。');
INSERT INTO `clothing_pattern_info` VALUES (2119530, 19996405, '纯色', '从图片看伞面为单一半透明色，没有花朵、条纹、格纹等具体图案元素，因此在元素维度选用“Pure Color/纯色”和“Solid color/素色”。整体没有具象图形，只是均匀着色的伞面，所以在图案定义维度归类为“Abstract Pattern/抽象图案”。未体现局部印花或复杂构图，因此不选择其他布局或风格标签。');
