INSERT INTO `clothing_pattern_info` VALUES (2119534, 19996407, '纯色', '从图片看伞面为单一半透明色，没有花朵、条纹、格纹等具体图案元素，因此在元素维度选用“Pure Color/纯色”和“Solid color/素色”。整体没有具象图形，只是均匀着色的伞面，所以在图案定义维度归类为“Abstract Pattern/抽象图案”。未体现局部印花或复杂构图，因此不选择其他布局或风格标签。');
INSERT INTO `clothing_pattern_info` VALUES (2119525, 19996401, '纯色', '从图片可见整件为单一纯色，没有可辨识的图案元素，因此选择“Pure Color”作为图案元素。整体没有具体具象图形或花纹，归为“Abstract Pattern”更贴切。风格上极简、干净，没有多余装饰，所以在图案风格维度选择“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119526, 19996402, '纯色', '从图片可见整件为单一纯色，没有可辨识的图案元素，因此选择“Pure Color”作为图案元素。整体没有具体具象图形或花纹，归为“Abstract Pattern”更贴切。风格上极简、干净，没有多余装饰，所以在图案风格维度选择“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119527, 19996403, '纯色', '从图片可见整件为单一纯色，没有可辨识的图案元素，因此选择“Pure Color”作为图案元素。整体没有具体具象图形或花纹，归为“Abstract Pattern”更贴切。风格上极简、干净，没有多余装饰，所以在图案风格维度选择“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119528, 19996404, '纯色', '从图片可见整件为单一纯色，没有可辨识的图案元素，因此选择“Pure Color”作为图案元素。整体没有具体具象图形或花纹，归为“Abstract Pattern”更贴切。风格上极简、干净，没有多余装饰，所以在图案风格维度选择“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119519, 19996398, '纯色', '从图片看整体为单一色调，无明显花朵、条纹或格纹等具体图案，因此归类为“Pure Color/纯色”和“Solid color/纯色面料”元素。针织结构形成的细微色纱与杢调效果并非具象图案，仅为抽象的视觉肌理，因此在图案定义维度选择“Abstract Pattern/抽象图案”。未见局部位置图案或复杂构图，故不添加其他图案标签。');
INSERT INTO `clothing_pattern_info` VALUES (2119520, 19996398, '纯色', '从图片看整体为单一色调，无明显花朵、条纹或格纹等具体图案，因此归类为“Pure Color/纯色”和“Solid color/纯色面料”元素。针织结构形成的细微色纱与杢调效果并非具象图案，仅为抽象的视觉肌理，因此在图案定义维度选择“Abstract Pattern/抽象图案”。未见局部位置图案或复杂构图，故不添加其他图案标签。');
