INSERT INTO `clothing_pattern_info` VALUES (2119395, 19996297, '纯色', '耳环整体以清透与金属色为主，没有具体具象图案，因此选用“Pure Color/纯色”和“Solid color/纯色”来表示表面图案元素；造型由几何圆形和线条构成，属于非具象的“Abstract Pattern/抽象图案”；整体视觉简洁干净、没有复杂装饰，风格上归为“Minimalist Style/极简风格”。');
