INSERT INTO `clothing_pattern_info` VALUES (2119363, 19996278, '纯色', '从图片看发夹表面为单一金属色，无任何图案或花纹，因此在图案元素上选择“Pure Color/纯色”“Solid color/纯色”。整体造型仅通过波浪线条形成抽象造型，没有具象花卉或动物等元素，属于“Abstract Pattern/抽象图案”，风格简洁利落，没有复杂装饰，归为“Minimalist Style/极简风格”。');
