INSERT INTO `clothing_pattern_info` VALUES (2119365, 19996279, '纯色', '从图片看发夹表面为单一金属色，无任何图案或花纹，因此在图案元素上选择“Pure Color/纯色”“Solid color/纯色”。整体造型仅通过波浪线条形成抽象造型，没有具象花卉或动物等元素，属于“Abstract Pattern/抽象图案”，风格简洁利落，没有复杂装饰，归为“Minimalist Style/极简风格”。');
INSERT INTO `clothing_pattern_info` VALUES (2119366, 19996279, '纯色', '从图片看发夹表面为单一金属色，无任何图案或花纹，因此在图案元素上选择“Pure Color/纯色”“Solid color/纯色”。整体造型仅通过波浪线条形成抽象造型，没有具象花卉或动物等元素，属于“Abstract Pattern/抽象图案”，风格简洁利落，没有复杂装饰，归为“Minimalist Style/极简风格”。');
INSERT INTO `clothing_pattern_info` VALUES (2119358, 19996273, '维希格', '从图片可见整体为细密格纹覆盖，因此选择“Allover pattern”表示全幅铺满式图案；图案由织物结构形成的格子感，适合用“Jacquard”体现结构性格纹效果；整体由重复的小格纹单元构成整体视觉，所以用“Composed Pattern”；格子属于“Gingham”细格纹类别；该格纹为具象可识别的格子图案，因此在定义上选“Representational Pattern”；整体风格干净简洁，没有复杂装饰效果，归为“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119359, 19996274, '维希格', '从图片可见整体为细密格纹覆盖，因此选择“Allover pattern”表示全幅铺满式图案；图案由织物结构形成的格子感，适合用“Jacquard”体现结构性格纹效果；整体由重复的小格纹单元构成整体视觉，所以用“Composed Pattern”；格子属于“Gingham”细格纹类别；该格纹为具象可识别的格子图案，因此在定义上选“Representational Pattern”；整体风格干净简洁，没有复杂装饰效果，归为“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119360, 19996275, '维希格', '从图片可见表面布满规则的细小方格，因此在布局上属于整体覆盖的“Allover pattern”，图案形成方式为印花类，选择“Print”。格纹由重复的多元小方格组成，整体为“Composed Pattern”。具体元素是细密的“Gingham”格子。此类几何格纹属于具象可识别图案，归为“Representational Pattern”。整体风格简洁利落，没有复杂装饰，因此选用“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119361, 19996276, '维希格', '从图片可见表面布满规则的细小方格，因此在布局上属于整体覆盖的“Allover pattern”，图案形成方式为印花类，选择“Print”。格纹由重复的多元小方格组成，整体为“Composed Pattern”。具体元素是细密的“Gingham”格子。此类几何格纹属于具象可识别图案，归为“Representational Pattern”。整体风格简洁利落，没有复杂装饰，因此选用“Minimalist Style”。');
INSERT INTO `clothing_pattern_info` VALUES (2119362, 19996277, '维希格', '从图片可见表面布满规则的细小方格，因此在布局上属于整体覆盖的“Allover pattern”，图案形成方式为印花类，选择“Print”。格纹由重复的多元小方格组成，整体为“Composed Pattern”。具体元素是细密的“Gingham”格子。此类几何格纹属于具象可识别图案，归为“Representational Pattern”。整体风格简洁利落，没有复杂装饰，因此选用“Minimalist Style”。');
