INSERT INTO `clothing_texture_info` VALUES (1952815, 19969263, '皱褶', '官方描述指出面料具有“自然的皱感”和“自然光泽”，且图片表面呈不规则褶皱效果，最贴近的材质肌理标签为“Crinkle（皱感面料）”。', '机织', NULL, NULL, '单元素图案', '抽象图案', NULL);
INSERT INTO `clothing_texture_info` VALUES (1952816, 19969264, '皱褶', '官方描述指出面料具有“自然的皱感”和“自然光泽”，且图片表面呈不规则褶皱效果，最贴近的材质肌理标签为“Crinkle（皱感面料）”。', '机织', NULL, NULL, '单元素图案', '抽象图案', NULL);
INSERT INTO `clothing_texture_info` VALUES (1952817, 19969265, '皱褶', '官方描述指出面料具有“自然的皱感”和“自然光泽”，且图片表面呈不规则褶皱效果，最贴近的材质肌理标签为“Crinkle（皱感面料）”。', '机织', NULL, NULL, '单元素图案', '抽象图案', NULL);
INSERT INTO `clothing_texture_info` VALUES (1952812, 19969260, '平纹', '面料为涤纶机织的防撕裂材质，表面平整、无绒毛与明显立体组织，视觉与手感更接近平纹结构；因此选择“平纹（Plain weave）”。', '机织', '满幅', '印花', '多元素图案', '具象图案', '速写效果');
INSERT INTO `clothing_texture_info` VALUES (1952813, 19969261, '平纹', '面料为涤纶机织的防撕裂材质，表面平整、无绒毛与明显立体组织，视觉与手感更接近平纹结构；因此选择“平纹（Plain weave）”。', '机织', '满幅', '印花', '多元素图案', '具象图案', '速写效果');
INSERT INTO `clothing_texture_info` VALUES (1952814, 19969262, '平纹', '面料为涤纶机织的防撕裂材质，表面平整、无绒毛与明显立体组织，视觉与手感更接近平纹结构；因此选择“平纹（Plain weave）”。', '机织', '满幅', '印花', '多元素图案', '具象图案', '速写效果');
INSERT INTO `clothing_texture_info` VALUES (1952809, 19969257, '皱褶', '面料为尼龙且呈现自然光泽，表面具有明显的自然褶皱与皱感效果，最符合“Crinkle（褶皱肌理）”的特征。', '机织', NULL, NULL, '单元素图案', '抽象图案', NULL);
INSERT INTO `clothing_texture_info` VALUES (1952810, 19969258, '皱褶', '面料为尼龙且呈现自然光泽，表面具有明显的自然褶皱与皱感效果，最符合“Crinkle（褶皱肌理）”的特征。', '机织', NULL, NULL, '单元素图案', '抽象图案', NULL);
INSERT INTO `clothing_texture_info` VALUES (1952811, 19969259, '皱褶', '面料为尼龙且呈现自然光泽，表面具有明显的自然褶皱与皱感效果，最符合“Crinkle（褶皱肌理）”的特征。', '机织', NULL, NULL, '单元素图案', '抽象图案', NULL);
INSERT INTO `clothing_texture_info` VALUES (1957445, 19973900, '刺绣', '包身布面装饰有 3D 花卉刺绣贴饰，表面呈现明显的针脚与立体纹理，最符合“刺绣面料（embroidered fabrics）”的肌理特征。', '机织', '满幅', '刺绣', '单元素图案', '具象图案', NULL);
INSERT INTO `clothing_texture_info` VALUES (1957439, 19973894, '平纹', '外层为尼龙塔丝隆防撕裂机织面料，表面平滑、无绒感与明显立体纹理，符合“平纹（Plain weave）”的视觉与触感特征。', '机织', '独幅', '印花', '单元素图案', '具象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1957440, 19973895, '平纹', '外层为尼龙塔丝隆防撕裂机织面料，表面平滑、无绒感与明显立体纹理，符合“平纹（Plain weave）”的视觉与触感特征。', '机织', '独幅', '印花', '单元素图案', '具象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1957441, 19973896, '平纹', '外层为尼龙塔丝隆防撕裂机织面料，表面平滑、无绒感与明显立体纹理，符合“平纹（Plain weave）”的视觉与触感特征。', '机织', '独幅', '印花', '单元素图案', '具象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1957442, 19973897, '平纹', '外层为尼龙塔丝隆防撕裂机织面料，表面平滑、无绒感与明显立体纹理，符合“平纹（Plain weave）”的视觉与触感特征。', '机织', '独幅', '印花', '单元素图案', '具象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1957438, 19973893, '涂层/轧光面料', '该裤为WUROS 2.5层结构，里侧为聚氨酯涂层实现防水透湿，表面手感平滑、带涂层质感，故选择“Coated/calendered（涂层/压光）”。', '机织', '满幅', NULL, '单元素图案', '抽象图案', NULL);
INSERT INTO `clothing_texture_info` VALUES (1965850, 19982305, '网眼布', '鞋面材料为高通气网眼生地，表面呈现均匀的孔隙结构与透气性特征，最贴近的材质肌理为 Mesh（网眼）。', '机织', '局部图案', '拼贴', '单元素图案', '具象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1957435, 19973890, '压花', '描述中明确为“全体にエンボス加工（全身压纹加工）”，且图面可见立体起伏的花卉压纹效果，最贴切的材质肌理为“压纹（Embossing）”。', '机织', '满幅', '压花', '单元素图案', '具象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1957434, 19973889, '压花', '面料表面以压纹方式形成连续花卉的立体凹凸，具有可见的纹理起伏与微光泽；结合描述中的“全体にエンボス加工”，最贴近的材质肌理为“压纹（Embossing）”。', '机织', '满幅', '压花', '单元素图案', '具象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1957430, 19973885, '平纹', '面料为尼龙防撕裂织物，表面平整、无毛绒与明显立体纹理，典型的平纹组织特征，故选择“Plain weave（平纹）”。', '机织', '独幅', '印花', '单元素图案', '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1957431, 19973886, '平纹', '面料为尼龙防撕裂织物，表面平整、无毛绒与明显立体纹理，典型的平纹组织特征，故选择“Plain weave（平纹）”。', '机织', '独幅', '印花', '单元素图案', '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1957432, 19973887, '平纹', '面料为尼龙防撕裂织物，表面平整、无毛绒与明显立体纹理，典型的平纹组织特征，故选择“Plain weave（平纹）”。', '机织', '独幅', '印花', '单元素图案', '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1957433, 19973888, '涂层/轧光面料', '面料表面具有明显的涂层光泽与平滑感，且成分注明“樹脂コーティング（树脂涂层/加工）”，与防风外套常用的压延涂层工艺相符，因此选择 Coated/calendered（涂层/压延）。', '机织', '满幅', '压花', '单元素图案', '具象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1965849, 19982304, '压花', '面料表面呈现连续的立体花卉纹理，与描述中的“全面压花处理”一致，最贴近的材质肌理标签为“压花（Embossing）”。', '机织', '满幅', '压花', '单元素图案', '具象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1964669, 19981124, '涂层/轧光面料', '面料为WUROS 2.5层结构，内侧为聚氨酯功能层，外观呈现平滑、轻微光泽的防水面感，符合“Coated/calendered（涂层/压光）”的表面特征。', '机织', '独幅', '印花', '单元素图案', '具象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1970102, 19986557, '涂层/轧光面料', '面料为尼龙基布配聚氨酯层压的防水透湿结构，表面平滑且具涂层质感，最贴合“Coated/calendered（涂层/压光）”纹理特征。', '机织', '局部图案，独幅', '印花', '多元素图案', '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1970103, 19986558, '涂层/轧光面料', '面料为尼龙基布配聚氨酯层压的防水透湿结构，表面平滑且具涂层质感，最贴合“Coated/calendered（涂层/压光）”纹理特征。', '机织', '局部图案，独幅', '印花', '多元素图案', '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1975385, 19991841, '涂层/轧光面料', '该面料为Ultra复合材质，表面平滑、略有光泽且手感偏挺，常见为防护型涂层/压延处理，因此选择“Coated/calendered（涂层/压延）”。', '机织', '满幅', NULL, '单元素图案', '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1975382, 19991838, '涂层/轧光面料', '面料为TPE涂层聚酯与尼龙，表面平滑且略有光泽，呈现典型涂层/压延加工效果，因此选择“Coated/calendered”。', '机织', '独幅', '印花', '多元素图案', '具象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1975383, 19991839, '涂层/轧光面料', '面料为TPE涂层聚酯与尼龙，表面平滑且略有光泽，呈现典型涂层/压延加工效果，因此选择“Coated/calendered”。', '机织', '独幅', '印花', '多元素图案', '具象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1975384, 19991840, '涂层/轧光面料', '面料为TPE涂层聚酯与尼龙，表面平滑且略有光泽，呈现典型涂层/压延加工效果，因此选择“Coated/calendered”。', '机织', '独幅', '印花', '多元素图案', '具象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1975381, 19991837, '涂层/轧光面料', '面料为具有光泽感的尼龙，呈现平滑亮面效果，常通过涂层或压光处理获得，故选择“Coated/calendered”作为材质肌理。', '机织', '满幅', NULL, '单元素图案', '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1975380, 19991836, '平纹', '从材质与外观来看为技术性尼龙包布表面，光滑无绒毛、无网孔或立体粒感，最贴近“平纹织（Plain weave）”。', '机织', NULL, NULL, '单元素图案', '抽象图案', NULL);
INSERT INTO `clothing_texture_info` VALUES (1975376, 19991832, '平纹', '包身表面平整细致、无毛圈或立体起伏纹理，呈现典型平纹织物的均匀网格与顺滑手感，因此选择“Plain weave（平纹）”。', '机织', '独幅', '印花', '单元素图案', '具象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1975377, 19991833, '珠地组织', '面料描述为鹿の子编织（即珠地针织），表面呈细密凹凸颗粒结构、透气清爽，最贴近“Piqu”材质肌理。', '纬编', '独幅', '印花', '单元素图案', '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1975378, 19991834, '珠地组织', '面料描述为鹿の子编织（即珠地针织），表面呈细密凹凸颗粒结构、透气清爽，最贴近“Piqu”材质肌理。', '纬编', '独幅', '印花', '单元素图案', '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1975379, 19991835, '珠地组织', '面料描述为鹿の子编织（即珠地针织），表面呈细密凹凸颗粒结构、透气清爽，最贴近“Piqu”材质肌理。', '纬编', '独幅', '印花', '单元素图案', '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1975373, 19991829, '平纹', '面料观感平滑细腻、无绒毛与明显凹凸纹理，符合常见的户外功能长裤所用“平纹（Plain weave）”织物特征，兼具轻薄与耐用。', '机织', '独幅', '印花', '多元素图案', '具象图案', '简约风格');
