INSERT INTO `clothing_texture_info` VALUES (1975364, 19991820, '平纹', '面料描述为双层织的尼龙与聚丙烯混合，外观光滑、无绒毛与明显纹理起伏，符合“平纹（Plain weave）”的常见户外机织面料特征。', '机织', '局部图案', '刺绣', '单元素图案', '抽象图案', '简约风格');
