INSERT INTO `clothing_texture_info` VALUES (1975366, 19991822, '平纹', '面料描述为双层织的尼龙与聚丙烯混合，外观光滑、无绒毛与明显纹理起伏，符合“平纹（Plain weave）”的常见户外机织面料特征。', '机织', '局部图案', '刺绣', '单元素图案', '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1975367, 19991823, '平纹', '面料描述为双层织的尼龙与聚丙烯混合，外观光滑、无绒毛与明显纹理起伏，符合“平纹（Plain weave）”的常见户外机织面料特征。', '机织', '局部图案', '刺绣', '单元素图案', '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1975368, 19991824, '平纹', '面料为尼龙机织壳布，表面平整光滑、无绒毛与开孔结构，整体观感最贴近“Plain weave（平纹）”的肌理特征。', '机织', '满幅', '印花', '多元素图案', '具象图案', '复古风格，插画效果');
INSERT INTO `clothing_texture_info` VALUES (1980369, 19996825, '平纹', '商品为陶瓷马克杯，表面光滑平整且非纺织品，但在可选纹理标签中只有“Plain weave（平纹）”最接近“光滑、无特殊立体肌理”的基础表面效果，因此用“Plain weave”指代这种基础光滑表面。', '机织', NULL, NULL, NULL, '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1980364, 19996820, '平纹', '产品主体为光滑透明的苏打玻璃，表面平整、无绒毛、无特殊凹凸或立体肌理，整体观感类似最基础的平滑表面。在给定选项中与“Plain weave（平纹）”所代表的光滑基础质感最为接近，因此选择“Plain weave”。', '机织', NULL, NULL, NULL, '抽象图案', NULL);
INSERT INTO `clothing_texture_info` VALUES (1980365, 19996821, '平纹', '产品主体为光滑透明的苏打玻璃，表面平整、无绒毛、无特殊凹凸或立体肌理，整体观感类似最基础的平滑表面。在给定选项中与“Plain weave（平纹）”所代表的光滑基础质感最为接近，因此选择“Plain weave”。', '机织', NULL, NULL, NULL, '抽象图案', NULL);
INSERT INTO `clothing_texture_info` VALUES (1980366, 19996822, '平纹', '商品为光滑釉面的陶瓷花盆，表面平整、无绒毛和立体织纹，整体呈现均匀细腻的普通平滑质感，在既有选项中与“Plain weave（平纹）”所代表的基础、平整表面效果最为接近，因此选择“Plain weave”。', '机织', NULL, NULL, NULL, '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1980367, 19996823, '平纹', '商品为光滑釉面的陶瓷花盆，表面平整、无绒毛和立体织纹，整体呈现均匀细腻的普通平滑质感，在既有选项中与“Plain weave（平纹）”所代表的基础、平整表面效果最为接近，因此选择“Plain weave”。', '机织', NULL, NULL, NULL, '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1980368, 19996824, '平纹', '从包装中露出的砂糖本身为颗粒状，但其外侧透明塑料包装呈现平滑、无立体绒毛或凸纹的表面效果，类似常见平纹塑料/薄膜的视觉质感，在给定选项中与“Plain weave（平纹）”的平整、均匀表观最为接近，因此选择“Plain weave”。', '机织', NULL, NULL, NULL, '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1980343, 19996799, '毛圈', '从图片可见表面为一圈圈竖起的短圈绒并非平织结构，触感蓬松、立体感强，这类结构典型属于“Loop-Pile Fabrics（圈绒织物）”。产品描述中的“ふわふわ素材”也说明其具有毛圈绒的柔软质感，因此选择“Loop-Pile Fabrics”。', '机织', '满幅', '提花', '多元素图案', '具象图案', '卡通/动漫风格');
INSERT INTO `clothing_texture_info` VALUES (1980344, 19996800, '毛圈', '从图片可见表面为一圈圈竖起的短圈绒并非平织结构，触感蓬松、立体感强，这类结构典型属于“Loop-Pile Fabrics（圈绒织物）”。产品描述中的“ふわふわ素材”也说明其具有毛圈绒的柔软质感，因此选择“Loop-Pile Fabrics”。', '机织', '满幅', '提花', '多元素图案', '具象图案', '卡通/动漫风格');
INSERT INTO `clothing_texture_info` VALUES (1980342, 19996798, '网眼布', '商品说明中明确为「メッシュ素材のポーチ」，且从图片可见布面为可见孔隙的网状结构，符合“Mesh（网眼织物）”的特征：结构疏松、可透视、表面为规则网孔，因此选择材质肌理为 Mesh。', '机织', '满幅', '提花', '多元素图案', '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1980340, 19996796, '摇粒绒', '产品为羊毛毡材质，表面呈现细短绒毛感和轻微绒面模糊边缘，视觉上接近“Fleece（抓绒）”的绒面效果，因此选用“Fleece”来概括这种柔软、有绒感的羊毛毡表面质感。', '机织', NULL, NULL, '单元素图案', '抽象图案', NULL);
INSERT INTO `clothing_texture_info` VALUES (1980341, 19996797, '平纹', '该产品为苏打玻璃制成的光滑硬质表面，没有绒毛、颗粒或特殊压纹效果，整体视觉与一般光滑平整的织物最接近“Plain weave（平纹）”的简洁光滑感，因此用“Plain weave”来类比其无明显肌理、平整顺滑的表面特征。', '机织', NULL, NULL, NULL, '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1980339, 19996795, '水洗牛仔布', '商品为牛仔夹克，说明中提到约10盎司的丹宁面料，图片中可见典型牛仔布的经纬色差与略显柔软的穿着效果，表面有轻微洗水的自然褪色感，整体最贴近“Washed denim（水洗牛仔）”这一材质肌理标签。', '机织', '满幅', '提花', '多元素图案', '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1980338, 19996794, '亮片', '从图片和描述看，表面为高密度亮片装饰，属于在面料上缝制/固定片状亮面装饰物的典型“Sequins”肌理，表面反光强烈且有颗粒感，与普通机织或针织底布手感和视觉效果明显不同，因此选择“Sequins”最为贴切。', '机织', NULL, NULL, '单元素图案', '抽象图案', '插画效果');
INSERT INTO `clothing_texture_info` VALUES (1980336, 19996792, '亚麻/苎麻布', '成分标明“麻（亜麻）リネン100%”，且照片中可见典型亚麻织物的不规则细纹与干爽质感，因此材质肌理选择“Linen”，突出其亚麻纤维特有的清爽、微硬挺和天然纹理特征。', '机织', '满幅', '提花', '多元素图案', '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1980337, 19996793, '亚麻/苎麻布', '成分标明“麻（亜麻）リネン100%”，且照片中可见典型亚麻织物的不规则细纹与干爽质感，因此材质肌理选择“Linen”，突出其亚麻纤维特有的清爽、微硬挺和天然纹理特征。', '机织', '满幅', '提花', '多元素图案', '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1980334, 19996790, '蕾丝', '商品说明中特别提到“レースとメッシュ素材がパッチワーク”，并且局部可见带花纹的镂空面料，整体手感与视觉以蕾丝感为主要特色，因此在材质肌理中选择“Lace”最为贴切。', '纬编', '满幅', '蕾丝', '多元素图案', '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1980335, 19996791, '蕾丝', '商品说明中特别提到“レースとメッシュ素材がパッチワーク”，并且局部可见带花纹的镂空面料，整体手感与视觉以蕾丝感为主要特色，因此在材质肌理中选择“Lace”最为贴切。', '纬编', '满幅', '蕾丝', '多元素图案', '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1980331, 19996787, '平纹', '描述为“綿ナイロンブロークン生地”，属于机织平纹类变体，表面清爽平整、无绒毛和凹凸结构，图片中也呈现光滑简洁的普通机织效果，因此在统一标签中选择最接近的“Plain weave（平纹）”。', '机织', NULL, NULL, NULL, '抽象图案', NULL);
INSERT INTO `clothing_texture_info` VALUES (1980332, 19996788, '平纹', '描述为“綿ナイロンブロークン生地”，属于机织平纹类变体，表面清爽平整、无绒毛和凹凸结构，图片中也呈现光滑简洁的普通机织效果，因此在统一标签中选择最接近的“Plain weave（平纹）”。', '机织', NULL, NULL, NULL, '抽象图案', NULL);
INSERT INTO `clothing_texture_info` VALUES (1980333, 19996789, '平纹', '描述为“綿ナイロンブロークン生地”，属于机织平纹类变体，表面清爽平整、无绒毛和凹凸结构，图片中也呈现光滑简洁的普通机织效果，因此在统一标签中选择最接近的“Plain weave（平纹）”。', '机织', NULL, NULL, NULL, '抽象图案', NULL);
INSERT INTO `clothing_texture_info` VALUES (1980328, 19996784, '钉珠', '主材为玻璃珠和涤纶线，通过一颗颗珠子串联形成明显的立体颗粒表面，整体视觉与触感特征都属于“Beading”类型的珠饰肌理，因此选择“Beading”作为材质肌理标签。', '机织', '满幅', '钉珠', '多元素图案', '抽象图案', '手绘风');
INSERT INTO `clothing_texture_info` VALUES (1980329, 19996785, '钉珠', '主材为玻璃珠和涤纶线，通过一颗颗珠子串联形成明显的立体颗粒表面，整体视觉与触感特征都属于“Beading”类型的珠饰肌理，因此选择“Beading”作为材质肌理标签。', '机织', '满幅', '钉珠', '多元素图案', '抽象图案', '手绘风');
INSERT INTO `clothing_texture_info` VALUES (1980330, 19996786, '钉珠', '主材为玻璃珠和涤纶线，通过一颗颗珠子串联形成明显的立体颗粒表面，整体视觉与触感特征都属于“Beading”类型的珠饰肌理，因此选择“Beading”作为材质肌理标签。', '机织', '满幅', '钉珠', '多元素图案', '抽象图案', '手绘风');
INSERT INTO `clothing_texture_info` VALUES (1980326, 19996782, '蕾丝', '商品说明中明确提到“同色のレースを組み合わせました”“袖口にも贅沢にレースを施し”，且图片中领口、袖口可以看到镂空花形的蕾丝结构，表面以装饰性花边为主，最贴合的材质肌理标签为“Lace（蕾丝）”。', '纬编', '满幅', '蕾丝', '多元素图案', '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1980327, 19996783, '蕾丝', '商品说明中明确提到“同色のレースを組み合わせました”“袖口にも贅沢にレースを施し”，且图片中领口、袖口可以看到镂空花形的蕾丝结构，表面以装饰性花边为主，最贴合的材质肌理标签为“Lace（蕾丝）”。', '纬编', '满幅', '蕾丝', '多元素图案', '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1980321, 19996777, '蕾丝', '商品成分注明有“レース部分:綿100%”，图片中下摆是透明感较强、带有花型镂空结构的面料，表面是花样图案与底网结构结合，典型属于“Lace（蕾丝）”质感，因此选择“Lace”作为材质肌理标签。', '机织', '独幅', '刺绣', '多元素图案', '具象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1980322, 19996778, '蕾丝', '商品成分注明有“レース部分:綿100%”，图片中下摆是透明感较强、带有花型镂空结构的面料，表面是花样图案与底网结构结合，典型属于“Lace（蕾丝）”质感，因此选择“Lace”作为材质肌理标签。', '机织', '独幅', '刺绣', '多元素图案', '具象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1980323, 19996779, '蕾丝', '商品成分注明有“レース部分:綿100%”，图片中下摆是透明感较强、带有花型镂空结构的面料，表面是花样图案与底网结构结合，典型属于“Lace（蕾丝）”质感，因此选择“Lace”作为材质肌理标签。', '机织', '独幅', '刺绣', '多元素图案', '具象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1980324, 19996780, '平纹', '面料说明为“ドライタッチでハリのある綿混の素材”，从图片也看不出绒毛、光泽或特殊立体肌理，呈现的是普通机织平整表面，因此选择“Plain weave（平纹）”作为最贴切的材质肌理标签。', '机织', NULL, NULL, NULL, '抽象图案', NULL);
INSERT INTO `clothing_texture_info` VALUES (1980325, 19996781, '平纹', '面料说明为“ドライタッチでハリのある綿混の素材”，从图片也看不出绒毛、光泽或特殊立体肌理，呈现的是普通机织平整表面，因此选择“Plain weave（平纹）”作为最贴切的材质肌理标签。', '机织', NULL, NULL, NULL, '抽象图案', NULL);
INSERT INTO `clothing_texture_info` VALUES (1980318, 19996774, '蕾丝', '下摆区域明显为镂空花型组织，并非单纯印花，而是具有通透孔洞、花形结构的“Lace（蕾丝）”，表面层次感强且轻薄，符合蕾丝面料特征，因此整体主导肌理选择“Lace”。', '机织', '满幅', '刺绣', '多元素图案', '具象图案', '手绘风');
INSERT INTO `clothing_texture_info` VALUES (1980319, 19996775, '蕾丝', '下摆区域明显为镂空花型组织，并非单纯印花，而是具有通透孔洞、花形结构的“Lace（蕾丝）”，表面层次感强且轻薄，符合蕾丝面料特征，因此整体主导肌理选择“Lace”。', '机织', '满幅', '刺绣', '多元素图案', '具象图案', '手绘风');
INSERT INTO `clothing_texture_info` VALUES (1980320, 19996776, '蕾丝', '下摆区域明显为镂空花型组织，并非单纯印花，而是具有通透孔洞、花形结构的“Lace（蕾丝）”，表面层次感强且轻薄，符合蕾丝面料特征，因此整体主导肌理选择“Lace”。', '机织', '满幅', '刺绣', '多元素图案', '具象图案', '手绘风');
INSERT INTO `clothing_texture_info` VALUES (1980313, 19996769, '提花', '文案说明采用“刺繍生地、ジャガード生地、レース生地”等多种棉质布料拼接，其中提花面料表面具有凹凸组织感和花纹结构，再结合图片中明显的立体织花效果，整体最具代表性的肌理为“Jacquard（提花）”。因此选择 Jacquard 作为主要材质肌理标签。', '机织', '满幅', '刺绣，提花，蕾丝', '多元素图案', '具象图案', '手绘风');
INSERT INTO `clothing_texture_info` VALUES (1980314, 19996770, '提花', '文案说明采用“刺繍生地、ジャガード生地、レース生地”等多种棉质布料拼接，其中提花面料表面具有凹凸组织感和花纹结构，再结合图片中明显的立体织花效果，整体最具代表性的肌理为“Jacquard（提花）”。因此选择 Jacquard 作为主要材质肌理标签。', '机织', '满幅', '刺绣，提花，蕾丝', '多元素图案', '具象图案', '手绘风');
INSERT INTO `clothing_texture_info` VALUES (1980315, 19996771, '蕾丝', '前身采用网眼蕾丝叠加，表面可以看到细密镂空和花样纹理，具有典型的“Lace（蕾丝）”肌理特征，蕾丝部分是最主要、最显著的表面材质效果，因此选择“Lace”作为唯一材质肌理标签。', '纬编', NULL, NULL, NULL, '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1980316, 19996772, '蕾丝', '前身采用网眼蕾丝叠加，表面可以看到细密镂空和花样纹理，具有典型的“Lace（蕾丝）”肌理特征，蕾丝部分是最主要、最显著的表面材质效果，因此选择“Lace”作为唯一材质肌理标签。', '纬编', NULL, NULL, NULL, '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1980317, 19996773, '蕾丝', '前身采用网眼蕾丝叠加，表面可以看到细密镂空和花样纹理，具有典型的“Lace（蕾丝）”肌理特征，蕾丝部分是最主要、最显著的表面材质效果，因此选择“Lace”作为唯一材质肌理标签。', '纬编', NULL, NULL, NULL, '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1980312, 19996768, '平纹', '产品梳体与背板为ABS等硬质材料，表面光滑平整，没有绒毛、颗粒、皱褶或提花等明显肌理特征，最接近服装织物中“Plain weave（平纹组织）”所代表的光洁、简单、无明显立体纹理的表面效果，因此选择“Plain weave”。', '机织', NULL, NULL, NULL, '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1980309, 19996765, '平纹', '商品面料以再生纤维、黏胶、涤纶和麻混纺为主，视觉上表面平整细腻、无绒毛、无明显凹凸或光泽变化，也未见特殊起皱或颗粒感，符合普通机织平纹布的特征，因此选择“Plain weave（平纹）”作为主要材质肌理描述。', '机织', '满幅', '提花', '多元素图案', '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1980310, 19996766, '平纹', '商品面料以再生纤维、黏胶、涤纶和麻混纺为主，视觉上表面平整细腻、无绒毛、无明显凹凸或光泽变化，也未见特殊起皱或颗粒感，符合普通机织平纹布的特征，因此选择“Plain weave（平纹）”作为主要材质肌理描述。', '机织', '满幅', '提花', '多元素图案', '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1980307, 19996763, '水洗牛仔布', '商品为牛仔面料的哈报帽，表面呈典型牛仔布的经纬纹理和略硬挺手感，无绒毛、镂空或明显光泽效果，最贴近“Washed denim（水洗牛仔）”这一肌理标签。', '机织', NULL, NULL, NULL, '抽象图案', NULL);
INSERT INTO `clothing_texture_info` VALUES (1980308, 19996764, '水洗牛仔布', '商品为牛仔面料的哈报帽，表面呈典型牛仔布的经纬纹理和略硬挺手感，无绒毛、镂空或明显光泽效果，最贴近“Washed denim（水洗牛仔）”这一肌理标签。', '机织', NULL, NULL, NULL, '抽象图案', NULL);
INSERT INTO `clothing_texture_info` VALUES (1980305, 19996761, '平纹', '商品为天竺针织T恤，表面细腻平滑、无绒毛与特殊肌理效果，整体视觉接近常规平整面料。在既有选项中，与普通顺滑、无明显纹路的针织/梭织外观最接近的是“Plain weave（平纹）”，故选“Plain weave”。', '纬编', '满幅', '印花', '多元素图案', '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1980306, 19996762, '平纹', '商品为天竺针织T恤，表面细腻平滑、无绒毛与特殊肌理效果，整体视觉接近常规平整面料。在既有选项中，与普通顺滑、无明显纹路的针织/梭织外观最接近的是“Plain weave（平纹）”，故选“Plain weave”。', '纬编', '满幅', '印花', '多元素图案', '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1980299, 19996755, '平纹', '商品为高针密的细腻针织POLO，描述中强调“目面の綺麗なハイゲージニット生地”，从视觉上表面平整、无绒毛、无凹凸肌理或特殊立体组织，整体呈现光滑均匀的基础纹理效果，在给定选项中与“Plain weave（平纹外观）”所代表的平滑细致表观最接近，因此选择“Plain weave”。', '纬编', NULL, '刺绣', '多元素图案', '具象图案', '手绘风');
INSERT INTO `clothing_texture_info` VALUES (1980300, 19996756, '平纹', '商品为高针密的细腻针织POLO，描述中强调“目面の綺麗なハイゲージニット生地”，从视觉上表面平整、无绒毛、无凹凸肌理或特殊立体组织，整体呈现光滑均匀的基础纹理效果，在给定选项中与“Plain weave（平纹外观）”所代表的平滑细致表观最接近，因此选择“Plain weave”。', '纬编', NULL, '刺绣', '多元素图案', '具象图案', '手绘风');
INSERT INTO `clothing_texture_info` VALUES (1980301, 19996757, '平纹', '从图片可见包体面料表面平整细腻，没有毛绒、绒感或立体颗粒，也不具备缎面高光或灯芯绒条纹等特征，说明是普通机织布的外观。成分为聚酯纤维，常用于制作手袋的基础平纹布，因此选择“Plain weave（平纹织物）”最为贴切。', '机织', '满幅', '提花', '多元素图案', '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1980302, 19996758, '蕾丝', '商品说明明确为“コードレース”，图片中也能看到整体为通体花型镂空结构，具有典型的蕾丝立体花纹与凹凸感，因此材质肌理选择“Lace（蕾丝）”，对应精细花纹、镂空感和柔软垂坠的表面特征。', '机织', '满幅', '蕾丝', '多元素图案', '具象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1980303, 19996759, '蕾丝', '商品说明明确为“コードレース”，图片中也能看到整体为通体花型镂空结构，具有典型的蕾丝立体花纹与凹凸感，因此材质肌理选择“Lace（蕾丝）”，对应精细花纹、镂空感和柔软垂坠的表面特征。', '机织', '满幅', '蕾丝', '多元素图案', '具象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1980304, 19996760, '蕾丝', '商品说明明确为“コードレース”，图片中也能看到整体为通体花型镂空结构，具有典型的蕾丝立体花纹与凹凸感，因此材质肌理选择“Lace（蕾丝）”，对应精细花纹、镂空感和柔软垂坠的表面特征。', '机织', '满幅', '蕾丝', '多元素图案', '具象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1980297, 19996753, '平纹', '商品说明为棉与人造纤维混纺的弹力针织上衣，表面光滑细腻、无绒毛、无凹凸立体肌理或提花效果，视觉上接近一般平整织物效果；在给定选项中最接近的是“Plain weave（平纹织物）”，用以概括这种细腻、均匀、无明显纹路的基础组织外观。', '纬编', NULL, NULL, NULL, '抽象图案', NULL);
INSERT INTO `clothing_texture_info` VALUES (1980298, 19996754, '平纹', '商品说明为棉与人造纤维混纺的弹力针织上衣，表面光滑细腻、无绒毛、无凹凸立体肌理或提花效果，视觉上接近一般平整织物效果；在给定选项中最接近的是“Plain weave（平纹织物）”，用以概括这种细腻、均匀、无明显纹路的基础组织外观。', '纬编', NULL, NULL, NULL, '抽象图案', NULL);
INSERT INTO `clothing_texture_info` VALUES (1980290, 19996746, '水洗牛仔布', '商品说明中明确为100%棉的牛仔面料，图片可见整体水洗与做旧效果，表面具有典型牛仔织纹和经水洗后的略微粗糙感与色差，因此在统一枚举中选择最贴切的“Washed denim（水洗牛仔）”作为材质肌理标签。', '机织', '满幅', '印花', '多元素图案', '抽象图案', '复古风格');
INSERT INTO `clothing_texture_info` VALUES (1980291, 19996747, '水洗牛仔布', '商品说明中明确为100%棉的牛仔面料，图片可见整体水洗与做旧效果，表面具有典型牛仔织纹和经水洗后的略微粗糙感与色差，因此在统一枚举中选择最贴切的“Washed denim（水洗牛仔）”作为材质肌理标签。', '机织', '满幅', '印花', '多元素图案', '抽象图案', '复古风格');
INSERT INTO `clothing_texture_info` VALUES (1980292, 19996748, '水洗牛仔布', '商品说明中明确为100%棉的牛仔面料，图片可见整体水洗与做旧效果，表面具有典型牛仔织纹和经水洗后的略微粗糙感与色差，因此在统一枚举中选择最贴切的“Washed denim（水洗牛仔）”作为材质肌理标签。', '机织', '满幅', '印花', '多元素图案', '抽象图案', '复古风格');
INSERT INTO `clothing_texture_info` VALUES (1980293, 19996749, '水洗牛仔布', '商品说明中明确为100%棉的牛仔面料，图片可见整体水洗与做旧效果，表面具有典型牛仔织纹和经水洗后的略微粗糙感与色差，因此在统一枚举中选择最贴切的“Washed denim（水洗牛仔）”作为材质肌理标签。', '机织', '满幅', '印花', '多元素图案', '抽象图案', '复古风格');
INSERT INTO `clothing_texture_info` VALUES (1980294, 19996750, '平纹', '成分以聚酯、尼龙、粘胶、羊毛及少量氨纶混纺，呈现轻薄顺滑、无绒毛和无明显立体纹路的日常梭织裤装质感，视觉上表面较为平整细腻，未见斜纹、罗纹或绒感，因此归类为最基础的「Plain weave 平纹织物」肌理。', '机织', '满幅', '印花', '多元素图案', '抽象图案', '插画效果');
INSERT INTO `clothing_texture_info` VALUES (1980295, 19996751, '平纹', '成分以聚酯、尼龙、粘胶、羊毛及少量氨纶混纺，呈现轻薄顺滑、无绒毛和无明显立体纹路的日常梭织裤装质感，视觉上表面较为平整细腻，未见斜纹、罗纹或绒感，因此归类为最基础的「Plain weave 平纹织物」肌理。', '机织', '满幅', '印花', '多元素图案', '抽象图案', '插画效果');
INSERT INTO `clothing_texture_info` VALUES (1980296, 19996752, '提花', '商品说明中明确写到“一面为ジャガード生地”，属于通过组织结构形成纹样的提花面料，表面有立体纹理感，因此材质肌理最符合“Jacquard（提花织物）”这一标签。另一面为光滑PVC，但整体视觉与卖点以提花面料为主。', '机织', '独幅', NULL, '多元素图案', '具象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1980284, 19996740, '平纹', '从面料成分（聚酯、尼龙、粘胶、毛、聚氨酯混纺）以及视觉效果来看，裙面平整顺滑、无绒毛、无明显斜纹或粗节、也没有褶皱、镂空等立体肌理，最符合基础的“Plain weave（平纹织物）”特征。此类平纹面料常用于轻薄、有一定垂感且带少量弹性的时装裙装。', '机织', NULL, NULL, NULL, '抽象图案', NULL);
INSERT INTO `clothing_texture_info` VALUES (1980285, 19996741, '平纹', '从面料成分（聚酯、尼龙、粘胶、毛、聚氨酯混纺）以及视觉效果来看，裙面平整顺滑、无绒毛、无明显斜纹或粗节、也没有褶皱、镂空等立体肌理，最符合基础的“Plain weave（平纹织物）”特征。此类平纹面料常用于轻薄、有一定垂感且带少量弹性的时装裙装。', '机织', NULL, NULL, NULL, '抽象图案', NULL);
INSERT INTO `clothing_texture_info` VALUES (1980286, 19996742, '提花', '商品明确为“ジャガードプリーツスカート”，主体和别布中有提花结构，表面具有提花组织起伏与纹理感，因此在肌理上最契合“Jacquard”这一纹理标签。', '机织', '满幅', '提花', '多元素图案', '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1980287, 19996743, '提花', '商品明确为“ジャガードプリーツスカート”，主体和别布中有提花结构，表面具有提花组织起伏与纹理感，因此在肌理上最契合“Jacquard”这一纹理标签。', '机织', '满幅', '提花', '多元素图案', '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1980288, 19996744, '提花', '商品明确为“ジャガードプリーツスカート”，主体和别布中有提花结构，表面具有提花组织起伏与纹理感，因此在肌理上最契合“Jacquard”这一纹理标签。', '机织', '满幅', '提花', '多元素图案', '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1980289, 19996745, '平纹', '成分主要为棉、涤纶、人造纤维等常规梭织面料，表面视觉上较为平整、无绒毛、无明显纹路或凹凸结构，也没有灯芯绒、牛仔、绗缝等强烈肌理特征，因此归为基础的“Plain weave（平纹织物）”最为合理。', '机织', NULL, NULL, NULL, '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1980282, 19996738, '斜纹', '描述中提到“ツイル（斜纹）素材”，表明表面具有斜纹纹路特征，因此在材质肌理上选用“Twill Weave（斜纹组织）”最为贴切，体现细斜纹线条的织纹感。', '机织', NULL, NULL, '单元素图案', '抽象图案', NULL);
INSERT INTO `clothing_texture_info` VALUES (1980283, 19996739, '斜纹', '描述中提到“ツイル（斜纹）素材”，表明表面具有斜纹纹路特征，因此在材质肌理上选用“Twill Weave（斜纹组织）”最为贴切，体现细斜纹线条的织纹感。', '机织', NULL, NULL, '单元素图案', '抽象图案', NULL);
INSERT INTO `clothing_texture_info` VALUES (1980276, 19996732, '棱条肌理', '商品说明中提到“リブ素材”，且图片清晰可见布面为规则纵向凹凸纹理，体现典型罗纹针织表面特征，因此选择“Ribbed Texture（罗纹肌理）”作为唯一材质肌理标签。罗纹结构使面料具有弹性和立体条沟感，符合这一纹理类型。', '纬编', '满幅', '提花', '多元素图案', '抽象图案', '简约风格');
