INSERT INTO `clothing_texture_info` VALUES (1980255, 19996711, '平纹', '商品为高密度针织西装外套，表面平整细腻、无绒毛与立体凹凸结构，视觉效果类似平滑的机织正装面料。在统一纹理标签中，与这种平整、细腻、无明显纹理起伏的表面最接近的是“Plain weave（平纹）”，因此选择“Plain weave”来概括其光滑、均匀的面料表观。', '纬编', NULL, NULL, NULL, '抽象图案', '简约风格');
