INSERT INTO `clothing_texture_info` VALUES (1980246, 19996702, '棱条肌理', '从描述“リブニット（罗纹针织）”以及图片上纵向清晰的沟槽纹理可以判断，主体面料是罗纹结构针织，表面呈现一凹一凸的条状纹理，因此材质肌理选择“Ribbed Texture（罗纹肌理）”最为贴切。', '纬编', '独幅', '刺绣', '单元素图案', '具象图案', '手绘风');
INSERT INTO `clothing_texture_info` VALUES (1980235, 19996691, '平纹', '材质为100%棉的常规T恤针织面料，表面平整、无绒毛、无明显肌理效果，与“Plain weave（平纹织物）”的视觉特征最接近，因此选择“Plain weave”。', '纬编', '满幅', '印花', '多元素图案', '具象图案', '简约风格');
