INSERT INTO `clothing_texture_info` VALUES (1980234, 19996690, '平纹', '商品说明提到“シャリ感のある素材”“軽やかでドライな肌触り”，结合照片可见面料较薄、无绒毛、无明显颗粒或高光效果，呈普通平整布面，最符合机织基础“Plain weave 平纹织物”的视觉与触感特征，因此选择“Plain weave”。', '机织', '满幅', '印花', '多元素图案', '具象图案', NULL);
INSERT INTO `clothing_texture_info` VALUES (1980233, 19996689, '平纹', '从图片与成分来看为聚酯机织面料，表面平整、无绒毛与明显立体肌理，仅有轻微自然垂感和微光泽，最接近普通平纹机织结构，因此选择“Plain weave（平纹）”作为主要材质肌理标签。', '机织', '满幅', '印花', '多元素图案', '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1980227, 19996683, '平纹', '商品说明为100%棉的日常衬衫面料，视觉上也呈现典型的衬衫布细致平整、无明显绒毛和立体组织效果，符合常见的棉质平纹机织衬衫布特征，因此选择“Plain weave（平纹组织）”作为材质肌理标签。', '机织', '满幅', '刺绣，印花', '多元素图案', '具象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1980228, 19996684, '平纹', '从描述看为耐用的尼龙户外功能帽，照片中表面较为平整、细密，没有绒毛、凹凸纹路或光泽感如缎面，符合普通尼龙平纹机织布的特征，因此选择“Plain weave”作为材质肌理标签。', '机织', '满幅', '印花', '多元素图案', '抽象图案', '插画效果');
INSERT INTO `clothing_texture_info` VALUES (1980229, 19996685, '平纹', '从描述看为耐用的尼龙户外功能帽，照片中表面较为平整、细密，没有绒毛、凹凸纹路或光泽感如缎面，符合普通尼龙平纹机织布的特征，因此选择“Plain weave”作为材质肌理标签。', '机织', '满幅', '印花', '多元素图案', '抽象图案', '插画效果');
INSERT INTO `clothing_texture_info` VALUES (1980230, 19996686, '平纹', '从描述看为耐用的尼龙户外功能帽，照片中表面较为平整、细密，没有绒毛、凹凸纹路或光泽感如缎面，符合普通尼龙平纹机织布的特征，因此选择“Plain weave”作为材质肌理标签。', '机织', '满幅', '印花', '多元素图案', '抽象图案', '插画效果');
INSERT INTO `clothing_texture_info` VALUES (1980231, 19996687, '平纹', '从图片与说明看，为常规轻薄衬衫面料，表面平整光洁、无绒毛与明显肌理，也未体现缎光、牛仔或雪纺等特殊组织，最符合普通平纹机织衬衫布特征，因此选择“Plain weave（平纹）”。', '机织', '满幅', NULL, '多元素图案', '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1980232, 19996688, '平纹', '商品名称中有“ツイル（斜纹）”字样，说明采用斜纹织法的亚麻布，表面平整略有纹理但无绒毛、无开孔等立体组织特征。在统一纹理枚举中没有单独“斜纹”选项，最接近的是一般机织表面的“Plain weave（平纹织物）”，用来概括这种相对光洁、无特殊立体效果的机织亚麻斜纹面料。', '机织', NULL, NULL, NULL, '抽象图案', NULL);
INSERT INTO `clothing_texture_info` VALUES (1980220, 19996676, '平纹', '商品说明为「コットン天竺生地」，天竺针织通常表面较为平滑、细腻，视觉效果接近普通平纹结构的简洁平整质感，在给定选项中与「Plain weave」描述的光滑、无明显纹理的基础织物外观最为接近，因此选择「Plain weave」。', '纬编', NULL, NULL, '单元素图案', '抽象图案', NULL);
INSERT INTO `clothing_texture_info` VALUES (1980221, 19996677, '平纹', '成分为100%棉，且为T恤类针织面料，表面平整、无绒毛、无明显凹凸肌理或光泽效果，也不是罗纹或卫衣那种厚组织，最接近基础平纹组织的手感与外观，因此在给定选项中选择“Plain weave/平纹”作为最合适的材质肌理标签。', '纬编', NULL, NULL, NULL, '抽象图案', NULL);
INSERT INTO `clothing_texture_info` VALUES (1980222, 19996678, '平纹', '成分为100%棉，且为T恤类针织面料，表面平整、无绒毛、无明显凹凸肌理或光泽效果，也不是罗纹或卫衣那种厚组织，最接近基础平纹组织的手感与外观，因此在给定选项中选择“Plain weave/平纹”作为最合适的材质肌理标签。', '纬编', NULL, NULL, NULL, '抽象图案', NULL);
INSERT INTO `clothing_texture_info` VALUES (1980223, 19996679, '平纹', '成分为100%棉，且为T恤类针织面料，表面平整、无绒毛、无明显凹凸肌理或光泽效果，也不是罗纹或卫衣那种厚组织，最接近基础平纹组织的手感与外观，因此在给定选项中选择“Plain weave/平纹”作为最合适的材质肌理标签。', '纬编', NULL, NULL, NULL, '抽象图案', NULL);
INSERT INTO `clothing_texture_info` VALUES (1980224, 19996680, '刺绣', '面料主体为平滑的棉织物，但视觉重点是大面积立体花朵刺绣，能看到线迹与凸起的纹理，因此整体肌理以“embroidered fabrics（刺绣面料）”最为贴切，突出花形刺绣带来的立体表面感。', '机织', '独幅', '刺绣', '多元素图案', '具象图案', '手绘风');
INSERT INTO `clothing_texture_info` VALUES (1980225, 19996681, '平纹', '从成分“棉82%＋尼龙18%”以及T恤这一品类判断，多为普通平纹针织或机织表面，视觉上也看不到绒毛、光泽或凹凸纹理，表现为平整细腻的表面效果，因此在统一的纹理标签中选择与之最接近的“Plain weave（平纹表面）”。', '纬编', NULL, NULL, NULL, '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1980226, 19996682, '平纹', '从成分“棉82%＋尼龙18%”以及T恤这一品类判断，多为普通平纹针织或机织表面，视觉上也看不到绒毛、光泽或凹凸纹理，表现为平整细腻的表面效果，因此在统一的纹理标签中选择与之最接近的“Plain weave（平纹表面）”。', '纬编', NULL, NULL, NULL, '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1980214, 19996670, '平纹', '商品材质为100%尼龙，表面平滑、无绒感、无立体纹路或针织罗纹效果，视觉上类似常见的机织平纹尼龙布，因此在材质肌理上选择“Plain weave（平纹织物）”最为贴切。', '机织', NULL, NULL, NULL, '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1980215, 19996671, '平纹', '商品材质为100%尼龙，表面平滑、无绒感、无立体纹路或针织罗纹效果，视觉上类似常见的机织平纹尼龙布，因此在材质肌理上选择“Plain weave（平纹织物）”最为贴切。', '机织', NULL, NULL, NULL, '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1980216, 19996672, '平纹', '商品说明指出采用“NYLON TWILL（尼龙斜纹）”和210D尼龙，属于常规机织化纤面料，表面平整细腻、无绒毛和立体凹凸纹理，外观接近平滑机织布的质感。在给定选项中，与这种常规尼龙包布最接近的是“Plain weave（平纹织物）”，因此选择该纹理标签。', '机织', NULL, NULL, NULL, '抽象图案', NULL);
INSERT INTO `clothing_texture_info` VALUES (1980217, 19996673, '提花', '商品说明提到“4種類の異なった番手の糸を撚った特殊な生地”“モール糸のストライプが混じっていて”以及实物图中条纹带有立体感与组织变化，说明是通过组织结构与不同纱线形成的肌理花型，与“提花组织”特征相符，因此选用“Jacquard”作为主要材质肌理标签。', '机织', '满幅', '提花', '多元素图案', '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1980218, 19996674, '提花', '商品说明提到“4種類の異なった番手の糸を撚った特殊な生地”“モール糸のストライプが混じっていて”以及实物图中条纹带有立体感与组织变化，说明是通过组织结构与不同纱线形成的肌理花型，与“提花组织”特征相符，因此选用“Jacquard”作为主要材质肌理标签。', '机织', '满幅', '提花', '多元素图案', '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1980219, 19996675, '提花', '商品说明提到“4種類の異なった番手の糸を撚った特殊な生地”“モール糸のストライプが混じっていて”以及实物图中条纹带有立体感与组织变化，说明是通过组织结构与不同纱线形成的肌理花型，与“提花组织”特征相符，因此选用“Jacquard”作为主要材质肌理标签。', '机织', '满幅', '提花', '多元素图案', '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1980213, 19996669, '平纹', '从商品说明“綿100%”及图片可见，这是普通棉质帽体，表面平整、无绒毛、无光泽感，也没有立体纹路或特殊后整理效果，符合常见的平纹机织布特征，因此选择“Plain weave（平纹织物）”。', '机织', '独幅', '刺绣', '单元素图案', '具象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1980206, 19996662, '平纹', '商品说明为100%棉T恤，从图片看表面平整无绒感、无明显纹路效果，属于常见的平纹针织T恤外观，在给定选项中与「Plain weave（平纹织物）」最为接近，故选择「Plain weave」。', '纬编', '独幅', '印花', '单元素图案', '具象图案', '卡通/动漫风格');
INSERT INTO `clothing_texture_info` VALUES (1980207, 19996663, '平纹', '商品说明为全棉T恤和吊带上衣，属于常规平整的棉质面料，表面无绒毛、无明显立体肌理或光泽效果，视觉上偏向顺滑细腻的基础针织/机织外观。在给定选项中最接近的是“Plain weave（平纹织物）”，用来概括这种表面平整、纹理细密的基础面料。', '纬编', '满幅', '印花', '多元素图案', '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1980208, 19996664, '平纹', '商品说明为全棉T恤和吊带上衣，属于常规平整的棉质面料，表面无绒毛、无明显立体肌理或光泽效果，视觉上偏向顺滑细腻的基础针织/机织外观。在给定选项中最接近的是“Plain weave（平纹织物）”，用来概括这种表面平整、纹理细密的基础面料。', '纬编', '满幅', '印花', '多元素图案', '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1980209, 19996665, '平纹', '从图片和描述看，此款为常规棉质针织T恤，但在给定选项中没有“针织”相关肌理标签，只能在机织向中择近似。表面平整、无绒毛、无明显纹格或立体结构，也没有光泽感或特殊组织变化，因此选择最接近基础平滑表面的「Plain weave」来代表这种普通棉布般的平滑肌理。', '纬编', '独幅', '印花', '单元素图案', '具象图案', '复古风格');
