INSERT INTO `clothing_texture_info` VALUES (1980202, 19996658, '平纹', '产品为100%尼龙的户外休闲短裤，表面平整、无绒感、无明显凹凸肌理或光泽特殊处理，符合常见尼龙平纹织物的特征，因此选择“Plain weave（平纹）”作为主要材质肌理类型。', '机织', '独幅', NULL, NULL, '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1980203, 19996659, '平纹', '产品为100%尼龙的户外休闲短裤，表面平整、无绒感、无明显凹凸肌理或光泽特殊处理，符合常见尼龙平纹织物的特征，因此选择“Plain weave（平纹）”作为主要材质肌理类型。', '机织', '独幅', NULL, NULL, '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1980204, 19996660, '平纹', '产品为100%尼龙的户外休闲短裤，表面平整、无绒感、无明显凹凸肌理或光泽特殊处理，符合常见尼龙平纹织物的特征，因此选择“Plain weave（平纹）”作为主要材质肌理类型。', '机织', '独幅', NULL, NULL, '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1980205, 19996661, '平纹', '成分为100%棉且为T恤针织单品，表面视觉上平滑细腻、无绒毛与明显立体组织，属于最常见的基础单面针织平纹结构，对应的肌理特点是“Plain weave（平纹）”这一类简洁、平整的表观效果。', '纬编', '独幅', '印花', '单元素图案', '具象图案', '插画效果，卡通/动漫风格');
INSERT INTO `clothing_texture_info` VALUES (1980199, 19996655, '蕾丝', '商品说明中提到“レースを織り込んだクラフト感のある素材”，实物也呈现明显镂空花片结构和细致花纹，符合“Lace（蕾丝）”面料的特征，因此将材质肌理归类为“Lace”。', '纬编', NULL, NULL, '单元素图案', '抽象图案', NULL);
INSERT INTO `clothing_texture_info` VALUES (1980200, 19996656, '蕾丝', '商品说明中提到“レースを織り込んだクラフト感のある素材”，实物也呈现明显镂空花片结构和细致花纹，符合“Lace（蕾丝）”面料的特征，因此将材质肌理归类为“Lace”。', '纬编', NULL, NULL, '单元素图案', '抽象图案', NULL);
INSERT INTO `clothing_texture_info` VALUES (1980201, 19996657, '蕾丝', '商品说明中提到“レースを織り込んだクラフト感のある素材”，实物也呈现明显镂空花片结构和细致花纹，符合“Lace（蕾丝）”面料的特征，因此将材质肌理归类为“Lace”。', '纬编', NULL, NULL, '单元素图案', '抽象图案', NULL);
INSERT INTO `clothing_texture_info` VALUES (1980197, 19996653, '亚麻/苎麻布', '面料成分为再生纤维（纤维素）与亚麻混纺，视觉上呈现典型亚麻织物的干爽、略微粗节与自然皱感，因此在材质肌理上最接近“Linen（亚麻肌理）”，既体现其透气干爽又保留天然纤维质感。', '机织', NULL, NULL, NULL, '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1980198, 19996654, '亚麻/苎麻布', '面料成分为再生纤维（纤维素）与亚麻混纺，视觉上呈现典型亚麻织物的干爽、略微粗节与自然皱感，因此在材质肌理上最接近“Linen（亚麻肌理）”，既体现其透气干爽又保留天然纤维质感。', '机织', NULL, NULL, NULL, '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1980194, 19996650, '平纹', '主布为细番手亚麻天竺针织，表面平滑、无绒毛与立体组织效果，视觉上接近平整简单的织物肌理。在给定选项中，与一般平整布面最接近的是“Plain weave（平纹织物）”，因此选用该标签来代表其简洁、无明显纹路的表观特点。', '纬编', NULL, NULL, NULL, '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1980195, 19996651, '平纹', '主布为细番手亚麻天竺针织，表面平滑、无绒毛与立体组织效果，视觉上接近平整简单的织物肌理。在给定选项中，与一般平整布面最接近的是“Plain weave（平纹织物）”，因此选用该标签来代表其简洁、无明显纹路的表观特点。', '纬编', NULL, NULL, NULL, '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1980196, 19996652, '平纹', '从材质成分为棉混纺针织卫衣面料判断，表面相对平滑、无绒毛、无明显凹凸组织效果和特殊后整理，最贴近基础的“Plain weave”质感标签，用来表示普通平整的卫衣表面肌理。', '纬编', '独幅', '印花', '单元素图案', '具象图案', '插画效果');
INSERT INTO `clothing_texture_info` VALUES (1980189, 19996645, '平纹', '商品为涤纶与棉混纺的轻薄衬衫面料，表面平整、无绒毛、无明显凹凸组织或褶皱效果，也不是针织罗纹或绒面材质，符合常见机织衬衫布的平纹组织特征，因此选择“Plain weave（平纹织物）”。', '机织', '满幅', '印花', '多元素图案', '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1980190, 19996646, '平纹', '商品为100%棉夏季上衣，从图片可见表面平整光洁、无明显绒毛、凹凸或光泽变化，结合其作为常规梭织衬衫类面料的定位，最符合典型的“Plain weave（平纹织物）”质感。', '机织', '满幅', '印花', '多元素图案', '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1980191, 19996647, '平纹', '商品为100%棉夏季上衣，从图片可见表面平整光洁、无明显绒毛、凹凸或光泽变化，结合其作为常规梭织衬衫类面料的定位，最符合典型的“Plain weave（平纹织物）”质感。', '机织', '满幅', '印花', '多元素图案', '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1980192, 19996648, '平纹', '商品说明强调“轻やかなシアー素材”“程よい艶感と滑らかな肌さわり”，实物图呈现为薄而微透、表面平整无绒毛和特别立体肌理的面料，结合成分为人造纤维混纺，典型为轻薄平纹机织布，因此选用“Plain weave”作为材质肌理标签。', '机织', '满幅', '印花', '多元素图案', '具象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1980193, 19996649, '平纹', '商品说明强调“轻やかなシアー素材”“程よい艶感と滑らかな肌さわり”，实物图呈现为薄而微透、表面平整无绒毛和特别立体肌理的面料，结合成分为人造纤维混纺，典型为轻薄平纹机织布，因此选用“Plain weave”作为材质肌理标签。', '机织', '满幅', '印花', '多元素图案', '具象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1980186, 19996642, '平纹', '面料为棉、再生纤维与少量涤纶、亚麻的轻薄夏季衬衫布，表面平整、无绒毛、无明显立体肌理或光泽，视觉上类似常见平纹衬衫布，因此在材质肌理上选择“Plain weave（平纹）”。', '机织', '满幅', '提花', '多元素图案', '具象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1980187, 19996643, '平纹', '面料为棉、再生纤维与少量涤纶、亚麻的轻薄夏季衬衫布，表面平整、无绒毛、无明显立体肌理或光泽，视觉上类似常见平纹衬衫布，因此在材质肌理上选择“Plain weave（平纹）”。', '机织', '满幅', '提花', '多元素图案', '具象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1980188, 19996644, '平纹', '面料为棉、再生纤维与少量涤纶、亚麻的轻薄夏季衬衫布，表面平整、无绒毛、无明显立体肌理或光泽，视觉上类似常见平纹衬衫布，因此在材质肌理上选择“Plain weave（平纹）”。', '机织', '满幅', '提花', '多元素图案', '具象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1980185, 19996641, '平纹', '商品为T恤上身拼接布帛下摆：下摆部分明显是机织布且表面平整无绒、无纹路感，呈现典型的“平纹机织”质感，整体手感偏清爽干净，因此在统一纹理标签中选择“Plain weave（平纹织物）”最为贴切。', '机织', NULL, NULL, NULL, '抽象图案', NULL);
INSERT INTO `clothing_texture_info` VALUES (1980183, 19996639, '平纹', '商品为100%人造纤维衬衫，描述强调柔软垂坠且表面平整光滑，图片中也未见明显绒感、筋纹或立体组织效果，最符合常见衬衫类面料的“Plain weave（平纹组织）”肌理特征，因此选择“Plain weave”作为材质肌理标签。', '机织', '满幅', '印花', '多元素图案', '具象图案', '卡通/动漫风格');
INSERT INTO `clothing_texture_info` VALUES (1980184, 19996640, '平纹', '商品为100%人造纤维衬衫，描述强调柔软垂坠且表面平整光滑，图片中也未见明显绒感、筋纹或立体组织效果，最符合常见衬衫类面料的“Plain weave（平纹组织）”肌理特征，因此选择“Plain weave”作为材质肌理标签。', '机织', '满幅', '印花', '多元素图案', '具象图案', '卡通/动漫风格');
INSERT INTO `clothing_texture_info` VALUES (1980181, 19996637, '天鹅绒', '商品说明明确为“ベロア素材”，且表面具有柔和光泽与细腻触感，这类短绒、光泽感强的面料在英文归类为“Velvet（丝绒/天鹅绒）”最为合适。因此选择纹理标签“Velvet”，以体现其短绒蓬松、柔软且带有光泽的表面特征。', '纬编', NULL, NULL, NULL, '抽象图案', NULL);
INSERT INTO `clothing_texture_info` VALUES (1980182, 19996638, '天鹅绒', '商品说明明确为“ベロア素材”，且表面具有柔和光泽与细腻触感，这类短绒、光泽感强的面料在英文归类为“Velvet（丝绒/天鹅绒）”最为合适。因此选择纹理标签“Velvet”，以体现其短绒蓬松、柔软且带有光泽的表面特征。', '纬编', NULL, NULL, NULL, '抽象图案', NULL);
INSERT INTO `clothing_texture_info` VALUES (1980179, 19996635, '网眼布', '说明中提到外层使用“チュール素材”，即轻薄网纱，且图片中可以看到透明、有网孔感的外罩层，因此材质肌理以“Mesh（网眼/网纱）”最为贴切。本体T恤为常规针织棉，但视觉主特征是外罩网纱层，所以选择“Mesh”作为主要材质肌理。', '纬编', '独幅', '印花', '单元素图案', '具象图案', '插画效果');
INSERT INTO `clothing_texture_info` VALUES (1980180, 19996636, '网眼布', '说明中提到外层使用“チュール素材”，即轻薄网纱，且图片中可以看到透明、有网孔感的外罩层，因此材质肌理以“Mesh（网眼/网纱）”最为贴切。本体T恤为常规针织棉，但视觉主特征是外罩网纱层，所以选择“Mesh”作为主要材质肌理。', '纬编', '独幅', '印花', '单元素图案', '具象图案', '插画效果');
INSERT INTO `clothing_texture_info` VALUES (1980176, 19996632, '雪纺', '从商品描述“シアー”以及图片中轻薄、略微透肤、垂感柔软的特征可判断为薄而轻盈的平纹织物，视觉效果与“Chiffon（雪纺）”最接近，因此选择“Chiffon”作为主要材质肌理标签。', '机织', '满幅', '印花', '多元素图案', '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1980177, 19996633, '平纹', '商品说明为100%棉的轻盈夏季衬衫布，实物照片表面平整、无绒感、无明显斜纹或凹凸肌理，符合普通平纹机织衬衫布特征，因此选择“Plain weave（平纹织物）”作为主要材质肌理。', '机织', NULL, NULL, NULL, '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1980178, 19996634, '平纹', '商品说明为100%棉的轻盈夏季衬衫布，实物照片表面平整、无绒感、无明显斜纹或凹凸肌理，符合普通平纹机织衬衫布特征，因此选择“Plain weave（平纹织物）”作为主要材质肌理。', '机织', NULL, NULL, NULL, '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1980175, 19996631, '平纹', '从成分“綿100%”及T恤的常规工艺推断为普通针织汗布，表面平滑无绒毛、无明显凹凸肌理或光泽效果，也未见罗纹或绗缝等特殊结构，因此在现有纹理标签中与“Plain weave（平纹）”最为接近，用于表示表面平整、纹理感弱的基础结构。', '纬编', '独幅', '印花', '单元素图案', '具象图案', '复古风格');
INSERT INTO `clothing_texture_info` VALUES (1980173, 19996629, '蕾丝', '商品描述中直接说明是“2種類の表情の異なるレース”拼接的卷裙，图片也清晰可见大面积镂空花型结构，因此材质肌理以“Lace（蕾丝）”最为贴切。蕾丝具有透视感和立体花纹的特点，符合该单一主导肌理。', '机织', '满幅', '蕾丝', '多元素图案', '具象图案', '复古风格');
INSERT INTO `clothing_texture_info` VALUES (1980174, 19996630, '蕾丝', '商品描述中直接说明是“2種類の表情の異なるレース”拼接的卷裙，图片也清晰可见大面积镂空花型结构，因此材质肌理以“Lace（蕾丝）”最为贴切。蕾丝具有透视感和立体花纹的特点，符合该单一主导肌理。', '机织', '满幅', '蕾丝', '多元素图案', '具象图案', '复古风格');
INSERT INTO `clothing_texture_info` VALUES (1980171, 19996627, '提花', '文中强调“かぎ編みのような丁寧な透かし編み”，实物图可以看到通过针织结构形成的规则镂空与起伏纹路，这类通过组织变化形成花纹和孔洞的表面效果，最接近“Jacquard（提花）”肌理，因此选择“Jacquard”作为主要材质肌理。', '纬编', '满幅', '提花', '多元素图案', '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1980172, 19996628, '提花', '文中强调“かぎ編みのような丁寧な透かし編み”，实物图可以看到通过针织结构形成的规则镂空与起伏纹路，这类通过组织变化形成花纹和孔洞的表面效果，最接近“Jacquard（提花）”肌理，因此选择“Jacquard”作为主要材质肌理。', '纬编', '满幅', '提花', '多元素图案', '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1980169, 19996625, '平纹', '商品说明写明使用尼龙オックス（尼龙牛津），属于典型的平纹机织结构，表面较为平整、无绒毛与立体纹路，整体质感接近「Plain weave」，且从图片看裙面光洁、有轻微挺括感，与平纹机织尼龙外观一致，因此选择「Plain weave」。', '机织', '满幅', '印花，扎染', '多元素图案', '抽象图案', NULL);
INSERT INTO `clothing_texture_info` VALUES (1980170, 19996626, '提花', '从描述中的「カギ編み」「クラフト感」「総柄デザイン」以及图片中清晰可见的立体花块结构判断，该裙子由多色线在结构上交织形成花型和块面，并非单纯印花，表面有明显的组织变化和花纹起伏，最接近“Jacquard（提花）”这一纹理类型，体现结构性花纹的肌理感。', '纬编', '满幅', '提花', '多元素图案', '具象图案', '复古风格');
INSERT INTO `clothing_texture_info` VALUES (1980168, 19996624, '平纹', '鞋面材质说明为“キャンバス（帆布）”，帆布通常为平纹结构表面，纹理细密、较为挺括，没有绒毛或立体花型等特殊肌理，因此在统一枚举中选择“Plain weave（平纹织物）”最为符合该鞋面的材质特征。', '机织', NULL, NULL, NULL, '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1980166, 19996622, '斜纹', '商品名与说明中明确标注为“ツイル（斜纹）サロペット”，且图片中裤身表面有细致的斜向纹路，是典型的“斜纹组织”外观，因此选择“Twill Weave（斜纹组织）”作为主要材质肌理标签。斜纹组织具有清晰斜向纹理，符合这条亚麻斜纹连体裤的表面特征。', '机织', '满幅', '提花', '多元素图案', '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1980167, 19996623, '平纹', '从图片与描述看，鞋面为天然皮革搭配部分合成材料与纺织衬里，但可见表面较为平整、无明显绒毛或颗粒感，接近“Plain weave（平纹）”这类光滑平整的普通织物/面层效果，因此选择“Plain weave”。', '机织', NULL, NULL, NULL, '具象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1980165, 19996621, '平纹', '鞋面主体为天然皮革和简洁的织物结构，表面相对平整细腻，没有绒毛、绗缝或立体颗粒效果，整体视觉接近常规平纹材质，因此在肌理上选择“Plain weave（平纹）”作为最接近的标签。', '机织', NULL, NULL, NULL, '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1980163, 19996619, '平纹', '产品主体为合金金属与仿珍珠，不是传统纺织面料。从视觉呈现上看金属表面光滑、无绒毛与立体织纹，最接近平滑的“Plain weave（平纹织物）”质感标签，因此用“Plain weave”来代表其光洁、均匀的表面效果。', '机织', NULL, NULL, NULL, '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1980164, 19996620, '平纹', '产品主体为合金金属与仿珍珠，不是传统纺织面料。从视觉呈现上看金属表面光滑、无绒毛与立体织纹，最接近平滑的“Plain weave（平纹织物）”质感标签，因此用“Plain weave”来代表其光洁、均匀的表面效果。', '机织', NULL, NULL, NULL, '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1980161, 19996617, '金属涂层', '耳饰表面呈现金属质感与光泽，材质为合金和黄铜，具有光滑反光效果，最符合“Metallic coating（金属光泽/涂层）”这一肌理特征。', '机织', NULL, NULL, NULL, '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1980162, 19996618, '金属涂层', '耳饰表面呈现金属质感与光泽，材质为合金和黄铜，具有光滑反光效果，最符合“Metallic coating（金属光泽/涂层）”这一肌理特征。', '机织', NULL, NULL, NULL, '抽象图案', '简约风格');
