INSERT INTO `clothing_texture_info` VALUES (1980149, 19996605, '绉纹', '描述中提到面料具有“ふんわりと優しい手触りと凹凸感”，并通过整体抽褶形成明显褶皱与颗粒感表面，整体观感带有细致的皱褶凹凸效果，最接近带微皱颗粒感的“Crepe（绉纹）”肌理，因此选择“Crepe”。', '机织', '满幅', '印花', '多元素图案', '具象图案', '复古风格');
INSERT INTO `clothing_texture_info` VALUES (1980150, 19996606, '绉纹', '描述中提到面料具有“ふんわりと優しい手触りと凹凸感”，并通过整体抽褶形成明显褶皱与颗粒感表面，整体观感带有细致的皱褶凹凸效果，最接近带微皱颗粒感的“Crepe（绉纹）”肌理，因此选择“Crepe”。', '机织', '满幅', '印花', '多元素图案', '具象图案', '复古风格');
INSERT INTO `clothing_texture_info` VALUES (1980146, 19996602, '平纹', '围巾表面看起来较为平整、细腻，无绒毛、无立体纹路，属于常见的光滑机织冷感面料视觉效果，因此在给定选项中最接近的是“Plain weave（平纹组织）”。', '机织', '满幅', '印花', '多元素图案', '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1980147, 19996603, '平纹', '围巾表面看起来较为平整、细腻，无绒毛、无立体纹路，属于常见的光滑机织冷感面料视觉效果，因此在给定选项中最接近的是“Plain weave（平纹组织）”。', '机织', '满幅', '印花', '多元素图案', '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1980148, 19996604, '平纹', '从图片和材质描述看，金属刀刃和仿木纹树脂手柄表面平整光滑，没有绒毛、起伏或复杂立体效果，最接近普通平纹致密光滑表面，因此选择“Plain weave”来代表这种平滑硬质表面效果。', '机织', NULL, NULL, NULL, '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1980142, 19996598, '平纹', '从图片可见为常规针织袜面，表面较为细腻平整，没有绒毛、起伏纹理或网孔结构，属于普通平整织物外观。在给定选项中，“Plain weave”最接近这种平滑、无特殊肌理效果的基础质感，因此选择 Plain weave。', '纬编', '满幅', '扎染', '多元素图案', '抽象图案', '手绘风');
