INSERT INTO `clothing_texture_info` VALUES (1980135, 19996591, '棱条肌理', '从图片可见袜筒部分有明显纵向罗纹结构，表面呈一条条凸起的纹路，典型属于“Ribbed Texture（罗纹肌理）”。这种罗纹针织不仅增加弹性与包覆感，也形成肉眼可见的立体条状表面效果，因此选择“Ribbed Texture”。', '纬编', '满幅', '提花', '单元素图案', '具象图案', '简约风格');
