INSERT INTO `clothing_texture_info` VALUES (1980134, 19996590, '平纹', '成分为棉与聚酯混纺，视觉上表面平整、无绒毛、无立体纹路，也没有明显光泽和垂坠感，整体呈现普通机织布的质感，与“Plain weave（平纹组织）”相符。', '机织', NULL, NULL, NULL, '抽象图案', NULL);
INSERT INTO `clothing_texture_info` VALUES (1980129, 19996585, '结子布', '文中提到“麻のような雰囲気”“ざっくりとしたドビー組織”，图中表面呈现略粗犷不规则的纱节感和干爽触感，整体有仿麻、轻微粗节纱效果，因此在给定选项中最接近“Slub fabrics（粗节纱面料）”。该纹理强调不规则纱节和略微粗糙的表面，符合本品仿麻质感的特征。', '机织', '满幅', '提花', NULL, '抽象图案', NULL);
INSERT INTO `clothing_texture_info` VALUES (1980130, 19996586, '结子布', '文中提到“麻のような雰囲気”“ざっくりとしたドビー組織”，图中表面呈现略粗犷不规则的纱节感和干爽触感，整体有仿麻、轻微粗节纱效果，因此在给定选项中最接近“Slub fabrics（粗节纱面料）”。该纹理强调不规则纱节和略微粗糙的表面，符合本品仿麻质感的特征。', '机织', '满幅', '提花', NULL, '抽象图案', NULL);
