INSERT INTO `clothing_texture_info` VALUES (1980133, 19996589, '结子布', '文中提到“麻のような雰囲気”“ざっくりとしたドビー組織”，图中表面呈现略粗犷不规则的纱节感和干爽触感，整体有仿麻、轻微粗节纱效果，因此在给定选项中最接近“Slub fabrics（粗节纱面料）”。该纹理强调不规则纱节和略微粗糙的表面，符合本品仿麻质感的特征。', '机织', '满幅', '提花', NULL, '抽象图案', NULL);
INSERT INTO `clothing_texture_info` VALUES (1980127, 19996583, '麂皮绒', '面料说明为“マイクロタッチの起毛感”“フェイクスウェード”，即微细纤维仿麂皮，表面细腻起毛、触感类似麂皮，因此选择“Microfiber Suede（微纤维麂皮）”作为主要材质肌理标签。', '机织', NULL, NULL, '单元素图案', '抽象图案', NULL);
INSERT INTO `clothing_texture_info` VALUES (1980128, 19996584, '麂皮绒', '面料说明为“マイクロタッチの起毛感”“フェイクスウェード”，即微细纤维仿麂皮，表面细腻起毛、触感类似麂皮，因此选择“Microfiber Suede（微纤维麂皮）”作为主要材质肌理标签。', '机织', NULL, NULL, '单元素图案', '抽象图案', NULL);
INSERT INTO `clothing_texture_info` VALUES (1980126, 19996582, '平纹', '从品牌和功能描述来看，帽子主体使用再生尼龙和网眼拼接，属于常见的户外防晒帽面料，多为平纹机织尼龙或聚酯，表面平整、无绒毛、无立体纹理，与“Plain weave（平纹织物）”的特征相符。', '机织', NULL, NULL, NULL, '抽象图案', NULL);
INSERT INTO `clothing_texture_info` VALUES (1980124, 19996580, '平纹', '鞋面材质为经典帆布，说明文字也指出是“キャンバス素材”，帆布通常为平纹组织的粗梗棉布，表面纹理平整但能看到经纬交织感，因此在肌理上最接近“Plain weave（平纹织物）”。', '机织', NULL, NULL, NULL, '抽象图案', NULL);
INSERT INTO `clothing_texture_info` VALUES (1980125, 19996581, '平纹', '鞋面材质为经典帆布，说明文字也指出是“キャンバス素材”，帆布通常为平纹组织的粗梗棉布，表面纹理平整但能看到经纬交织感，因此在肌理上最接近“Plain weave（平纹织物）”。', '机织', NULL, NULL, NULL, '抽象图案', NULL);
INSERT INTO `clothing_texture_info` VALUES (1980118, 19996574, '平纹', '从“ストレッチデニム生地”“リネンブレンド”以及实物图来看，为常规牛仔机织布，表面有细微经纬纹理，类似平纹/斜纹机织结构；题中未提供专门“denim”选项，在统一纹理枚举里与普通牛仔最接近的是“Plain weave（平纹）”，用以表示这种常规机织、表面较为平整略有纹理的布面，因此选择“Plain weave”。', '机织', NULL, NULL, NULL, '抽象图案', NULL);
INSERT INTO `clothing_texture_info` VALUES (1980119, 19996575, '平纹', '从“ストレッチデニム生地”“リネンブレンド”以及实物图来看，为常规牛仔机织布，表面有细微经纬纹理，类似平纹/斜纹机织结构；题中未提供专门“denim”选项，在统一纹理枚举里与普通牛仔最接近的是“Plain weave（平纹）”，用以表示这种常规机织、表面较为平整略有纹理的布面，因此选择“Plain weave”。', '机织', NULL, NULL, NULL, '抽象图案', NULL);
INSERT INTO `clothing_texture_info` VALUES (1980120, 19996576, '结子布', '商品说明提到面料表面具有凹凸感、呈网眼般表情，并为弹力牛仔且含亚麻混纺，视觉上可以看到细微不规则的纹理，这与纱线粗细不一、表面略有颗粒感的“Slub fabrics（竹节纹理面料）”特征相符，因此选择“Slub fabrics”作为材质肌理标签。', '机织', NULL, NULL, NULL, '抽象图案', NULL);
INSERT INTO `clothing_texture_info` VALUES (1980121, 19996577, '结子布', '商品说明提到面料表面具有凹凸感、呈网眼般表情，并为弹力牛仔且含亚麻混纺，视觉上可以看到细微不规则的纹理，这与纱线粗细不一、表面略有颗粒感的“Slub fabrics（竹节纹理面料）”特征相符，因此选择“Slub fabrics”作为材质肌理标签。', '机织', NULL, NULL, NULL, '抽象图案', NULL);
INSERT INTO `clothing_texture_info` VALUES (1980122, 19996578, '平纹', '从成分“綿98% ポリウレタン2%”及牛仔面料描述来看，为典型的丹宁机织布，属平纹或斜纹的梭织结构，在统一枚举中最接近的基础肌理类型为“Plain weave”，代表常见的机织基础纹理，与软质轻量牛仔的表面质感相符。', '机织', NULL, NULL, NULL, '抽象图案', NULL);
INSERT INTO `clothing_texture_info` VALUES (1980123, 19996579, '平纹', '从成分“綿98% ポリウレタン2%”及牛仔面料描述来看，为典型的丹宁机织布，属平纹或斜纹的梭织结构，在统一枚举中最接近的基础肌理类型为“Plain weave”，代表常见的机织基础纹理，与软质轻量牛仔的表面质感相符。', '机织', NULL, NULL, NULL, '抽象图案', NULL);
INSERT INTO `clothing_texture_info` VALUES (1980115, 19996571, '平纹', '商品说明为14/- OE空纺棉纱编织的T恤针织面料，表面看起来较为平整、无绒毛与特殊立体组织效果，呈现普通棉T那种自然干爽的平滑感。在给定选项中，与这种基础针织布表观最接近的是“Plain weave”，因此选择“Plain weave”来概括其简洁、平坦的织物外观。', '纬编', '独幅', '印花', '单元素图案', '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1980116, 19996572, '平纹', '商品说明为14/- OE空纺棉纱编织的T恤针织面料，表面看起来较为平整、无绒毛与特殊立体组织效果，呈现普通棉T那种自然干爽的平滑感。在给定选项中，与这种基础针织布表观最接近的是“Plain weave”，因此选择“Plain weave”来概括其简洁、平坦的织物外观。', '纬编', '独幅', '印花', '单元素图案', '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1980117, 19996573, '平纹', '商品说明为14/- OE空纺棉纱编织的T恤针织面料，表面看起来较为平整、无绒毛与特殊立体组织效果，呈现普通棉T那种自然干爽的平滑感。在给定选项中，与这种基础针织布表观最接近的是“Plain weave”，因此选择“Plain weave”来概括其简洁、平坦的织物外观。', '纬编', '独幅', '印花', '单元素图案', '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1980113, 19996569, '皮革/PU革', '商品材质标注为“合成皮革”，鞋面表观平整略有光泽，符合“Leather/PU leather（皮革/PU皮革）”的质感特征，因此选择“Leather/PU leather”作为唯一材质肌理标签。', '机织', NULL, NULL, NULL, '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1980114, 19996570, '皮革/PU革', '商品材质标注为“合成皮革”，鞋面表观平整略有光泽，符合“Leather/PU leather（皮革/PU皮革）”的质感特征，因此选择“Leather/PU leather”作为唯一材质肌理标签。', '机织', NULL, NULL, NULL, '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1980111, 19996567, '平纹', '文中说明使用“からみ素材”（卡拉米组织），属于一种经纬线交织形成的轻薄机织结构，表面平整、清爽，没有绒毛、光泽涂层或明显立体组织效果，整体呈现典型的平纹机织感，因此在材质肌理上选择“Plain weave（平纹组织）”。', '机织', NULL, NULL, NULL, '抽象图案', NULL);
INSERT INTO `clothing_texture_info` VALUES (1980112, 19996568, '平纹', '文中说明使用“からみ素材”（卡拉米组织），属于一种经纬线交织形成的轻薄机织结构，表面平整、清爽，没有绒毛、光泽涂层或明显立体组织效果，整体呈现典型的平纹机织感，因此在材质肌理上选择“Plain weave（平纹组织）”。', '机织', NULL, NULL, NULL, '抽象图案', NULL);
INSERT INTO `clothing_texture_info` VALUES (1980109, 19996565, '平纹', '产品说明为“カラミ素材”，属轻薄透气的机织结构，图片中表面细密平整，仅有均匀小纹理，无绒毛、无凸起立体效果，整体视觉接近常规平纹机织感，因此在给定选项中选择最接近的“Plain weave（平纹织物）”作为材质肌理描述。', '机织', '满幅', '提花', '多元素图案', '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1980110, 19996566, '平纹', '产品说明为“カラミ素材”，属轻薄透气的机织结构，图片中表面细密平整，仅有均匀小纹理，无绒毛、无凸起立体效果，整体视觉接近常规平纹机织感，因此在给定选项中选择最接近的“Plain weave（平纹织物）”作为材质肌理描述。', '机织', '满幅', '提花', '多元素图案', '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1980107, 19996563, '平纹', '商品主要由再生纤维、粘胶、聚酯和少量麻混纺而成，用于夏季吊带连衣裙，描述为“さらっとした質感”，图中表面平整、无绒毛、无明显立体纹路或织花效果，最符合平滑、细密的机织平纹特征，因此选择“Plain weave（平纹织物）”。', '机织', '满幅', '印花', '多元素图案', '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1980108, 19996564, '平纹', '商品主要由再生纤维、粘胶、聚酯和少量麻混纺而成，用于夏季吊带连衣裙，描述为“さらっとした質感”，图中表面平整、无绒毛、无明显立体纹路或织花效果，最符合平滑、细密的机织平纹特征，因此选择“Plain weave（平纹织物）”。', '机织', '满幅', '印花', '多元素图案', '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1980105, 19996561, '泡泡纱', '文案明确说明为“表面に波状の細かい凹凸を出したサッカー生地”，即表面有波状细小凹凸的沙卡（泡泡纱）面料，这正是“Seersucker（泡泡纱/沙卡面料）”的典型特征：局部收缩形成不规则凹凸，触感清爽、离肌感好，因此选择“Seersucker”作为单一材质肌理标签。', '机织', NULL, NULL, '单元素图案', '抽象图案', NULL);
INSERT INTO `clothing_texture_info` VALUES (1980106, 19996562, '泡泡纱', '文案明确说明为“表面に波状の細かい凹凸を出したサッカー生地”，即表面有波状细小凹凸的沙卡（泡泡纱）面料，这正是“Seersucker（泡泡纱/沙卡面料）”的典型特征：局部收缩形成不规则凹凸，触感清爽、离肌感好，因此选择“Seersucker”作为单一材质肌理标签。', '机织', NULL, NULL, '单元素图案', '抽象图案', NULL);
INSERT INTO `clothing_texture_info` VALUES (1980102, 19996558, '提花', '商品说明为「ドビーレース」加「コットンレース」，图片中可见面料有细密凸起的小纹理，是通过组织结构形成的花纹，属于提花类肌理，因此选择「Jacquard」作为主要材质肌理。', '机织', '满幅', '提花', '多元素图案', '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1980103, 19996559, '平纹', '从材质成分看以聚酯纤维与人造纤维为主，适合做轻薄平滑梭织面料，图片中表面较为平整、无明显绒毛或立体肌理，呈普通平纹机织感，因此选择“Plain weave（平纹织物）”作为主要材质肌理。', '机织', '满幅', '印花', '多元素图案', '具象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1980104, 19996560, '平纹', '从材质成分看以聚酯纤维与人造纤维为主，适合做轻薄平滑梭织面料，图片中表面较为平整、无明显绒毛或立体肌理，呈普通平纹机织感，因此选择“Plain weave（平纹织物）”作为主要材质肌理。', '机织', '满幅', '印花', '多元素图案', '具象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1980101, 19996557, '砂洗面料', '商品说明写明为“ウォッシュド加工を施したコットン生地”，表明面料经过水洗做旧处理，表面带有轻微泛白与柔和的磨洗感，与“Sand-washed fabrics（砂洗/水洗感面料）”最为接近，因此选择该纹理标签。', '机织', '独幅', '刺绣', '单元素图案', '具象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1980099, 19996555, '水洗牛仔布', '商品说明中提到「ウォッシュド加工を施したコットン生地」，即对棉质面料进行了洗水做旧处理，表面具有类似牛仔洗水的复古感和轻微磨洗痕迹。统一枚举中最接近这类洗水棉斜纹/牛仔感表面的标签为「Washed denim」，故选用「Washed denim」作为材质肌理描述。', '机织', '独幅', '刺绣', '单元素图案', '具象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1980100, 19996556, '水洗牛仔布', '商品说明中提到「ウォッシュド加工を施したコットン生地」，即对棉质面料进行了洗水做旧处理，表面具有类似牛仔洗水的复古感和轻微磨洗痕迹。统一枚举中最接近这类洗水棉斜纹/牛仔感表面的标签为「Washed denim」，故选用「Washed denim」作为材质肌理描述。', '机织', '独幅', '刺绣', '单元素图案', '具象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1980097, 19996553, '水洗牛仔布', '从图片与“Acid加工”描述看，表面有明显水洗做旧痕迹和丹宁风格质感，属于典型水洗牛仔布外观，因此选择“Washed denim（水洗牛仔）”来描述这种经过水洗处理的面料肌理。', '机织', '满幅', '印花', '多元素图案', '抽象图案', '复古风格');
INSERT INTO `clothing_texture_info` VALUES (1980098, 19996554, '水洗牛仔布', '从图片与“Acid加工”描述看，表面有明显水洗做旧痕迹和丹宁风格质感，属于典型水洗牛仔布外观，因此选择“Washed denim（水洗牛仔）”来描述这种经过水洗处理的面料肌理。', '机织', '满幅', '印花', '多元素图案', '抽象图案', '复古风格');
INSERT INTO `clothing_texture_info` VALUES (1980095, 19996551, '网眼布', '包体采用纸质镂空编织结构，表面由线条与孔洞组成，具有明显的通透感与网状结构特征，最接近“Mesh（网眼材质）”这种肌理，因此选择“Mesh”。', '机织', '满幅', NULL, '多元素图案', '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1980096, 19996552, '网眼布', '包体采用纸质镂空编织结构，表面由线条与孔洞组成，具有明显的通透感与网状结构特征，最接近“Mesh（网眼材质）”这种肌理，因此选择“Mesh”。', '机织', '满幅', NULL, '多元素图案', '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1980091, 19996547, '平纹', '商品为ポンチ（罗马布）针织面料，表面描述为“滑らかな表面感”，从图片也能看出表面平整顺滑、无绒毛、无明显纹路或凹凸组织效果，视觉上接近普通平纹织物的光洁感，因此在给定选项中选择最接近的“Plain weave”来表示这种平滑、均匀的表面质感。', '纬编', '满幅', '印花', '多元素图案', '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1980092, 19996548, '平纹', '商品为ポンチ（罗马布）针织面料，表面描述为“滑らかな表面感”，从图片也能看出表面平整顺滑、无绒毛、无明显纹路或凹凸组织效果，视觉上接近普通平纹织物的光洁感，因此在给定选项中选择最接近的“Plain weave”来表示这种平滑、均匀的表面质感。', '纬编', '满幅', '印花', '多元素图案', '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1980093, 19996549, '缎纹', '商品描述强调“上品な光沢”“なめらかな質感”，图片中也可见表面有亮泽、柔顺且较为平整，符合缎纹面料特征，因此选择“Satin weaves（缎纹）”作为主要材质肌理标签。', '机织', '满幅', '印花', '多元素图案', '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1980094, 19996550, '缎纹', '商品描述强调“上品な光沢”“なめらかな質感”，图片中也可见表面有亮泽、柔顺且较为平整，符合缎纹面料特征，因此选择“Satin weaves（缎纹）”作为主要材质肌理标签。', '机织', '满幅', '印花', '多元素图案', '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1980085, 19996541, '绉纹', '文中说明为“ボイル素材”，并从图片看面料表面略带细微不规则纹理和干爽感，整体轻薄、有垂坠且带有轻微皱感，与“Crepe（绉纹面料）”特征相符，因此选择“Crepe”这一肌理标签。', '机织', '满幅', NULL, '多元素图案', '抽象图案', NULL);
INSERT INTO `clothing_texture_info` VALUES (1980086, 19996542, '绉纹', '文中说明为“ボイル素材”，并从图片看面料表面略带细微不规则纹理和干爽感，整体轻薄、有垂坠且带有轻微皱感，与“Crepe（绉纹面料）”特征相符，因此选择“Crepe”这一肌理标签。', '机织', '满幅', NULL, '多元素图案', '抽象图案', NULL);
INSERT INTO `clothing_texture_info` VALUES (1980087, 19996543, '绉纹', '文中说明为“ボイル素材”，并从图片看面料表面略带细微不规则纹理和干爽感，整体轻薄、有垂坠且带有轻微皱感，与“Crepe（绉纹面料）”特征相符，因此选择“Crepe”这一肌理标签。', '机织', '满幅', NULL, '多元素图案', '抽象图案', NULL);
INSERT INTO `clothing_texture_info` VALUES (1980088, 19996544, '平纹', '商品说明为轻盈的“ボイル”材质，这类薄纱多为平纹组织，表面平整细腻、略带挺括与透感，图片也呈现光滑无绒毛、无立体纹道的平滑织物特征，因此选择“Plain weave（平纹）”作为最贴合的材质肌理标签。', '机织', NULL, NULL, NULL, '抽象图案', NULL);
INSERT INTO `clothing_texture_info` VALUES (1980089, 19996545, '平纹', '商品说明为轻盈的“ボイル”材质，这类薄纱多为平纹组织，表面平整细腻、略带挺括与透感，图片也呈现光滑无绒毛、无立体纹道的平滑织物特征，因此选择“Plain weave（平纹）”作为最贴合的材质肌理标签。', '机织', NULL, NULL, NULL, '抽象图案', NULL);
INSERT INTO `clothing_texture_info` VALUES (1980090, 19996546, '平纹', '商品说明为轻盈的“ボイル”材质，这类薄纱多为平纹组织，表面平整细腻、略带挺括与透感，图片也呈现光滑无绒毛、无立体纹道的平滑织物特征，因此选择“Plain weave（平纹）”作为最贴合的材质肌理标签。', '机织', NULL, NULL, NULL, '抽象图案', NULL);
INSERT INTO `clothing_texture_info` VALUES (1980083, 19996539, '缎纹', '文案明确说明为“微光泽で滑らかなサテン素材”，且从图片中也能看到有一定光泽与顺滑垂感，因此选择“Satin weaves（缎纹面料）”作为主要材质肌理。缎纹结构通常表面平滑、有光泽感，与描述高度一致。', '机织', '满幅', '印花', '多元素图案', '抽象图案', NULL);
INSERT INTO `clothing_texture_info` VALUES (1980084, 19996540, '缎纹', '文案明确说明为“微光泽で滑らかなサテン素材”，且从图片中也能看到有一定光泽与顺滑垂感，因此选择“Satin weaves（缎纹面料）”作为主要材质肌理。缎纹结构通常表面平滑、有光泽感，与描述高度一致。', '机织', '满幅', '印花', '多元素图案', '抽象图案', NULL);
INSERT INTO `clothing_texture_info` VALUES (1980077, 19996533, '平纹', '商品说明为ポンチジャージー针织，表面平滑细腻、无绒毛、无明显凹凸或特殊整理效果，视觉上接近普通平滑针织面，最接近统一枚举中的“Plain weave”所代表的平整光洁表观，因此选择“Plain weave”来概括其顺滑平整的表面质感。', '纬编', '满幅', '印花', '多元素图案', '具象图案', '简约风格');
