INSERT INTO `clothing_texture_info` VALUES (1980060, 19996516, '天鹅绒', '商品介绍中说明为“高級感あるベロア素材”，且图片中表面有柔软顺滑、略带光泽的绒面质感，这与“Velvet（天鹅绒）”的外观和手感相符，因此选择“Velvet”作为材质肌理标签。', '纬编', '满幅', '提花', '多元素图案', '具象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1980059, 19996515, '网眼布', '商品名称与描述中明确为“メッシュパーカー”，可见为大网眼结构，表面孔洞清晰、具有透视感，最符合“Mesh（网眼材质）”这一肌理特征。', '纬编', NULL, NULL, NULL, '抽象图案', NULL);
INSERT INTO `clothing_texture_info` VALUES (1980057, 19996513, '平纹', '从材质成分为全棉卫衣面料以及图片中微哑光、表面较为平整的织物结构判断，为常见的平纹针织汗布外观，对应分类中最接近的是“Plain weave（平纹织物）”，用于指代这种表面光洁、无明显绒毛或立体组织感的基础纹理。', '纬编', '独幅', '印花', '单元素图案', '具象图案', '插画效果');
