INSERT INTO `clothing_texture_info` VALUES (1979995, 19996451, '水洗牛仔布', '从图片和描述可见帽身为棉质，并有明显水洗做旧的色差与泛白效果，表面呈现类似牛仔水洗的磨淡感和微微的粗糙纹理，因此在统一纹理标签中选择“Washed denim（水洗牛仔风格）”最为贴切，用来指代这种经过水洗处理的棉斜纹外观。', '机织', '独幅', '刺绣', '单元素图案', '抽象图案', '复古风格');
INSERT INTO `clothing_texture_info` VALUES (1979996, 19996452, '水洗牛仔布', '从图片和描述可见帽身为棉质，并有明显水洗做旧的色差与泛白效果，表面呈现类似牛仔水洗的磨淡感和微微的粗糙纹理，因此在统一纹理标签中选择“Washed denim（水洗牛仔风格）”最为贴切，用来指代这种经过水洗处理的棉斜纹外观。', '机织', '独幅', '刺绣', '单元素图案', '抽象图案', '复古风格');
INSERT INTO `clothing_texture_info` VALUES (1979997, 19996453, '水洗牛仔布', '从图片和描述可见帽身为棉质，并有明显水洗做旧的色差与泛白效果，表面呈现类似牛仔水洗的磨淡感和微微的粗糙纹理，因此在统一纹理标签中选择“Washed denim（水洗牛仔风格）”最为贴切，用来指代这种经过水洗处理的棉斜纹外观。', '机织', '独幅', '刺绣', '单元素图案', '抽象图案', '复古风格');
INSERT INTO `clothing_texture_info` VALUES (1979998, 19996454, '水洗牛仔布', '从图片和描述可见帽身为棉质，并有明显水洗做旧的色差与泛白效果，表面呈现类似牛仔水洗的磨淡感和微微的粗糙纹理，因此在统一纹理标签中选择“Washed denim（水洗牛仔风格）”最为贴切，用来指代这种经过水洗处理的棉斜纹外观。', '机织', '独幅', '刺绣', '单元素图案', '抽象图案', '复古风格');
INSERT INTO `clothing_texture_info` VALUES (1979999, 19996455, '平纹', '商品说明为“ハイゲージニット（高针距针织）”，视觉上表面细腻平滑、无毛圈和绒毛感，也无明显立体纹路，整体呈现均匀细致的平整纹理。综合判断其表观效果最接近“Plain weave 平纹质感”的光滑细腻外观，因此选择纹理标签为 Plain weave。', '纬编', '满幅', '提花', '多元素图案', '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1980000, 19996456, '平纹', '商品说明为“ハイゲージニット（高针距针织）”，视觉上表面细腻平滑、无毛圈和绒毛感，也无明显立体纹路，整体呈现均匀细致的平整纹理。综合判断其表观效果最接近“Plain weave 平纹质感”的光滑细腻外观，因此选择纹理标签为 Plain weave。', '纬编', '满幅', '提花', '多元素图案', '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1979992, 19996448, '平纹', '从图片看为常见的小袋包装基材，表面平整、略有光泽，接近普通平纹机织材料的视觉效果，因此选择“Plain weave（平纹织物）”作为最合适的肌理标签。', '机织', NULL, NULL, NULL, '抽象图案', NULL);
INSERT INTO `clothing_texture_info` VALUES (1979993, 19996449, '平纹', '产品为粉末状洁面品，外包装为常见塑料袋/软包装材质，从视觉上呈现平滑、无明显绒感或立体纹理的表面表现，最接近一般平纹结构的“Plain weave（平纹）”效果，因此选择“Plain weave”。', '机织', NULL, NULL, NULL, '抽象图案', NULL);
INSERT INTO `clothing_texture_info` VALUES (1979994, 19996450, '平纹', '产品为塑料瓶身印刷工艺，非纺织面料。在所有面料肌理标签中，与普通平滑无明显组织纹理的表面最接近的是“Plain weave（平纹）”，可抽象类比为表面细腻、无立体纹理的基础状态，因此选用“Plain weave”作为形式上的归类。', '机织', NULL, NULL, NULL, '抽象图案', NULL);
INSERT INTO `clothing_texture_info` VALUES (1979990, 19996446, '平纹', '产品外层为普通塑料软袋和透明窗口，视觉上类似平滑、无明显纹理的平整表面，在既有标签中与“Plain weave（平纹）”效果最接近，代表表面光滑、无立体纹路的基础结构感。', '机织', NULL, NULL, NULL, '抽象图案', NULL);
INSERT INTO `clothing_texture_info` VALUES (1979991, 19996447, '平纹', '这是塑料瓶装的粉状洁面产品，外观并非纺织服装面料。按任务要求需从既有纹理标签中择一最接近的选项，仅能类比为表面光滑、无明显立体织纹的“Plain weave（平纹）”效果，以代表其整体平整细腻、无特殊凹凸的视觉质感。', '机织', NULL, NULL, NULL, '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1979988, 19996444, '平纹', '产品为玻璃瓶身与普通纸质标签，并非纺织面料；在可选纺织肌理标签中，与之最接近的是表面平整光滑、无显著织纹感的“Plain weave（平纹织物）”，用来代表其光滑、均匀的表面效果。', '机织', NULL, NULL, NULL, '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1979989, 19996445, '平纹', '这是硬质塑料瓶身外观，没有明显绒毛、光泽金属感或复杂肌理，按照任务要求需在给定纺织类肌理中择一最接近的基础表面效果，只能类比为表面平整光滑、结构简单的“Plain weave（平纹）”。', '机织', '独幅', '印花', '单元素图案', '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1979987, 19996443, '平纹', '从图片上看为普通柔软塑料/纸质包装的平整表面，在本题提供的面料肌理标签中，与“Plain weave（平纹）”最为接近，代表表面较为光滑、无明显绒感或凹凸纹理的基础平整质感，因此选择“Plain weave”。', '机织', NULL, NULL, NULL, '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1979985, 19996441, '平纹', '产品为化妆水塑料瓶加内装水状液体，未涉及特殊织物或立体肌理。若对应面料质感，最接近的是普通平滑表面的“Plain weave”概念，用来抽象表示其表面光滑、无绒毛与特殊纹理的特征。', '机织', '独幅', '印花', '单元素图案', '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1979986, 19996442, '平纹', '从包装外观判断为普通柔软塑料/铝塑复合袋类平滑表面，最接近纺织结构中的平纹组织效果，因此在现有选项中选择“Plain weave”来表示表面平整、无明显绒毛或立体纹理的平滑质感。', '机织', NULL, NULL, NULL, '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1979984, 19996440, '平纹', '产品为透明玻璃杯，并非纺织面料，但在必须从既有选项中选择一个材质肌理标签的前提下，只能选与“平滑、无明显织纹或毛感”的表面最接近的“Plain weave（平纹）”。玻璃表面光滑平整、无绒毛与立体纹路，与平纹织物的视觉感受相对更接近，因此选择“Plain weave”。', '机织', NULL, NULL, NULL, '抽象图案', NULL);
INSERT INTO `clothing_texture_info` VALUES (1979980, 19996436, '平纹', '该勺为不锈钢制品，表面平整光滑，无绒毛、凹凸颗粒或特殊压纹效果，可视作类似平纹金属光洁表面。在给定选项中最接近的是“Plain weave/平纹”，用来表示其表面简单、均匀、无立体纹理的特点。', '机织', NULL, NULL, NULL, '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1979981, 19996437, '平纹', '该产品是光滑透明的玻璃杯，表面平整，无绒毛、无颗粒、无褶皱或提花等织物肌理。尽管枚举主要针对纺织品，在可选项中与这种光滑、基础表面最接近的是“Plain weave（平纹）”，因此使用“Plain weave”来表示其表面简洁、无特殊立体纹理的特征。', '机织', NULL, NULL, NULL, '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1979982, 19996438, '平纹', '产品主体为透明玻璃和树脂，表面光滑平整、无绒毛和凹凸纹理，类似最基础的平滑材质肌理，在给定选项中与“Plain weave（平纹织物）”的光洁、平整感最为接近，故选择“Plain weave”。', '机织', NULL, NULL, NULL, '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1979983, 19996439, '平纹', '该产品为光滑的玻璃杯表面，没有纤维绒感、织纹或立体颗粒，视觉上平整且硬质。在现有选项中没有专门针对玻璃的纹理，只能类比为表面平滑、无明显组织纹理的“Plain weave（平纹）”效果，因此选择“Plain weave”作为最接近的材质肌理描述。', '机织', NULL, NULL, NULL, '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1979978, 19996434, '平纹', '该产品为高温烧制的陶瓷制品，表面为光滑致密的釉面，没有绒毛、纹理凹凸或织物结构可见。在可选纹理标签中，没有专门针对陶瓷光滑面的选项，只能在织物基础纹理中择其接近的“Plain weave（平纹）”来表示一种光滑、均匀、无立体肌理的表面效果。', '机织', NULL, NULL, NULL, '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1979979, 19996435, '平纹', '该商品为不锈钢制容器，其表面平整光滑、无绒毛、无凹凸肌理，类似普通平纹材质的平滑效果。在可选纹理标签中，“Plain weave/平纹”最接近这类简单、光洁且无特殊立体组织感的表面状态。', '机织', NULL, NULL, NULL, '抽象图案', NULL);
INSERT INTO `clothing_texture_info` VALUES (1979975, 19996431, '平纹', '瓶身为光滑透明的耐热玻璃，表面平整无绒毛、无凹凸肌理，接近“Plain weave（平纹）”所代表的基础、光滑平整表面质感，在现有纹理标签中与其最为接近，因此选择“Plain weave”。', '机织', NULL, NULL, NULL, '抽象图案', NULL);
INSERT INTO `clothing_texture_info` VALUES (1979976, 19996432, '平纹', '产品为陶器杯，没有纺织肌理可见，在可选纹理标签中只能选择与光滑、基础表面最接近的“Plain weave”，用以抽象表示其平整简洁的表面效果。', '机织', NULL, NULL, NULL, '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1979977, 19996433, '平纹', '产品为陶器杯，没有纺织肌理可见，在可选纹理标签中只能选择与光滑、基础表面最接近的“Plain weave”，用以抽象表示其平整简洁的表面效果。', '机织', NULL, NULL, NULL, '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1979973, 19996429, '平纹', '产品材质为纸张且表面平整光洁，无绒毛、凹凸或特殊肌理效果，视觉上接近普通平纹表面效果，因此在既有选项中选择“Plain weave”作为最接近的平滑基础纹理描述。', '机织', '独幅', '印花', '单元素图案', '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1979974, 19996430, '篮格组织', '器物由白竹条交错编织成均匀的格状结构，表面可以明显看到纵横交错的“筐编”肌理，符合“Basket Weave（筐编/篮织纹理）”的特点，因此选择 Basket Weave 作为唯一材质肌理标签。', '机织', '满幅', '提花', '多元素图案', '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1979972, 19996428, '平纹', '该产品为上釉彩绘陶器盘，表面光滑平整，没有绒毛、立体织纹或特殊压花效果。从可选标签中没有专门的陶瓷质感，只能在织物类中选一个中性、代表表面较为平整的“Plain weave”作为最接近的对应标签，用以表示其表面相对光滑、无明显立体肌理。', '机织', '满幅', '印花', '多元素图案', '具象图案', '手绘风');
INSERT INTO `clothing_texture_info` VALUES (1979971, 19996427, '平纹', '产品为瓷质汤杯，表面平滑细腻、无绒感、无明显立体织纹效果，整体呈现均匀光滑的硬质表面。在可选纹理标签中，没有专门针对陶瓷的选项，只能类比为表面平整细腻、无立体纹路的基础结构，因此选用最接近的“Plain weave”来表示这种简洁光滑的表面质感。', '机织', '独幅', '印花', '单元素图案', '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1979970, 19996426, '平纹', '从图片看，保护套表面平整细腻，没有绒毛、凹凸纹路或光泽变化，类似普通机织平纹或细腻成型表面的质感，在给定选项中最接近“Plain weave（平纹）”这种光滑均匀的表面效果，因此选择 Plain weave。', '机织', NULL, NULL, NULL, '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1979967, 19996423, '平纹', '面料说明为高密度尼龙短裤，视觉上表面平整、无绒毛、无立体肌理，也无明显斜纹或颗粒感，符合常见尼龙机织布的平纹组织特征，因此选择“Plain weave（平纹组织）”作为主要材质肌理标签。', '机织', '独幅', '刺绣', '单元素图案', '具象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1979968, 19996424, '平纹', '面料说明为高密度尼龙短裤，视觉上表面平整、无绒毛、无立体肌理，也无明显斜纹或颗粒感，符合常见尼龙机织布的平纹组织特征，因此选择“Plain weave（平纹组织）”作为主要材质肌理标签。', '机织', '独幅', '刺绣', '单元素图案', '具象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1979969, 19996425, '平纹', '面料说明为高密度尼龙短裤，视觉上表面平整、无绒毛、无立体肌理，也无明显斜纹或颗粒感，符合常见尼龙机织布的平纹组织特征，因此选择“Plain weave（平纹组织）”作为主要材质肌理标签。', '机织', '独幅', '刺绣', '单元素图案', '具象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1979964, 19996420, '平纹', '产品说明为聚酯纤维伞布，照片中表面平滑、无绒毛、无立体纹路，符合常规伞布所用的机织平纹结构特征，因此选择“Plain weave（平纹织物）”作为最合适的材质肌理标签。', '机织', NULL, NULL, NULL, '抽象图案', NULL);
INSERT INTO `clothing_texture_info` VALUES (1979965, 19996421, '平纹', '产品说明为聚酯纤维伞布，照片中表面平滑、无绒毛、无立体纹路，符合常规伞布所用的机织平纹结构特征，因此选择“Plain weave（平纹织物）”作为最合适的材质肌理标签。', '机织', NULL, NULL, NULL, '抽象图案', NULL);
INSERT INTO `clothing_texture_info` VALUES (1979966, 19996422, '平纹', '产品说明为聚酯纤维伞布，照片中表面平滑、无绒毛、无立体纹路，符合常规伞布所用的机织平纹结构特征，因此选择“Plain weave（平纹织物）”作为最合适的材质肌理标签。', '机织', NULL, NULL, NULL, '抽象图案', NULL);
INSERT INTO `clothing_texture_info` VALUES (1979959, 19996415, '平纹', '从图片和材质描述看，瓶身为光滑的树脂成型表面，视觉上类似普通平滑硬质面，没有绒毛、褶皱或特殊立体肌理，最接近基础的“Plain weave（平纹织物）”这一光滑均一表面效果，因此选择 Plain weave。', '机织', '独幅', '印花', '单元素图案', '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1979960, 19996416, '平纹', '从图片和材质描述看，瓶身为光滑的树脂成型表面，视觉上类似普通平滑硬质面，没有绒毛、褶皱或特殊立体肌理，最接近基础的“Plain weave（平纹织物）”这一光滑均一表面效果，因此选择 Plain weave。', '机织', '独幅', '印花', '单元素图案', '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1979961, 19996417, '压花', '托盘表面有明显的凹凸纹理，用浮雕感的线条表现花瓣和花心细节，属于通过压纹工艺形成立体肌理的“Embossing（压纹）”质感。', '机织', NULL, NULL, NULL, '抽象图案', NULL);
INSERT INTO `clothing_texture_info` VALUES (1979962, 19996418, '压花', '托盘表面有明显的凹凸纹理，用浮雕感的线条表现花瓣和花心细节，属于通过压纹工艺形成立体肌理的“Embossing（压纹）”质感。', '机织', NULL, NULL, NULL, '抽象图案', NULL);
INSERT INTO `clothing_texture_info` VALUES (1979963, 19996419, '平纹', '产品为陶质茶壶，表面光滑致密、无绒毛、无特殊立体肌理或织物纹理。在给定纹理标签中没有专门针对陶瓷或石器表面，只能选择最接近“平滑、均匀表面”的“Plain weave（平纹）”来表示其外观上的均匀、平整效果。', '机织', '满幅', NULL, '单元素图案', '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1979956, 19996412, '平纹', '商品说明为轻量耐久尼龙短裤，从图片细节可见表面基本平整、无绒毛与明显凹凸结构，符合常见的尼龙平纹机织布特征，因此选择“Plain weave（平纹织物）”来描述面料肌理。', '机织', '独幅', '刺绣', '单元素图案', '具象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1979957, 19996413, '平纹', '商品说明为轻量耐久尼龙短裤，从图片细节可见表面基本平整、无绒毛与明显凹凸结构，符合常见的尼龙平纹机织布特征，因此选择“Plain weave（平纹织物）”来描述面料肌理。', '机织', '独幅', '刺绣', '单元素图案', '具象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1979958, 19996414, '平纹', '商品说明为轻量耐久尼龙短裤，从图片细节可见表面基本平整、无绒毛与明显凹凸结构，符合常见的尼龙平纹机织布特征，因此选择“Plain weave（平纹织物）”来描述面料肌理。', '机织', '独幅', '刺绣', '单元素图案', '具象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1979952, 19996408, '平纹', '从材质成分“綿93%、麻7%”以及商品说明“リネンライクな風合い”可知为棉麻混纺衬衫面料，一般为简洁的机织平纹结构，表面较为平整细腻，无明显绒毛或特殊肌理，因此选择“Plain weave（平纹）”作为主要材质肌理。', '机织', '独幅', '刺绣', '多元素图案', '具象图案', '插画效果');
INSERT INTO `clothing_texture_info` VALUES (1979953, 19996409, '平纹', '从材质成分“綿93%、麻7%”以及商品说明“リネンライクな風合い”可知为棉麻混纺衬衫面料，一般为简洁的机织平纹结构，表面较为平整细腻，无明显绒毛或特殊肌理，因此选择“Plain weave（平纹）”作为主要材质肌理。', '机织', '独幅', '刺绣', '多元素图案', '具象图案', '插画效果');
INSERT INTO `clothing_texture_info` VALUES (1979954, 19996410, '平纹', '商品说明为聚酯纤维100%，夏季度假衬衫通常采用轻薄平纹机织面料，表面较为平整顺滑，图片中也未见绒毛或凹凸肌理，因此将材质肌理归为“Plain weave（平纹织物）”最为贴切。', '机织', '满幅', '印花', '多元素图案', '具象图案', '插画效果');
INSERT INTO `clothing_texture_info` VALUES (1979955, 19996411, '平纹', '商品说明为聚酯纤维100%，夏季度假衬衫通常采用轻薄平纹机织面料，表面较为平整顺滑，图片中也未见绒毛或凹凸肌理，因此将材质肌理归为“Plain weave（平纹织物）”最为贴切。', '机织', '满幅', '印花', '多元素图案', '具象图案', '插画效果');
INSERT INTO `clothing_texture_info` VALUES (1979949, 19996405, '涂层/轧光面料', '伞面为聚乙烯薄膜材质，表面光滑、有一定硬挺度和防水性，属于具有涂层/压延处理特征的膜状材料，因此选择“Coated/calendered（涂层/压延）”作为主要肌理特征。', '机织', NULL, NULL, NULL, '抽象图案', NULL);
INSERT INTO `clothing_texture_info` VALUES (1979950, 19996406, '涂层/轧光面料', '伞面为聚乙烯薄膜材质，表面光滑、有一定硬挺度和防水性，属于具有涂层/压延处理特征的膜状材料，因此选择“Coated/calendered（涂层/压延）”作为主要肌理特征。', '机织', NULL, NULL, NULL, '抽象图案', NULL);
INSERT INTO `clothing_texture_info` VALUES (1979951, 19996407, '涂层/轧光面料', '伞面为聚乙烯薄膜材质，表面光滑、有一定硬挺度和防水性，属于具有涂层/压延处理特征的膜状材料，因此选择“Coated/calendered（涂层/压延）”作为主要肌理特征。', '机织', NULL, NULL, NULL, '抽象图案', NULL);
INSERT INTO `clothing_texture_info` VALUES (1979945, 19996401, '平纹', '面料成分为高比例人造纤维配以尼龙，具有一定垂坠与挺括感，视觉上表面较为平整，仅有轻微凹凸感，没有绒毛、光泽缎感或明显纹路组织，最符合常见的平纹机织布特征，因此选择“Plain weave（平纹织物）”。', '机织', NULL, NULL, NULL, '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1979946, 19996402, '平纹', '面料成分为高比例人造纤维配以尼龙，具有一定垂坠与挺括感，视觉上表面较为平整，仅有轻微凹凸感，没有绒毛、光泽缎感或明显纹路组织，最符合常见的平纹机织布特征，因此选择“Plain weave（平纹织物）”。', '机织', NULL, NULL, NULL, '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1979947, 19996403, '平纹', '面料成分为高比例人造纤维配以尼龙，具有一定垂坠与挺括感，视觉上表面较为平整，仅有轻微凹凸感，没有绒毛、光泽缎感或明显纹路组织，最符合常见的平纹机织布特征，因此选择“Plain weave（平纹织物）”。', '机织', NULL, NULL, NULL, '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1979948, 19996404, '平纹', '面料成分为高比例人造纤维配以尼龙，具有一定垂坠与挺括感，视觉上表面较为平整，仅有轻微凹凸感，没有绒毛、光泽缎感或明显纹路组织，最符合常见的平纹机织布特征，因此选择“Plain weave（平纹织物）”。', '机织', NULL, NULL, NULL, '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1979942, 19996398, '平纹', '从商品描述可知为细针织无袖上衣，表面平整细腻，无绒毛、无明显立体织纹或褶皱效果，视觉上接近均匀、紧密的基础组织，因此在既有选项中选取最接近的“Plain weave/平纹”，用于表示这种平滑、规则的表面感。材质为人造丝、棉和亚麻混纺，也常呈现类似平整的针织纹理。', '纬编', NULL, NULL, NULL, '抽象图案', NULL);
INSERT INTO `clothing_texture_info` VALUES (1979943, 19996399, '平纹', '从商品描述可知为细针织无袖上衣，表面平整细腻，无绒毛、无明显立体织纹或褶皱效果，视觉上接近均匀、紧密的基础组织，因此在既有选项中选取最接近的“Plain weave/平纹”，用于表示这种平滑、规则的表面感。材质为人造丝、棉和亚麻混纺，也常呈现类似平整的针织纹理。', '纬编', NULL, NULL, NULL, '抽象图案', NULL);
INSERT INTO `clothing_texture_info` VALUES (1979944, 19996400, '平纹', '从商品描述可知为细针织无袖上衣，表面平整细腻，无绒毛、无明显立体织纹或褶皱效果，视觉上接近均匀、紧密的基础组织，因此在既有选项中选取最接近的“Plain weave/平纹”，用于表示这种平滑、规则的表面感。材质为人造丝、棉和亚麻混纺，也常呈现类似平整的针织纹理。', '纬编', NULL, NULL, NULL, '抽象图案', NULL);
INSERT INTO `clothing_texture_info` VALUES (1979910, 19996366, '平纹', '从图片与“カットソー”“柔らかく肌触りの良い素材”描述来看，这是常见的棉质针织T恤面料，表面平整、无绒毛、无明显凹凸结构，只经过颜料加工产生褪色效果。综合判断最接近基础平滑结构纹理，对应标签为“Plain weave/平纹织物感”以表示其平整、细腻的基础肌理。', '纬编', NULL, NULL, NULL, '抽象图案', NULL);
INSERT INTO `clothing_texture_info` VALUES (1979897, 19996353, '平纹', '产品为糯米类点心，没有纺织表面肌理可选，只能在给定选项中择一最中性的“Plain weave”代表普通、光滑的表面感，图中饼表面细腻平整、无毛绒或立体纹路，与“Plain weave”的平整感较为接近。', '机织', NULL, NULL, NULL, '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1979880, 19996336, '雪纺', '商品说明中明确写到“シフォン素材”，为轻薄、略透明、表面细腻的“Chiffon（雪纺）”质感，面料飘逸柔软、具有典型雪纺风格，因此选择纹理标签“Chiffon”。', '机织', NULL, NULL, NULL, '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1979878, 19996334, '平纹', '耳钉主体为光滑金属表面，没有绒毛、颗粒或压纹等特殊肌理，视觉效果接近平整致密的“Plain weave（平纹）”质感，相比其他纹理选项最为贴近，因此选择“Plain weave”。', '机织', NULL, NULL, '单元素图案', '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1979879, 19996335, '平纹', '耳钉主体为光滑金属表面，没有绒毛、颗粒或压纹等特殊肌理，视觉效果接近平整致密的“Plain weave（平纹）”质感，相比其他纹理选项最为贴近，因此选择“Plain weave”。', '机织', NULL, NULL, '单元素图案', '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1979875, 19996331, '平纹', '文案说明使用“帆布”面料，帆布通常为较粗厚的平纹机织结构，表面较为平整、硬挺，没有绒毛或明显立体肌理，因此选用“Plain weave（平纹）”作为主要材质肌理标签。', '机织', '满幅', '印花', '多元素图案', '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1979876, 19996332, '平纹', '文案说明使用“帆布”面料，帆布通常为较粗厚的平纹机织结构，表面较为平整、硬挺，没有绒毛或明显立体肌理，因此选用“Plain weave（平纹）”作为主要材质肌理标签。', '机织', '满幅', '印花', '多元素图案', '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1979877, 19996333, '平纹', '文案说明使用“帆布”面料，帆布通常为较粗厚的平纹机织结构，表面较为平整、硬挺，没有绒毛或明显立体肌理，因此选用“Plain weave（平纹）”作为主要材质肌理标签。', '机织', '满幅', '印花', '多元素图案', '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1979868, 19996324, '平纹', '该商品为金属与玻璃材质戒指，没有织物肌理，只能在既有纹理标签中选最中性的“Plain weave/平纹”。其表面光滑、无绒毛或立体织纹，也不具备绗缝、罗纹等特征，因此用“Plain weave”作为无明显织物肌理的近似描述。', '机织', NULL, NULL, NULL, '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1979869, 19996325, '平纹', '该商品为金属与玻璃材质戒指，没有织物肌理，只能在既有纹理标签中选最中性的“Plain weave/平纹”。其表面光滑、无绒毛或立体织纹，也不具备绗缝、罗纹等特征，因此用“Plain weave”作为无明显织物肌理的近似描述。', '机织', NULL, NULL, NULL, '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1979870, 19996326, '平纹', '此为金属项链而非纺织面料，严格来说不存在织物肌理。在必须从纺织纹理中二选一时，选择最接近“光滑、无明显纹路”的“Plain weave/平纹”作为形式上的归类，以对应其细腻平滑的金属表面感。', '机织', NULL, NULL, NULL, '抽象图案', NULL);
INSERT INTO `clothing_texture_info` VALUES (1979871, 19996327, '平纹', '此为金属项链而非纺织面料，严格来说不存在织物肌理。在必须从纺织纹理中二选一时，选择最接近“光滑、无明显纹路”的“Plain weave/平纹”作为形式上的归类，以对应其细腻平滑的金属表面感。', '机织', NULL, NULL, NULL, '抽象图案', NULL);
INSERT INTO `clothing_texture_info` VALUES (1979860, 19996316, '平纹', '该手链主体为光滑不锈钢金属链条，并非纺织面料。在可选纹理标签中没有专门的金属类，只能选择中性、最基础的“Plain weave（平纹）”来表示表面相对平整、无毛绒和复杂肌理。实际质感为光滑金属，仅用“Plain weave”作为技术性占位。', '机织', NULL, NULL, NULL, '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1979861, 19996317, '平纹', '该手链主体为光滑不锈钢金属链条，并非纺织面料。在可选纹理标签中没有专门的金属类，只能选择中性、最基础的“Plain weave（平纹）”来表示表面相对平整、无毛绒和复杂肌理。实际质感为光滑金属，仅用“Plain weave”作为技术性占位。', '机织', NULL, NULL, NULL, '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1979862, 19996318, '平纹', '该不锈钢链条手链表面光滑细腻，无绒毛、凹凸颗粒或特殊涂层效果，视觉上类似一般光滑金属链的平整质感，在给定选项中与“Plain weave（平纹质感）”所代表的基础光滑表面最接近，因此选择“Plain weave”。', '机织', NULL, NULL, NULL, '抽象图案', NULL);
INSERT INTO `clothing_texture_info` VALUES (1979863, 19996319, '平纹', '该不锈钢链条手链表面光滑细腻，无绒毛、凹凸颗粒或特殊涂层效果，视觉上类似一般光滑金属链的平整质感，在给定选项中与“Plain weave（平纹质感）”所代表的基础光滑表面最接近，因此选择“Plain weave”。', '机织', NULL, NULL, NULL, '抽象图案', NULL);
INSERT INTO `clothing_texture_info` VALUES (1979864, 19996320, '平纹', '耳环为光滑金属表面，没有绒毛、纹理压花等立体肌理，视觉效果平整细腻，最接近织物中的“Plain weave（平纹）”这一基础、平滑的表面质感标签。', '机织', NULL, NULL, NULL, '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1979865, 19996321, '平纹', '耳环为光滑金属表面，没有绒毛、纹理压花等立体肌理，视觉效果平整细腻，最接近织物中的“Plain weave（平纹）”这一基础、平滑的表面质感标签。', '机织', NULL, NULL, NULL, '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1979866, 19996322, '平纹', '该商品为金属与玻璃材质的戒指，本身没有纺织面料肌理，为满足枚举只可选其一的要求，选择最基础、无明显肌理效果的“Plain weave（平纹）”作为近似标签，表示表面相对平滑、无绒毛与复杂纹理。', '机织', NULL, NULL, NULL, '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1979867, 19996323, '平纹', '该商品为金属与玻璃材质的戒指，本身没有纺织面料肌理，为满足枚举只可选其一的要求，选择最基础、无明显肌理效果的“Plain weave（平纹）”作为近似标签，表示表面相对平滑、无绒毛与复杂纹理。', '机织', NULL, NULL, NULL, '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1979856, 19996312, '金属涂层', '该戒指为不锈钢金属材质表面电镀抛光，有明显金属光泽和光滑硬质触感，最接近“Metallic coating（金属感涂层）”这一肌理标签，用于表现表面金属镀层的质感。', '机织', NULL, NULL, NULL, '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1979857, 19996313, '金属涂层', '该戒指为不锈钢金属材质表面电镀抛光，有明显金属光泽和光滑硬质触感，最接近“Metallic coating（金属感涂层）”这一肌理标签，用于表现表面金属镀层的质感。', '机织', NULL, NULL, NULL, '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1979858, 19996314, '平纹', '商品为金属耳环，本身并非织物，但在必须选择一个织物肌理标签的前提下，其表面光滑、无绒毛、无凹凸花纹，视觉效果最接近简单平整的“Plain weave（平纹织物）”表观，因此以“Plain weave”作为最接近的类比描述。', '机织', NULL, NULL, NULL, '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1979859, 19996315, '平纹', '这是金属合金与玻璃材质的项链，并非织物。由于必须从既定纹理标签中二选一，只能选与表面最相近的“Plain weave”作为形式占位。实际表面为光滑金属与玻璃硬质质感，无明显绒感或纹理织造结构。', '机织', NULL, NULL, NULL, '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1979854, 19996310, '平纹', '产品为金属链条与十字架吊坠，从视觉上表面平滑细致，类似常规光滑材质，没有绒毛、褶皱或立体织纹效果，在现有选项中最接近的是“Plain weave（平纹）”，用以表示表面平整光洁的基础质感。', '机织', NULL, NULL, NULL, '抽象图案', NULL);
INSERT INTO `clothing_texture_info` VALUES (1979855, 19996311, '平纹', '产品为金属链条与十字架吊坠，从视觉上表面平滑细致，类似常规光滑材质，没有绒毛、褶皱或立体织纹效果，在现有选项中最接近的是“Plain weave（平纹）”，用以表示表面平整光洁的基础质感。', '机织', NULL, NULL, NULL, '抽象图案', NULL);
INSERT INTO `clothing_texture_info` VALUES (1979841, 19996297, '平纹', '从图片看，主体为金属与光滑树脂硬质表面，没有绒毛、纹路或织造感，视觉上平整光滑、类似普通硬质平面。在现有选项中最接近的是“Plain weave/平纹”，用来代表无特殊立体肌理、表面平滑的基础质感。', '机织', NULL, NULL, NULL, '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1979842, 19996298, '平纹', '从图片看，主体为金属与光滑树脂硬质表面，没有绒毛、纹路或织造感，视觉上平整光滑、类似普通硬质平面。在现有选项中最接近的是“Plain weave/平纹”，用来代表无特殊立体肌理、表面平滑的基础质感。', '机织', NULL, NULL, NULL, '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1979822, 19996278, '平纹', '产品为金属发夹，表面光滑无绒毛、颗粒或浮雕等特殊肌理，视觉上类似普通平滑平纹表面，在给定选项中最接近“Plain weave/平纹”。', '机织', NULL, NULL, NULL, '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1979823, 19996279, '平纹', '产品为金属发夹，表面光滑无绒毛、颗粒或浮雕等特殊肌理，视觉上类似普通平滑平纹表面，在给定选项中最接近“Plain weave/平纹”。', '机织', NULL, NULL, NULL, '抽象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1979817, 19996273, '平纹', '发圈面料表面平整细腻、无绒毛和凹凸立体肌理，呈现典型平纹机织布的观感，因此选择“Plain weave”作为材质肌理标签。', '机织', '满幅', '提花', '多元素图案', '具象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1979818, 19996274, '平纹', '发圈面料表面平整细腻、无绒毛和凹凸立体肌理，呈现典型平纹机织布的观感，因此选择“Plain weave”作为材质肌理标签。', '机织', '满幅', '提花', '多元素图案', '具象图案', '简约风格');
INSERT INTO `clothing_texture_info` VALUES (1979819, 19996275, '平纹', '从材质描述为聚酯纤维、表面平整且无绒毛、蕾丝或网孔等特征，可判断使用的是普通机织布，纹理细腻、手感偏光滑，最接近“Plain weave”这种平纹机织质感。', '机织', '满幅', '印花', '多元素图案', '具象图案', '简约风格');
