-- ----------------------------
-- Table structure for clothing_info
-- ----------------------------
DROP TABLE IF EXISTS `clothing_info`;
CREATE TABLE `clothing_info`  (
  `Id` bigint NOT NULL DEFAULT 0,
  `Name` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NOT NULL DEFAULT '' COMMENT '名称',
  `NameEn` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NULL DEFAULT '' COMMENT '名称（外文）',
  `SeasonId` int NOT NULL DEFAULT 0 COMMENT '季节ID',
  `BrandCode` int NOT NULL DEFAULT 0 COMMENT '品牌编码',
  `BrandName` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NOT NULL DEFAULT '' COMMENT '品牌名称',
  `ArticleNo` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NOT NULL DEFAULT '' COMMENT '货号',
  `StyleNo` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NOT NULL DEFAULT '' COMMENT '款号',
  `DescribeInfo` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NULL COMMENT '详情',
  `DescribeInfoEn` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NULL COMMENT '详情（外文）',
  `OriginalPrice` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NULL DEFAULT '' COMMENT '原始价格',
  `Price` decimal(10, 2) NOT NULL DEFAULT 0.00 COMMENT '价格',
  `StyleType` int NOT NULL DEFAULT 0 COMMENT '服装款式',
  `PopulationType` int NOT NULL DEFAULT 0 COMMENT '人群',
  `FabricType` int NOT NULL DEFAULT 0 COMMENT '面料类型',
  `Delivery` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NULL DEFAULT '' COMMENT '发货地',
  `TotalSales` int NULL DEFAULT 0 COMMENT '总销量',
  `IsEffective` int NOT NULL DEFAULT 0 COMMENT '1有效，0无效',
  `ListingYearSeason` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NOT NULL DEFAULT '' COMMENT '上市年份季节',
  `CreateTime` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '上架时间',
  `ReceiveTime` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '推送日期',
  `ProductId` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NOT NULL DEFAULT '' COMMENT '知衣数据ItemId=ArticleNo，其他的不等于',
  `UniqueKey` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NULL DEFAULT '' COMMENT 'UniqueKey',
  `MongoDBId` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NOT NULL DEFAULT '' COMMENT 'MongoDBId',
  `SuitableScene` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NULL DEFAULT '' COMMENT '适用场景',
  `SuitableSeason` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NULL DEFAULT '' COMMENT '适用季节',
  `SuitableGender` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NULL DEFAULT '' COMMENT '适用性别',
  `SuitableAge` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NULL DEFAULT '' COMMENT '适用年龄',
  `FiberList` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NULL COMMENT '成份',
  `SourceUrl` varchar(1000) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NULL DEFAULT '' COMMENT '来源链接',
  `Category` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NULL DEFAULT '' COMMENT '一级类目名',
  `SubCategory` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NULL DEFAULT '' COMMENT '二级类目名',
  `TertiaryCategory` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NULL DEFAULT '' COMMENT '三级类目名',
  `QuaternaryCategory` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NULL DEFAULT '' COMMENT '四级类目名',
  `LeafCategory` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NULL DEFAULT '' COMMENT '叶子类目',
  `ShopId` bigint NULL DEFAULT 0 COMMENT '商铺Id',
  `ShopName` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NULL DEFAULT '' COMMENT '商铺名',
  `ImageId` int NOT NULL DEFAULT 0 COMMENT '图片Id',
  `ImageURL` varchar(1000) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NOT NULL DEFAULT '' COMMENT '图片Url',
  `Width` int NOT NULL DEFAULT 0 COMMENT '宽',
  `Height` int NOT NULL DEFAULT 0 COMMENT '高',
  `IsDiscernType` tinyint NOT NULL DEFAULT 0 COMMENT '类型识别1完成，0未完成',
  `DiscernTypeConfidence` decimal(10, 5) NOT NULL DEFAULT 0.00000 COMMENT '款式识别置信度',
  `IsDiscernPattern` tinyint NOT NULL DEFAULT 0 COMMENT '图案识别1完成，0未完成',
  `IsMatting` tinyint NOT NULL DEFAULT 0 COMMENT '抠图识别1完成，0未完成，-5异常执行回滚',
  `IsDiscernColor` tinyint NOT NULL DEFAULT 0 COMMENT '颜色识别1完成，0未完成',
  `IsDiscernStyle` tinyint NOT NULL DEFAULT 0 COMMENT '款式识别1完成，0未完成',
  `IsPrint` tinyint NOT NULL DEFAULT 0 COMMENT '是否识别印花',
  `Source` int NOT NULL DEFAULT 0 COMMENT '来源：1.魔镜/知衣，2.中国官网，3.日本官网，4.日本其他',
  `OldId` bigint NULL DEFAULT NULL COMMENT '主表ID（待删除）',
  `Functions` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NULL DEFAULT '' COMMENT '功能性',
  `OtherFunctions` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NULL DEFAULT '' COMMENT '其他功能性',
  `Technologies` varchar(1000) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NULL DEFAULT '' COMMENT '科技',
  `OtherFeatures` varchar(1000) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NULL DEFAULT '' COMMENT '其他特征',
  `Pattern` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NULL DEFAULT '' COMMENT '图案',
  `CategoryRationale` varchar(1000) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NULL DEFAULT '' COMMENT '识别置信度',
  `IsDifferentColors` tinyint NULL DEFAULT 0 COMMENT '是否有不同的颜色',
  `IndexNo` int NULL DEFAULT 0 COMMENT '位置',
  `AIDiscernCategoryStatus` tinyint NULL DEFAULT 0 COMMENT 'AI识别款式状态',
  `AIDiscernPatternStatus` tinyint NULL DEFAULT 0 COMMENT 'AI识别图案状态',
  `LeafCategoryEn` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NULL DEFAULT '' COMMENT 'LeafCategoryEn',
  `RemoveBackgroundImageUrl` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NULL DEFAULT NULL COMMENT '删除背景Url链接',
  `FunctionsStandard` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NULL DEFAULT '' COMMENT '功能性 规范',
  `MattingResult` int NULL DEFAULT 0 COMMENT '抠图结果',
  `MetaData` text CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NULL COMMENT '组合查询字段',
  `Status` int NULL DEFAULT 0 COMMENT '核验状态',
  `LastCheckRepeatTime` datetime NULL DEFAULT NULL COMMENT '核验时间/下线时间',
  `ColorList` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NULL COMMENT '颜色信息（淘宝）',
  `ColorCode` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NULL DEFAULT '' COMMENT '颜色编码',
  `ColorName` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NULL DEFAULT '' COMMENT '颜色名称',
  `YearSeason` int NOT NULL DEFAULT 0 COMMENT '季节'
) ENGINE = InnoDB AUTO_INCREMENT = 512 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_bin ROW_FORMAT = Dynamic;

